// ── HOSA HISTORY FLASHCARD TOP-UP (52 more) ───────────────────────────────
(function(){
  if(!window.QB_HOSA_HISTORY) return;
  var fc = window.QB_HOSA_HISTORY.flashcards;
  if(!fc.easy) fc.easy=[]; if(!fc.medium) fc.medium=[];
  fc.easy = fc.easy.concat([
    {term:"HOSA Bowl subject areas",def:"Four areas: medical terminology, health science, HOSA history/bylaws, and current health issues"},
    
    {term:"HOSA Bowl alternate rule",def:"A pre-registered alternate may replace a team member before the event begins — not during competition"},
    {term:"HOSA competitive event categories (3)",def:"Health Science Events, Leadership Events, and Recognition Events — the three main HOSA competitive categories"},
    {term:"HOSA Bowl team point goal",def:"Teams accumulate points through toss-ups and bonuses — highest total wins the match"},
    {term:"HOSA chapter newsletter",def:"A published document showcasing chapter activities — judged as a HOSA Recognition Event"},
    
    
    {term:"HOSA chapter of merit",def:"A recognition tier for chapters that meet baseline achievement criteria — below Chapter of Excellence"},
    
    {term:"HOSA ILC rotating cities",def:"ILC is held in a different city each year — recent host cities include Nashville and Dallas"},
    {term:"HOSA and global health",def:"WHO initiatives, global disease burden, and international health data appear in HOSA Bowl current events questions"},
    {term:"HOSA Bowl power question",def:"Answering before the question ends — earns points and bonus if correct, forfeits opportunity if wrong"},
    
    
    {term:"HOSA and simulation learning",def:"Skills events increasingly use patient simulators and standardized patient scenarios for assessment"},
    {term:"HOSA chapter president",def:"Presides over meetings, represents the chapter externally, and coordinates officer team activities"},
    {term:"HOSA chapter secretary",def:"Records meeting minutes, tracks attendance, and manages official correspondence"},
    {term:"HOSA and HIPAA",def:"Patient privacy law tested across HOSA health science events — members learn to protect patient information"},
    {term:"HOSA and bioethics",def:"Autonomy, beneficence, non-maleficence, and justice — four bioethical principles tested in HOSA events"},
    
    {term:"HOSA chapter dues vs. national dues",def:"Chapter dues are paid to the local chapter; affiliation fees are paid to national HOSA — they are separate"},
    
    {term:"HOSA Bowl tie-breaker",def:"Sudden death toss-up questions break ties — first correct answer wins"},
    
    {term:"HOSA grant writing",def:"Some chapters pursue grants for community health projects as part of Chapter of Excellence program of work"},
  ]);
  fc.medium = fc.medium.concat([
    {term:"HOSA Bowl study strategy: domain specialization",def:"Top teams assign members to become domain experts — one covers HOSA bylaws, another medical terminology, another current events"},
    {term:"HOSA and health literacy promotion",def:"Improving patient understanding of health information is a goal in Health Education and Community Awareness events"},
    
    {term:"HOSA competitive event grievance window",def:"Formal protests must be filed within a specified time after results are posted — late protests are not accepted"},
    {term:"HOSA Bowl moderator's packet",def:"Contains sealed questions with answers, point values, and tie-breakers — kept secure until competition begins"},
    
    
    {term:"HOSA Bowl advanced: pharmacology",def:"Drug classifications, routes of administration, and common medication classes appear at advanced HOSA Bowl levels"},
    {term:"HOSA Bowl advanced: epidemiology",def:"Incidence, prevalence, R0, herd immunity, and outbreak investigation concepts appear in ILC-level questions"},
    {term:"HOSA and National Healthcare Foundation Standards",def:"NHFS competencies — developed by NCHSE — are the framework HOSA competitive events are mapped to"},
    {term:"HOSA Delegate Assembly quorum",def:"A majority of registered delegates must be present to conduct binding votes at ILC Delegate Assembly"},
    
    
    {term:"HOSA Bowl: anti-coaching enforcement",def:"Advisors and spectators may not signal or communicate with competitors — violation results in team disqualification"},
    {term:"HOSA Bowl cumulative scoring",def:"In large tournaments, final standings use cumulative points across rounds; ties broken by head-to-head record first"},
    
    {term:"HOSA and accreditation",def:"HOSA programs often align with CAAHEP or ACEN accreditation frameworks for program quality assurance"},
    {term:"HOSA Biomedical Debate event",def:"Teams research and argue health science policy positions — judged on evidence quality and argumentation"},
    {term:"HOSA resolution submission process",def:"Resolutions must be submitted 60 days before ILC, reviewed by committee, distributed to delegates before the vote"},
    {term:"HOSA and social media conduct policy",def:"Misrepresenting HOSA or posting inappropriate content can result in disciplinary action under HOSA guidelines"},
    {term:"HOSA and DoD international chapters",def:"Department of Defense overseas school HOSA chapters are among the most competitive globally"},
    {term:"HOSA and rural workforce pipeline",def:"Chapters in rural and underserved areas play a critical role in building local health career pipelines where shortages are acute"},
    {term:"HOSA Bowl question sourcing and vetting",def:"HOSA Bowl questions are written by health educators and vetted by health professionals before use in competition"},
    {term:"HOSA competitive integrity: plagiarism",def:"Fabricating data or plagiarizing in projects results in disqualification — zero tolerance under HOSA's integrity policy"},
    {term:"HOSA bylaws amendment vs. standing rules change",def:"Bylaws require 2/3 vote and define fundamental governance; standing rules need only simple majority and govern daily operations"},
    {term:"HOSA state bylaw autonomy",def:"State HOSA associations govern their own bylaws independently — they do not need national ILC approval to change state-level rules"},
  ]);
})();

// ── HOSA HISTORY FINAL TOP-UP (19 flashcards) ─────────────────────────────
