// ── STOP THE BLEED EXPANSION ───────────────────────────────────────────────
(function(){
  if(!window.QB_STOP_BLEED) return;
  var fc = window.QB_STOP_BLEED.flashcards;
  var qz = window.QB_STOP_BLEED.quiz;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});

  fc.easy = fc.easy.concat([
    {term:"Stop the Bleed founder",def:"The Stop the Bleed campaign was launched by the American College of Surgeons in 2015 following the Sandy Hook tragedy"},
    {term:"Hartford Consensus",def:"A 2013 agreement by medical and law enforcement leaders establishing that bystanders can prevent death from bleeding — foundation of Stop the Bleed"},
    {term:"TECC",def:"Tactical Emergency Casualty Care — civilian version of military TCCC, guiding bleeding control in mass casualty and high-threat events"},
    {term:"TCCC",def:"Tactical Combat Casualty Care — military battlefield hemorrhage control protocol that inspired Stop the Bleed training"},
    {term:"Massive hemorrhage",def:"Uncontrolled, life-threatening bleeding — the leading cause of preventable death in trauma, accounting for up to 40% of trauma deaths"},
    {term:"Bystander bleeder effect",def:"Research showing that immediate bystander intervention before EMS arrival dramatically increases survival from severe bleeding"},
    {term:"Average EMS response time",def:"7–10 minutes nationally — critically long when a patient can die from arterial bleeding in 3–5 minutes"},
    {term:"Tourniquet history",def:"Tourniquets were used in military medicine as far back as the U.S. Civil War; modern adoption grew from lessons in Iraq and Afghanistan"},
    {term:"Combat Application Tourniquet (CAT)",def:"The most widely used commercial tourniquet in the U.S. military and civilian first aid — windlass mechanism, one-hand application"},
    {term:"SOFTT-W",def:"Special Operations Forces Tactical Tourniquet Wide — a dual-ring tourniquet system used as an alternative to the CAT"},
    {term:"Bleeding control kit (B-Con kit)",def:"A publicly accessible kit containing gloves, tourniquet, pressure bandage, hemostatic gauze, and a marker — placed in public spaces like AEDs"},
    {term:"Public bleeding control kit",def:"Stop the Bleed kits are increasingly co-located with AEDs in schools, airports, stadiums, and public buildings"},
    {term:"Marker or pen in bleeding kit",def:"Used to write the time of tourniquet application on the patient's forehead or tourniquet — critical for hospital handoff"},
    {term:"Normal adult blood volume",def:"Approximately 5 liters (10–12 pints) — loss of just 1–1.5 liters can cause hemorrhagic shock"},
    {term:"Critical blood loss threshold",def:"Loss of more than 30% of blood volume (about 1.5 liters) triggers Class III hemorrhagic shock requiring urgent intervention"},
    {term:"Pallor (pale skin)",def:"One of the classic signs of significant blood loss — caused by blood being redirected away from the skin"},
    {term:"Diaphoresis",def:"Cold, clammy, sweaty skin — a sign of shock as the body activates the sympathetic nervous system in response to blood loss"},
    {term:"Tachycardia in hemorrhage",def:"Rapid heart rate (>100 bpm) — the body's compensatory response to maintain cardiac output during blood loss"},
    {term:"Hypotension in hemorrhage",def:"Low blood pressure — a late sign of hemorrhagic shock indicating the body can no longer compensate for blood loss"},
    {term:"Altered mental status (blood loss)",def:"Confusion, agitation, or unconsciousness from reduced oxygen delivery to the brain — a sign of severe blood loss"},
    {term:"Direct pressure technique",def:"Apply firm, continuous pressure to a wound using a cloth or gauze — the first step for any bleeding wound"},
    {term:"Wound packing steps",def:"Pack gauze tightly into the wound, apply direct pressure for at least 3 minutes, do not remove — used for deep wounds where direct pressure alone won't work"},
    {term:"Tourniquet placement site",def:"Applied 2–3 inches above the wound on a limb — never over a joint, never on the neck, chest, or abdomen"},
    {term:"Tourniquet tightening endpoint",def:"Tighten until bleeding stops — not until patient screams; the goal is cessation of bleeding, not a specific tightness level"},
    {term:"Leave tourniquet in place",def:"Never remove a tourniquet in the field — only hospital staff with blood products available should remove it"},
    {term:"Tourniquet documentation time",def:"Write the time of tourniquet application (T=HH:MM) on the patient's skin or the tourniquet itself — vital for hospital teams"},
    {term:"Arterial bleed identification",def:"Bright red blood that pulses or spurts with each heartbeat — indicates damage to an artery, most life-threatening type"},
    {term:"Venous bleed identification",def:"Dark red blood that flows steadily — from a vein; less immediately dangerous than arterial but still potentially fatal if large vein"},
    {term:"Capillary bleed",def:"Slow oozing from the skin surface — the least dangerous type, usually controlled with light pressure"},
    {term:"Junctional wound definition",def:"A wound in an area where a tourniquet cannot be applied — groin, armpit, neck, or pelvis"},
    {term:"Junctional wound treatment",def:"Use wound packing with hemostatic gauze and apply firm direct pressure — no tourniquet possible in these areas"},
    {term:"Hemostatic gauze brands",def:"QuikClot Combat Gauze, Celox, and ChitoGauze — impregnated with agents that accelerate blood clotting when packed into wounds"},
    {term:"QuikClot mechanism",def:"Kaolin-impregnated gauze that activates the clotting cascade on contact with blood — does not generate heat like older versions"},
    {term:"Celox mechanism",def:"Contains chitosan (derived from shellfish) that creates a gel-like clot independent of the body's normal clotting factors — useful in hypothermic patients"},
    {term:"Gloves as PPE in bleeding control",def:"Nitrile or latex gloves protect the rescuer from bloodborne pathogens — always the first step before touching a bleeding patient"},
    {term:"Bloodborne pathogens",def:"Infectious agents (HIV, Hepatitis B, Hepatitis C) transmitted through contact with blood — reason PPE is essential in bleeding control"},
    {term:"Good Samaritan protections",def:"Laws in all U.S. states that protect bystanders who provide emergency aid in good faith from civil liability"},
    {term:"Scene safety in bleeding control",def:"Before helping a bleeding patient, ensure the scene is safe — active shooters, traffic, or hazards must be addressed or avoided"},
    
    {term:"Israeli bandage",def:"A widely used pressure bandage with a built-in pressure applicator bar — designed for one-handed self-application in the field"},
    {term:"Shock definition",def:"A life-threatening state where the body cannot deliver enough oxygen to vital organs — hemorrhagic shock is the type caused by blood loss"},
    {term:"Compensated shock",def:"Early stage where the body maintains blood pressure through increased heart rate and vasoconstriction — patient may appear relatively normal"},
    {term:"Decompensated shock",def:"Late stage where compensatory mechanisms fail — blood pressure drops, consciousness decreases, death is imminent without intervention"},
    {term:"EMS handoff key information",def:"Time of injury, tourniquet application time, mechanism of injury, and estimated blood loss — all communicated to arriving EMS"},
    {term:"Recovery position",def:"Place a stabilized bleeding patient on their side if unconscious — protects the airway from vomit while waiting for EMS"},
    {term:"Two-tourniquet rule",def:"If bleeding continues after the first tourniquet, apply a second one directly above (proximal to) the first — do not remove the first"},
    {term:"Improvised tourniquet materials",def:"A belt, tie, or torn shirt can be used as a last resort — must be at least 1 inch wide, applied with consistent tension"},
    {term:"Why improvised tourniquets often fail",def:"Too narrow (causes tissue damage without stopping flow), too loose, or not tightened enough — commercial tourniquets are far more reliable"},
    {term:"Pediatric tourniquet",def:"Same principles apply — use the smallest commercial tourniquet or improvise; child's smaller limb means less material is needed"},
    {term:"Neck wound first aid",def:"Never apply circumferential pressure to the neck — use direct finger pressure on the wound site to compress the bleeding vessel"},
    {term:"Abdominal wound first aid",def:"Do not pack or apply direct pressure to an abdominal wound with protruding organs — cover with moist dressing and await EMS"},
    {term:"Stop the Bleed training duration",def:"The standard Stop the Bleed course is approximately 2 hours including hands-on practice with tourniquets and wound packing simulators"},
    {term:"Who should take Stop the Bleed",def:"Anyone — teachers, students, parents, office workers — bystanders are statistically the first responders at most bleeding emergencies"},
    {term:"AVPU scale",def:"Alert, Verbal, Pain, Unresponsive — a rapid mental status assessment tool used during initial evaluation of a trauma patient"},
    {term:"Pulse check in bleeding",def:"Check radial (wrist) pulse first — weak or absent radial pulse with a strong carotid pulse indicates significant blood loss"},
    {term:"Capillary refill time",def:"Normal is less than 2 seconds — prolonged refill (press nail bed, release, count seconds until color returns) indicates poor perfusion"},
    {term:"Tourniquets and nerve damage",def:"Prolonged tourniquet application (>2 hours) risks nerve and muscle damage — but this risk is always less than the risk of exsanguination"},
    {term:"Prehospital tourniquet evidence",def:"Military data from Iraq and Afghanistan showed tourniquets reduce extremity hemorrhage deaths by up to 85% with minimal complications when properly applied"},
    {term:"Wound gauze packing pressure",def:"Packing requires firm, sustained pressure — use body weight if needed, maintaining pressure for a minimum of 3 full minutes"},
    {term:"Hemostatic dressing application time",def:"Press hemostatic gauze into the wound and apply direct pressure for 3 minutes — the agent needs time to activate clotting"},
    {term:"Mass casualty bleeding triage",def:"In a mass casualty event, focus on the most severely bleeding patients who are still conscious — unconscious patients with no pulse are lowest priority"},
    {term:"SALT triage",def:"Sort, Assess, Lifesaving Interventions, Treatment — a mass casualty triage system where bleeding control is a first-tier lifesaving intervention"},
    {term:"START triage",def:"Simple Triage and Rapid Treatment — colors: black (deceased/expectant), red (immediate), yellow (delayed), green (minor)"},
    {term:"Bleeding control in CPR",def:"If a patient needs both CPR and bleeding control, control life-threatening bleeding first — you cannot circulate oxygenated blood if it's all on the floor"},
    {term:"Public access bleeding control",def:"The movement to co-locate bleeding control kits with AEDs in public spaces — analogous to the public AED movement of the 1990s"},
    {term:"Stop the Bleed website",def:"stopthebleed.org — the official site for training registration, kit information, and instructor resources"},
    {term:"Certified Stop the Bleed instructor",def:"A healthcare professional or trained layperson certified to teach the Stop the Bleed curriculum to community groups"},
    {term:"ACT (Awareness, Call 911, Treatment)",def:"An older bleeding control mnemonic emphasizing awareness of the scene, activating EMS, and treating the wound"},
    {term:"3 C's of Stop the Bleed",def:"Call 911, Compress the wound, Apply a tourniquet — the three core action steps taught in the Stop the Bleed program"},
  ]);

  fc.medium = fc.medium.concat([
    {term:"MARCH protocol expanded",def:"Massive hemorrhage first, Airway second, Respiration third, Circulation fourth, Hypothermia last — militarily proven hemorrhage-first prioritization"},
    {term:"Why hemorrhage before airway",def:"MARCH places hemorrhage control before airway management because exsanguination kills faster than most airway obstructions in trauma"},
    {term:"Permissive hypotension rationale",def:"Allowing systolic BP of 80–90 mmHg in penetrating trauma avoids high-volume crystalloid that dilutes clotting factors and worsens the lethal triad"},
    {term:"Lethal triad components",def:"Hypothermia, acidosis, and coagulopathy — the three interconnected conditions that spiral together in major trauma to cause death"},
    {term:"Hypothermia and coagulopathy link",def:"Clotting enzymes work best at 37°C — body temperature below 35°C significantly impairs clotting factor function, worsening hemorrhage"},
    {term:"Acidosis and coagulopathy link",def:"Acidosis (low blood pH from tissue hypoxia) directly impairs platelet aggregation and clotting factor activity"},
    {term:"TXA mechanism",def:"Tranexamic acid blocks fibrinolysis (the breakdown of blood clots) — preserving clots that form at bleeding sites"},
    {term:"TXA timing window",def:"TXA is most effective when given within 1 hour of injury — effectiveness decreases sharply after 3 hours and may be harmful after that"},
    {term:"CRASH-2 trial",def:"The landmark 20,000-patient randomized controlled trial showing TXA reduces mortality in bleeding trauma patients by 1.5% when given within 3 hours"},
    {term:"Damage control surgery",def:"Abbreviated surgery focused solely on controlling hemorrhage and contamination — detailed repair performed later when the patient is stabilized"},
    {term:"1:1:1 balanced resuscitation",def:"Transfusing packed red blood cells, fresh frozen plasma, and platelets in a 1:1:1 ratio — mimics whole blood and preserves clotting function"},
    {term:"Whole blood transfusion",def:"Increasingly used in military and trauma settings — provides red cells, plasma, and platelets together without the dilution of component therapy"},
    {term:"Crystalloid overload risk",def:"Large volumes of saline or lactated Ringer's solution dilute clotting factors, worsen hypothermia, and contribute to the lethal triad"},
    {term:"Classes of hemorrhagic shock",def:"Class I (<15% blood loss), II (15–30%), III (30–40%), IV (>40%) — Class III+ is life-threatening requiring immediate blood product resuscitation"},
    {term:"Class I hemorrhage signs",def:"<750 mL blood loss — minimal symptoms, heart rate <100 bpm, normal BP — body fully compensates"},
    {term:"Class II hemorrhage signs",def:"750–1500 mL blood loss — heart rate 100–120 bpm, anxiety, decreased urine output, narrow pulse pressure"},
    {term:"Class III hemorrhage signs",def:"1500–2000 mL blood loss — heart rate >120, hypotension, altered mental status, markedly decreased urine output — requires blood products"},
    {term:"Class IV hemorrhage signs",def:">2000 mL blood loss — heart rate >140, severe hypotension, unconsciousness — immediately life-threatening"},
    {term:"Pulse pressure in hemorrhage",def:"The difference between systolic and diastolic BP — narrowing pulse pressure is an early sign of volume loss and vasoconstriction"},
    {term:"Tourniquet conversion",def:"In hospital, tourniquets should be converted to definitive hemorrhage control (surgery, vascular repair) as quickly as possible to minimize ischemia time"},
    {term:"Fasciotomy after tourniquet",def:"Release of fascial compartments may be needed if a tourniquet was in place >2 hours — compartment syndrome from reperfusion can occur"},
    {term:"Compartment syndrome",def:"Pressure buildup within a muscle compartment after injury or prolonged tourniquet — causes ischemia if not released by fasciotomy"},
    {term:"Reperfusion injury",def:"Damage that occurs when blood flow is restored to ischemic tissue — releases inflammatory mediators and free radicals"},
    {term:"Hemostatic dressing comparison",def:"Combat Gauze (kaolin) vs Celox (chitosan) — Combat Gauze is FDA-cleared for military use; Celox works independently of the clotting cascade, useful in anticoagulated patients"},
    {term:"Wound packing vs tourniquet decision",def:"Tourniquet for extremity wounds where pressure alone fails; wound packing for junctional or torso wounds where tourniquet is impossible"},
    {term:"Pressure dressing application",def:"Apply gauze over wound, wrap elastic bandage with consistent tension, secure end — the bar of an Israeli bandage creates focused pressure"},
    {term:"Non-compressible hemorrhage",def:"Bleeding in the torso, pelvis, or neck that cannot be controlled with tourniquet or direct pressure — requires emergency surgery"},
    {term:"Resuscitative endovascular balloon occlusion (REBOA)",def:"A catheter-based device inflated in the aorta to reduce blood flow to hemorrhaging pelvic or abdominal vessels — a bridge to surgery"},
    {term:"Junctional tourniquet device",def:"Devices like the JETT or SAM Junctional Tourniquet apply pressure to the groin or axilla — bleeding sites where standard tourniquets cannot be used"},
    {term:"Hemorrhage control in pregnancy",def:"Standard direct pressure and wound packing apply; tourniquets are not effective on the gravid abdomen — requires urgent surgical intervention"},
    {term:"Bleeding control in anticoagulated patients",def:"Patients on warfarin, Xarelto, or Eliquis have impaired clotting — hemostatic agents like Celox (chitosan) may work better; reversal agents needed in hospital"},
    {term:"Factor Xa inhibitors and bleeding",def:"Apixaban (Eliquis) and rivaroxaban (Xarelto) — reversed with andexanet alfa; can cause severe bleeding that is difficult to control in the field"},
    {term:"Warfarin and bleeding risk",def:"Warfarin prolongs INR — patients on warfarin who sustain trauma can bleed dramatically; reversed with vitamin K and/or fresh frozen plasma"},
    {term:"Hemophilia and bleeding control",def:"People with hemophilia lack clotting factors — factor replacement is needed; field hemostatic dressings provide temporary control"},
    {term:"Pediatric hemorrhage class thresholds",def:"Children have smaller total blood volume (~80 mL/kg) — loss of 30–40 mL/kg constitutes Class III hemorrhage (proportionally similar to adults)"},
    {term:"Tourniquet pain management",def:"Tourniquets cause significant pain — this is expected and normal; do not loosen for pain; reassure the patient and await EMS with analgesics"},
    {term:"Scene time in trauma",def:"'Load and go' principle — major trauma patients should be transported to trauma center within 10 minutes of scene arrival; do not delay for complex field interventions"},
    {term:"Platinum 10 minutes",def:"The goal of spending no more than 10 minutes on scene for major trauma — minimizing prehospital time improves survival"},
    {term:"Wound irrigation in field",def:"Do not irrigate or probe penetrating wounds in the field — this can dislodge clots and worsen bleeding; cover and transport"},
    {term:"Blast injury and hemorrhage",def:"Explosions cause primary (pressure wave), secondary (shrapnel), tertiary (thrown), and quaternary (burns) injuries — all can cause life-threatening hemorrhage"},
    {term:"Gunshot wound hemorrhage",def:"High-velocity gunshot wounds create both entry and exit wounds with a cavitation effect — both wounds may require packing"},
    {term:"Stab wound hemorrhage",def:"Stab wounds may have a small entry wound but deep internal damage — field treatment focuses on external bleeding control; internal hemorrhage requires surgery"},
  ]);

  fc.hard = fc.hard.concat([
    {term:"von Willebrand disease and bleeding",def:"The most common inherited bleeding disorder — impairs platelet adhesion; patients may need desmopressin (DDAVP) or von Willebrand factor concentrate to stop hemorrhage"},
    {term:"DIC (disseminated intravascular coagulation)",def:"Widespread activation of clotting followed by consumption of clotting factors — causes simultaneous bleeding and clotting; occurs in sepsis, major trauma, obstetric emergencies"},
    {term:"Trauma-induced coagulopathy (TIC)",def:"Coagulopathy that develops within minutes of major injury — driven by tissue factor release, hypoperfusion, and hypothermia — distinct from DIC"},
    {term:"Viscoelastic testing (TEG/ROTEM)",def:"Thromboelastography (TEG) and rotational thromboelastometry (ROTEM) — point-of-care devices measuring the full clotting process from initiation to fibrinolysis — guides targeted resuscitation"},
    {term:"Fibrinolysis and bleeding",def:"Premature breakdown of clots — occurs in major trauma; treated with TXA; excessive fibrinolysis leads to hemorrhage that does not respond to clot-forming measures"},
    {term:"Cryoprecipitate in trauma",def:"Contains fibrinogen, factor VIII, von Willebrand factor — used in massive transfusion when fibrinogen is depleted; fibrinogen <150 mg/dL predicts ongoing hemorrhage"},
    {term:"Massive transfusion protocol (MTP)",def:"A pre-established hospital protocol that activates rapid delivery of blood components in a 1:1:1 ratio to trauma patients requiring >10 units pRBC in 24 hours"},
    {term:"Platelet dysfunction in hypothermia",def:"Platelet aggregation and adhesion are severely impaired below 33°C — rewarming is a critical component of trauma resuscitation alongside blood products"},
    {term:"Cell salvage (autotransfusion)",def:"Intraoperative collection, washing, and reinfusion of the patient's own shed blood — reduces need for donor blood in major surgical hemorrhage"},
    {term:"AABB guidelines for massive hemorrhage",def:"American Association of Blood Banks recommends 1:1:1 or 1:1:2 (plasma:platelet:pRBC) ratio in massive hemorrhage and early use of viscoelastic testing"},
    {term:"Endothelial glycocalyx in trauma",def:"A protective layer on vascular endothelium — damaged by ischemia, large crystalloid volumes, and inflammation — loss contributes to fluid leaking out of vessels (third spacing)"},
    {term:"Damage control resuscitation (DCR) principles",def:"(1) Limit crystalloids, (2) Use blood products early in 1:1:1 ratio, (3) Allow permissive hypotension, (4) Prevent/treat hypothermia and acidosis, (5) Use TXA within 3 hours"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"What are the 3 steps of Stop the Bleed?",opts:["Look, Listen, Act","Call 911, Compress, Tourniquet","Check, Call, Care","Stop, Drop, Roll"],correct:1,explain:"The 3 steps are Call 911, Compress the wound (direct pressure), and apply a Tourniquet if direct pressure fails on a limb. These three actions can be performed by any bystander."},
    {q:"What organization launched the Stop the Bleed campaign in 2015?",opts:["American Red Cross","CDC","American College of Surgeons","FEMA"],correct:2,explain:"The American College of Surgeons launched Stop the Bleed in 2015 following the Sandy Hook shooting, aiming to train the public to control life-threatening bleeding before EMS arrives."},
    {q:"Bright red blood that spurts or pulses with each heartbeat indicates which type of bleeding?",opts:["Capillary","Venous","Arterial","Internal"],correct:2,explain:"Arterial bleeding is bright red and spurts or pulses with the heartbeat because it comes directly from pressurized arteries. It is the most immediately life-threatening type of external bleeding."},
    {q:"How far above a wound should a tourniquet be applied?",opts:["Directly over the wound","1 inch above","2–3 inches above","As high as possible on the limb"],correct:2,explain:"Tourniquets should be applied 2–3 inches (about two finger-widths) above the wound. Applying directly over a wound or joint is ineffective."},
    {q:"Why should you never remove a tourniquet once applied in the field?",opts:["It causes nerve damage if removed","Removing it can cause sudden blood loss and death","It is painful to remove","It is glued to the skin"],correct:1,explain:"Removing a tourniquet in the field can cause a sudden rush of blood loss and death. Only hospital staff with blood products and surgical capability should remove tourniquets."},
    {q:"Where should you write the time when applying a tourniquet?",opts:["On your glove","On the patient's forehead or on the tourniquet","In your phone","You don't need to document time"],correct:1,explain:"Write T= followed by the time of tourniquet application on the patient's skin (forehead) or on the tourniquet itself. This is critical information for the receiving hospital team."},
    {q:"What is the first step before assisting a bleeding patient?",opts:["Apply a tourniquet","Put on gloves","Call the patient's family","Check blood pressure"],correct:1,explain:"Always put on gloves first to protect yourself from bloodborne pathogens. Personal protective equipment (PPE) is the first step before any contact with a bleeding patient."},
    {q:"What should you do if direct pressure alone does not stop limb bleeding?",opts:["Apply more gauze and wait","Apply a tourniquet","Remove the gauze and repack","Call a doctor"],correct:1,explain:"If direct pressure does not stop limb bleeding, apply a tourniquet 2–3 inches above the wound. Tourniquets are life-saving tools, not last resorts."},
    {q:"What type of wound requires packing rather than a tourniquet?",opts:["Arm laceration","Leg wound","Junctional wound (groin, armpit, neck)","Hand wound"],correct:2,explain:"Junctional wounds in the groin, armpit, or neck cannot receive a tourniquet — you cannot encircle those areas. Instead, pack the wound tightly with gauze and apply firm direct pressure."},
    {q:"How long should you apply direct pressure to a packed wound?",opts:["30 seconds","1 minute","At least 3 minutes","10 minutes"],correct:2,explain:"Apply firm, continuous pressure for at least 3 minutes after wound packing to allow hemostatic agents to activate and clots to form. Do not peek or lift gauze during this time."},
    {q:"What does 'exsanguination' mean?",opts:["Blood poisoning","Death from excessive blood loss","Fainting from blood sight","Low blood pressure"],correct:1,explain:"Exsanguination is death from excessive blood loss. A person can die from arterial bleeding in as few as 3–5 minutes — which is why bystander action before EMS arrives is so critical."},
    {q:"What is the approximate average EMS response time in the U.S.?",opts:["1–2 minutes","3–4 minutes","7–10 minutes","15–20 minutes"],correct:2,explain:"Average EMS response time is 7–10 minutes nationally. Since a patient can die from arterial bleeding in 3–5 minutes, trained bystanders who act immediately can prevent death before EMS arrives."},
    {q:"What is a 'junctional wound'?",opts:["A wound between two bones","A wound in the groin, armpit, neck, or pelvis where a tourniquet cannot be applied","A wound that has already been treated","A wound from a blunt object"],correct:1,explain:"Junctional wounds are located at body junctions where tourniquets cannot be applied — the groin, armpit, neck, and pelvis. These require wound packing and direct pressure."},
    {q:"Which of the following is a sign of significant blood loss?",opts:["Flushed, warm skin","Pale, cold, clammy skin and rapid heart rate","Slow, regular breathing","Normal blood pressure"],correct:1,explain:"Pale, cold, clammy skin and rapid heart rate are signs of hemorrhagic shock — the body is redirecting blood from the skin to vital organs and increasing heart rate to compensate for blood loss."},
    {q:"What is hemostatic gauze?",opts:["Standard cotton gauze","Gauze treated with agents that accelerate blood clotting","Gauze soaked in antiseptic","Gauze used only in hospitals"],correct:1,explain:"Hemostatic gauze is impregnated with clotting-accelerating agents (kaolin or chitosan) that help form blood clots faster when packed into wounds. Brands include QuikClot Combat Gauze and Celox."},
    {q:"What is the Hartford Consensus?",opts:["A law requiring AEDs in all schools","A 2013 agreement establishing that bystander bleeding control saves lives","A military trauma protocol","A standard for hospital emergency rooms"],correct:1,explain:"The Hartford Consensus (2013) was a landmark agreement by medical, law enforcement, and emergency response leaders establishing that immediate bystander action — particularly hemorrhage control — can prevent preventable trauma deaths."},
    {q:"What does AVPU stand for in trauma assessment?",opts:["Airway, Ventilation, Pulse, Unconscious","Alert, Verbal, Pain, Unresponsive","Assess, Verify, Prioritize, Understand","Airway, Vitals, Pupils, Unresponsive"],correct:1,explain:"AVPU is a rapid mental status tool: Alert (aware), Verbal (responds to voice), Pain (responds only to pain), Unresponsive (no response). Used to quickly gauge how much blood a trauma patient has lost."},
    {q:"What is the minimum width recommended for an improvised tourniquet?",opts:["Half an inch","1 inch","3 inches","5 inches"],correct:1,explain:"An improvised tourniquet should be at least 1 inch wide. Narrower materials (like rope or wire) cut into tissue without stopping arterial blood flow and can cause permanent damage."},
    {q:"Which bleeding control step comes FIRST after scene safety?",opts:["Apply tourniquet","Put on gloves","Call 911","Pack the wound"],correct:1,explain:"After confirming scene safety, the first step is always to put on gloves (PPE). Protecting yourself from bloodborne pathogens is essential before any patient contact."},
    {q:"What is the purpose of writing the time on a tourniquet?",opts:["To track how long the patient has been injured","To tell the hospital how long the tourniquet has been on so they can plan for complications","To help police document the event","It is not necessary in civilian settings"],correct:1,explain:"Tourniquet time helps hospital staff assess ischemia risk. Tourniquets left on >2 hours risk nerve and muscle damage. Knowing the exact time allows surgeons to plan removal and possible fasciotomy."},
    {q:"Stop the Bleed kits in public spaces are most often co-located with which other device?",opts:["Fire extinguishers","AEDs (Automated External Defibrillators)","First aid stations","Security cameras"],correct:1,explain:"Stop the Bleed kits are increasingly placed alongside AEDs in schools, airports, stadiums, and public buildings — following the same public access model that normalized AEDs in public spaces."},
    {q:"What is the 'windlass' on a CAT tourniquet?",opts:["The Velcro strap","A rod that is twisted to tighten the tourniquet","The buckle that holds the band","The time-stamp window"],correct:1,explain:"The windlass is the plastic rod on a CAT tourniquet that is twisted to tighten the band after initial application — the mechanism that provides the mechanical advantage needed to occlude arterial blood flow."},
    {q:"Which law protects bystanders who give emergency aid in good faith?",opts:["HIPAA","Duty to Act law","Good Samaritan law","Emergency Medical Treatment Act"],correct:2,explain:"Good Samaritan laws in all 50 U.S. states protect bystanders who provide emergency first aid in good faith and without expectation of payment from civil liability — encouraging public intervention."},
    {q:"What should you do with a wound that has an object impaled in it?",opts:["Remove the object before packing","Apply pressure around the object — never remove it","Cover it and ignore it","Wiggle it to assess depth"],correct:1,explain:"Never remove an impaled object — it may be tamponading (plugging) the bleeding vessel. Apply pressure around the object, stabilize it, and transport immediately."},
    {q:"Direct pressure is the first step for which types of wounds?",opts:["Limb wounds only","All external bleeding wounds","Junctional wounds only","Wounds with impaled objects only"],correct:1,explain:"Direct pressure — pressing firmly on the wound — is the first step for ALL external bleeding, regardless of location. A tourniquet is added for uncontrolled limb bleeding; packing is added for deep or junctional wounds."},
    {q:"What does it mean if a tourniquet is 'properly applied'?",opts:["The patient feels pain","The bleeding has stopped","The limb turns blue","The tourniquet is as tight as possible"],correct:1,explain:"A properly applied tourniquet has stopped the bleeding. The endpoint is cessation of hemorrhage — not a specific tightness level and not patient pain. If bleeding continues, apply a second tourniquet above the first."},
    {q:"Approximately how much blood can an adult lose before hemorrhagic shock develops?",opts:["200–300 mL (less than 1 pint)","1,000–1,500 mL (about 1–1.5 quarts)","4,000 mL (1 gallon)","Only IV fluids can replace lost blood"],correct:1,explain:"Loss of 1,000–1,500 mL (about 30% of the 5-liter adult blood volume) produces significant hemorrhagic shock. Death can occur after loss of >40% (~2,000 mL). This is why rapid hemorrhage control is so critical."},
    {q:"What is the correct action if you apply a tourniquet and the bleeding continues?",opts:["Remove the tourniquet and try direct pressure","Loosen and retighten the same tourniquet","Apply a second tourniquet immediately above the first","Wait for EMS to decide"],correct:2,explain:"If bleeding continues after the first tourniquet, apply a second tourniquet directly above (proximal to) the first — never remove the first one. Continue until bleeding stops."},
    {q:"How should you position an unconscious patient after controlling hemorrhage?",opts:["Flat on their back","On their side (recovery position)","Sitting upright","Face down"],correct:1,explain:"Place an unconscious patient in the recovery position (on their side) after controlling hemorrhage — this protects the airway from aspiration of vomit while you wait for EMS."},
    {q:"Which of the following is NOT a component of a standard Stop the Bleed kit?",opts:["Tourniquet","Hemostatic gauze","Gloves","Blood pressure cuff"],correct:3,explain:"Standard Stop the Bleed kits contain a tourniquet, hemostatic or regular gauze, gloves, a pressure bandage, and a marker. A blood pressure cuff is a clinical device — not part of a field bleeding control kit."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"Why does the MARCH protocol prioritize massive hemorrhage control BEFORE airway management?",opts:["Airway is less important than bleeding","Exsanguination kills faster than most airway obstructions in trauma — seconds matter","It is easier to control bleeding than manage an airway","Military protocol has never been evaluated"],correct:1,explain:"MARCH (Massive Hemorrhage, Airway, Respiration, Circulation, Hypothermia) prioritizes hemorrhage because exsanguination from arterial bleeding kills in 3–5 minutes — faster than most traumatic airway obstructions. This is counterintuitive to traditional ABC training."},
    {q:"What is the 'lethal triad' of trauma and why is it dangerous?",opts:["Bleeding, pain, and shock — cause patient distress","Hypothermia, acidosis, and coagulopathy — each worsens the others in a deadly cycle","Hypoxia, hypovolemia, and hypotension — cause cardiac arrest","Infection, dehydration, and organ failure — late complications"],correct:1,explain:"The lethal triad is hypothermia + acidosis + coagulopathy. Each worsens the others: cold blood doesn't clot, acidosis further impairs clotting enzymes, coagulopathy causes more blood loss → more hypothermia and acidosis. Breaking this cycle requires targeted resuscitation with blood products and warming."},
    {q:"Why is permissive hypotension used in penetrating trauma resuscitation?",opts:["It conserves IV fluids in resource-limited settings","High BP forces more clot breakdown; low BP allows clots to form and avoids diluting clotting factors with crystalloid","Patients with penetrating trauma cannot tolerate normal BP","It reduces pain from the injury"],correct:1,explain:"In penetrating trauma, allowing systolic BP of 80–90 mmHg prevents dislodging forming clots, reduces crystalloid-induced dilution of clotting factors, and minimizes the lethal triad. It is NOT used in traumatic brain injury where cerebral perfusion pressure must be maintained."},
    {q:"What distinguishes hemostatic gauze brands Celox and QuikClot Combat Gauze?",opts:["They are identical products with different names","QuikClot uses kaolin to activate the clotting cascade; Celox uses chitosan which forms clots independent of the clotting cascade — useful in hypothermic or anticoagulated patients","Celox is only for military use; QuikClot is for civilians","QuikClot generates dangerous heat; Celox does not work"],correct:1,explain:"QuikClot Combat Gauze uses kaolin to trigger the body's normal clotting cascade. Celox uses chitosan (shellfish-derived) to physically bind red blood cells and form a gel-like clot independent of clotting factors — potentially more effective in anticoagulated or hypothermic patients where the clotting cascade is impaired."},
    {q:"A trauma patient has Class III hemorrhagic shock. What does this mean clinically?",opts:["Minor blood loss — give oral fluids and monitor","Moderate loss — IV saline will restore volume","Loss of 30–40% blood volume (1500–2000 mL) — requires immediate blood product transfusion, not just IV fluids","Loss >40% — patient is already dead"],correct:2,explain:"Class III hemorrhage (30–40% blood loss) causes: heart rate >120, hypotension, altered mental status, markedly decreased urine output. At this point, crystalloid alone is insufficient and may worsen the lethal triad. Packed red blood cells, plasma, and platelets in 1:1:1 ratio are needed."},
    {q:"Why is TXA (tranexamic acid) ineffective or possibly harmful when given more than 3 hours after injury?",opts:["The drug expires after 3 hours","After 3 hours, fibrinolysis has already completed — blocking it further may cause pathological clot formation","The kidneys clear TXA too quickly to be effective","TXA only works on arterial bleeding"],correct:1,explain:"In early trauma, fibrinolysis (clot breakdown) is pathologically accelerated. TXA blocks this to preserve clots. By 3 hours, the fibrinolytic phase has resolved — giving TXA then risks promoting thrombosis without benefit. The CRASH-2 trial showed harm when TXA was given 3+ hours post-injury."},
    {q:"A patient on rivaroxaban (Xarelto) sustains a major laceration. How does this complicate bleeding control?",opts:["It has no effect — Xarelto only prevents heart attacks","Rivaroxaban inhibits Factor Xa, impairing the coagulation cascade — standard hemostasis may be inadequate; reversal with andexanet alfa is needed in hospital","Rivaroxaban causes excessive clotting, not bleeding","The drug wears off before bleeding becomes a problem"],correct:1,explain:"Factor Xa inhibitors like rivaroxaban impair the coagulation cascade — patients bleed more and clot less effectively. Field treatment is the same (direct pressure, packing, tourniquet) but hemostatic agents like Celox (chitosan, clotting-factor independent) may be more effective. Hospital reversal requires andexanet alfa (Andexxa)."},
    {q:"What is damage control resuscitation (DCR) and how does it differ from traditional trauma resuscitation?",opts:["DCR uses more IV fluids to rapidly restore blood pressure","DCR limits crystalloids, uses early 1:1:1 blood products, allows permissive hypotension, and prevents hypothermia — replacing the traditional high-volume crystalloid approach","DCR focuses only on surgery, not fluid management","DCR is only used in military, not civilian trauma"],correct:1,explain:"Traditional resuscitation used large crystalloid volumes (normal saline, LR) to restore BP. DCR replaces this with: early 1:1:1 blood product transfusion, permissive hypotension (~80–90 mmHg systolic), TXA within 3 hours, and aggressive prevention of hypothermia. Crystalloid overload worsens the lethal triad."},
    {q:"What is REBOA and when is it used?",opts:["A type of tourniquet for the abdomen","A resuscitative endovascular balloon occlusion device placed in the aorta to reduce flow to non-compressible hemorrhage sites — bridges to surgery","A reversal agent for anticoagulant-related bleeding","A technique for packing pelvic wounds"],correct:1,explain:"REBOA (Resuscitative Endovascular Balloon Occlusion of the Aorta) involves placing a balloon catheter in the aorta and inflating it to reduce blood flow to areas of non-compressible hemorrhage (pelvis, abdomen). It temporarily maintains cerebral and cardiac perfusion while the patient is transported to an OR. It is a bridge, not a definitive treatment."},
    {q:"Why does major trauma cause coagulopathy within minutes of injury, even before significant blood loss?",opts:["The body releases anti-clotting hormones as a protective response","Tissue factor release, endothelial damage, and shock activate anticoagulant and fibrinolytic pathways early — this trauma-induced coagulopathy (TIC) is distinct from DIC","Blood dilution from crystalloid infusion is the sole cause","Coagulopathy in trauma is always a late finding"],correct:1,explain:"Trauma-induced coagulopathy (TIC) begins within minutes of major injury from: tissue factor release at injury sites triggering systemic coagulation activation, hypoperfusion activating protein C (anticoagulant), and endothelial damage causing fibrinolysis. TIC can be severe before any resuscitation fluids have been given."},
    {q:"A tourniquet has been in place for 3 hours when the patient arrives at the hospital. What complication must the surgical team anticipate?",opts:["Tourniquet site infection","Compartment syndrome and reperfusion injury when blood flow is restored","Permanent paralysis in all cases","The tourniquet must be left on permanently"],correct:1,explain:"Prolonged tourniquet application (>2 hours) causes ischemia to distal tissues. When blood flow is restored, reperfusion injury occurs — releasing inflammatory mediators that damage muscle cells. Compartment syndrome (pressure buildup) can develop and may require fasciotomy (surgical release of fascial compartments)."},
    {q:"In a mass casualty event, which patients should receive bleeding control interventions FIRST?",opts:["The most severely injured patient with no vital signs","All patients in order of arrival","Patients with life-threatening hemorrhage who are still conscious and have vital signs","Patients with the least severe injuries to ensure fastest recovery"],correct:2,explain:"In mass casualty triage (SALT or START), bleeding control focuses on patients in the RED (immediate) category — life-threatening bleeding with vital signs present. Patients with no vital signs (BLACK/expectant) receive lowest priority when resources are limited. This maximizes lives saved."},
    {q:"What is the significance of narrowing pulse pressure in a hemorrhaging patient?",opts:["It indicates the patient is stabilizing","Narrowing pulse pressure (systolic–diastolic) is an early sign of volume loss and vasoconstriction — often precedes frank hypotension","It means the tourniquet is too tight","It indicates infection"],correct:1,explain:"Pulse pressure (systolic BP minus diastolic BP) narrows when blood volume decreases — the body constricts peripheral vessels (raising diastolic), while systolic pressure is maintained by increased heart rate. Narrowing pulse pressure can be an earlier warning than absolute hypotension."},
    {q:"Why is wound irrigation contraindicated in the field for penetrating wounds?",opts:["Irrigation causes pain","Irrigation can dislodge forming clots, worsen bleeding, and introduce air into vascular wounds","Irrigation is fine in the field","Irrigation is only contraindicated for abdominal wounds"],correct:1,explain:"Field irrigation or probing of penetrating wounds risks dislodging clots that have formed naturally, potentially causing more severe hemorrhage. Cover and compress — do not irrigate, probe, or remove impaled objects. Leave that for the hospital."},
    {q:"How does hypothermia impair hemorrhage control in major trauma?",opts:["It has no effect on clotting","Hypothermia reduces clotting enzyme function (optimal at 37°C) and impairs platelet aggregation — worsening coagulopathy and increasing bleeding","It causes vasoconstriction that reduces bleeding","Hypothermia only matters after hospital admission"],correct:1,explain:"Clotting is an enzyme-driven process optimized at 37°C. At 34°C, clotting efficiency drops significantly. At <32°C, coagulation is severely impaired. This is why trauma patients must be kept warm — blankets, warm IV fluids, warm resuscitation rooms — as part of damage control resuscitation."},
    {q:"What information must be communicated during EMS handoff for a bleeding patient?",opts:["Only the patient's name and insurance","Time of injury, tourniquet application time, mechanism of injury, estimated blood loss, interventions performed, and changes in patient condition","Only the type of wound","EMS does not need field information"],correct:1,explain:"An effective EMS handoff includes: time of injury (T=), tourniquet time (T=), mechanism of injury, estimated blood loss, all interventions performed, and any changes in mental status or vital signs. This directly guides hospital decision-making and tourniquet management."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"A patient in Class IV hemorrhagic shock has lost >40% of blood volume. Their physiology includes all of the following EXCEPT:",opts:["Heart rate >140 bpm","Severe hypotension","Bradycardia as the primary compensatory mechanism","Loss of consciousness"],correct:2,explain:"Class IV hemorrhage causes TACHYCARDIA (not bradycardia) as the primary compensatory mechanism — the body increases heart rate to maintain cardiac output. Bradycardia in shock (vagally-mediated or terminal) is a pre-arrest sign. All other options — tachycardia, severe hypotension, altered consciousness — are hallmarks of Class IV."},
    {q:"Balanced resuscitation with 1:1:1 (pRBC:FFP:platelets) is superior to crystalloid resuscitation in massive hemorrhage primarily because:",opts:["It avoids the need for surgical intervention","Blood products replace volume AND clotting factors while avoiding the dilutional coagulopathy, hypothermia, and acidosis caused by large crystalloid volumes","It is less expensive than saline","It works faster than IV fluids"],correct:1,explain:"Crystalloid (saline, LR) replaces volume but dilutes clotting factors, lowers body temperature, and can cause hyperchloremic acidosis — all three elements of the lethal triad. Blood products restore both volume and clotting capacity. The PROPPR trial confirmed that 1:1:1 resuscitation reduces 24-hour and 30-day mortality in massive hemorrhage."},
    {q:"Viscoelastic testing (TEG/ROTEM) guides trauma resuscitation by providing which information that standard coagulation tests (INR, PTT) cannot?",opts:["Patient blood type","Real-time assessment of the entire clotting process — initiation, clot strength, and fibrinolysis — allowing goal-directed blood product therapy","Whether a tourniquet was applied correctly","Patient's medication history"],correct:1,explain:"Standard tests (INR, PTT, platelet count) measure individual components and take 30–60 minutes. TEG/ROTEM measures the complete clot formation and lysis process in real time (20–30 minutes), showing exactly which component is deficient — fibrinogen (needs cryoprecipitate), factors (needs FFP), platelets (needs platelet transfusion) or fibrinolysis (needs TXA). This guides targeted, goal-directed therapy."},
    {q:"In the context of damage control surgery (DCS), what is the correct sequence of care?",opts:["Full definitive repair immediately, then ICU, then rehabilitation","Abbreviated hemorrhage/contamination control in OR → ICU resuscitation (correct lethal triad) → planned return to OR for definitive repair","ICU stabilization first, then surgery when patient is stronger","Surgery is deferred until all blood products are available"],correct:1,explain:"DCS is staged: (1) Abbreviated OR — stop bleeding (packing, ligation, shunts), control contamination, close temporarily; (2) ICU — correct hypothermia, acidosis, coagulopathy with blood products; (3) Return to OR (24–72 hours) — definitive anatomic repair. This approach prevents the lethal triad from killing the patient during a prolonged initial surgery."},
    {q:"A patient with von Willebrand disease type 3 sustains a major laceration. Standard field hemostatic dressings are applied. Why might hospital treatment differ significantly from a patient without a bleeding disorder?",opts:["No difference — bleeding disorders don't affect wound healing","vWD Type 3 patients lack von Willebrand factor and may also have low Factor VIII — bleeding will continue despite local measures until vWF concentrate and Factor VIII are replaced","They need a higher tourniquet pressure","Standard tourniquets are contraindicated in bleeding disorders"],correct:1,explain:"von Willebrand factor (vWF) is essential for platelet adhesion to damaged vessel walls and carries Factor VIII. Type 3 vWD (complete absence of vWF) causes severe bleeding that local hemostatics and tourniquets cannot fully control — vWF concentrate (Humate-P, Wilate) with Factor VIII is required. Field care buys time; definitive treatment is factor replacement."},
    {q:"REBOA (Resuscitative Endovascular Balloon Occlusion of the Aorta) is contraindicated in which zone for hemorrhage from a pelvic fracture?",opts:["Zone I (descending thoracic aorta) — indicated here","Zone III (infra-renal aorta) — most appropriate for pelvic hemorrhage","Zone II (visceral aorta) — contraindicated due to renal and mesenteric ischemia","Zone IV (iliac arteries) — indicated here"],correct:2,explain:"REBOA is placed in Zone I (descending thoracic aorta, above celiac) for abdominal/thoracic hemorrhage or Zone III (infra-renal, below renal arteries) for pelvic hemorrhage. Zone II is contraindicated — inflation here occludes the renal and mesenteric vessels, causing immediate ischemic injury to kidneys and bowel. Zone III inflation for pelvic hemorrhage maintains renal perfusion while reducing pelvic hemorrhage."},
    {q:"The CRASH-2 trial's primary finding regarding TXA administration timing has which clinical implication for Stop the Bleed-trained bystanders and first responders?",opts:["Bystanders should carry TXA and administer it immediately","First responders who can administer medications should consider early TXA — and report accurate injury time to hospital so the 3-hour window can be tracked","TXA has no role in prehospital care","TXA should only be given after blood pressure is stabilized"],correct:1,explain:"CRASH-2 showed TXA reduces trauma mortality when given within 1–3 hours of injury. While bystanders cannot administer IV TXA, first responders (paramedics) should consider early TXA administration. Critically, accurate documentation of injury time (by any bystander) allows the hospital team to determine if TXA is still within its therapeutic window — another way bystander documentation saves lives."},
  ]);
})();

(function(){
  if(!window.QB_STOP_BLEED) return;
  var fc = window.QB_STOP_BLEED.flashcards;
  var qz = window.QB_STOP_BLEED.quiz;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});
  fc.hard = fc.hard.concat([{"term":"Balanced resuscitation (1:1:1)","def":"Equal ratio of packed red blood cells: fresh frozen plasma: platelets — replaces whole blood components","breakdown":"Avoids crystalloid dilution of clotting factors. PRBCs restore oxygen carrying capacity. FFP replaces coagulation factors. Platelets support primary hemostasis. Military origin: Damage Control Resuscitation"}]);
  qz.easy=qz.easy.concat([{"q":"What does the 'ABC' of bleeding control stand for?","opts":["Airway, Breathing, Circulation","Alert, Bleeding control, Care","Assess, Bandage, Call","Apply, Bind, Compress"],"correct":1,"explain":"The Stop the Bleed ABC stands for: Alert (call 911), Bleeding control (apply pressure or tourniquet), Care (maintain until EMS arrives). This simplified framework helps bystanders remember the sequence of actions during a bleeding emergency."},{"q":"Where should a tourniquet be placed on the leg?","opts":["Directly over the wound","On the knee joint","2-3 inches above the wound","At the ankle"],"correct":2,"explain":"A tourniquet should be placed 2-3 inches ABOVE the wound (between the wound and the heart) on the limb. Never place on a joint. 'High and tight' is the guideline — when in doubt, place higher up the limb."},{"q":"A wound is bleeding heavily from the thigh. What is the BEST first action?","opts":["Apply a pressure dressing","Apply a tourniquet 2-3 inches above the wound","Pack the wound with gauze","Apply ice to slow bleeding"],"correct":1,"explain":"For life-threatening extremity bleeding (like a thigh wound), a tourniquet is the fastest and most effective intervention. Apply it 2-3 inches above the wound and tighten until bleeding completely stops. Wound packing is used when tourniquets cannot be applied (groin, armpit, neck)."},{"q":"A tourniquet has been applied and the wound is bleeding controlled. EMS is 5 minutes away. Should you remove the tourniquet?","opts":["Yes, to allow blood flow back","Yes, if the patient asks you to","No — never remove a tourniquet once applied","Yes, after exactly 10 minutes"],"correct":2,"explain":"NEVER remove a tourniquet once it has been applied and bleeding is controlled. Only medical personnel should remove a tourniquet. Removal can restart hemorrhage and precipitate shock. Always note the time of application and communicate it to EMS."},{"q":"When should wound packing be used instead of a tourniquet?","opts":["When the wound is small","For wounds on the neck, armpit, or groin where a tourniquet cannot be placed","When the patient refuses a tourniquet","Only when trained medical personnel are present"],"correct":1,"explain":"Wound packing is used for junctional wounds — neck, armpit, groin, buttocks — where a tourniquet cannot encircle the limb. Pack tightly into the wound cavity with gauze, apply firm direct pressure for at least 3 minutes. Junctional wounds are a leading cause of preventable trauma death."},{"q":"How should you respond if a bandage on a wound becomes soaked with blood?","opts":["Remove and replace the bandage","Apply more material on top without removing","Apply ice to slow bleeding","Elevate and massage the limb"],"correct":1,"explain":"Do NOT remove the original dressing — removing it can disrupt any clot that has begun to form. Instead, add more material on top and continue applying firm pressure. If bleeding continues despite this, consider upgrading to a tourniquet if on an extremity."},{"q":"What is the Stop the Bleed program?","opts":["A hospital protocol for blood transfusions","A national initiative teaching civilians to control life-threatening bleeding before EMS arrives","A first aid certification required for all students","A military-only bleeding control program"],"correct":1,"explain":"Stop the Bleed is a national awareness campaign launched in 2015 teaching the general public how to control life-threatening bleeding. Based on military tourniquet success in combat, the program has trained millions of civilians. The goal: bystander intervention in the critical minutes before EMS arrives."},{"q":"Which body area CANNOT be treated with a tourniquet and requires wound packing?","opts":["Upper arm","Thigh","Groin","Forearm"],"correct":2,"explain":"The groin (and armpit and neck) cannot be treated with a tourniquet because you cannot encircle these areas to cut off blood flow. Wound packing — tightly filling the wound cavity with gauze and applying firm pressure — is the appropriate intervention for junctional bleeding."},{"q":"After applying a tourniquet, what important information should be communicated to EMS?","opts":["The patient's name and insurance","The time the tourniquet was applied","The color of the tourniquet","How much blood was lost before application"],"correct":1,"explain":"The time of tourniquet application is critical medical information — it helps medical personnel assess how long the limb has been without blood flow and make decisions about tourniquet management. Write the time on the tourniquet with a marker or on the patient's skin."},{"q":"A student has a deep stab wound to the shoulder (not on the limb). What is the appropriate treatment?","opts":["Apply a tourniquet to the neck","Pack the wound with gauze and apply firm pressure","Apply ice and elevate the arm","Do nothing — wait for EMS"],"correct":1,"explain":"A deep wound at the shoulder junction cannot be controlled with a tourniquet (cannot encircle the area). Pack the wound tightly with gauze — fill the entire cavity — then apply firm, sustained direct pressure for at least 3 minutes. This is wound packing for a junctional wound."},{"q":"What are signs that indicate a victim may be losing dangerous amounts of blood?","opts":["Flushed red skin and fever","Pale, cool, clammy skin; rapid weak pulse; confusion; and thirst","Bright red skin and high energy","Increased blood pressure and slow pulse"],"correct":1,"explain":"Signs of significant blood loss (hypovolemic shock): pale/cool/clammy skin, rapid and weak pulse, confusion or altered mental status, extreme thirst, and rapid breathing. These develop when 15-30% of blood volume is lost. Immediate bleeding control and EMS activation are critical."},{"q":"Which material is NOT appropriate for an improvised tourniquet?","opts":["A wide belt","A folded bandana (2+ inches wide)","A necktie","A thin rope or bungee cord"],"correct":3,"explain":"Thin ropes, bungee cords, or wire should NEVER be used as improvised tourniquets — they concentrate pressure on a narrow band, causing severe tissue and nerve damage without effectively stopping arterial blood flow. Any improvised tourniquet must be at least 2 inches wide."}]);
  qz.medium=qz.medium.concat([{"q":"What is hemostatic gauze and how does it improve bleeding control?","opts":["Normal gauze with extra absorbency","Gauze treated with clotting agents (kaolin or chitosan) that accelerates clot formation","Gauze that can be left in wounds permanently","A type of bandage that applies automatic pressure"],"correct":1,"explain":"Hemostatic gauze (QuikClot uses kaolin, HemCon uses chitosan) is impregnated with agents that accelerate the body's natural clotting process. It is more effective than plain gauze for severe bleeding, especially in wounds where direct pressure alone is insufficient. Pack into wound and hold firm pressure for 3 minutes."},{"q":"A tourniquet has been on for 2 hours. What should a rescuer do?","opts":["Remove it immediately to restore circulation","Loosen it slightly to allow some blood flow","Keep it in place and continue communicating time of application to medical personnel","Replace it with a new tourniquet"],"correct":2,"explain":"Keep the tourniquet in place and communicate the exact time of application to medical personnel. Only trained medical personnel in a clinical setting should evaluate removing or converting a tourniquet. While prolonged application (>2 hours) can cause nerve and muscle damage, uncontrolled hemorrhage is more immediately life-threatening."},{"q":"The 'lethal triad' in trauma refers to which three conditions that worsen bleeding?","opts":["Pain, confusion, and rapid pulse","Hypothermia, acidosis, and coagulopathy","Hypoxia, hypotension, and hypoglycemia","Dehydration, infection, and blood loss"],"correct":1,"explain":"The lethal triad: hypothermia (cold impairs clotting enzymes), acidosis (from shock and poor perfusion), and coagulopathy (impaired clotting from blood loss and dilution). These three conditions are mutually worsening — each makes the others worse. Prevention: keep patient warm, control bleeding early, limit saline."},{"q":"Why is TXA (tranexamic acid) time-sensitive in trauma?","opts":["It becomes toxic after 3 hours","It only works during active bleeding","Research shows no benefit when given more than 3 hours after injury, and possible harm","It must be given before tourniquet application"],"correct":2,"explain":"The CRASH-2 trial showed TXA significantly reduces hemorrhagic death when given within 3 hours of injury — but provides no benefit (and may cause harm) when given after 3 hours. TXA prevents fibrinolysis (premature clot dissolution). This strict time window makes early administration critical."},{"q":"How does wound packing work physiologically to control bleeding?","opts":["It chemically dissolves blood clots","It physically fills the wound cavity, applying pressure to bleeding vessels and supporting clot formation","It absorbs blood to prevent shock","It seals blood vessels with adhesive"],"correct":1,"explain":"Wound packing works by physically filling the wound cavity with gauze, applying direct pressure to bleeding vessels from within the wound. This mechanical compression slows blood flow, allowing the natural coagulation cascade to form a stable clot. Hemostatic gauze also activates platelets and clotting factors at the wound site."}]);
  qz.hard=qz.hard.concat([{"q":"A patient has a junctional groin wound with arterial bleeding. Wound packing has been applied with firm pressure for 3 minutes. Bleeding continues. What is the next step?","opts":["Remove the packing and apply fresh gauze","Apply a tourniquet to the leg above the knee","Re-pack more tightly with additional hemostatic gauze and maintain firm pressure, consider junctional tourniquet device","Apply ice to the groin"],"correct":2,"explain":"If initial wound packing fails: re-pack more tightly (the first attempt may not have filled the cavity completely), use hemostatic gauze if available, and maintain firm sustained pressure. Junctional tourniquet devices (SAM Junctional Tourniquet, JETT) can apply pneumatic pressure to the groin. Leg tourniquet above the knee is NOT effective for groin bleeding — the femoral artery originates above the tourniquet site."},{"q":"In damage control resuscitation, why are crystalloids (normal saline, Lactated Ringer's) limited?","opts":["They are too expensive","They dilute clotting factors, worsen coagulopathy, contribute to hypothermia, and increase risk of abdominal compartment syndrome","They cause allergic reactions","They raise blood pressure too quickly"],"correct":1,"explain":"Large-volume crystalloid resuscitation worsens the lethal triad: (1) dilutes clotting factors → worsening coagulopathy, (2) is administered at room temperature → contributes to hypothermia, (3) can cause third-spacing → abdominal compartment syndrome. Damage control resuscitation uses balanced blood products (1:1:1 PRBCs:FFP:platelets) to replace what was lost."}]);
})();

(function(){
  if(!window.QB_MEDICAL_READING) return;
  var fc=window.QB_MEDICAL_READING.flashcards,qz=window.QB_MEDICAL_READING.quiz;
  if(!fc||!qz) return;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});
  fc.easy=fc.easy.concat([{"term":"2025-2026 HOSA Medical Reading books","def":"Gifted Hands (Carson), The Immortal Life of Henrietta Lacks (Skloot), The Hot Zone (Preston), When Breath Becomes Air (Kalanithi), Wonder (Palacio), Chasing My Cure (Fajgenbaum)","breakdown":"Selected to commemorate HOSA's 50th anniversary — books spanning the decades. Test covers plot, characters, themes, medical content, and connections to health careers"},{"term":"Gifted Hands — Ben Carson","def":"Autobiography of neurosurgeon Ben Carson — from poverty in Detroit to leading pediatric neurosurgeon at Johns Hopkins","breakdown":"Key themes: perseverance, faith, education, beating the odds. First surgeon to successfully separate twins joined at the head. Important: how education transformed his life trajectory"},{"term":"Henrietta Lacks — Rebecca Skloot","def":"Story of HeLa cells — first immortal human cell line taken from Henrietta Lacks without consent in 1951","breakdown":"Key themes: medical ethics, informed consent, race and medicine, scientific legacy vs human cost. HeLa cells used in polio vaccine, cancer research. Family never compensated"},{"term":"HeLa cells","def":"First immortal human cancer cell line — taken from Henrietta Lacks' cervical cancer without consent","breakdown":"'HeLa' = Henrietta Lacks. Grew outside body indefinitely — revolutionary for research. Used in 60,000+ research publications. Debate: who owns cells removed from your body?"},{"term":"Informed consent (Henrietta Lacks context)","def":"Medical ethics principle violated in 1951 — Lacks' cells were taken without knowledge or permission","breakdown":"Now foundational in medical research ethics. Nuremberg Code (1947) and Belmont Report (1979) developed partly in response to such violations. Patients must consent to tissue use in research"},{"term":"The Hot Zone — Richard Preston","def":"Account of 1989 Ebola outbreak in Reston, Virginia primate facility and origins of Ebola virus in Africa","breakdown":"Key themes: infectious disease, biosafety, human risk, Ebola's origins. First U.S. filovirus outbreak — affected monkeys, not humans (Reston strain). Basis for understanding BSL-4 lab protocols"},{"term":"Ebola virus disease","def":"Severe hemorrhagic fever with 25-90% mortality — viral hemorrhage, organ failure, massive bleeding","breakdown":"Filovirus. Spread by direct contact with infected bodily fluids. BSL-4 pathogen. Fruit bats: reservoir hosts. No effective treatment historically; Inmazeb approved 2020. African origin"},{"term":"When Breath Becomes Air — Paul Kalanithi","def":"Memoir by neurosurgeon diagnosed with terminal lung cancer at 36 — explores life, death, and meaning","breakdown":"Key themes: physician perspective on dying, what makes life meaningful, identity crisis when doctor becomes patient. Written while dying. Published posthumously. Won numerous awards"},{"term":"Wonder — R.J. Palacio","def":"Novel about Auggie Pullman, a boy with facial differences (Treacher Collins syndrome) entering 5th grade","breakdown":"Key themes: inclusion, kindness, disability, identity, bullying, acceptance. Medical content: craniofacial anomalies. 'Be kind, for everyone is fighting a hard battle' — core theme"},{"term":"Chasing My Cure — David Fajgenbaum","def":"Memoir of physician-researcher who developed life-threatening Castleman disease and helped find his own treatment","breakdown":"Key themes: rare disease, perseverance, physician-as-patient, medical research process, drug repurposing. Founded Castleman Disease Collaborative Network. Autobiographical and scientific"},{"term":"Author vs narrator distinction","def":"Author: real person who wrote the book. Narrator: voice telling the story (may be fictional character)","breakdown":"Important for HOSA test: in memoirs (Carson, Kalanithi, Fajgenbaum, Lacks): author = narrator. In fiction (Wonder): author is Palacio, narrator is Auggie/other characters"},{"term":"Non-fiction vs memoir","def":"Non-fiction: factual account. Memoir: personal first-person account of author's own experience","breakdown":"Gifted Hands, When Breath Becomes Air, Chasing My Cure: memoirs. Immortal Life: narrative non-fiction (Skloot is author but not protagonist). Hot Zone: narrative non-fiction. Wonder: fiction"},{"term":"Theme vs plot","def":"Plot: what happens (events). Theme: what it means (underlying message/lesson)","breakdown":"HOSA Medical Reading tests both. Theme in Gifted Hands: perseverance overcomes obstacles. Theme in Wonder: choose kindness. Theme in Lacks book: science without ethics causes harm"},{"term":"Medical ethics principles (4)","def":"Autonomy, Beneficence, Non-maleficence, Justice — the four pillars of medical ethics","breakdown":"Autonomy: patient's right to decide. Beneficence: do good. Non-maleficence: do no harm. Justice: fair treatment. Henrietta Lacks case violated autonomy and justice. Used in every medical ethics discussion"},{"term":"Biosafety level 4 (BSL-4)","def":"Highest level containment laboratory — for extremely dangerous pathogens with no treatment or vaccine","breakdown":"Full positive-pressure suit. Air showers. Negative pressure. Examples: Ebola, Marburg, smallpox. Featured in The Hot Zone. Only ~40 BSL-4 labs worldwide"},{"term":"Point of view (POV) in medical narratives","def":"First-person: narrator is in the story. Third-person: narrator outside the story. Second-person: 'you'","breakdown":"Memoirs use first-person. Wonder uses multiple first-person narrators (Auggie, Via, Jack, Summer, Julian's mom). The Hot Zone: third-person. Immortal Life: mixed (Skloot first-person + Lacks family third-person)"},{"term":"Annotation techniques","def":"Active reading: underlining, marginal notes, questions, summarizing key passages","breakdown":"HOSA Medical Reading tests comprehension, not just recall. Annotation helps: mark medical terms, ethical dilemmas, character decisions, themes. Particularly useful for identifying medical content connections"},{"term":"Foreshadowing","def":"Author's use of hints or clues about future events — important literary device in medical narratives","breakdown":"In When Breath Becomes Air: Kalanithi's descriptions of other patients' deaths foreshadow his own. In The Hot Zone: descriptions of Ebola symptoms foreshadow later human exposure. Test questions may ask about foreshadowing"}]);
  fc.medium=fc.medium.concat([{"term":"Henrietta Lacks — race and medicine","def":"Her cells were taken without consent, partly reflecting systemic devaluation of Black patients' autonomy in 1950s","breakdown":"Historical context: 1951 Baltimore. Segregated hospital wards. Black patients had less power to refuse. HeLa cells generated billions in pharmaceutical value; family received nothing and couldn't afford healthcare"},{"term":"Ben Carson — early life challenges","def":"Raised in poverty in Detroit by single mother, struggled academically early, transformed by reading program","breakdown":"Mother couldn't read but required Ben and Curtis to write book reports. Reading transformed Carson's trajectory. Themes of resilience, education as equalizer, parental influence, faith"},{"term":"Paul Kalanithi — identity crisis","def":"Shifts from doctor (expert) to patient (vulnerable) when diagnosed — explores what remains of identity when career is gone","breakdown":"Central tension of book: who am I when I can't be a surgeon? Wife is also physician. Wrote book while dying from cancer treatment. Published posthumously by wife Lucy. What gives life meaning?"},{"term":"David Fajgenbaum — drug repurposing","def":"Found that sirolimus (transplant drug) controlled his Castleman disease — systematic search through FDA-approved drugs","breakdown":"Searched for existing drugs with anti-inflammatory properties that might work for Castleman. Approach: mine published data for drugs affecting relevant pathways. Saved his own life, now helps others. CDCN founded"},{"term":"Auggie Pullman — inclusion themes","def":"Mainstreamed student with significant facial difference — navigates friendship, bullying, identity, belonging","breakdown":"Wonder explores who is 'different' from whose perspective. Auggie is the same inside. Other characters' POVs reveal their own struggles. 'Ordinary' is a theme — everyone is extraordinary in their struggles"},{"term":"Zaire Ebola vs Reston Ebola","def":"Zaire: fatal to humans (70-90% mortality). Reston: fatal to monkeys but NOT to humans — both in The Hot Zone","breakdown":"The 1989 Reston outbreak: monkeys dying in Reston, VA lab. Workers exposed — none got sick. Reston strain: airborne between primates but not lethal to humans. Lucky. Zaire strain is the one causing human outbreaks"},{"term":"Rebecca Skloot — narrative technique","def":"Weaves two narratives: Skloot's investigative journey + Lacks family history — alternates perspectives and time periods","breakdown":"Scientific narrative (HeLa cells, research) intercut with human narrative (Henrietta's life, family's pain). Technique shows how separate worlds of science and humanity affect each other. Won NBCC award"},{"term":"Medical research ethics — Belmont Report","def":"1979 federal report establishing three principles for human research ethics: respect, beneficence, justice","breakdown":"Response to Tuskegee and other abuses. Respect = informed consent. Beneficence = maximize benefit, minimize harm. Justice = fair subject selection. Still governs IRB (institutional review board) oversight"},{"term":"Tuskegee Syphilis Study connection","def":"1932-1972 U.S. government study withholding syphilis treatment from Black men — linked to ongoing medical distrust","breakdown":"Henrietta Lacks and Tuskegee: both illustrate historical exploitation of Black Americans in medicine. Tuskegee: treatment withheld. Lacks: tissue taken. Both violated autonomy and justice. Legacy: medical distrust in Black communities today"},{"term":"Palliative care vs curative care","def":"Palliative: comfort-focused, manages symptoms. Curative: aims to eliminate disease","breakdown":"Kalanithi's When Breath Becomes Air explores the transition from curative to palliative goals. Palliative care is appropriate when cure is not possible. Does not hasten death — manages suffering"},{"term":"Character vs theme distinction","def":"Character: person in the story with traits, motivations, development. Theme: universal message that transcends story","breakdown":"Character: Auggie is kind, resilient, funny. Theme: everyone deserves to belong. HOSA tests ask about both. Themes are stated or implied — identify them from character actions and author's message"},{"term":"Medical terminology in fiction context","def":"Wonder: craniosynostosis, mandibulofacial dysostosis, stapedectomy, tracheotomy. Hot Zone: hemorrhage, filovirus, viremia","breakdown":"HOSA test may ask about medical terms in context of books. Know what Auggie's surgeries involved. Know what Ebola does to the body (hemorrhage, organ failure). Connect book content to medical knowledge"},{"term":"Irony in medical memoirs","def":"Dramatic irony: reader knows something characters don't. Situational: unexpected outcome. Verbal: saying opposite of meaning","breakdown":"When Breath Becomes Air: irony that a neurosurgeon studying death dies young from cancer. Chasing My Cure: irony that a medical student develops a rare disease he then helps cure. Common test question type"},{"term":"Allusion","def":"Reference to another work, historical event, or cultural touchstone","breakdown":"Kalanithi alludes extensively to T.S. Eliot and Whitman. The Hot Zone alludes to outbreak movies. Gifted Hands alludes to biblical stories. HOSA may ask about significant allusions in the books"},{"term":"Tone vs mood","def":"Tone: author's attitude toward subject (determined by word choice). Mood: reader's emotional response","breakdown":"When Breath Becomes Air: tone is reflective, philosophical, often accepting. Mood: somber, contemplative, hopeful. Wonder: tone often hopeful/warm. Mood: emotional, uplifting despite challenges. Different things, easily confused"}]);
  fc.hard=fc.hard.concat([{"term":"HeLa cell contamination crisis","def":"HeLa cells contaminated thousands of other cell cultures globally — discovered in 1960s-1970s, denied by scientists","breakdown":"HeLa cells grow so aggressively they can contaminate and overtake other cell cultures. Major scientific crisis. Some scientists who discovered contamination were discredited. Lesson: scientific culture, reproducibility, transparency"},{"term":"Henrietta Lacks estate and bioethics","def":"Debate: who owns cells/tissue removed from a body? U.S. courts ruled patients have no property rights to removed tissue","breakdown":"Moore v. Regents of UC (1990): John Moore's cancer cells patented — court ruled he had no property rights. Lacks family received no compensation. HELA cell use ongoing. Genome published without consent in 2013 — withdrawn after family protest"},{"term":"Castleman disease pathophysiology","def":"Abnormal lymph node growth driven by IL-6 overproduction — causes multi-organ failure in idiopathic MCD","breakdown":"IL-6: pro-inflammatory cytokine. TAFRO syndrome subtype: Thrombocytopenia, Anasarca, Fever, Reticulin fibrosis, Organomegaly. Siltuximab (anti-IL-6): approved treatment. Sirolimus: Fajgenbaum's discovery. Extremely rare"},{"term":"Narrative medicine","def":"Medical discipline using storytelling to improve physician empathy, patient communication, and clinical care","breakdown":"Rita Charon (Columbia): founded narrative medicine. Reading literature builds empathy by inhabiting others' perspectives. HOSA Medical Reading embodies this philosophy — medical knowledge + human stories"},{"term":"Hemostatic fever viral disease classification","def":"Filoviruses (Ebola, Marburg), Arenaviruses (Lassa), Bunyaviruses (Hantavirus) — viral hemorrhagic fevers in The Hot Zone","breakdown":"Feature: damage to vascular endothelium → bleeding. Filoviruses: characteristic filamentous appearance. CDC Category A bioterrorism agents (Ebola, Marburg). BSL-4 containment required. No effective treatment historically"}]);
  qz.easy=qz.easy.concat([{"q":"Which book tells the story of HeLa cells and their original owner, Henrietta Lacks?","opts":["Gifted Hands","The Immortal Life of Henrietta Lacks","The Hot Zone","Chasing My Cure"],"correct":1,"explain":"The Immortal Life of Henrietta Lacks by Rebecca Skloot tells the story of how Henrietta Lacks' cancer cells were taken without her consent in 1951 and became the first immortal human cell line — used in thousands of scientific studies while her family remained in poverty and didn't know for decades."},{"q":"What is the central theme of Wonder by R.J. Palacio?","opts":["The dangers of modern medicine","Kindness, inclusion, and the value of every person regardless of appearance","How genetics determines personality","The history of facial surgery"],"correct":1,"explain":"Wonder's central theme is the importance of kindness and the value of every person. The story of Auggie Pullman — a boy with a facial difference entering mainstream school — explores how choosing kindness transforms communities. The school's motto: 'When given the choice between being right and being kind, choose kind.'"},{"q":"Ben Carson's autobiography Gifted Hands describes his journey to become a:","opts":["Heart surgeon","Oncologist","Pediatric neurosurgeon","General practitioner"],"correct":2,"explain":"Gifted Hands tells the story of Ben Carson's journey from poverty in Detroit to becoming one of the world's leading pediatric neurosurgeons at Johns Hopkins Hospital. He is famous for being the first surgeon to successfully separate twins who were joined at the head (craniopagus twins) in 1987."},{"q":"What virus is the focus of The Hot Zone by Richard Preston?","opts":["HIV","Influenza","Ebola virus","SARS-CoV-2"],"correct":2,"explain":"The Hot Zone by Richard Preston tells the true story of the 1989 Ebola outbreak in a Reston, Virginia primate research facility and traces the origins of the Ebola virus in Africa. The book is known for its detailed, visceral descriptions of what Ebola does to the human body."},{"q":"Paul Kalanithi wrote When Breath Becomes Air while:","opts":["Completing his residency","Retired from medicine","Dying from stage IV lung cancer","Studying philosophy in college"],"correct":2,"explain":"Paul Kalanithi, a neurosurgeon at Stanford, was diagnosed with stage IV lung cancer at age 36 and wrote When Breath Becomes Air while undergoing treatment and dying from the disease. The book explores life, death, meaning, and the experience of a doctor becoming a patient. It was published posthumously in 2016."},{"q":"What medical condition does Auggie Pullman have in Wonder?","opts":["Down syndrome","Treacher Collins syndrome (mandibulofacial dysostosis)","Cerebral palsy","Spina bifida"],"correct":1,"explain":"Auggie Pullman has a form of mandibulofacial dysostosis (similar to Treacher Collins syndrome) — a genetic condition causing underdevelopment of facial bones and tissues. He has had 27 surgeries by the time the story begins. The condition affects his appearance but not his intelligence or personality."},{"q":"Henrietta Lacks' cells were taken in which year?","opts":["1935","1945","1951","1963"],"correct":2,"explain":"Henrietta Lacks' cancer cells were collected at Johns Hopkins Hospital in 1951 without her knowledge or consent. They were given to researcher George Gey, who discovered they could survive and multiply outside the body indefinitely — creating the first immortal human cell line, named HeLa."},{"q":"What does 'HeLa' stand for?","opts":["Health Laboratory","Henrietta Lacks","Helen Lazar","Human Leukemia"],"correct":1,"explain":"HeLa stands for Henrietta Lacks — the cells were named using the first two letters of her first and last name. This was the naming convention used by the lab at the time to code cell samples. The name was kept secret for decades; the public didn't know who HeLa came from until much later."},{"q":"David Fajgenbaum in Chasing My Cure is remarkable because he:","opts":["Discovered the Ebola vaccine","Was the first neurosurgeon to separate conjoined twins","Developed Castleman disease as a medical student and helped find his own treatment","Identified the HeLa cell contamination problem"],"correct":2,"explain":"David Fajgenbaum developed a rare and life-threatening disease (Castleman disease) while in medical school, nearly died five times, and systematically searched through FDA-approved drugs to find a treatment that worked for him (sirolimus). He founded the Castleman Disease Collaborative Network to help others."},{"q":"Which of the 2025-2026 Medical Reading books is a work of FICTION?","opts":["Gifted Hands","When Breath Becomes Air","Wonder","Chasing My Cure"],"correct":2,"explain":"Wonder by R.J. Palacio is a novel — a work of fiction. Auggie Pullman and all characters are invented. The other three options (Gifted Hands, When Breath Becomes Air, Chasing My Cure) are memoirs — non-fiction accounts by real people about their real experiences."},{"q":"The ethical issue at the center of The Immortal Life of Henrietta Lacks is primarily:","opts":["Whether cancer is hereditary","Informed consent — Lacks' cells were taken and used without her knowledge or permission","Whether HeLa cells are scientifically valuable","The dangers of working in cancer research"],"correct":1,"explain":"The central ethical issue is informed consent — Henrietta Lacks' cancer cells were removed during a medical procedure in 1951 without her knowledge, consent, or any explanation of how they would be used. This was legal at the time but would violate today's research ethics standards. Her family struggled financially while her cells generated enormous scientific and commercial value."},{"q":"What is the significance of the 2025-2026 Medical Reading book selection for HOSA?","opts":["The books are all written by HOSA members","The selection commemorates HOSA's 50th anniversary with books spanning the decades","All books are about the same disease","The books are only about pediatric medicine"],"correct":1,"explain":"The 2025-2026 Medical Reading books were selected to commemorate HOSA's 50th anniversary (1976-2026). The books span different decades, health topics, and perspectives on medicine — from neurosurgery (Carson) to viral outbreak (Preston) to patient advocacy (Fajgenbaum) — representing the breadth of health careers HOSA has supported over 50 years."},{"q":"What literary device is used when an author hints at future events in the story?","opts":["Flashback","Foreshadowing","Allusion","Irony"],"correct":1,"explain":"Foreshadowing is the use of hints or clues early in a narrative to suggest events that will happen later. In When Breath Becomes Air, Kalanithi's descriptions of treating dying patients foreshadow his own death. In The Hot Zone, the descriptions of Ebola's effects on African patients foreshadow the Reston outbreak."},{"q":"The four principles of medical ethics are:","opts":["Safety, Efficacy, Equity, Access","Autonomy, Beneficence, Non-maleficence, Justice","Respect, Research, Results, Resources","Prevention, Diagnosis, Treatment, Recovery"],"correct":1,"explain":"The four pillars of medical ethics are: Autonomy (patient's right to make informed decisions), Beneficence (duty to do good), Non-maleficence (duty to do no harm — 'primum non nocere'), and Justice (fair treatment). These principles are violated in Henrietta Lacks' story and form the foundation of bioethics education."},{"q":"A 'memoir' differs from an 'autobiography' in that:","opts":["A memoir is always fiction","A memoir focuses on a specific period or theme rather than an entire life story","An autobiography is always shorter","A memoir must be written about a famous person"],"correct":1,"explain":"A memoir focuses on a specific period, event, or theme from the author's life — not the entire life story (which is an autobiography). When Breath Becomes Air is a memoir about Kalanithi's final years facing cancer. Chasing My Cure is a memoir about Fajgenbaum's illness and research. Both are written in first person about personal experience."}]);
  qz.medium=qz.medium.concat([{"q":"Why did the publication of Henrietta Lacks' genome in 2013 cause controversy, and what was the resolution?","opts":["Scientists disputed the genome's accuracy","It revealed genetic information about living family members who had not consented — the genome was later restricted with family involvement in access decisions","The genome proved HeLa cells were not from Lacks","The publication was a hoax"],"correct":1,"explain":"When researchers published the HeLa cell genome in 2013, the Lacks family objected because the genome revealed private genetic information about living family members — without their consent. After negotiations, NIH established a policy requiring researchers to apply for access to HeLa genomic data, with Lacks family representatives on the review board — a landmark decision in genomic privacy."},{"q":"How does Paul Kalanithi's experience as a patient change his perspective on medicine compared to his previous role as a physician?","opts":["He becomes more critical of the medical system","He gains empathy for what patients experience — uncertainty, vulnerability, loss of identity — that cannot be fully understood from the physician's side","He concludes that medicine is ineffective","He becomes less interested in patient communication"],"correct":1,"explain":"When Breath Becomes Air's core tension is Kalanithi's shift from the physician (who delivers news and controls care) to the patient (who receives news and depends on others). He discovers that the uncertainty patients face cannot be fully understood from the other side. This perspective shift is central to narrative medicine — reading such accounts builds physician empathy."},{"q":"The Reston Ebola outbreak in The Hot Zone was particularly alarming because:","opts":["It killed hundreds of people in Virginia","The Reston strain was airborne between primates — suggesting Ebola could spread via air — but fortunately was not lethal to humans","It was caused by laboratory contamination of water supply","Government officials covered it up completely"],"correct":1,"explain":"The Reston outbreak was alarming because the Reston strain appeared to spread via airborne route between monkey cages — not just direct contact. This suggested that if a lethal strain like Zaire Ebola acquired airborne transmission, it could be catastrophic. Fortunately, Reston strain causes no disease in humans. Several workers tested positive for antibodies but remained well."},{"q":"David Fajgenbaum's approach to finding a treatment for his own Castleman disease demonstrates which research strategy?","opts":["Developing entirely new drugs from scratch","Drug repurposing — systematically searching FDA-approved drugs for ones that might affect relevant disease pathways","Conducting traditional clinical trials with healthy volunteers","Using herbal remedies instead of pharmaceutical drugs"],"correct":1,"explain":"Fajgenbaum used drug repurposing — mining published scientific literature and databases to identify FDA-approved drugs that affect the interleukin-6 (IL-6) pathway that was overactive in his Castleman disease. He found sirolimus (an immunosuppressant used in organ transplant) and tried it on himself. Drug repurposing is faster and cheaper than developing new drugs — a growing strategy in rare disease research."},{"q":"What is the difference between 'tone' and 'mood' in a literary work?","opts":["They are identical — two words for the same concept","Tone is the author's attitude toward the subject; mood is the emotional atmosphere the reader experiences","Mood is the author's attitude; tone is the reader's feeling","Tone applies only to non-fiction; mood only to fiction"],"correct":1,"explain":"Tone is the author's attitude toward the subject, revealed through word choice (e.g., Kalanithi's tone is philosophical and accepting). Mood is the emotional atmosphere the reader experiences (somber, hopeful, tense). HOSA tests may ask you to identify both. They are related but distinct — the same tone can create different moods in different readers."},{"q":"Multiple narrators in Wonder (Auggie, Via, Jack, Summer, Julian's mom) serve which literary purpose?","opts":["To confuse the reader intentionally","To show that the same events look completely different from different perspectives — building empathy for all characters","Because Palacio couldn't decide on a single narrator","To make the book longer"],"correct":1,"explain":"Multiple narrators in Wonder serve to show how the same events, the same person (Auggie), and the same school year look radically different depending on who is experiencing them. Each narrator has blind spots and private struggles. This structure builds empathy — we see Auggie through other eyes, and we see the 'normal' kids struggling with their own difficulties. A key theme: everyone is fighting a hard battle."},{"q":"How does Rebecca Skloot's narrative technique in The Immortal Life of Henrietta Lacks differ from a standard biography?","opts":["Skloot only focuses on the science, avoiding the human story","Skloot weaves her own investigative journey alongside the Lacks family's story, making the author herself a character","Skloot uses entirely fictional composite characters","The book is told entirely from Henrietta's first-person perspective"],"correct":1,"explain":"Skloot uses a dual-narrative structure: her own investigative journey (reporting the book, building trust with Lacks family) runs parallel to the historical narrative of Henrietta's life and the discovery/use of HeLa cells. Skloot herself becomes a character — her relationship with Deborah Lacks (Henrietta's daughter) is central. This 'narrative non-fiction' approach makes abstract scientific and ethical issues deeply personal."}]);
  qz.hard=qz.hard.concat([{"q":"The Moore v. Regents of University of California (1990) Supreme Court ruling relates most directly to which book's central ethical issue?","opts":["Gifted Hands — about neurosurgical rights","The Immortal Life of Henrietta Lacks — about property rights in human tissue","The Hot Zone — about pathogen containment","Chasing My Cure — about drug patents"],"correct":1,"explain":"Moore v. Regents (1990) ruled that patients have NO property rights to cells and tissues removed from their bodies — doctors could patent and profit from such tissues without patient consent or compensation. This ruling directly relates to Henrietta Lacks' situation: her HeLa cells generated enormous commercial value, but the court's ruling (established after her case) confirms her family would have no legal claim even today."},{"q":"When Breath Becomes Air explores the concept of 'what makes life meaningful.' Which philosophical framework does Kalanithi primarily draw on in his exploration?","opts":["Utilitarianism — maximizing happiness for the greatest number","Existentialism and humanism — particularly T.S. Eliot's poetry and Whitman's transcendentalism — asking what constitutes a meaningful human existence","Nihilism — concluding that life has no inherent meaning","Religious determinism — accepting God's plan without question"],"correct":1,"explain":"Kalanithi extensively references T.S. Eliot (particularly 'The Waste Land') and Walt Whitman throughout his memoir. His philosophical exploration is existentialist — asking what constitutes a meaningful human life when the future is uncertain. He was a literature major before medical school and draws on humanist traditions to make sense of his mortality."},{"q":"Narrative medicine, as represented by the HOSA Medical Reading event, proposes that reading literature helps health professionals in which specific clinical way?","opts":["It teaches medical facts more efficiently than textbooks","It builds the capacity for empathy and perspective-taking — enabling providers to better understand patient experiences that differ from their own","It replaces the need for bedside manner training","It primarily helps with administrative tasks"],"correct":1,"explain":"Narrative medicine (founded by Rita Charon at Columbia) proposes that literary reading trains the 'close reading' and perspective-taking skills needed for empathetic clinical care. By inhabiting characters' inner lives — a dying surgeon, a child with facial differences, a patient whose cells were taken — health professionals develop imaginative capacity to understand patient experiences that differ from their own. This is the philosophical foundation of HOSA's Medical Reading event."}]);
})();

(function(){
  if(!window.QB_HOSA_HISTORY) return;
  var fc=window.QB_HOSA_HISTORY.flashcards,qz=window.QB_HOSA_HISTORY.quiz;
  if(!fc||!qz) return;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});
  fc.easy=fc.easy.concat([{"term":"HOSA current name","def":"HOSA – Future Health Professionals (changed from Health Occupations Students of America in 2004)","breakdown":"Delegate Assembly vote in June 2004. Name reflects broader scope of health careers beyond traditional 'occupations'"},{"term":"HOSA emblem components","def":"Caduceus (medical symbol) + hands + circle — representing medicine, caring, and unity","breakdown":"Caduceus: winged staff with two snakes. Hands: member caring. Circle: unity. Official HOSA colors: maroon and gold"},{"term":"ILC full name","def":"International Leadership Conference — HOSA's annual national competitive event, held each summer","breakdown":"Competitors qualify through state SLC. Events across all divisions. Delegate Assembly meets at ILC. National officers elected at ILC"},{"term":"SLC full name","def":"State Leadership Conference — state-level HOSA competition before national ILC","breakdown":"Winners advance to ILC. Each state runs its own SLC with own format and schedule. Gateway to national competition"},{"term":"HOSA membership divisions","def":"Middle School, Secondary (high school), Post-Secondary/Collegiate","breakdown":"Competitors only compete within their division. Events differ by division. HOSA Academy focuses on Middle School division events"},{"term":"HOSA chapter","def":"Local group of HOSA members at a school or college — the basic organizational unit","breakdown":"Chapters elect officers, pay dues, enter competitions at regional → state (SLC) → national (ILC). Advisors are health science CTE teachers"},{"term":"HOSA member count","def":"Approximately 300,000 members in the United States","breakdown":"One of the largest student CTE organizations nationally. Millions of alumni working across all healthcare fields"},{"term":"HOSA competitive event categories","def":"Health Science Events, Leadership Events, Recognition Events","breakdown":"Health Science: written tests, skills demos, team events. Leadership: public speaking, writing, parliamentary procedure. Recognition: community service, healthy lifestyle — non-competitive"},{"term":"Business attire (HOSA competitions)","def":"Professional dress required at most HOSA competitive events — bonus points awarded","breakdown":"Suit, dress, or official HOSA uniform. Bonus points awarded before competition begins. Trains students in professional presentation. Part of HOSA's professional development mission"},{"term":"HOSA event guidelines","def":"Official annual rules for each competitive event — updated each summer, must use current year's version","breakdown":"Specify: format, time limits, reference materials, scoring rubric, dress code, required supplies. Using outdated guidelines is a common mistake. Always confirm you have the current year"},{"term":"HOSA Health Science Events examples","def":"Medical Terminology, Nutrition, Math for Health Careers, HOSA Bowl, Stop the Bleed, Vet Science, Medical Reading","breakdown":"Written tests (35 questions, 60 min), skills demonstrations, team events. Most Middle School events are written tests. Each has specific reference materials listed in guidelines"},{"term":"HOSA Leadership Events examples","def":"Prepared Speaking, Extemporaneous Writing, Community Awareness, Parliamentary Procedure","breakdown":"Test communication, management, and leadership skills beyond clinical knowledge. Prepared Speaking: memorized health speech. Extemporaneous Writing: 30-minute timed essay. Parliamentary Procedure: team of 5"}]);
  fc.medium=fc.medium.concat([{"term":"HOSA co-curricular vs extracurricular","def":"Co-curricular: integrated with curriculum. Extracurricular: separate from coursework","breakdown":"HOSA events directly align with CTE Health Science learning standards. Students practice what they learn in class. Not just an after-school club — HOSA is part of the educational program"},{"term":"HOSA health science CTE pathway","def":"HOSA serves Health Science Technology Education (HSTE) — one of 16 career clusters in CTE","breakdown":"16 CTE career clusters include agriculture, technology, healthcare, etc. HOSA is the official student organization for HSTE cluster. Other CTE student orgs: FFA (agriculture), DECA (business), SkillsUSA (trade/tech)"},{"term":"HOSA mission statement","def":"Empower HOSA members to become effective leaders in the global health community through education, collaboration, and experience","breakdown":"Three pillars: education, collaboration, experience. Global = healthcare is international. Effective leaders = not just knowledgeable, but able to lead and communicate. Competitions develop all three"},{"term":"HOSA Hippocratic connection","def":"HOSA embeds healthcare ethics — First Do No Harm — into all health science education","breakdown":"'Primum non nocere' is the foundation of medical ethics. HOSA prepares students who will carry professional ethics into healthcare careers. Ethics tested in competitions and embedded in curriculum"},{"term":"HOSA 2025-2026 theme","def":"50th anniversary celebrated through Medical Reading book selection spanning decades, special events, and retrospective programming","breakdown":"Books selected representing different eras: Gifted Hands (1990), Immortal Life (2010), Hot Zone (1994), When Breath Becomes Air (2016), Wonder (2012), Chasing My Cure (2019)"}]);
  fc.hard=fc.hard.concat([{"term":"HOSA quadruple aim alignment","def":"HOSA's mission aligns with IHI's Quadruple Aim: better patient experience, population health, lower costs, AND improved provider experience","breakdown":"HOSA addresses provider experience aim by developing professionals who are passionate and prepared — reducing early career burnout and dropout. Well-trained passionate providers = better experience for all"},{"term":"National Health Care Skill Standards","def":"Standards defining competencies needed for healthcare careers — HOSA competitive events are aligned to these","breakdown":"Developed by Health Science Technology Education. Serve as curriculum foundation for CTE Health Science programs. HOSA events validate student attainment of these standards competitively"},{"term":"HOSA history timeline","def":"1976: founded as HOSA. 1992: joined with American Association for Health Professions. 2004: renamed HOSA – Future Health Professionals. 2015: Stop the Bleed event added. 2025-26: 50th anniversary","breakdown":"Timeline shows how HOSA evolves with healthcare. New events added as healthcare changes. Stop the Bleed: response to mass casualty events. Future events will reflect emerging health fields"},{"term":"HOSA and workforce pipeline","def":"HOSA creates a documented pipeline from student to health professional — critical for addressing projected healthcare worker shortage","breakdown":"BLS projects 1.8 million new healthcare jobs per year through 2030. HOSA alumni fill every healthcare role. With 300,000 current members and millions of alumni, HOSA is a major workforce development force"}]);
  qz.easy=qz.easy.concat([{"q":"What year was HOSA founded?","opts":["1968","1972","1976","1984"],"correct":2,"explain":"HOSA was founded in 1976 as Health Occupations Students of America. It was established to provide a student organization for health science Career and Technical Education (CTE) programs — like FFA for agriculture or DECA for business students."},{"q":"What is HOSA's current official name?","opts":["Health Occupations Students of America","HOSA – Future Health Professionals","Health Organization for Student Advancement","Healthcare Occupations Student Alliance"],"correct":1,"explain":"HOSA's current official name is HOSA – Future Health Professionals, changed in 2004 at the Delegate Assembly from the original name Health Occupations Students of America. The new name better reflects the modern scope of health careers."},{"q":"HOSA membership includes which three divisions?","opts":["Elementary, Middle School, High School","Middle School, Secondary, Post-Secondary/Collegiate","Freshman, Sophomore, Junior/Senior","High School, Community College, University"],"correct":1,"explain":"HOSA has three divisions: Middle School (grades 6-8), Secondary (high school, grades 9-12), and Post-Secondary/Collegiate (community college and university students). Competitors only compete against others in their same division."},{"q":"What body governs HOSA and votes on major decisions?","opts":["HOSA National Board of Trustees","U.S. Department of Education","The Delegate Assembly","State HOSA Advisors Council"],"correct":2,"explain":"The Delegate Assembly is HOSA's governing body — state delegates vote on constitutional amendments, bylaw changes, and elect national student officers. It meets annually at ILC. The 2004 name change was voted on by the Delegate Assembly."},{"q":"HOSA is described as 'co-curricular.' What does this mean?","opts":["HOSA is only for extracurricular activities after school","HOSA activities are integrated with the health science CTE classroom curriculum","HOSA is optional and separate from all coursework","Co-curricular means HOSA is competitive"],"correct":1,"explain":"Co-curricular means HOSA is part of the curriculum itself — HOSA events directly align with Career and Technical Education (CTE) Health Science learning standards. Students practice real health science knowledge in competitions. This distinguishes HOSA from purely extracurricular clubs."},{"q":"What are the three categories of HOSA competitive events?","opts":["Written, Oral, and Hands-On Events","Health Science Events, Leadership Events, and Recognition Events","Academic, Vocational, and Elective Events","Team, Individual, and Community Events"],"correct":1,"explain":"HOSA events are organized into: Health Science Events (clinical knowledge and skills — written tests, skills demos, team events), Leadership Events (communication and management — public speaking, writing, parliamentary procedure), and Recognition Events (non-competitive community service and character recognition)."},{"q":"The HOSA 2025-2026 school year is significant because it marks:","opts":["HOSA's 25th anniversary","The first year HOSA held an ILC","HOSA's 50th anniversary since its 1976 founding","HOSA's 100th anniversary"],"correct":2,"explain":"The 2025-2026 school year marks HOSA's 50th anniversary since its founding in 1976 (1976 + 50 = 2026). This milestone is commemorated through the Medical Reading book selection, which features titles spanning the decades of HOSA's existence."},{"q":"What does the circle in the HOSA emblem represent?","opts":["The global scope of healthcare","Unity among HOSA members","A medical pill","The cycle of education"],"correct":1,"explain":"The circle in the HOSA emblem represents unity among HOSA members. Combined with the caduceus (medicine/health) and hands (caring), the emblem as a whole represents HOSA's mission: unified, caring future health professionals."},{"q":"Which of these is a HOSA Leadership Event?","opts":["Medical Terminology","Stop the Bleed","Prepared Speaking","HOSA Bowl"],"correct":2,"explain":"Prepared Speaking is a HOSA Leadership Event — competitors deliver a memorized speech on a health topic and are judged on content, delivery, and organization. Medical Terminology, Stop the Bleed, and HOSA Bowl are all Health Science Events."},{"q":"A Recognition Event in HOSA differs from a competitive event because:","opts":["Recognition Events are only for seniors","They are non-competitive — judged on portfolio of activities, not against other students","They are harder to qualify for","Recognition Events are held at a different venue"],"correct":1,"explain":"HOSA Recognition Events (like Service Learning, Healthy Lifestyle, HOSA Chapter of Excellence) are non-competitive — students/chapters are recognized for their achievements based on submitted portfolios, not scored against each other. Any chapter or student who meets the criteria can earn recognition."},{"q":"Business attire is required at HOSA competitive events for which reason?","opts":["It helps judges identify competitors","It is part of professional development — healthcare is a professional field","It is required by federal law for CTE competitions","To make events look more prestigious on social media"],"correct":1,"explain":"Business attire requirements reflect HOSA's professional development mission — healthcare careers require professional appearance, communication, and conduct. Wearing professional dress at competitions trains students to present themselves as future health professionals from a young age. Bonus points are awarded."}]);
  qz.medium=qz.medium.concat([{"q":"How does a HOSA competitor typically advance from chapter to ILC?","opts":["By applying directly to HOSA national","Chapter → Regional → State Leadership Conference (SLC) → International Leadership Conference (ILC)","By invitation from a HOSA national officer","By winning an online qualifying round"],"correct":1,"explain":"The typical pathway: compete at chapter level → advance to regional competition → place at State Leadership Conference (SLC) → qualify for International Leadership Conference (ILC). The exact structure varies by state, but SLC is always the gateway to ILC."},{"q":"HOSA competitive event guidelines must be from which year?","opts":["Any year from the past 5 years","Only the very first year guidelines were published","The current school year — guidelines are updated annually each summer","The most recent year available before 2020"],"correct":2,"explain":"HOSA event guidelines are updated annually every summer for the coming school year. Formats, reference materials, point values, and rules can change. Using outdated guidelines is a common mistake — always confirm you have the current year's guidelines. This is why advisors must check for updates each year."},{"q":"What is the significance of HOSA being 'co-curricular' rather than 'extracurricular'?","opts":["There is no practical difference — both mean after-school activities","Co-curricular means HOSA activities are aligned with and extend classroom learning — not separate from the educational program","Extracurricular is more prestigious than co-curricular","Co-curricular means HOSA is mandatory"],"correct":1,"explain":"Co-curricular means HOSA is integrated with the health science CTE curriculum — HOSA competitive events validate real classroom learning, not separate skills. Students who study medical terminology in class compete in Medical Terminology. This alignment is why HOSA has official recognition from the U.S. Department of Education."},{"q":"Which statement BEST describes how HOSA addresses the healthcare workforce shortage?","opts":["HOSA trains current healthcare workers through continuing education","HOSA creates a documented pipeline from student interest to health professional career through education, competition, and professional development","HOSA lobbies Congress for healthcare funding","HOSA recruits international healthcare workers"],"correct":1,"explain":"HOSA addresses the workforce shortage by creating an educational pipeline: identifying students interested in health careers → developing their knowledge, skills, and professional identity through CTE and HOSA activities → connecting them to career pathways. With 300,000 current members and millions of alumni, HOSA has already populated every sector of the healthcare workforce."},{"q":"The Parliamentary Procedure event in HOSA tests knowledge of which document?","opts":["HOSA's official bylaws","Robert's Rules of Order","The U.S. Constitution","The Hippocratic Oath"],"correct":1,"explain":"HOSA's Parliamentary Procedure event tests Robert's Rules of Order — the standard system for conducting formal meetings. A team of 5 students conducts a mock HOSA chapter meeting following parliamentary procedure. This same system is used in HOSA's own Delegate Assembly and chapter meetings."}]);
  qz.hard=qz.hard.concat([{"q":"HOSA's mission aligns with the Quadruple Aim's fourth element (improving provider experience). How?","opts":["By reducing healthcare costs directly","By producing passionate, prepared health professionals who are less likely to experience early burnout and career dropout","By eliminating the need for continuing education","By providing salary supplements to HOSA alumni"],"correct":1,"explain":"The Quadruple Aim's fourth element (provider experience/burnout reduction) is addressed by HOSA by developing health professionals who enter their careers with strong foundational knowledge, professional identity, and clear purpose. Research shows early career enthusiasm and competence — hallmarks of HOSA-prepared students — correlate with lower burnout rates and longer career retention."},{"q":"A state HOSA chapter wants to change a national HOSA policy. What is the correct formal process?","opts":["The state advisor emails HOSA national headquarters","The state chapter president contacts a national officer","The state association submits a proposed bylaw amendment to the Delegate Assembly at ILC for a vote by state delegates","Individual students can vote through the HOSA website"],"correct":2,"explain":"HOSA governance follows parliamentary procedure: policy changes require a bylaw amendment submitted through proper channels to the Delegate Assembly — HOSA's governing body that meets at ILC. State delegates (not individual students) vote. This is why understanding HOSA's governance structure is important — it's a model of democratic organizational governance."},{"q":"Which combination of factors BEST explains why HOSA has grown from a small vocational education organization to a 300,000-member organization?","opts":["Mandatory enrollment in all U.S. high schools","Alignment of HOSA's mission with growing demand for healthcare workers, expansion from vocational to all health science pathways, and the 2004 name change reflecting modern health career diversity","HOSA received a major federal government grant in 2000","Celebrity endorsements increased HOSA's visibility"],"correct":1,"explain":"HOSA's growth reflects multiple aligned factors: (1) the healthcare workforce shortage created massive demand for health career pathways, (2) CTE expanded health science programs beyond traditional vocational tracks to include biotech, informatics, and research, (3) the 2004 name change attracted students into broader health career pathways, and (4) competitive events like HOSA Bowl and newer events like Stop the Bleed kept content relevant to evolving healthcare practice."}]);
})();

(function(){
  if(!window.QB_EMERGENCY) return;
  var fc=window.QB_EMERGENCY.flashcards,qz=window.QB_EMERGENCY.quiz;
  if(!fc||!qz) return;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});
  fc.easy=fc.easy.concat([{"term":"Epistaxis","def":"Nosebleed — lean forward, pinch soft part of nose 10–15 min; tilt back risks airway aspiration"},{"term":"Febrile seizure","def":"Seizure triggered by rapid fever spike in children 6 months–5 years; usually brief and benign"},{"term":"Status epilepticus","def":"Seizure lasting >5 minutes or two seizures without regaining consciousness — medical emergency"},{"term":"Angina pectoris","def":"Chest pain from reduced coronary blood flow; relieved by rest/nitroglycerin; not a heart attack"},{"term":"Bradycardia","def":"Heart rate <60 bpm; symptomatic bradycardia (dizzy, syncope) may need atropine or pacing"},{"term":"Tachycardia","def":"Heart rate >100 bpm; may indicate infection, dehydration, pain, arrhythmia, or anaphylaxis"},{"term":"Asthma attack","def":"Bronchospasm causing wheezing, shortness of breath; treated with bronchodilator inhaler (albuterol)"},{"term":"Pulmonary edema","def":"Fluid in lungs causing severe breathlessness; pink frothy sputum; often from heart failure"},{"term":"Airway obstruction","def":"Blocked airway from foreign body, swelling, or tongue; treated per conscious/unconscious protocol"},{"term":"Hemothorax","def":"Blood in pleural space; signs: decreased breath sounds, dullness to percussion, shock"},{"term":"Open pneumothorax","def":"Sucking chest wound — seal 3 sides with occlusive dressing; do NOT fully seal (air escape needed)"},{"term":"Rib fractures","def":"Broken ribs cause pain with breathing; flail segment (3+ consecutive) causes paradoxical movement"},{"term":"Pericardial tamponade","def":"Blood in pericardial sac compressing heart — Beck's triad: hypotension, muffled heart sounds, JVD"},{"term":"Aortic dissection","def":"Tear in aortic wall — sudden tearing chest/back pain; different BP in each arm; emergency surgery"},{"term":"Pulmonary embolism","def":"Blood clot in pulmonary artery — sudden dyspnea, chest pain, tachycardia; may cause collapse"},{"term":"Deep vein thrombosis","def":"Clot in deep vein (usually leg) — swelling, redness, warmth, calf tenderness; PE risk"},{"term":"Sepsis","def":"Life-threatening organ dysfunction from infection — altered mental status, fast breathing, low BP"},{"term":"Septic shock","def":"Sepsis plus persistent low BP despite fluids; high mortality; requires vasopressors"},{"term":"Meningitis","def":"Brain/spinal cord membrane infection — stiff neck, severe headache, light sensitivity, petechial rash"},{"term":"Encephalitis","def":"Brain inflammation from viral infection — fever, confusion, seizures; herpes simplex most common"},{"term":"Diabetic emergency","def":"Either hypoglycemia or DKA; if unsure and patient is conscious, give glucose — will not harm DKA"},{"term":"Addisonian crisis","def":"Acute adrenal insufficiency — severe hypotension, nausea, weakness, hyperkalemia; treat with IV steroids"},{"term":"Thyroid storm","def":"Extreme hyperthyroidism — high fever, tachycardia, agitation, heart failure; life-threatening"},{"term":"Myxedema coma","def":"Severe hypothyroidism emergency — hypothermia, decreased consciousness, bradycardia"},{"term":"Eclampsia","def":"Seizures in pregnant patient with preeclampsia; treat with magnesium sulfate; deliver baby"},{"term":"Placental abruption","def":"Premature placenta separation — painful vaginal bleeding, uterine rigidity, fetal distress"},{"term":"Ectopic pregnancy","def":"Pregnancy outside uterus; rupture causes severe abdominal pain, internal bleeding, shock"},{"term":"Rhabdomyolysis","def":"Muscle breakdown releasing myoglobin into blood — brown urine, muscle pain, acute kidney injury"},{"term":"Compartment syndrome","def":"Pressure buildup in muscle compartment cutting off circulation — 6 Ps; emergency fasciotomy"},{"term":"Priapism","def":"Prolonged painful erection (>4 hours) — can cause permanent damage; treat based on ischemic vs non-ischemic"},{"term":"Testicular torsion","def":"Twisting of testicle cutting off blood supply — sudden severe scrotal pain; surgical emergency within 6 hours"},{"term":"Acute abdomen","def":"Sudden severe abdominal pain requiring urgent evaluation — may indicate appendicitis, perforation, ischemia"},{"term":"Appendicitis","def":"Appendix inflammation — periumbilical pain migrating to RLQ, fever, nausea; ruptured appendix = peritonitis"},{"term":"Bowel obstruction","def":"Blocked intestine — colicky abdominal pain, vomiting, distension, absent bowel sounds"},{"term":"Mesenteric ischemia","def":"Intestinal blood supply loss — severe abdominal pain out of proportion to exam; high mortality"},{"term":"Peritonitis","def":"Abdominal cavity infection — rigid board-like abdomen, severe pain, rebound tenderness; sepsis risk"},{"term":"GI hemorrhage","def":"Upper: hematemesis, melena; Lower: hematochezia; massive bleeding causes hemorrhagic shock"},{"term":"Ruptured ectopic","def":"Fallopian tube rupture — sudden severe unilateral abdominal pain, shoulder pain, shock"},{"term":"Ovarian torsion","def":"Twisting of ovary — sudden severe pelvic pain with nausea/vomiting; surgical emergency"},{"term":"Urinary retention","def":"Inability to urinate — suprapubic pain, distended bladder; catheterization relieves acute episode"},{"term":"Renal colic","def":"Kidney stone passage — severe flank pain radiating to groin; nausea; hematuria"},{"term":"Hypertensive crisis","def":"BP >180/120 — urgency: no organ damage; emergency: with organ damage (stroke, MI, aortic dissection)"},{"term":"Stroke hemorrhagic","def":"Bleeding in brain — sudden headache, neuro deficits; CT distinguishes from ischemic; NO tPA"},{"term":"Subarachnoid hemorrhage","def":"Bleeding around brain — worst headache of life (thunderclap); stiff neck; 50% mortality"},{"term":"Subdural hematoma","def":"Venous bleeding under dura — gradual onset; common in elderly after minor head trauma"},{"term":"Epidural hematoma","def":"Arterial bleeding between skull and dura — lucid interval then rapid deterioration; biconvex CT"},{"term":"Transfusion reaction","def":"Hemolytic reaction — fever, flank pain, dark urine; STOP transfusion immediately"},{"term":"Sickle cell crisis","def":"Pain crisis from sickling cells blocking vessels — severe bone/abdomen pain; treat with fluids, oxygen, pain control"},{"term":"Hyperkalemia","def":"High potassium — peaked T waves, wide QRS, arrhythmias; treat with calcium, insulin+glucose, Kayexalate"},{"term":"Hypokalemia","def":"Low potassium — muscle weakness, cramps, flat T waves, U waves; treat with potassium replacement"},{"term":"Hyponatremia","def":"Low sodium — nausea, headache, seizures; rapid correction causes central pontine myelinolysis"},{"term":"Hypernatremia","def":"High sodium — thirst, confusion, seizures; usually from dehydration; correct slowly"},{"term":"Metabolic acidosis","def":"Low blood pH from acid buildup or base loss — Kussmaul breathing if severe (DKA, lactic acidosis)"},{"term":"Respiratory acidosis","def":"Low pH from CO2 buildup — hypoventilation; treat underlying cause (COPD, opioid overdose, airway)"},{"term":"Alcohol intoxication","def":"CNS depression — confusion, ataxia, slurred speech; protect airway; risk of aspiration"},{"term":"Alcohol withdrawal","def":"Dangerous withdrawal — tremors, seizures, delirium tremens (DTs); treat with benzodiazepines"},{"term":"Stimulant overdose","def":"Cocaine/meth — tachycardia, hypertension, hyperthermia, seizures; benzodiazepines first-line"},{"term":"Sedative overdose","def":"Benzodiazepines/barbiturates — CNS depression, respiratory failure; flumazenil reverses benzo"},{"term":"Acetaminophen overdose","def":"Delayed liver failure (24-72h after ingestion); treat with N-acetylcysteine; nomogram guides treatment"},{"term":"Aspirin overdose","def":"Tinnitus, tachypnea, respiratory alkalosis then metabolic acidosis; treat with sodium bicarbonate"},{"term":"Beta-blocker overdose","def":"Bradycardia, hypotension, heart block; treat with calcium, glucagon, high-dose insulin"},{"term":"Calcium channel blocker overdose","def":"Similar to beta-blocker; bradycardia, hypotension; treat with calcium, high-dose insulin therapy"},{"term":"TCA overdose","def":"Tricyclic antidepressants — wide QRS, hypotension, seizures; treat with sodium bicarbonate"},{"term":"Cyanide poisoning","def":"Inhibits cellular oxygen use — bitter almond smell, rapid collapse; antidote: hydroxocobalamin"},{"term":"Organophosphate poisoning","def":"Pesticide/nerve agent — SLUDGE (Salivation, Lacrimation, Urination, Defecation, GI distress, Emesis); antidote: atropine"},{"term":"Smoke inhalation","def":"Upper airway burns, toxic gas inhalation — hoarse voice, stridor, carbonaceous sputum; early intubate"},{"term":"Electrical burn","def":"Entry/exit wounds; internal injury worse than external; cardiac monitoring 24h; fasciotomy may be needed"},{"term":"Lightning strike","def":"Reverse triage — treat apparently dead first; can cause cardiac arrest, keraunoparalysis"},{"term":"Drowning management","def":"Remove from water, begin CPR immediately; all near-drowning victims need hospital evaluation"},{"term":"Scuba diving emergency","def":"Decompression sickness (bends) — joint pain, neurological symptoms; treat with hyperbaric oxygen"},{"term":"Altitude sickness","def":"High altitude pulmonary edema (HAPE) or cerebral edema (HACE) — descend immediately, O2, dexamethasone"},{"term":"Animal bite","def":"Clean wound, assess rabies risk, tetanus status; dog bites may need antibiotics; cat bites high infection risk"},{"term":"Snakebite","def":"Immobilize limb at heart level; remove jewelry; antivenom for pit vipers; do NOT cut/suck wound"},{"term":"Black widow spider bite","def":"Neurotoxin — muscle cramps/rigidity, diaphoresis, hypertension; antivenom if severe"},{"term":"Brown recluse spider bite","def":"Cytotoxin — necrotic wound that expands; treat supportively; surgery if large necrosis"},{"term":"Tick bite","def":"Remove with fine-tipped tweezers; risk of Lyme disease, Rocky Mountain spotted fever, anaplasmosis"},{"term":"Allergic contact dermatitis","def":"Delayed hypersensitivity reaction — rash, blisters at contact site; treat with topical/oral steroids"},{"term":"Fire ant sting","def":"Pustules form at sting site; anaphylaxis risk in sensitized individuals; EpiPen if systemic reaction"},{"term":"Marine envenomation","def":"Jellyfish, sea urchin, stingray — remove tentacles, hot water immersion for venom denaturation"},{"term":"Frostbite management","def":"Rapid rewarming in 104°F water; do NOT rub or refreeze; ibuprofen for inflammation; debride blisters"},{"term":"Trench foot","def":"Non-freezing cold injury from prolonged wet/cold exposure — numb, red, blistered; rewarm slowly"},{"term":"Hypothermia management","def":"Handle gently (arrhythmia risk), warm from core out, passive then active rewarming; not dead until warm and dead"},{"term":"Heat cramps","def":"Muscle cramps from sodium loss in heat; treat with rest, cool environment, oral electrolyte solution"},{"term":"Exertional heat stroke","def":"Young athletes — high core temp, may still sweat; cool immediately with ice water immersion"},{"term":"Classic heat stroke","def":"Elderly/chronically ill — hot dry skin, confusion; fans + misting most practical in field"},{"term":"Asphyxia","def":"Oxygen deprivation causing unconsciousness; causes: strangulation, choking, drowning, CO poisoning"},{"term":"Positional asphyxia","def":"Body position compromises breathing — common in intoxicated/restrained patients; reposition immediately"},{"term":"Traumatic asphyxia","def":"Crush injury to chest compressing lungs — petechiae on face/neck; rapid decompression"},{"term":"Eye trauma","def":"Blunt: orbital fracture, hyphema; Penetrating: do NOT remove object, shield eye; chemical: irrigate 30 min"},{"term":"Ear foreign body","def":"Do NOT push deeper; ENT removal needed; insects: mineral oil to immobilize before removal"},{"term":"Nasal foreign body","def":"Children most common; can cause infection; do NOT use instruments; positive pressure technique"},{"term":"Tooth avulsion","def":"Reimplant within 30-60 min; store in Hank's solution/saliva/milk; handle by crown only"},{"term":"Jaw dislocation","def":"Unable to close mouth; relocation technique by pushing down and back on molars; consult oral surgery"},{"term":"Facial fracture","def":"Le Fort classification for midface; always check airway; orbital blowout can trap extraocular muscle"},{"term":"Blast injury","def":"Primary (pressure wave), secondary (shrapnel), tertiary (thrown body), quaternary (burns/crush)"},{"term":"Gunshot wound","def":"Count entry/exit wounds; assume internal injury; do NOT probe; control bleeding; spine precautions if warranted"},{"term":"Stab wound","def":"Do NOT remove impaled objects; wound depth unpredictable from surface; all chest/abdominal stabs need evaluation"},{"term":"Crush injury","def":"Prolonged compression causes muscle necrosis; reperfusion releases myoglobin, potassium; rhabdo risk"},{"term":"Degloving injury","def":"Skin and soft tissue stripped from underlying structure; requires urgent surgical evaluation"},{"term":"Pediatric head trauma","def":"Non-accidental trauma signs: bilateral retinal hemorrhages, posterior rib fractures, multiple injuries at different stages"},{"term":"Domestic violence emergency","def":"Screen all patients; safety planning; mandatory reporting in some states; document injuries accurately"},{"term":"Sexual assault emergency","def":"SANE exam within 72-96h for evidence; emergency contraception; STI prophylaxis; trauma-informed care"},{"term":"Mass casualty incident","def":"Casualties exceed immediate resources — activate ICS, implement triage, establish treatment/transport sectors"},{"term":"Incident command system","def":"Standardized management structure for emergencies — single commander, unified command for multi-agency"},{"term":"Hazmat emergency","def":"Decontaminate before transport; hot/warm/cold zones; PPE levels A-D; call poison control"},{"term":"Active shooter response","def":"Run-Hide-Fight; tourniquet application; calling 911 with location, description, direction of travel"},{"term":"Wilderness emergency","def":"STOP (Stop, Think, Observe, Plan); improvise from environment; protect from elements first"},{"term":"Emergency childbirth","def":"ABCD approach: Airway baby, Breathe, Circulation/cord, Deliver placenta; support perineum during delivery"},{"term":"Amniotic fluid embolism","def":"Rare obstetric emergency — sudden cardiovascular collapse, DIC in labor/delivery; supportive care only"},{"term":"Umbilical cord prolapse","def":"Cord exits before baby — keep cord warm/moist, push presenting part off cord, emergency C-section"},{"term":"Respiratory distress vs failure","def":"Distress: compensating (tachypnea, accessory muscles); Failure: can't compensate (altered mental status, apnea, cyanosis)"},{"term":"Stridor","def":"High-pitched inspiratory sound from upper airway obstruction — croup, epiglottitis, anaphylaxis; can be life-threatening"},{"term":"Wheezing","def":"High-pitched expiratory sound from lower airway narrowing — asthma, COPD, anaphylaxis; bronchodilators"},{"term":"Crackles (rales)","def":"Popping sounds on inspiration from fluid in small airways — pulmonary edema, pneumonia"},{"term":"Absent breath sounds","def":"No air movement — pneumothorax, hemothorax, complete obstruction; emergency if unilateral with hypotension"},{"term":"Oxygen delivery devices","def":"Nasal cannula 24-44%; simple mask 35-50%; non-rebreather 60-90%; BVM with O2 nearly 100%"},{"term":"Pulse oximetry limitations","def":"Inaccurate in: CO poisoning, methemoglobinemia, poor perfusion, nail polish, motion artifact"},{"term":"Glasgow Coma Scale","def":"Eyes (1-4) + Verbal (1-5) + Motor (1-6) = 3-15; ≤8 severe (intubate); 9-12 moderate; 13-15 mild"},{"term":"Primary survey (ABCDE)","def":"Airway, Breathing, Circulation, Disability (neuro), Exposure; systematic life-threat identification"},{"term":"Secondary survey","def":"Head-to-toe physical exam after primary survey; identify all injuries; SAMPLE history"},{"term":"Mechanism of injury","def":"How injury occurred — guides suspicion for hidden injuries; high vs low energy; MOI = clue to severity"},{"term":"Index of suspicion","def":"Clinical judgment based on MOI and presentation to anticipate injuries not yet visible"},{"term":"Triage START system","def":"Simple Triage and Rapid Treatment: walking=green, breathing after airway=red, no breathing=black, respirations>30 or poor perfusion=red"},{"term":"Triage JumpSTART","def":"Pediatric START modification — gives 5 rescue breaths to apneic children before classifying as black"},{"term":"Mass casualty triage colors","def":"Red: immediate; Yellow: delayed; Green: minor (walking wounded); Black: deceased or expectant"},{"term":"START triage respirations","def":"If not breathing after repositioning: BLACK; respirations >30/min or <10/min: RED; 10-29: continue assessment"},{"term":"EMS communication","def":"Radio report includes: age/sex, chief complaint, vitals, interventions; estimated arrival time"},{"term":"Handoff communication","def":"SBAR (Situation, Background, Assessment, Recommendation) or MIST (Mechanism, Injury, Signs, Treatment)"},{"term":"Personal protective equipment levels","def":"Level A: highest (SCBA + fully encapsulated); B: SCBA + splash protection; C: air-purifying respirator; D: work clothes"},{"term":"Decontamination","def":"Remove clothing (eliminates 80% of contamination), flush with water; done before patient enters hospital"},{"term":"Pediatric airway anatomy","def":"Larger head, smaller mouth, floppy epiglottis, trachea shorter and narrower — sniffing position for airway opening"},{"term":"Jaw thrust technique","def":"Lifts mandible without extending neck — preferred airway maneuver with suspected cervical spine injury"},{"term":"Head-tilt chin-lift","def":"Standard airway opening for non-trauma patients — NOT used with suspected cervical spine injury"},{"term":"Agonal gasping","def":"Irregular gasping breaths after cardiac arrest; NOT normal breathing; start CPR immediately"},{"term":"Two-rescuer CPR advantage","def":"Less fatigue, better compression quality; rescuer switch every 2 min; use bag-valve mask for ventilation"},{"term":"CPR in pregnancy","def":"Standard compressions; manually displace uterus left; if no ROSC in 4 min: perimortem C-section"},{"term":"Infant CPR technique","def":"2 fingers on sternum (solo) or 2-thumb encircling hands (2-rescuer); 1.5 inch depth; 30:2 solo, 15:2 duo"},{"term":"Child CPR technique","def":"1 or 2 hands on sternum; 2-inch depth; 30:2 solo, 15:2 with second rescuer; 100-120/min"},{"term":"High-quality CPR summary","def":"Rate 100-120/min, depth 2-2.4 inches adult, full recoil, minimize pauses, 30:2 ratio, avoid hyperventilation"},{"term":"Pediatric normal vitals","def":"RR: neonate 30-60, infant 25-50, child 20-30, adolescent 12-20; HR: faster in younger children"},{"term":"Hypovolemia signs","def":"Tachycardia (earliest), cool/pale skin, delayed cap refill, thirst, decreased urine output, then hypotension"},{"term":"Capillary refill time","def":"Normal <2 seconds; >3 seconds suggests poor perfusion; press nail bed 5 sec and time return to pink"},{"term":"Blood pressure in shock","def":"Hypotension is a LATE sign of shock in adults; children compensate until 25-30% blood loss then crash"},{"term":"Fluid bolus in pediatrics","def":"20 mL/kg isotonic crystalloid; reassess after each bolus; repeat up to 3x if needed in septic shock"},{"term":"Blood type O negative","def":"Universal donor RBCs; given in emergency before type/crossmatch available; scarce resource"},{"term":"Bleeding from ear","def":"After head trauma: blood/CSF from ear suggests basilar skull fracture; do NOT pack ear"},{"term":"Battle's sign","def":"Bruising behind ear (mastoid) — indicates basilar skull fracture; develops hours after injury"},{"term":"Raccoon eyes","def":"Periorbital ecchymosis — bilateral black eyes from basilar skull fracture; develops hours after injury"},{"term":"Pupil abnormalities","def":"Unequal pupils (anisocoria) after head trauma: herniation or CN III compression; both blown = herniation"},{"term":"AVPU scale","def":"Alert, responds to Voice, responds to Pain, Unresponsive; simple neuro assessment; V or P = GCS ~12"},{"term":"Decorticate posturing","def":"Arms flexed, legs extended — lesion above brainstem (cortical/subcortical); better prognosis than decerebrate"},{"term":"Decerebrate posturing","def":"Arms and legs extended and rotated — brainstem lesion; worse prognosis; both indicate severe brain injury"},{"term":"Doll's eye reflex","def":"Eyes move opposite head turn — intact in normal; absent = brainstem dysfunction; not tested if c-spine injury"},{"term":"Carbon monoxide treatment","def":"100% O2 by non-rebreather mask halves CO-Hgb half-life; hyperbaric O2 for severe cases"},{"term":"Methemoglobinemia","def":"Oxidized hemoglobin cannot carry O2; cyanosis with normal PaO2; pulse ox reads ~85%; treat with methylene blue"},{"term":"Cyanide antidote","def":"Hydroxocobalamin (preferred) or sodium nitrite/sodium thiosulfate; fire/smoke victims may have both CO and cyanide"},{"term":"Activated charcoal","def":"Adsorbs many ingested toxins; give within 1-2h of ingestion; contraindicated if altered mental status"},{"term":"Ipecac syrup","def":"NO LONGER RECOMMENDED for poisoning — can cause aspiration, Mallory-Weiss tears; call Poison Control instead"},{"term":"Poison Control USA","def":"1-800-222-1222; call for all potential poisoning/overdose; available 24/7; free confidential advice"},{"term":"Bystander AED use","def":"Public AED programs save lives; average lay person can use an AED; turn on and follow voice prompts"},{"term":"Do not resuscitate (DNR)","def":"Legal order to withhold CPR; must be verified before stopping resuscitation; different from POLST"},{"term":"POLST form","def":"Physician Orders for Life-Sustaining Treatment; portable medical order; supersedes DNR in most states"},{"term":"Informed consent in emergency","def":"Obtained from competent adult; informed of risks/benefits; minors need parent except life-threatening emergency"},{"term":"Abandonment","def":"Leaving a patient without transfer of care; illegal; must ensure continuity of care before leaving"},{"term":"Negligence in emergency care","def":"4 elements: duty to act, breach of duty, causation, damages; standard of care is key reference"},{"term":"Scope of practice","def":"Legal boundary of what a healthcare provider can do; determined by certification/licensure and local protocols"},{"term":"Medical direction","def":"Physician oversight of EMS; online (real-time) and offline (protocols/training); enables advanced interventions"},{"term":"Online medical direction","def":"Direct physician contact during call; used for unusual situations or protocol deviations"},{"term":"Offline medical direction","def":"Standing orders and protocols established in advance; most day-to-day EMS care follows offline direction"},{"term":"Documentation importance","def":"Legal record; continuity of care; quality improvement; 'if it wasn't documented, it wasn't done'"},{"term":"EMS incident report","def":"Prehospital care report (PCR); documents assessment, interventions, times, patient response"},{"term":"Violent scene management","def":"Do NOT enter until law enforcement declares scene safe; retreat if threat develops; patient safety after yours"},{"term":"Emotional response after emergency","def":"Critical Incident Stress Management (CISM); debriefing within 24-72h; watch for PTSD symptoms"},{"term":"Fire safety and burns","def":"RACE (Rescue, Alarm, Contain, Extinguish); PASS for extinguisher; stop drop roll for clothing fires"},{"term":"Drowning prevention","def":"Life jackets, pool fencing, adult supervision, swimming lessons; dry drowning/secondary drowning rare but real"},{"term":"Sports emergency protocol","def":"Emergency action plan at all athletic events; AED on-site; medical timeout for head injuries; return-to-play protocol"},{"term":"Return to play concussion","def":"Stepwise protocol; cannot return same day; must be symptom-free at rest before each step; physician clearance"},{"term":"Concussion signs","def":"Headache, confusion, amnesia, dizziness, 'foggy' feeling after head impact; second impact syndrome risk"},{"term":"HOSA emergency events","def":"HOSA members may compete in CPR/First Aid, Emergency Medical Technician, and Medical Emergency Response events"},{"term":"Cardiopulmonary resuscitation (CPR)","def":"Emergency procedure combining chest compressions and rescue breaths to maintain circulation and oxygenation","breakdown":"Cardio=heart, pulmonary=lungs. Goal: keep oxygenated blood reaching brain until advanced care arrives. Survival drops 10% per minute without CPR"},{"term":"Compression depth (adult CPR)","def":"At least 2 inches (5 cm) but no more than 2.4 inches — allow full chest recoil between compressions","breakdown":"Too shallow = ineffective circulation. Too deep = rib fractures, liver laceration. Don't lean on chest between compressions"},{"term":"Compression rate","def":"100-120 compressions per minute — pace of 'Stayin' Alive' by Bee Gees","breakdown":"Too slow = poor perfusion. Too fast = incomplete cardiac filling. Use a metronome app or count aloud to maintain rate"},{"term":"Hands-only CPR","def":"CPR using compressions only (no rescue breaths) — recommended for untrained bystanders on adult victims","breakdown":"Equally effective for first few minutes. Eliminates hesitation. Call 911 first, then push hard and fast on center of chest"},{"term":"AED pad placement","def":"Right pad: upper right chest below collarbone. Left pad: lower left chest below armpit","breakdown":"Never place over pacemaker lump or medication patch. Use pediatric pads for children under 8. If unavailable, adult pads work"},{"term":"Shockable rhythm","def":"Ventricular fibrillation (VF) or pulseless VT — the only rhythms treated with defibrillation","breakdown":"AED detects these automatically. Chaotic electrical activity = no effective pumping. Shock + immediate CPR = best chance of survival"},{"term":"Non-shockable rhythm","def":"Asystole (flatline) or PEA — AED says 'no shock advised' — only CPR helps","breakdown":"Cannot be shocked back into rhythm. Must find and fix reversible causes (Hs and Ts). Continue CPR aggressively"},{"term":"Defibrillation timing","def":"Every minute without defibrillation reduces VF survival by ~10% — get AED immediately","breakdown":"CPR buys time between shocks. After shock: resume CPR immediately for 2 min before next rhythm check. Don't delay AED for extra CPR"},{"term":"Agonal breathing","def":"Irregular gasping after cardiac arrest — NOT effective breathing — do NOT delay CPR","breakdown":"Occurs in 40% of cardiac arrests. Bystanders mistake it for normal breathing and delay CPR. If unresponsive + gasping = start CPR"},{"term":"Pulse check","def":"Check carotid pulse for no more than 10 seconds — if absent or uncertain, begin CPR immediately","breakdown":"Trained providers: 2 fingers beside trachea in neck. If no definite pulse within 10 seconds → start CPR. Don't waste time"},{"term":"Obstructed airway (infant)","def":"5 back blows + 5 chest thrusts (NOT abdominal) alternating for choking infant under 1 year","breakdown":"Face-down on forearm for back blows. Face-up on thigh for chest thrusts with 2 fingers on breastbone. Never abdominal thrusts on infants"},{"term":"Obstructed airway (pregnant/obese)","def":"Use chest thrusts instead of abdominal thrusts — hands on center of chest","breakdown":"Same inward thrust motion as Heimlich but placed on chest. Equally effective and avoids harm to pregnant abdomen"},{"term":"Unconscious choking victim","def":"Lower to floor, start CPR, look in mouth before each breath — never do blind finger sweep","breakdown":"Open airway for each breath: look for visible object and remove if seen. CPR chest compressions may help dislodge object"},{"term":"Anaphylaxis signs","def":"Hives + swelling + difficulty breathing + low blood pressure after exposure to allergen","breakdown":"Systemic reaction: skin (hives, flushing), respiratory (wheeze, stridor), cardiovascular (hypotension, tachycardia). Any two systems = anaphylaxis"},{"term":"Two EpiPen rule","def":"Always carry two epinephrine auto-injectors — biphasic anaphylaxis can recur 1-72 hours later","breakdown":"Biphasic reaction (3-20% of anaphylaxis): symptom-free period then return. Second EpiPen for recurrence before hospital arrival"},{"term":"EpiPen technique","def":"Inject outer thigh, through clothing if needed, hold 10 seconds, remove and massage site","breakdown":"Outer thigh = fastest absorption. Clothing doesn't significantly reduce delivery. After use: still need emergency care immediately"},{"term":"Allergen","def":"Substance triggering allergic reaction — top 9: milk, eggs, fish, shellfish, tree nuts, peanuts, wheat, soy, sesame","breakdown":"Must be labeled on packaged foods (FASTER Act 2023 added sesame). Peanuts most common cause of fatal food anaphylaxis"},{"term":"Angioedema","def":"Deep tissue swelling of lips, tongue, throat — can obstruct airway rapidly","breakdown":"Throat angioedema = hoarse voice, stridor, difficulty swallowing → immediate epinephrine. Different from hives (superficial swelling)"},{"term":"Ischemic stroke","def":"Stroke from blood clot blocking brain artery — 87% of all strokes","breakdown":"Treatment: tPA within 3-4.5 hours, mechanical thrombectomy up to 24 hours. Time is brain: 1.9 million neurons die per minute"},{"term":"Hemorrhagic stroke","def":"Stroke from ruptured blood vessel in brain — 13% of strokes, higher mortality","breakdown":"tPA is contraindicated. Treatment: control bleeding, reduce ICP, surgery if needed. Cannot give clot-busting drugs"},{"term":"TIA (transient ischemic attack)","def":"'Mini-stroke' — stroke symptoms resolving within 24 hours — urgent warning sign","breakdown":"10-15% risk of major stroke within 3 months, highest in first 48 hours. Treat as emergency. Workup and secondary prevention urgently"},{"term":"Angina","def":"Chest pain from reduced coronary blood flow — stable (predictable) vs unstable (at rest = emergency)","breakdown":"Stable: exertion-triggered, relieved by rest/nitroglycerin. Unstable: occurs at rest, escalating = acute coronary syndrome"},{"term":"Aspirin in heart attack","def":"Chew (not swallow whole) 325mg or 4 baby aspirin immediately if heart attack suspected","breakdown":"Anti-platelet: prevents clot growth. Chewing gives faster absorption. Give unless allergy or recent significant GI bleeding"},{"term":"Nitroglycerin","def":"Sublingual tablet or spray that dilates coronary arteries — for angina and heart attack","breakdown":"Up to 3 doses every 5 min. Contraindications: SBP <90, recent erectile dysfunction drugs (Viagra/Cialis). Call 911 regardless"},{"term":"Syncope","def":"Transient loss of consciousness from temporary reduction in brain blood flow — fainting","breakdown":"Vasovagal most common (pain, emotion, prolonged standing). Lay flat, elevate legs. Cardiac syncope (exertion, no warning) = more serious"},{"term":"Hypoxia","def":"Insufficient oxygen delivery to tissues — causes confusion, cyanosis, rapid breathing","breakdown":"Causes: airway obstruction, drowning, lung disease, CO poisoning. Treatment: open airway, supplemental oxygen, treat underlying cause"},{"term":"Cyanosis","def":"Blue-purple discoloration of skin and lips from inadequate oxygenation","breakdown":"Central (lips, tongue) = severe systemic hypoxia. Peripheral (fingers, toes) = poor local circulation. Both require emergency evaluation"},{"term":"Carbon monoxide (CO)","def":"Colorless, odorless gas binding hemoglobin 240x stronger than oxygen — sources include car exhaust, gas appliances, generators","breakdown":"Standard pulse oximeter shows falsely normal SpO2. Symptoms: headache, dizziness, confusion, nausea. Treatment: fresh air + 100% O2"},{"term":"Sudden cardiac arrest","def":"Abrupt loss of heart function — most commonly from ventricular fibrillation","breakdown":"Different from heart attack (plumbing) vs cardiac arrest (electrical). Heart attack causes cardiac arrest. Early CPR + AED saves lives"},{"term":"Commotio cordis","def":"Cardiac arrest from blunt chest impact during vulnerable cardiac phase — no structural damage","breakdown":"Common in youth sports (baseball, hockey, lacrosse). Victim appears well then suddenly collapses. Only treatment: CPR + immediate AED"},{"term":"Insulin shock","def":"Severe hypoglycemia from too much insulin — glucose dangerously low, brain starved","breakdown":"Signs: shaking, sweating, confusion, seizure, unconsciousness. Give sugar if conscious. Glucagon or IV dextrose if unconscious"},{"term":"Rule of 15 (hypoglycemia)","def":"Give 15g fast carbs → wait 15 minutes → recheck glucose → repeat if still below 70 mg/dL","breakdown":"15g carbs: 4oz juice, 3-4 glucose tablets, 1 tbsp honey. Always recheck — glucose can drop again after initial treatment"},{"term":"Glucagon kit","def":"Emergency medication to raise blood glucose in unconscious hypoglycemic patient — injection or nasal spray","breakdown":"Stimulates liver to release stored glucose. Takes 10-15 min to work. Also available as Baqsimi nasal spray (no injection needed)"},{"term":"Naloxone (Narcan)","def":"Opioid reversal drug — blocks opioid receptors and reverses overdose within 2-3 minutes","breakdown":"Available without prescription in most states. Nasal spray or injection. May need repeat doses for fentanyl. Doesn't harm non-opioid users"},{"term":"Opioid toxidrome","def":"Triad: miosis (pinpoint pupils) + respiratory depression + decreased consciousness","breakdown":"Classic triad of opioid overdose. Give naloxone if these signs present + opioid history. Rescue breathing while waiting for naloxone to work"},{"term":"Naloxone dosing","def":"0.4-2mg IV/IM/nasal — repeat every 2-3 minutes if no response — may need infusion for fentanyl","breakdown":"Naloxone has shorter half-life than most opioids — patient may re-sedate after naloxone wears off. Transport to hospital always"},{"term":"Secondary drowning","def":"Delayed respiratory distress hours after submersion — water irritates lungs causing pulmonary edema","breakdown":"Can occur 1-72 hours after incident. Child seems fine after near-drowning then develops cough, dyspnea. All submersion victims need hospital"},{"term":"Cold water drowning","def":"Cold water submersion victims may survive despite prolonged arrest — 'never dead until warm and dead'","breakdown":"Diving reflex + hypothermia can preserve brain. Children especially. Aggressive CPR until fully rewarmed. Documented neurologically intact survivors"},{"term":"Toxic substance ingestion","def":"Call Poison Control (1-800-222-1222) — do NOT induce vomiting unless directed","breakdown":"Route matters: ingestion, inhalation, injection, skin/eye absorption. Activated charcoal within 1 hour if conscious and directed by poison control"},{"term":"Acetaminophen (Tylenol) overdose","def":"Most common intentional overdose — causes liver failure if untreated — often asymptomatic initially","breakdown":"Treatment: N-acetylcysteine (NAC). Must treat before symptoms develop. Check 4-hour acetaminophen level. Seemingly well patient can die in days"},{"term":"Scene safety","def":"FIRST priority at any emergency — hazards include traffic, fire, toxic fumes, violence, power lines","breakdown":"Unsafe rescuer = additional victim. Don't enter unsafe scene. Call for specialized resources (hazmat, fire, police) before entering"},{"term":"Personal protective equipment","def":"Gloves, mask, eye protection, gown — worn whenever contact with blood or body fluids is possible","breakdown":"Minimum: gloves for all patient contact. Add mask + eye protection for splash risk. Double glove for heavy bleeding situations"},{"term":"Bloodborne pathogen risks","def":"HIV, Hepatitis B, Hepatitis C transmitted through needlesticks, blood splash to mucous membranes","breakdown":"Report exposures immediately. Post-exposure prophylaxis available for HIV within 72 hours. HBV vaccination recommended for all responders"},{"term":"Good Samaritan Law","def":"Legal protection for bystanders providing reasonable emergency care in good faith — all 50 states","breakdown":"Protects when: acting in good faith, not grossly negligent, not the cause of the emergency. Does NOT protect willful negligence"},{"term":"911 call essentials","def":"State location FIRST, describe emergency, follow dispatcher instructions, stay on the line","breakdown":"Location is most critical — caller may become incapacitated. Dispatchers can guide CPR, childbirth, and other emergencies by phone"},{"term":"Implied consent","def":"Unconscious adults presumed to consent to emergency life-saving treatment","breakdown":"Cannot get expressed consent when unconscious. Implied consent allows treatment. Conscious adults can still refuse. Different rules for minors"},{"term":"Medical identification jewelry","def":"MedicAlert bracelet or necklace indicating allergies, conditions, medications — check on all unconscious patients","breakdown":"Common alerts: diabetes, penicillin allergy, blood thinners, seizure disorder. Could change emergency treatment decisions"},{"term":"Primary assessment (ABCDE)","def":"Airway, Breathing, Circulation, Disability, Exposure — systematic emergency patient evaluation","breakdown":"Life threats found and treated in order. Airway obstruction kills fastest. Disability = neurological status (AVPU, GCS). Expose to find injuries"},{"term":"Hemorrhage control priorities","def":"Direct pressure first → pressure dressing → tourniquet for extremity → wound packing for junctional","breakdown":"STOP THE BLEED: apply pressure, pack the wound, apply tourniquet. Tourniquet for life-threatening extremity bleeding. Document time applied"},{"term":"Internal bleeding signs","def":"Abdominal rigidity/distension, bruising over injury site, signs of shock without visible bleeding","breakdown":"Blood hidden in abdomen, chest, pelvis, long bones. Grey Turner's sign (flank bruise), Cullen's sign (belly button bruise) = retroperitoneal blood"},{"term":"Exsanguination","def":"Fatal hemorrhage — death from blood loss — preventable with proper hemorrhage control","breakdown":"Causes 30-40% of trauma deaths. Most preventable cause of death in trauma. Stop the Bleed program trained 2+ million Americans"},{"term":"Flail chest","def":"3+ consecutive ribs broken in 2+ places — paradoxical movement (moves opposite to normal breathing)","breakdown":"Segment moves IN with inspiration (instead of out). Severe pain prevents effective breathing. Often associated with underlying pulmonary contusion"},{"term":"Tracheal deviation","def":"Trachea shifts away from midline — late sign of tension pneumothorax or massive hemothorax","breakdown":"Late and unreliable sign. Don't wait for tracheal deviation to treat suspected tension PTX in an unstable patient. Act on other signs first"},{"term":"Evisceration","def":"Abdominal organs protruding through wound — cover with moist sterile dressing, do NOT push back","breakdown":"Saline-moistened gauze + occlusive covering. Flex knees to reduce abdominal tension. NPO. Surgical emergency"},{"term":"Impaled object","def":"Never remove — stabilize in place with bulky dressings around the object — call 911","breakdown":"Removal risks massive uncontrollable bleeding. Stabilize to prevent movement during transport. Exception: cheek impalement blocking airway"},{"term":"Amputation","def":"Control hemorrhage with tourniquet — preserve amputated part in cool moist environment for possible replantation","breakdown":"Wrap part in moist gauze, seal in plastic bag, place bag on ice (not IN ice). Replantation possible up to 6 hours warm, 12 hours cooled"},{"term":"Traumatic brain injury signs","def":"Altered mental status, unequal pupils, Battle's sign, raccoon eyes, CSF from ears/nose","breakdown":"Battle's sign (bruising behind ear), raccoon eyes = basilar skull fracture. Dilated unreactive pupil = brain herniation — emergency"},{"term":"Pediatric vital sign norms","def":"Children: higher heart rate and respiratory rate, lower blood pressure than adults — age-dependent","breakdown":"Infant HR 100-160, RR 30-60. Toddler HR 90-150, RR 24-40. Tachycardia in a child = compensating for something serious until proven otherwise"},{"term":"Broselow tape","def":"Color-coded tape measuring child length to estimate weight — guides drug doses and equipment selection","breakdown":"Measure head to heel. Color zone = weight range = pre-calculated correct doses and equipment sizes. Standard pediatric emergency tool"},{"term":"Anaphylaxis biphasic reaction","def":"Anaphylaxis returning 1-72 hours after initial episode even after treatment — reason to observe all patients in ED","breakdown":"Occurs in 3-20% of anaphylaxis. Patient feels better, then deteriorates. Always observe 4-8 hours in ED. Use second EpiPen if recurs"},{"term":"Fever in emergency","def":"Temperature >100.4°F (38°C) — in infants under 3 months always an emergency","breakdown":"Fever + stiff neck + petechial rash = meningococcemia emergency. Febrile seizure in children: first episode still needs evaluation"},{"term":"Altered mental status causes","def":"AEIOU-TIPS: Alcohol, Epilepsy, Insulin, Opiates, Uremia — Trauma, Infection, Psychiatric, Stroke/Shock","breakdown":"Systematic mnemonic for AMS causes. Always check glucose first (quick, easy, reversible). Don't assume psychiatric cause without ruling out medical"},{"term":"Overdose signs by class","def":"Opioids: pinpoint pupils, slow breathing. Stimulants: dilated pupils, agitation, tachycardia. Sedatives: slurred speech, ataxia","breakdown":"Toxidrome recognition guides treatment. Mixed overdoses common. Always consider co-ingestants. Maintain airway and call poison control"},{"term":"Eye injury first aid","def":"Do not rub — flush with water for chemical exposure (15-20 min) — cover without pressure for penetrating injury","breakdown":"Chemical burn: flush IMMEDIATELY before anything else, even calling 911. Penetrating: rigid cup over eye, no pressure. Vision at stake"},{"term":"Dental avulsion","def":"Tooth knocked out — handle by crown, rinse without scrubbing, replant or store in milk — see dentist within 60 min","breakdown":"Do NOT scrub root. Replant in socket if possible. If not: milk > saliva > saline. Dry storage = poor prognosis. Time critical"},{"term":"Epistaxis (nosebleed)","def":"Lean FORWARD, pinch soft part of nose (not bridge), hold 10-15 minutes continuously","breakdown":"Lean forward prevents blood swallowing (causes nausea/vomiting). Most: Kiesselbach's plexus (anterior). Posterior bleeds: more serious, ENT needed"},{"term":"Tetanus prophylaxis","def":"Booster needed for contaminated wounds if >5 years since last, or any wound if >10 years","breakdown":"3-dose primary series recommended. Tdap preferred (includes pertussis coverage). TIG (tetanus immune globulin) for high-risk wounds"},{"term":"Rabies post-exposure","def":"Wound wash + immune globulin + 4-dose vaccine — 100% effective if given before symptoms develop","breakdown":"Rabies 100% fatal once symptomatic. Bat exposure even without visible bite may need PEP. Report animal bites to health department"},{"term":"Universal distress signal","def":"International distress: SOS (…---…), three whistle blasts, waving both arms — used when unable to call 911","breakdown":"Ground-to-air signals: X = need medical help, V = need help. Mirror flashes, smoke, fire used for search and rescue signaling"},{"term":"Pediatric fever emergencies","def":"Any fever in infant <3 months, fever >104°F (40°C), fever + stiff neck or rash = emergency","breakdown":"Neonatal fever: immature immune system = serious infection until proven otherwise. Always transport <3 month febrile infant to ED"},{"term":"Wound care basics","def":"Control bleeding with direct pressure, clean with water/saline, cover with clean dressing — don't remove embedded objects","breakdown":"Irrigation reduces infection: clean running water works as well as sterile saline. Change dressings if soaked through. Watch for infection signs"},{"term":"Hypothermia field treatment","def":"Remove wet clothing, insulate from ground, add heat to core (not extremities), avoid rough handling","breakdown":"Rewarming extremities first can trigger arrhythmias (afterdrop). Core first: warm blankets, hot packs to armpits/groin/neck. Gentle movement"},{"term":"Heat illness prevention","def":"Hydrate before/during activity, acclimatize over 7-14 days, avoid peak heat hours, wear loose light clothing","breakdown":"High-risk: elderly, young children, athletes, outdoor workers. Heat index considers humidity. WBGT used for athletic event cancellation decisions"},{"term":"Disaster preparedness","def":"72-hour emergency kit: water (1 gal/person/day), food, medications, first aid kit, documents, flashlight, radio","breakdown":"FEMA recommends 72-hour minimum kit. Know your evacuation routes. Have family meeting point. Register special needs with local emergency management"},{"term":"Mass casualty triage goal","def":"Greatest good for greatest number — prioritize who will benefit most from immediate care with available resources","breakdown":"Utilitarian ethics applies. Expectant (black) category ethically justified in true MCI. Re-triage as resources become available"},{"term":"Duty to act","def":"Paid emergency responders on duty have legal obligation to provide care — bystanders have moral but not legal duty","breakdown":"Off-duty healthcare providers: depends on state. EMTs on duty must respond. Good Samaritan laws protect all good-faith helpers"},{"term":"Decompression sickness","def":"'The bends' — nitrogen bubbles form in blood from too-rapid ascent during scuba diving","breakdown":"Symptoms: joint pain, skin marbling, neurological deficits, respiratory distress. Treatment: hyperbaric oxygen chamber. Prevention: slow ascent, safety stops"}]);
  fc.medium=fc.medium.concat([{"term":"Epinephrine dosing","def":"Adult anaphylaxis: 0.3-0.5 mg IM (anterolateral thigh); child: 0.01 mg/kg; repeat every 5-15 min"},{"term":"CPR quality metrics","def":"Rate 100-120/min, depth 2-2.4 inches, full recoil, minimize interruptions (<10 sec), 30:2 ratio"},{"term":"Waveform capnography","def":"Gold standard for ETT confirmation; ETCO2 <10 mmHg during CPR predicts poor outcome; >40 at ROSC"},{"term":"Post-resuscitation syndrome","def":"Multi-organ dysfunction after ROSC — brain injury, myocardial dysfunction, systemic ischemia-reperfusion"},{"term":"Targeted temperature management","def":"Cool post-arrest patients to 32-36°C for 24h; prevents secondary brain injury from reperfusion"},{"term":"Vasopressin vs epinephrine","def":"Vasopressin 40 IU IV can substitute first or second dose of epi in VF/VT; combined used in asystole"},{"term":"Hs and Ts of cardiac arrest","def":"Hypovolemia, Hypoxia, H+, Hypo/Hyperkalemia, Hypothermia; Tamponade, Tension PTX, Toxins, Thrombosis (PE/CAD)"},{"term":"Synchronized cardioversion","def":"Timed shock to QRS — for unstable SVT, VT with pulse, atrial flutter; NOT for VF/pulseless VT"},{"term":"Defibrillation energy","def":"Biphasic: 120-200J (manufacturer); monophasic: 360J; pediatric: 2 J/kg first, 4 J/kg subsequent"},{"term":"Rapid sequence intubation","def":"Sedation + paralysis for emergency intubation — preoxygenate, sedate, paralyze, intubate, confirm"},{"term":"Cricothyrotomy technique","def":"Emergency surgical airway — palpate cricothyroid membrane, incise, insert tube; Seldinger or surgical"},{"term":"Chest tube insertion","def":"4th-5th intercostal space, anterior axillary line; blunt dissection; confirm with CXR; drainage tubing"},{"term":"Pericardiocentesis","def":"Needle aspiration of pericardial sac — subxiphoid approach; guided by ultrasound; relieves tamponade"},{"term":"FAST exam","def":"Focused Assessment with Sonography in Trauma — pericardium, RUQ, LUQ, pelvis; identifies free fluid"},{"term":"Massive transfusion protocol","def":"Activated for >10 units pRBC in 24h; fixed ratio blood products; monitor Ca2+, temp, pH"},{"term":"Hemorrhage control progression","def":"Direct pressure → pressure dressing → wound packing with hemostatic gauze → tourniquet → junctional tourniquet"},{"term":"Internal bleeding assessment","def":"Signs: tachycardia, hypotension, pallor, distension, referred shoulder pain; FAST/CT confirms"},{"term":"Spinal motion restriction","def":"Selective immobilization based on mechanism, neuro exam, altered mental status, distracting injury"},{"term":"Neurogenic shock","def":"Spinal cord injury causing loss of sympathetic tone — bradycardia + hypotension (not tachycardia)"},{"term":"Obstructive shock","def":"Outflow obstruction: tension pneumothorax, tamponade, massive PE — reduced cardiac output despite adequate volume"},{"term":"Distributive shock mechanisms","def":"Vasodilation → inadequate perfusion: anaphylactic (IgE), septic (cytokines), neurogenic (spinal), hepatic"},{"term":"Cardiogenic shock features","def":"Pump failure — Killip class IV; cool extremities, elevated JVP, S3 gallop; low BP despite adequate volume"},{"term":"Fluid resuscitation strategy","def":"Hemorrhagic: blood products; septic: 30 mL/kg crystalloid; burn: Parkland formula; trauma: restrict crystalloid"},{"term":"Parkland formula","def":"4 mL × kg × %BSA burned; give half in first 8h, half in next 16h; Lactated Ringer's preferred"},{"term":"Burns depth assessment","def":"Superficial (1st): red, painful; Partial thickness (2nd): blisters, moist; Full thickness (3rd): dry, no pain"},{"term":"Inhalation injury management","def":"Early intubation if stridor/singed nasal hair; 100% O2; humidified air; bronchoscopy diagnostic"},{"term":"Pediatric resuscitation differences","def":"Asphyxia most common cause; 30:2 alone, 15:2 two-rescuer; weight-based dosing; Broselow tape"},{"term":"Neonatal resuscitation","def":"Warmth, dry, stimulate; if HR<100: PPV; HR<60 after PPV: CPR 3:1; epinephrine if HR<60 after CPR"},{"term":"Obstetric emergency management","def":"Left lateral tilt for aortocaval decompression; aggressive fluid resuscitation; early delivery if needed"},{"term":"REBOA technique","def":"Balloon catheter in aorta — Zone 1 for abdominal hemorrhage; Zone 3 for pelvic; temporary hemorrhage control"},{"term":"Intraosseous access","def":"IO needle in proximal tibia or humeral head; all IV drugs can be given; standard doses apply"},{"term":"Point-of-care ultrasound","def":"FAST, cardiac windows, lung assessment, IVC size for volume; immediate bedside diagnosis"},{"term":"Traumatic brain injury management","def":"Maintain CPP (MAP-ICP); SBP>90; O2 sat>90%; avoid hyperthermia; osmotherapy for ICP elevation"},{"term":"Intracranial pressure monitoring","def":"Ventriculostomy: monitors ICP and drains CSF; normal ICP <15 mmHg; treat >20 mmHg"},{"term":"Cerebral perfusion pressure","def":"CPP = MAP − ICP; target CPP 60-70 mmHg in TBI; below 50 = severe ischemia risk"},{"term":"Seizure pharmacology","def":"First: lorazepam or diazepam; second: phenytoin/levetiracetam; third: phenobarbital; refractory: ketamine/propofol"},{"term":"Status epilepticus management","def":"Airway first; benzodiazepine IV 0-5 min; second drug 5-20 min; general anesthesia if 30+ min"},{"term":"Stroke code activation","def":"Door-to-CT <25 min; door-to-needle <60 min; tPA window 3-4.5h; thrombectomy up to 24h selected patients"},{"term":"tPA contraindications","def":"Recent surgery/trauma, BP>185/110, active bleeding, prior stroke <3 months, anticoagulated, platelets <100k"},{"term":"STEMI management","def":"Aspirin + P2Y12 inhibitor; primary PCI within 90 min (door-to-balloon); fibrinolysis if PCI unavailable"},{"term":"Ventricular tachycardia treatment","def":"Pulseless VT: defibrillation + CPR; stable VT with pulse: amiodarone or lidocaine; unstable: cardioversion"},{"term":"Aortic dissection management","def":"Type A (ascending): emergency surgery; Type B (descending): beta-blockers to reduce HR/BP; BP<120 systolic"},{"term":"PE massive treatment","def":"Hemodynamically unstable: systemic thrombolysis; stable with high risk: catheter-directed therapy; all: anticoagulation"},{"term":"Meningitis empiric treatment","def":"Ceftriaxone + vancomycin + dexamethasone; LP before antibiotics if no contraindications; treat immediately if uncertain"},{"term":"Sepsis bundle (1-hour)","def":"Measure lactate; blood cultures; broad-spectrum antibiotics; 30 mL/kg crystalloid if hypotensive; vasopressors if needed"},{"term":"DKA management","def":"IV fluids first; insulin drip after K>3.5; potassium replacement; correct pH gradually; watch for cerebral edema"},{"term":"Hyperosmolar hyperglycemic state","def":"HHS — extreme hyperglycemia (>600) without ketoacidosis; older T2DM patients; treat with fluids, slow insulin"},{"term":"Adrenal crisis management","def":"Hydrocortisone 100 mg IV bolus; IV fluids; glucose if hypoglycemic; identify precipitating cause"},{"term":"Acute liver failure","def":"Coagulopathy + encephalopathy; acetaminophen most common in US; N-acetylcysteine; transplant evaluation"},{"term":"Upper GI bleed management","def":"2 large-bore IVs; PPI drip; blood transfusion threshold Hgb<7; endoscopy within 24h; Blatchford score"},{"term":"Esophageal varices bleeding","def":"Portal hypertension → varices; octreotide drip; banding/sclerotherapy; TIPS if refractory"},{"term":"Acute kidney injury","def":"RIFLE/KDIGO criteria; prerenal (most common): treat with fluids; intrinsic: avoid nephrotoxins; post: relieve obstruction"},{"term":"Hyperkalemia ECG changes","def":"Peaked T waves → prolonged PR → wide QRS → sine wave → VF; calcium gluconate stabilizes membrane"},{"term":"Hyponatremia treatment","def":"Symptomatic (seizure): 3% NaCl bolus 100 mL; asymptomatic: fluid restrict; correct <10 mEq/L per day"},{"term":"Alcohol withdrawal severity","def":"CIWA scale; mild: anxiety/tremor; moderate: diaphoresis/tachycardia; severe: DTs/seizures; all: benzos"},{"term":"Wernicke encephalopathy","def":"Thiamine deficiency triad: confusion, ataxia, ophthalmoplegia; give thiamine BEFORE glucose in alcoholics"},{"term":"Toxic alcohol poisoning","def":"Methanol/ethylene glycol → anion gap metabolic acidosis + osmol gap; treat with fomepizole; dialysis if severe"},{"term":"Excited delirium","def":"Severe agitation, hyperthermia, tachycardia — often stimulants; high sudden death risk; chemical sedation, cooling"},{"term":"Neuroleptic malignant syndrome","def":"Antipsychotic reaction — fever, rigidity, altered consciousness, autonomic instability; stop drug, bromocriptine, dantrolene"},{"term":"Serotonin syndrome","def":"Serotonergic drug excess — tremor, clonus, hyperthermia, diarrhea; cyproheptadine; benzodiazepines; supportive"},{"term":"Malignant hyperthermia","def":"Inhaled anesthetics/succinylcholine trigger — rapid hyperthermia, rigidity; dantrolene immediately"},{"term":"Heat stroke cooling methods","def":"Ice water immersion most effective; evaporative cooling; cold packs to groin/axilla; cool IV fluids"},{"term":"Frostbite rewarming","def":"Rapid rewarming at 37-40°C water; do NOT rub; ibuprofen 400 mg; TPA within 24h for deep frostbite"},{"term":"High altitude illness treatment","def":"HACE: dexamethasone 8 mg then 4 mg q6h; HAPE: nifedipine; both: immediate descent + supplemental O2"},{"term":"Drowning resuscitation","def":"Start CPR immediately; 5 rescue breaths first if alone; do NOT attempt Heimlich; all patients observe 6-24h"},{"term":"Child abuse patterns","def":"Spiral fractures, posterior rib fractures, multiple fractures at different stages, retinal hemorrhages, unexplained bruising"},{"term":"Intimate partner violence screening","def":"HITS tool (Hurt, Insult, Threaten, Scream); universal screening; safety plan; document; mandatory reporting varies"},{"term":"Hemorrhagic vs ischemic stroke distinction","def":"CT without contrast: hemorrhagic = white (blood); ischemic = normal early; treatment differs fundamentally"},{"term":"NIHSS score interpretation","def":"National Institutes of Health Stroke Scale 0-42; >15 = severe; scores guide tPA decision and thrombectomy eligibility"},{"term":"Mechanical thrombectomy window","def":"Up to 24h in selected patients with salvageable tissue on imaging (DAWN/DEFUSE 3 trials); expands treatment window"},{"term":"DKA vs HHS comparison","def":"DKA: type 1, ketosis, pH<7.3, glucose 250-600; HHS: type 2, no ketosis, pH>7.3, glucose>600, more dehydration"},{"term":"Hyperkalemia treatment ladder","def":"Calcium gluconate (membrane stabilization) → insulin+D50 → bicarb → albuterol → Kayexalate/patiromer → dialysis"},{"term":"Pulmonary embolism Wells criteria","def":"Clinical probability score; low (<2), moderate (2-6), high (>6); guides D-dimer vs CT-PA decision"},{"term":"PE treatment by severity","def":"Submassive: anticoagulation ± CDT; massive (hemodynamically unstable): systemic thrombolysis or thrombectomy"},{"term":"Deep sedation vs general anesthesia","def":"Deep sedation: protective reflexes preserved; GA: all reflexes lost; both require monitoring and resuscitation readiness"},{"term":"Procedural sedation agents","def":"Ketamine: dissociative, bronchodilator; Propofol: fast recovery; Etomidate: hemodynamically stable; Midazolam: anxiolysis"},{"term":"Ketamine in emergency","def":"Dissociative anesthetic; preserves airway reflexes; bronchodilator; increases BP/HR; used in hypotensive patients"},{"term":"Propofol emergency use","def":"Rapid onset/offset sedation; drops BP — use cautiously in hypotensive patients; PRIS risk with prolonged infusion"},{"term":"Vasopressor comparison","def":"Norepinephrine: 1st septic shock; Epinephrine: anaphylaxis/cardiac arrest; Vasopressin: augments NE; Dopamine: cautious"},{"term":"IV access in emergency","def":"Largest accessible vein; AC or external jugular in field; central line if peripheral fails; IO if no IV access"},{"term":"Intraosseous access sites","def":"Proximal tibia (most common); distal tibia; proximal humerus; sternum (adult); all drug doses same as IV"},{"term":"Blood product storage","def":"pRBC: 42 days refrigerated; FFP: 1 year frozen; platelets: 5 days room temperature (must agitate); cryoprecipitate: frozen"},{"term":"Type and crossmatch vs screen","def":"Crossmatch: specific patient-donor compatibility; type and screen: identifies blood type + antibodies for emergency use"},{"term":"Emergency airway decision tree","def":"Can intubate? Yes: RSI. Cannot intubate, can oxygenate: wake up if possible. Cannot intubate, cannot oxygenate: surgical airway"},{"term":"LEMON airway assessment","def":"Look (face anatomy), Evaluate (3-3-2 rule), Mallampati, Obstruction, Neck mobility; predicts difficult intubation"},{"term":"Rapid sequence intubation drugs","def":"Pre-oxygenate; Sedate: ketamine/etomidate; Paralyze: succinylcholine (1.5 mg/kg) or rocuronium (1.2 mg/kg); Intubate"},{"term":"Post-intubation management","def":"Confirm with waveform capnography; CXR; ventilator settings; sedation; NG tube; reassess q1h"},{"term":"Ventilator basics","def":"Rate, tidal volume (6-8 mL/kg IBW), PEEP, FiO2; lung-protective strategy minimizes barotrauma and volutrauma"},{"term":"ARDS management","def":"Low tidal volume (6 mL/kg IBW); prone positioning 16h/day; high PEEP; conservative fluids; ECMO if refractory"},{"term":"Permissive hypercapnia","def":"Allow PaCO2 to rise in ARDS to avoid high pressures; tolerate up to 60-80 mmHg if pH >7.20"},{"term":"Electrolyte emergencies overview","def":"Life-threatening: hyper/hypokalemia (arrhythmias), severe hyponatremia (seizures), severe hypocalcemia (tetany/arrest)"},{"term":"Calcium role in resuscitation","def":"Hyperkalemia: calcium gluconate stabilizes cardiac membrane; hypocalcemia: calcium chloride (more bioavailable); citrate toxicity in massive transfusion"},{"term":"Magnesium sulfate uses","def":"Torsades de pointes, eclampsia, severe asthma (bronchodilator), hypomagnesemia; dose 2-4g IV slowly"},{"term":"Nitroglycerin uses in emergency","def":"Angina/NSTEMI chest pain; hypertensive emergency with pulmonary edema; AVOID if SBP<90 or recent PDE5 inhibitor use"},{"term":"Aspirin in ACS","def":"160-325 mg chewed immediately; irreversibly inhibits COX-1, preventing thromboxane A2 platelet aggregation; give to all ACS"},{"term":"P2Y12 inhibitors in ACS","def":"Clopidogrel/ticagrelor/prasugrel with aspirin (DAPT); administered before PCI; reduces stent thrombosis and MI"},{"term":"Thrombolysis vs PCI for STEMI","def":"Primary PCI preferred if available within 90 min (door-to-balloon); thrombolysis if PCI not available within 120 min"},{"term":"Right ventricular infarction","def":"Inferior STEMI + JVD + hypotension + clear lungs; right-sided ECG leads; avoid nitrates; preload-dependent"},{"term":"Cardiac arrest in special situations","def":"Pregnancy: left tilt + perimortem C-section 4-5 min; drowning: 5 rescue breaths; hypothermia: rewarm first; electrocution: same ACLS"},{"term":"Post-ROSC vasopressor","def":"Norepinephrine first-line after ROSC; maintain MAP 65-70 mmHg; avoid excessive fluid; early coronary angiography if STEMI"},{"term":"Targeted temperature management protocol","def":"Induction: cooling vest/catheter to 33-36°C; maintenance 24h; rewarming 0.25°C/hr; monitor for K+ and seizures"},{"term":"Pediatric sepsis recognition","def":"SIRS criteria adjusted for age; altered mental status + hypoperfusion + fever/hypothermia; early antibiotics and fluids"},{"term":"Pediatric fluid resuscitation sepsis","def":"20 mL/kg NS or LR over 5-10 min; reassess; repeat up to 60 mL/kg first hour; vasopressors if unresponsive"},{"term":"Respiratory syncytial virus (RSV)","def":"Leading cause of infant bronchiolitis; wheezing, tachypnea, hypoxia; supportive care; high-flow O2 if needed"},{"term":"Croup management","def":"Racemic epinephrine nebulized; dexamethasone 0.6 mg/kg IM/PO; cool mist helpful; observe for rebound after epi"},{"term":"Foreign body aspiration in children","def":"Toddlers 1-3 most common; sudden coughing/choking during play or eating; CXR: air trapping; bronchoscopy"},{"term":"Intussusception","def":"Intestinal telescoping — crampy abdominal pain, currant jelly stool, sausage-shaped mass; barium/air enema treatment"},{"term":"Pyloric stenosis","def":"Projectile non-bilious vomiting in 2-8 week infant; palpable olive mass; hypertrophic pylorus on US; surgical pyloromyotomy"},{"term":"Meningococcemia","def":"Petechial or purpuric rash + fever + sepsis = meningococcemia until proven otherwise; ceftriaxone immediately"},{"term":"Kawasaki disease","def":"Prolonged fever + CREAM (Conjunctivitis, Rash, Edema hands/feet, Adenopathy, Mucositis); IVIG + aspirin; coronary aneurysm risk"},{"term":"CPR quality feedback","def":"Real-time coaching on rate, depth, and recoil during CPR — improves outcomes","breakdown":"AED pads with sensors, metronome apps, CPR feedback devices. Target: 100-120/min, 2-2.4 inches, full recoil, chest compression fraction >60%"},{"term":"Post-cardiac arrest TTM","def":"Targeted temperature management: cool comatose ROSC survivors to 32-36°C for 24 hours","breakdown":"Reduces neurological damage from reperfusion injury. Active cooling devices. Prevent fever >37.7°C in ALL post-arrest patients. Rewarm 0.25°C/hour"},{"term":"ETCO2 in cardiac arrest","def":"Waveform capnography during CPR: confirms quality (>10 mmHg good) and predicts ROSC (sudden rise >40 mmHg)","breakdown":"ETCO2 <10 mmHg despite optimal CPR = poor prognosis. Sudden rise to >40 mmHg = likely ROSC. Stop CPR and check pulse"},{"term":"Airway obstruction levels","def":"Upper (oral cavity to larynx): tongue, food, foreign body. Lower airway: bronchospasm, secretions, edema","breakdown":"Upper: positioning, jaw thrust, foreign body removal, advanced airway. Lower: bronchodilators, suction, CPAP, intubation"},{"term":"Jaw thrust maneuver","def":"Airway opening without neck extension — used when spinal injury suspected","breakdown":"Fingers behind jaw angles, thrust jaw forward. Maintains spinal alignment. Replaces head-tilt chin-lift when trauma suspected"},{"term":"Bag-valve mask (BVM) technique","def":"EC clamp seal, 1 second per breath, watch for chest rise, 10-12 breaths/min, 500-600mL tidal volume","breakdown":"Two-person BVM: one seals mask, one squeezes bag — better seal and volumes. Over-ventilation harmful: causes gastric inflation, reduces venous return"},{"term":"Oropharyngeal airway (OPA)","def":"J-shaped device preventing tongue from blocking airway — ONLY for unconscious patients without gag reflex","breakdown":"Size: corner of mouth to earlobe. Insert upside down in adults, rotate 180°. Conscious patients vomit and aspirate. Never if intact gag reflex"},{"term":"Nasopharyngeal airway (NPA)","def":"Soft tube through nostril — tolerated by semiconscious patients who would vomit with OPA","breakdown":"Size: tip of nose to earlobe. Lubricate well. Contraindicated in basilar skull fracture. Less gag reflex stimulation than OPA"},{"term":"Aspiration risk management","def":"Lateral positioning for unconscious patients, suction available, minimize bag-mask ventilation pressure","breakdown":"Prevention more effective than treatment. Aspiration causes aspiration pneumonia (right lower lobe most common). Suction must be immediately available"},{"term":"Epiglottitis recognition","def":"Drooling, tripod position, muffled 'hot potato' voice, sudden-onset sore throat, toxic-appearing patient","breakdown":"DO NOT examine throat with tongue depressor. DO NOT agitate. Keep patient calm. Call ENT and anesthesia. Airway secured in OR"},{"term":"Asthma exacerbation management","def":"Albuterol (SABA) q20min x3 + systemic corticosteroids first line — magnesium, heliox, CPAP for severe","breakdown":"Oral steroids as effective as IV for mild-moderate. Intubation extremely high risk in asthma (air trapping, barotrauma). Avoid sedatives"},{"term":"Anaphylaxis epinephrine mechanism","def":"Alpha-1: vasoconstriction (raises BP). Beta-1: increases HR/contractility. Beta-2: bronchodilation (opens airways)","breakdown":"Three-pronged simultaneous action. No other drug addresses all components. IM outer thigh > IV for routine anaphylaxis. No contraindications in anaphylaxis"},{"term":"Stroke: symptom onset time","def":"Stroke clock starts at last known well — not when symptoms discovered","breakdown":"Patient wakes up with symptoms: clock starts at bedtime. Treatment window calculated from last known WELL. This affects tPA and thrombectomy eligibility"},{"term":"NIH Stroke Scale (NIHSS)","def":"11-item 0-42 score: 0=no deficit, 1-4=minor, 5-15=moderate, 16-20=moderate-severe, 21+=severe","breakdown":"Guides treatment decisions and predicts outcome. High score more likely to benefit from thrombectomy. Perform before any treatment"},{"term":"Mechanical thrombectomy","def":"Mechanical clot removal from brain artery — effective up to 24 hours in selected patients","breakdown":"Large vessel occlusion (LVO): main trunk of MCA, carotid terminus, basilar artery. Requires comprehensive stroke center. Better outcomes than tPA alone for LVO"},{"term":"STEMI treatment","def":"Primary PCI within 90 minutes of first medical contact (door-to-balloon time) — fibrinolytics if PCI unavailable","breakdown":"Every 30-minute delay in PCI increases 1-year mortality. Dual antiplatelet therapy. Anticoagulation. O2 only if SpO2 <90% (hyperoxia harms)"},{"term":"Troponin significance","def":"Cardiac protein released when heart muscle is damaged — rises 3-4h post-MI, peaks 12-24h, persists 7-14 days","breakdown":"High-sensitivity troponin detects MI within 1 hour. Serial measurements at 0h and 3h. Also elevated in: PE, myocarditis, renal failure"},{"term":"Pulmonary embolism management","def":"Anticoagulation (heparin) first line — thrombolytics for massive PE with hemodynamic instability","breakdown":"Wells score + D-dimer for probability. CTPAfor diagnosis. Massive PE: SBP <90 + PE = thrombolytics or catheter-directed therapy"},{"term":"Sepsis antibiotics timing","def":"Broad-spectrum antibiotics within 1 hour of sepsis recognition — each hour delay increases mortality 6-7%","breakdown":"Blood cultures x2 BEFORE antibiotics if this doesn't delay >45 min. Source matters: UTI vs pneumonia vs abdominal guide coverage"},{"term":"Septic shock management","def":"30mL/kg crystalloid bolus + norepinephrine (first-line vasopressor) + culture-driven antibiotics","breakdown":"Target MAP ≥65 mmHg. Lactate clearance guides adequacy. Hydrocortisone if norepinephrine >0.25 mcg/kg/min and inadequate response"},{"term":"Meningitis emergency treatment","def":"Lumbar puncture if no contraindications → immediate antibiotics + dexamethasone — don't wait for LP if contraindicated","breakdown":"Contraindications to LP: papilledema, focal neuro deficit, immunocompromised, altered MS → CT first. Treat meningococcemia with IM penicillin immediately"},{"term":"Status epilepticus progression","def":"Seizure >5 min = treat as status. Step 1: benzos → Step 2: phenytoin/fosphenytoin → Step 3: anesthesia","breakdown":"Lorazepam or midazolam first. If fails in 5 min: escalate. >30 min = refractory: propofol, phenobarbital, or ketamine infusion"},{"term":"Hyperkalemia ECG progression","def":"Peaked T waves → prolonged PR interval → wide QRS → sine wave pattern → VF or asystole","breakdown":"Any ECG change + hyperkalemia = give calcium immediately (stabilizes heart). Insulin+glucose shifts K+ intracellularly. Dialysis removes K+"},{"term":"Opioid overdose resuscitation","def":"Rescue breathing first if respiratory arrest with pulse — naloxone takes 2-3 min. CPR if no pulse","breakdown":"Opioids cause respiratory arrest before cardiac arrest in most cases. Ventilation buys time while naloxone works. Repeat naloxone for fentanyl"},{"term":"Drowning pathophysiology","def":"Submersion → laryngospasm OR aspiration → hypoxia → hypoxic cardiac arrest → anoxic brain injury","breakdown":"Freshwater vs saltwater: similar outcomes clinically. Cold water protective (diving reflex + hypothermia). Never give up on cold water drowning"},{"term":"Sickle cell vaso-occlusive crisis","def":"Severe pain from RBC sickling — triggers: dehydration, cold, infection, hypoxia, stress","breakdown":"Treatment: IV fluids, opioids, oxygen (only if hypoxic), warmth. Acute chest syndrome: fever + chest pain + infiltrate = most common cause of death"},{"term":"Toxic shock syndrome","def":"Toxin-mediated multi-organ failure — staph or strep — fever + hypotension + diffuse sunburn-like rash","breakdown":"Menstrual TSS: prolonged tampon use. Non-menstrual: wounds, nasal packing, post-surgical. Remove source + antibiotics + vasopressors + ICU"},{"term":"Blast injury classification","def":"Primary: pressure wave (lungs, bowel, ears). Secondary: fragments. Tertiary: thrown. Quaternary: burns, crush","breakdown":"Ears most sensitive: tympanic membrane rupture at lowest pressure. Lung blast injury: hemoptysis, pneumothorax, air emboli. All blast victims need full assessment"},{"term":"Pelvic fracture hemorrhage","def":"Unstable pelvis holds 4-6 liters — hemorrhagic shock without visible bleeding — pelvic binder immediately","breakdown":"Binder reduces pelvic volume, tamponades retroperitoneal space. Don't 'spring' the pelvis (opens it further). Early angioembolization for persistent hemorrhage"},{"term":"Long bone fracture blood loss","def":"Femur: 500-1000mL. Tibia: 250-500mL. Humerus: 250mL. Pelvis: 2000mL+","breakdown":"Significant hidden blood loss without external hemorrhage. Account in resuscitation calculations. Femur fractures in elderly: high 1-year mortality"},{"term":"Damage control surgery principles","def":"Abbreviated surgery: control hemorrhage and contamination → ICU correction of lethal triad → return for definitive repair","breakdown":"Pack, clip, shunt, close temporarily. Correct hypothermia, acidosis, coagulopathy in ICU. Return to OR in 24-48 hours for definitive repair"},{"term":"Neck trauma zones","def":"Zone I: clavicle to cricoid. Zone II: cricoid to mandible angle. Zone III: mandible angle to base of skull","breakdown":"Zone II: most common injury, most accessible surgically. Management changed: all symptomatic neck trauma → CT angiography regardless of zone"},{"term":"Permissive hypotension rationale","def":"Allow SBP 80-90 in penetrating trauma until surgical hemorrhage control — excessive fluids dilute clotting factors","breakdown":"Does NOT apply to TBI (need MAP >80). Optimal for penetrating trauma. Blunt trauma: more controversial. Fluids: blood products over crystalloids"},{"term":"Intraosseous (IO) access","def":"Needle through bone cortex into marrow cavity — all resuscitation drugs and fluids work as fast as IV","breakdown":"EZ-IO device: tibial plateau, proximal humerus, sternal. Standard if IV fails after 2 attempts in cardiac arrest. 15 seconds to place"},{"term":"FAST exam (ultrasound)","def":"Focused Assessment Sonography in Trauma: pericardium, RUQ (liver), LUQ (spleen), pelvis — free fluid = blood","breakdown":"Bedside, immediate, reproducible. Positive FAST + hemodynamic instability = OR immediately. Negative FAST doesn't rule out injury"},{"term":"Compartment syndrome diagnosis","def":"Pain out of proportion + pain with passive stretch (earliest sign) + tense compartment = fasciotomy needed","breakdown":"Pulselessness is LATE — don't wait. Compartment pressure >30 mmHg (or within 30 mmHg of diastolic BP) = surgical decompression urgently"},{"term":"Lethal triad of trauma","def":"Hypothermia + Acidosis + Coagulopathy — each worsens the others, rapidly fatal if uncorrected","breakdown":"Hypothermia impairs clotting enzyme function. Acidosis (from hypoperfusion) worsens coagulopathy. Correct all three simultaneously"},{"term":"Damage control resuscitation","def":"Blood products in 1:1:1 ratio (PRBC:FFP:platelets) instead of crystalloids — prevents lethal triad","breakdown":"Fresh whole blood best (military). Minimizes crystalloid use. Tranexamic acid within 3 hours. Warm blood products. Massive transfusion protocol"},{"term":"Pneumothorax types","def":"Spontaneous (tall thin young males), traumatic, tension (life-threatening), open (sucking chest wound)","breakdown":"Tension: one-way valve mechanism — air enters pleural space but cannot exit. Progressive mediastinal shift → cardiovascular collapse → death"},{"term":"Hemothorax management","def":"Small: observation. Large (>300mL or hemodynamic instability): chest tube (36-40 French)","breakdown":"Massive hemothorax (>1500mL initial or >200mL/hr x 4 hours): thoracotomy. Blood can be auto-transfused. Concurrent pneumothorax = hemopneumothorax"},{"term":"Spinal cord injury levels","def":"C3-5 diaphragm (breathe); T1-L2 arms/hands (work); L1-L3 legs; S2-4 bowel/bladder","breakdown":"Injury above C3: ventilator dependent. C4-5: shoulder movement only. Cervical injury: neurogenic shock (bradycardia + hypotension)"},{"term":"Hypothermia rewarming methods","def":"Passive (blankets), active external (warm packs to core areas), active internal (warm IV, airway, lavage, ECMO)","breakdown":"Afterdrop: core temp continues falling after rescue. Add heat to axillae/groin/neck first. ECMO for VF in severe hypothermia (<28°C)"},{"term":"Carbon monoxide poisoning treatment","def":"Remove from source, 100% O2 (non-rebreather mask), consider hyperbaric O2 for severe cases","breakdown":"100% O2 reduces CO half-life from 5 hours to 90 min. Hyperbaric O2 indications: LOC, neuro symptoms, CO>25%, pregnancy, cardiac arrhythmia"},{"term":"Cyanide poisoning management","def":"Hydroxocobalamin (Cyanokit) is antidote — 5g IV for adults — also given empirically for smoke inhalation","breakdown":"Mechanism: binds cyanide and is excreted. Old antidote kit (amyl nitrite/sodium thiosulfate) less preferred now. 100% O2 also given"},{"term":"Rhabdomyolysis diagnosis","def":"CK >5x normal + myoglobinuria (dark urine) + elevated creatinine — check CK and renal function","breakdown":"CK >10,000: significant renal risk. Aggressive fluids. Alkalinize urine (controversial). Avoid NSAIDs. Check potassium for hyperkalemia"},{"term":"NEXUS cervical spine criteria","def":"No cervical tenderness, no intoxication, normal alertness, no neurological deficit, no distracting injury = no imaging needed","breakdown":"Low-risk NEXUS: no X-ray required (reduces radiation). High-risk: CT cervical spine. Sensitivity 99% when all criteria met"},{"term":"Aortic dissection classification","def":"Stanford Type A: ascending aorta involved → emergency surgery. Type B: descending only → medical management","breakdown":"Type A mortality: 1-2% per hour without surgery. Diagnosed by CT angiography. Tearing/ripping chest pain radiating to back = classic presentation"},{"term":"Pulmonary embolism risk factors","def":"Virchow's triad: venous stasis (immobility), hypercoagulability (cancer, OCP, pregnancy), endothelial injury (surgery, trauma)","breakdown":"High-risk: hip/knee replacement, prolonged travel, hospitalization, cancer. Wells score guides imaging decision. PERC rule to exclude low risk"},{"term":"Hypertensive emergency","def":"SBP >180/120 + end-organ damage (neuro, cardiac, renal) — lower BP 10-15% in first hour — no faster","breakdown":"Too-rapid reduction causes watershed infarcts. End-organ damage distinguishes emergency from urgency. IV labetalol or nicardipine. Oral for urgency"}]);
  fc.hard=fc.hard.concat([{"term":"Cushing's response","def":"Triad of hypertension + bradycardia + irregular respirations — indicates critically elevated ICP; herniation imminent"},{"term":"Cerebral herniation types","def":"Uncal: CN III palsy, blown pupil; Central: Cheyne-Stokes breathing; Tonsillar: apnea, sudden death"},{"term":"Diffuse axonal injury","def":"Shear injury from rapid deceleration — MRI shows small hemorrhages; poor prognosis; CT may be normal"},{"term":"Second impact syndrome","def":"Second concussion before first resolves → massive cerebral edema; potentially fatal; young athletes"},{"term":"Post-cardiac arrest brain injury","def":"Hypoxic-ischemic encephalopathy after ROSC; TTM helps; prognostication not before 72h; SSEP and EEG used"},{"term":"Extracorporeal CPR (ECPR)","def":"VA-ECMO during refractory cardiac arrest; select patients; ELSO guidelines; best results if early deployment"},{"term":"Double sequential defibrillation","def":"Two defibrillators in rapid succession for refractory VF; evidence limited but used in refractory cases"},{"term":"Sodium bicarbonate indications","def":"TCA overdose (QRS>100ms), hyperkalemia, severe metabolic acidosis (pH<7.1), cocaine cardiotoxicity"},{"term":"Cyanide antidote mechanism","def":"Hydroxocobalamin binds cyanide → cyanocobalamin (excreted); 5 g IV; do NOT give sodium thiosulfate simultaneously"},{"term":"Organophosphate toxidrome","def":"SLUDGE + DUMBELS; muscarinic (atropine) and nicotinic (pralidoxime) effects; pralidoxime within 24-48h"},{"term":"Tranexamic acid mechanism","def":"Antifibrinolytic — blocks lysine-binding sites on plasminogen; most effective within 3h of trauma; CRASH-2 trial"},{"term":"Abdominal compartment syndrome","def":"Intra-abdominal pressure >20 mmHg with organ dysfunction; decompressive laparotomy indicated"},{"term":"Venous thromboembolism in pregnancy","def":"Hypercoagulable state; LMWH is anticoagulant of choice; thrombolysis for massive PE only if dying"},{"term":"Blunt cerebrovascular injury","def":"Carotid/vertebral artery injury after blunt trauma — stroke risk; screen with CTA; antiplatelet or anticoagulation"},{"term":"Trauma in pregnancy","def":"Fetal monitoring 4h minimum; DPL above fundus; MVC leading cause; Kleihauer-Betke for fetomaternal hemorrhage"},{"term":"Fat embolism syndrome","def":"After long bone fracture/liposuction — dyspnea, confusion, petechial rash; supportive; early fracture fixation"},{"term":"Air embolism","def":"IV air → right heart → pulmonary embolism; Durant's maneuver (left lateral decubitus); hyperbaric O2"},{"term":"Hypothermic cardiac arrest protocol","def":"ACLS + rewarming; defibrillate once at <30°C, retry every 1°C rise; ECMO preferred for rewarming during arrest"},{"term":"Perimortem cesarean delivery","def":"Emergency C-section during maternal arrest; must deliver within 5 min of arrest to improve maternal/fetal outcomes"},{"term":"Vascular injury repair principles","def":"Damage control: shunting first; definitive: anastomosis or graft; reperfusion injury and compartment syndrome risks"},{"term":"Targeted temperature management evidence","def":"TTM trial: 33°C vs 36°C — both better than fever; avoid hyperthermia >37.8°C for 72h post-ROSC absolutely"},{"term":"Refeeding syndrome emergency","def":"Phosphate drops rapidly when refeeding malnourished patients — cardiac arrhythmias, rhabdomyolysis, death"},{"term":"Immune reconstitution inflammatory syndrome","def":"IRIS after starting HIV treatment — paradoxical worsening; opportunistic infection unmasked; treat with steroids"},{"term":"Hantavirus pulmonary syndrome","def":"Rodent contact → fever then rapid pulmonary edema; bilateral infiltrates; ECMO for severe; ~38% mortality"},{"term":"Tetanus emergency","def":"Trismus, risus sardonicus, opisthotonus; TIG + metronidazole + diazepam + ICU; airway management critical"},{"term":"Botulism emergency","def":"Descending paralysis, dysarthria, diplopia; antitoxin early; respiratory failure leading cause of death; no fever"},{"term":"SIADH vs DI in neurotrauma","def":"SIADH: low Na, concentrated urine → water restrict; DI: high Na, dilute urine → DDAVP; both after TBI"},{"term":"Rabies post-exposure management","def":"Wound irrigation; RIG into wound; vaccine days 0,3,7,14; once symptoms appear: near 100% fatal"},{"term":"Epiglottitis airway management","def":"Allow patient to sit up; call anesthesia/ENT for controlled intubation in OR; avoid agitation; racemic epi may temporize"},{"term":"High-dose insulin therapy","def":"For refractory cardiogenic shock in Ca-channel blocker/beta-blocker overdose; 1 unit/kg bolus then infusion"},{"term":"Prone positioning","def":"Severe ARDS — 16h/day prone improves V/Q matching; 28-day mortality reduction; risk: pressure sores, ETT dislodgment"},{"term":"Extracorporeal membrane oxygenation","def":"VA-ECMO: cardiac support; VV-ECMO: respiratory; cannula-related bleeding and thrombosis major risks"},{"term":"Pulseless electrical activity algorithm","def":"CPR + epinephrine every 3-5 min; treat Hs and Ts; no shock; reversible causes drive survival"},{"term":"Thromboelastography","def":"TEG/ROTEM: whole-blood viscoelastic coagulation testing; guides product transfusion in massive hemorrhage"},{"term":"Thoracic aorta endovascular repair","def":"TEVAR for Type B dissection and traumatic aortic injury; less morbidity than open; spinal cord ischemia risk"},{"term":"Balanced resuscitation evidence","def":"PROPPR trial: 1:1:1 ratio improves 24h survival; reduces coagulopathy; modern standard for massive transfusion"},{"term":"Emergency department thoracotomy","def":"Penetrating torso trauma with witnessed arrest <15 min; cardiac tamponade decompression; aortic cross-clamp"},{"term":"Tension hydrothorax","def":"Fluid (blood) under pressure causing mediastinal shift — haemothorax with kinked drain; finger thoracostomy or chest tube"},{"term":"Retroperitoneal hematoma zones","def":"Zone 1 (central): always explore; Zone 2 (flank): explore if penetrating; Zone 3 (pelvic): pack + IR embolization"},{"term":"Damage control orthopedics","def":"External fixation first (DCO) vs early total care (ETC); physiological status guides timing; DCO if borderline/critical"},{"term":"Crush syndrome hyperkalemia management","def":"Calcium gluconate + insulin+D50 + sodium bicarbonate + albuterol; dialysis if K>7 or renal failure"},{"term":"Pediatric non-accidental trauma indicators","def":"Inconsistent history, developmental mismatch, bilateral retinal hemorrhages, posterior rib fractures, classic metaphyseal lesions"},{"term":"Hypothermic cardiac arrest resuscitation","def":"VF resistant to defibrillation below 30°C — continue CPR during rewarming — ECMO for deep hypothermia","breakdown":"'Not dead until warm and dead.' Longest documented neurologically intact survival: >60 min submersion in cold water. Aggressive rewarming justified"},{"term":"Refractory VF management","def":"VF after 3 shocks + amiodarone → consider double sequential defibrillation (DSED) + esmolol infusion","breakdown":"DSED: two defibrillators fire simultaneously from different vectors. DOSE VF trial: improved ROSC. Esmolol reduces VF recurrence between shocks"},{"term":"Post-ROSC hyperoxia avoidance","def":"After ROSC, target SpO2 92-98% — hyperoxia generates reactive oxygen species damaging ischemic neurons","breakdown":"Titrate oxygen DOWN after ROSC. Both hypoxia AND hyperoxia worsen neurological outcomes. ETCO2 35-45 mmHg target — avoid hyperventilation too"},{"term":"Traumatic brain injury secondary insults","def":"Hypoxia (SpO2 <90%) + hypotension (SBP <90) each independently double TBI mortality — prevent both aggressively","breakdown":"Secondary brain injury causes most deaths and disability. Treat systemic insults before elevated ICP. MAP >80 target. SpO2 >95% target"},{"term":"Cushing's Triad physiology","def":"Hypertension + bradycardia + irregular respirations from rising ICP — reflex to maintain cerebral perfusion","breakdown":"Widened pulse pressure (high systolic, lower diastolic). Bradycardia is reflex response to hypertension. Late sign — intervene before Cushing's appears"},{"term":"Intracranial hemorrhage types","def":"Epidural (biconvex, lucid interval, arterial), subdural (concave, venous, elderly), intracerebral (HTN), subarachnoid (worst HA of life)","breakdown":"EDH: lucid interval then rapid deterioration (MMA tear). Chronic SDH: elderly, alcoholics. SAH: aneurysm rupture. ALL are neurosurgical emergencies"},{"term":"Tension pneumothorax needle decompression","def":"14g needle at 2nd ICS MCL OR 4th/5th ICS AAL — insert perpendicular, listen for air rush, leave in place","breakdown":"4th/5th ICS AAL preferred in obese/muscular patients (less chest wall thickness). High failure rate (50%) at 2nd MCL in these patients. Converts to open PTX needing chest tube"},{"term":"Emergency thoracotomy indications","def":"Penetrating trauma: arrest <15 min or signs of life. Blunt trauma: arrest <5 min — open chest, relieve tamponade, cross-clamp aorta","breakdown":"Survival: penetrating 11%, blunt <2%. Internal cardiac massage. Pericardiotomy for tamponade. Aortic cross-clamp redirects flow to heart and brain. High-skill procedure"},{"term":"Perimortem cesarean delivery physiology","def":"Gravid uterus compresses IVC + aorta reducing CPR cardiac output 40% — delivery within 5 min restores venous return","breakdown":"Perform at bedside, don't wait for OR. Continue CPR throughout procedure. Can save mother AND fetus ≥24 weeks. Manual uterine displacement is temporary measure only"},{"term":"Succinylcholine fatal hyperkalemia","def":"Contraindicated in burns >48h, crush, denervation, immobility >5 days — upregulated ACh receptors cause massive K+ efflux","breakdown":"Normal: K+ released only from neuromuscular junction. After upregulation: K+ from entire muscle membrane. Serum K+ can rise 5+ mEq/L → cardiac arrest. Use rocuronium instead"},{"term":"RSI rapid sequence intubation","def":"Sedation + paralysis simultaneously to achieve intubation conditions while minimizing aspiration risk","breakdown":"Preoxygenate 3-5 min. Sedative: etomidate or ketamine. Paralytic: succinylcholine or rocuronium. Confirm with waveform capnography. Bag-mask if desaturates"},{"term":"Traumatic aortic injury","def":"Deceleration forces tear aorta at ligamentum arteriosum — widened mediastinum on CXR — 80% die at scene","breakdown":"High-speed MVA, fall from height. CT angiography diagnoses. Survivors: endovascular stent repair (TEVAR) preferred over open surgery. Hypotensive resuscitation"},{"term":"TXA (tranexamic acid) in trauma","def":"Anti-fibrinolytic given within 3 hours of injury — CRASH-2 trial: reduces hemorrhage mortality — harmful if given after 3h","breakdown":"1g IV over 10 min, then 1g over 8 hours. Military standard. Growing civilian prehospital use. Prevents clot breakdown without promoting clotting per se"},{"term":"Osmotic demyelination syndrome","def":"Rapid hyponatremia correction causes myelin sheath destruction — locked-in syndrome or death","breakdown":"Prevent by correcting Na+ no faster than 8-10 mEq/L per 24h. Central pontine myelinolysis. Risk highest with chronic hyponatremia. Monitor Na+ every 2-4h"},{"term":"DIC (disseminated intravascular coagulation)","def":"Trauma or infection activates clotting throughout vasculature — simultaneous clotting AND bleeding — consumes all factors","breakdown":"Low fibrinogen (<100), prolonged PT/PTT, thrombocytopenia + clinical bleeding. Treatment: treat cause, FFP (factors), cryoprecipitate (fibrinogen), platelets"},{"term":"REBOA (resuscitative endovascular balloon occlusion of aorta)","def":"Femoral artery balloon inflated in aorta — redirects blood to heart and brain, reduces hemorrhage below balloon","breakdown":"Bridge to surgery. Zone I for thoracoabdominal hemorrhage, Zone III for pelvic hemorrhage. Less invasive than emergency thoracotomy. Growing trauma use"},{"term":"Local anesthetic systemic toxicity (LAST)","def":"Seizures + cardiovascular collapse from local anesthetic overdose — antidote is 20% lipid emulsion (Intralipid)","breakdown":"'Lipid sink' sequesters local anesthetic from cardiac sodium channels. 1.5 mL/kg bolus + infusion. Avoid propofol. Prolonged CPR may be needed"},{"term":"Neuroleptic malignant syndrome vs serotonin syndrome","def":"NMS: antipsychotic trigger, days onset, lead-pipe rigidity, no clonus. SS: serotonergic trigger, hours onset, clonus, hyperreflexia","breakdown":"NMS treatment: stop drug, dantrolene, bromocriptine. SS treatment: cyproheptadine, benzos, cooling. Both cause hyperthermia and AMS but managed differently"},{"term":"Massive transfusion protocol (MTP)","def":"Predefined 1:1:1 PRBC:FFP:platelets ratio activated for massive hemorrhage — prevents dilutional coagulopathy","breakdown":"Activates blood bank to prepare and release products simultaneously. Reduces crystalloid use. TXA given early. Calcium for citrate chelation in massive transfusion"},{"term":"Blast lung (primary blast injury)","def":"Pressure wave causes alveolar-capillary disruption — pulmonary hemorrhage, pneumothorax, air emboli — no visible injury","breakdown":"Most serious primary blast injury. Presents like pulmonary contusion but more severe. Avoid high positive pressure ventilation (pneumothorax risk)"},{"term":"Hyperbaric oxygen therapy","def":"2-3 ATA pressure chamber — indications: CO poisoning, DCS, air embolism, necrotizing infection, osteomyelitis","breakdown":"Eliminates CO in 80 min vs 90 min on 100% NRB vs 5 hours on room air. Clostridial myonecrosis (gas gangrene). Radiation necrosis. Delayed wound healing"},{"term":"Waveform capnography for ROSC","def":"Sudden ETCO2 rise to >40 mmHg during CPR = ROSC — most reliable real-time indicator available","breakdown":"CO2 from tissues carried to lungs when heart resumes. Stop CPR and check pulse when ETCO2 rises suddenly. Not explained by compressor change or drug"},{"term":"Neurogenic shock vs hypovolemic shock","def":"Neurogenic: bradycardia + hypotension + warm skin (vasodilation). Hypovolemic: tachycardia + hypotension + cool skin (vasoconstriction)","breakdown":"Spinal cord injury (above T6) disrupts sympathetic outflow → bradycardia and vasodilation. Treatment: vasopressors (phenylephrine) + judicious fluids"},{"term":"ECMO-CPR (ECPR)","def":"Extracorporeal CPR for refractory cardiac arrest — provides mechanical circulatory support during continued resuscitation","breakdown":"Femoral cannulation while CPR continues. Allows time for reversible cause correction (rewarming, PCI, toxin clearance). Specialized centers only. Growing evidence base"},{"term":"Biomarker neuroprognostication","def":"NSE >33 mcg/L at 48-72h post-arrest predicts poor neurological outcome — used with EEG, SSEP, brain imaging","breakdown":"Multimodal prognostication: no single test sufficient. NSE = neuron-specific enolase. Confounders: hemolysis elevates NSE falsely. Serum NFL also promising"},{"term":"Damage control resuscitation vs conventional","def":"DCR: blood products 1:1:1, permissive hypotension, TXA, avoid crystalloids. Conventional: normal saline boluses","breakdown":"PROPPR trial: 1:1:1 improves 24h survival and hemostasis. Every liter of NS: 0.1 pH drop, 4.5°C temperature drop. Crystalloid = worsens lethal triad"},{"term":"Wartime vs civilian hemorrhage control","def":"TCCC (military): CAT tourniquet + Combat Gauze + TXA. Civilian: Stop the Bleed: direct pressure + wound packing + tourniquet","breakdown":"Military evidence drives civilian hemorrhage control advances. 'Compressible hemorrhage' vs 'non-compressible' (junctional, truncal). REBOA for non-compressible"},{"term":"Therapeutic hypothermia post-arrest evidence","def":"TTM2 trial (2021): 33°C vs 37.5°C showed no neurological benefit — current target: prevent fever (>37.7°C) in all ROSC patients","breakdown":"Earlier TTM1: 33°C vs 36°C no difference. TTM2: questioned value of active cooling vs fever prevention. Current consensus: maintain normothermia, aggressively prevent fever"},{"term":"Point-of-care ultrasound in emergencies","def":"RUSH exam: Resuscitation, Assessment of Shock and Hypotension — cardiac function, IVC, free fluid, lung","breakdown":"FAST + cardiac + lung in 5 minutes. IVC collapse = hypovolemia. Absent lung sliding = pneumothorax. Pericardial effusion = tamponade. Bilat B-lines = pulmonary edema"},{"term":"Wilderness vs urban emergency differences","def":"Evacuation time >1 hour changes management: wound closure timing, improvised splints, extended CPR decisions","breakdown":"Wilderness CPR: can stop after 30 min in normothermic patient if no ROSC. Evacuation decision: walk out vs litter vs helicopter. Delayed care = different antibiotic decisions"},{"term":"Intraosseous drug delivery pharmacokinetics","def":"IO drugs reach central circulation in 15-30 seconds — same as IV — all cardiac arrest drugs can be given IO","breakdown":"IO > endotracheal drug delivery (unpredictable absorption). Flush with 10-20mL saline after each drug. Pain with conscious patients (lidocaine IO first)"},{"term":"Global cerebral ischemia after arrest","def":"Post-cardiac arrest brain injury: cerebral edema, seizures, cognitive impairment — from reperfusion injury","breakdown":"Excitotoxicity, free radicals, calcium influx cause neuronal death on reperfusion. TTM reduces this. Seizures worsen outcome (increase metabolic demand). EEG monitoring"},{"term":"Cardiac arrest after ROSC re-arrest","def":"Re-arrest occurs in 30-40% of ROSC patients — continuous cardiac monitoring mandatory post-arrest","breakdown":"Treat underlying cause: STEMI (cath lab), hyperkalemia (calcium + insulin), tamponade (pericardiocentesis). Antiarrhythmic infusions for recurrent VF"},{"term":"Tension pneumothorax in ventilated patient","def":"High peak airway pressures + hypotension + desaturation in mechanically ventilated patient = tension PTX until proven otherwise","breakdown":"Positive pressure ventilation rapidly converts simple PTX to tension. Immediate needle decompression. No time for X-ray confirmation if hemodynamically unstable"},{"term":"Hemostatic resuscitation endpoints","def":"Lactate <2 mmol/L, base deficit >-6, pH >7.35, fibrinogen >2 g/L, TEG/ROTEM normal clot formation","breakdown":"Traditional endpoints (BP, HR) inadequate. Viscoelastic testing (TEG, ROTEM) guides component-specific replacement. Lactate clearance predicts survival"},{"term":"Massive transfusion hypocalcemia","def":"Citrate preservative in blood products chelates free ionized calcium — impairs cardiac contractility and coagulation","breakdown":"Calcium chloride (3x more elemental calcium than gluconate) per 4 units blood products in massive transfusion. Monitor ionized calcium. 1g CaCl2 IV bolus"},{"term":"Burn resuscitation (Parkland formula)","def":"4 mL/kg/% TBSA burned of LR over 24h — half in first 8h, half in next 16h — titrate to urine output 0.5-1 mL/kg/hr","breakdown":"Controversially high volume: many centers now use modified Brooke (2mL/kg/%). Over-resuscitation causes abdominal compartment syndrome, pulmonary edema"}]);
  qz.easy=qz.easy.concat([{"q":"What is the FIRST step when you arrive at any emergency scene?","opts":["Call 911","Check scene safety","Start CPR","Apply tourniquet"],"correct":1,"explanation":"Scene safety (BSI/PPE) is always first — you cannot help if you become a victim"},{"q":"A person collapses and is unresponsive with no normal breathing. What is the correct sequence?","opts":["Check pulse, call 911, start CPR","Call 911, give rescue breaths, then compressions","Call 911 (or have someone else call), start CPR","Apply AED first, then call 911"],"correct":2,"explanation":"Call 911 and start CPR — or start CPR while someone calls. Early CPR and early defibrillation are the two most impactful steps"},{"q":"For an adult, what is the correct CPR compression depth?","opts":["1 inch","At least 2 inches (5 cm)","3 inches","As deep as possible"],"correct":1,"explanation":"2–2.4 inches (5–6 cm) for adults; deeper risks injury without benefit"},{"q":"The correct CPR compression rate for any age is:","opts":["60–80/min","80–100/min","100–120/min","120–140/min"],"correct":2,"explanation":"100–120 compressions per minute — confirmed by AHA guidelines for all ages"},{"q":"An AED advises 'no shock indicated.' What should you do?","opts":["Check for a pulse and stop if present","Continue CPR for 2 minutes then re-analyze","Stop and wait for EMS","Give rescue breaths only"],"correct":1,"explanation":"If AED says no shock, resume CPR immediately for 2 min then re-analyze — the rhythm may still be a non-shockable arrest"},{"q":"A conscious adult is clutching their throat and cannot speak. What do you do?","opts":["Perform rescue breaths","Call 911 immediately and wait","Give abdominal thrusts (Heimlich maneuver)","Place in recovery position"],"correct":2,"explanation":"The universal choking sign + inability to speak = complete airway obstruction → abdominal thrusts"},{"q":"Anaphylaxis should be treated FIRST with:","opts":["Antihistamine (Benadryl)","Albuterol inhaler","Epinephrine (EpiPen) IM","Corticosteroids IV"],"correct":2,"explanation":"Epinephrine is the only first-line treatment for anaphylaxis — antihistamines and steroids are adjuncts only"},{"q":"Where is an epinephrine auto-injector (EpiPen) injected?","opts":["Buttocks","Outer thigh","Upper arm","Abdomen"],"correct":1,"explanation":"Anterolateral thigh — fastest absorption; can be given through clothing in emergency"},{"q":"Heat stroke differs from heat exhaustion because heat stroke includes:","opts":["Heavy sweating and weakness","Normal mental status and pale skin","Altered mental status and usually no sweating","Low blood pressure only"],"correct":2,"explanation":"Heat stroke = neurological dysfunction (confusion, altered consciousness) ± dry skin; heat exhaustion = weakness, sweating, normal mental status"},{"q":"You see a victim of lightning strike who appears not to be breathing. You should:","opts":["Wait for EMS since the victim may still be electrified","Begin CPR immediately — lightning victims are safe to touch","Only assess; do not touch until storm passes","Give rescue breaths only"],"correct":1,"explanation":"Lightning victims are NOT electrically charged — begin CPR immediately; lightning reversal of electrical cardiac arrest is possible"},{"q":"A patient has a burn covering the entire right arm and front of the chest. Using Rule of Nines, the approximate BSA burned is:","opts":["18%","27%","36%","13.5%"],"correct":1,"explanation":"Arm = 9%, chest front = 18%; total = 27% BSA"},{"q":"For a patient with suspected spinal injury, you should:","opts":["Log-roll immediately to check the back","Maintain manual in-line cervical stabilization and minimize movement","Place in recovery position","Perform jaw thrust only if breathing is absent"],"correct":1,"explanation":"Minimize movement; maintain inline stabilization; only move if immediate life threat requires it"},{"q":"A patient is found unconscious and breathing but vomiting. What position is correct?","opts":["Supine (flat on back)","Recovery position (lateral)","Prone (face down)","Sitting upright"],"correct":1,"explanation":"Recovery position protects the airway from aspiration while maintaining breathing"},{"q":"Signs of opioid overdose include all EXCEPT:","opts":["Pinpoint pupils","Slow/absent breathing","Agitation and combativeness","Unresponsiveness"],"correct":2,"explanation":"Opioid overdose causes CNS depression — unconscious, not agitated; agitation suggests stimulant or withdrawal"},{"q":"Carbon monoxide poisoning is dangerous because:","opts":["It causes cyanosis detectable with pulse oximetry","Standard pulse oximetry reads falsely normal SpO2","It only affects children","Symptoms appear immediately"],"correct":1,"explanation":"CO binds hemoglobin like O2; pulse ox cannot distinguish — victim appears well-oxygenated but is not"},{"q":"A child has a fever of 103°F and suddenly has a 45-second generalized seizure. It stops on its own. The correct response is:","opts":["Start CPR immediately","Protect from injury, time the seizure, call 911 if >5 min","Hold the child tightly to stop movements","Place something in the mouth"],"correct":1,"explanation":"Simple febrile seizures are usually brief and self-limited; protect from injury; call 911 if >5 min (status epilepticus)"},{"q":"Naloxone (Narcan) works by:","opts":["Stimulating the opioid receptors","Blocking opioid receptors and reversing respiratory depression","Metabolizing opioids in the bloodstream","Stimulating the respiratory center directly"],"correct":1,"explanation":"Naloxone is a competitive opioid antagonist — displaces opioids from receptors; duration shorter than most opioids — may need repeat doses"},{"q":"When applying a tourniquet, you should:","opts":["Apply loosely to reduce pain","Apply 2-3 inches below the wound","Apply 2-3 inches above the wound and tighten until bleeding stops","Remove after 30 minutes"],"correct":2,"explanation":"2-3 inches proximal (above) the wound; tighten until bleeding stops; note the time; do NOT remove in field"},{"q":"A patient has a sucking chest wound (air moving through wound). You should:","opts":["Apply an occlusive dressing sealed on all 4 sides","Apply a 3-sided occlusive dressing","Pack the wound with gauze","Apply direct pressure only"],"correct":1,"explanation":"3-sided dressing acts as a flutter valve — air can exit on exhale but cannot enter on inhale; fully sealing risks tension pneumothorax"},{"q":"The primary danger of a tension pneumothorax is:","opts":["Infection of the pleural space","Mediastinal shift compressing the heart and great vessels causing obstructive shock","Pneumonia development","Rib fractures"],"correct":1,"explanation":"Air under pressure shifts mediastinum, kinks great vessels, reduces venous return → obstructive shock; immediately fatal if untreated"},{"q":"Which type of shock results from severe allergic reaction?","opts":["Cardiogenic","Obstructive","Distributive (anaphylactic)","Hypovolemic"],"correct":2,"explanation":"Anaphylactic shock is distributive — massive vasodilation from histamine/mediators causes relative hypovolemia"},{"q":"A patient with known diabetes is found confused and shaking. Blood glucose is 48 mg/dL. They can swallow. You give:","opts":["Insulin immediately","15-20g oral glucose (juice, glucose tablets)","Water only","Nothing — call 911 and wait"],"correct":1,"explanation":"Rule of 15: 15g glucose, recheck in 15 min; if conscious and can swallow, oral glucose is safe and effective"},{"q":"What is the CORRECT action for an impaled object in the eye?","opts":["Remove the object carefully","Flush with water for 20 minutes","Stabilize the object and shield BOTH eyes; do NOT remove","Apply pressure to stop bleeding"],"correct":2,"explanation":"Never remove impaled objects; stabilize in place; shield both eyes (consensual movement); immediate ophthalmology"},{"q":"A patient has a suspected broken femur (thigh bone). Besides immobilization, you are most concerned about:","opts":["Infection","Significant blood loss (up to 2 liters) causing shock","Pain only","Fat embolism only"],"correct":1,"explanation":"Femur fracture can cause 1-2 L blood loss internally — enough to cause hypovolemic shock; hemodynamic monitoring essential"},{"q":"Which is the CORRECT treatment for frostbite in the field?","opts":["Rub the affected area vigorously to restore circulation","Rewarm rapidly in warm (not hot) water 37-40°C","Pop blisters to prevent infection","Continue the activity to generate heat"],"correct":1,"explanation":"Rapid rewarming in 37-40°C water is the correct treatment; rubbing causes tissue damage; do NOT rewarm if refreezing risk"},{"q":"A trauma patient is found at the bottom of a staircase, unconscious. Your PRIMARY concern is:","opts":["Stopping any visible bleeding","Airway with cervical spine precautions","Checking pupils","Looking for fractures"],"correct":1,"explanation":"Airway first in all trauma patients; c-spine precautions assumed until cleared; other injuries addressed after ABC security"},{"q":"A patient's skin is hot, dry, and flushed with altered mental status after working outside in 100°F heat. This suggests:","opts":["Heat exhaustion","Heat cramps","Heat stroke — EMERGENCY","Normal exertion response"],"correct":2,"explanation":"Hot dry skin + altered mental status = heat stroke; immediately cool the patient; this is life-threatening"},{"q":"What does SAMPLE stand for in patient history?","opts":["Signs, Allergies, Medications, Past history, Last meal, Events","Symptoms, Airway, Mechanism, Pupils, Level of consciousness, Events","Scene, Assessment, Medical, Pulse, Level of consciousness, Exam","Signs, Anaphylaxis, Movement, Pelvis, Lungs, Extremities"],"correct":0,"explanation":"Signs/Symptoms, Allergies, Medications, Pertinent past history, Last oral intake, Events leading to emergency"},{"q":"A responsive adult is having a seizure. You should NOT:","opts":["Time the seizure","Protect the head from impact","Put something in the patient's mouth","Call 911 if seizure lasts >5 minutes"],"correct":2,"explanation":"NEVER place anything in mouth during seizure — you will cause injury to patient and yourself; protect from harm, time it, call 911 if prolonged"},{"q":"What is the FIRST priority in treating a burn patient?","opts":["Apply burn cream","Stop the burning process (remove from heat source/cool with cool water)","Pop blisters","Wrap with dry bandage immediately"],"correct":1,"explanation":"Stop the burn first — remove from source, cool with cool running water 20 min; then cover, keep warm, transport"},{"q":"A 2-year-old is found with an unknown number of adult Tylenol tablets. The child seems fine now. You should:","opts":["Wait and observe at home","Call Poison Control (1-800-222-1222) or go to ED immediately","Give the child milk to absorb the medication","Induce vomiting"],"correct":1,"explanation":"Acetaminophen overdose causes delayed liver failure — the child may look normal for 24h; immediate evaluation and possible N-acetylcysteine"},{"q":"Which burn requires IMMEDIATE transport to a burn center?","opts":["Superficial burn on the forearm from a hot pan","Full-thickness burn on the hand, face, or genitals","Sunburn covering the entire back","Minor blistering on one finger"],"correct":1,"explanation":"Full-thickness burns on hands, face, feet, genitals, perineum, major joints = burn center criteria; functional and cosmetic significance"},{"q":"A patient describes the 'worst headache of my life' that came on suddenly. What is your HIGHEST concern?","opts":["Migraine headache","Tension headache","Subarachnoid hemorrhage — brain bleed","Sinus infection"],"correct":2,"explanation":"'Thunderclap headache' — worst headache of life with sudden onset — is SAH until proven otherwise; 50% mortality; CT head stat"},{"q":"Domestic violence screening should be performed:","opts":["Only when injuries are visible","Only in the ED","Universally for all patients in private","Only for women"],"correct":2,"explanation":"Universal screening in private setting for all patients; IPV affects all demographics; HITS tool; documentation is critical"},{"q":"A patient is stung by multiple bees and develops throat tightness, hives, and dizziness. After giving epinephrine, you should:","opts":["Discharge home immediately","Monitor 4-8 hours for biphasic anaphylaxis reaction","Give antihistamine only","Give a second EpiPen immediately regardless of response"],"correct":1,"explanation":"Biphasic anaphylaxis can occur 1-72h later; all anaphylaxis patients should be observed 4-8 hours even if initial response to epi is good"},{"q":"Which intervention is FIRST for a pulseless patient in ventricular fibrillation?","opts":["Give epinephrine","Start chest compressions","Defibrillation as soon as possible","Secure the airway"],"correct":2,"explanation":"For witnessed VF, immediate defibrillation gives best chance of survival; if AED not immediately available, begin CPR until it arrives"},{"q":"You find an unconscious adult. How long should you take to check for a pulse before starting CPR?","opts":["Up to 30 seconds","Up to 10 seconds","Until you are absolutely sure","1 minute"],"correct":1,"explanation":"No more than 10 seconds for pulse check — if no pulse or uncertain, begin CPR; delay costs brain cells"},{"q":"What is the CORRECT first aid for a person whose clothing is on fire?","opts":["Throw water on them","Stop, Drop, and Roll","Fan the flames to extinguish","Remove clothing first"],"correct":1,"explanation":"Stop, drop, and roll smothers flames; water is second option; do not run (fans flames); do not remove burning clothing (may remove skin)"},{"q":"A trauma patient has uncontrolled leg bleeding from a deep laceration. Direct pressure has failed. What next?","opts":["Apply a pressure bandage and hope for the best","Elevate the limb only","Apply a tourniquet 2-3 inches above the wound","Pack with regular gauze only"],"correct":2,"explanation":"When direct pressure fails on extremity: tourniquet is next; hemostatic gauze wound packing is alternative for wounds where tourniquet can't be placed"},{"q":"What does AED stand for, and when should it be used?","opts":["Automatic Emergency Defibrillator — use for any unconscious person","Automated External Defibrillator — use when a person is pulseless and not breathing normally","Acute Emergency Device — use for chest pain only","Airway Emergency Device — use for choking"],"correct":1,"explanation":"AED: automated external defibrillator; use when victim is unresponsive, pulseless, not breathing normally; it will analyze and advise shock if needed"},{"q":"A patient is found face-down, pulseless and apneic. What is the FIRST action?","opts":["Start compressions immediately without moving the patient","Carefully roll the patient face-up (log roll if spine injury suspected), then begin CPR","Check breathing only, don't move","Give rescue breaths before compressions"],"correct":1,"explanation":"CPR cannot be performed face-down; roll supine carefully; if trauma suspected, use two rescuers for log roll with c-spine protection"},{"q":"How long should CPR be performed before stopping in a non-hospital setting?","opts":["20 minutes","Until EMS arrives, the patient shows signs of life, or you are too exhausted to continue","5 minutes","10 minutes maximum"],"correct":1,"explanation":"Continue CPR until: AED advises and delivers shock, patient shows signs of life, EMS takes over, you are physically unable, or a physician pronounces death"},{"q":"Which of the following is a sign of INTERNAL bleeding?","opts":["Bleeding from a laceration","Distended (swollen/rigid) abdomen, tachycardia, hypotension without visible injury","High blood pressure","Slow heart rate"],"correct":1,"explanation":"Internal bleeding: pain/distension at injury site, signs of shock (tachycardia, hypotension), referred shoulder pain (diaphragm irritation), altered mental status"},{"q":"A patient with asthma is having a severe attack. The rescue medication is:","opts":["Oral steroid tablets","Short-acting beta-agonist (albuterol/salbutamol) inhaler","Antihistamine","Long-acting bronchodilator only"],"correct":1,"explanation":"Short-acting beta-agonist (SABA) like albuterol is the first-line rescue medication for acute bronchospasm; opens airways within minutes"},{"q":"The MOST common cause of airway obstruction in an unconscious patient is:","opts":["Foreign body (food)","The tongue falling back and blocking the airway","Vomit","Swelling from anaphylaxis"],"correct":1,"explanation":"The tongue is the most common cause — in unconscious patients, muscle tone is lost and tongue falls posteriorly; head-tilt chin-lift or jaw thrust opens the airway"},{"q":"A patient with suspected diabetic emergency cannot swallow. You should:","opts":["Give oral glucose","Give nothing and wait for EMS","Apply glucagon injection if available, or call EMS immediately","Give insulin"],"correct":2,"explanation":"If unconscious or cannot protect airway: cannot give oral glucose (aspiration risk); glucagon IM or IV dextrose by trained provider; call 911"},{"q":"What does pale, cool, clammy skin indicate in a trauma patient?","opts":["Fever","Shock — inadequate perfusion/blood loss","Sunburn","Nervous response only"],"correct":1,"explanation":"Pale, cool, diaphoretic skin = vasoconstriction from sympathetic activation trying to maintain BP during shock; early and important sign of blood loss"},{"q":"A patient's respirations are 6 per minute and shallow. This is:","opts":["Normal","Bradypnea — possibly requiring assisted ventilation","Tachypnea","Hyperventilation"],"correct":1,"explanation":"Normal adult respiration is 12-20/min; <10 with shallow depth = inadequate ventilation; consider assisted ventilation (BVM) to prevent respiratory failure"},{"q":"For a patient who ingested a corrosive chemical (acid or alkali), you should:","opts":["Induce vomiting to remove it","Do NOT induce vomiting — call Poison Control; dilute with small amount of water if fully alert","Give milk only","Apply activated charcoal"],"correct":1,"explanation":"Corrosives cause chemical burns; vomiting re-exposes esophagus and mouth to the chemical; dilution with water or milk if alert; call Poison Control"},{"q":"A responsive patient fell from 20 feet and is ambulatory but has back pain. You should:","opts":["Allow them to walk it off","Treat as spinal injury — keep still, call EMS, apply cervical collar if trained","Apply ice and send home","Assess only if they cannot walk"],"correct":1,"explanation":"Fall from height + back pain = spinal injury until proven otherwise; ambulatory patients CAN have unstable spinal fractures; immobilize and transport"},{"q":"Hands-only CPR is recommended when:","opts":["The patient has a pulse","A lay bystander witnesses sudden cardiac collapse in an adult and is not trained in rescue breathing","The patient is a child","The patient is known to have a DNR"],"correct":1,"explanation":"Hands-only CPR for untrained bystanders witnessing adult sudden collapse; blood remains oxygenated for first few minutes; compression-only CPR greatly increases survival rates"},{"q":"What is the correct compression-to-breath ratio for single-rescuer CPR on an adult?","opts":["15:2","30:2","5:1","50:5"],"correct":1,"explain":"30 compressions to 2 breaths for single-rescuer adult CPR. With an advanced airway (ETT or supraglottic), give 1 breath every 6 seconds (10/min) without pausing compressions. Two-rescuer CPR on a CHILD uses 15:2."},{"q":"Where should chest compressions be performed on an adult?","opts":["Upper third of the sternum","Lower half of the sternum (center of the chest)","Left side of the chest over the heart","Just below the xiphoid process"],"correct":1,"explain":"Compressions go on the lower half of the sternum — center of the chest. Placing too high reduces effectiveness; placing over the xiphoid risks liver laceration. Interlock hands, heel of hand on center of chest."},{"q":"What should you do immediately after delivering an AED shock?","opts":["Check for a pulse for 60 seconds","Resume CPR immediately — start with compressions","Wait for the AED to re-analyze","Give 2 rescue breaths first"],"correct":1,"explain":"After AED shock: immediately resume CPR starting with chest compressions. Don't pause to check pulse. CPR for 2 minutes, then the AED re-analyzes. Time without compressions is time without circulation."},{"q":"For infant CPR, how many fingers compress the chest?","opts":["One finger","Two fingers (on lower half of sternum)","Full hand","Heel of one hand only"],"correct":1,"explain":"For single-rescuer infant CPR: two fingers (middle and ring) on the center of the chest just below the nipple line. Two-rescuer infant CPR uses the two-thumb encircling technique, which generates higher compression pressures."},{"q":"What is the minimum number of EpiPens a person with known severe allergy should carry?","opts":["One — one is enough for any reaction","Two — biphasic reactions can recur after initial treatment","Three — in case of multiple exposures","None if they avoid their allergens completely"],"correct":1,"explain":"Always carry TWO EpiPens. Biphasic anaphylaxis occurs in 3-20% of cases — symptoms return 1-72 hours after initial reaction. The second EpiPen treats the recurrence before reaching the hospital. One is never enough."},{"q":"A patient has a severe allergic reaction and you administer an EpiPen. What must you do next?","opts":["Observe for 10 minutes — if improved, no hospital needed","Call 911 and transport to emergency care regardless of improvement","Give a second EpiPen immediately as one dose is never enough","Have them lie down and take oral antihistamines"],"correct":1,"explain":"After EpiPen: ALWAYS call 911 and transport. Epinephrine's effect lasts only 15-20 minutes. Biphasic reactions can recur. Hospital monitoring for 4-8 hours is standard. Oral antihistamines and steroids are adjuncts — not substitutes for emergency evaluation."},{"q":"The window for giving tPA (clot-busting drug) for ischemic stroke is:","opts":["Within 1 hour of symptom onset","Within 3-4.5 hours of last known well","Within 12 hours","Within 24 hours for all patients"],"correct":1,"explain":"tPA must be given within 3-4.5 hours of last known well (not symptom discovery). Mechanical thrombectomy extends treatment to 24 hours for selected large vessel occlusions. Time is brain: earlier = better outcomes."},{"q":"What is the universal choking sign?","opts":["Clutching the chest","Hands grasping the throat (thumbs pointing toward face)","Pointing to the mouth","Waving arms overhead"],"correct":1,"explain":"The universal choking sign is grasping the throat with both hands. This is universally recognized and alerts bystanders even when the choking victim cannot speak or make sound. Act immediately if you see this sign."},{"q":"A child falls off a trampoline and is unconscious. You suspect spine injury. How do you open the airway?","opts":["Head-tilt chin-lift — most effective airway opening","Jaw thrust — opens airway without neck extension","Don't open airway — wait for EMS","Rotate head to the side for drainage"],"correct":1,"explain":"Use jaw thrust (not head-tilt chin-lift) when spinal injury is suspected. Thrust the jaw forward with fingers behind the jaw angles without moving the neck. This opens the airway while maintaining spinal alignment."},{"q":"What should you do with wet clothing on a hypothermia victim?","opts":["Leave it on — removing causes more heat loss","Remove it — wet clothing conducts heat away 25x faster than air","Cut it off only if temperature is below 50°F","Leave it on outdoors, only remove indoors"],"correct":1,"explain":"Remove wet clothing immediately — wet fabric conducts heat away from the body 25 times faster than air. Replace with dry insulating layers. Handle hypothermic patients gently (rough movement can trigger VF in severe hypothermia)."},{"q":"Which victim should be treated FIRST in a lightning strike mass casualty event?","opts":["The one still breathing — they need the least help","Those who appear dead (not breathing, no pulse) — they are most salvageable","The most severely injured visible wounds","The one who called for help first"],"correct":1,"explain":"Reverse triage in lightning strike: treat the apparently dead FIRST. Lightning-induced cardiac arrest has a high rate of success with CPR because victims are otherwise healthy. Those still breathing will survive without immediate intervention."},{"q":"A diabetic patient is found confused and shaky. You have juice available. What should you do?","opts":["Don't give anything by mouth — may aspirate","Give 4oz (120mL) of juice if the patient is conscious and can swallow safely","Give water only — juice has too much sugar","Give insulin to stabilize blood glucose"],"correct":1,"explain":"For conscious hypoglycemia (glucose <70): give 15g fast-acting carbs immediately — 4oz juice, 4 glucose tablets, or 1 tbsp honey. They must be conscious and able to swallow safely. If unconscious: use glucagon or call 911. Never give insulin for hypoglycemia."},{"q":"What does 'bystander CPR' refer to?","opts":["CPR performed by off-duty paramedics","CPR performed by a non-medical person before EMS arrives","CPR performed while watching others do it","CPR performed in a group setting"],"correct":1,"explain":"Bystander CPR is CPR performed by a non-medical bystander before EMS arrives. It doubles or triples survival from cardiac arrest. Most cardiac arrests happen at home. Hands-only CPR (compressions without breaths) is acceptable and encouraged for untrained bystanders."},{"q":"Carbon monoxide poisoning symptoms include all of the following EXCEPT:","opts":["Headache and dizziness","High fever (>103°F)","Confusion and weakness","Nausea and vomiting"],"correct":1,"explain":"Carbon monoxide poisoning does NOT cause high fever — it is often called the 'great imitator' of flu because it causes headache, dizziness, nausea, and weakness BUT WITHOUT fever. A flu-like illness with no fever, especially affecting multiple people in the same building, should raise CO suspicion."},{"q":"For a patient who ingested a toxic substance, the FIRST action is:","opts":["Induce vomiting to remove the substance","Call Poison Control (1-800-222-1222) for guidance","Give milk to coat the stomach","Start IV fluids immediately"],"correct":1,"explain":"Call Poison Control (1-800-222-1222) FIRST for guidance on the specific substance. Do NOT induce vomiting unless directed — for some substances (corrosives, petroleum products) vomiting causes additional damage. Poison Control provides real-time expert advice 24/7."},{"q":"What is the correct position to place a patient during a seizure?","opts":["Restrain them to prevent injury","On their side (recovery position) to protect the airway","On their back with head tilted back","Sitting upright to improve breathing"],"correct":1,"explain":"Position on their side (recovery position) to prevent aspiration if they vomit during or after the seizure. Do NOT restrain — let the seizure run its course. Remove nearby hazards. Time the seizure. Do NOT put anything in their mouth."},{"q":"What color tag does START triage assign to a patient who cannot walk but is breathing with a radial pulse and follows commands?","opts":["Red — immediate","Yellow — delayed","Green — minor","Black — expectant"],"correct":1,"explain":"START YELLOW (delayed): patient cannot walk but is breathing spontaneously, has a radial pulse, and CAN follow commands. They are stable enough to wait. RED: same but cannot follow commands. GREEN: can walk. BLACK: not breathing after airway opening."},{"q":"An unconscious patient has pinpoint pupils, slow breathing, and a history of heroin use. What should you give?","opts":["Activated charcoal","Naloxone (Narcan) — opioid reversal agent","Epinephrine","Glucose gel"],"correct":1,"explain":"Pinpoint pupils + respiratory depression + opioid history = opioid overdose → give naloxone immediately. Naloxone blocks opioid receptors and reverses the overdose within 2-3 minutes. Give rescue breaths while preparing naloxone if patient is not breathing."},{"q":"When should you stop CPR?","opts":["After 5 minutes if there is no ROSC","When you are too exhausted to continue safely, when an AED or EMS takes over, or when a valid DNR is presented","After 30 minutes in all cases","When the patient turns blue"],"correct":1,"explain":"Stop CPR when: (1) AED or trained rescuer takes over, (2) EMS arrives and takes over, (3) you are physically unable to continue, (4) valid DNR order is presented, (5) obvious signs of death (rigor, lividity). Not based on a time limit alone."},{"q":"What is the main danger of giving too many rescue breaths (over-ventilation) during CPR?","opts":["It causes chest bruising","Increases intrathoracic pressure reducing venous return and cardiac output — also causes gastric inflation and aspiration risk","Causes lung rupture","It delays defibrillation time"],"correct":1,"explain":"Over-ventilation increases intrathoracic pressure, reducing blood returning to the heart and decreasing CPR-generated cardiac output. Also causes gastric inflation, increasing aspiration risk. Give 1 breath over 1 second with visible chest rise — don't over-breathe."},{"q":"A patient you are treating says 'I don't want any treatment — let me die.' They are conscious, alert, and oriented. What should you do?","opts":["Ignore their request and treat them — medical providers must always help","Respect their refusal — competent adults have the right to refuse treatment","Call family to override their decision","Only proceed if their refusal is in writing"],"correct":1,"explain":"Conscious, alert, and oriented competent adults have the legal and ethical right to refuse medical treatment, even life-saving treatment. Implied consent only applies to UNCONSCIOUS patients. Document the refusal. Inform them of the risks. Offer alternative help."},{"q":"What is the role of the 'Incident Command System (ICS)' in mass casualty events?","opts":["It assigns blame after the event","It is a standardized management system providing unified command and coordination of emergency resources","It is only used by the military","It replaces triage in large events"],"correct":1,"explain":"ICS provides a standardized, scalable management structure with clear roles: Incident Commander, Operations, Planning, Logistics, Finance. Used in any emergency — from car accidents to disasters. NIMS (National Incident Management System) requires ICS for federal funding."},{"q":"A patient who was rescued from near-drowning seems fine and wants to go home. What should you advise?","opts":["They can go home if they feel well and their SpO2 is normal","They MUST be evaluated at a hospital — secondary drowning can occur 1-72 hours later","They only need observation if they swallowed water","Only children need hospital evaluation after near-drowning"],"correct":1,"explain":"ALL near-drowning victims require hospital evaluation regardless of how they feel. Secondary drowning causes pulmonary edema hours later from water irritating the lungs. A normal SpO2 does not rule this out. Children especially must be evaluated even after brief submersion."},{"q":"What is the 'recovery position' and when is it used?","opts":["Lying flat on back with legs elevated — used for shock","Side-lying with top knee forward — used for unconscious breathing patients to protect the airway","Sitting upright — used for respiratory distress","On stomach face-down — used for spinal injuries"],"correct":1,"explain":"Recovery position: on side with top knee bent forward to stabilize, bottom arm extended. Used for unconscious patients who are breathing to prevent aspiration of vomit or secretions. Allows airway drainage and maintains open airway without staff holding it."},{"q":"What is the most important action a bystander can take during cardiac arrest while waiting for an AED?","opts":["Call family members","Continuous, high-quality chest compressions","Keep the patient warm","Record the event on a phone"],"correct":1,"explain":"High-quality continuous chest compressions are the most important action while waiting for an AED. Each second without compressions reduces survival. Push hard (2+ inches), fast (100-120/min), allow full recoil, minimize interruptions. This is the bridge to defibrillation."}]);
  qz.medium=qz.medium.concat([{"q":"A patient is in cardiac arrest. CPR has been ongoing for 5 minutes. ETCO2 on capnography is 8 mmHg. What does this suggest?","opts":["Excellent CPR quality","ETT is in the esophagus","Poor cardiac output — poor CPR quality or non-survivable arrest","Normal finding"],"correct":2,"explanation":"ETCO2 <10 mmHg during CPR indicates very poor cardiac output; if ETCO2 is consistently low despite good CPR mechanics, prognosis is poor"},{"q":"What is the MOST important reason to minimize interruptions in CPR compressions?","opts":["To prevent rib fractures","Coronary perfusion pressure drops rapidly and takes 30-60 sec to restore when compressions stop","To reduce rescuer fatigue","To maintain a steady rhythm"],"correct":1,"explanation":"Coronary perfusion pressure (CPP) generated by CPR collapses rapidly with any pause; chest compressions must resume within 10 seconds"},{"q":"For a patient in refractory ventricular fibrillation after 3 shocks, what medication should be given?","opts":["Lidocaine 100 mg IV only","Amiodarone 300 mg IV push","Atropine 1 mg IV","Calcium gluconate"],"correct":1,"explanation":"After 3 shocks in refractory VF/pulseless VT: amiodarone 300 mg IV; second dose 150 mg; lidocaine is acceptable alternative"},{"q":"Which finding BEST indicates a tension pneumothorax over a simple pneumothorax?","opts":["Absent breath sounds on one side","Absent breath sounds + tracheal deviation away from affected side + hypotension + JVD","Subcutaneous emphysema","Decreased chest rise on one side"],"correct":1,"explanation":"Tension PTX causes obstructive shock: tracheal deviation (away from lesion), JVD, hypotension, absent breath sounds; simple PTX has no hemodynamic compromise"},{"q":"Beck's triad of cardiac tamponade consists of:","opts":["Fever, JVD, friction rub","Hypotension, muffled heart sounds, JVD","Tachycardia, hypotension, wide pulse pressure","Hypertension, bradycardia, irregular respirations (Cushing's triad)"],"correct":1,"explanation":"Beck's triad: Hypotension (pump failure), Muffled heart sounds (fluid around heart), JVD (venous backup); classic but only present in ~30% of cases"},{"q":"A 35-year-old trauma patient arrives with BP 80/50, HR 145, cool clammy extremities, and diminished urine output. The MOST likely diagnosis is:","opts":["Cardiogenic shock","Obstructive shock","Hypovolemic hemorrhagic shock","Distributive shock"],"correct":2,"explanation":"Young trauma patient with tachycardia, hypotension, cool extremities = hypovolemic hemorrhagic shock until proven otherwise; find the bleeding source"},{"q":"In damage control resuscitation for hemorrhagic shock, why is crystalloid fluid restricted?","opts":["It is too expensive","It worsens coagulopathy by diluting clotting factors, causes hypothermia, and increases inflammation","It raises BP too quickly","Patients cannot absorb it"],"correct":1,"explanation":"Crystalloid (NS/LR) dilutes clotting factors → coagulopathy; completes the lethal triad (hypothermia, acidosis, coagulopathy); use balanced blood products instead"},{"q":"A child is in cardiac arrest. The MOST likely cause compared to an adult is:","opts":["Ventricular fibrillation from arrhythmia","Asphyxia from respiratory failure or airway obstruction","Myocardial infarction","Pulmonary embolism"],"correct":1,"explanation":"Pediatric cardiac arrest is almost always asphyxial (not primary cardiac); oxygenation and ventilation are critical; 2 rescue breaths before compressions in children (if alone)"},{"q":"The stroke chain: door-to-needle time for tPA should be under:","opts":["30 minutes","60 minutes","90 minutes","120 minutes"],"correct":1,"explanation":"Door-to-needle <60 minutes; door-to-CT <25 min; tPA can be given up to 4.5 hours after symptom onset in eligible patients"},{"q":"A patient presents with sudden-onset unilateral facial droop, arm weakness, and slurred speech. CT shows no hemorrhage. BP is 175/100. What is the priority treatment?","opts":["Lower BP aggressively to 140/90","Aspirin 325 mg and observation","tPA if within time window and no contraindications","IV heparin bolus"],"correct":2,"explanation":"Ischemic stroke + no hemorrhage + within 4.5h window + no contraindications = tPA; do NOT lower BP before tPA (needs adequate perfusion pressure)"},{"q":"What is the PRIMARY reason epinephrine is used in cardiac arrest?","opts":["It directly defibrillates the heart","It increases coronary and cerebral perfusion pressure by peripheral vasoconstriction","It is an antiarrhythmic","It prevents blood clots"],"correct":1,"explanation":"Epi alpha-1 effect vasoconstricts peripherally, raising diastolic BP → increases coronary perfusion pressure; does not improve neurological outcomes but increases ROSC"},{"q":"A patient develops hypotension after 2 liters of IV saline for apparent hemorrhagic shock. Neck veins are distended. Breath sounds are absent on the left. What is MOST likely?","opts":["Cardiac tamponade","Tension pneumothorax","Pulmonary embolism","Cardiogenic shock"],"correct":1,"explanation":"Trauma + hypotension + absent breath sounds + JVD = tension pneumothorax until proven; immediate needle decompression 2nd ICS MCL"},{"q":"The Hs and Ts represent reversible causes of cardiac arrest. Which H is treated with sodium bicarbonate?","opts":["Hypoxia","Hypovolemia","Hydrogen ion (acidosis)","Hyperkalemia"],"correct":2,"explanation":"H+ (metabolic acidosis) treated with sodium bicarbonate; Hyperkalemia also treated with NaHCO3 as one of several agents; Hypoxia → oxygen; Hypovolemia → fluids"},{"q":"A patient in status epilepticus has received lorazepam 4 mg without effect. What is the NEXT medication?","opts":["Repeat benzodiazepine only","Fosphenytoin or levetiracetam IV","Haloperidol","Dextrose 50%"],"correct":1,"explanation":"Benzodiazepine-refractory status: second-line agents — fosphenytoin, levetiracetam, or valproic acid IV; all equal per ESETT trial"},{"q":"After successful ROSC from cardiac arrest, a patient's temperature is 37.8°C. Targeted temperature management should:","opts":["Target 33°C strictly","Maintain temperature at 36°C or prevent fever >37.8°C for 72h","Not be used — normothermia is fine","Cool to 28°C for maximum neuroprotection"],"correct":1,"explanation":"TTM-2 trial: 37.5°C target (prevent fever) vs 33°C — similar outcomes; key is preventing hyperthermia; 36°C acceptable target"},{"q":"A patient has DKA. Blood glucose is 480, pH 7.15, K+ is 3.1. What should be done FIRST?","opts":["Start insulin infusion immediately","Give IV fluids then insulin, and replace potassium before starting insulin","Administer sodium bicarbonate","Start insulin and ignore potassium"],"correct":1,"explanation":"Insulin drives K+ into cells — never start insulin if K+<3.5; first: IVF + K+ replacement; then insulin; monitor K+ closely every 1-2h"},{"q":"What is the MOST common reversible cause of pulseless electrical activity (PEA)?","opts":["Hypothermia","Hypovolemia (hemorrhage or dehydration)","Hyperkalemia","Cardiac tamponade"],"correct":1,"explanation":"Hypovolemia is the most common reversible cause of PEA; aggressive fluid resuscitation may restore cardiac output; always consider the Hs and Ts"},{"q":"A pregnant patient at 32 weeks is in cardiac arrest. The best position for CPR is:","opts":["Standard supine","Left lateral tilt 15-30° or manual uterine displacement to the left","Prone","Right lateral tilt"],"correct":1,"explanation":"Pregnant uterus compresses IVC in supine position (aortocaval compression) reducing venous return; tilt left or displace uterus manually; if no ROSC in 4 min: perimortem C-section"},{"q":"What is the Glasgow Coma Scale score for: Eyes open to voice (3) + Confused speech (4) + Withdraws to pain (4)?","opts":["GCS 10","GCS 11","GCS 12","GCS 13"],"correct":1,"explanation":"Eyes (3) + Verbal (4) + Motor (4) = GCS 11; <8 = severe TBI, intubation generally recommended; <13 = moderate TBI"},{"q":"A patient with anaphylaxis receives epinephrine IM but hypotension persists after 2 doses. Next step?","opts":["Give oral antihistamines","IV epinephrine infusion and IV fluids","High-dose steroids only","Discharge with EpiPen prescription"],"correct":1,"explanation":"Refractory anaphylaxis after 2+ IM epi doses: IV epinephrine infusion (1-10 mcg/min); aggressive IVF for distributive shock; vasopressin alternative"},{"q":"A patient has septic shock. Despite 2L of IV fluids, BP is 75/45. What is the NEXT intervention?","opts":["Give another 2L of fluids","Start vasopressors (norepinephrine first-line)","Give broad-spectrum antibiotics","Perform intubation"],"correct":1,"explanation":"Fluid-refractory septic shock: norepinephrine is first-line vasopressor; vasopressin added second; antibiotics should already be given within 1 hour"},{"q":"Perimortem cesarean delivery should ideally be completed within how many minutes of maternal cardiac arrest?","opts":["2 minutes","5 minutes","10 minutes","15 minutes"],"correct":1,"explanation":"Delivery within 5 minutes gives best outcomes for both mother (ROSC improves significantly after uterine decompression) and fetus"},{"q":"A marathon runner collapses with core temperature 41.5°C and altered mental status. The MOST effective cooling method is:","opts":["Fanning with cool mist","Ice packs to axillae and groin","Ice water immersion","Cool IV fluids alone"],"correct":2,"explanation":"Ice water immersion is fastest and most effective cooling for exertional heat stroke; target <39°C; do not delay cooling waiting for transport"},{"q":"What is the MOST important step after applying a tourniquet to stop arterial bleeding?","opts":["Remove the tourniquet every 2 hours","Document the time of application","Apply a pressure dressing on top","Loosen slightly to allow partial blood flow"],"correct":1,"explanation":"Time of application is critical: determines safe tourniquet time (generally 2 hours max); write time on tourniquet AND on patient's forehead with marker"},{"q":"A patient has ETCO2 suddenly rise from 15 mmHg to 42 mmHg during CPR without any intervention change. What does this indicate?","opts":["The ETT has been dislodged","Return of spontaneous circulation (ROSC)","The patient is not salvageable","Hyperventilation is occurring"],"correct":1,"explanation":"Sudden rise in ETCO2 during CPR is the earliest sign of ROSC — increased cardiac output delivers more CO2 to lungs; check pulse immediately"},{"q":"A patient with known COPD is brought in confused with SpO2 87%. You should give oxygen targeting:","opts":["100% FiO2 via non-rebreather mask","SpO2 88–92% — avoid hyperoxia which suppresses hypoxic drive","SpO2 99-100%","No supplemental oxygen"],"correct":1,"explanation":"COPD patients may rely on hypoxic drive; target SpO2 88-92%; hyperoxia worsens hypercapnia and outcomes; titrate oxygen carefully"},{"q":"Which of these is the HIGHEST priority in multi-system trauma (using MARCH)?","opts":["Airway management","Massive hemorrhage control","Circulation assessment","Hypothermia prevention"],"correct":1,"explanation":"MARCH = Massive hemorrhage, Airway, Respiration, Circulation, Hypothermia; hemorrhage control is first in tactical/prehospital care — uncontrolled bleeding kills fastest"},{"q":"A patient develops sudden-onset tearing chest pain radiating to the back, with BP difference of 30 mmHg between arms. The MOST likely diagnosis is:","opts":["Myocardial infarction","Pulmonary embolism","Aortic dissection","Esophageal rupture"],"correct":2,"explanation":"Tearing/ripping pain + BP difference between arms = aortic dissection until proven otherwise; Type A needs emergent surgery; Type B: blood pressure control"},{"q":"Waveform capnography is used to confirm endotracheal tube placement because:","opts":["It measures oxygen saturation","Continuous CO2 waveform over 6 cycles confirms tracheal (not esophageal) placement","It is more accurate than CXR only","It measures tube depth"],"correct":1,"explanation":"Colorimetric CO2 detectors are backup; waveform capnography is gold standard for ETT confirmation and ongoing monitoring of CPR quality and ROSC"},{"q":"In the START triage system, what color is assigned to a patient who is breathing after you open the airway?","opts":["Green (minor)","Yellow (delayed)","Red (immediate)","Black (expectant/deceased)"],"correct":2,"explanation":"If patient was not breathing, you reposition airway: if breathing resumes → Red (immediate); if still not breathing → Black (expectant) in mass casualty"},{"q":"A patient receives RSI with succinylcholine. 2 minutes later, the jaw is rigid and temperature begins to spike rapidly. What is happening?","opts":["Normal succinylcholine fasciculations","Malignant hyperthermia — give dantrolene immediately","Neuroleptic malignant syndrome","Allergic reaction to succinylcholine"],"correct":1,"explanation":"Masseter rigidity + hyperthermia after succinylcholine = malignant hyperthermia; STOP triggering agent; dantrolene 2.5 mg/kg IV; notify MHAUS 1-800-644-9737"},{"q":"A patient was found down, is now in cardiac arrest, and you note marked lividity (pooling of blood). What should you do?","opts":["Begin CPR immediately regardless","Assess for other signs of death (rigor mortis, dependent lividity, injuries incompatible with life); if obvious death signs — do not resuscitate","Begin CPR for 2 minutes then reassess","Call medical direction only"],"correct":1,"explanation":"Obvious signs of biological death (lividity, rigor, decapitation, decomposition) are contraindications to CPR; intervening without medical direction is inappropriate and futile"},{"q":"A patient with sickle cell disease presents with severe bone pain, fever, and chest pain with hypoxia. The MOST dangerous acute complication is:","opts":["Vaso-occlusive crisis only","Acute chest syndrome — new infiltrate + fever + hypoxia; can rapidly progress to respiratory failure","Splenic sequestration","Stroke only"],"correct":1,"explanation":"Acute chest syndrome is the leading cause of death in sickle cell disease; treatment: oxygen, exchange transfusion, bronchodilators, antibiotics; escalate rapidly"},{"q":"A patient presents with altered mental status, hyperthermia, muscle rigidity, and autonomic instability after starting a new antipsychotic. How do you distinguish NMS from serotonin syndrome?","opts":["They are clinically identical","NMS: slow onset (days), lead-pipe rigidity, normal reflexes; Serotonin syndrome: rapid onset (hours), clonus/hyperreflexia, diarrhea","Serotonin syndrome has bradycardia","NMS only occurs with typical antipsychotics"],"correct":1,"explanation":"NMS: dopamine blockade, gradual onset, bradykinesia, rigidity, hyporeflexia; Serotonin syndrome: serotonergic excess, rapid onset, hyperreflexia, clonus, mydriasis, diarrhea — different treatments"},{"q":"A firefighter is rescued from a house fire and has cherry-red skin and altered mental status. SpO2 reads 99%. What is wrong with the SpO2 reading?","opts":["The reading is accurate","CO-hemoglobin is mistaken for oxyhemoglobin by standard pulse oximetry — the patient is severely hypoxic despite normal SpO2","The pulse ox probe is not positioned correctly","Cherry-red skin means good oxygenation"],"correct":1,"explanation":"Standard pulse oximetry cannot distinguish carboxyhemoglobin from oxyhemoglobin; CO-oximetry (co-oximeter) is needed for accurate SaO2 in CO poisoning; treat with 100% O2 immediately"},{"q":"A patient with severe hypothermia (29°C) and no pulse. After one defibrillation attempt, VF persists. You should:","opts":["Defibrillate again every 2 minutes as per standard ACLS","Attempt one more defibrillation then focus on CPR and active rewarming — heart may not respond until warmer","Stop resuscitation — hypothermic VF is not survivable","Give epinephrine every cycle without limit"],"correct":1,"explanation":"Hypothermic VF: defibrillate once; if unsuccessful, withhold further shocks until temp >30°C; continue CPR + aggressive rewarming; ECMO if available; excellent neurological recovery possible"},{"q":"Which combination of drugs is most likely to cause serotonin syndrome?","opts":["Metoprolol + lisinopril","SSRI + tramadol (or MAOI + SSRI)","Amiodarone + digoxin","Warfarin + aspirin"],"correct":1,"explanation":"Serotonin syndrome from combining serotonergic drugs; classic: MAOI + SSRI (most dangerous); also: SSRI + tramadol, SSRI + linezolid, SSRI + triptans; treat with cyproheptadine + benzos"},{"q":"A 65-year-old patient receives thrombolytics for suspected PE and immediately develops severe headache, vomiting, and right-sided weakness. What has likely occurred?","opts":["Allergic reaction to tPA","Intracranial hemorrhage — most feared complication of thrombolytic therapy","Reperfusion syndrome","Anaphylaxis"],"correct":1,"explanation":"Intracranial hemorrhage: most feared tPA complication; risk 0.5-1% in PE, 3-6% in stroke if given outside criteria; immediate CT head; reverse anticoagulation (FFP, cryoprecipitate); neurosurgery consult"},{"q":"A trauma patient has tachycardia 130, BP 95/70, is pale and anxious. Estimated blood loss is which class?","opts":["Class I (<15%)","Class II (15-30%, 750-1500 mL)","Class III (30-40%)","Class IV (>40%)"],"correct":1,"explanation":"Hemorrhagic shock Class II: 15-30% blood loss; tachycardia, narrow pulse pressure, anxiety; BP often maintained; resuscitate with blood products; early surgical control if not responding"},{"q":"A patient was given 1g ceftriaxone IM in the ED and 10 minutes later develops urticaria, angioedema, and hypotension. The reaction is:","opts":["A simple allergic rash","Anaphylaxis — immediate epinephrine IM required","Serum sickness","Antibiotic side effect to observe only"],"correct":1,"explanation":"Drug-induced anaphylaxis behaves identically to other anaphylaxis; immediate epinephrine IM in anterolateral thigh; IV access and fluids; position supine; second dose in 5-15 min if no response"},{"q":"A 16-year-old football player is hit in the head and seems 'dazed' but continues to play. He then collapses 20 minutes later and is unresponsive. This describes:","opts":["Simple concussion","Second Impact Syndrome — second blow before first concussion resolved; can cause fatal cerebral edema","Heat stroke","Exertional hyponatremia"],"correct":1,"explanation":"Second Impact Syndrome: rare but potentially fatal; diffuse cerebral swelling after second concussion before first resolves; young athletes most vulnerable; any head injury = out of play same day"},{"q":"A drowning victim is pulled from pool and is pulseless. After 5 rescue breaths, there is no pulse. What is the compression-to-breath ratio you should use?","opts":["30:2 regardless of rescuer count","30:2 if alone; 15:2 with two rescuers for pediatric victims","No rescue breaths — compressions only","2:30"],"correct":1,"explanation":"Drowning is asphyxial arrest — oxygenation is critical; give 5 rescue breaths first; then 30:2 if alone (adult victim), 15:2 two rescuers for children; do NOT use hands-only CPR for drowning"},{"q":"A nursing home patient has a POLST form stating 'DNR/DNI.' She is found unresponsive. What should be done?","opts":["Start CPR and call family","Verify the form is valid and complete; honor the order — provide comfort care only","Disregard — this is outside a hospital","Call a physician before doing anything"],"correct":1,"explanation":"POLST (Physician Orders for Life-Sustaining Treatment) is a legally binding physician order valid outside the hospital; verify it's properly signed; honor the patient's expressed wishes; provide comfort care"},{"q":"A patient is in pulseless ventricular tachycardia. The FIRST treatment is:","opts":["Amiodarone 300 mg IV","Unsynchronized defibrillation (same as VF)","Synchronized cardioversion","Lidocaine 100 mg IV push"],"correct":1,"explanation":"Pulseless VT = treat same as VF: immediate unsynchronized defibrillation + CPR; synchronized cardioversion is for VT WITH a pulse but unstable; amiodarone is adjunct, not first-line"},{"q":"A patient has a massive hemothorax after stabbing. After chest tube placement, 1500 mL drains immediately. What does this indicate?","opts":["Normal finding, continue monitoring","Massive hemothorax — likely major vessel injury; emergent thoracotomy indicated if >1500 mL initial drainage or >200 mL/hr ongoing","Chest tube malposition","Pleural effusion from infection"],"correct":1,"explanation":"Massive hemothorax: initial drainage >1500 mL OR continued bleeding >200 mL/hr is an indication for emergent thoracotomy to control hemorrhage"},{"q":"A patient with seizures has sodium of 110 mEq/L. What is the IMMEDIATE treatment?","opts":["Free water restriction only","3% hypertonic saline 100-150 mL over 10-20 min to raise sodium 4-6 mEq/L and stop seizures","Normal saline 1L bolus","Dialysis immediately"],"correct":1,"explanation":"Symptomatic severe hyponatremia (seizure): 3% NaCl bolus raises Na rapidly enough to stop neurological symptoms; target 4-6 mEq/L rise; maximum 10 mEq/L per 24h to prevent osmotic demyelination"},{"q":"Which patient should NOT receive high-flow oxygen via non-rebreather mask?","opts":["A patient with CO poisoning","A patient with COPD and SpO2 94% who is not in acute distress","A trauma patient with respiratory distress","A patient with anaphylaxis and respiratory distress"],"correct":1,"explanation":"COPD with SpO2 94%: NOT in distress; give controlled O2 targeting SpO2 88-92%; high-flow O2 causes hypercapnia by suppressing hypoxic drive in CO2-retaining COPD; titrate carefully"},{"q":"A construction worker is trapped under a beam for 2 hours. After rescue, you are most concerned about which lab value?","opts":["Blood glucose","Serum potassium — crush injury causes massive K+ release from damaged muscle","Sodium","Calcium"],"correct":1,"explanation":"Crush syndrome: compressed muscle dies → releases K+, myoglobin, phosphate, uric acid; reperfusion after rescue can cause fatal hyperkalemia and cardiac arrest; aggressive IVF to protect kidneys"},{"q":"For a patient with suspected cervical spine injury who requires airway management, the PREFERRED technique is:","opts":["Blind nasotracheal intubation","Video laryngoscopy or direct laryngoscopy with manual in-line cervical stabilization (MILS)","Surgical cricothyrotomy first-line","Head-tilt chin-lift and oral airway only"],"correct":1,"explanation":"MILS maintains cervical alignment during intubation; video laryngoscopy allows intubation with minimal neck movement; surgical airway reserved for cannot-intubate situations; MILS is standard for potential c-spine injury"},{"q":"A patient develops bronchospasm, urticaria, and hypotension after the first sip of IV contrast. After epinephrine, what is CRITICAL to monitor for?","opts":["Liver function tests","Biphasic anaphylaxis — second reaction can occur 1-72h later without re-exposure; observe minimum 4-8h","Cardiac enzymes","Renal function only"],"correct":1,"explanation":"Contrast-induced anaphylaxis treated same as any anaphylaxis; biphasic reaction occurs in 1-20% of anaphylaxis cases; all anaphylaxis patients require 4-8h observation; discharge with epinephrine auto-injector prescription"},{"q":"After ROSC from cardiac arrest, target SpO2 should be:","opts":["100% — more oxygen is always better","94-98% — avoid both hypoxia AND hyperoxia","88-92%","SpO2 is not important post-arrest"],"correct":1,"explanation":"Post-ROSC: avoid hyperoxia (SpO2 >98%) — excess O2 causes free radical injury to reperfused brain; avoid hypoxia (SpO2 <94%); titrate FiO2 to maintain SpO2 94-98%; also target PaCO2 35-45 mmHg"},{"q":"A patient in septic shock requires vasopressors. Which is the FIRST-LINE vasopressor per Surviving Sepsis Campaign?","opts":["Epinephrine","Dopamine","Norepinephrine","Vasopressin"],"correct":2,"explanation":"Norepinephrine is first-line vasopressor for septic shock; vasopressin added as second agent to reduce NE dose; epinephrine if inadequate response to NE + vasopressin; dopamine associated with more arrhythmias"},{"q":"A patient presents with pinpoint pupils, respiratory rate of 4, and is unresponsive. You give naloxone 0.4 mg IV. The patient immediately becomes combative and tries to pull out the IV. What happened?","opts":["The naloxone wasn't effective","Naloxone reversed the opioid and precipitated acute opioid withdrawal — shorten naloxone dose and titrate carefully","The patient is having a seizure","Serotonin syndrome was triggered"],"correct":1,"explanation":"Naloxone reverses opioid-induced respiratory depression but can precipitate acute withdrawal — agitation, tachycardia, vomiting, hypertension; titrate naloxone: 0.04 mg IV increments to restore breathing without precipitating withdrawal"},{"q":"A patient's glucose is 42 mg/dL and they are unconscious. No IV access. What should you give?","opts":["Oral glucose tablets","Glucagon 1 mg IM or intranasal","Insulin","Nothing — wait for IV access"],"correct":1,"explanation":"Unconscious hypoglycemia without IV access: glucagon IM (thigh, arm, or abdomen) or intranasal (Baqsimi); stimulates glycogen release from liver; IV dextrose (D50) is preferred when IV access available"},{"q":"A patient in cardiac arrest has been in VF for 2 minutes. CPR is ongoing. After the 3rd shock, VF persists. What drug is given next and at what dose?","opts":["Atropine 1mg IV — anticholinergic","Amiodarone 300mg IV (lidocaine 1-1.5mg/kg is alternative)","Magnesium 2g IV — first line for VF","Epinephrine 3mg IV — triple dose for refractory VF"],"correct":1,"explain":"Amiodarone 300mg IV is first-line antiarrhythmic for shock-refractory VF/VT. A second dose of 150mg may be given for recurrent VF. Lidocaine 1-1.5mg/kg is an acceptable alternative. Epinephrine 1mg IV/IO is given every 3-5 minutes regardless (not amiodarone's role)."},{"q":"Which finding MOST suggests tension pneumothorax rather than simple pneumothorax?","opts":["Absent breath sounds on one side","Pleuritic chest pain","Hypotension and tachycardia with absent breath sounds — hemodynamic instability","SpO2 of 92%"],"correct":2,"explain":"Tension pneumothorax = hemodynamic instability (hypotension + tachycardia → cardiovascular collapse). Simple pneumothorax causes respiratory symptoms without hemodynamic compromise. Absent breath sounds occur in both. Treat immediately without imaging if hemodynamically unstable."},{"q":"A diabetic patient found unconscious has glucose of 28 mg/dL. They cannot swallow safely. What treatment is given in the field?","opts":["Oral juice forced through the mouth","Glucagon 1mg IM or 3mg intranasal (Baqsimi) — for unconscious hypoglycemia","Insulin to 'normalize' the glucose level","High-flow oxygen only"],"correct":1,"explain":"For unconscious severe hypoglycemia: glucagon 1mg IM (or 3mg nasal Baqsimi) stimulates the liver to release stored glucose. Takes 10-15 minutes. IV dextrose (D50 or D10) is ideal if IV access available — faster effect. NEVER oral glucose for unconscious patient (aspiration)."},{"q":"When should epinephrine be given in non-shockable cardiac arrest rhythms (PEA/asystole)?","opts":["Only after 15 minutes","As soon as IV/IO access is obtained — every 3-5 minutes","Only if the patient has known cardiac disease","Epinephrine is not used in PEA/asystole"],"correct":1,"explain":"Epinephrine 1mg IV/IO every 3-5 minutes is given as soon as access is established in non-shockable rhythms (PEA, asystole). In shockable rhythms (VF/VT): after 3rd shock. Epinephrine causes vasoconstriction, improves coronary and cerebral perfusion pressure during CPR."},{"q":"Which GCS score indicates severe traumatic brain injury requiring airway protection?","opts":["GCS 15 — fully normal","GCS 13 — mild TBI","GCS 10 — moderate TBI","GCS ≤8 — severe TBI, unable to protect airway"],"correct":3,"explain":"GCS ≤8 = severe TBI and indicates inability to protect the airway — intubation is typically required. GCS 9-12 = moderate. GCS 13-15 = mild. The motor component is most predictive of outcome. GCS ≤8: 'If the GCS is 8, intubate.'"},{"q":"A trauma patient arrives unconscious with BP 60/40, HR 160. FAST exam shows fluid in the pericardium. What is the diagnosis and immediate treatment?","opts":["Tension pneumothorax — needle decompression","Cardiac tamponade — pericardiocentesis or emergency thoracotomy","Hypovolemic shock — massive transfusion only","Septic shock — IV antibiotics"],"correct":1,"explain":"Beck's Triad (hypotension + JVD + muffled heart sounds) + pericardial fluid on FAST = cardiac tamponade. Immediate treatment: pericardiocentesis (needle drainage) or emergency thoracotomy in cardiac arrest. Blood in pericardial sac prevents cardiac filling — even small amounts cause hemodynamic collapse."},{"q":"A crush victim is trapped under rubble for 3 hours. Before rescuers free him, what is the MOST critical pre-release medical intervention?","opts":["Pain management with IM morphine","IV fluid resuscitation to prevent crush syndrome before compression is released","Tourniquet to all four extremities","High-flow oxygen only"],"correct":1,"explain":"IV fluids BEFORE release reduce crush syndrome. When compression releases, myoglobin, potassium, and lactic acid flood the circulation. Pre-release fluids dilute these and protect kidneys. Hyperkalemia on release can cause immediate cardiac arrest — monitor ECG."},{"q":"What is 'damage control resuscitation' in trauma?","opts":["Aggressive crystalloid resuscitation to normalize blood pressure","Blood products in 1:1:1 ratio, permissive hypotension, TXA within 3h, limiting crystalloids","Using only saline and glucose until the patient reaches the OR","Giving vasopressors before blood products to maintain pressure"],"correct":1,"explain":"Damage control resuscitation (DCR): (1) blood products 1:1:1 (PRBC:FFP:platelets) replace what was lost; (2) permissive hypotension SBP 80-90 for penetrating trauma; (3) TXA within 3 hours; (4) minimize crystalloids (dilute clotting factors, worsen hypothermia). Prevents the lethal triad."},{"q":"A patient develops sudden severe 'thunderclap' headache — worst of their life. CT head is negative. What is the critical next step?","opts":["Discharge with analgesics — CT rules out subarachnoid hemorrhage","Lumbar puncture to detect xanthochromia — CT misses 5-10% of subarachnoid hemorrhage","MRI brain — more sensitive than CT","Observe 6 hours and repeat CT"],"correct":1,"explain":"'Worst headache of life' (thunderclap headache) = subarachnoid hemorrhage (SAH) until proven otherwise. CT is negative in 5-10% of SAH (especially >6h after onset). Lumbar puncture showing xanthochromia (yellow CSF from blood breakdown) confirms SAH. SAH requires urgent neurosurgical evaluation."},{"q":"Regarding post-ROSC oxygen management: a patient has SpO2 100% on 15L O2. What should you do?","opts":["Maintain at 100% — higher oxygen is better post-arrest","Titrate O2 DOWN to target SpO2 92-98% — hyperoxia causes additional neurological injury","Switch to room air immediately","Increase to 100% O2 for 24 hours to maximize oxygen delivery"],"correct":1,"explain":"After ROSC, hyperoxia (SpO2 100% on high-flow O2) generates reactive oxygen species that damage already-ischemic neurons. Target SpO2 92-98%. Titrate oxygen down. Also target: ETCO2 35-45 mmHg (avoid hyperventilation), MAP >65 mmHg. Both hypoxia AND hyperoxia worsen neurological outcomes."},{"q":"What is the 'lethal triad' in trauma and why is it dangerous?","opts":["Hypoxia + tachycardia + anemia — all reduce oxygen delivery","Hypothermia + acidosis + coagulopathy — each worsens the other two, creating a fatal spiral","Hypotension + bradycardia + altered mental status","Tachycardia + hyperthermia + alkalosis"],"correct":1,"explain":"The lethal triad: Hypothermia (impairs clotting enzyme function below 35°C), Acidosis (from hypoperfusion, impairs clotting), Coagulopathy (from dilution and consumption of factors). Each worsens the others. Damage control resuscitation specifically prevents and reverses all three simultaneously."},{"q":"When is needle decompression for suspected tension pneumothorax indicated WITHOUT a chest X-ray?","opts":["Never — always confirm with imaging first","Hemodynamically unstable patient with absent unilateral breath sounds and suspected tension PTX — immediate clinical treatment","Only in pediatric patients","Only during CPR"],"correct":1,"explain":"Tension PTX is a clinical diagnosis in the hemodynamically unstable patient — no time for imaging. Absent breath sounds + tracheal deviation (late sign) + shock in trauma = immediate needle decompression. Inserting a needle into a simple pneumothorax is far less harmful than delaying treatment for true tension PTX."},{"q":"A patient in status epilepticus received lorazepam and the seizure continues. What is the next step?","opts":["Repeat lorazepam — higher dose","Fosphenytoin or valproic acid IV — second-line antiepileptic","Wait 20 minutes for lorazepam to take full effect","Start propofol immediately"],"correct":1,"explain":"Status epilepticus treatment protocol: (1) Benzodiazepine (lorazepam) → if no response in 5 min → (2) Fosphenytoin, valproic acid, or levetiracetam IV → if no response in 5 min → (3) General anesthesia (propofol, phenobarbital, ketamine). Don't skip steps or wait too long."},{"q":"An elderly patient falls from standing and has battle's sign and raccoon eyes. What do these signs indicate?","opts":["Severe facial lacerations","Basilar skull fracture — spinal immobilization is critical","Ocular hemorrhage from direct eye injury","Normal finding in elderly after falls"],"correct":1,"explain":"Battle's sign (bruising behind the ear over the mastoid) and raccoon eyes (periorbital ecchymosis) are classic signs of basilar skull fracture from blood tracking through fascial planes. Spinal immobilization is critical. Other signs: CSF leaking from ears or nose, hemotympanum (blood behind eardrum)."},{"q":"A patient is taking lisinopril (an ACE inhibitor) and develops recurrent episodes of severe lip and tongue swelling without hives. What is the diagnosis?","opts":["Anaphylaxis — give epinephrine","ACE inhibitor-induced angioedema — stop the ACE inhibitor","Hereditary angioedema — treat with C1-inhibitor concentrate","Contact dermatitis — treat with antihistamines"],"correct":1,"explain":"ACE inhibitor-induced angioedema: bradykinin accumulation causes recurrent angioedema (no hives, no IgE mechanism). Stop the ACE inhibitor — episodes stop within weeks. This is NOT anaphylaxis — epinephrine has limited benefit. Switch to ARB (lower but not zero risk). Airway management if severe swelling."},{"q":"A 3-year-old is found unresponsive and not breathing after choking on a toy. You've performed back blows and chest thrusts without success. What do you do now?","opts":["Continue back blows and chest thrusts indefinitely","Begin CPR — open airway before each breath and remove any visible foreign object","Call poison control for guidance","Attempt abdominal thrusts — they work better in children"],"correct":1,"explain":"When a choking victim loses consciousness: start CPR. Before each rescue breath attempt: open the airway and look in the mouth — remove any visible object with a finger sweep. Chest compressions during CPR may help dislodge the object. Never do blind finger sweeps."},{"q":"A patient has suspected spinal cord injury at C4 with paradoxical abdominal breathing. What does this pattern indicate?","opts":["Normal breathing in an anxious patient","Diaphragmatic breathing — C3-5 innervates the diaphragm — intercostal muscles are paralyzed","Tension pneumothorax — treat immediately","Upper airway obstruction"],"correct":1,"explain":"'C3, 4, 5 keep the diaphragm alive.' C4 injury: intercostal muscles paralyzed, diaphragm preserved → abdomen rises with breathing but chest wall doesn't expand (paradoxical). C3 or above: diaphragm also paralyzed → complete ventilatory failure → immediate intubation required."},{"q":"During CPR, you note ETCO2 suddenly rises from 15 to 45 mmHg without any change in CPR technique. What does this mean?","opts":["CPR compressions have become too deep","Return of spontaneous circulation — check for pulse immediately","The endotracheal tube has been displaced","Patient needs more epinephrine"],"correct":1,"explain":"Sudden ETCO2 rise to >40 mmHg during ongoing CPR = ROSC. The heart has resumed beating and CO2 from tissues is now being exhaled. Stop CPR and immediately check for a carotid pulse. ETCO2 is the most reliable real-time ROSC indicator available during resuscitation."},{"q":"What is the mechanism of action of naloxone and why might repeated doses be needed for fentanyl overdose?","opts":["Naloxone metabolizes opioids in the bloodstream — more fentanyl requires more naloxone to metabolize","Naloxone competitively blocks opioid receptors but has a shorter half-life than many opioids — fentanyl persists after naloxone wears off","Naloxone increases respiratory rate through direct CNS stimulation","Naloxone only works for heroin, not fentanyl"],"correct":1,"explain":"Naloxone competitively displaces opioids from mu-receptors. Naloxone half-life: 30-90 minutes. Fentanyl is highly potent and lipophilic — it redistributes from tissues after naloxone wears off, causing re-sedation. Repeat doses or infusion needed. Never discharge after naloxone alone — observe for re-narcotization."},{"q":"A young athlete collapses during a soccer game. AED shows no shockable rhythm. CPR is ongoing. What is the most likely reversible cause to look for?","opts":["Tension pneumothorax from sports injury","Hypertrophic cardiomyopathy causing VF — already defibrillated without response","Hypovolemia from dehydration — give IV fluids aggressively","All young athletic collapses are commotio cordis"],"correct":1,"explain":"Young athletes with cardiac arrest most likely have: (1) hypertrophic cardiomyopathy (HCM) — most common cause of sudden cardiac death in young athletes in the US, (2) commotio cordis (impact-induced VF), (3) anomalous coronary arteries, (4) long QT syndrome. If AED shows no shockable rhythm: continue CPR + look for reversible causes."},{"q":"A patient has a tourniquet applied to their left arm at 10:15 AM. It is now 10:45 AM. Should you remove it to restore circulation?","opts":["Yes — remove after 30 minutes to prevent permanent nerve damage","No — do NOT remove once applied for hemorrhage control. Note the time and transport to definitive care","Remove partially — loosen but don't fully remove","Replace with a different tourniquet after 30 minutes"],"correct":1,"explain":"NEVER remove a tourniquet in the field once applied for life-threatening hemorrhage control. Removal can restart massive bleeding. Note the time prominently (on skin or device). Warm ischemia tolerance is approximately 6 hours — 30 minutes is well within this window. Definitive hemostasis happens in the OR."},{"q":"You arrive at the scene of a chemical plant explosion with 30 casualties showing SLUDGE symptoms. What is your FIRST action?","opts":["Immediately start treating patients with atropine","Establish scene safety and decontamination zone — providers who enter without PPE become casualties themselves","Call poison control","Triage patients and bring the most critical inside first"],"correct":1,"explain":"Scene safety and decontamination are FIRST in chemical agent events. Treating patients before decontamination exposes providers to the same agent. Set up hot zone (avoid entry), warm zone (decontamination), cold zone (treatment). PPE before entry. Contaminated patients entering hospital can expose entire staff."},{"q":"A trauma patient with penetrating abdominal injury has BP 88/60 on arrival. You establish IV access. How much crystalloid should you give?","opts":["2-3 liters of normal saline to normalize blood pressure","Minimal crystalloid — blood products in 1:1:1 ratio, maintaining SBP 80-90 until surgical hemorrhage control","1 liter bolus, then reassess — no blood products until BP <60","Normal saline until blood pressure reaches 120/80"],"correct":1,"explain":"Damage control resuscitation for penetrating trauma: permissive hypotension (SBP 80-90 until surgery), blood products 1:1:1 over crystalloids. Large crystalloid boluses: dilute clotting factors, worsen hypothermia, increase abdominal compartment risk, dislodge forming clots. Give blood — not saline."},{"q":"In pediatric cardiac arrest, a trained responder should give 2 rescue breaths BEFORE compressions because:","opts":["Pediatric hearts are stronger and need less compression support","Respiratory failure (not cardiac) is the most common cause — oxygenation addresses the root cause","It is physically easier to do breaths first on a small patient","The 2020 AHA guidelines changed to breaths first for all ages"],"correct":1,"explain":"Children most commonly arrest from respiratory causes (hypoxia) — drowning, foreign body, respiratory illness. For trained rescuers: 2 breaths FIRST may restore oxygenation and prevent cardiac arrest entirely. Adults primarily arrest from cardiac causes, hence compressions first (CAB order). Ratio: 30:2 single rescuer, 15:2 two rescuers."},{"q":"A child who was in a house fire is brought to you. SpO2 is 99% but they are confused. What is the priority diagnosis?","opts":["Head injury from the fire — CT head urgently","Carbon monoxide poisoning — standard SpO2 is falsely normal in CO poisoning","Smoke inhalation without CO — treat with oxygen only","Anxiety from the traumatic event"],"correct":1,"explain":"Confused child from house fire with 'normal' SpO2 = carbon monoxide poisoning until proven otherwise. Standard pulse oximetry CANNOT distinguish carboxyhemoglobin from oxyhemoglobin — SpO2 is falsely normal. Diagnose with CO-oximetry or arterial blood gas. Treat with 100% O2 (non-rebreather mask). Consider hyperbaric O2."},{"q":"A patient in cardiac arrest receives epinephrine. What is the PRIMARY mechanism by which it improves CPR outcomes?","opts":["It directly stimulates the heart to resume beating","Alpha-1 adrenergic vasoconstriction increases aortic diastolic pressure, improving coronary and cerebral perfusion pressure during CPR","It increases the chance of a shockable rhythm","It prevents post-resuscitation brain injury"],"correct":1,"explain":"Epinephrine's primary benefit in cardiac arrest is alpha-1 vasoconstriction — it increases systemic vascular resistance, raising aortic diastolic pressure (the driving pressure for coronary perfusion during CPR). Coronary perfusion pressure >15 mmHg is needed for ROSC. Epinephrine improves ROSC rates but has not consistently improved neurologically-intact survival."}]);
  qz.hard=qz.hard.concat([{"q":"A trauma patient in cardiac arrest has penetrating chest trauma and witnessed arrest 8 minutes ago in the ED. What intervention may be life-saving?","opts":["Immediate intubation only","Emergency department thoracotomy with pericardiotomy and aortic cross-clamping","Bilateral chest tubes only","High-dose epinephrine protocol"],"correct":1,"explanation":"EDT is indicated for penetrating torso trauma with witnessed arrest or arrest <15 min before arrival; pericardiotomy for tamponade, aortic cross-clamp for distal hemorrhage control"},{"q":"A patient with TBI has ICP of 28 mmHg (normal <15) and MAP of 75 mmHg. What is the cerebral perfusion pressure and what should be done?","opts":["CPP 47 — acceptable; continue monitoring","CPP 47 — critically low; raise MAP with vasopressors to target CPP 60-70 mmHg","CPP 28 — needs hyperventilation","CPP 103 — too high; lower MAP"],"correct":1,"explanation":"CPP = MAP − ICP = 75 − 28 = 47 mmHg; target CPP 60-70 mmHg in TBI; raise MAP with norepinephrine; consider mannitol or hypertonic saline for ICP"},{"q":"A 27-year-old hypothermic (26°C core temp) drowning victim arrives pulseless. After 3 defibrillation attempts the patient remains in VF. What is the BEST next step?","opts":["Continue ACLS and wait for spontaneous warming","Transport to ECMO-capable center for extracorporeal rewarming during arrest","Give epinephrine every 3 minutes only","Pronounce death — prolonged arrest"],"correct":1,"explanation":"'Not dead until warm and dead' — hypothermic cardiac arrest patients have been resuscitated after prolonged arrests; ECMO rewarming is the definitive treatment for refractory hypothermic VF"},{"q":"A patient in refractory VF has received 6 shocks, 4 doses of amiodarone, and multiple epinephrine doses. What is the most evidence-based next step?","opts":["Continue the same ACLS protocol","Double sequential external defibrillation (DSED) or vector-change defibrillation","Sodium bicarbonate alone","Magnesium sulfate 2g IV"],"correct":1,"explanation":"DOSE VF trial: both DSED and vector-change defibrillation improved termination of refractory VF compared to standard; small but meaningful survival benefit"},{"q":"A patient on antipsychotics develops fever 40.2°C, severe muscle rigidity, autonomic instability, and confusion over 48 hours. The antidote/treatment includes:","opts":["Dantrolene and succinylcholine","Stop the antipsychotic, bromocriptine 2.5-10 mg TID, and dantrolene if severe rigidity","Cyproheptadine and benzodiazepines","IV epinephrine and cooling"],"correct":1,"explanation":"NMS vs serotonin syndrome distinction: NMS develops slowly (days), has lead-pipe rigidity; treatment: stop offending drug, bromocriptine (dopamine agonist), dantrolene for severe rigidity"},{"q":"Succinylcholine is RELATIVELY CONTRAINDICATED in which patient?","opts":["A patient with a full stomach requiring RSI","A burn patient 48 hours after injury requiring emergent intubation","A patient with a difficult airway","A patient in anaphylaxis requiring intubation"],"correct":1,"explanation":"Burns, crush injuries, prolonged immobilization, denervation injuries: upregulate extrajunctional acetylcholine receptors → succinylcholine causes massive K+ efflux → hyperkalemic cardiac arrest; use rocuronium instead 24-48h post-burn"},{"q":"In the treatment of local anesthetic systemic toxicity (LAST) with cardiovascular collapse, what is the SPECIFIC antidote?","opts":["Sodium bicarbonate 1-2 mEq/kg","20% Intralipid (lipid emulsion) 1.5 mL/kg IV bolus","High-dose epinephrine 1 mg","Calcium gluconate 1g"],"correct":1,"explanation":"Lipid emulsion 'lipid sink' theory — sequesters lipophilic LA from myocardium; 20% intralipid 1.5 mL/kg bolus then infusion; avoid epinephrine or use low dose (<1 mcg/kg)"},{"q":"A patient in hemorrhagic shock receives 12 units of pRBC. Oozing from IV sites and mucous membranes begins. TEG shows prolonged clot formation time. What is occurring?","opts":["Heparin effect from blood products","Dilutional coagulopathy and consumptive DIC — treat with FFP and cryoprecipitate","Hypervolemia — stop transfusion","Hemolytic transfusion reaction"],"correct":1,"explanation":"Massive transfusion → dilutional coagulopathy + DIC; treat with FFP (for coagulation factors), cryoprecipitate (for fibrinogen), platelets; TEG/ROTEM guides targeted replacement"},{"q":"REBOA (Resuscitative Endovascular Balloon Occlusion of Aorta) in Zone 1 would be used for:","opts":["Cardiac tamponade","Traumatic aortic injury at the isthmus","Intra-abdominal hemorrhage (liver/spleen/mesenteric) causing hemorrhagic shock","Pelvic fracture hemorrhage alone"],"correct":2,"explanation":"Zone 1 = descending thoracic aorta (controls abdominal bleeding); Zone 3 = infrarenal aorta (controls pelvic bleeding); Zone 2 = visceral segment (avoid — branches); Zone 1 for abdominal, Zone 3 for pelvic"},{"q":"A patient develops sudden cardiovascular collapse, DIC, and bronchospasm immediately after delivery. No other cause is found. The MOST likely diagnosis is:","opts":["Pulmonary embolism","Placental abruption","Amniotic fluid embolism","Eclampsia"],"correct":2,"explanation":"AFE: sudden cardiovascular collapse + DIC + bronchospasm during/after delivery; pathophysiology is anaphylactoid reaction to amniotic fluid; supportive care only; 20-60% maternal mortality"},{"q":"A patient requires emergent cricothyrotomy. The landmark you must identify is:","opts":["The thyroid notch superiorly","The cricothyroid membrane — between thyroid cartilage above and cricoid cartilage below","The hyoid bone superiorly","The sternal notch inferiorly"],"correct":1,"explanation":"Cricothyroid membrane is the target: palpate thyroid cartilage, move inferiorly to the soft space before the cricoid ring; vertical incision then horizontal through membrane; smallest but accessible airway structure"},{"q":"Tranexamic acid (TXA) is most effective when given in hemorrhagic trauma:","opts":["Any time within 24 hours","Within 3 hours of injury — CRASH-2 trial shows increased mortality if given after 3 hours","Only in the operating room","After blood transfusions have started"],"correct":1,"explanation":"CRASH-2 trial: TXA within 3h reduces all-cause mortality; after 3h it significantly INCREASES mortality; do not give late; 1g IV over 10 min, then 1g over 8h"},{"q":"A patient develops sudden cardiovascular collapse 2 minutes after a nerve block with bupivacaine. What is the treatment?","opts":["Standard ACLS with high-dose epinephrine","20% intralipid 1.5 mL/kg IV bolus, then infusion; avoid high-dose epi; prolonged CPR may be needed","Sodium bicarbonate alone","Calcium gluconate and atropine"],"correct":1,"explanation":"Local Anesthetic Systemic Toxicity (LAST): lipid emulsion sequesters bupivacaine from myocardium; high-dose epi worsens outcome in LAST; may need 60+ min CPR while lipid takes effect"},{"q":"After resuscitation from cardiac arrest, a patient is comatose with no purposeful movement. NSE (neuron-specific enolase) is markedly elevated at 72 hours. This suggests:","opts":["Full neurological recovery expected","Poor neurological prognosis — NSE is a biomarker of neuronal injury; >60 mcg/L at 72h post-ROSC predicts poor outcome","NSE is not useful for prognosis","Repeat at 24 hours is needed instead"],"correct":1,"explanation":"Neuroprognostication after cardiac arrest: no single test; multimodal approach uses NSE, SSEP (bilateral absent N20), EEG (burst suppression), CT/MRI findings, clinical exam at ≥72h post-TTM"},{"q":"A patient presents with symmetric ascending weakness, areflexia, and recent URI 3 weeks ago. Respiratory monitoring is critical because:","opts":["Aspiration pneumonia is the main risk","Guillain-Barré syndrome can progress to respiratory failure requiring intubation","Cardiac arrhythmias are the primary risk","Autonomic involvement is rare"],"correct":1,"explanation":"GBS: progressive demyelinating neuropathy; respiratory failure in 25-30%; monitor FVC (intubate if <20 mL/kg or declining rapidly); IVIG or plasmapheresis; dysautonomia can cause arrhythmias"},{"q":"A patient is in cardiac arrest after a massive PE. They receive tPA 50 mg IV push. CPR must continue for at least how long to allow drug distribution?","opts":["5 minutes","60–90 minutes","10 minutes","Stop CPR — give time for drug to work"],"correct":1,"explanation":"After systemic thrombolysis for PE during arrest, continue CPR for at least 60-90 minutes to circulate the drug; tPA is contraindicated if >10 min CPR due to hemorrhage risk — weigh risk/benefit"},{"q":"A patient develops fulminant hepatic failure after acetaminophen overdose. The MOST important early treatment is:","opts":["Liver transplant immediately","N-acetylcysteine (NAC) as early as possible — effective up to 24-36h post-ingestion; transfers to transplant center","Activated charcoal alone","Hemodialysis"],"correct":1,"explanation":"NAC replenishes glutathione which detoxifies NAPQI; most effective within 8h but still given up to 24-36h; IV protocol for severe cases; early transplant listing if King's College criteria met"},{"q":"A 3-year-old is in cardiac arrest from drowning. Two-rescuer CPR is being performed. The correct compression-to-ventilation ratio and compression rate is:","opts":["30:2 at 100/min","15:2 at 100-120/min","15:2 at 80/min","30:2 at 120/min"],"correct":1,"explanation":"Pediatric two-rescuer CPR: 15:2 ratio (allows more ventilations since asphyxia is leading cause); rate 100-120/min; single rescuer: 30:2; asphyxia correction more critical in pediatric arrest than adult"},{"q":"A patient is in cardiogenic shock post-MI with BP 70/50 despite norepinephrine. Which mechanical support device is preferred as a bridge to revascularization?","opts":["Intra-aortic balloon pump (IABP)","Impella or VA-ECMO — provide more robust hemodynamic support than IABP in refractory cardiogenic shock","Pacemaker placement","Cardioversion"],"correct":1,"explanation":"IABP-SHOCK II trial showed no mortality benefit for IABP in cardiogenic shock; Impella CP provides 3.5 L/min assist; VA-ECMO provides full cardiopulmonary support; ECMO preferred if profound shock"},{"q":"What is the pathophysiology of reperfusion injury and how does targeted temperature management help?","opts":["Reperfusion injury doesn't exist — blood flow returning is always beneficial","Reperfusion generates reactive oxygen species and calcium overload causing neuronal death; TTM reduces metabolic rate and ROS production during vulnerable period","TTM only helps by reducing heart rate","TTM prevents bleeding after reperfusion"],"correct":1,"explanation":"After ischemia-reperfusion: ROS burst, calcium influx, inflammation, apoptosis cascade; TTM (32-36°C) reduces cerebral metabolic rate 5-7% per degree; suppresses glutamate, ROS, apoptosis during critical 24h window"},{"q":"Which of the following scenarios requires IMMEDIATE needle decompression, NOT waiting for chest tube?","opts":["Hemothorax after chest trauma with stable vitals","Suspected pneumothorax with normal vital signs","Tension pneumothorax — patient in hemodynamic shock with absent breath sounds and tracheal deviation","Simple rib fracture"],"correct":2,"explanation":"Tension pneumothorax is a clinical diagnosis; do NOT wait for CXR in an unstable patient; immediate needle decompression 2nd ICS MCL buys time; definitive treatment is chest tube (finger thoracostomy in field)"},{"q":"A patient collapses during exercise with a heart rate of 220 and regular rhythm. BP is 70/50 and the patient is unconscious. Treatment is:","opts":["Adenosine 6 mg IV push","Amiodarone 300 mg IV over 20 minutes","Unsynchronized defibrillation (cardioversion)","Synchronized cardioversion at 200J"],"correct":3,"explanation":"Unstable SVT or VT with a pulse: synchronized cardioversion; this patient is hemodynamically unstable (hypotension, unconscious); start at 50-100J for SVT; 200J for VT; unsynchronized only for pulseless VT/VF"},{"q":"A patient is in status epilepticus. Lorazepam 4mg IV has been given twice without effect. IV access is now lost. What is the BEST alternative route for benzodiazepine?","opts":["Wait for another IV","Intranasal midazolam or rectal diazepam","Oral diazepam","IM lorazepam only"],"correct":1,"explanation":"Alternative benzodiazepine routes for status epilepticus: IM midazolam (fastest), intranasal midazolam, rectal diazepam; IM midazolam shown equivalent to IV lorazepam in RAMPART trial; preferred if no IV access"},{"q":"A patient's blood pressure drops from 150/90 to 90/60 immediately after IV push of metoprolol for rate control of rapid atrial fibrillation. What is the NEXT step?","opts":["Give more metoprolol to maintain rate control","IV calcium chloride or glucagon to reverse beta-blocker effect; IV fluids; vasopressors if needed","Give adenosine","Observe and recheck BP in 5 minutes"],"correct":1,"explanation":"Beta-blocker toxicity causing hemodynamic compromise: calcium chloride (1g IV) and glucagon (2-10 mg IV) reverse negative inotropic/chronotropic effects; high-dose insulin therapy if refractory; vasopressors as needed"},{"q":"In the context of mass casualty incidents, 'expectant' (black tag) means:","opts":["The patient is already dead","Injuries are survivable with immediate surgery","The patient's injuries are so severe that survival is unlikely even with treatment, and limited resources should be directed to salvageable patients","The patient is walking and has minor injuries"],"correct":2,"explanation":"Expectant (black) in mass casualty: NOT always already dead; injuries may be survivable individually but require extensive resources that would deprive many salvageable patients; ethically difficult but resource-appropriate triage decision"},{"q":"A patient has a cardiac arrest and you begin CPR. Your ETCO2 reading is consistently 5 mmHg despite high-quality CPR. What is the clinical implication?","opts":["The ETT is correctly placed — continue","This indicates either esophageal intubation OR non-survivable cardiac arrest with no cardiac output","The patient is hyperventilated","ETCO2 is not reliable during CPR"],"correct":1,"explanation":"ETCO2 <10 mmHg during CPR: either esophageal placement (verify with direct laryngoscopy) OR cardiac output too low to deliver CO2 to lungs; if ETT confirmed tracheal and ETCO2 consistently <10 despite ACLS = poor prognosis"},{"q":"A patient has been in cardiac arrest for 45 minutes. The team considers stopping resuscitation. Which factor, if present, is MOST associated with recommending continued resuscitation?","opts":["Patient age over 60","Witnessed arrest with immediately initiated CPR, initial shockable rhythm, and reversible cause identified (e.g., hypothermia, K+<12)","Male sex","Type of cardiac arrest location"],"correct":1,"explanation":"Survival predictors supporting continued resuscitation: witnessed arrest, bystander CPR, shockable rhythm (VF/VT), potentially reversible cause (hypothermia, overdose, electrolytes); absent all these after 20+ min = poor prognosis; hypothermia exception"},{"q":"Which electrolyte abnormality is the MOST immediately life-threatening in a patient with acute renal failure?","opts":["Hyponatremia","Hyperkalemia — can cause fatal arrhythmias (VF/VT) with minimal warning","Hyperphosphatemia","Hypomagnesemia"],"correct":1,"explanation":"Hyperkalemia in acute renal failure: K+>6.5 mEq/L or ECG changes → emergency; peaked T waves → prolonged PR → wide QRS → sine wave → VF; calcium gluconate stabilizes membrane immediately; shift K+ with insulin/glucose/bicarb"},{"q":"A patient is found unconscious with a blood glucose of 18 mg/dL. IV access is obtained. What is the correct treatment?","opts":["Glucagon 1 mg IM","25g (50 mL of D50) or 25-50g dextrose IV push, then reassess and start glucose infusion","Normal saline bolus","Insulin to 'balance' the glucose"],"correct":1,"explanation":"Severe hypoglycemia with IV access: D50W 25-50g (50 mL) IV push immediately; recheck glucose in 15 min; start D10W infusion to maintain; always look for and treat the underlying cause; thiamine before glucose in alcoholics"},{"q":"Post-ROSC management: ETCO2 is 25 mmHg on controlled ventilation at rate 16. SpO2 97%. What change is needed?","opts":["Decrease ventilation rate — ETCO2 25 indicates hyperventilation causing cerebral vasoconstriction","Increase O2 to 100% — SpO2 97% is dangerously low post-arrest","Increase ventilation rate — ETCO2 25 is too high","No changes needed — all parameters are acceptable"],"correct":0,"explain":"ETCO2 25 mmHg = hyperventilation (target 35-45 mmHg). Post-cardiac arrest hyperventilation causes cerebral vasoconstriction, reducing cerebral blood flow and worsening neurological outcomes. Decrease respiratory rate. Also note: SpO2 97% is GOOD — target 92-98% to avoid hyperoxia. Both hypocapnia and hyperoxia worsen post-arrest brain injury."},{"q":"A 6-year-old with severe asthma is intubated for status asthmaticus. Peak airway pressures are 65 cmH2O and rising. BP is dropping. What is happening?","opts":["Tube obstruction — suction immediately","Auto-PEEP (breath stacking/dynamic hyperinflation) causing tension physiology — disconnect from ventilator","Tension pneumothorax only — perform needle decompression immediately","Endotracheal tube displacement — confirm with laryngoscopy"],"correct":1,"explain":"Air trapping in severe asthma during mechanical ventilation causes auto-PEEP (intrinsic PEEP) — progressive hyperinflation that mimics tension pneumothorax. First: disconnect from ventilator to allow exhalation (immediate pressure release). Then: reduce respiratory rate, increase expiratory time, permissive hypercapnia. Distinguish from tension PTX before needling."},{"q":"A trauma patient receives 12 units of packed red blood cells. They develop diffuse oozing, prolonged PT/PTT, fibrinogen 80 mg/dL. What is the priority treatment?","opts":["More packed red blood cells — the problem is anemia","Cryoprecipitate to replace fibrinogen — fibrinogen <100 is critical threshold","Fresh frozen plasma only — contains all clotting factors","Hold all blood products — patient has DIC and products worsen it"],"correct":1,"explain":"Fibrinogen <100 mg/dL is a critical threshold requiring cryoprecipitate (each unit contains 250 mg fibrinogen). Fibrinogen is the first clotting factor depleted in massive hemorrhage. FFP contains fibrinogen but in lower concentration — cryoprecipitate is more efficient. Target fibrinogen >150-200 mg/dL in massive transfusion."},{"q":"During RSI, succinylcholine 1.5 mg/kg is given to a patient with undiagnosed extensive burns (48 hours post-burn). Immediately after, ECG shows sine wave pattern. What happened?","opts":["Succinylcholine caused malignant hyperthermia","Succinylcholine caused fatal hyperkalemia from upregulated extrajunctional acetylcholine receptors","Normal ECG response to succinylcholine — temporary pattern","The patient has Wolff-Parkinson-White syndrome"],"correct":1,"explain":"Burns >48h upregulate extrajunctional ACh receptors throughout all muscle membranes. Succinylcholine depolarizes ALL receptors simultaneously causing massive K+ efflux. K+ can rise 5+ mEq/L → hyperkalemia → peaked T waves → sine wave → VF/asystole. Sine wave pattern = severe hyperkalemia. Treatment: calcium chloride immediately, insulin+glucose, defibrillation."},{"q":"A patient in VF fails 5 defibrillation attempts, amiodarone, epinephrine, and lidocaine. What intervention has the best evidence for refractory VF?","opts":["Triple-dose epinephrine (3mg IV)","Double sequential external defibrillation (DSED) — DOSE VF trial showed improved ROSC rates","Bretylium tosylate IV — only agent proven for refractory VF","Magnesium sulfate 4g IV regardless of Mg level"],"correct":1,"explain":"DOSE VF trial (2022): DSED (two defibrillators firing simultaneously from anterior-posterior + right lateral vectors) significantly improved ROSC and survival compared to standard defibrillation in refractory VF. Vector-change defibrillation also showed benefit. Esmolol infusion reduces recurrent VF. Reserve DSED for truly refractory VF."},{"q":"A patient is given bupivacaine (a local anesthetic) for a nerve block. Five minutes later: seizures, then cardiac arrest with wide QRS. What is the treatment?","opts":["Naloxone — reverses local anesthetic toxicity","20% Intralipid 1.5 mL/kg IV bolus — lipid emulsion sequesters bupivacaine away from cardiac sodium channels","Sodium bicarbonate only — same as TCA overdose","Physostigmine — reverses sodium channel blockade"],"correct":1,"explain":"Local anesthetic systemic toxicity (LAST): lipid emulsion (Intralipid 20%) is the antidote. Creates a 'lipid sink' in plasma that sequesters lipophilic local anesthetic away from cardiac Na+ channels. 1.5 mL/kg bolus, then infusion. AVOID propofol (insufficient lipid, causes hypotension). CPR may be prolonged — ECMO if available."},{"q":"A septic patient (MAP 50 despite 3L crystalloid) requires vasopressors. You choose norepinephrine. They remain hypotensive on norepinephrine 0.5 mcg/kg/min. What do you add?","opts":["Epinephrine is always second — add epinephrine 0.5 mcg/kg/min","Vasopressin 0.03 units/min — spares norepinephrine dose and has synergistic effect in septic shock","Phenylephrine — pure alpha agent is superior to mixed agents","Dopamine — more physiological than synthetic catecholamines"],"correct":1,"explain":"Vasopressin is the recommended second vasopressor in septic shock. VASST trial: vasopressin 0.03-0.04 units/min allows norepinephrine dose reduction and may improve outcomes in less severe septic shock. Acts on V1 receptors (independent of adrenergic system). Also consider hydrocortisone 200-300 mg/day if refractory to 2 vasopressors."},{"q":"A patient with traumatic arrest (penetrating chest) arrives after 8 minutes of CPR. What is the one intervention most likely to save their life that is not standard CPR?","opts":["Higher dose epinephrine (5mg instead of 1mg)","Emergency department thoracotomy — directly relieve tamponade, cross-clamp aorta, and perform internal cardiac massage","Immediate CT scan to identify injuries","High-dose steroids to reduce cardiac inflammation"],"correct":1,"explain":"Emergency department thoracotomy (EDT) for penetrating traumatic arrest: directly open pericardium (relieve tamponade), cross-clamp the descending aorta (redirects blood to heart and brain), perform internal cardiac massage. EDT survival for penetrating cardiac injury: 11-35%. For blunt: <2%. Must be done within 15 minutes of arrest with signs of life previously."},{"q":"Sodium is 124 mEq/L in a SIADH patient who is asymptomatic. They ask if they can eat normally. What is the most important instruction?","opts":["Drink 2+ liters of water daily — SIADH causes sodium loss and water replaces it","Restrict fluid intake to 500-1000 mL/day — fluid restriction is first-line treatment for SIADH","Increase salt intake only — fluid restriction is not needed","No dietary changes — SIADH resolves spontaneously"],"correct":1,"explain":"SIADH treatment: fluid restriction (500-1000 mL/day) is first-line. SIADH = excess ADH → water retention → dilutional hyponatremia. Salt tablets + fluid restriction, or vaptans (tolvaptan) for refractory cases. Hypertonic saline only for symptomatic (seizure) hyponatremia. Rate-limit correction (8-10 mEq/L per 24h) to prevent osmotic demyelination."},{"q":"During a mass casualty incident with 50 casualties, you have only 5 trauma surgeons available. A patient is in cardiac arrest with 3rd-degree burns to 95% BSA and obvious unsurvivable injuries. How should they be triaged?","opts":["Red (immediate) — cardiac arrest always receives highest priority","Black (expectant) — resources spent here cannot help salvageable patients","Yellow (delayed) — provide comfort measures and reassess later","Green (minor) — burns are not immediately life-threatening"],"correct":1,"explain":"Black (expectant) triage for unsurvivable injuries in a true MCI is ethically justified and clinically correct. Utilitarian ethics: greatest good for greatest number. 95% BSA burns in cardiac arrest = non-survivable with available resources. Re-triage if resources become available. This is NOT abandonment — comfort measures continue."},{"q":"A patient develops hyperthermia to 41°C, severe muscle rigidity, and autonomic instability 2 days after starting haloperidol. Creatinine is rising. What distinguishes this from serotonin syndrome and what is the treatment?","opts":["This is serotonin syndrome — treat with cyproheptadine and benzos","NMS: gradual onset over days, lead-pipe rigidity throughout range of motion, NO clonus — stop antipsychotic, give dantrolene + bromocriptine + supportive care","Identical to serotonin syndrome — same treatment","Malignant hyperthermia — give dantrolene and cool immediately regardless of cause"],"correct":1,"explain":"NMS distinguishers: (1) antipsychotic trigger; (2) gradual onset over 24-72 hours; (3) 'lead-pipe' rigidity throughout ROM; (4) NO clonus or hyperreflexia; (5) 'cogwheel' rigidity. Serotonin syndrome: rapid onset (hours), inducible ankle clonus, hyperreflexia. NMS treatment: stop drug, dantrolene (reduces rigidity), bromocriptine (dopamine agonist), cooling, supportive care. Mortality 5-20%."},{"q":"An unconscious trauma patient has no IV access and needs immediate epinephrine. Attempts at peripheral IV have failed twice. What is the fastest next step?","opts":["Central venous catheter — subclavian or internal jugular","Intraosseous (IO) access — tibial plateau — provides central venous access equivalent in 15 seconds","Endotracheal drug delivery — give 3x IV dose down the tube","Femoral vein — always accessible in trauma"],"correct":1,"explain":"IO access is the fastest alternative to IV access in emergency: tibial plateau (or proximal humerus) with EZ-IO device in <15 seconds. All resuscitation drugs and fluids reach central circulation in 15-30 seconds — identical to IV. Endotracheal drug delivery has unpredictable absorption and is no longer recommended. Central line takes too long and requires positioning."},{"q":"In damage control surgery, the surgeon 'packs and runs.' The patient returns to the ICU with an open abdomen, BP 85/60, temperature 34°C, pH 7.25, and fibrinogen 80 mg/dL. In what order should these abnormalities be corrected?","opts":["Blood pressure first — everything else follows from adequate perfusion","All simultaneously — warm blood products address hypothermia, coagulopathy, and hypoperfusion together","Fibrinogen first — coagulopathy causes ongoing bleeding which drives the other abnormalities","Hypothermia first — then acid-base correction, then coagulopathy"],"correct":1,"explain":"DCR in ICU targets ALL components of lethal triad simultaneously with warm blood products: (1) Warm blood + external warming corrects hypothermia; (2) FFP + cryoprecipitate corrects coagulopathy; (3) Perfusion (vasopressors if needed) + bicarb corrects acidosis. Sequential correction is slower and allows the triad to worsen further. Target: temp >36°C, pH >7.35, fibrinogen >150."},{"q":"You are caring for a 36-week pregnant patient in cardiac arrest. After 4 minutes of CPR with no ROSC, what intervention should be performed?","opts":["Increase epinephrine frequency to every 2 minutes","Perimortem cesarean section at bedside — delivery within 5 min of arrest improves maternal ROSC by relieving aortocaval compression","Transport immediately to OR before any surgical intervention","Do not perform PMCD — risk of harm to fetus too high at 36 weeks"],"correct":1,"explain":"PMCD (perimortem cesarean delivery) within 5 minutes of maternal arrest: the gravid uterus compresses the IVC (reduces venous return) and aorta (increases afterload), reducing CPR effectiveness by up to 40%. Delivery relieves this compression, improving maternal CPR output and ROSC rates. At 36 weeks, fetal viability is excellent. Perform at bedside — don't wait for OR."},{"q":"A firefighter returns from a structure fire confused and tachycardic. SpO2 is 99%. Carboxyhemoglobin level returns at 35%. Based on this COHb level, what treatment beyond 100% O2 should be considered?","opts":["No additional treatment needed — 100% O2 is definitive for all CO poisoning","Hyperbaric oxygen therapy — COHb >25%, neurological symptoms, or cardiac involvement are indications","IV sodium bicarbonate to treat metabolic acidosis","Intubation and ventilation for all patients with COHb >20%"],"correct":1,"explain":"Hyperbaric oxygen (HBO) indications for CO poisoning: COHb >25%, any loss of consciousness, neurological symptoms (confusion, syncope), cardiac arrhythmia or ischemia, pregnancy at any COHb level. HBO at 3 ATA reduces CO half-life to 23 minutes vs 90 min on 100% O2. Reduces delayed neurological syndrome by 46%."},{"q":"A critically injured trauma patient requires emergency intubation. After RSI and tube placement, you hear equal breath sounds but ETCO2 reads 0 mmHg on waveform capnography. What has happened?","opts":["The patient has severe metabolic acidosis causing no CO2 production","Esophageal intubation — no CO2 detected because tube is not in trachea — remove tube immediately and reoxygenate with BVM","ETCO2 is unreliable in trauma — confirm with chest X-ray","Correct placement — ETCO2 takes 2-3 minutes to equilibrate"],"correct":1,"explain":"ETCO2 = 0 with waveform capnography = esophageal intubation until proven otherwise. Esophageal placement may briefly show a few capnography waves from gastric CO2 that rapidly disappear — flat line = esophagus. Remove immediately. Reoxygenate with BVM. Re-intubate. This is why waveform capnography is THE gold standard for tube confirmation — auscultation alone is unreliable."}]);
})();

// ══════════════════════════════════════════════════════════════════════════
// NUTRITION EXPANSION
// ══════════════════════════════════════════════════════════════════════════
(function(){
  if(!window.QB_NUTRITION) return;
  var fc=window.QB_NUTRITION.flashcards, qz=window.QB_NUTRITION.quiz;
  if(!fc||!qz) return;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});
  fc.easy=fc.easy.concat([{"term":"Calorie","def":"Unit of energy in food — 1 calorie = energy to raise 1g water by 1°C","breakdown":"Food calories are actually kilocalories (kcal). The calorie count on a food label = kcal"},{"term":"Carbohydrate calories","def":"4 calories per gram of carbohydrate","breakdown":"Carbs are the body's preferred energy source. 1 slice bread ≈ 15g carbs = 60 calories"},{"term":"Protein calories","def":"4 calories per gram of protein","breakdown":"Same as carbs but protein builds/repairs tissue. 3oz chicken ≈ 21g protein = 84 calories"},{"term":"Fat calories","def":"9 calories per gram of fat — more than double carbs/protein","breakdown":"Fat is energy-dense. 1 tbsp olive oil = 14g fat = 126 calories. Why fatty foods are calorie-heavy"},{"term":"Alcohol calories","def":"7 calories per gram of alcohol — between fat and carbs","breakdown":"Alcohol provides calories but no essential nutrients — 'empty calories'"},{"term":"Simple carbohydrates","def":"Single or double sugar units — digest quickly, rapid blood sugar spike","breakdown":"Glucose, fructose (fruit), lactose (milk), sucrose (table sugar). Fast energy but short-lasting"},{"term":"Complex carbohydrates","def":"Long chains of sugar units — digest slowly, steady blood sugar","breakdown":"Starch (potatoes, rice) and fiber (vegetables, whole grains). Sustained energy release"},{"term":"Dietary fiber","def":"Indigestible plant carbohydrate — feeds gut bacteria, aids digestion, lowers cholesterol","breakdown":"Soluble fiber: dissolves in water (oats, beans). Insoluble fiber: doesn't dissolve (wheat bran, vegetables)"},{"term":"Recommended daily fiber","def":"25g/day for women, 38g/day for men (or 14g per 1000 calories)","breakdown":"Most Americans get only 15g/day. Fiber deficiency linked to constipation, colon cancer risk, heart disease"},{"term":"Essential amino acids","def":"9 amino acids the body cannot make — must come from food","breakdown":"Histidine, Isoleucine, Leucine, Lysine, Methionine, Phenylalanine, Threonine, Tryptophan, Valine"},{"term":"Fat-soluble vitamins","def":"Vitamins A, D, E, K — stored in fat tissue and liver — can accumulate to toxic levels","breakdown":"Stored long-term so don't need daily intake. Excess supplementation can cause toxicity (especially A and D)"},{"term":"Water-soluble vitamins","def":"Vitamins C and all B vitamins — not stored, excess excreted in urine","breakdown":"Need regular daily intake. Deficiency develops faster than fat-soluble vitamins. B12 exception: stored in liver"},{"term":"Vitamin A functions","def":"Vision (especially night vision), immune function, skin and cell growth","breakdown":"Preformed A (retinol) in animal foods. Provitamin A (beta-carotene) in orange/yellow vegetables. Deficiency causes night blindness"},{"term":"Vitamin C functions","def":"Collagen synthesis, antioxidant, immune support, iron absorption enhancement","breakdown":"Found in citrus, bell peppers, strawberries. Deficiency causes scurvy. Water-soluble — cook gently to preserve"},{"term":"Vitamin D functions","def":"Calcium absorption, bone health, immune function, muscle function","breakdown":"Synthesized in skin from sunlight. Food sources: fatty fish, fortified dairy. Deficiency: rickets (children), osteomalacia (adults)"},{"term":"Iron functions","def":"Oxygen transport in hemoglobin, energy metabolism, immune function","breakdown":"Heme iron (meat) absorbed 2-3x better than non-heme iron (plants). Vitamin C enhances non-heme iron absorption"},{"term":"Calcium functions","def":"Bone and tooth structure, muscle contraction, nerve transmission, blood clotting","breakdown":"99% of body's calcium is in bones/teeth. Dairy, leafy greens, fortified foods. Deficiency leads to osteoporosis"},{"term":"Sodium functions","def":"Fluid balance, nerve transmission, muscle contraction","breakdown":"DRI: <2300mg/day. Average American gets ~3400mg. Excess raises blood pressure. Kidney disease requires further restriction"},{"term":"Potassium functions","def":"Fluid balance, heart rhythm, muscle and nerve function — counters sodium","breakdown":"High potassium diet lowers blood pressure. Found in bananas, potatoes, beans, leafy greens"},{"term":"Dehydration signs","def":"Dark urine, dry mouth, headache, fatigue, dizziness, reduced urine output","breakdown":"2% body weight fluid loss impairs cognitive performance. 5-8% causes serious symptoms. Sports drinks replace electrolytes"},{"term":"BMI formula","def":"Body Mass Index = weight(kg) / height(m)². Screening tool, not diagnostic","breakdown":"<18.5 underweight; 18.5-24.9 normal; 25-29.9 overweight; ≥30 obese. Doesn't account for muscle mass"},{"term":"Basal Metabolic Rate (BMR)","def":"Calories burned at complete rest — energy for vital functions (breathing, circulation, cell repair)","breakdown":"Largest component of total daily energy expenditure. Influenced by age, sex, body composition, genetics"},{"term":"Food label serving size","def":"Reference amount for nutrition information — NOT a recommendation of how much to eat","breakdown":"Calories and all nutrients on label are per serving. If you eat 2 servings, double everything"},{"term":"% Daily Value (%DV)","def":"How much a nutrient in one serving contributes to a 2000-calorie daily diet","breakdown":"5% DV or less = low in that nutrient. 20% DV or more = high. Use to compare foods and assess diet quality"},{"term":"Added sugars","def":"Sugars added during food processing — listed separately on Nutrition Facts since 2020","breakdown":"DRI: <10% of calories (50g/day for 2000-cal diet). Natural sugars in fruit and milk not counted as added"},{"term":"Macronutrient","def":"Nutrient needed in large amounts — carbohydrates, proteins, and fats","breakdown":"Macro=large. These provide energy (calories). Contrast with micronutrients (vitamins/minerals) needed in small amounts"},{"term":"Micronutrient","def":"Vitamin or mineral needed in small amounts for body functions","breakdown":"Micro=small. No calories. Essential for immune function, bone health, metabolism. Deficiency causes specific diseases"},{"term":"Carbohydrate","def":"Primary energy source — sugars, starches, and fiber; 4 calories per gram","breakdown":"Simple carbs: sugar (quick energy). Complex carbs: starch/fiber (slow energy). 45-65% of calories should come from carbs"},{"term":"Protein","def":"Macronutrient made of amino acids — builds and repairs tissue; 4 calories per gram","breakdown":"Complete proteins: all 9 essential amino acids (meat, eggs, quinoa). Incomplete: missing some (beans, rice). 10-35% of calories"},{"term":"Fat","def":"Macronutrient providing 9 calories per gram — most energy-dense nutrient","breakdown":"Saturated (solid at room temp): limit. Unsaturated (liquid): heart-healthy. Trans fat: avoid. 20-35% of total calories"},{"term":"Vitamin","def":"Organic compound essential in small amounts for normal body function","breakdown":"Fat-soluble (A,D,E,K): stored in body. Water-soluble (C, B vitamins): excreted in urine. Must come from food"},{"term":"Mineral","def":"Inorganic element essential for body functions — calcium, iron, potassium, etc.","breakdown":"Major minerals (>100mg/day): calcium, phosphorus, magnesium, sodium, potassium. Trace minerals (<100mg/day): iron, zinc, iodine"},{"term":"Amino acid","def":"Building block of protein — 20 total, 9 are essential (must come from food)","breakdown":"Essential: histidine, isoleucine, leucine, lysine, methionine, phenylalanine, threonine, tryptophan, valine. Body makes the other 11"},{"term":"Essential nutrient","def":"Nutrient the body cannot make in sufficient amounts — must be obtained from food","breakdown":"6 classes: carbohydrates, proteins, fats, vitamins, minerals, water. 'Essential' means diet-required, not just 'important'"},{"term":"Dietary Reference Intake (DRI)","def":"Set of nutrient intake values used to plan and assess diets","breakdown":"Includes RDA (Recommended Dietary Allowance), AI (Adequate Intake), UL (Tolerable Upper Intake Level), and EAR"},{"term":"Food label","def":"Nutrition facts panel on packaged food showing serving size, calories, and nutrients","breakdown":"Read: serving size first (all values per serving). % Daily Value based on 2000 cal diet. 5%=low, 20%=high"},{"term":"Serving size","def":"Standardized amount of food used as reference on nutrition facts label","breakdown":"NOT a recommendation — just a reference. Actual portions people eat may differ. Compare packages using same serving size"},{"term":"Empty calories","def":"Calories from food with little nutritional value — high in sugar or solid fats","breakdown":"Examples: soda, candy, alcohol, many processed snacks. Provide energy but few vitamins, minerals, or fiber"},{"term":"Whole grain","def":"Grain containing bran, germ, and endosperm — not refined or processed","breakdown":"Examples: whole wheat, oats, brown rice, quinoa, barley. Higher fiber and nutrients than refined grains. '100% whole grain' on label"},{"term":"Refined grain","def":"Grain with bran and germ removed — lower in fiber and nutrients","breakdown":"Examples: white bread, white rice, white pasta. Often enriched with some B vitamins and iron back. Choose whole grains instead"},{"term":"Added sugar","def":"Sugar added to foods during processing — not naturally occurring","breakdown":"American Heart Association limit: women <25g/day, men <36g/day. Linked to obesity, type 2 diabetes, tooth decay, heart disease"},{"term":"Vitamin D","def":"Fat-soluble vitamin essential for calcium absorption and bone health","breakdown":"Made from sunlight. Food sources: fatty fish, fortified milk, egg yolks. Most Americans deficient. Recommended 600-800 IU/day"},{"term":"Vitamin C","def":"Water-soluble antioxidant vitamin essential for immune function and collagen synthesis","breakdown":"Sources: citrus, strawberries, bell peppers, broccoli. Deficiency = scurvy. Recommended: men 90mg, women 75mg. Smokers need more"},{"term":"Vitamin A","def":"Fat-soluble vitamin essential for vision, immune function, and cell growth","breakdown":"Preformed (retinol): animal foods. Provitamin A (beta-carotene): orange/yellow plants. Deficiency = night blindness"},{"term":"B vitamins","def":"Group of 8 water-soluble vitamins essential for energy metabolism and nerve function","breakdown":"B1 thiamine, B2 riboflavin, B3 niacin, B5 pantothenic, B6, B7 biotin, B9 folate, B12. Found in whole grains, meat, legumes"},{"term":"Folate (folic acid)","def":"B vitamin essential for DNA synthesis and cell division — critical in pregnancy","breakdown":"Prevents neural tube defects. Women of childbearing age: 400mcg/day. Folic acid (synthetic) better absorbed than folate (food)"},{"term":"Antioxidant","def":"Compound that neutralizes free radicals — protects cells from oxidative damage","breakdown":"Vitamins C, E, beta-carotene are antioxidants. Found in colorful fruits and vegetables. Associated with reduced chronic disease risk"},{"term":"Free radical","def":"Unstable molecule that damages cells — contributes to aging and chronic disease","breakdown":"Produced by normal metabolism, pollution, UV radiation, smoking. Antioxidants neutralize free radicals. Excess causes oxidative stress"},{"term":"Omega-3 fatty acid","def":"Essential polyunsaturated fat — anti-inflammatory; found in fatty fish, flaxseed, walnuts","breakdown":"EPA and DHA: marine sources. ALA: plant sources. Benefits: heart health, brain function, reduce inflammation. 2 fish servings/week"},{"term":"Omega-6 fatty acid","def":"Essential polyunsaturated fat found in vegetable oils — pro-inflammatory in excess","breakdown":"Linoleic acid is the essential omega-6. Western diet has too many omega-6 relative to omega-3. Balance is important for health"},{"term":"Cholesterol (dietary)","def":"Waxy substance in animal foods — liver also produces cholesterol","breakdown":"Current guidelines: no specific limit. Saturated and trans fats raise LDL more than dietary cholesterol. Found in eggs, meat, dairy"},{"term":"Triglyceride","def":"Main form of fat in blood and stored in adipose tissue — elevated levels increase heart risk","breakdown":"Normal <150 mg/dL. Raised by excess carbs, sugar, alcohol. Lowered by exercise, less sugar, omega-3 fatty acids"},{"term":"Phytochemical","def":"Bioactive plant compound with health benefits — not classified as essential nutrient","breakdown":"Examples: lycopene (tomatoes), flavonoids (berries), glucosinolates (broccoli). Associated with reduced cancer and heart disease risk"},{"term":"Probiotic","def":"Live beneficial bacteria in food — supports gut microbiome health","breakdown":"Found in yogurt, kefir, sauerkraut, kimchi, miso. Strains: Lactobacillus, Bifidobacterium. Benefits: digestion, immunity"},{"term":"Prebiotic","def":"Non-digestible fiber that feeds beneficial gut bacteria","breakdown":"Found in garlic, onions, bananas, asparagus, oats. Fermented by gut bacteria producing short-chain fatty acids. Supports gut health"},{"term":"Electrolyte","def":"Mineral with electric charge — regulates fluid balance, nerve, and muscle function","breakdown":"Key electrolytes: sodium, potassium, chloride, magnesium, calcium. Lost in sweat. Sports drinks replace electrolytes in prolonged exercise"},{"term":"Food allergy","def":"Immune system reaction to a food protein — can be life-threatening","breakdown":"Top 9 allergens: milk, eggs, fish, shellfish, tree nuts, peanuts, wheat, soy, sesame. Symptoms: hives to anaphylaxis. Avoid the food"},{"term":"Food intolerance","def":"Digestive difficulty with a food — not immune-mediated, rarely life-threatening","breakdown":"Example: lactose intolerance (missing enzyme). Symptoms: bloating, gas, diarrhea. Different from allergy — dose-dependent"},{"term":"Lactose","def":"Sugar found in milk — requires lactase enzyme to digest","breakdown":"Lactose intolerance: insufficient lactase enzyme. Common in adults worldwide. Symptoms after dairy: bloating, gas, diarrhea"},{"term":"Gluten","def":"Protein in wheat, rye, and barley — triggers immune reaction in celiac disease","breakdown":"Celiac disease: autoimmune, gluten damages small intestine. Non-celiac gluten sensitivity: symptoms without autoimmune damage"},{"term":"BMI (Body Mass Index)","def":"Weight-to-height ratio used to screen for weight categories","breakdown":"BMI = kg/m². Underweight <18.5, Normal 18.5-24.9, Overweight 25-29.9, Obese ≥30. Limitations: doesn't measure body fat directly"},{"term":"Metabolism","def":"All chemical processes in the body that convert food to energy","breakdown":"Basal metabolic rate (BMR): energy at rest. Total energy expenditure adds activity. Thyroid controls metabolic rate"},{"term":"Undernutrition","def":"Insufficient intake of calories or nutrients — causes stunting, wasting, deficiencies","breakdown":"Marasmus: severe calorie deficiency. Kwashiorkor: severe protein deficiency with edema. Most common in developing countries"},{"term":"Obesity","def":"Excess body fat — BMI ≥30; associated with chronic diseases","breakdown":"Causes: excess calories, inactivity, genetics, environment. Associated with: type 2 diabetes, heart disease, sleep apnea, joint problems"},{"term":"Type 2 diabetes","def":"Metabolic disorder where cells become resistant to insulin — largely diet and lifestyle related","breakdown":"Prevention: healthy weight, exercise, whole grains, vegetables, less sugar. Treatment: diet, exercise, medications, insulin if needed"},{"term":"Insulin","def":"Hormone from pancreas that allows cells to absorb glucose from blood","breakdown":"Released after eating. Resistance: cells don't respond — blood glucose stays high. Type 2 diabetes is insulin resistance"},{"term":"Blood glucose","def":"Amount of sugar in the bloodstream — regulated by insulin and glucagon","breakdown":"Normal fasting: 70-100 mg/dL. Pre-diabetes: 100-125. Diabetes: ≥126. After meals: up to 140 mg/dL is normal"},{"term":"Glycemic index","def":"Ranking of how quickly a carbohydrate food raises blood glucose","breakdown":"High GI (>70): white bread, white rice. Low GI (<55): lentils, oats, most fruits. Fiber slows digestion and lowers GI"},{"term":"Whole food","def":"Food in its natural, unprocessed state — minimally refined","breakdown":"Examples: fruits, vegetables, whole grains, legumes, nuts, lean meats. Generally higher in fiber, vitamins, minerals than processed"},{"term":"Processed food","def":"Food that has been altered from its natural state through cooking, preserving, or adding ingredients","breakdown":"Not all processing is bad (frozen vegetables, yogurt). Ultra-processed (chips, soda) have many additives, low nutrition"},{"term":"DASH diet","def":"Dietary Approaches to Stop Hypertension — emphasizes fruits, vegetables, low-fat dairy, less sodium","breakdown":"Reduces blood pressure by 8-14 mmHg. High in potassium, calcium, magnesium. Limits sodium to 2300mg (or 1500mg) per day"},{"term":"Sustainable diet","def":"Diet with low environmental impact that supports food security and health","breakdown":"Less meat (especially beef), more plants, less food waste, local/seasonal foods. Planetary health diet reduces greenhouse gas emissions"},{"term":"Food desert","def":"Area with limited access to affordable, nutritious food","breakdown":"Often in low-income or rural areas. Associated with poor diet quality and chronic disease. Convenience stores dominate. Public health concern"},{"term":"Portion size","def":"Amount of food actually eaten — may differ from serving size","breakdown":"Super-sizing and large plates increase portions. Use smaller plates, measure portions, eat slowly, stop when satisfied"},{"term":"Appetite","def":"Desire to eat, influenced by hunger, emotions, environment, and learned behaviors","breakdown":"Hunger is physiological (stomach empty, blood sugar low). Appetite can exist without hunger (emotional eating, food cues)"},{"term":"Hunger","def":"Physiological signal from body indicating need for energy","breakdown":"Controlled by ghrelin (hunger hormone) and leptin (satiety hormone). Hypothalamus regulates hunger/fullness signals"},{"term":"Satiety","def":"Feeling of fullness that signals to stop eating","breakdown":"Protein and fiber are most satiating. Hormones: leptin (satiety), CCK (fullness after eating). Eat slowly to allow satiety signals to develop"},{"term":"Food diary","def":"Record of everything eaten and drunk — used to track intake and identify patterns","breakdown":"Research shows food diaries improve dietary compliance. Apps make tracking easier. Increases awareness of actual intake vs perceived"},{"term":"Fad diet","def":"Popular weight-loss plan promising quick results — often restricts food groups","breakdown":"Examples: keto, juice cleanses, detox diets. Usually lack scientific support. Weight often regained. Focus on sustainable changes instead"},{"term":"Sports nutrition","def":"Field of nutrition focused on optimizing athletic performance through diet","breakdown":"Carbs: primary fuel for exercise. Protein: muscle repair (1.2-2g/kg). Hydration critical. Timing: eat carbs before, protein after exercise"},{"term":"Food preparation methods","def":"Ways food is cooked that affect nutrient content — baking, boiling, steaming, grilling","breakdown":"Boiling: water-soluble vitamins leach out. Steaming: preserves more nutrients. High heat: destroys some vitamins. Raw: maximum vitamins"},{"term":"Nutrient absorption","def":"Process of nutrients moving from digestive tract into bloodstream","breakdown":"Small intestine: primary absorption site. Fat with fat-soluble vitamins improves absorption. Vitamin C enhances iron absorption"},{"term":"Digestion","def":"Mechanical and chemical breakdown of food into nutrients the body can absorb","breakdown":"Mouth: chewing + amylase (starch). Stomach: acid + pepsin (protein). Small intestine: most digestion/absorption. Large intestine: water"},{"term":"Gut microbiome","def":"Trillions of microorganisms in digestive tract that affect health and digestion","breakdown":"Supports immunity, vitamin production, digestion. Promoted by prebiotics, probiotics, fiber. Disrupted by antibiotics, poor diet"},{"term":"Dietary fat absorption","def":"Fats absorbed in small intestine with bile salts — transported via lymphatic system","breakdown":"Fat-soluble vitamins (A,D,E,K) absorbed with fat. Chylomicrons carry fat through lymph then blood. Liver processes fats"},{"term":"Functional food","def":"Food with health benefits beyond basic nutrition","breakdown":"Examples: oats (lower cholesterol), yogurt (probiotics), fatty fish (omega-3). Some are naturally functional; others have added nutrients"},{"term":"Nutritional epidemiology","def":"Study of diet's relationship to disease in populations","breakdown":"Types: cohort studies, case-control, randomized trials. Confounding factors are challenge. Food frequency questionnaires used. Long-term studies"},{"term":"Food system","def":"All activities involved in growing, processing, distributing, and consuming food","breakdown":"Includes: farming, processing, packaging, transport, retail, consumption, waste. Each step affects nutrition, environment, economics"},{"term":"Agricultural practices","def":"Methods used to grow food — affects nutritional quality, environment, and food safety","breakdown":"Conventional: pesticides, monocultures. Organic: no synthetic pesticides. Regenerative: soil health focus. All feed the world differently"},{"term":"Food additives","def":"Substances added to food to preserve, color, flavor, or texturize","breakdown":"FDA GRAS (Generally Recognized As Safe) list. Examples: salt, sugar, ascorbic acid, artificial colors. Some controversial (BHA, nitrates)"},{"term":"Food safety","def":"Practices that prevent foodborne illness — proper storage, cooking, handling","breakdown":"'Danger zone': 40-140°F bacteria multiply rapidly. Cook to safe temps: chicken 165°F, beef 160°F, fish 145°F. Refrigerate within 2 hours"},{"term":"Foodborne illness","def":"Illness from consuming contaminated food or beverages","breakdown":"Common pathogens: Salmonella, E. coli, Listeria, Norovirus. Prevention: handwashing, proper cooking, refrigeration, avoiding cross-contamination"},{"term":"Cross-contamination","def":"Transfer of harmful bacteria from one food or surface to another","breakdown":"Raw meat juices onto vegetables is most common. Prevent: separate cutting boards, wash hands, store raw meat on bottom shelf of fridge"},{"term":"Pasteurization","def":"Heat treatment that kills harmful pathogens in food without significantly affecting quality","breakdown":"Named after Louis Pasteur. Used for milk, juice, eggs. Ultra-pasteurized has longer shelf life. Required for commercial dairy"},{"term":"Organic food","def":"Food produced without synthetic pesticides, fertilizers, antibiotics, or GMOs","breakdown":"USDA certified organic. Not necessarily more nutritious. May have lower pesticide residues. Higher cost. Environmental benefits debated"},{"term":"GMO (Genetically Modified Organism)","def":"Organism with DNA altered using genetic engineering","breakdown":"Examples: Bt corn, Roundup Ready soybeans, Golden Rice. FDA deems safe. Controversial: environment, corporate control, labeling"},{"term":"Nutrition label reading","def":"Understanding how to interpret the Nutrition Facts panel on packaged foods","breakdown":"Check: serving size, total calories, % DV. Limit: saturated fat, trans fat, sodium, added sugars. Get enough: fiber, vitamins, minerals"},{"term":"Dietary supplement","def":"Product taken to supplement diet — vitamins, minerals, herbs, or other substances","breakdown":"FDA does not regulate for safety/efficacy before sale. Supplements don't replace balanced diet. Some can interact with medications"},{"term":"Fortification","def":"Adding nutrients to food to prevent deficiency — iodine in salt, vitamin D in milk","breakdown":"Mandatory fortification: folic acid in grains, iodine in salt. Voluntary: many breakfast cereals. Different from enrichment (replacing lost nutrients)"},{"term":"Enrichment","def":"Adding back nutrients lost during food processing","breakdown":"Example: white flour enriched with B vitamins and iron lost in milling. Required by law for refined grains sold in US"},{"term":"Energy balance","def":"Relationship between calories consumed and calories burned","breakdown":"Positive balance: more in than out → weight gain. Negative: more out than in → weight loss. Neutral: maintain weight. Not just calories"},{"term":"Thermoregulation","def":"Body's ability to maintain core temperature — requires adequate nutrition and hydration","breakdown":"Water and electrolytes critical for sweating (cooling). Inadequate intake → heat exhaustion or heat stroke. Nutrition affects performance in heat"},{"term":"Vegetarian diet","def":"Diet excluding meat — may include dairy and eggs depending on type","breakdown":"Lacto-ovo: includes dairy+eggs. Lacto: dairy only. Ovo: eggs only. Vegan: no animal products. Well-planned vegetarian diets are healthy"},{"term":"Vegan diet","def":"Diet excluding all animal products — no meat, dairy, eggs, or honey","breakdown":"Nutrients to watch: B12, iron, calcium, zinc, omega-3, vitamin D. Well-planned vegan diet is healthy for all life stages per AND"},{"term":"Infant nutrition","def":"Nutritional needs of babies 0-12 months — breast milk or formula is primary food","breakdown":"Breast milk: ideal nutrition + antibodies + bonding. Formula: safe alternative. Solid foods: introduce around 6 months. No honey <1 year"},{"term":"Childhood nutrition","def":"Dietary needs during growth and development — ages 1-12","breakdown":"Higher needs per kg for protein, calcium, iron during growth. Establish healthy habits early. Limit sugar, sodium, processed foods"},{"term":"Adolescent nutrition","def":"Nutritional needs during puberty — increased requirements for calcium, iron, protein","breakdown":"Girls: iron needs increase with menstruation. Boys and girls: calcium peak bone mass 18-25. Calorie needs highest during growth spurts"},{"term":"Geriatric nutrition","def":"Nutritional considerations for older adults — absorption decreases, needs shift","breakdown":"Decreased: calories, B12 absorption, calcium absorption. Increased: protein needs (prevent sarcopenia), vitamin D, calcium. Hydration critical"},{"term":"Food culture","def":"Traditions, beliefs, and practices around food that vary by culture and community","breakdown":"Influences food choices, preparation methods, meal timing. Cultural competency in nutrition counseling improves outcomes"},{"term":"Eating disorder","def":"Mental health condition characterized by disturbed eating behaviors","breakdown":"Anorexia: restricted intake, fear of weight gain. Bulimia: binge-purge cycles. Binge eating: uncontrolled eating. Require professional treatment"},{"term":"Disordered eating","def":"Irregular eating patterns that don't meet criteria for eating disorder but still affect health","breakdown":"Skipping meals, chronic dieting, food guilt, compensatory behaviors. Can develop into eating disorder. Common in teens and athletes"},{"term":"Intuitive eating","def":"Framework encouraging eating based on hunger and fullness cues, not rules or emotions","breakdown":"10 principles include: reject diet mentality, honor hunger, make peace with food, respect body. Positive relationship with food"},{"term":"Mindful eating","def":"Paying attention to the eating experience — slowing down, reducing distractions","breakdown":"Benefits: improved satiety recognition, portion control, enjoyment. Reduces emotional eating. Eat without screens, chew thoroughly"},{"term":"Nutrition assessment","def":"Evaluation of nutritional status using dietary, biochemical, clinical, and anthropometric data","breakdown":"ABCD method: Anthropometric (height, weight), Biochemical (lab tests), Clinical (physical signs), Dietary (food intake analysis)"},{"term":"Food frequency questionnaire","def":"Survey tool asking how often specific foods are eaten over a time period","breakdown":"Used in nutrition research and assessment. Captures usual intake over weeks/months. Less accurate than food diary but easier to complete"},{"term":"24-hour dietary recall","def":"Nutrition assessment method where person recalls all food consumed in past 24 hours","breakdown":"Used by NHANES. Quick and inexpensive. Limitation: doesn't capture usual intake (one day may be atypical). Multiple recalls more accurate"},{"term":"Registered Dietitian Nutritionist (RDN)","def":"Healthcare professional with specialized training in nutrition and dietetics","breakdown":"Requires: bachelor's degree, supervised practice, national exam. Can diagnose nutrition problems, provide medical nutrition therapy, counsel patients"},{"term":"Medical nutrition therapy","def":"Use of specific nutrition interventions to treat medical conditions","breakdown":"Examples: diabetic meal planning, renal diet for kidney disease, low-sodium for hypertension. Requires RDN. Insurance may cover"},{"term":"Enteral nutrition","def":"Delivery of liquid nutrients directly into the GI tract via tube when oral intake is inadequate","breakdown":"NG tube (nose to stomach), G-tube (stomach), J-tube (jejunum). Used when GI tract functional but person can't eat enough"},{"term":"Parenteral nutrition","def":"Intravenous delivery of nutrients when GI tract cannot be used","breakdown":"Total parenteral nutrition (TPN): all nutrients via IV. Used for: bowel obstruction, Crohn's, post-surgery. Risk: infection, metabolic complications"},{"term":"Hunger vs appetite differences","def":"Hunger: physical need for food. Appetite: psychological desire for food — driven by sight, smell, emotions","breakdown":"Hunger: physical signals (growling stomach, low energy, irritability). Appetite: external cues. Emotional eating uses food to manage feelings"},{"term":"Macronutrient ratios","def":"Proportion of calories from carbohydrates, protein, and fat in the diet","breakdown":"AMDR: carbs 45-65%, fat 20-35%, protein 10-35%. Keto: very low carb. Zone diet: 40-30-30. Evidence supports ranges, not one perfect ratio"},{"term":"Weight management","def":"Strategies to achieve and maintain a healthy body weight","breakdown":"Sustainable approach: modest calorie reduction, regular physical activity, behavior change. Crash dieting ineffective long-term. Focus on habits"},{"term":"Caloric density","def":"The number of calories per gram of food — high caloric density foods pack many calories in small portions","breakdown":"Oils and nuts: ~9 cal/g. Vegetables: ~0.2 cal/g. Understanding caloric density helps with portion control and weight management"},{"term":"Hidden sugars","def":"Added sugars in processed foods not obviously sweet — ketchup, bread, salad dressing, yogurt","breakdown":"Look for: high-fructose corn syrup, sucrose, dextrose, maltose on ingredients list. Average American consumes 17 tsp added sugar daily vs recommended 6-9 tsp"},{"term":"Protein complementation","def":"Combining two incomplete plant proteins to get all essential amino acids — beans + rice, hummus + pita","breakdown":"Plant proteins are 'incomplete' missing some essential amino acids. Complementary proteins don't need to be eaten at the same meal — just throughout the day"},{"term":"Nutrient absorption factors","def":"Factors affecting how well nutrients are absorbed: cooking method, food combinations, gut health, age","breakdown":"Vitamin C increases iron absorption. Fat helps absorb fat-soluble vitamins. Tannins in tea reduce iron absorption. Cooking breaks cell walls improving many nutrient absorptions"},{"term":"USDA Dietary Guidelines","def":"Federal nutrition recommendations updated every 5 years — current 2020-2025 guidelines emphasize variety, nutrient-dense foods, limiting added sugars and sodium","breakdown":"Key recommendations: half plate fruits/veggies, vary protein sources, choose whole grains, limit saturated fat <10% calories, sodium <2300mg/day"},{"term":"Saturated fat sources","def":"Animal products (meat, dairy, butter), coconut oil, palm oil — solid at room temperature","breakdown":"American Heart Association: limit to <6% of daily calories. Raises LDL cholesterol. Choose lean meats, low-fat dairy, plant oils to reduce intake"},{"term":"Unsaturated fat benefits","def":"Mono and polyunsaturated fats improve cholesterol levels and reduce heart disease risk","breakdown":"Monounsaturated: olive oil, avocado, nuts. Polyunsaturated: fish oil, flaxseed, walnuts. Replace saturated and trans fats with these to improve heart health"},{"term":"Cholesterol in food","def":"Dietary cholesterol found only in animal products — liver, egg yolks, shellfish, meat","breakdown":"Body makes its own cholesterol. Dietary cholesterol has less effect on blood cholesterol than saturated/trans fat. Current guidelines removed specific dietary cholesterol limit"},{"term":"Plant-based protein sources","def":"Legumes, tofu, tempeh, seitan, nuts, seeds, quinoa — generally lower in saturated fat than animal protein","breakdown":"Quinoa and soy are complete proteins. Most plant proteins incomplete — require complementation. Benefits: fiber, lower saturated fat, environmental sustainability"},{"term":"Food processing levels","def":"Minimal (fresh produce) → Moderately processed (canned beans, frozen vegetables) → Ultra-processed (chips, candy, fast food)","breakdown":"NOVA classification system. Ultra-processed foods linked to obesity, diabetes, cardiovascular disease. Minimally processed foods retain more nutrients and fiber"},{"term":"Sodium (salt) in diet","def":"Essential electrolyte — but most Americans consume 3400mg/day vs recommended 2300mg/day limit","breakdown":"High sodium raises blood pressure in sodium-sensitive individuals. 70% of sodium comes from processed/restaurant foods, not the salt shaker. DASH diet reduces sodium"},{"term":"Hidden sodium","def":"Sodium in foods that don't taste salty — bread, cheese, canned soups, deli meats, cottage cheese","breakdown":"Bread is the #1 source of sodium for Americans. Read labels: >20% DV sodium is high. Choose low-sodium versions when available"},{"term":"Potassium-rich foods","def":"Bananas, potatoes, beans, leafy greens, avocado, yogurt — counteract sodium's blood pressure effect","breakdown":"Most Americans don't get enough potassium (AI: 2600-3400mg). Potassium helps kidneys excrete sodium. DASH diet emphasizes potassium-rich foods"},{"term":"Calcium-rich foods","def":"Dairy, fortified plant milks, sardines (with bones), leafy greens (kale, bok choy), tofu made with calcium","breakdown":"Teens and young adults need most calcium (1300mg/day) for peak bone mass. Spinach and Swiss chard have calcium but oxalates reduce absorption"},{"term":"Iron-rich foods","def":"Heme iron: red meat, poultry, fish. Non-heme iron: beans, lentils, fortified cereals, spinach, tofu","breakdown":"Heme iron (animal) absorbed 15-35%. Non-heme iron (plant) 2-20% — enhanced by vitamin C. Inhibited by calcium, tea, coffee. Women need more iron (18mg vs 8mg for men)"},{"term":"Vitamin B12 sources","def":"Found ONLY in animal products — meat, fish, dairy, eggs. Vegans must supplement","breakdown":"B12 deficiency causes irreversible nerve damage. All vegans need B12 supplement (2.4mcg/day). Fortified nutritional yeast is a plant source. Older adults absorb less B12"},{"term":"Zinc food sources","def":"Oysters (highest), red meat, poultry, beans, nuts, seeds, fortified cereals","breakdown":"Vegetarians may need 50% more zinc because plant phytates inhibit absorption. Zinc critical for immune function, wound healing, taste and smell"},{"term":"Folate food sources","def":"Dark leafy greens, legumes, fortified grains, oranges, liver — critical for cell division","breakdown":"Folic acid (synthetic) better absorbed than natural folate. ALL women of childbearing age need 400mcg folic acid daily to prevent neural tube defects"},{"term":"Omega-3 food sources","def":"Fatty fish (salmon, mackerel, sardines), flaxseed, chia seeds, walnuts, hemp seeds","breakdown":"EPA and DHA (fish): directly usable by body. ALA (plant): must convert to EPA/DHA (only 5-10% conversion). Aim for 2 servings fatty fish per week"},{"term":"Fiber food sources","def":"Vegetables, fruits, whole grains, legumes, nuts, seeds — plant foods only","breakdown":"Soluble fiber (oats, beans): lowers cholesterol, slows glucose absorption. Insoluble fiber (wheat bran): adds bulk, promotes regularity. Adults need 25-38g/day"},{"term":"Vitamin K functions","def":"Blood clotting (K1: phylloquinone) and bone metabolism (K2: menaquinone)","breakdown":"K1 from leafy greens. K2 from fermented foods, some animal products. Warfarin (blood thinner) works by blocking vitamin K. Maintain consistent K intake on warfarin"},{"term":"Magnesium functions","def":"300+ enzyme reactions, muscle and nerve function, blood glucose control, blood pressure regulation","breakdown":"Deficiency common (50% of Americans). Sources: dark chocolate, avocado, nuts, legumes, whole grains. Helps with sleep, stress, and migraine prevention"},{"term":"Iron deficiency symptoms","def":"Fatigue, weakness, pale skin, cold hands/feet, brittle nails, pica (craving non-food items)","breakdown":"World's most common nutrient deficiency. Women, children, athletes most at risk. Ferritin blood test detects early deficiency before anemia develops"},{"term":"Calcium deficiency effects","def":"Osteopenia → osteoporosis, muscle cramps, dental problems, increased fracture risk","breakdown":"Body takes calcium from bones when dietary intake is low. Peak bone mass achieved by age 30 — critical to build it now. 1000-1200mg calcium/day recommended for adults"},{"term":"Potassium deficiency (hypokalemia)","def":"Muscle weakness, fatigue, constipation, heart arrhythmias — serum K+ below 3.5 mEq/L","breakdown":"Causes: poor diet, excessive sweating, diarrhea, diuretic medications. Heart arrhythmias can be life-threatening. Eat potassium-rich foods daily"},{"term":"Zinc deficiency symptoms","def":"Poor wound healing, loss of taste/smell, immune impairment, growth retardation, hair loss","breakdown":"Common in developing countries and elderly. Also: delayed sexual maturation in adolescents. Diagnosis: plasma zinc levels. Treatment: zinc supplementation and zinc-rich foods"},{"term":"Iodine deficiency effects","def":"Goiter (enlarged thyroid), hypothyroidism, cretinism (severe developmental disability in infants if mother deficient)","breakdown":"Iodized salt introduced 1920s eliminated goiter in US. Still a problem globally. Pregnant women need 220mcg iodine. Seafood and dairy are good sources"},{"term":"Vitamin B12 deficiency","def":"Megaloblastic anemia, peripheral neuropathy, cognitive decline — often seen in vegans and elderly","breakdown":"Requires intrinsic factor for absorption — elderly lose this → pernicious anemia. Irreversible nerve damage if untreated. Serum B12 or methylmalonic acid blood tests used"},{"term":"Niacin (B3) deficiency","def":"Pellagra: 4 Ds — Dermatitis, Diarrhea, Dementia, Death — rare in developed countries","breakdown":"Caused by corn-only diets (niacin bound in corn is unavailable). Nixtamalization (lime-soaking corn) releases niacin. High-dose niacin used to treat high triglycerides"},{"term":"Folate deficiency effects","def":"Megaloblastic anemia, neural tube defects in pregnancy (spina bifida, anencephaly)","breakdown":"Critical in first 28 days of pregnancy — before most women know they're pregnant. Why folic acid is added to all enriched grains. Men also benefit from folate for DNA integrity"},{"term":"Phosphorus in diet","def":"Second most abundant mineral in body — bones, teeth, energy production (ATP), cell membranes","breakdown":"Found in most protein-rich foods. Deficiency rare. Excess common in kidney disease (must restrict). Phosphoric acid in sodas reduces bone density over time"},{"term":"Selenium functions","def":"Antioxidant (part of glutathione peroxidase), thyroid hormone metabolism, immune function","breakdown":"Brazil nuts: 1 nut = 96mcg (RDA is 55mcg). Deficiency: Keshan disease (heart disease in China). Toxicity (selenosis) from excess supplements: hair loss, nail brittleness"},{"term":"Food safety temperature danger zone","def":"40°F to 140°F (4°C to 60°C) — bacteria multiply rapidly, doubling every 20 minutes","breakdown":"Two-hour rule: don't leave food at room temperature over 2 hours (1 hour if >90°F). Refrigerator: ≤40°F. Freezer: 0°F. Cook to safe internal temperatures"},{"term":"Safe cooking temperatures","def":"Poultry: 165°F. Ground meat: 160°F. Whole cuts: 145°F. Fish: 145°F. Eggs: 160°F","breakdown":"Use food thermometer — color is NOT reliable. USDA recommends 3-minute rest time for whole cuts after reaching temperature. Leftovers: reheat to 165°F"},{"term":"Foodborne illness risk foods","def":"Raw/undercooked meat, poultry, eggs, seafood; unpasteurized dairy; unwashed produce; deli meats","breakdown":"High risk groups: pregnant, elderly, young children, immunocompromised. Most common pathogens: Salmonella, E. coli O157, Listeria, Campylobacter, Norovirus"},{"term":"Carbohydrate counting","def":"Method for managing blood glucose — tracking grams of carbohydrate per meal","breakdown":"Used in diabetes management. 1 serving carb = 15g. Most adults with diabetes: 45-60g carb per meal. Counting total carbs more important than type"},{"term":"Glycemic load","def":"Glycemic index × grams of carbohydrate ÷ 100 — considers both quality and quantity of carbs","breakdown":"More practical than GI alone. Watermelon has high GI but low glycemic load (small actual carb amount). Low GL: <10. Medium: 11-19. High: ≥20"},{"term":"Nutrition during pregnancy","def":"Increased needs: folate (+400mcg), iron (+9mg), calcium, iodine, omega-3 DHA — avoid alcohol, limit caffeine, avoid raw seafood","breakdown":"Weight gain: 25-35 lbs for normal weight. First trimester: +0 calories. Second: +340 calories. Third: +452 calories. Morning sickness: small frequent meals, bland foods, ginger"},{"term":"Breastfeeding nutrition","def":"Increases calorie needs by ~500 calories/day — continue prenatal vitamins, increase fluid intake, vitamin D supplement for infant","breakdown":"Breast milk provides perfect infant nutrition first 6 months. Maternal diet affects milk flavor. Caffeine passes to milk. Alcohol: wait 2-3 hours after drinking before nursing"},{"term":"Infant nutrition milestones","def":"0-6 months: breast milk or formula only. 6 months: introduce solid foods. 12 months: whole cow's milk. 1-2 years: family foods","breakdown":"Never give honey under 1 year (botulism risk). Introduce allergens early (4-11 months) reduces allergy risk. Iron-rich foods critical at 6 months — breast milk iron depletes"},{"term":"Childhood nutrition needs","def":"Growing children need adequate calcium (bone growth), iron (brain development), vitamin D, and sufficient calories for activity","breakdown":"Picky eating is normal developmental phase. Repeated exposure (10-15 times) increases food acceptance. Family meals associated with better dietary patterns in kids"},{"term":"Geriatric nutrition challenges","def":"Decreased appetite, reduced absorption (B12, D, calcium), medication-nutrient interactions, risk of malnutrition","breakdown":"Protein needs increase (1.0-1.2g/kg vs 0.8g/kg for adults) to prevent sarcopenia. Chewing difficulties affect food choices. Dehydration risk increases (reduced thirst sensation)"},{"term":"Mediterranean diet components","def":"High: olive oil, vegetables, fruits, whole grains, legumes, nuts, fish. Moderate: poultry, eggs, dairy, wine. Low: red meat, sweets","breakdown":"Most researched dietary pattern. Reduces cardiovascular disease, dementia, diabetes. No calorie counting — focus on food quality and pattern, not individual foods"},{"term":"DASH diet specifics","def":"8-10 servings fruits/vegetables, low-fat dairy, whole grains, lean protein, limit sodium to 1500-2300mg","breakdown":"Dietary Approaches to Stop Hypertension. Reduces systolic BP by 8-14 mmHg. As effective as medications for mild hypertension. Rich in potassium, magnesium, calcium"},{"term":"Vegetarian diet types","def":"Lacto-ovo: includes dairy and eggs. Lacto: dairy only. Ovo: eggs only. Vegan: no animal products at all","breakdown":"Well-planned vegetarian diets healthy for all life stages. Key nutrients to monitor: B12, vitamin D, calcium, iron, zinc, omega-3s, and iodine (vegans)"},{"term":"Food labeling requirements","def":"FDA requires: serving size, calories, total fat, saturated fat, trans fat, cholesterol, sodium, carbs, fiber, sugars, added sugars, protein, key vitamins/minerals","breakdown":"2016 updated label: added sugars now listed separately. Removed 'calories from fat.' Vitamin D and potassium added. Larger serving size font. Based on 2000-calorie diet"},{"term":"Organic food standards","def":"USDA Organic: no synthetic pesticides, fertilizers, GMOs, antibiotics, or growth hormones","breakdown":"100% organic: all organic ingredients. Organic: 95%+ organic. Made with organic: 70%+. Studies show minimal nutritional difference vs conventional — mainly a pesticide exposure choice"},{"term":"GMO foods","def":"Genetically Modified Organisms — crops modified to resist pests, disease, drought, or enhance nutrition","breakdown":"Over 90% of US soybeans, corn, cotton, canola are GMO. Golden Rice: GMO with beta-carotene added. FDA considers currently approved GMOs safe. Require labeling in US since 2022"},{"term":"Dietary supplement regulation","def":"FDA regulates supplements as food, not drugs — manufacturers don't need to prove safety or efficacy before selling","breakdown":"Third-party testing seals (USP, NSF, ConsumerLab) indicate verified contents. Supplements can interact with medications. Always inform healthcare provider of all supplements"},{"term":"Sports nutrition basics","def":"Performance nutrition: adequate carbs for fuel, protein for muscle repair, hydration, and proper timing","breakdown":"Carb loading before endurance events increases glycogen stores. Protein immediately post-workout maximizes muscle protein synthesis. Electrolytes replace sweat losses"},{"term":"Hydration guidelines","def":"Men: ~3.7L total water/day. Women: ~2.7L. Includes all beverages and food moisture (about 20% from food)","breakdown":"Thirst is late indicator of dehydration. Urine color guide: pale yellow = well hydrated. Dark yellow/amber = dehydrated. Coffee and tea count toward fluid intake"},{"term":"Energy drinks health effects","def":"High caffeine + stimulants — associated with cardiovascular events, especially in young people and when combined with alcohol","breakdown":"AAP recommends children and adolescents avoid energy drinks. Caffeine content: 80-300mg vs 95mg coffee. Mixing with alcohol masks intoxication — very dangerous"},{"term":"Intuitive eating principles","def":"10 principles including reject diet mentality, honor hunger, make peace with food, respect fullness, body acceptance","breakdown":"Evidence-based approach associated with better psychological health, lower BMI, reduced disordered eating. Opposite of restrictive dieting. Focuses on internal cues not external rules"},{"term":"Food security definition","def":"Physical, social, and economic access to sufficient, safe, and nutritious food for an active and healthy life — all four dimensions","breakdown":"Four pillars: availability, access, utilization, stability. 10-15% of US households food insecure. Disproportionately affects low-income, minority, and rural populations"},{"term":"Nutrition screening tools","def":"Malnutrition screening: MNA (elderly), MUST, MST — identify nutrition risk in clinical settings","breakdown":"Joint Commission requires nutrition screening within 24 hours of hospital admission. Screened for weight loss, decreased intake, BMI. Dietitian performs full assessment if at risk"},{"term":"Meal planning principles","def":"Balance macronutrients, include variety of colors, plan ahead to reduce impulse eating, batch cook for efficiency","breakdown":"Half plate vegetables/fruit, quarter protein, quarter whole grains, small amount healthy fat. Planning reduces food waste and saves money. Grocery list based on planned meals"},{"term":"Reading ingredients list","def":"Ingredients listed in order of weight — first ingredient is present in greatest amount","breakdown":"If sugar appears in first 3 ingredients, it's a high-sugar food. Long ingredients list with unrecognizable ingredients = highly processed. Whole foods have 1-ingredient lists"},{"term":"Cultural nutrition considerations","def":"Dietary patterns reflect culture, religion, tradition — halal, kosher, Hindu vegetarianism, fasting practices are examples","breakdown":"Culturally competent nutrition care respects food traditions. Cultural foods often have nutritional benefits. Work within food preferences rather than imposing Western diet ideals"},{"term":"Eating disorder warning signs","def":"Extreme food restriction, purging, excessive exercise, preoccupation with weight, distorted body image","breakdown":"Anorexia: lowest mortality of any psychiatric illness... false. Actually highest mortality rate. Early intervention critical. Screen with SCOFF questionnaire. Refer to multidisciplinary team"},{"term":"Mindful eating practice","def":"Paying full attention to eating experience — slowing down, eliminating distractions, noticing hunger and satiety cues","breakdown":"Reduces overeating and emotional eating. Takes 20 minutes for satiety signals to reach brain — slowing down allows recognition. Eat without screens to reduce unconscious overeating"},{"term":"Food budgeting and nutrition","def":"Nutrient-dense affordable foods: eggs, beans, lentils, canned fish, frozen vegetables, whole grains, peanut butter","breakdown":"Protein cost per serving: eggs (<$0.25), beans (<$0.15), canned tuna (~$0.50). Frozen vegetables as nutritious as fresh. Buying in bulk and seasonal foods reduces cost"},{"term":"MyPlate food groups","def":"Five groups: Fruits, Vegetables, Grains, Protein Foods, Dairy — each providing different key nutrients","breakdown":"Replaced Food Pyramid in 2011. Key message: half plate fruits and vegetables. Vary protein sources. Make half grains whole grains. Move to low-fat/fat-free dairy"},{"term":"Carbohydrate types comparison","def":"Simple: sugars (quick energy, spike glucose). Complex: starches and fiber (slower digestion, steadier glucose)","breakdown":"Not all simple carbs are bad (fruit). Not all complex carbs are healthy (refined white flour). Focus on fiber content and whole food form rather than simple vs complex label"},{"term":"Protein digestion process","def":"Begins in stomach (pepsin breaks peptide bonds) → small intestine (pancreatic proteases) → absorbed as amino acids or di/tripeptides","breakdown":"Complete digestion takes 3-4 hours. Protein quality affects digestion completeness. Gastric acid essential — proton pump inhibitors can affect protein digestion and B12 absorption"},{"term":"Fat digestion process","def":"Emulsified by bile (liver/gallbladder) → broken down by lipase → absorbed as fatty acids and glycerol → reformed into chylomicrons","breakdown":"Fat digestion primarily in small intestine. Takes longest to digest (4-5 hours) — contributes to satiety. Fat-soluble vitamins absorbed alongside dietary fat"},{"term":"Carbohydrate digestion process","def":"Begins in mouth (salivary amylase) → stomach (activity stops at low pH) → small intestine (pancreatic amylase, brush border enzymes)","breakdown":"Glucose absorbed within 1-2 hours. Fiber not digested — fermented by gut bacteria. Lactase enzyme digests lactose — absent → lactose intolerance"}]);
  fc.medium=fc.medium.concat([{"term":"Anemia types in nutrition","def":"Iron-deficiency anemia (most common), B12/folate (megaloblastic), vitamin C deficiency anemia","breakdown":"Iron: microcytic small RBCs. B12/folate: macrocytic large RBCs. All reduce oxygen-carrying capacity"},{"term":"Folate/Folic acid","def":"B vitamin critical for DNA synthesis and cell division — prevents neural tube defects in pregnancy","breakdown":"Folate = natural form (leafy greens, beans). Folic acid = synthetic (supplements, fortified foods). 400mcg/day recommended; 600mcg pregnant"},{"term":"Vitamin B12","def":"B vitamin for nerve function, DNA synthesis, red blood cell formation — only in animal foods","breakdown":"Vegans must supplement. Deficiency causes pernicious anemia and nerve damage. Stored in liver (3-5 year supply)"},{"term":"Thiamin (B1)","def":"B vitamin for carbohydrate metabolism and nerve function","breakdown":"Deficiency causes beriberi (wet: heart failure; dry: nerve damage). Wernicke-Korsakoff syndrome in alcoholics"},{"term":"Niacin (B3)","def":"B vitamin for energy metabolism — too much causes flushing","breakdown":"Deficiency causes pellagra: Dermatitis, Diarrhea, Dementia, Death (the 4 D's)"},{"term":"Zinc functions","def":"Immune function, wound healing, protein synthesis, taste/smell, DNA synthesis","breakdown":"Oysters highest zinc content. Red meat, poultry, beans, nuts. Deficiency: impaired growth, taste loss, poor wound healing"},{"term":"Iodine functions","def":"Thyroid hormone synthesis — regulates metabolism, growth, brain development","breakdown":"Iodized salt solved endemic goiter (enlarged thyroid). Deficiency during pregnancy causes cretinism (intellectual disability)"},{"term":"Phytochemicals","def":"Non-nutrient plant compounds with health benefits — not essential but protective","breakdown":"Lycopene (tomatoes), flavonoids (berries), glucosinolates (broccoli), resveratrol (red wine). Disease prevention, not just treatment"},{"term":"Probiotics","def":"Live beneficial microorganisms that colonize the gut — improve digestive and immune health","breakdown":"Lactobacillus and Bifidobacterium common strains. Found in yogurt, kefir, kimchi, sauerkraut. Restore gut flora after antibiotics"},{"term":"Prebiotics","def":"Non-digestible food components that feed beneficial gut bacteria","breakdown":"Inulin, FOS (fructooligosaccharides). Found in garlic, onions, bananas, asparagus. Distinct from probiotics"},{"term":"Top 9 food allergens","def":"Milk, Eggs, Fish, Shellfish, Tree nuts, Peanuts, Wheat, Soybeans, Sesame","breakdown":"Required on U.S. food labels since FALCPA (2004). Sesame added as 9th in 2023. Together cause 90% of food allergic reactions"},{"term":"Insulin function in nutrition","def":"Pancreatic hormone that allows cells to take up glucose from blood — lowers blood sugar","breakdown":"Released after meals. Signals cells to absorb glucose. Also promotes fat and protein storage. Absence/resistance = diabetes"},{"term":"Glucagon function","def":"Pancreatic hormone that raises blood glucose by stimulating glycogen breakdown and gluconeogenesis","breakdown":"Released when blood glucose falls (fasting, exercise). Counter-regulatory to insulin. Used as emergency treatment for severe hypoglycemia"},{"term":"Dietary Reference Intakes (DRI)","def":"Framework of nutrient intake standards including RDA, AI, UL, and EAR","breakdown":"RDA: meets needs of 97% of healthy people. AI: adequate intake when RDA unknown. UL: highest daily intake unlikely to cause harm"},{"term":"Energy balance equation","def":"Weight change = Energy in (food) - Energy out (BMR + activity + thermic effect)","breakdown":"Positive balance = weight gain. Negative balance = weight loss. 3500 kcal deficit ≈ 1 lb fat loss (approximate and contested)"},{"term":"Hypertension and diet","def":"DASH diet reduces blood pressure: low sodium, high potassium, calcium, magnesium","breakdown":"DASH = Dietary Approaches to Stop Hypertension. Emphasizes fruits, vegetables, low-fat dairy, whole grains. Limit sodium to 1500-2300mg"},{"term":"Mediterranean diet","def":"Plant-based diet with olive oil, fish, whole grains, legumes, moderate wine — linked to longevity","breakdown":"Consistently ranked top diet by research. Reduces cardiovascular disease, type 2 diabetes, cognitive decline. UNESCO intangible heritage"},{"term":"Food security","def":"All people at all times have access to sufficient, safe, and nutritious food","breakdown":"4 dimensions: Availability, Access, Utilization, Stability. Food insecurity affects 800M globally, 30M+ in U.S."},{"term":"Hunger vs appetite","def":"Hunger: physiological need for food. Appetite: psychological desire for food","breakdown":"Hunger = ghrelin (stomach hormone). Appetite influenced by senses, emotions, habits. Leptin signals satiety to brain"},{"term":"Protein quality (PDCAAS)","def":"Protein Digestibility Corrected Amino Acid Score — measures protein quality based on amino acid profile and digestibility","breakdown":"Scale 0-1. Score of 1: casein, egg white, soy. Meat and fish ~0.9. Grains lower. Determines how well protein meets human needs"},{"term":"Net protein utilization","def":"Measure of how much protein from food is actually retained and used by the body","breakdown":"Considers both protein quality and digestibility. Egg has highest NPU (~94%). Used alongside PDCAAS to evaluate protein foods"},{"term":"Leucine threshold","def":"Minimum amount of leucine needed to maximally stimulate muscle protein synthesis","breakdown":"~2.5g leucine per meal. Found in ~25-30g high-quality protein. Animal proteins generally higher in leucine than plant proteins"},{"term":"Muscle protein synthesis","def":"Process of building new muscle proteins — stimulated by protein intake and resistance exercise","breakdown":"Requires adequate essential amino acids, especially leucine. Stimulated for ~3-4 hours after protein ingestion. Exercise increases sensitivity"},{"term":"Sarcopenia","def":"Age-related loss of muscle mass and strength — begins around age 30-35","breakdown":"Causes: decreased protein synthesis, hormonal changes, inactivity. Prevention: adequate protein (1.2-1.6g/kg), resistance exercise"},{"term":"Glycogen stores","def":"Glucose stored in liver and muscle — primary carbohydrate reserve for energy","breakdown":"Liver glycogen (~100g): maintains blood glucose. Muscle glycogen (~400g): fuel for exercise. Depleted after intense exercise or fasting"},{"term":"Fatty acid oxidation (beta-oxidation)","def":"Metabolic process breaking down fatty acids to produce ATP — occurs in mitochondria","breakdown":"Requires oxygen. Produces more ATP per gram than glucose. Primary fuel at rest and low-intensity exercise. Impaired in some metabolic disorders"},{"term":"Ketone bodies","def":"Alternative fuel produced from fat breakdown when carbohydrates are very low","breakdown":"Acetoacetate, beta-hydroxybutyrate, acetone. Brain uses ketones during fasting/low-carb. Excessive ketones = ketoacidosis (diabetic emergency)"},{"term":"Lipogenesis","def":"Synthesis of fat from excess carbohydrates or protein — occurs mainly in liver and adipose tissue","breakdown":"When calories exceed needs, excess glucose/amino acids converted to fat. Insulin promotes lipogenesis. Important in understanding weight gain"},{"term":"Adipokines","def":"Hormones secreted by adipose (fat) tissue — affect metabolism, inflammation, appetite","breakdown":"Leptin: reduces appetite (resistance in obesity). Adiponectin: improves insulin sensitivity (lower in obesity). TNF-alpha: promotes inflammation"},{"term":"Leptin","def":"Hormone from fat cells that signals satiety to brain — reduced appetite, increased energy expenditure","breakdown":"Leptin resistance in obese individuals: high levels but brain doesn't respond. Low-calorie diets reduce leptin, increase hunger. Sleep deprivation lowers leptin"},{"term":"Ghrelin","def":"'Hunger hormone' produced in stomach — stimulates appetite, increases before meals","breakdown":"Rises before meals, falls after eating. Increases with calorie restriction (makes dieting hard). Sleep deprivation raises ghrelin — increases hunger"},{"term":"Cholecystokinin (CCK)","def":"Hormone released from small intestine in response to protein and fat — signals fullness","breakdown":"Stimulates bile release (for fat digestion) and pancreatic enzymes. Reduces appetite. Protein and fat more satiating partly because of CCK"},{"term":"GLP-1 (Glucagon-like peptide-1)","def":"Incretin hormone from small intestine — enhances insulin release, slows gastric emptying, reduces appetite","breakdown":"Released after eating, especially carbs and fat. Basis for semaglutide (Ozempic/Wegovy) weight loss drugs. Reduces hunger and food intake"},{"term":"Insulin-like growth factor (IGF-1)","def":"Hormone stimulated by growth hormone — promotes muscle and bone growth, affected by dietary protein","breakdown":"Protein intake, especially dairy protein, increases IGF-1. Linked to muscle growth but also potentially cancer promotion. Research ongoing"},{"term":"Dietary cholesterol absorption","def":"About 50% of dietary cholesterol is absorbed — remainder excreted","breakdown":"Absorption varies by individual (hyper-responders vs hypo-responders). Dietary fiber reduces cholesterol absorption. Phytosterols compete with absorption"},{"term":"Bile recycling (enterohepatic circulation)","def":"Recycling of bile salts between liver and intestine — soluble fiber interrupts this, lowering cholesterol","breakdown":"Most bile salts reabsorbed in ileum and returned to liver. Soluble fiber binds bile, prevents reabsorption — liver must make more using blood cholesterol"},{"term":"Short-chain fatty acids (SCFAs)","def":"Fatty acids produced when gut bacteria ferment dietary fiber — acetate, propionate, butyrate","breakdown":"Butyrate: primary fuel for colon cells. Propionate: signals liver. Acetate: goes to muscles. Benefits: gut health, inflammation reduction, colon cancer prevention"},{"term":"Visceral fat vs subcutaneous fat","def":"Visceral: surrounds organs (dangerous). Subcutaneous: under skin (less dangerous)","breakdown":"Visceral fat more metabolically active, releases inflammatory substances. Measured by waist circumference. Associated with metabolic syndrome and heart disease"},{"term":"Adipose tissue","def":"Fat storage tissue — also an endocrine organ producing hormones","breakdown":"White adipose: energy storage. Brown adipose: thermogenesis (generates heat). Beige adipose: can convert to brown. Brown fat activated by cold, exercise"},{"term":"Non-alcoholic fatty liver disease (NAFLD)","def":"Excess fat in liver without alcohol use — associated with obesity and metabolic syndrome","breakdown":"Now called MASLD. Ranges from simple steatosis to NASH (inflammation) to cirrhosis. Prevention/treatment: weight loss, reduce sugar, exercise"},{"term":"Cardiovascular nutrition","def":"Dietary strategies to reduce heart disease risk","breakdown":"Reduce: saturated fat, trans fat, sodium, added sugars. Increase: fiber, omega-3, potassium, antioxidants. Mediterranean and DASH diets evidence-based"},{"term":"Cancer and nutrition","def":"Diet accounts for 30-35% of cancer risk — certain foods increase or decrease risk","breakdown":"Increase risk: processed meat, alcohol, obesity. Decrease risk: vegetables, fruits, fiber. No single food prevents cancer. Overall dietary pattern matters"},{"term":"Bone health nutrients","def":"Calcium, vitamin D, protein, and vitamin K essential for bone health — phosphorus and magnesium also important","breakdown":"Peak bone mass by age 25-30. Calcium + Vitamin D: bone mineral density. Vitamin K: activates bone proteins. Weight-bearing exercise also critical"},{"term":"Renal diet","def":"Diet modified for kidney disease — restricts phosphorus, potassium, sodium, and often protein","breakdown":"Damaged kidneys can't filter these minerals. Protein restriction reduces waste products. Individual needs vary by stage of disease. RDN needed"},{"term":"Celiac disease nutrition","def":"Strict gluten-free diet required — avoid wheat, rye, barley","breakdown":"Cross-contamination must be avoided. Nutrient deficiencies common at diagnosis: iron, calcium, B vitamins, zinc. Oats may be tolerated if uncontaminated"},{"term":"Iron deficiency anemia","def":"Most common nutritional deficiency worldwide — insufficient iron for hemoglobin production","breakdown":"Stages: depleted stores, iron-deficient erythropoiesis, anemia. Symptoms: fatigue, pale skin, shortness of breath. More common in women, athletes, vegans"},{"term":"Vitamin D deficiency","def":"Insufficient vitamin D — impairs calcium absorption, causes rickets in children, osteomalacia in adults","breakdown":"Risk factors: limited sun, dark skin, obesity, northern latitudes. 40% of Americans deficient. Supplementation (1000-2000 IU) often needed"},{"term":"Selenium","def":"Antioxidant trace mineral — part of selenoproteins involved in thyroid hormone metabolism","breakdown":"Deficiency: Keshan disease (heart), Kashin-Beck (joint disease). Brazil nuts highest source (1 nut = full day's selenium). Important for immune function"},{"term":"Chromium","def":"Trace mineral that enhances insulin action — helps regulate blood glucose","breakdown":"Found in broccoli, whole grains, meat, grape juice. Deficiency rare but may impair glucose tolerance. Supplement evidence mixed"},{"term":"Fluoride","def":"Mineral that strengthens tooth enamel and prevents dental caries","breakdown":"Added to drinking water (0.7 ppm) in US since 1945. Reduced tooth decay by 25%. Excessive fluoride: fluorosis (white spots on teeth)"},{"term":"Vitamin E","def":"Fat-soluble antioxidant — protects cell membranes from oxidative damage","breakdown":"8 forms; alpha-tocopherol most active. Sources: nuts, seeds, vegetable oils, wheat germ. Deficiency rare but causes nerve damage"},{"term":"Riboflavin (B2)","def":"B vitamin essential for energy metabolism and cellular function","breakdown":"Found in dairy, meat, fortified grains. Deficiency: ariboflavinosis (cracked lips, inflamed tongue, eye sensitivity). Urine turns bright yellow when supplementing"},{"term":"Thiamine (B1)","def":"B vitamin essential for carbohydrate metabolism and nerve function","breakdown":"Deficiency: beriberi (dry: nerve disease; wet: heart disease) and Wernicke-Korsakoff syndrome (alcohol-related). Sources: whole grains, legumes, pork"},{"term":"Pantothenic acid (B5)","def":"B vitamin essential for energy metabolism and CoA synthesis","breakdown":"Found in almost all foods (pantothenic = everywhere). Deficiency very rare. Important for fat, carbohydrate, protein metabolism. Found in avocado, mushrooms, chicken"},{"term":"Biotin (B7)","def":"B vitamin essential for fat synthesis, gluconeogenesis, and amino acid metabolism","breakdown":"Deficiency: hair loss, skin rash, neurological symptoms. Raw egg whites contain avidin which blocks biotin absorption. Found in eggs (cooked), nuts, liver"},{"term":"Phosphorus","def":"Major mineral — component of bones, teeth, DNA, RNA, and ATP","breakdown":"Works with calcium in 2:1 ratio ideally. Found in meat, dairy, nuts, legumes, cola (phosphoric acid). High phosphorus-to-calcium ratio impairs bone health"},{"term":"Copper","def":"Trace mineral essential for iron metabolism, collagen synthesis, and antioxidant defense","breakdown":"Deficiency: anemia (despite adequate iron), bone problems, neurological issues. Excess: liver damage. Found in shellfish, nuts, seeds, whole grains"},{"term":"Manganese","def":"Trace mineral cofactor for enzymes involved in bone formation, carbohydrate metabolism, and antioxidant defense","breakdown":"Deficiency rare. Found in whole grains, legumes, nuts, tea. Toxicity possible from supplements or environmental exposure (mining, welding)"},{"term":"Molybdenum","def":"Trace mineral cofactor for enzymes that metabolize certain amino acids and process waste","breakdown":"Deficiency very rare. Found in legumes, grains, nuts. Important for detoxification of sulfur-containing amino acids"},{"term":"Alcohol and nutrition","def":"Alcohol provides 7 calories/gram with no nutritional value — displaces nutrients and impairs absorption","breakdown":"Impairs absorption of: B vitamins, folate, zinc. Increases requirements. Heavy use causes deficiencies and liver disease. Moderate use: men ≤2 drinks/day"},{"term":"Caffeine","def":"Stimulant found in coffee, tea, chocolate, energy drinks — affects nutrient absorption and sleep","breakdown":"Moderate caffeine (<400mg/day) generally safe for adults. Impairs iron absorption when consumed with meals. Can cause calcium loss. Diuretic effect mild"},{"term":"Phytates (phytic acid)","def":"Anti-nutrient in grains and legumes that binds minerals and reduces absorption","breakdown":"Reduces absorption of iron, zinc, calcium. Soaking, sprouting, fermentation reduces phytate content. Traditional food preparation methods helped bioavailability"},{"term":"Oxalate","def":"Anti-nutrient in spinach, nuts, chocolate — binds calcium, reducing absorption","breakdown":"Oxalate + calcium → calcium oxalate = kidney stones in susceptible people. Most people absorb calcium from spinach poorly despite high content"},{"term":"Tannins","def":"Polyphenols in tea, coffee, wine, legumes — reduce iron absorption when consumed with meals","breakdown":"Bind to non-heme iron, reducing absorption up to 50-60%. Separate iron-rich meals from tea/coffee by 1-2 hours. Also have antioxidant properties"},{"term":"Food synergy","def":"Concept that nutrients work better together than in isolation","breakdown":"Examples: vitamin C + iron (enhances absorption), fat + fat-soluble vitamins (required for absorption), turmeric + black pepper (bioavailability). Whole foods > supplements"},{"term":"Bioavailability","def":"Proportion of a nutrient that is absorbed and used by the body","breakdown":"Factors: food form, cooking method, anti-nutrients, other nutrients present, gut health, genetics. Varies widely for same nutrient from different sources"},{"term":"Resistant starch","def":"Starch that resists digestion — acts like fiber, feeds gut bacteria","breakdown":"Found in: unripe bananas, cooked/cooled potato or rice, legumes. Increases after cooling. Benefits: blood glucose, satiety, colon health"},{"term":"Blood glucose regulation","def":"Homeostatic system maintaining blood glucose 70-100 mg/dL through insulin and glucagon","breakdown":"After eating: glucose rises → insulin released → cells absorb glucose. Fasting: glucose falls → glucagon released → liver releases glucose"},{"term":"Total parenteral nutrition (TPN)","def":"Complete intravenous nutrition when GI tract cannot be used","breakdown":"Contains: glucose, amino acids, lipids, electrolytes, vitamins, minerals. Risks: infection, liver disease, metabolic complications. Requires monitoring"},{"term":"Nutrition screening","def":"Initial rapid assessment to identify patients at nutritional risk","breakdown":"Tools: MNA (elderly), MUST (adults), PG-SGA (cancer). Identifies who needs full nutrition assessment. Done on hospital admission. Brief and easy"},{"term":"Malabsorption","def":"Impaired absorption of nutrients in small intestine — causes deficiencies despite adequate intake","breakdown":"Causes: celiac disease, Crohn's, short bowel syndrome, pancreatic insufficiency. Symptoms: steatorrhea (fatty stools), diarrhea, weight loss, deficiencies"},{"term":"Dysphagia","def":"Difficulty swallowing — requires texture modification of foods and liquids","breakdown":"IDDSI levels 0-7 (thin to regular). Causes: stroke, Parkinson's, head/neck cancer. Risk: aspiration pneumonia. RDN and speech therapist collaborate"},{"term":"Community nutrition","def":"Application of nutrition principles to promote health of populations and communities","breakdown":"Programs: WIC, SNAP, school lunch, Meals on Wheels. Public health nutrition: policy, education, research. Address food security and access"},{"term":"WIC (Women, Infants, Children)","def":"Federal program providing nutrition support for low-income pregnant/breastfeeding women and young children","breakdown":"Provides: supplemental foods, nutrition education, healthcare referrals. Currently serves 6.7 million/month. Shown to improve birth outcomes and child development"},{"term":"SNAP (Supplemental Nutrition Assistance Program)","def":"Federal food assistance program (formerly food stamps) for low-income individuals and families","breakdown":"Average benefit ~$6/day. Cannot purchase: alcohol, tobacco, vitamins, prepared hot foods. Debate over whether to restrict eligible foods"},{"term":"School nutrition programs","def":"National School Lunch Program and School Breakfast Program — federally subsidized meals for students","breakdown":"Must meet USDA nutrition standards (whole grains, fruits, vegetables, low sodium). Free/reduced price for eligible students. Improves diet quality"},{"term":"Food insecurity and health","def":"Insufficient food access associated with poor diet quality, obesity, diabetes, mental health issues","breakdown":"Paradox: food insecurity and obesity coexist. Cheap, calorie-dense foods accessible; nutrient-dense foods cost more. Chronic stress affects metabolism"},{"term":"Protein turnover rate","def":"Continuous process of breaking down and rebuilding proteins — liver proteins: 10 days, muscle: 180 days","breakdown":"About 200-300g protein degraded and resynthesized daily. Dietary protein needed to replace losses. Illness and stress increase protein turnover — higher protein needs"},{"term":"Gluconeogenesis in fasting","def":"Liver synthesizes glucose from non-carbohydrate sources (amino acids, glycerol, lactate) during fasting","breakdown":"Glucogenic amino acids most important source. Cortisol promotes gluconeogenesis. Maintains blood glucose for brain and red blood cells which cannot use fatty acids"},{"term":"Lipid transport system","def":"Chylomicrons (dietary fat) → VLDL → IDL → LDL → taken up by cells or HDL → returns cholesterol to liver","breakdown":"Chylomicrons from intestine carry dietary triglycerides. VLDL from liver carries endogenous triglycerides. LDL carries cholesterol to tissues. HDL scavenges excess cholesterol"},{"term":"Insulin signaling in nutrition","def":"Insulin triggers GLUT4 glucose transporters to move to cell membrane, enabling cellular glucose uptake","breakdown":"Type 2 diabetes: insulin resistance — cells don't respond. Muscles and fat main targets. Exercise makes cells more insulin sensitive for hours. High-carb meals trigger large insulin release"},{"term":"Adipose tissue functions","def":"Energy storage (triglycerides), insulation, cushioning organs, endocrine organ (secretes leptin, adiponectin)","breakdown":"Visceral fat (around organs) metabolically active and harmful. Subcutaneous fat (under skin) less harmful. Adiponectin: improves insulin sensitivity. Leptin: signals satiety to hypothalamus"},{"term":"Hepatic glucose regulation","def":"Liver acts as glucose buffer — stores as glycogen when high, releases glucose when blood glucose falls","breakdown":"Glycogen capacity: ~100g in liver (brain fuel), ~400g in muscles (local use only). After 12-18 hours fasting, liver glycogen depleted → gluconeogenesis begins"},{"term":"Microbiome and nutrition","def":"Gut bacteria ferment fiber → produce short-chain fatty acids → provide energy, regulate immune system, affect weight","breakdown":"Butyrate (from fiber fermentation) feeds colon cells, reduces colon cancer risk, anti-inflammatory. Diversity is key. Antibiotics, processed foods, low-fiber diets reduce diversity"},{"term":"Renal nutrition considerations","def":"CKD patients may need to limit: phosphorus, potassium, sodium, protein — dialysis patients need MORE protein","breakdown":"Damaged kidneys can't excrete phosphorus/potassium → accumulate to dangerous levels. Phosphorus binders taken with meals. Dialysis removes waste but also removes amino acids"},{"term":"Cardiovascular nutrition evidence","def":"Mediterranean diet, DASH diet most evidence-based for cardiovascular health. Saturated fat replacement with unsaturated fat reduces risk","breakdown":"Trans fat removal from food supply one of biggest public health nutrition wins. Omega-3 supplementation: inconsistent evidence. Dietary pattern more important than individual foods"},{"term":"Diabetes nutrition management","def":"Medical nutrition therapy: carbohydrate monitoring, weight management if overweight, glycemic control, individualized meal plan","breakdown":"Low-carb, Mediterranean, DASH, plant-based all evidence-based. Carb distribution throughout day important. Glycemic index helpful secondary to total carbs. Alcohol raises then drops glucose"},{"term":"Osteoporosis prevention nutrition","def":"Peak bone mass by age 30 depends on calcium, vitamin D, protein, magnesium, vitamin K2, and weight-bearing exercise","breakdown":"Most osteoporosis fractures preventable with adequate nutrition during adolescence. Calcium supplements: <2500mg/day. Vitamin D needed for calcium absorption. After 30: maintenance"},{"term":"Celiac disease nutritional management","def":"Strict lifelong gluten-free diet — also check for deficiencies: iron, folate, B12, vitamin D, calcium from malabsorption","breakdown":"Cross-contamination must be avoided. Oats controversial (some tolerate gluten-free oats, some react). Nutritional deficiencies improve with gluten-free diet but supplementation often needed"},{"term":"Irritable bowel syndrome diet","def":"Low FODMAP diet reduces fermentable carbohydrates — reduces bloating, gas, diarrhea in IBS","breakdown":"FODMAP: Fermentable Oligosaccharides, Disaccharides, Monosaccharides, Polyols. 3-phase approach: elimination → reintroduction → personalization. Should be done with RD guidance"},{"term":"Inflammatory bowel disease nutrition","def":"Crohn's and UC: malnutrition common from malabsorption, reduced intake, increased losses — individualized nutrition support needed","breakdown":"Enteral nutrition as effective as steroids for inducing remission in pediatric Crohn's. Omega-3s may help. Avoid: raw fruits/vegetables during flares. High protein needs during active disease"},{"term":"Bariatric surgery nutrition","def":"Post-surgery: liquid diet progression, small portions, high protein, lifelong vitamin/mineral supplementation (especially B12, iron, vitamin D, calcium)","breakdown":"Gastric bypass: malabsorptive — higher risk of B12, iron, calcium deficiencies. Gastric sleeve: restrictive only. Dumping syndrome from high-sugar foods. Protein priority at every meal"},{"term":"Eating disorder nutrition rehabilitation","def":"Gradual caloric increase, normalize eating patterns, fear food exposure, address nutritional deficiencies","breakdown":"Refeeding syndrome risk if too aggressive early nutrition restoration. Phosphorus critical to monitor. Weight restoration needed for cognitive function to engage in therapy. Team approach essential"},{"term":"Nutrition in HIV/AIDS","def":"HIV increases metabolic rate and protein needs, causes malabsorption, medication-nutrient interactions — wasting syndrome is a complication","breakdown":"Antiretroviral medications with food requirements. Increased protein (1.2-1.4g/kg). Food safety critical — immunocompromised. Omega-3s, glutamine may help with wasting. RD essential"},{"term":"Pediatric nutrition assessment","def":"Growth charts (CDC or WHO) track height, weight, head circumference — most important nutrition tool for children","breakdown":"Weight-for-length used under 2. BMI-for-age charts used 2-20. Faltering growth: weight drops 2+ percentile lines. Food security, feeding relationship, developmental feeding assessed"},{"term":"Prenatal nutrition complications","def":"Gestational diabetes: carbohydrate monitoring, weight gain management. Pre-eclampsia: adequate protein, calcium, vitamin D. Hyperemesis gravidarum: medical nutrition support","breakdown":"GDM increases risk of type 2 diabetes for mother and obesity for child. Excessive pregnancy weight gain associated with childhood obesity. Undernourishment: low birth weight, preterm"},{"term":"Nutrition in critical illness","def":"Hypermetabolism, hypercatabolism require early enteral nutrition (within 24-48 hours of ICU admission) — parenteral if gut not functioning","breakdown":"'If the gut works, use it.' Enteral preferred — maintains gut integrity, cheaper, fewer complications. Permissive underfeeding in early critical illness trending. High protein needs (1.5-2g/kg)"},{"term":"Nutrition assessment methods","def":"ABCD: Anthropometric (height, weight, skin folds), Biochemical (labs), Clinical (physical exam signs), Dietary (intake history)","breakdown":"Most comprehensive: combine all four. Albumin: traditional but reflects inflammation not acute nutrition status. Prealbumin: reflects nutrition better. SGA (Subjective Global Assessment) widely used"},{"term":"Functional fiber vs dietary fiber","def":"Dietary fiber: naturally in plant foods. Functional fiber: extracted or synthesized and added to foods — both count toward daily needs","breakdown":"Added fiber in yogurt, breads, cereals. Inulin, chicory root, psyllium common functional fibers. Same fermentation benefits but studies mostly on dietary fiber from whole foods"},{"term":"Phytochemicals categories","def":"Carotenoids (lycopene, beta-carotene), Flavonoids (quercetin, resveratrol), Glucosinolates (cruciferous), Allicin (garlic), Lignans (flaxseed)","breakdown":"Thousands of phytochemicals identified. Function as antioxidants, anti-inflammatory, phytoestrogens. Not essential nutrients but associated with disease prevention. Eat the rainbow to get variety"},{"term":"Nutraceutical vs pharmaceutical","def":"Nutraceutical: food-derived substance with health benefits beyond basic nutrition. Different from drugs — food regulatory pathway","breakdown":"Examples: fish oil, glucosamine, probiotics, plant sterols. Claims regulated: structure-function claims vs disease claims (require FDA approval). Evidence quality varies greatly"},{"term":"Nutrition label % Daily Value","def":"Based on 2000-calorie diet. 5% DV or less = low. 20% DV or more = high. Help compare foods and assess diet quality","breakdown":"Not everyone needs 2000 calories. Use %DV to compare similar products. Aim for high %DV: fiber, vitamins, minerals. Aim for low %DV: saturated fat, sodium, added sugars"},{"term":"Protein digestibility scores","def":"PDCAAS (Protein Digestibility-Corrected Amino Acid Score) and DIAAS (Digestible Indispensable Amino Acid Score) — animal proteins score highest","breakdown":"DIAAS: newer, more accurate. Soy protein = 1.0 (perfect). Wheat = 0.4 (low). Animal proteins: 0.9-1.0. Egg white = 1.21 (above 1 means excess). Combined plant proteins can achieve high scores"},{"term":"Conditional essential nutrients","def":"Non-essential under normal conditions but become essential during illness, stress, or developmental stages","breakdown":"Examples: arginine (growth, trauma), glutamine (GI stress), cysteine (premature infants). Increased need exceeds body's synthesis capacity. Used in clinical nutrition support"},{"term":"Bioactive food components","def":"Beyond basic nutrients — plant sterols, stanols reduce cholesterol; lycopene reduces prostate cancer risk; lutein protects eyes","breakdown":"Plant sterols in fortified margarines block cholesterol absorption — proven LDL reduction. Lutein in eggs and leafy greens — macular degeneration prevention. Evidence varies by component"},{"term":"Resting metabolic rate (RMR) vs BMR","def":"BMR: metabolic rate in completely rested, fasted, post-absorptive state. RMR: easier to measure, slightly higher (~10%)","breakdown":"Both measure resting energy expenditure. Clinical practice uses RMR. Mifflin-St Jeor equation commonly used. Multiply by activity factor for total daily energy expenditure (TDEE)"},{"term":"Vitamin-mineral interactions","def":"Calcium inhibits iron and zinc absorption. Vitamin C enhances iron. Vitamin D enables calcium absorption. Fat enables A, D, E, K absorption","breakdown":"Take calcium and iron supplements at different times. Eat vitamin C with plant iron sources. Take fat-soluble vitamins with meals. High zinc competes with copper absorption"},{"term":"Alcohol metabolism and nutrition","def":"Alcohol metabolized in liver by alcohol dehydrogenase → acetaldehyde → acetate. Interferes with nutrient metabolism and storage","breakdown":"Empty calories: 7 cal/gram. Inhibits gluconeogenesis → hypoglycemia. Reduces folate, thiamine, magnesium levels. Excess leads to fatty liver → alcoholic hepatitis → cirrhosis"},{"term":"Enteral nutrition formulas","def":"Standard polymeric, elemental (predigested for malabsorption), disease-specific (renal, hepatic, diabetic, pulmonary) formulas available","breakdown":"Standard: intact protein, complex carbs, long-chain fat. Elemental: amino acids, glucose, MCT — better for malabsorption, Crohn's, short bowel. Tube feeding rates and positions important"},{"term":"Nutrition and immune function","def":"Malnutrition impairs all aspects of immunity. Key nutrients: zinc, vitamin A, vitamin C, vitamin D, omega-3s, protein","breakdown":"Obesity also impairs immune function — 'malnutrition in the obese.' COVID-19 worse outcomes with vitamin D deficiency. Single nutrient supplements less effective than overall good diet"},{"term":"Ghrelin and leptin in obesity","def":"Ghrelin (hunger hormone) elevated with sleep deprivation and dieting. Leptin resistance in obesity means satiety signals ignored despite high leptin levels","breakdown":"Sleep deprivation: +24% ghrelin, -18% leptin → increased appetite. Leptin resistance: obesity → high leptin but brain doesn't respond. Set point theory — body defends weight"},{"term":"Nutrient density of beverages","def":"Water: no calories, highest hydration. Milk: calcium, protein, vitamins. 100% juice: vitamins but high sugar, low fiber. Soda: zero nutrients","breakdown":"Liquid calories don't satisfy hunger the same as solid food. Sweetened beverages #1 source added sugar. Choose beverages with nutrients or plain water for hydration"},{"term":"Community nutrition programs","def":"WIC, SNAP, School Breakfast/Lunch, Congregate Meals (elderly), Food Banks — government programs addressing food insecurity","breakdown":"WIC: women, infants, children under 5. SNAP: food purchasing assistance for low-income. School meals: 30 million children daily. Community kitchens and gardens also important"},{"term":"Clinical malnutrition criteria","def":"ASPEN/AND malnutrition diagnosis requires 2+ of: inadequate intake, weight loss, loss of muscle mass, loss of body fat, fluid accumulation, reduced grip strength","breakdown":"Malnutrition affects 30-50% of hospitalized patients. Increases complications, length of stay, mortality. Early screening (within 24h admission) and intervention critical"},{"term":"Pediatric failure to thrive","def":"Inadequate weight gain/growth in children — inadequate intake, malabsorption, or increased metabolic needs most common causes","breakdown":"Not a diagnosis — a sign. Organic causes (celiac, reflux, heart disease) vs non-organic (poverty, neglect, feeding difficulties). Full multidisciplinary assessment needed"},{"term":"Herbal supplement interactions","def":"St. John's Wort reduces antibiotic/contraceptive effectiveness. Ginkgo increases bleeding risk. Garlic supplements affect blood thinners. Grapefruit inhibits drug metabolism","breakdown":"10% of prescription drug interactions involve supplements. Always ask patients about supplements. CYP3A4 enzyme system affected by many botanicals. Report adverse events to MedWatch"},{"term":"Nutrition and mental health","def":"Mediterranean diet associated with reduced depression risk. Gut-brain axis. Omega-3s studied for depression and bipolar. B vitamins for neurological function","breakdown":"Serotonin (brain) synthesized from tryptophan (dietary protein). 95% of serotonin made in gut. Microbiome affects mood. Deficiencies in B12, folate, zinc, D linked to depression symptoms"},{"term":"Glycemic response factors","def":"Ripeness, cooking method, particle size, fat and protein co-consumed all affect glycemic response to the same food","breakdown":"Ripe banana: higher GI than green. Pasta al dente: lower GI than soft pasta. Mashed potato: higher GI than whole. Fat slows gastric emptying → lower GI. Individual response varies 50%"},{"term":"Weight cycling (yo-yo dieting)","def":"Repeated cycles of losing and regaining weight — may cause metabolic adaptation, increased visceral fat, cardiovascular stress","breakdown":"Metabolic adaptation: body reduces RMR after weight loss. After regain: more fat, less muscle than before. Chronic dieters: higher cortisol, disordered eating risk. Stable moderate weight may be healthier than cycling"},{"term":"Nutrient timing for athletes","def":"Pre-workout: carbs 1-4 hours before. During (>1h): carbs every 30-60 min. Post-workout: carbs + protein within 30-60 min","breakdown":"'Anabolic window' post-exercise for protein: ~20-40g protein. Carbs restore glycogen. Chocolate milk: practical post-workout recovery (carbs + protein). Hydration before, during, after"},{"term":"Food additives safety","def":"FDA generally recognized as safe (GRAS) substances, direct additives (approved), color additives — all regulated","breakdown":"Common additives: preservatives (BHA, BHT), emulsifiers (lecithin), sweeteners (aspartame), colors. GRAS list: 10,000+ substances — most with limited safety data. 'Natural flavors' can be complex mixtures"},{"term":"Sustainable diets","def":"Diets that are healthy, environmentally friendly, economically fair — plant-based diets generally have lower environmental impact","breakdown":"Beef production: 20x more land, 5x more GHGs than chicken. Food waste: 1/3 of food produced globally wasted. EAT-Lancet planetary health diet: mostly plant foods, small amounts animal products"},{"term":"Food insecurity health effects","def":"Associated with: obesity (cheaper calorie-dense foods), diabetes, hypertension, mental health disorders, developmental delays in children","breakdown":"Paradox: food insecurity and obesity coexist — cheap ultra-processed foods available, nutritious foods expensive. SNAP reduces food insecurity by 30%. Reduces hospitalizations in elderly"},{"term":"Hunger hormones and appetite regulation","def":"Hunger: ghrelin (stomach), NPY, AgRP (hypothalamus). Satiety: leptin (fat), CCK (small intestine), GLP-1, PYY","breakdown":"Hypothalamic arcuate nucleus integrates hunger/satiety signals. Short-term: blood glucose, gut hormones. Long-term: leptin from fat stores. Sleep, stress, medications affect balance"},{"term":"Medical nutrition therapy (MNT)","def":"Use of specific nutrition services to treat illness — provided by RDN — Medicare covers MNT for diabetes and renal disease","breakdown":"Evidence-based nutrition interventions. Reduces HbA1c in diabetes, improves GFR in CKD, reduces complications. Cost-effective — saves healthcare dollars. Requires physician referral for Medicare"},{"term":"Tube feeding complications","def":"Diarrhea (#1), aspiration (most serious), tube displacement, refeeding syndrome, bloating, constipation, infection","breakdown":"Aspiration prevention: HOB elevated 30-45°, small bore tube, check residuals (controversial), post-pyloric placement for high-risk. Diarrhea: check formula, rate, medications, Clostridium difficile"},{"term":"Parenteral nutrition indications","def":"GI tract non-functional or inaccessible — bowel obstruction, short bowel syndrome, severe Crohn's fistula, GI surgery","breakdown":"Central PN (CPN): requires central venous access — used for long-term. Peripheral PN (PPN): limited to 2 weeks, lower concentration. Infectious complications main concern. Gut still best"},{"term":"Vitamin A retinoic acid function","def":"Retinoic acid (active form) — gene expression regulator, essential for cell differentiation, growth, embryonic development","breakdown":"Teratogen in excess — excess vitamin A causes birth defects. Isotretinoin (Accutane): must have negative pregnancy test before prescribing. Beta-carotene (plant) safe — body converts as needed"},{"term":"Iron absorption pathway","def":"Heme iron: absorbed as intact porphyrin ring by HCP1 transporter. Non-heme iron: reduced to Fe2+ by Dcytb, absorbed via DMT1, regulated by hepcidin","breakdown":"Hepcidin: master regulator of iron — liver makes more with iron overload and inflammation → reduces absorption. Hemochromatosis: genetic mutation → hepcidin resistance → iron overload"},{"term":"Osteomalacia vs osteoporosis","def":"Osteomalacia: inadequate mineralization of newly formed bone (vitamin D deficiency). Osteoporosis: loss of bone density — both calcium and bone protein lost","breakdown":"Osteomalacia: bone pain, muscle weakness, stress fractures. X-ray: looser bands (Looser zones). Treat with vitamin D and calcium. Rickets: osteomalacia in growing children"},{"term":"ERAS (Enhanced Recovery After Surgery)","def":"Evidence-based protocol including pre-op carbohydrate loading, early post-op oral feeding, reduced fasting periods — improves surgical outcomes","breakdown":"Traditional NPO midnight → ERAS: carb drink 2-3h before. Earlier post-op feeding reduces complications, length of stay, costs. Reduces insulin resistance from surgery. Now standard of care"},{"term":"Taste perception and nutrition","def":"5 tastes: sweet, salty, sour, bitter, umami. Taste receptors affect food preferences and food choices","breakdown":"MSG produces umami taste. Bitter sensitivity (supertasters) affects vegetable intake. Salt enhances flavor perception — explains why low-sodium diets initially taste bland. Taste changes with age, illness, medications"},{"term":"Epigenetics in nutrition","def":"Nutritional factors can turn genes on or off through DNA methylation and histone modification — without changing DNA sequence","breakdown":"Folate, B12: provide methyl groups for DNA methylation. Maternal diet affects offspring health decades later (Dutch Hunger Winter studies). Imprinting — Prader-Willi syndrome example"}]);
  fc.hard=fc.hard.concat([{"term":"Absorptive state (fed state)","def":"Post-meal period — nutrients absorbed, insulin dominant, anabolism occurs","breakdown":"Glucose → glycogen and fat storage. Amino acids → protein synthesis. Lasts 2-4 hours after meal"},{"term":"Post-absorptive state (fasted state)","def":"Between meals — glycogen breakdown, gluconeogenesis, fat oxidation to maintain blood glucose","breakdown":"Glucagon dominant. Liver releases glucose. After 12-18h glycogen depleted, fat becomes primary fuel"},{"term":"Ketogenesis","def":"Liver converts fatty acids to ketone bodies during prolonged fasting or carb restriction","breakdown":"Ketones: acetoacetate, beta-hydroxybutyrate, acetone. Brain uses ketones when glucose scarce. Basis of ketogenic diet"},{"term":"Gluconeogenesis","def":"Synthesis of new glucose from non-carbohydrate precursors (amino acids, glycerol, lactate)","breakdown":"Occurs in liver and kidney. Maintains blood glucose during fasting. Amino acids most important substrate"},{"term":"Enterohepatic circulation","def":"Recycling of bile salts from intestine back to liver via portal circulation","breakdown":"Bile salts emulsify fat for absorption. 95% recycled, 5% lost in feces. Soluble fiber interrupts this cycle, lowering cholesterol"},{"term":"VLDL, IDL, LDL, HDL differences","def":"Lipoprotein particles differ in triglyceride/cholesterol ratio and apolipoprotein composition","breakdown":"VLDL: liver-made, triglyceride-rich. IDL: VLDL remnant. LDL: cholesterol-rich, atherogenic. HDL: reverse cholesterol transport"},{"term":"Phospholipid structure and function","def":"Glycerol + 2 fatty acids + phosphate group — forms cell membrane bilayer","breakdown":"Amphipathic: hydrophilic head, hydrophobic tails. Forms lipid bilayer of all cell membranes. Lecithin is a common dietary phospholipid"},{"term":"Proteolysis and peptide absorption","def":"Protein digested to amino acids and small peptides — absorbed by specific transporters","breakdown":"Stomach: pepsin. Pancreas: trypsin, chymotrypsin. Small intestine brush border: peptidases. Di/tripeptides absorbed whole"},{"term":"Vitamin D synthesis pathway","def":"7-dehydrocholesterol → UV light → previtamin D3 → liver (25-OH-D3) → kidney (1,25-OH2-D3 = calcitriol)","breakdown":"Calcitriol is the active hormone form. Kidney conversion impaired in kidney disease — supplementation as active form needed"},{"term":"Iron absorption regulation","def":"Hepcidin (liver hormone) regulates iron absorption — high iron → high hepcidin → reduced absorption","breakdown":"Hepcidin degrades ferroportin (iron exporter) in enterocytes. Inflammation increases hepcidin → anemia of chronic disease"},{"term":"Protein turnover","def":"Continuous process of protein synthesis and breakdown — about 300g protein/day in adults","breakdown":"Net protein balance = synthesis - breakdown. Muscle protein turnover ~1-2%/day. Exercise and nutrition modulate balance. Key to understanding protein needs"},{"term":"Epigenetics and nutrition","def":"How diet and nutrients affect gene expression without changing DNA sequence","breakdown":"Examples: folate and DNA methylation, calorie restriction and aging genes. 'Nutritional epigenomics.' Early life nutrition has lasting epigenetic effects"},{"term":"Nutrigenomics","def":"Study of how nutrients affect gene expression and how genetics affect nutrient metabolism","breakdown":"Personalized nutrition based on genetic variants. Example: MTHFR gene affects folate metabolism. Still emerging — direct-to-consumer tests often premature"},{"term":"Microbiome-diet interactions","def":"Bidirectional relationship between gut bacteria and diet — diet shapes microbiome, microbiome affects nutrition","breakdown":"High-fiber diets increase microbial diversity and SCFA production. Antibiotics disrupt microbiome. Fecal transplant experimental for C. diff treatment"},{"term":"Dietary inflammation index","def":"Score measuring the overall inflammatory potential of a person's diet","breakdown":"Anti-inflammatory foods: fatty fish, vegetables, fruits, olive oil, spices. Pro-inflammatory: refined carbs, red meat, fried foods, sugar. High score linked to chronic disease"},{"term":"Advanced glycation end products (AGEs)","def":"Harmful compounds formed when sugars react with proteins or fats — accelerate aging and disease","breakdown":"Formed in body during hyperglycemia, in food during high-heat cooking (browning). Accumulate with age. Linked to kidney disease, Alzheimer's, cardiovascular disease"},{"term":"Oxidative stress","def":"Imbalance between free radicals and antioxidants — damages DNA, proteins, and cell membranes","breakdown":"Results from: inflammation, UV radiation, pollution, exercise, poor diet. Dietary antioxidants (vitamin C, E, polyphenols) help restore balance"},{"term":"Mitochondrial nutrition","def":"Role of nutrients in mitochondrial function and energy production","breakdown":"CoQ10, B vitamins, magnesium, lipoic acid support mitochondrial function. Mitochondrial dysfunction linked to aging and metabolic disease"},{"term":"Hormonal effects of diet","def":"Dietary choices significantly affect hormone levels — insulin, estrogen, testosterone, thyroid hormones","breakdown":"High sugar: spikes insulin repeatedly. Phytoestrogens (soy): mild estrogen effect. Iodine: thyroid hormone production. Protein: testosterone production"},{"term":"Ketogenic diet mechanism","def":"Very low carb (<50g/day) forces liver to produce ketones for fuel — shifts metabolism from glucose to fat","breakdown":"Takes 2-7 days to enter ketosis. Benefits claimed: weight loss, epilepsy control, metabolic health. Risks: keto flu, micronutrient deficiencies, unsustainable for many"},{"term":"Intermittent fasting physiology","def":"Cycling between fasting and eating periods — affects insulin, ketones, autophagy, and gene expression","breakdown":"16:8, 5:2, OMAD. Mechanisms: lower insulin, ketone production, autophagy (cellular cleaning), circadian rhythm benefits. Research still evolving"},{"term":"Calorie restriction and longevity","def":"Reducing calories 20-40% below ad libitum extends lifespan in model organisms — human evidence limited","breakdown":"CR mimetics: resveratrol, metformin. Mechanisms: lower IGF-1, AMPK activation, sirtuin activation, autophagy. Blue zone diets tend toward modest calories"},{"term":"Gut-brain axis","def":"Bidirectional communication network between gut microbiome and brain — affects mood, behavior, cognition","breakdown":"Vagus nerve main pathway. Gut produces 90% of serotonin. Microbiome imbalance linked to depression, anxiety, autism spectrum. Probiotics show promise"},{"term":"Cognitive nutrition","def":"Effect of diet on brain function, cognitive performance, and dementia risk","breakdown":"Mediterranean diet reduces Alzheimer's risk. DHA critical for brain structure. B vitamins for homocysteine (high = brain damage). Sugar and ultra-processed foods impair cognition"},{"term":"Sports nutrition timing","def":"Optimal timing of nutrient intake around exercise for performance and recovery","breakdown":"Before: carbs 1-4 hours prior. During (>60 min): 30-60g carbs/hour. After: carbs+protein within 30-60 min for glycogen resynthesis and muscle repair"},{"term":"Creatine supplementation","def":"Most researched ergogenic supplement — increases phosphocreatine stores for high-intensity exercise","breakdown":"Dose: 3-5g/day (or loading 20g/day x 5 days). Benefits: strength, power, muscle mass, recovery. Safe for healthy adults. Vegetarians benefit most (lower baseline)"},{"term":"Protein synthesis timing","def":"Muscle protein synthesis is elevated for 24-48 hours post-exercise — optimal response with adequate protein","breakdown":"~20-40g protein per meal maximizes synthesis. Evenly distributed meals better than one large serving. Leucine threshold (~2.5g) must be met"},{"term":"Carbohydrate periodization","def":"Strategically varying carbohydrate intake to optimize training adaptations and performance","breakdown":"Train low (low glycogen): enhances fat oxidation adaptations. Compete high: carb-load for performance. Not appropriate for all athletes or all sessions"},{"term":"Relative Energy Deficiency in Sport (RED-S)","def":"Impaired function from insufficient energy intake relative to exercise energy expenditure","breakdown":"Affects: hormones, bone density, immunity, mood, cardiovascular health, performance. Female athlete triad (older concept) is subset. Males also affected"},{"term":"Branched-chain amino acids (BCAAs)","def":"Leucine, isoleucine, valine — metabolized in muscle (not liver), important for protein synthesis","breakdown":"BCAA supplements popular but whole protein sources provide same BCAAs plus other essential AAs. Best to get from diet. Evidence for supplements weak if adequate protein consumed"},{"term":"Carnitine","def":"Molecule that transports long-chain fatty acids into mitochondria for oxidation","breakdown":"Body makes carnitine from lysine and methionine. Conditionally essential for premature infants. Supplements not proven to enhance fat burning in healthy individuals"},{"term":"Creatine phosphate system","def":"Immediate energy system using phosphocreatine to rapidly regenerate ATP — lasts 5-10 seconds","breakdown":"No oxygen needed. Highest intensity activities (sprint, Olympic lift). Creatine supplementation increases PCr stores by ~20%. Recovery: 3-5 minutes"},{"term":"Nutrition in wound healing","def":"Protein, vitamin C, zinc, and adequate calories essential for tissue repair","breakdown":"Protein: collagen synthesis (1.5-2g/kg for healing). Vitamin C: collagen cross-linking. Zinc: cell proliferation. Arginine: wound healing and immune function"},{"term":"Immunonutrition","def":"Use of specific nutrients to modulate immune function — particularly in critical illness and surgery","breakdown":"Key nutrients: glutamine, arginine, omega-3, antioxidants. Enteral formulas with immunonutrients reduce infections and hospital stay in surgical patients"},{"term":"Oncology nutrition","def":"Nutrition management in cancer — preventing/treating malnutrition, managing treatment side effects","breakdown":"Cancer cachexia: progressive muscle loss. Chemotherapy/radiation: nausea, taste changes, mucositis. Malnutrition worsens outcomes. Early RDN referral critical"},{"term":"Fatty acid eicosanoid synthesis","def":"Omega-6 arachidonic acid → pro-inflammatory eicosanoids (prostaglandins, leukotrienes). Omega-3 EPA → less inflammatory eicosanoids","breakdown":"Eicosanoids: locally acting hormones regulating inflammation, pain, fever, platelet aggregation. High omega-6:omega-3 ratio (modern diet 15:1 vs ideal 4:1) promotes chronic inflammation"},{"term":"mTOR pathway and nutrition","def":"Mechanistic target of rapamycin — nutrient sensor activated by amino acids (especially leucine) and insulin — drives protein synthesis","breakdown":"mTORC1: anabolic switch. Activated by leucine (10-15% above threshold triggers MPS). Fasting inhibits mTOR → stimulates autophagy. Rapamycin (mTOR inhibitor) studied for longevity"},{"term":"AMPK energy sensing","def":"AMP-activated protein kinase — cellular energy sensor activated by low ATP (exercise, fasting) — promotes catabolism, inhibits anabolism","breakdown":"AMPK activation: increases fatty acid oxidation, glucose uptake, mitochondrial biogenesis. Inhibits fatty acid synthesis, protein synthesis, cholesterol synthesis. Metformin activates AMPK"},{"term":"Vitamin D receptor activation","def":"25-OH vitamin D → 1,25-OH2 vitamin D (calcitriol) via kidney 1-alpha-hydroxylase — active hormone binds VDR nuclear receptor","breakdown":"VDR present in nearly every cell. 1-alpha-hydroxylase activity regulated by PTH, calcium, phosphorus. Kidney failure → cannot activate D3. Calcitriol directly prescribed in renal failure"},{"term":"Bile acid metabolism","def":"Cholesterol → primary bile acids (cholic, chenodeoxycholic) → secondary bile acids (deoxycholic, lithocholic) via gut bacteria","breakdown":"Bile acids: detergent-like emulsifiers. 95% reabsorbed in terminal ileum (enterohepatic circulation). Terminal ileum disease/resection → fat malabsorption. Bile sequestrants lower LDL by trapping bile"},{"term":"Metabolomics in nutrition research","def":"Comprehensive analysis of all small molecules (metabolites) in biological samples — provides functional view of nutritional status","breakdown":"Can identify nutritional biomarkers, diet-disease associations, individual metabolic variation. Metabolic fingerprinting reveals how individuals respond differently to same diet (personalized nutrition)"},{"term":"Nutrigenetics","def":"How genetic variation affects individual response to nutrients — SNPs (single nucleotide polymorphisms) alter enzyme activity","breakdown":"MTHFR C677T: reduced folate metabolism → increased homocysteine. APOE4: increased cardiovascular response to saturated fat. FTO gene variants: obesity susceptibility. Lactase persistence: lactose tolerance"},{"term":"Autophagy and fasting nutrition","def":"Cellular self-cleaning process — degradation and recycling of damaged proteins and organelles — activated by fasting, calorie restriction","breakdown":"mTOR inhibition → autophagy activation. 24-48h fasting induces significant autophagy. May explain longevity benefits of calorie restriction. Mitophagy: damaged mitochondria recycled"},{"term":"Intestinal permeability (leaky gut)","def":"Disruption of tight junctions between intestinal cells — allows antigens to pass into bloodstream triggering immune response","breakdown":"Associated with: celiac disease, Crohn's, food allergies, SIBO, stress. Increased by: alcohol, NSAIDs, low-fiber diet, dysbiosis. Decreased by: butyrate, glutamine, zinc, fiber"},{"term":"Ketone body utilization","def":"Beta-hydroxybutyrate, acetoacetate, acetone — produced by liver from fatty acids during fasting/ketogenic diet — used by brain, heart, muscle","breakdown":"Brain requires 2 weeks to adapt fully to ketones. Ketones: 2 ATP more efficient per carbon than glucose. Acetone exhaled → fruity breath. Ketosis ≠ ketoacidosis (different magnitudes)"},{"term":"Protein quality: DIAAS methodology","def":"Digestible Indispensable Amino Acid Score — compares digestibility of each essential amino acid against human needs at specific life stage","breakdown":"Improvement over PDCAAS: accounts for ileal digestibility, not total digestibility. Provides score for each DIAA separately. Allows identification of limiting amino acid. Animal proteins generally higher DIAAS"},{"term":"Lipogenesis regulation","def":"De novo lipogenesis: glucose → acetyl-CoA → fatty acids — primarily in liver. Stimulated by: insulin, excess carbohydrates. Inhibited by: glucagon, dietary fat","breakdown":"Not major fat storage pathway in humans (unlike rodents). High carb diets do increase lipogenesis 10-fold. Fructose more lipogenic than glucose. NAFLD partly from hepatic lipogenesis"},{"term":"Vitamin K2 (menaquinone) carboxylation","def":"K2 activates matrix Gla protein (MGP) which prevents arterial calcification, and osteocalcin for bone mineralization","breakdown":"K2 different from K1 (phylloquinone in leafy greens). K2 in fermented foods, animal products. Rotterdam study: highest K2 intake associated with lowest cardiovascular mortality. Poor activation = arterial calcification"},{"term":"Carnitine biosynthesis and transport","def":"Carnitine made from lysine and methionine with vitamin C, iron, B6, niacin — transports long-chain fatty acids into mitochondria","breakdown":"L-carnitine supplementation: no benefit in healthy individuals with adequate intake. Deficiency: organic acidemias, dialysis, some medications (valproate). Red meat richest dietary source"},{"term":"Short bowel syndrome nutrition","def":"Loss of >50-60% small intestine → malabsorption, high-volume diarrhea, fluid/electrolyte losses, dependence on parenteral nutrition","breakdown":"Remaining bowel adapts over 1-2 years (intestinal adaptation). Ileum more adaptable than jejunum. Colon absorbs short-chain fatty acids if preserved. Goal: transition off TPN to enteral/oral"},{"term":"Homocysteine and nutrition","def":"Homocysteine: toxic amino acid intermediate — elevated with B12, B6, folate deficiency — independent cardiovascular risk factor","breakdown":"Remethylation pathway: homocysteine → methionine requires B12 and folate. Transsulfuration: homocysteine → cystathionine requires B6. Elevated homocysteine: >15 μmol/L. Treat with B vitamins"},{"term":"Phospholipid fatty acid composition","def":"Cell membrane fatty acid composition reflects dietary fat intake — high omega-3 intake → more fluid, anti-inflammatory membranes","breakdown":"Erythrocyte phospholipid omega-3 content: biomarker of long-term omega-3 intake. More accurate than 24h recall. Membrane fluidity affects receptor function, insulin signaling"},{"term":"Serotonin synthesis from tryptophan","def":"Dietary tryptophan → 5-HTP (via TPH1 in gut, TPH2 in brain) → serotonin → melatonin. Competes with other large neutral amino acids for brain uptake","breakdown":"95% of serotonin: gut (regulates motility). 5% in brain. Carbohydrates increase tryptophan uptake into brain (insulin moves competing AAs into muscle). Tryptophan depletion → depression in susceptible"},{"term":"Exocrine pancreatic insufficiency","def":"Inadequate digestive enzymes from pancreas → severe fat malabsorption (steatorrhea), protein and carb malabsorption","breakdown":"Causes: chronic pancreatitis, cystic fibrosis, pancreatic cancer, pancreatectomy. Treatment: pancreatic enzyme replacement therapy (PERT) taken with meals. Need fat-soluble vitamin supplementation"},{"term":"Nutritional pharmacology of statins","def":"Statins inhibit HMG-CoA reductase → reduce cholesterol synthesis → also reduce CoQ10 synthesis — may cause myopathy","breakdown":"Grapefruit inhibits CYP3A4 → increases statin levels → toxicity risk. CoQ10 depletion: muscle pain (myalgia), weakness. CoQ10 supplementation sometimes helpful. Red yeast rice: natural statin"},{"term":"Dietary inflammatory index (DII)","def":"Scoring system measuring overall diet's inflammatory potential based on 45 food parameters — negative score = anti-inflammatory","breakdown":"Anti-inflammatory: omega-3s, fiber, vitamins C and D, magnesium, turmeric, ginger, garlic. Pro-inflammatory: saturated fat, trans fat, cholesterol, refined carbs. High DII → increased CRP, IL-6"},{"term":"Iron overload (hemochromatosis)","def":"Hereditary hemochromatosis: HFE gene mutation → excessive iron absorption → iron deposits in liver, heart, pancreas, joints","breakdown":"Most common genetic disorder in Northern Europeans. C282Y mutation most common. Symptoms delayed until iron accumulates (decades). Treatment: therapeutic phlebotomy. Avoid vitamin C supplements"},{"term":"Copper metabolism and ceruloplasmin","def":"Copper transported by ceruloplasmin in blood — Wilson's disease: copper accumulates → liver and brain damage. Menkes disease: copper deficiency from transport defect","breakdown":"Wilson's: copper chelation (D-penicillamine). Menkes: X-linked, copper injections. Zinc competes with copper absorption — excess zinc supplementation can cause copper deficiency"},{"term":"Selenium and selenoproteins","def":"Selenium incorporated as selenocysteine (21st amino acid) into selenoproteins including glutathione peroxidase and thioredoxin reductase","breakdown":"25 selenoprotein genes in humans. Glutathione peroxidase: antioxidant defense, reduces lipid peroxides. Thyroid deiodinase: converts T4 to active T3. Selenium deficiency → impaired thyroid function"},{"term":"Nutritional assessment in aging","def":"Mini Nutritional Assessment (MNA), DETERMINE checklist — screen for malnutrition in elderly. DEXA scan for body composition","breakdown":"Sarcopenic obesity: high fat, low muscle despite normal BMI. Calf circumference: simple muscle mass proxy. Handgrip strength: functional muscle strength, predicts outcomes. Weight loss >10% = significant"},{"term":"Protein restricted diet in hepatic encephalopathy","def":"Historical protein restriction now known harmful — instead: branched-chain amino acids (BCAAs) and smaller frequent meals preferred","breakdown":"Hepatic encephalopathy: ammonia accumulates from protein catabolism + gut bacteria. BCAAs metabolized by muscle (not liver) and reduce ammonia. BCAA supplements improve encephalopathy and muscle mass in cirrhosis"},{"term":"Refeeding syndrome mechanism","def":"Rapid carbohydrate administration after prolonged starvation → insulin surge → cellular uptake of phosphorus, potassium, magnesium → dangerous drops in serum levels","breakdown":"Phosphate most critical (hypophosphatemia → respiratory failure, hemolysis, rhabdomyolysis, cardiac arrhythmia, seizure). Monitor electrolytes before and during refeeding. Start slowly (50% of goal)"},{"term":"Fetal programming (Barker hypothesis)","def":"Nutritional environment in utero permanently programs metabolic disease risk — low birth weight predicts type 2 diabetes, cardiovascular disease in adulthood","breakdown":"Dutch Hunger Winter 1944-45: famine exposure in utero → metabolic syndrome in offspring 60 years later. First trimester: more sensitive to famine. Epigenetic mechanisms responsible"},{"term":"Very low calorie diet (VLCD) physiology","def":"<800 kcal/day — causes rapid weight loss but also lean mass loss, metabolic adaptation, gallstone formation, nutrient deficiencies","breakdown":"Protein-sparing modified fast: VLCD + high protein to minimize lean mass loss. Must be medically supervised. Rapid weight loss associated with gallstones (cholesterol supersaturation). Yo-yo risk"}]);
  qz.easy=qz.easy.concat([{"q":"How many calories does 1 gram of carbohydrate provide?","opts":["2","4","7","9"],"correct":1,"explain":"Carbohydrates provide 4 calories per gram. The same as protein (4 cal/g). Fat provides 9 cal/g and alcohol provides 7 cal/g."},{"q":"Which nutrient is the body's preferred energy source?","opts":["Fat","Protein","Carbohydrates","Vitamins"],"correct":2,"explain":"Carbohydrates are the body's preferred energy source because they are most efficiently converted to glucose for immediate use. The brain especially relies on glucose."},{"q":"What is the recommended daily sodium intake for healthy adults?","opts":["Less than 1000mg","Less than 2300mg","Less than 3500mg","Less than 5000mg"],"correct":1,"explain":"The recommended daily sodium intake is less than 2300mg for healthy adults. The average American consumes about 3400mg daily, which contributes to hypertension."},{"q":"Which type of fat is considered most harmful to heart health?","opts":["Monounsaturated fat","Polyunsaturated fat","Saturated fat","Trans fat"],"correct":3,"explain":"Trans fat (partially hydrogenated oil) is most harmful — it raises LDL (bad) cholesterol AND lowers HDL (good) cholesterol simultaneously. The FDA banned most trans fats in U.S. foods in 2018."},{"q":"Vitamin D deficiency in children causes which condition?","opts":["Scurvy","Rickets","Pellagra","Beriberi"],"correct":1,"explain":"Vitamin D deficiency in children causes rickets — soft, weak bones that bow under body weight. In adults, the same deficiency causes osteomalacia (soft bones). Vitamin D is needed for calcium absorption."},{"q":"Which mineral is most important for bone health?","opts":["Iron","Zinc","Calcium","Magnesium"],"correct":2,"explain":"Calcium is the most important mineral for bone health — 99% of body calcium is stored in bones and teeth. Adequate calcium throughout life reduces osteoporosis risk. Vitamin D is needed for calcium absorption."},{"q":"What does MyPlate recommend for half the plate?","opts":["Grains and dairy","Fruits and vegetables","Protein and grains","Fruits and protein"],"correct":1,"explain":"MyPlate recommends filling half the plate with fruits and vegetables. One quarter should be grains (preferably whole grains) and one quarter protein, with a small dairy serving on the side."},{"q":"Which vitamin is produced by the skin in sunlight?","opts":["Vitamin A","Vitamin B12","Vitamin C","Vitamin D"],"correct":3,"explain":"Vitamin D is synthesized in the skin when UV light converts 7-dehydrocholesterol to previtamin D3. This is then activated in the liver and kidneys. Many people are deficient due to limited sun exposure."},{"q":"A food label shows 20% DV for sodium. This means the food is:","opts":["Low in sodium","Moderate in sodium","High in sodium","Sodium-free"],"correct":2,"explain":"20% Daily Value or more means the food is HIGH in that nutrient. 5% DV or less = low. The %DV shows how much a nutrient in one serving contributes to a 2000-calorie daily diet."},{"q":"Omega-3 fatty acids are best obtained from which food source?","opts":["Red meat","White bread","Fatty fish (salmon, sardines)","Vegetable oils"],"correct":2,"explain":"Fatty fish like salmon, mackerel, sardines, and herring are the best sources of EPA and DHA — the most beneficial forms of omega-3 fatty acids. ALA omega-3 from flaxseed and walnuts must be converted and is less efficiently used."},{"q":"Which is an example of a complete protein?","opts":["White rice","Black beans","Eggs","Whole wheat bread"],"correct":2,"explain":"Eggs are a complete protein — they contain all 9 essential amino acids in adequate amounts. Most animal proteins (meat, dairy, eggs) are complete. Most plant proteins are incomplete but can be combined."},{"q":"What is fiber's primary benefit for digestive health?","opts":["Provides energy for digestion","Adds bulk to stool and feeds beneficial gut bacteria","Breaks down fat in the intestine","Absorbs water-soluble vitamins"],"correct":1,"explain":"Dietary fiber adds bulk to stool (preventing constipation) and feeds beneficial gut bacteria (prebiotic effect). Soluble fiber also lowers cholesterol and slows glucose absorption."},{"q":"Which B vitamin is essential for preventing neural tube defects in pregnancy?","opts":["Thiamin (B1)","Niacin (B3)","Folate (B9)","Cobalamin (B12)"],"correct":2,"explain":"Folate (vitamin B9) is critical for preventing neural tube defects like spina bifida. All women of childbearing age should consume 400mcg daily; pregnant women need 600mcg. Folic acid fortification in grains has reduced neural tube defects dramatically."},{"q":"What happens to excess water-soluble vitamins in the body?","opts":["Stored in fat tissue","Stored in the liver","Excreted in urine","Converted to fat-soluble vitamins"],"correct":2,"explain":"Excess water-soluble vitamins (vitamin C and all B vitamins) are excreted in urine since the body cannot store them. This is why they need to be consumed regularly, and why toxicity is rare (unlike fat-soluble vitamins)."},{"q":"Iron absorption is enhanced by consuming iron with which nutrient?","opts":["Calcium","Vitamin C","Vitamin D","Zinc"],"correct":1,"explain":"Vitamin C (ascorbic acid) significantly enhances non-heme iron absorption from plant foods. Consuming iron-rich plants with vitamin C sources (citrus juice, bell peppers) can double or triple iron absorption."},{"q":"What does BMI measure?","opts":["Body fat percentage precisely","Weight relative to height as a screening tool","Muscle mass and bone density","Metabolic rate"],"correct":1,"explain":"BMI (Body Mass Index) measures weight in kg divided by height in meters squared. It is a SCREENING tool, not a precise health measure. It cannot distinguish between muscle and fat mass."},{"q":"Which eating pattern is associated with the longest healthy lifespans?","opts":["High-protein diet","Ketogenic diet","Mediterranean diet","Low-fat diet"],"correct":2,"explain":"The Mediterranean diet — rich in olive oil, fish, vegetables, legumes, and whole grains — is consistently associated with the longest healthy lifespans and lowest rates of heart disease, diabetes, and cognitive decline in research studies."},{"q":"What is the function of insulin in nutrition?","opts":["Break down stored fat","Allow cells to absorb glucose from the blood","Convert protein to glucose","Signal hunger to the brain"],"correct":1,"explain":"Insulin is a pancreatic hormone that allows cells to take up glucose from the bloodstream, lowering blood sugar after meals. Type 1 diabetes: no insulin produced. Type 2: cells don't respond properly to insulin."},{"q":"How many glasses of water does the Institute of Medicine recommend for women daily?","opts":["4 glasses (1 liter)","6 glasses (1.5 liters)","9 glasses (2.2 liters)","13 glasses (3 liters)"],"correct":2,"explain":"The Institute of Medicine recommends about 9 cups (2.2 liters) of total water daily for women and 13 cups (3 liters) for men. This includes water from all beverages and food (about 20% of water comes from food)."},{"q":"Which condition results from inadequate protein intake in children?","opts":["Rickets","Kwashiorkor","Scurvy","Pellagra"],"correct":1,"explain":"Kwashiorkor results from protein deficiency (with adequate calories) in children — characterized by edema (fluid swelling, especially abdominal), growth failure, and fatty liver. Common in developing regions where weaned children receive starchy but protein-poor diets."},{"q":"The DASH diet was specifically designed to reduce:","opts":["Blood cholesterol","Blood pressure (hypertension)","Blood glucose (diabetes)","Body weight"],"correct":1,"explain":"DASH stands for Dietary Approaches to Stop Hypertension. It emphasizes fruits, vegetables, low-fat dairy, whole grains, and limits sodium. It reduces blood pressure by 8-14 mmHg — as effective as some blood pressure medications."},{"q":"Which vitamin is produced in skin when exposed to sunlight?","opts":["Vitamin A","Vitamin B12","Vitamin C","Vitamin D"],"correct":3,"explain":"Vitamin D is synthesized in the skin when ultraviolet B (UVB) rays from sunlight convert 7-dehydrocholesterol to vitamin D3. Many Americans are deficient, especially in northern latitudes, dark-skinned individuals, and those with limited sun exposure."},{"q":"What is the primary function of dietary fiber?","opts":["Provide sustained energy","Promote digestive health and reduce constipation","Build muscle tissue","Carry fat-soluble vitamins"],"correct":1,"explain":"Dietary fiber promotes digestive health by adding bulk to stool, preventing constipation, feeding beneficial gut bacteria, and slowing nutrient absorption. Insoluble fiber (wheat bran) promotes movement; soluble fiber (oats) lowers cholesterol and blood glucose."},{"q":"A registered dietitian nutritionist (RDN) is required to:","opts":["Have a medical degree (MD)","Complete a bachelor's degree, supervised practice, and pass a national exam","Only need a high school diploma and nutrition certification","Have a pharmacy license"],"correct":1,"explain":"RDNs must complete: a bachelor's degree (or higher) with approved coursework, 1,000+ hours supervised practice, and pass a national credentialing exam. They are the nutrition experts on healthcare teams and can provide medical nutrition therapy."},{"q":"The term 'empty calories' refers to foods that:","opts":["Have no calories at all","Are high in calories but low in nutrients (vitamins, minerals, fiber)","Are diet foods with artificial sweeteners","Have only protein calories"],"correct":1,"explain":"Empty calories provide energy (calories) but very few vitamins, minerals, fiber, or other beneficial nutrients. Examples include soda, candy, alcohol, and many processed snack foods. Limiting empty calories is key to nutrient-dense eating."},{"q":"Which nutrient is most important for preventing neural tube defects during pregnancy?","opts":["Iron","Calcium","Folate (folic acid)","Vitamin D"],"correct":2,"explain":"Folate (folic acid in supplement form) is critical for DNA synthesis during rapid cell division. Women who could become pregnant should take 400mcg/day BEFORE conception, as neural tube defects occur in the first 28 days — often before pregnancy is known."},{"q":"What does BMI stand for and what does it measure?","opts":["Body Mass Index — measures body fat percentage directly","Body Mass Index — weight-to-height ratio used to screen for weight categories","Body Metabolism Index — measures metabolic rate","Body Muscle Index — measures muscle mass"],"correct":1,"explain":"BMI = weight(kg) ÷ height(m)². It's a screening tool, not a direct measure of body fat. Categories: <18.5 underweight, 18.5-24.9 normal, 25-29.9 overweight, ≥30 obese. Limitation: doesn't account for muscle mass or fat distribution."},{"q":"Heme iron is better absorbed than non-heme iron. Which food contains heme iron?","opts":["Spinach","Fortified cereal","Beef (red meat)","Kidney beans"],"correct":2,"explain":"Heme iron is found only in animal foods (meat, poultry, fish). Non-heme iron is in plant foods and fortified foods. Heme iron absorption: 15-35%. Non-heme: 2-20%. Vitamin C significantly enhances non-heme iron absorption when eaten together."},{"q":"The MyPlate model recommends that fruits and vegetables should make up what portion of your plate?","opts":["One quarter","One third","One half","Three quarters"],"correct":2,"explain":"MyPlate recommends filling half your plate with fruits and vegetables. The other half is divided between grains (make at least half whole grains) and protein. Dairy (low-fat) is shown as a cup on the side. This replaced the complex food pyramid in 2011."},{"q":"Which type of fat is generally considered most harmful to heart health?","opts":["Monounsaturated fat","Polyunsaturated fat","Saturated fat","Omega-3 fatty acids"],"correct":2,"explain":"Saturated fat raises LDL ('bad') cholesterol, increasing heart disease risk. Found primarily in animal products (butter, fatty meat, full-fat dairy) and tropical oils (coconut, palm). Should be limited to <10% of total calories per Dietary Guidelines."},{"q":"What is the recommended daily water intake for most adults?","opts":["2-4 cups (500-1000mL)","4-6 cups (1-1.5L)","8-10 cups (2-2.5L)","15-20 cups (3.5-5L)"],"correct":2,"explain":"The general recommendation is about 8-10 cups (2-2.5 liters) per day, though individual needs vary based on activity, climate, body size, and health status. About 20% of water comes from food. Check urine color — pale yellow indicates good hydration."},{"q":"What is a complete protein?","opts":["A protein with more than 50 grams per serving","A protein containing all 9 essential amino acids","A protein that is 100% absorbed by the body","A protein from plant sources only"],"correct":1,"explain":"A complete protein contains all 9 essential amino acids in adequate amounts. Complete protein sources include: meat, poultry, fish, eggs, dairy, soy, and quinoa. Most plant proteins are incomplete (missing one or more essential amino acids) but can be complemented."},{"q":"The glycemic index ranks foods based on:","opts":["Their calorie content per serving","How quickly they raise blood glucose compared to pure glucose","Their total carbohydrate content","Their sugar content only"],"correct":1,"explain":"The glycemic index (GI) measures how quickly a carbohydrate food raises blood glucose compared to pure glucose (GI=100). High GI (>70): white bread, white rice. Low GI (<55): legumes, oats, most fruits. Fiber, fat, and protein lower the GI of a food."},{"q":"Which population group is most at risk for iron deficiency anemia?","opts":["Adult men","Children over age 12","Women of childbearing age and young children","Elderly men over 70"],"correct":2,"explain":"Women of childbearing age lose iron through menstruation and have higher needs during pregnancy. Young children have high iron needs for rapid growth and often limited dietary iron. Iron deficiency anemia is the most common nutritional deficiency worldwide."},{"q":"Omega-3 fatty acids are primarily found in:","opts":["Vegetable oils like corn and sunflower oil","Butter and animal fat","Fatty fish (salmon, sardines), flaxseed, and walnuts","Refined white flour products"],"correct":2,"explain":"EPA and DHA omega-3s are primarily in fatty fish (salmon, mackerel, sardines, herring). ALA omega-3 is in flaxseed, chia seeds, and walnuts. The American Heart Association recommends 2 servings of fatty fish per week for heart health benefits."},{"q":"What is food insecurity?","opts":["A fear or phobia about eating certain foods","Lack of reliable access to sufficient, affordable, nutritious food","Being allergic to many different foods","Difficulty digesting food properly"],"correct":1,"explain":"Food insecurity is defined as lack of consistent access to enough food for an active, healthy life. It affects about 1 in 10 American households. Food insecurity is associated with poor diet quality, obesity paradox, chronic disease, and mental health issues."},{"q":"Which cooking method best preserves water-soluble vitamins (like vitamin C and B vitamins)?","opts":["Boiling in large amounts of water","Deep frying","Steaming or microwaving with minimal water","Baking at high temperatures"],"correct":2,"explain":"Water-soluble vitamins leach into cooking water when boiled. Steaming or microwaving with minimal water preserves the most nutrients. If boiling, use the cooking water in soups or sauces to retain the vitamins that did leach out."},{"q":"What is the primary cause of type 2 diabetes?","opts":["The pancreas stops producing insulin completely","Cells become resistant to insulin over time","A viral infection destroys insulin-producing cells","Eating too much sugar directly causes it"],"correct":1,"explain":"Type 2 diabetes is primarily caused by insulin resistance — cells don't respond properly to insulin, so glucose can't enter cells and builds up in blood. The pancreas produces more insulin to compensate, eventually wearing out. Obesity and inactivity are major risk factors."},{"q":"What does 'fortification' mean in food production?","opts":["Adding preservatives to extend shelf life","Adding nutrients that weren't originally in the food to prevent deficiency","Removing harmful substances from food","Increasing the fiber content of processed foods"],"correct":1,"explain":"Fortification adds nutrients not originally present in a food to prevent deficiency diseases. Examples: iodine added to salt (prevents goiter), vitamin D added to milk (prevents rickets), folic acid added to grain products (prevents neural tube defects)."},{"q":"The WIC program provides nutrition support to which group?","opts":["Elderly adults over 65","Active military personnel and veterans","Low-income pregnant/breastfeeding women and children under 5","All low-income households"],"correct":2,"explain":"WIC (Women, Infants, and Children) is a federal program serving low-income pregnant/breastfeeding women, infants, and children up to age 5. It provides supplemental foods, nutrition education, breastfeeding support, and healthcare referrals. Currently serves ~6.7 million people/month."},{"q":"Which nutrient is essential for iron absorption and also boosts immune function?","opts":["Calcium","Vitamin C","Zinc","Vitamin A"],"correct":1,"explain":"Vitamin C (ascorbic acid) enhances non-heme iron absorption from plant foods and fortified foods by converting iron to a more absorbable form. Drinking orange juice with iron-rich plant foods or fortified cereals significantly improves iron absorption. Vitamin C also supports immune function."},{"q":"What is the role of cholesterol in the body?","opts":["It only causes harm and has no positive functions","It builds cell membranes, produces hormones, and helps make vitamin D","It is the main energy storage molecule in fat cells","It directly causes heart attacks in all people who consume it"],"correct":1,"explain":"Despite its reputation, cholesterol is essential: it's a structural component of all cell membranes, a precursor to steroid hormones (estrogen, testosterone, cortisol), needed to make bile acids for fat digestion, and converted to vitamin D in skin. Problems arise when LDL levels are too high."},{"q":"Which dietary pattern is associated with the longest life expectancy and lowest chronic disease rates?","opts":["High-protein, low-carbohydrate diet","Western diet (high processed food, sugar, red meat)","Mediterranean diet","Strict calorie restriction diet"],"correct":2,"explain":"The Mediterranean diet is associated with the most consistent evidence for longevity and reduced chronic disease. Key components: abundant vegetables, fruits, whole grains, legumes, nuts, olive oil; moderate fish and poultry; limited red meat; moderate wine. Rich in fiber, healthy fats, and antioxidants."},{"q":"What does 'nutrient density' mean?","opts":["The concentration of sugar in a food","The ratio of beneficial nutrients to total calories in a food","The number of different vitamins in one serving","The thickness or heaviness of a food"],"correct":1,"explain":"Nutrient density describes how many beneficial nutrients (vitamins, minerals, fiber, protein) a food provides relative to its calorie content. Spinach is very nutrient-dense (many nutrients, few calories). Soda is low nutrient density (calories, no nutrients). Choose nutrient-dense foods to meet needs within calorie budget."},{"q":"A teenager who avoids all animal products (vegan) should be especially careful to get enough:","opts":["Vitamin C and folate — only found in animal products","Vitamin B12 and iron — harder to get from plant foods","Calcium and vitamin A — cannot be obtained from plants","Carbohydrates — plants are low in carbohydrates"],"correct":1,"explain":"Vitamin B12 is found almost exclusively in animal products — vegans must supplement or eat fortified foods. Non-heme iron from plants is less absorbed than heme iron from meat. Other nutrients to watch: omega-3, calcium, zinc, vitamin D, iodine. A well-planned vegan diet is healthy but requires attention."},{"q":"Which vitamin must be supplemented by all vegans because it is found ONLY in animal products?","opts":["Vitamin C","Vitamin B12","Vitamin E","Vitamin K"],"correct":1,"explain":"Vitamin B12 is found exclusively in animal products (meat, fish, dairy, eggs). Vegans who do not supplement B12 will develop deficiency, which can cause irreversible nerve damage and megaloblastic anemia. All vegans should supplement 2.4mcg B12 daily."},{"q":"What is the PRIMARY danger of trans fat compared to other fats?","opts":["It provides too many calories","It raises LDL AND lowers HDL simultaneously — worst of both","It causes immediate allergic reactions","It is stored differently than other fats"],"correct":1,"explain":"Trans fat uniquely raises LDL ('bad') cholesterol AND lowers HDL ('good') cholesterol simultaneously. This double harm is worse than saturated fat (which only raises LDL). The FDA banned artificial trans fats from the US food supply in 2018."},{"q":"Vitamin D is called the 'sunshine vitamin' because:","opts":["It is yellow like the sun","Skin produces it when exposed to UV-B radiation","It increases energy levels during daytime","It is destroyed by sunlight in foods"],"correct":1,"explain":"Skin synthesizes vitamin D3 from cholesterol when exposed to UV-B radiation. The amount produced depends on latitude, season, skin color, sunscreen use, and time spent outdoors. Many people need supplementation because sun exposure is inadequate."},{"q":"Iron absorption from plant foods (non-heme iron) is best enhanced by:","opts":["Taking it with dairy products","Eating it with foods rich in vitamin C","Taking it with calcium supplements","Cooking in iron cookware only"],"correct":1,"explain":"Vitamin C (ascorbic acid) converts non-heme iron from Fe3+ to Fe2+, the form that can be absorbed. For example, drinking orange juice with iron-fortified cereal significantly improves iron absorption. Calcium, tea, and coffee inhibit iron absorption."},{"q":"What does 20% DV (Daily Value) for sodium on a food label tell you?","opts":["The food has 20g of sodium","The food provides 20% of the 2,000 calorie daily diet","The food is high in sodium — 20% DV or more means high","The food was tested in 20 different labs"],"correct":2,"explain":"The FDA guideline: 5% DV or less = low in that nutrient; 20% DV or more = HIGH in that nutrient. For nutrients to LIMIT (sodium, saturated fat, added sugars), 20% DV means the food is high and should be chosen carefully."},{"q":"Which food group is MOST important for providing iron to teenage girls who have started menstruation?","opts":["Dairy products","Fruits","Iron-rich foods (lean meat, beans, fortified cereals)","Grain products only"],"correct":2,"explain":"Teenage girls need 15mg of iron daily — the highest of any life stage for females. Menstrual blood loss significantly increases iron needs. Iron-rich foods (lean red meat, beans, lentils, fortified cereals, spinach with vitamin C) are essential to prevent iron-deficiency anemia."},{"q":"What is the difference between hunger and appetite?","opts":["They are the same thing","Hunger is physiological need for food; appetite is psychological desire for food","Appetite is physiological; hunger is psychological","Hunger only occurs in children; appetite in adults"],"correct":1,"explain":"Hunger is a physiological signal — driven by hormones (ghrelin rises when stomach is empty, blood glucose falls). Appetite is psychological — influenced by emotions, food availability, social cues, memories, and the sight/smell of food. Understanding this difference helps with mindful eating."},{"q":"Complementary proteins are important for plant-based diets because:","opts":["Plant proteins have more calories","Most plant proteins are 'incomplete' — missing some essential amino acids — combining them provides all essential AAs","Plant proteins digest too slowly alone","Complementary proteins reduce cholesterol better"],"correct":1,"explain":"Most plant proteins lack one or more essential amino acids. Combining complementary proteins ensures all 9 essential amino acids are available. Examples: rice + beans, peanut butter + whole wheat bread, hummus + pita. They don't need to be eaten at the same meal."},{"q":"A person is told to eat more 'nutrient-dense' foods. This means choosing foods that:","opts":["Have the most calories per serving","Provide the most nutrients relative to their calorie content","Are fresh rather than frozen or canned","Come in the largest package sizes"],"correct":1,"explain":"Nutrient-dense foods provide a high amount of vitamins, minerals, protein, and/or fiber relative to their calorie content. Examples: leafy greens, eggs, salmon, berries, legumes. 'Empty calorie' foods (soda, chips) provide calories with few nutrients."},{"q":"What percentage of the MyPlate should be fruits and vegetables combined?","opts":["25%","50%","75%","100% — all fruits and vegetables"],"correct":1,"explain":"MyPlate recommends half the plate (50%) be fruits and vegetables. The remaining half is divided between grains (25%) and protein foods (25%), with a small amount of dairy on the side. This visual guide replaced the Food Pyramid in 2011."},{"q":"Which is the most accurate description of dietary fiber?","opts":["A type of digestible carbohydrate that provides energy","Indigestible plant carbohydrate that feeds gut bacteria and promotes digestive health","A protein found in plant foods that reduces cholesterol","A vitamin-like substance found in whole grains"],"correct":1,"explain":"Dietary fiber is plant carbohydrate that human enzymes cannot digest. Soluble fiber (oats, beans) lowers cholesterol and slows glucose absorption. Insoluble fiber (wheat bran) adds bulk and promotes bowel regularity. Both feed beneficial gut bacteria. Adults need 25-38g daily."},{"q":"A teenager has been eating very few fruits and vegetables and develops fatigue, bruising easily, and small hemorrhages around hair follicles. Which deficiency is most likely?","opts":["Iron deficiency","Vitamin C deficiency causing early scurvy","Vitamin D deficiency","Calcium deficiency"],"correct":1,"explain":"Perifollicular hemorrhages (bleeding around hair follicles), easy bruising, and fatigue are classic signs of vitamin C deficiency (early scurvy). Vitamin C is essential for collagen synthesis — without it, blood vessel walls weaken. Sources: citrus, bell peppers, strawberries, broccoli."},{"q":"Which eating pattern has the strongest evidence for reducing cardiovascular disease risk?","opts":["Ketogenic (very low carb) diet","Mediterranean diet","High-protein Atkins diet","Paleolithic (Paleo) diet"],"correct":1,"explain":"The Mediterranean diet has the strongest, most consistent evidence base for cardiovascular disease prevention (PREDIMED trial, multiple meta-analyses). It emphasizes olive oil, vegetables, fruits, whole grains, legumes, fish, nuts, and moderate wine, with limited red meat and sweets."},{"q":"How long does it take for satiety signals to reach the brain after starting a meal?","opts":["1-2 minutes","5-10 minutes","20 minutes","45-60 minutes"],"correct":2,"explain":"It takes approximately 20 minutes for satiety hormones (CCK, GLP-1, PYY) and blood glucose changes to register in the hypothalamus. This is why eating slowly and mindfully reduces overeating — you give your body time to register fullness before eating excess food."},{"q":"Fortification of foods means:","opts":["Removing harmful substances from food","Adding nutrients that were not naturally present or were lost in processing","Increasing the caloric density of food","Preserving food with chemicals"],"correct":1,"explain":"Fortification adds nutrients to foods that weren't originally there (or were present in very small amounts). Examples: vitamin D and calcium in orange juice, iodine in salt, vitamins A and D in milk, B vitamins and iron in enriched grains. Enrichment restores nutrients lost in processing."},{"q":"What makes whole grains healthier than refined grains?","opts":["They have more calories","They retain the bran and germ which contain fiber, vitamins, minerals, and phytochemicals","They are easier to digest","They are naturally lower in sodium"],"correct":1,"explain":"Whole grains contain all three parts: bran (fiber, B vitamins, minerals), germ (vitamins E, B, antioxidants, healthy fats), and endosperm (mostly starch). Refining removes the bran and germ, leaving mostly starch. Enriched grains add back some B vitamins and iron but not fiber or other nutrients."},{"q":"A vegan athlete needs to ensure adequate intake of which nutrient for energy production and oxygen transport?","opts":["Omega-6 fatty acids","Iron — particularly important from plant sources combined with vitamin C","Vitamin A from plants","Sodium and chloride"],"correct":1,"explain":"Iron is critical for oxygen transport (hemoglobin) and energy production (electron transport chain). Vegan athletes have higher iron needs because non-heme plant iron absorbs poorly. Strategies: eat iron-rich plants (lentils, beans, tofu, fortified cereals) with vitamin C sources at every meal."},{"q":"What is the recommended daily sodium limit for most adults according to the Dietary Guidelines for Americans?","opts":["1000mg","1500mg","2300mg","3400mg (current average intake is fine)"],"correct":2,"explain":"The 2020-2025 Dietary Guidelines recommend limiting sodium to <2300mg per day (about 1 teaspoon of salt). The DASH diet recommends an even lower limit of 1500mg for maximum blood pressure benefit. Current average American intake is about 3400mg per day."},{"q":"A food label shows '0g trans fat' but the ingredients list includes 'partially hydrogenated oil.' What does this mean?","opts":["The product has no trans fat at all — the label is correct","The product may contain up to 0.5g trans fat per serving — the label can legally round down to 0","The ingredients list is wrong and the label is right","Partially hydrogenated oil is the same as olive oil"],"correct":1,"explain":"FDA labeling law allows products to claim '0g trans fat' if they contain less than 0.5g per serving. 'Partially hydrogenated oil' IS trans fat. Multiple servings can add up to significant trans fat intake. Choose products without partially hydrogenated oils in the ingredient list entirely."},{"q":"The glycemic index (GI) ranks foods based on:","opts":["Total carbohydrate content per serving","How quickly they raise blood glucose compared to pure glucose","Their calorie content per gram","Their fiber content relative to carbs"],"correct":1,"explain":"The glycemic index ranks foods 0-100 based on how rapidly they raise blood glucose compared to pure glucose (GI=100). Low GI (<55): oats, legumes, most fruits. Medium (56-69): whole wheat bread. High (≥70): white bread, white rice, potatoes. Processing, ripeness, and food combinations all affect GI."},{"q":"Which population group has the HIGHEST calcium requirement?","opts":["Adults 19-50 years","Infants under 1 year","Teenagers 9-18 years","Adults over 70 years"],"correct":2,"explain":"Teenagers 9-18 years need 1300mg calcium daily — the highest of any life stage. This is because this period is critical for building peak bone mass. By age 30, 90% of peak bone mass is achieved. Adequate calcium during adolescence significantly reduces osteoporosis risk decades later."},{"q":"What is 'food insecurity'?","opts":["Being afraid of unfamiliar foods","Lack of consistent access to enough food for an active, healthy life","Having food allergies that limit choices","Uncertainty about whether food is safe to eat"],"correct":1,"explain":"Food insecurity is defined as limited or uncertain availability of nutritionally adequate and safe foods, or limited ability to acquire acceptable foods in socially acceptable ways. It affects 10-15% of US households and is associated with obesity, diabetes, poor mental health, and developmental problems in children."},{"q":"Omega-3 fatty acids EPA and DHA are primarily found in:","opts":["Vegetable oils like corn and sunflower","Fatty fish like salmon, mackerel, and sardines","Nuts and seeds","Fortified orange juice"],"correct":1,"explain":"EPA (eicosapentaenoic acid) and DHA (docosahexaenoic acid) are the active omega-3s found primarily in fatty fish. ALA (alpha-linolenic acid) in plant foods (flaxseed, walnuts) can be converted to EPA/DHA but only 5-10% efficiency. Aim for 2 servings fatty fish per week for adequate omega-3 intake."}]);
  qz.medium=qz.medium.concat([{"q":"Which lipoprotein is known as 'bad' cholesterol because it deposits cholesterol in artery walls?","opts":["HDL","VLDL","LDL","Chylomicrons"],"correct":2,"explain":"LDL (Low-Density Lipoprotein) carries cholesterol from the liver to cells and can deposit it in artery walls, forming plaques (atherosclerosis). LDL < 100 mg/dL is optimal. Saturated and trans fats raise LDL."},{"q":"Which vitamin deficiency causes pellagra, characterized by the 4 D's?","opts":["Thiamin (B1)","Riboflavin (B2)","Niacin (B3)","Pyridoxine (B6)"],"correct":2,"explain":"Niacin (B3) deficiency causes pellagra — Dermatitis, Diarrhea, Dementia, and Death (the 4 D's). Common where corn-based diets dominate without traditional nixtamalization process. Tryptophan can be converted to niacin."},{"q":"What is the thermic effect of food?","opts":["Temperature increase from eating hot food","Energy used to digest, absorb, and metabolize food (about 10% of calories)","Calories burned during cooking","Heat generated during food storage"],"correct":1,"explain":"The thermic effect of food (TEF) is the energy required to digest, absorb, and metabolize nutrients — about 10% of total energy intake. Protein has the highest TEF (20-30%), making high-protein diets slightly more metabolically costly."},{"q":"A patient has iron-deficiency anemia. Which food combination would BEST improve iron absorption?","opts":["Iron supplement with milk","Spinach salad with lemon dressing and vitamin C-rich bell peppers","Red meat with coffee","Iron-fortified cereal with tea"],"correct":1,"explain":"Spinach (non-heme iron) with bell peppers and lemon dressing provides vitamin C, which dramatically enhances non-heme iron absorption. Coffee and tea contain tannins that INHIBIT iron absorption. Calcium in milk can also reduce iron absorption."},{"q":"What is glycogen, and where is it stored?","opts":["Fat storage in adipose tissue","Glucose storage in liver and muscles","Protein storage in organ tissue","Cholesterol storage in the gallbladder"],"correct":1,"explain":"Glycogen is the storage form of glucose in the body — long chains of glucose molecules. About 100g stored in liver (to maintain blood glucose) and 300-400g in muscles (for local energy use). Depleted after 12-18 hours of fasting."},{"q":"The DASH diet was specifically designed to address which health condition?","opts":["Type 2 diabetes","Osteoporosis","Hypertension (high blood pressure)","Celiac disease"],"correct":2,"explain":"DASH (Dietary Approaches to Stop Hypertension) was designed to reduce blood pressure without medication. It emphasizes fruits, vegetables, low-fat dairy, whole grains, and limits sodium, saturated fat, and added sugars."},{"q":"What distinguishes celiac disease from gluten sensitivity?","opts":["Celiac is less severe","Celiac is an autoimmune condition that damages intestinal villi; gluten sensitivity is not","Gluten sensitivity requires stricter avoidance","They are identical conditions"],"correct":1,"explain":"Celiac disease is an autoimmune reaction where gluten triggers the immune system to attack and damage the small intestine's villi, impairing nutrient absorption. Non-celiac gluten sensitivity causes symptoms without the autoimmune intestinal damage."},{"q":"Which hormone signals satiety (fullness) to the brain?","opts":["Ghrelin","Glucagon","Leptin","Cortisol"],"correct":2,"explain":"Leptin is produced by fat cells and signals the brain (hypothalamus) that energy stores are sufficient — suppressing hunger. Ghrelin is the 'hunger hormone' that increases before meals. In obesity, leptin resistance can develop."},{"q":"What is nutrient density?","opts":["The weight of nutrients in a food","The number of different nutrients in a food","The amount of nutrients relative to a food's calorie content","The concentration of minerals in water"],"correct":2,"explain":"Nutrient density measures the amount of beneficial nutrients (vitamins, minerals, protein, fiber) per calorie. A highly nutrient-dense food provides many nutrients with few calories (kale, salmon). Low nutrient density = many calories, few nutrients (soda, candy)."},{"q":"Which macronutrient is most important for wound healing and tissue repair?","opts":["Carbohydrates","Fat","Protein","Vitamins"],"correct":2,"explain":"Protein is most critical for wound healing — amino acids are the building blocks for new tissue, collagen synthesis, and immune cells. Vitamin C also plays a role in collagen formation. Adequate protein intake is essential after surgery or injury."},{"q":"What is the main function of bile in fat digestion?","opts":["Break down fat chemically","Emulsify fat into small droplets for enzyme access","Absorb fat-soluble vitamins","Transport fat in the blood"],"correct":1,"explain":"Bile (produced by the liver, stored in the gallbladder) emulsifies fat — breaking large fat globules into tiny droplets, increasing surface area for pancreatic lipase to work. Bile does not chemically digest fat; lipase does."},{"q":"Excessive consumption of vitamin A (preformed retinol) can cause:","opts":["Scurvy","Goiter","Toxicity — liver damage, birth defects","Pellagra"],"correct":2,"explain":"Vitamin A (preformed retinol from animal sources/supplements) is fat-soluble and stored in the liver. Excess causes hypervitaminosis A — liver damage, bone pain, birth defects. Beta-carotene (plant form) cannot cause toxicity as the body regulates conversion."},{"q":"Which fatty acid type is essential (must be obtained from diet) for human health?","opts":["Saturated fatty acids","Monounsaturated fatty acids","Linoleic acid (omega-6) and alpha-linolenic acid (omega-3)","All fatty acids are essential"],"correct":2,"explain":"Linoleic acid (omega-6) and alpha-linolenic acid (omega-3) are the two essential fatty acids — the body cannot synthesize them. All other fatty acids can be made from these or from acetyl-CoA."},{"q":"What is the primary role of the large intestine in nutrition?","opts":["Protein digestion","Fat absorption","Water absorption and gut bacteria fermentation of fiber","Vitamin synthesis"],"correct":2,"explain":"The large intestine (colon) absorbs water and electrolytes from indigestible food residue. Resident gut bacteria ferment dietary fiber, producing short-chain fatty acids that nourish colonocytes and reduce cancer risk. No significant nutrient absorption occurs here."},{"q":"A teenage athlete needs more of which nutrient compared to a sedentary peer?","opts":["Fat","Vitamin C","Protein and overall calories","Sodium"],"correct":2,"explain":"Active teens need more total calories to fuel activity and more protein to support muscle repair and growth. Iron needs also increase for female athletes. Energy needs vary by sport intensity and training volume."},{"q":"Which condition results from excessive fluoride intake during tooth development?","opts":["Dental caries","Dental fluorosis (white spots/mottling on teeth)","Gingivitis","Enamel erosion from acid"],"correct":1,"explain":"Dental fluorosis occurs when children ingest too much fluoride during tooth development — causing white spots, streaks, or pitting on permanent teeth. Low levels are cosmetic only. Fluoride in water prevents caries; excess causes fluorosis."},{"q":"What is the 'thermic effect of food' for protein compared to carbohydrates?","opts":["Lower (0-3%) vs higher (5-10%)","Higher (20-30%) vs lower (5-10%)","The same for both (10%)","Protein has no thermic effect"],"correct":1,"explain":"Protein has a thermic effect of 20-30% — meaning 20-30% of protein calories are burned just in digestion and metabolism. Carbohydrates have a 5-10% thermic effect. This is one reason high-protein diets may aid weight management."},{"q":"Which test best assesses long-term blood glucose control over 2-3 months?","opts":["Fasting blood glucose","Oral glucose tolerance test","Hemoglobin A1c (HbA1c)","Random blood glucose"],"correct":2,"explain":"HbA1c (glycated hemoglobin) reflects average blood glucose over the past 2-3 months — the lifespan of red blood cells. Used to diagnose and monitor diabetes management. Normal: <5.7%; Prediabetes: 5.7-6.4%; Diabetes: ≥6.5%"},{"q":"What is the role of phytochemicals in nutrition?","opts":["They are essential nutrients like vitamins","Non-essential plant compounds with disease-preventive properties","They replace protein in plant-based diets","They are toxic when consumed in large amounts"],"correct":1,"explain":"Phytochemicals are non-nutrient plant compounds (lycopene, flavonoids, glucosinolates, etc.) that have health-protective properties but are not nutritionally essential. They function as antioxidants, anti-inflammatory agents, and cancer-protective compounds."},{"q":"A patient has a BMI of 32, hypertriglyceridemia, low HDL, elevated blood pressure, and elevated fasting glucose. This is consistent with:","opts":["Iron deficiency anemia","Metabolic syndrome","Vitamin D deficiency","Celiac disease"],"correct":1,"explain":"Metabolic syndrome requires 3 of 5 criteria: (1) abdominal obesity (waist >40in men, >35in women), (2) triglycerides ≥150, (3) HDL <40 men/<50 women, (4) blood pressure ≥130/85, (5) fasting glucose ≥100. It dramatically increases cardiovascular disease and type 2 diabetes risk."},{"q":"A breastfed infant of a strict vegan mother is most at risk for deficiency of which nutrient?","opts":["Vitamin C","Calcium","Vitamin B12","Zinc"],"correct":2,"explain":"Vitamin B12 is found almost exclusively in animal products. A vegan mother's breast milk will have very low B12 if she doesn't supplement. B12 deficiency in infants causes: irreversible neurological damage, developmental delays, failure to thrive. Vegan breastfeeding mothers must supplement B12."},{"q":"A patient is recovering from surgery and needs maximum support for wound healing. Which nutrient combination is MOST critical?","opts":["Carbohydrates and fat for energy only","Vitamin C, zinc, protein, and adequate calories","Iron and calcium only","B vitamins and magnesium only"],"correct":1,"explain":"Wound healing requires: adequate calories (prevent catabolism), protein 1.5-2g/kg/day (collagen synthesis, tissue repair), vitamin C (collagen cross-linking, antioxidant), and zinc (cell proliferation, enzyme function). Arginine also enhances wound healing. Malnutrition significantly impairs healing."},{"q":"The PDCAAS score of 1.0 is the highest possible protein quality score. Which food scores 1.0?","opts":["Wheat bread","Kidney beans","Beef","Egg white"],"correct":3,"explain":"Foods scoring PDCAAS of 1.0 (highest quality): egg white, milk/casein, whey protein, and soy protein. They contain all 9 essential amino acids in adequate amounts AND are highly digestible. Beef scores ~0.92, wheat ~0.40. PDCAAS = Protein Digestibility Corrected Amino Acid Score."},{"q":"A dialysis patient is advised to limit potassium, phosphorus, and sodium while maintaining adequate protein intake. What type of diet is this?","opts":["Anti-inflammatory diet","Renal (kidney disease) diet","DASH diet","Cancer diet"],"correct":1,"explain":"The renal diet restricts potassium, phosphorus, sodium, and often fluid because damaged kidneys cannot filter these adequately. Despite restriction, adequate protein is important (1.2g/kg for dialysis patients) because dialysis removes protein. RDN individualization is essential as needs vary by disease stage."},{"q":"Kwashiorkor is caused by a deficiency of which macronutrient and is characterized by which distinctive sign?","opts":["Fat deficiency — extreme thinness","Carbohydrate deficiency — high blood glucose","Protein deficiency — edema (fluid retention), particularly in the abdomen","Vitamin deficiency — skin lesions and hair loss"],"correct":2,"explain":"Kwashiorkor = severe protein deficiency, often occurring when a child is weaned onto a carbohydrate-only diet. Low serum albumin → fluid leaks from blood vessels → edema (swelling), especially in abdomen (pot belly). Hair may lose color, become brittle. Often with adequate or excess calories."},{"q":"A patient reports eating a diet high in oxalate-rich foods (spinach, nuts) and experiencing recurrent kidney stones. The BEST nutritional advice is to:","opts":["Avoid all calcium-rich foods to reduce calcium oxalate stones","Increase dietary calcium intake with meals (binds oxalate in gut) and limit sodium","Eliminate all protein to reduce uric acid","Increase vitamin C supplements to flush the kidneys"],"correct":1,"explain":"Counterintuitively, INCREASING dietary calcium actually reduces calcium oxalate kidney stone risk: calcium binds oxalate IN THE GUT, preventing absorption and excretion in urine. Also: limit sodium (increases calcium excretion), stay hydrated, and moderate oxalate intake. High vitamin C can increase oxalate — don't supplement."},{"q":"The glycemic load (GL) is considered more useful than glycemic index (GI) alone because:","opts":["GL is easier to calculate than GI","GL accounts for both the quality (GI) AND quantity of carbohydrate in a serving","GL measures fat content, not just carbs","GL is always lower than GI for any given food"],"correct":1,"explain":"GL = (GI × grams of carbohydrate) ÷ 100. Watermelon has a high GI (~72) but low GL (~4) because a standard serving contains very little carbohydrate. A small portion of high-GI food may have similar blood glucose impact to a large portion of low-GI food. GL gives the full picture."},{"q":"A patient on warfarin (blood thinner) should be counseled to maintain consistent intake of which vitamin?","opts":["Vitamin C","Vitamin D","Vitamin K","Vitamin E"],"correct":2,"explain":"Vitamin K is essential for synthesis of blood clotting factors. Warfarin works by blocking vitamin K's action. Sudden increases in vitamin K (from eating more leafy greens) can decrease warfarin's effectiveness; decreases can cause dangerous over-anticoagulation. Consistency is key — don't avoid vitamin K, just keep intake stable."},{"q":"Refeeding syndrome is a potentially fatal complication. It occurs when:","opts":["A healthy person overeats at one meal","A severely malnourished person receives rapid nutritional repletion, especially carbohydrates","A patient eats too much protein after surgery","Someone drinks too much water during exercise"],"correct":1,"explain":"Refeeding syndrome: when severely malnourished patients receive rapid carbohydrate/calories, insulin surges → massive cellular uptake of phosphorus, potassium, magnesium from blood → dangerously low serum levels → cardiac arrhythmia, respiratory failure, seizures, death. Prevention: start slowly, monitor electrolytes closely, supplement phosphorus."},{"q":"Short-chain fatty acids (SCFAs) like butyrate are primarily produced by:","opts":["Digestion of dietary fat in the small intestine","Gut bacteria fermenting dietary fiber in the large intestine","The liver from excess carbohydrates","Kidneys filtering the blood"],"correct":1,"explain":"SCFAs (acetate, propionate, butyrate) are produced when colonic bacteria ferment dietary fiber (prebiotics). Butyrate is the primary fuel for colonocytes (colon cells). SCFAs reduce inflammation, improve insulin sensitivity, strengthen the gut barrier, and may protect against colorectal cancer. More fiber = more SCFAs."},{"q":"A patient with celiac disease on a strict gluten-free diet continues to have symptoms. The MOST likely cause is:","opts":["The gluten-free diet itself is causing new symptoms","Cross-contamination or hidden gluten in foods","Too much fiber in the diet","Vitamin supplementation causing reactions"],"correct":1,"explain":"Even tiny amounts of gluten (as little as 20 ppm) can trigger immune response in celiac disease. Hidden gluten sources: soy sauce, malt vinegar, beer, medications, shared cooking equipment/toasters. Cross-contamination at restaurants is common. Ongoing symptoms despite 'gluten-free' diet require detailed diet history."},{"q":"Relative Energy Deficiency in Sport (RED-S) affects athletes who:","opts":["Consume too many calories relative to training","Have insufficient energy availability (intake vs expenditure) impairing health and performance","Only train for aesthetic sports like gymnastics","Only affects female athletes (formerly called female athlete triad)"],"correct":1,"explain":"RED-S occurs when energy intake doesn't cover energy expenditure plus basal physiological needs. Consequences: menstrual dysfunction, bone stress fractures, impaired immunity, cardiovascular changes, and decreased performance. Affects male AND female athletes in any sport. Treatment: increase energy intake, often requires multidisciplinary team."},{"q":"Why might a patient with chronic kidney disease (CKD) be advised to limit dietary protein?","opts":["Protein causes directly kidney damage by entering the kidneys","Protein metabolism produces nitrogen waste products (urea) that damaged kidneys cannot adequately excrete","Protein makes the blood too thick for damaged kidneys to filter","All CKD patients need more protein, not less"],"correct":1,"explain":"Protein catabolism produces nitrogen-containing waste (urea, creatinine). Damaged kidneys cannot adequately filter these, leading to uremia (toxic buildup). Low-protein diets (0.6-0.8g/kg for non-dialysis CKD) reduce uremic burden and may slow disease progression. Dialysis patients actually need MORE protein (1.2g/kg) because dialysis removes it."},{"q":"A patient is admitted with symptoms of fatigue, weakness, pale skin, and a mean corpuscular volume (MCV) above normal (macrocytic anemia). This pattern is MOST consistent with deficiency of:","opts":["Iron","Vitamin C","Folate or vitamin B12","Zinc"],"correct":2,"explain":"Macrocytic anemia (large, immature red blood cells = high MCV) results from impaired DNA synthesis. Both folate and B12 are essential for DNA synthesis. Distinguishing them: B12 deficiency also causes neurological symptoms (numbness, gait problems). Folate deficiency does not cause neurological damage. Iron deficiency causes microcytic (small cell) anemia."},{"q":"A clinical dietitian calculating a hospitalized patient's energy needs would most accurately use:","opts":["The simple 25 kcal/kg rule for all patients","Indirect calorimetry (measuring O2 consumption and CO2 production) or validated predictive equations like Mifflin-St. Jeor","The patient's reported calorie intake at home","Multiplying height by weight"],"correct":1,"explain":"Indirect calorimetry is the gold standard for measuring resting metabolic rate in clinical settings. When not available, validated predictive equations (Mifflin-St. Jeor, Penn State for critical illness) with appropriate activity/stress factors are used. Simple rules (25 kcal/kg) are quick estimates, not individualized. Critical illness dramatically changes needs."},{"q":"The MIND diet (Mediterranean-DASH Diet Intervention for Neurodegenerative Delay) specifically emphasizes which foods for brain health?","opts":["High animal protein and saturated fat","Green leafy vegetables, other vegetables, berries, nuts, whole grains, fish, poultry, olive oil, and wine (moderate)","Dairy products and fortified foods primarily","Supplements and functional foods only"],"correct":1,"explain":"The MIND diet combines Mediterranean and DASH principles with specific emphasis on brain-protective foods: leafy greens (6+ servings/week), berries (especially blueberries, 2+/week), nuts, whole grains, fish (1+/week), poultry (2+/week), beans (4+/week), olive oil, and limited wine. Associated with 35-53% reduced Alzheimer's risk."},{"q":"A patient with iron-deficiency anemia is prescribed iron supplements. Which combination is CORRECT for maximizing absorption?","opts":["Iron supplement + glass of milk + calcium supplement","Iron supplement + orange juice (vitamin C) + taken on empty stomach or with small meal","Iron supplement + green tea + high-fiber meal","Iron supplement + antacid to reduce GI upset"],"correct":1,"explain":"Iron absorption is maximized by: (1) taking with vitamin C (converts Fe3+ to absorbable Fe2+), (2) taking on empty stomach or with small meal (reduces but doesn't eliminate absorption), (3) avoiding calcium, tea, coffee, and antacids which inhibit absorption. Orange juice is ideal."},{"q":"A patient develops symmetrical dermatitis on sun-exposed areas, diarrhea, and dementia. Which deficiency is most likely?","opts":["Vitamin B12","Vitamin C","Niacin (B3) — pellagra","Vitamin A"],"correct":2,"explain":"Pellagra: the 4 Ds — Dermatitis (photosensitive, symmetrical on sun-exposed skin), Diarrhea, Dementia (depression, confusion, ultimately psychosis), and Death if untreated. Caused by niacin (B3) deficiency. Historically seen in corn-based diets because corn niacin is bound and unavailable. Treatment: niacin supplementation."},{"q":"A 16-year-old female athlete with restricted eating has stopped menstruating. She reports stress fractures. Which condition best describes this?","opts":["Normal in female athletes — nothing to worry about","Female Athlete Triad — or Relative Energy Deficiency in Sport (RED-S) — requires immediate intervention","Simple anemia from low iron intake","Growth-related bone changes that resolve on their own"],"correct":1,"explain":"Relative Energy Deficiency in Sport (RED-S), formerly called the Female Athlete Triad: low energy availability → menstrual dysfunction → decreased bone density → stress fractures. This is a medical emergency. Without intervention, bone loss may be irreversible. Requires team: physician, RD, sports psychologist."},{"q":"A dialysis patient is advised to limit potassium and phosphorus. Why does phosphorus restriction apply despite adequate dietary protein?","opts":["Phosphorus and protein always appear together in foods","Damaged kidneys cannot excrete phosphorus → accumulates → pulls calcium from bones, causes cardiovascular calcification","Phosphorus causes kidney damage directly","Dialysis removes phosphorus so restriction is unnecessary"],"correct":1,"explain":"Healthy kidneys efficiently excrete phosphorus. In CKD, phosphorus accumulates, triggering parathyroid hormone release which pulls calcium from bones (renal osteodystrophy) and deposits in blood vessels and organs (vascular calcification). Phosphorus binders are taken with meals to limit absorption."},{"q":"A patient starts a ketogenic diet (<50g carbs/day). After several days they develop 'keto flu' — fatigue, headache, nausea. What is the PRIMARY nutritional cause?","opts":["Too much dietary fat causing nausea","Electrolyte losses (sodium, potassium, magnesium) as kidneys excrete more in response to low insulin from low-carb diet","Protein toxicity from high protein intake","Vitamin deficiency from eliminating grains"],"correct":1,"explain":"When carbohydrates are restricted, insulin drops. Low insulin causes kidneys to excrete more sodium (and with it, water, potassium, and magnesium). This electrolyte depletion causes 'keto flu.' Treatment: increase sodium, potassium, and magnesium intake through food or supplements during adaptation."},{"q":"A breastfed infant of a strict vegan mother develops neurological symptoms at 4 months. The most likely nutritional cause is:","opts":["Low fat intake from breast milk","Vitamin B12 deficiency — breast milk B12 reflects maternal status — vegans must supplement","Protein deficiency from plant-based diet","Iron deficiency from maternal diet"],"correct":1,"explain":"Breast milk B12 concentration directly reflects maternal B12 status. Vegan mothers with adequate B12 supplementation have adequate breast milk B12. Without supplementation, infants can develop severe B12 deficiency causing developmental regression, hypotonia, seizures, and irreversible neurological damage. All vegan breastfeeding mothers must supplement B12."},{"q":"What is the physiological explanation for why people feel warmer after a high-protein meal compared to a high-carbohydrate meal?","opts":["Protein contains more calories per gram","Protein has the highest thermic effect of food (TEF) — 20-30% of calories burned as heat during digestion vs 5-10% for carbs","Protein is digested in a different organ that generates more heat","High-protein meals increase thyroid hormone temporarily"],"correct":1,"explain":"Thermic Effect of Food (TEF): protein 20-30%, carbohydrates 5-10%, fat 0-3%. This means for every 100 calories of protein consumed, 20-30 calories are burned during digestion. This is one reason high-protein diets have a metabolic advantage and contribute to satiety."},{"q":"A postoperative patient is started on total parenteral nutrition (TPN). After 3 days they develop hypophosphatemia, hypokalemia, and cardiac arrhythmia. What is happening?","opts":["The TPN formula is missing these electrolytes","Refeeding syndrome — rapid carbohydrate infusion triggers insulin release, driving electrolytes into cells depleting serum levels","The patient has developed a blood infection from the TPN catheter","The patient is not absorbing the TPN correctly"],"correct":1,"explain":"Refeeding syndrome: after prolonged starvation, providing glucose triggers insulin release → massive cellular uptake of phosphorus (for ATP synthesis), potassium, and magnesium → dangerous drops in serum levels. Phosphorus depletion: respiratory failure, hemolysis, cardiac arrhythmia. Prevent by starting TPN slowly and monitoring electrolytes."},{"q":"A researcher studies why people who eat breakfast have better school performance than those who skip. Which nutritional mechanism best explains this?","opts":["Breakfast foods contain caffeine that improves alertness","Breakfast stabilizes blood glucose providing consistent fuel for the brain's glucose-dependent metabolism","Skipping breakfast causes dehydration which impairs cognition","Eating breakfast increases vitamin B12 absorption which supports memory"],"correct":1,"explain":"The brain uses exclusively glucose for fuel and cannot store significant glycogen. After an overnight fast, blood glucose is at its lowest. Breakfast restores blood glucose, providing consistent fuel for neurotransmitter synthesis, neuronal function, and cognitive performance. Studies consistently show improved attention, memory, and test scores with breakfast."},{"q":"A patient with Crohn's disease has had 60cm of terminal ileum resected. Which TWO nutritional complications are MOST likely?","opts":["Vitamin C and thiamine deficiency from small intestinal malabsorption","Vitamin B12 deficiency (absorbed in terminal ileum) and fat malabsorption from reduced bile acid reabsorption","Only iron deficiency because the duodenum is the site of iron absorption","Protein deficiency and dehydration only"],"correct":1,"explain":"Terminal ileum specifically absorbs: (1) Vitamin B12-intrinsic factor complex — no other site can compensate → B12 deficiency inevitable requiring IM injections. (2) Bile acids (enterohepatic circulation) — loss → reduced fat digestion → steatorrhea → fat-soluble vitamin deficiency (A, D, E, K). Both require specific supplementation."},{"q":"A patient on warfarin (blood thinner) asks about dietary changes. What is the MOST accurate advice?","opts":["Avoid all vitamin K foods completely","Maintain a CONSISTENT vitamin K intake — do not drastically increase or decrease green vegetables","Increase vitamin K intake to counteract warfarin","Vitamin K is unrelated to warfarin efficacy"],"correct":1,"explain":"Warfarin works by blocking vitamin K's role in blood clotting. The KEY is consistency — not complete elimination. If a patient suddenly increases vitamin K (more greens), warfarin becomes less effective (more clotting risk). If they suddenly decrease, warfarin becomes too strong (bleeding risk). Maintain consistent intake and warfarin dose is adjusted accordingly."},{"q":"A marathon runner is experiencing hyponatremia (low blood sodium) during a race despite drinking plenty of fluids. What is the most likely cause?","opts":["Excessive sodium intake from sports gels","Drinking too much plain water, diluting body sodium — exercise-associated hyponatremia","Inadequate carbohydrate intake reducing sodium absorption","Heat stroke causing kidney sodium loss"],"correct":1,"explain":"Exercise-Associated Hyponatremia (EAH): over-hydration with hypotonic fluids (water) dilutes blood sodium below 135 mEq/L. More common in slow runners (more drinking time), women (smaller body size), and events >4 hours. Prevention: drink to thirst, not on a schedule. Use sports drinks with sodium for long events. Cerebral edema can be fatal."},{"q":"A registered dietitian is conducting a nutrition assessment and wants the most accurate indicator of a patient's recent (2-3 week) nutritional status. Which test is MOST appropriate?","opts":["Serum albumin — reflects 3-month nutrition status","Prealbumin (transthyretin) — half-life 2-3 days, reflects recent nutrition status","Hemoglobin — reflects iron status over months","BMI — reflects long-term body composition"],"correct":1,"explain":"Prealbumin (transthyretin): half-life 2-3 days, best reflects recent nutrition status and response to nutrition intervention (ideal for monitoring). Albumin: half-life 18-20 days, reflects longer-term status but also drops with inflammation (not specific to nutrition). Neither is ideal during acute illness due to inflammation's effect."},{"q":"A patient asks about the health benefits of probiotics. Which statement is MOST evidence-based?","opts":["Probiotics cure all GI diseases and should be taken by everyone","Specific probiotic strains have evidence for specific conditions — Lactobacillus rhamnosus GG for antibiotic-associated diarrhea, S. boulardii for C. diff prevention","All probiotic products contain the same strains and have equal benefits","Probiotics permanently colonize the gut and provide permanent benefits after one course"],"correct":1,"explain":"Probiotic evidence is strain-specific and condition-specific. Strongest evidence: L. rhamnosus GG and S. boulardii for antibiotic-associated diarrhea; VSL#3 for ulcerative colitis. Probiotics are transient — they don't permanently colonize. Effects stop when supplementation stops. Must survive manufacturing, storage, and GI acid."},{"q":"A clinical dietitian is calculating energy needs for a critically ill patient using indirect calorimetry. Why is this preferred over predictive equations?","opts":["Indirect calorimetry is less expensive and faster","It measures actual oxygen consumption and CO2 production to calculate actual metabolic rate — predictive equations can be off by 20-40%","Predictive equations overestimate needs in all patients","Indirect calorimetry also measures protein needs directly"],"correct":1,"explain":"Indirect calorimetry measures VO2 and VCO2 to calculate resting energy expenditure via the Weir equation (REE = [3.94 × VO2 + 1.11 × VCO2] × 1440). Predictive equations (Harris-Benedict, Mifflin-St Jeor) can be inaccurate by 20-40% in critical illness due to metabolic stress, medications, and altered body composition. Gold standard in ICU."},{"q":"A patient has been on antibiotics for 2 weeks and develops C. difficile colitis. From a nutrition perspective, the BEST long-term strategy is:","opts":["Restrict all fiber to rest the colon","Restore gut microbiome with high-fiber diet, fermented foods, and possibly targeted probiotics — fiber feeds beneficial bacteria growth","Start parenteral nutrition to rest the gut","Eliminate all carbohydrates to starve C. diff"],"correct":1,"explain":"Antibiotics disrupt the gut microbiome, allowing C. diff to overgrow. Recovery requires restoring beneficial bacteria: dietary fiber feeds Lactobacillus and Bifidobacterium. Fermented foods (yogurt, kefir) provide beneficial organisms. S. boulardii probiotic has evidence for reducing C. diff recurrence. High-fiber, plant-rich diet promotes microbiome diversity."},{"q":"A teenager reports using protein supplements because they want to build muscle. They already eat 120g protein/day. What should the RD advise?","opts":["Add another 50g/day in supplements — more protein always builds more muscle","120g is likely already adequate — additional protein beyond needs is oxidized for energy, not converted to additional muscle","Stop all protein intake — the supplements are dangerous","Switch to BCAA supplements which are better than whole protein"],"correct":1,"explain":"Muscle protein synthesis is maximized at ~1.6-2.2g/kg body weight/day for resistance-trained individuals. Beyond this, additional protein is simply burned as fuel. Protein supplements are expensive and unnecessary if dietary protein is adequate. Distribute protein across meals (20-40g/meal) to maximize muscle protein synthesis. Resistance training, not extra protein, builds muscle."},{"q":"A patient newly diagnosed with type 2 diabetes asks about carbohydrate intake. Which approach is MOST evidence-based?","opts":["Eliminate all carbohydrates — carbs are poison for diabetics","Monitor and distribute carbohydrate intake throughout the day — 45-60g per meal — focus on glycemic impact, fiber content, and food quality","Only eat simple sugars for faster energy absorption","Eat as many complex carbohydrates as possible — they don't affect blood sugar"],"correct":1,"explain":"Evidence-based approaches for T2DM carbohydrate management: total carbohydrate monitoring is most important factor affecting blood glucose. Distribute carbs throughout day to prevent spikes. Choose high-fiber, low-GI sources. Low-carb (<130g/day), Mediterranean, DASH, and plant-based diets all evidence-based — individualize to patient's food culture, preferences, and goals."},{"q":"A public health nutritionist wants to design a school lunch program that maximizes nutritional quality within a limited budget. Which strategy is MOST effective?","opts":["Focus only on reducing fat content of all meals","Maximize fruits and vegetables (frozen acceptable), include legumes as protein sources, serve whole grains, and reduce ultra-processed items","Provide calorie information for all items and let children choose","Eliminate all animal products to reduce cost"],"correct":1,"explain":"Evidence-based school nutrition: fruits/vegetables are most nutrient-dense at reasonable cost (frozen = fresh nutritionally). Legumes (beans, lentils) are the most affordable protein source. Whole grains provide fiber. Reducing ultra-processed items improves diet quality even on tight budget. Studies show improved school nutrition correlates with better academic performance and reduced obesity."},{"q":"A patient is told they have 'metabolic syndrome.' Which combination of findings earned this diagnosis?","opts":["High blood pressure + elevated creatinine + weight over 200 lbs","3 or more of: waist circumference >40in (men) or >35in (women), triglycerides ≥150, low HDL, blood pressure ≥130/85, fasting glucose ≥100","Any single abnormal lab combined with obesity","High cholesterol + family history of heart disease"],"correct":1,"explain":"Metabolic syndrome requires 3+ of 5 criteria: (1) abdominal obesity (waist >40in men, >35in women); (2) triglycerides ≥150mg/dL; (3) low HDL (<40 men, <50 women); (4) blood pressure ≥130/85 or on medication; (5) fasting glucose ≥100mg/dL or on medication. Doubles CVD risk, 5x type 2 diabetes risk."},{"q":"Which combination of nutrients is MOST critical during the first trimester of pregnancy for neural tube development?","opts":["Calcium and vitamin D for bone formation","Folate (400mcg minimum) and iodine — neural tube closes at day 22-28, often before pregnancy is confirmed","Iron and zinc for blood production","Omega-3 fatty acids only for brain development"],"correct":1,"explain":"Neural tube defects (spina bifida, anencephaly) result from failure of neural tube closure at days 22-28 of embryonic development — often before pregnancy is confirmed. All women of childbearing age should take 400mcg folic acid daily (RDA 600mcg during pregnancy). Iodine essential for thyroid function which governs early brain development."},{"q":"A patient on a low-fat diet for gallstone prevention asks about fat-soluble vitamins. What is the most important nutrition concern?","opts":["They will absorb too many fat-soluble vitamins","Inadequate dietary fat reduces absorption of vitamins A, D, E, and K — include small amounts of healthy fats with meals","Fat-soluble vitamins are not affected by dietary fat intake","Only vitamin D absorption is affected by fat intake"],"correct":1,"explain":"Fat-soluble vitamins (A, D, E, K) require dietary fat for absorption via the lymphatic system (chylomicrons). Very low-fat diets (<10% calories from fat) can cause deficiencies. Patients should include small amounts of healthy fat (olive oil, nuts, avocado) with vegetables to maximize vitamin absorption even on fat-restricted diets."},{"q":"A nutrition educator is explaining the difference between enriched and fortified grains. Which statement is ACCURATE?","opts":["Enrichment adds new nutrients; fortification restores lost nutrients","Enrichment restores specific nutrients lost in refining (B1, B2, B3, iron); fortification adds nutrients not originally present (folic acid was added as fortification in 1998)","They are identical processes with different names","Fortification only applies to beverages, not grains"],"correct":1,"explain":"Enrichment: restores nutrients removed during processing — white flour enriched with thiamine (B1), riboflavin (B2), niacin (B3), and iron (lost when bran/germ removed). Fortification: adds nutrients not originally present — folic acid added to enriched grains in 1998 as fortification (not naturally in high amounts in grain). Vitamin D in milk = fortification."},{"q":"A research study examines whether eating fish twice weekly reduces dementia risk over 20 years. What type of study is this, and what does it prove?","opts":["Randomized controlled trial — proves causation definitively","Prospective cohort study — shows strong association but cannot definitively prove causation due to potential confounders","Case-control study — looks backward at past diet","Cross-sectional study — looks at one point in time"],"correct":1,"explain":"Following people forward over time is a prospective cohort study — it shows association between fish intake and dementia risk, controlling for known confounders, but cannot prove causation (fish eaters may have other healthier habits). Randomized controlled trials are the gold standard for causation but are difficult for long-term dietary interventions."},{"q":"A clinical dietitian is developing a nutrition care plan for a patient with gastroparesis (delayed gastric emptying). Which dietary modification is MOST appropriate?","opts":["High-fat, high-protein meals to slow gastric emptying further","Small frequent meals, low fat, low fiber, liquid or soft textures — easier to empty from stomach","Large meals once daily to maximize nutrient absorption","High-fiber diet to improve intestinal motility"],"correct":1,"explain":"Gastroparesis management: small, frequent meals (5-6/day) reduce gastric distension. Low fat (fat delays emptying further). Low fiber (fiber slows and may form bezoars). Liquid and pureed foods empty faster than solids. Chew thoroughly. Avoid carbonated beverages. If oral intake fails: enteral nutrition via jejunal tube (bypasses stomach)."},{"q":"A patient with chronic liver disease has low serum albumin (2.1 g/dL) and edema. The MOST accurate interpretation is:","opts":["The patient is definitely malnourished and needs immediate tube feeding","Low albumin in liver disease primarily reflects the liver's reduced synthetic capacity and inflammation, not necessarily malnutrition — nutrition assessment requires multiple tools","Normal liver disease finding — albumin is irrelevant in liver disease","Albumin will normalize with high-protein diet alone"],"correct":1,"explain":"Albumin has multiple limitations as a nutrition marker: (1) liver disease reduces albumin synthesis regardless of nutrition status; (2) inflammation (acute phase response) causes albumin to fall even with adequate nutrition; (3) fluid overload dilutes albumin. Use comprehensive assessment: SGA, handgrip strength, muscle mass, dietary intake — not albumin alone."},{"q":"A gym trainer recommends that clients take creatine monohydrate supplements for improved performance. What is the most evidence-based statement about creatine?","opts":["Creatine is a steroid with serious health risks","Creatine monohydrate is one of the most researched and effective supplements for short-duration, high-intensity exercise — improves strength and power, safe for healthy adults","Creatine is only effective for endurance athletes","Creatine supplements are no more effective than eating beef"],"correct":1,"explain":"Creatine monohydrate: most researched supplement in sports nutrition. Mechanism: increases phosphocreatine stores → more rapid ATP resynthesis → improved performance in high-intensity, short-duration activities (sprinting, weightlifting). Most effective loading: 20g/day for 5-7 days, then 3-5g maintenance. No evidence of harm in healthy adults with normal kidney function."},{"q":"A mother asks whether her child's picky eating requires a nutritional supplement. The MOST evidence-based response is:","opts":["All picky eaters need multivitamin supplements","Assess the child's actual nutrient intake first — most picky eaters get adequate nutrition, but specific deficiencies (iron, vitamin D, zinc) are common and may warrant targeted supplementation","Picky eating is always a nutritional emergency","Restrict all preferred foods until they eat more variety"],"correct":1,"explain":"Picky eating peaks ages 2-6 and is developmentally normal. Most picky eaters get adequate macronutrients but may lack iron, zinc, vitamin D, and omega-3s. Assessment first — then targeted supplementation if deficiencies identified. Pressure and food restriction worsen picky eating. Division of responsibility: parents provide food, children decide whether and how much to eat."},{"q":"A patient asks about the benefits of 'eating the rainbow' of fruits and vegetables. The primary nutritional rationale is:","opts":["Colorful foods contain more calories needed for energy","Different colors represent different phytochemicals (lycopene in red, beta-carotene in orange, lutein in yellow/green, anthocyanins in purple) — variety provides broadest protection","Colors are added artificially in all produce","Only green vegetables have nutritional value"],"correct":1,"explain":"Plant pigments are bioactive phytochemicals: red lycopene (tomatoes) — prostate/cardiovascular protection; orange beta-carotene (carrots) — provitamin A, antioxidant; yellow lutein (corn, squash) — eye protection; green chlorophyll + glucosinolates (broccoli) — cancer protective; blue/purple anthocyanins (berries) — cognitive protection, anti-inflammatory. Eating variety ensures broad phytochemical coverage."},{"q":"A patient with phenylketonuria (PKU) needs to follow a strict phenylalanine-restricted diet. Why is this nutritionally challenging?","opts":["Phenylalanine is only found in rare exotic foods","Phenylalanine is an essential amino acid found in all protein-containing foods — restriction requires special low-phenylalanine medical formulas for adequate protein intake","PKU only affects carbohydrate metabolism, not protein","Phenylalanine restriction is simple — just avoid meat"],"correct":1,"explain":"PKU: inability to metabolize phenylalanine (PA) → accumulates → brain damage. PA is in ALL proteins — meat, dairy, beans, grains. Cannot eliminate protein (it's essential). Solution: special amino acid formula with all essential amino acids EXCEPT phenylalanine. Small amounts of natural protein allowed. Lifelong restriction needed. Aspartame (NutraSweet) contains phenylalanine — must be avoided."}]);
  qz.hard=qz.hard.concat([{"q":"In nitrogen balance, what does a 'negative nitrogen balance' indicate?","opts":["More nitrogen consumed than excreted — muscle building","More nitrogen excreted than consumed — muscle breakdown","Equal nitrogen in and out — maintenance","Nitrogen being converted to fat"],"correct":1,"explain":"Negative nitrogen balance means more nitrogen is lost (excreted) than consumed. Since nitrogen comes almost entirely from protein, this indicates net protein breakdown — occurring during starvation, illness, severe injury, or inadequate protein intake."},{"q":"What is enterohepatic circulation and why does it matter for cholesterol?","opts":["Liver-to-intestine nutrient delivery","Recycling of bile salts from intestine back to liver — soluble fiber interrupts this, lowering cholesterol","The pathway of dietary fat absorption","The portal circulation carrying nutrients from intestine to liver"],"correct":1,"explain":"Enterohepatic circulation is the recycling of bile salts from the intestine back to the liver via the portal vein — 95% of bile salts are recycled. Soluble fiber binds bile salts in the intestine, interrupting recycling and forcing the liver to use cholesterol to make new bile salts, thus lowering blood cholesterol."},{"q":"What is gluconeogenesis, and which amino acid is the primary substrate?","opts":["Glucose storage as glycogen; branched-chain amino acids","New glucose synthesis from non-carbohydrate precursors; alanine is the primary amino acid substrate","Fat synthesis from glucose; glutamine","Ketone body synthesis from fatty acids; leucine"],"correct":1,"explain":"Gluconeogenesis is the synthesis of new glucose from non-carbohydrate precursors (amino acids, glycerol, lactate) primarily in the liver. Alanine from muscle protein breakdown is the most important amino acid substrate during fasting/starvation."},{"q":"The vitamin D synthesis pathway requires activation in which two organs?","opts":["Stomach and intestine","Liver (25-hydroxylation) and kidney (1-alpha-hydroxylation to active calcitriol)","Pancreas and liver","Skin and small intestine"],"correct":1,"explain":"Vitamin D synthesis: skin produces cholecalciferol (D3) from UV light. The LIVER adds a hydroxyl group (25-OH-D3/calcidiol). The KIDNEY adds another hydroxyl group to make 1,25-OH2-D3 (calcitriol) — the active hormone form that promotes calcium absorption."},{"q":"Hepcidin regulates iron homeostasis. Which condition would INCREASE hepcidin secretion?","opts":["Iron deficiency anemia","Hemochromatosis (iron overload) and inflammation","Blood loss and pregnancy","Vegetarian diet"],"correct":1,"explain":"Hepcidin is the master regulator of iron. High iron levels and inflammation INCREASE hepcidin, which degrades ferroportin (the iron exporter), reducing iron absorption. This explains anemia of chronic disease — inflammation raises hepcidin, blocking iron release even when stores are present."},{"q":"A patient on a ketogenic diet for 3 weeks develops nausea, fatigue, and headache during the transition. This 'keto flu' is primarily caused by:","opts":["Protein toxicity from increased meat intake","Electrolyte imbalances (sodium, potassium, magnesium) as kidneys excrete more electrolytes due to lower insulin and glycogen depletion","Vitamin deficiencies from removing fruits and vegetables","The production of ketones directly poisoning cells"],"correct":1,"explain":"During carbohydrate restriction, insulin falls → kidneys excrete more sodium (taking potassium and water with it) → electrolyte imbalances. Also: glycogen depletion (water loss — 3-4g water per gram glycogen). Keto flu symptoms: headache, fatigue, brain fog, nausea, muscle cramps. Treatment: sodium, potassium, magnesium supplementation, adequate hydration."},{"q":"A patient with non-alcoholic fatty liver disease (NAFLD) asks about dietary interventions. The MOST evidence-based recommendation is:","opts":["Eliminate all dietary fat immediately","Achieve 7-10% weight loss through calorie reduction and increase physical activity","Follow a high-protein, low-calorie liquid diet","Take omega-3 supplements regardless of other dietary changes"],"correct":1,"explain":"7-10% weight loss through modest calorie reduction (500-1000 kcal/day deficit) and increased physical activity is the most evidence-based treatment for NAFLD. This reduces liver fat, inflammation, and fibrosis. Also beneficial: reduce fructose/added sugars (major driver of hepatic lipogenesis), limit alcohol, Mediterranean diet pattern. Weight loss surgery effective for severe cases."},{"q":"Epigenetic effects of nutrition are best described as:","opts":["Mutations in DNA caused by poor diet","Changes in gene expression without changing the DNA sequence — diet can turn genes on or off","The direct incorporation of food molecules into the genetic code","Inheritance of nutritional preferences through genes"],"correct":1,"explain":"Epigenetics refers to modifications (primarily DNA methylation and histone modification) that change gene expression without altering the DNA sequence. Folate/methyl-group donors affect DNA methylation. Early life nutrition has lasting epigenetic effects (Barker hypothesis: fetal programming). Maternal diet affects offspring's lifelong disease risk."},{"q":"The gut-brain axis is BEST described as:","opts":["The brain's control of eating behavior only","A bidirectional communication system between gut microbiome and brain via vagus nerve, immune system, and hormones","The physical connection between the esophagus and hypothalamus","One-directional hormone signals from brain to gut only"],"correct":1,"explain":"The gut-brain axis is a bidirectional communication network: gut sends signals to brain (90% of vagal fibers are afferent), brain sends signals to gut (stress affects motility). The microbiome produces neurotransmitters (90% of serotonin made in gut), modulates immune response, and affects mood. Dysbiosis linked to anxiety, depression, cognitive changes."},{"q":"A competitive endurance athlete completing 3-hour training sessions daily requires approximately how many grams of carbohydrate per kilogram of body weight?","opts":["1-2g/kg (same as sedentary adults)","3-5g/kg","8-10g/kg per day, with 60-90g/hour during exercise","20g/kg — elite athletes need massive carb intake"],"correct":2,"explain":"High-volume endurance athletes (>4-5 hours/day): 8-10g/kg/day. Moderate-volume (1-3 hours/day): 6-10g/kg/day. During exercise (>60 min): 30-60g/hour; for >2.5 hours: 60-90g/hour using multiple transportable carbohydrates (glucose + fructose). Carbohydrate periodization (train low, compete high) is emerging strategy."},{"q":"The MTHFR genetic variant (C677T) affects nutrition because it:","opts":["Causes complete inability to absorb any B vitamins","Reduces the enzyme that converts folate to its active form — affects DNA methylation and homocysteine metabolism","Increases the requirement for vitamin C dramatically","Makes all dietary fat immediately toxic"],"correct":1,"explain":"MTHFR enzyme converts 5,10-methylenetetrahydrofolate to 5-methyltetrahydrofolate (active form). C677T variant reduces enzyme activity 30-70%. Consequences: elevated homocysteine (cardiovascular risk), impaired DNA methylation. People with this variant may need methylated folate (L-methylfolate) rather than folic acid. Found in ~25% of Hispanics, 10-15% of whites."},{"q":"A patient develops oxalate nephropathy (kidney damage from oxalate) after Roux-en-Y gastric bypass surgery. This occurs because:","opts":["The surgery removes the kidney's oxalate-filtering ability","Fat malabsorption allows more oxalate to be absorbed — calcium that would normally bind oxalate in the gut is bound to unabsorbed fat instead","The surgery directly increases oxalate production in the liver","Bypass patients eat more spinach post-surgery"],"correct":1,"explain":"After gastric bypass, fat malabsorption occurs. Normally, dietary calcium binds oxalate in the gut, preventing absorption. With fat malabsorption, fatty acids bind to calcium instead, leaving oxalate free to be absorbed. Increased oxalate reaches kidneys → calcium oxalate crystals → kidney stones and nephropathy. Treatment: low-oxalate diet, calcium with meals, hydration."},{"q":"In total parenteral nutrition (TPN), which electrolyte is most critical to monitor and replete to prevent refeeding syndrome?","opts":["Sodium","Potassium","Phosphorus","Chloride"],"correct":2,"explain":"Phosphorus is the hallmark electrolyte of refeeding syndrome. When carbohydrates are administered to malnourished patients, insulin drives massive cellular uptake of phosphorus for ATP synthesis and phosphorylation. Serum phosphorus plummets → hypophosphatemia causes: cardiac arrhythmia, respiratory muscle failure, seizures, rhabdomyolysis, hemolytic anemia, death."},{"q":"Carnitine's primary role in metabolism is to:","opts":["Act as an antioxidant protecting cell membranes","Transport long-chain fatty acids across the inner mitochondrial membrane for beta-oxidation","Store glycogen in muscle tissue","Synthesize cholesterol from acetyl-CoA"],"correct":1,"explain":"Carnitine shuttles long-chain fatty acids (>12 carbons) across the inner mitochondrial membrane where beta-oxidation occurs. The body synthesizes carnitine from lysine and methionine (requires vitamins C, B6, niacin). Deficiency (genetic or dialysis) causes fatty acid oxidation impairment. Supplementation doesn't enhance fat burning in healthy people with adequate intake."},{"q":"A patient has MTHFR C677T homozygous polymorphism. Which SPECIFIC form of folate supplement is most appropriate?","opts":["Synthetic folic acid — highest bioavailability","Methylfolate (L-5-MTHF) — because this mutation reduces MTHFR enzyme activity that normally converts folic acid to the active form methylfolate","Any folate supplement — the polymorphism has no clinical significance","High-dose folic acid will overcome the enzyme deficiency"],"correct":1,"explain":"MTHFR C677T: reduces enzyme activity by 30-70% in heterozygotes, 70-90% in homozygotes. MTHFR converts dietary folate and folic acid to methylfolate (5-MTHF) — the active form used for homocysteine remethylation and DNA synthesis. With reduced enzyme activity, folic acid accumulates. Methylfolate bypasses the conversion step. Also: elevated homocysteine is common in homozygotes."},{"q":"A research team measures respiratory quotient (RQ = VCO2/VO2) in a subject and finds RQ = 0.72. What does this indicate about substrate utilization?","opts":["The subject is primarily metabolizing carbohydrates (RQ = 1.0)","The subject is primarily metabolizing fat (RQ = 0.7) — fatty acid oxidation uses less oxygen relative to CO2 produced","The subject is in starvation with muscle catabolism (RQ > 1.0)","RQ of 0.72 indicates mixed substrate use and provides no useful information"],"correct":1,"explain":"RQ interpretation: Carbohydrate = 1.0 (equal CO2 produced and O2 consumed). Fat = 0.7 (fat requires more O2 relative to CO2 produced). Protein = 0.82. Mixed diet = 0.82-0.87. RQ 0.72 indicates predominantly fat oxidation (fasting, ketogenic diet, between meals). RQ >1.0 indicates de novo lipogenesis from excess carbohydrate. Used to guide macronutrient composition in critically ill patients."},{"q":"A patient develops oxalate nephropathy after gastric bypass surgery. Which nutritional mechanism explains this complication?","opts":["Excessive protein absorption after surgery damages kidneys directly","Fat malabsorption post-bypass → unabsorbed fat binds calcium → free oxalate (normally bound by calcium) absorbed excessively → hyperoxaluria → kidney stones","The patient consumed too many oxalate-rich foods post-surgery","Dehydration from restricted fluid intake post-surgery concentrated oxalate"],"correct":1,"explain":"Enteric hyperoxaluria after Roux-en-Y gastric bypass: fat malabsorption → unabsorbed fatty acids bind calcium in the gut → calcium unavailable to bind dietary oxalate → free oxalate absorbed in excess → hyperoxaluria → calcium oxalate kidney stones. Prevention: low-oxalate diet, adequate calcium with meals (NOT supplements between meals), hydration, low-fat diet. A significant long-term complication of malabsorptive surgeries."},{"q":"Which mechanism explains why vitamin D deficiency is common despite adequate sun exposure in elderly patients with chronic kidney disease?","opts":["CKD causes sun sensitivity requiring avoidance of sunlight","CKD damages the 1-alpha-hydroxylase enzyme in kidney proximal tubules that converts 25-OH vitamin D to the active form 1,25-OH2 vitamin D (calcitriol)","Elderly skin cannot absorb UV rays efficiently","CKD causes vitamin D to be excreted in urine before it is activated"],"correct":1,"explain":"Vitamin D activation: Sun/diet → D3 → liver 25-hydroxylase → 25-OH vitamin D (storage form) → kidney 1-alpha-hydroxylase → 1,25-OH2 vitamin D (calcitriol, active hormone). CKD destroys kidney tubular cells containing 1-alpha-hydroxylase → cannot complete final activation step. Serum 25-OH D may be normal but calcitriol deficient. Treatment: calcitriol (active vitamin D) prescribed directly, not regular vitamin D supplements."},{"q":"A cancer patient on chemotherapy develops severe mucositis limiting oral intake. Their albumin is 2.0, prealbumin is 8 mg/dL. The oncology team debates parenteral vs enteral nutrition. The MOST evidence-based recommendation is:","opts":["Immediate total parenteral nutrition — the gut is clearly not functioning","If any GI tract function remains and mucositis is limited to mouth/throat, nasogastric or nasojejunal tube feeding is preferred — 'if the gut works, use it'","Wait until chemotherapy is complete before initiating any nutrition support","Oral nutritional supplements are always sufficient for cancer patients"],"correct":1,"explain":"Enteral nutrition is preferred over parenteral whenever GI tract is functional because: (1) maintains gut barrier integrity preventing bacterial translocation; (2) preserves gut mucosal immunity; (3) cheaper with fewer infectious complications (central line infections with TPN); (4) preserves normal gut hormonal responses. Mucositis limited to oral cavity/throat may allow tube feeding past the lesion. Evidence shows enteral nutrition superior to TPN in oncology patients."},{"q":"A research dietitian calculates the glycemic load (GL) of a meal. The meal contains one cup of white rice (GI=73, 45g carbs). What is the GL and what does it predict?","opts":["GL = 73 — the same as GI, it predicts the same blood glucose response","GL = 73 × 45 ÷ 100 = 32.9 (HIGH GL ≥20) — predicts a large blood glucose response more accurately than GI alone by accounting for both quality and quantity of carbs","GL = 45 ÷ 73 = 0.6 — very low glycemic response","GL = (73 + 45) = 118 — sum of GI and carbs for total impact"],"correct":1,"explain":"GL = (GI × available carbohydrate grams) ÷ 100. White rice: GL = (73 × 45) ÷ 100 = 32.9 = HIGH (≥20). GL more clinically useful than GI because it accounts for real portion size and actual carb content. Example: watermelon GI=72 but GL=4 (low) because it has only ~6g carbs per 100g. Use GL for realistic glycemic impact prediction."},{"q":"A patient with short bowel syndrome (150cm small intestine remaining, no colon) is 18 months post-resection. They have been TPN-dependent. The key nutritional strategy to promote intestinal adaptation and TPN independence is:","opts":["Provide all nutrition via TPN — remaining intestine is insufficient","Begin small amounts of enteral/oral nutrition (even if inadequate for full needs) — luminal nutrients are the primary driver of intestinal adaptation (mucosal hyperplasia, villous lengthening)","High-fat elemental formula via tube — fat drives intestinal adaptation best","Complete bowel rest until adaptation is complete"],"correct":1,"explain":"Intestinal adaptation: mucosal hyperplasia, villous lengthening, increased absorptive capacity in remaining intestine. Primary driver: luminal nutrients (particularly glutamine, short-chain fatty acids, complex carbs). Trophic hormones (GLP-2: teduglutide drug). Even small amounts of oral/enteral feeding stimulate adaptation. TPN provides nutrition while gut adapts. Goal: transition off TPN. Colon presence significantly improves outcome."},{"q":"A lipid panel shows: Total cholesterol 220, LDL 160, HDL 35, Triglycerides 350. Which dietary intervention has the GREATEST evidence for improving this SPECIFIC pattern?","opts":["Eliminate all dietary cholesterol — eat only egg whites and avoid shrimp","Reduce refined carbohydrates and added sugars (primary driver of hypertriglyceridemia), increase omega-3s, limit alcohol — LDL may improve with less saturated fat","Start a very low-fat diet — all fats raise triglycerides","Increase saturated fat and reduce carbohydrates — saturated fat raises HDL"],"correct":1,"explain":"Hypertriglyceridemia (>200) is primarily driven by: refined carbohydrates, added sugars, alcohol, and physical inactivity — not dietary fat. Dietary interventions with strongest evidence for triglycerides: restrict sugar, refined carbs, and alcohol; increase omega-3 fatty acids (fish or supplements >2-4g EPA+DHA); lose weight; increase physical activity. Dietary cholesterol has minimal effect on LDL in most people."},{"q":"An ICU dietitian is monitoring a mechanically ventilated patient on continuous tube feeding. The patient develops diarrhea (>500mL/day). Stool culture is negative. Which nutritional factor should be evaluated FIRST?","opts":["Immediately stop tube feeding — diarrhea always indicates formula intolerance","Evaluate medications (sorbitol-containing liquid medications, antibiotics, prokinetics, magnesium) before changing tube feeding — medications are the most common cause of diarrhea in tube-fed ICU patients","Switch to elemental formula immediately","Add fiber supplement to the formula"],"correct":1,"explain":"Diarrhea in tube-fed patients is most commonly caused by MEDICATIONS, not formula: liquid medications in sorbitol base (acetaminophen elixir, metoclopramide), antibiotics (disrupt microbiome, C. diff), magnesium-containing medications (antacids), prokinetics. Evaluate medication list first. If medications eliminated as cause, then consider: formula osmolality, rate, fiber content, or infectious etiology (if not yet ruled out)."},{"q":"A research team uses doubly labeled water (DLW) to measure total energy expenditure. Why is this method considered the gold standard over diet recalls and predictive equations?","opts":["It's the cheapest and easiest method available","DLW measures CO2 production from labeled hydrogen and oxygen isotope elimination in urine over 7-14 days — objective, non-invasive, measures free-living energy expenditure without behavioral alteration","DLW measures basal metabolic rate most accurately","It directly measures food intake rather than estimating energy expenditure"],"correct":1,"explain":"Doubly labeled water method: subject drinks water with stable isotopes (²H and ¹⁸O). ¹⁸O eliminated as both water and CO2; ²H as water only. Difference = CO2 production rate → calculate energy expenditure via RQ. Gold standard for free-living total energy expenditure because: measures over 1-2 weeks, non-intrusive (no behavioral change), objective. Used to validate other methods. Very expensive (~$1000/subject)."},{"q":"A dietitian is counseling a patient with hereditary hemochromatosis (HFE gene mutation). Which dietary advice is MOST critical?","opts":["Eliminate all iron from diet — this will normalize iron stores","Avoid vitamin C with meals (vitamin C dramatically enhances iron absorption), limit red meat, avoid iron cookware and supplements, avoid alcohol (worsens liver damage), continue therapeutic phlebotomy","Take iron chelation supplements to bind and remove iron","Increase calcium intake to compete with iron absorption"],"correct":1,"explain":"Hereditary hemochromatosis: HFE mutation → reduced hepcidin → excessive iron absorption. Primary treatment: therapeutic phlebotomy (removing blood regularly). Dietary modification is adjunctive: avoid vitamin C with iron-rich meals (C dramatically increases absorption), limit red meat and alcohol (both increase iron absorption and liver damage), avoid iron supplements and cookware. Cannot eliminate dietary iron entirely (need some), but reduce enhancers."},{"q":"During a clinical nutrition rotation, a student dietitian calculates Harris-Benedict equation for a hospitalized patient: BMR = 1450 kcal. The patient is post-surgical day 2, febrile (38.5°C), ambulating minimally. What is the MOST appropriate total energy estimate?","opts":["1450 kcal — BMR is sufficient for hospitalized patients","Approximately 1740-2175 kcal — multiply BMR by appropriate activity factor (1.2) and injury/stress factor (1.0-1.5 for post-surgical with fever) — then consider 80-100% of estimated needs to avoid overfeeding","Double the BMR — all sick patients have doubled metabolic needs","Use indirect calorimetry — Harris-Benedict is never appropriate in hospitalized patients"],"correct":1,"explain":"Harris-Benedict application: BMR × activity factor × stress factor. Activity: bed rest = 1.2. Stress: post-surgical with fever = 1.2-1.5. Estimated TEE: 1450 × 1.2 × 1.2-1.5 = ~2088-2610 kcal. However, most current guidelines recommend 80-100% of estimated needs in early critical illness to avoid overfeeding (overfeeding → hyperglycemia, liver steatosis, respiratory failure from excess CO2). Indirect calorimetry is gold standard when available."},{"q":"A patient with anorexia nervosa is hospitalized at 68% ideal body weight. On day 3 of nutritional rehabilitation, potassium drops to 2.8, phosphorus to 1.8, and magnesium to 1.2. What is occurring and what is the priority intervention?","opts":["The patient is refusing to eat — increase caloric target and encourage eating","Refeeding syndrome — reduce calories immediately to 50% of goal, aggressively replace potassium, phosphorus, and magnesium, monitor cardiac rhythm continuously","These electrolyte values are expected and don't require intervention","Increase protein intake to maintain muscle mass during refeeding"],"correct":1,"explain":"Refeeding syndrome in anorexia nervosa: carbohydrate provision after starvation → insulin surge → massive intracellular shift of phosphorus, potassium, magnesium → dangerous serum drops. Phosphorus <2.0: highest priority (ATP synthesis impaired → cardiac, respiratory failure). Treatment: REDUCE calories (not increase), aggressively replace electrolytes IV/PO, cardiac monitoring, daily labs. Then SLOWLY increase calories by 200 kcal every 2-3 days."}]);
})();

