// ── STOP THE BLEED EXPANSION ───────────────────────────────────────────────
(function(){
  if(!window.QB_STOP_BLEED) return;
  var fc = window.QB_STOP_BLEED.flashcards;
  var qz = window.QB_STOP_BLEED.quiz;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});

  fc.easy = fc.easy.concat([
    {term:"Stop the Bleed founder",def:"The Stop the Bleed campaign was launched by the American College of Surgeons in 2015 following the Sandy Hook tragedy"},
    {term:"Hartford Consensus",def:"A 2013 agreement by medical and law enforcement leaders establishing that bystanders can prevent death from bleeding — foundation of Stop the Bleed"},
    {term:"TECC",def:"Tactical Emergency Casualty Care — civilian version of military TCCC, guiding bleeding control in mass casualty and high-threat events"},
    {term:"TCCC",def:"Tactical Combat Casualty Care — military battlefield hemorrhage control protocol that inspired Stop the Bleed training"},
    {term:"Massive hemorrhage",def:"Uncontrolled, life-threatening bleeding — the leading cause of preventable death in trauma, accounting for up to 40% of trauma deaths"},
    {term:"Bystander bleeder effect",def:"Research showing that immediate bystander intervention before EMS arrival dramatically increases survival from severe bleeding"},
    {term:"Average EMS response time",def:"7–10 minutes nationally — critically long when a patient can die from arterial bleeding in 3–5 minutes"},
    {term:"Tourniquet history",def:"Tourniquets were used in military medicine as far back as the U.S. Civil War; modern adoption grew from lessons in Iraq and Afghanistan"},
    {term:"Combat Application Tourniquet (CAT)",def:"The most widely used commercial tourniquet in the U.S. military and civilian first aid — windlass mechanism, one-hand application"},
    {term:"SOFTT-W",def:"Special Operations Forces Tactical Tourniquet Wide — a dual-ring tourniquet system used as an alternative to the CAT"},
    {term:"Bleeding control kit (B-Con kit)",def:"A publicly accessible kit containing gloves, tourniquet, pressure bandage, hemostatic gauze, and a marker — placed in public spaces like AEDs"},
    {term:"Public bleeding control kit",def:"Stop the Bleed kits are increasingly co-located with AEDs in schools, airports, stadiums, and public buildings"},
    {term:"Marker or pen in bleeding kit",def:"Used to write the time of tourniquet application on the patient's forehead or tourniquet — critical for hospital handoff"},
    {term:"Normal adult blood volume",def:"Approximately 5 liters (10–12 pints) — loss of just 1–1.5 liters can cause hemorrhagic shock"},
    {term:"Critical blood loss threshold",def:"Loss of more than 30% of blood volume (about 1.5 liters) triggers Class III hemorrhagic shock requiring urgent intervention"},
    {term:"Pallor (pale skin)",def:"One of the classic signs of significant blood loss — caused by blood being redirected away from the skin"},
    {term:"Diaphoresis",def:"Cold, clammy, sweaty skin — a sign of shock as the body activates the sympathetic nervous system in response to blood loss"},
    {term:"Tachycardia in hemorrhage",def:"Rapid heart rate (>100 bpm) — the body's compensatory response to maintain cardiac output during blood loss"},
    {term:"Hypotension in hemorrhage",def:"Low blood pressure — a late sign of hemorrhagic shock indicating the body can no longer compensate for blood loss"},
    {term:"Altered mental status (blood loss)",def:"Confusion, agitation, or unconsciousness from reduced oxygen delivery to the brain — a sign of severe blood loss"},
    {term:"Direct pressure technique",def:"Apply firm, continuous pressure to a wound using a cloth or gauze — the first step for any bleeding wound"},
    {term:"Wound packing steps",def:"Pack gauze tightly into the wound, apply direct pressure for at least 3 minutes, do not remove — used for deep wounds where direct pressure alone won't work"},
    {term:"Tourniquet placement site",def:"Applied 2–3 inches above the wound on a limb — never over a joint, never on the neck, chest, or abdomen"},
    {term:"Tourniquet tightening endpoint",def:"Tighten until bleeding stops — not until patient screams; the goal is cessation of bleeding, not a specific tightness level"},
    {term:"Leave tourniquet in place",def:"Never remove a tourniquet in the field — only hospital staff with blood products available should remove it"},
    {term:"Tourniquet documentation time",def:"Write the time of tourniquet application (T=HH:MM) on the patient's skin or the tourniquet itself — vital for hospital teams"},
    {term:"Arterial bleed identification",def:"Bright red blood that pulses or spurts with each heartbeat — indicates damage to an artery, most life-threatening type"},
    {term:"Venous bleed identification",def:"Dark red blood that flows steadily — from a vein; less immediately dangerous than arterial but still potentially fatal if large vein"},
    {term:"Capillary bleed",def:"Slow oozing from the skin surface — the least dangerous type, usually controlled with light pressure"},
    {term:"Junctional wound definition",def:"A wound in an area where a tourniquet cannot be applied — groin, armpit, neck, or pelvis"},
    {term:"Junctional wound treatment",def:"Use wound packing with hemostatic gauze and apply firm direct pressure — no tourniquet possible in these areas"},
    {term:"Hemostatic gauze brands",def:"QuikClot Combat Gauze, Celox, and ChitoGauze — impregnated with agents that accelerate blood clotting when packed into wounds"},
    {term:"QuikClot mechanism",def:"Kaolin-impregnated gauze that activates the clotting cascade on contact with blood — does not generate heat like older versions"},
    {term:"Celox mechanism",def:"Contains chitosan (derived from shellfish) that creates a gel-like clot independent of the body's normal clotting factors — useful in hypothermic patients"},
    {term:"Gloves as PPE in bleeding control",def:"Nitrile or latex gloves protect the rescuer from bloodborne pathogens — always the first step before touching a bleeding patient"},
    {term:"Bloodborne pathogens",def:"Infectious agents (HIV, Hepatitis B, Hepatitis C) transmitted through contact with blood — reason PPE is essential in bleeding control"},
    {term:"Good Samaritan protections",def:"Laws in all U.S. states that protect bystanders who provide emergency aid in good faith from civil liability"},
    {term:"Scene safety in bleeding control",def:"Before helping a bleeding patient, ensure the scene is safe — active shooters, traffic, or hazards must be addressed or avoided"},
    
    {term:"Israeli bandage",def:"A widely used pressure bandage with a built-in pressure applicator bar — designed for one-handed self-application in the field"},
    {term:"Shock definition",def:"A life-threatening state where the body cannot deliver enough oxygen to vital organs — hemorrhagic shock is the type caused by blood loss"},
    {term:"Compensated shock",def:"Early stage where the body maintains blood pressure through increased heart rate and vasoconstriction — patient may appear relatively normal"},
    {term:"Decompensated shock",def:"Late stage where compensatory mechanisms fail — blood pressure drops, consciousness decreases, death is imminent without intervention"},
    {term:"EMS handoff key information",def:"Time of injury, tourniquet application time, mechanism of injury, and estimated blood loss — all communicated to arriving EMS"},
    {term:"Recovery position",def:"Place a stabilized bleeding patient on their side if unconscious — protects the airway from vomit while waiting for EMS"},
    {term:"Two-tourniquet rule",def:"If bleeding continues after the first tourniquet, apply a second one directly above (proximal to) the first — do not remove the first"},
    {term:"Improvised tourniquet materials",def:"A belt, tie, or torn shirt can be used as a last resort — must be at least 1 inch wide, applied with consistent tension"},
    {term:"Why improvised tourniquets often fail",def:"Too narrow (causes tissue damage without stopping flow), too loose, or not tightened enough — commercial tourniquets are far more reliable"},
    {term:"Pediatric tourniquet",def:"Same principles apply — use the smallest commercial tourniquet or improvise; child's smaller limb means less material is needed"},
    {term:"Neck wound first aid",def:"Never apply circumferential pressure to the neck — use direct finger pressure on the wound site to compress the bleeding vessel"},
    {term:"Abdominal wound first aid",def:"Do not pack or apply direct pressure to an abdominal wound with protruding organs — cover with moist dressing and await EMS"},
    {term:"Stop the Bleed training duration",def:"The standard Stop the Bleed course is approximately 2 hours including hands-on practice with tourniquets and wound packing simulators"},
    {term:"Who should take Stop the Bleed",def:"Anyone — teachers, students, parents, office workers — bystanders are statistically the first responders at most bleeding emergencies"},
    {term:"AVPU scale",def:"Alert, Verbal, Pain, Unresponsive — a rapid mental status assessment tool used during initial evaluation of a trauma patient"},
    {term:"Pulse check in bleeding",def:"Check radial (wrist) pulse first — weak or absent radial pulse with a strong carotid pulse indicates significant blood loss"},
    {term:"Capillary refill time",def:"Normal is less than 2 seconds — prolonged refill (press nail bed, release, count seconds until color returns) indicates poor perfusion"},
    {term:"Tourniquets and nerve damage",def:"Prolonged tourniquet application (>2 hours) risks nerve and muscle damage — but this risk is always less than the risk of exsanguination"},
    {term:"Prehospital tourniquet evidence",def:"Military data from Iraq and Afghanistan showed tourniquets reduce extremity hemorrhage deaths by up to 85% with minimal complications when properly applied"},
    {term:"Wound gauze packing pressure",def:"Packing requires firm, sustained pressure — use body weight if needed, maintaining pressure for a minimum of 3 full minutes"},
    {term:"Hemostatic dressing application time",def:"Press hemostatic gauze into the wound and apply direct pressure for 3 minutes — the agent needs time to activate clotting"},
    {term:"Mass casualty bleeding triage",def:"In a mass casualty event, focus on the most severely bleeding patients who are still conscious — unconscious patients with no pulse are lowest priority"},
    {term:"SALT triage",def:"Sort, Assess, Lifesaving Interventions, Treatment — a mass casualty triage system where bleeding control is a first-tier lifesaving intervention"},
    {term:"START triage",def:"Simple Triage and Rapid Treatment — colors: black (deceased/expectant), red (immediate), yellow (delayed), green (minor)"},
    {term:"Bleeding control in CPR",def:"If a patient needs both CPR and bleeding control, control life-threatening bleeding first — you cannot circulate oxygenated blood if it's all on the floor"},
    {term:"Public access bleeding control",def:"The movement to co-locate bleeding control kits with AEDs in public spaces — analogous to the public AED movement of the 1990s"},
    {term:"Stop the Bleed website",def:"stopthebleed.org — the official site for training registration, kit information, and instructor resources"},
    {term:"Certified Stop the Bleed instructor",def:"A healthcare professional or trained layperson certified to teach the Stop the Bleed curriculum to community groups"},
    {term:"ACT (Awareness, Call 911, Treatment)",def:"An older bleeding control mnemonic emphasizing awareness of the scene, activating EMS, and treating the wound"},
    {term:"3 C's of Stop the Bleed",def:"Call 911, Compress the wound, Apply a tourniquet — the three core action steps taught in the Stop the Bleed program"},
  ]);

  fc.medium = fc.medium.concat([
    {term:"MARCH protocol expanded",def:"Massive hemorrhage first, Airway second, Respiration third, Circulation fourth, Hypothermia last — militarily proven hemorrhage-first prioritization"},
    {term:"Why hemorrhage before airway",def:"MARCH places hemorrhage control before airway management because exsanguination kills faster than most airway obstructions in trauma"},
    {term:"Permissive hypotension rationale",def:"Allowing systolic BP of 80–90 mmHg in penetrating trauma avoids high-volume crystalloid that dilutes clotting factors and worsens the lethal triad"},
    {term:"Lethal triad components",def:"Hypothermia, acidosis, and coagulopathy — the three interconnected conditions that spiral together in major trauma to cause death"},
    {term:"Hypothermia and coagulopathy link",def:"Clotting enzymes work best at 37°C — body temperature below 35°C significantly impairs clotting factor function, worsening hemorrhage"},
    {term:"Acidosis and coagulopathy link",def:"Acidosis (low blood pH from tissue hypoxia) directly impairs platelet aggregation and clotting factor activity"},
    {term:"TXA mechanism",def:"Tranexamic acid blocks fibrinolysis (the breakdown of blood clots) — preserving clots that form at bleeding sites"},
    {term:"TXA timing window",def:"TXA is most effective when given within 1 hour of injury — effectiveness decreases sharply after 3 hours and may be harmful after that"},
    {term:"CRASH-2 trial",def:"The landmark 20,000-patient randomized controlled trial showing TXA reduces mortality in bleeding trauma patients by 1.5% when given within 3 hours"},
    {term:"Damage control surgery",def:"Abbreviated surgery focused solely on controlling hemorrhage and contamination — detailed repair performed later when the patient is stabilized"},
    {term:"1:1:1 balanced resuscitation",def:"Transfusing packed red blood cells, fresh frozen plasma, and platelets in a 1:1:1 ratio — mimics whole blood and preserves clotting function"},
    {term:"Whole blood transfusion",def:"Increasingly used in military and trauma settings — provides red cells, plasma, and platelets together without the dilution of component therapy"},
    {term:"Crystalloid overload risk",def:"Large volumes of saline or lactated Ringer's solution dilute clotting factors, worsen hypothermia, and contribute to the lethal triad"},
    {term:"Classes of hemorrhagic shock",def:"Class I (<15% blood loss), II (15–30%), III (30–40%), IV (>40%) — Class III+ is life-threatening requiring immediate blood product resuscitation"},
    {term:"Class I hemorrhage signs",def:"<750 mL blood loss — minimal symptoms, heart rate <100 bpm, normal BP — body fully compensates"},
    {term:"Class II hemorrhage signs",def:"750–1500 mL blood loss — heart rate 100–120 bpm, anxiety, decreased urine output, narrow pulse pressure"},
    {term:"Class III hemorrhage signs",def:"1500–2000 mL blood loss — heart rate >120, hypotension, altered mental status, markedly decreased urine output — requires blood products"},
    {term:"Class IV hemorrhage signs",def:">2000 mL blood loss — heart rate >140, severe hypotension, unconsciousness — immediately life-threatening"},
    {term:"Pulse pressure in hemorrhage",def:"The difference between systolic and diastolic BP — narrowing pulse pressure is an early sign of volume loss and vasoconstriction"},
    {term:"Tourniquet conversion",def:"In hospital, tourniquets should be converted to definitive hemorrhage control (surgery, vascular repair) as quickly as possible to minimize ischemia time"},
    {term:"Fasciotomy after tourniquet",def:"Release of fascial compartments may be needed if a tourniquet was in place >2 hours — compartment syndrome from reperfusion can occur"},
    {term:"Compartment syndrome",def:"Pressure buildup within a muscle compartment after injury or prolonged tourniquet — causes ischemia if not released by fasciotomy"},
    {term:"Reperfusion injury",def:"Damage that occurs when blood flow is restored to ischemic tissue — releases inflammatory mediators and free radicals"},
    {term:"Hemostatic dressing comparison",def:"Combat Gauze (kaolin) vs Celox (chitosan) — Combat Gauze is FDA-cleared for military use; Celox works independently of the clotting cascade, useful in anticoagulated patients"},
    {term:"Wound packing vs tourniquet decision",def:"Tourniquet for extremity wounds where pressure alone fails; wound packing for junctional or torso wounds where tourniquet is impossible"},
    {term:"Pressure dressing application",def:"Apply gauze over wound, wrap elastic bandage with consistent tension, secure end — the bar of an Israeli bandage creates focused pressure"},
    {term:"Non-compressible hemorrhage",def:"Bleeding in the torso, pelvis, or neck that cannot be controlled with tourniquet or direct pressure — requires emergency surgery"},
    {term:"Resuscitative endovascular balloon occlusion (REBOA)",def:"A catheter-based device inflated in the aorta to reduce blood flow to hemorrhaging pelvic or abdominal vessels — a bridge to surgery"},
    {term:"Junctional tourniquet device",def:"Devices like the JETT or SAM Junctional Tourniquet apply pressure to the groin or axilla — bleeding sites where standard tourniquets cannot be used"},
    {term:"Hemorrhage control in pregnancy",def:"Standard direct pressure and wound packing apply; tourniquets are not effective on the gravid abdomen — requires urgent surgical intervention"},
    {term:"Bleeding control in anticoagulated patients",def:"Patients on warfarin, Xarelto, or Eliquis have impaired clotting — hemostatic agents like Celox (chitosan) may work better; reversal agents needed in hospital"},
    {term:"Factor Xa inhibitors and bleeding",def:"Apixaban (Eliquis) and rivaroxaban (Xarelto) — reversed with andexanet alfa; can cause severe bleeding that is difficult to control in the field"},
    {term:"Warfarin and bleeding risk",def:"Warfarin prolongs INR — patients on warfarin who sustain trauma can bleed dramatically; reversed with vitamin K and/or fresh frozen plasma"},
    {term:"Hemophilia and bleeding control",def:"People with hemophilia lack clotting factors — factor replacement is needed; field hemostatic dressings provide temporary control"},
    {term:"Pediatric hemorrhage class thresholds",def:"Children have smaller total blood volume (~80 mL/kg) — loss of 30–40 mL/kg constitutes Class III hemorrhage (proportionally similar to adults)"},
    {term:"Tourniquet pain management",def:"Tourniquets cause significant pain — this is expected and normal; do not loosen for pain; reassure the patient and await EMS with analgesics"},
    {term:"Scene time in trauma",def:"'Load and go' principle — major trauma patients should be transported to trauma center within 10 minutes of scene arrival; do not delay for complex field interventions"},
    {term:"Platinum 10 minutes",def:"The goal of spending no more than 10 minutes on scene for major trauma — minimizing prehospital time improves survival"},
    {term:"Wound irrigation in field",def:"Do not irrigate or probe penetrating wounds in the field — this can dislodge clots and worsen bleeding; cover and transport"},
    {term:"Blast injury and hemorrhage",def:"Explosions cause primary (pressure wave), secondary (shrapnel), tertiary (thrown), and quaternary (burns) injuries — all can cause life-threatening hemorrhage"},
    {term:"Gunshot wound hemorrhage",def:"High-velocity gunshot wounds create both entry and exit wounds with a cavitation effect — both wounds may require packing"},
    {term:"Stab wound hemorrhage",def:"Stab wounds may have a small entry wound but deep internal damage — field treatment focuses on external bleeding control; internal hemorrhage requires surgery"},
  ]);

  fc.hard = fc.hard.concat([
    {term:"von Willebrand disease and bleeding",def:"The most common inherited bleeding disorder — impairs platelet adhesion; patients may need desmopressin (DDAVP) or von Willebrand factor concentrate to stop hemorrhage"},
    {term:"DIC (disseminated intravascular coagulation)",def:"Widespread activation of clotting followed by consumption of clotting factors — causes simultaneous bleeding and clotting; occurs in sepsis, major trauma, obstetric emergencies"},
    {term:"Trauma-induced coagulopathy (TIC)",def:"Coagulopathy that develops within minutes of major injury — driven by tissue factor release, hypoperfusion, and hypothermia — distinct from DIC"},
    {term:"Viscoelastic testing (TEG/ROTEM)",def:"Thromboelastography (TEG) and rotational thromboelastometry (ROTEM) — point-of-care devices measuring the full clotting process from initiation to fibrinolysis — guides targeted resuscitation"},
    {term:"Fibrinolysis and bleeding",def:"Premature breakdown of clots — occurs in major trauma; treated with TXA; excessive fibrinolysis leads to hemorrhage that does not respond to clot-forming measures"},
    {term:"Cryoprecipitate in trauma",def:"Contains fibrinogen, factor VIII, von Willebrand factor — used in massive transfusion when fibrinogen is depleted; fibrinogen <150 mg/dL predicts ongoing hemorrhage"},
    {term:"Massive transfusion protocol (MTP)",def:"A pre-established hospital protocol that activates rapid delivery of blood components in a 1:1:1 ratio to trauma patients requiring >10 units pRBC in 24 hours"},
    {term:"Platelet dysfunction in hypothermia",def:"Platelet aggregation and adhesion are severely impaired below 33°C — rewarming is a critical component of trauma resuscitation alongside blood products"},
    {term:"Cell salvage (autotransfusion)",def:"Intraoperative collection, washing, and reinfusion of the patient's own shed blood — reduces need for donor blood in major surgical hemorrhage"},
    {term:"AABB guidelines for massive hemorrhage",def:"American Association of Blood Banks recommends 1:1:1 or 1:1:2 (plasma:platelet:pRBC) ratio in massive hemorrhage and early use of viscoelastic testing"},
    {term:"Endothelial glycocalyx in trauma",def:"A protective layer on vascular endothelium — damaged by ischemia, large crystalloid volumes, and inflammation — loss contributes to fluid leaking out of vessels (third spacing)"},
    {term:"Damage control resuscitation (DCR) principles",def:"(1) Limit crystalloids, (2) Use blood products early in 1:1:1 ratio, (3) Allow permissive hypotension, (4) Prevent/treat hypothermia and acidosis, (5) Use TXA within 3 hours"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"What are the 3 steps of Stop the Bleed?",opts:["Look, Listen, Act","Call 911, Compress, Tourniquet","Check, Call, Care","Stop, Drop, Roll"],correct:1,explain:"The 3 steps are Call 911, Compress the wound (direct pressure), and apply a Tourniquet if direct pressure fails on a limb. These three actions can be performed by any bystander."},
    {q:"What organization launched the Stop the Bleed campaign in 2015?",opts:["American Red Cross","CDC","American College of Surgeons","FEMA"],correct:2,explain:"The American College of Surgeons launched Stop the Bleed in 2015 following the Sandy Hook shooting, aiming to train the public to control life-threatening bleeding before EMS arrives."},
    {q:"Bright red blood that spurts or pulses with each heartbeat indicates which type of bleeding?",opts:["Capillary","Venous","Arterial","Internal"],correct:2,explain:"Arterial bleeding is bright red and spurts or pulses with the heartbeat because it comes directly from pressurized arteries. It is the most immediately life-threatening type of external bleeding."},
    {q:"How far above a wound should a tourniquet be applied?",opts:["Directly over the wound","1 inch above","2–3 inches above","As high as possible on the limb"],correct:2,explain:"Tourniquets should be applied 2–3 inches (about two finger-widths) above the wound. Applying directly over a wound or joint is ineffective."},
    {q:"Why should you never remove a tourniquet once applied in the field?",opts:["It causes nerve damage if removed","Removing it can cause sudden blood loss and death","It is painful to remove","It is glued to the skin"],correct:1,explain:"Removing a tourniquet in the field can cause a sudden rush of blood loss and death. Only hospital staff with blood products and surgical capability should remove tourniquets."},
    {q:"Where should you write the time when applying a tourniquet?",opts:["On your glove","On the patient's forehead or on the tourniquet","In your phone","You don't need to document time"],correct:1,explain:"Write T= followed by the time of tourniquet application on the patient's skin (forehead) or on the tourniquet itself. This is critical information for the receiving hospital team."},
    {q:"What is the first step before assisting a bleeding patient?",opts:["Apply a tourniquet","Put on gloves","Call the patient's family","Check blood pressure"],correct:1,explain:"Always put on gloves first to protect yourself from bloodborne pathogens. Personal protective equipment (PPE) is the first step before any contact with a bleeding patient."},
    {q:"What should you do if direct pressure alone does not stop limb bleeding?",opts:["Apply more gauze and wait","Apply a tourniquet","Remove the gauze and repack","Call a doctor"],correct:1,explain:"If direct pressure does not stop limb bleeding, apply a tourniquet 2–3 inches above the wound. Tourniquets are life-saving tools, not last resorts."},
    {q:"What type of wound requires packing rather than a tourniquet?",opts:["Arm laceration","Leg wound","Junctional wound (groin, armpit, neck)","Hand wound"],correct:2,explain:"Junctional wounds in the groin, armpit, or neck cannot receive a tourniquet — you cannot encircle those areas. Instead, pack the wound tightly with gauze and apply firm direct pressure."},
    {q:"How long should you apply direct pressure to a packed wound?",opts:["30 seconds","1 minute","At least 3 minutes","10 minutes"],correct:2,explain:"Apply firm, continuous pressure for at least 3 minutes after wound packing to allow hemostatic agents to activate and clots to form. Do not peek or lift gauze during this time."},
    {q:"What does 'exsanguination' mean?",opts:["Blood poisoning","Death from excessive blood loss","Fainting from blood sight","Low blood pressure"],correct:1,explain:"Exsanguination is death from excessive blood loss. A person can die from arterial bleeding in as few as 3–5 minutes — which is why bystander action before EMS arrives is so critical."},
    {q:"What is the approximate average EMS response time in the U.S.?",opts:["1–2 minutes","3–4 minutes","7–10 minutes","15–20 minutes"],correct:2,explain:"Average EMS response time is 7–10 minutes nationally. Since a patient can die from arterial bleeding in 3–5 minutes, trained bystanders who act immediately can prevent death before EMS arrives."},
    {q:"What is a 'junctional wound'?",opts:["A wound between two bones","A wound in the groin, armpit, neck, or pelvis where a tourniquet cannot be applied","A wound that has already been treated","A wound from a blunt object"],correct:1,explain:"Junctional wounds are located at body junctions where tourniquets cannot be applied — the groin, armpit, neck, and pelvis. These require wound packing and direct pressure."},
    {q:"Which of the following is a sign of significant blood loss?",opts:["Flushed, warm skin","Pale, cold, clammy skin and rapid heart rate","Slow, regular breathing","Normal blood pressure"],correct:1,explain:"Pale, cold, clammy skin and rapid heart rate are signs of hemorrhagic shock — the body is redirecting blood from the skin to vital organs and increasing heart rate to compensate for blood loss."},
    {q:"What is hemostatic gauze?",opts:["Standard cotton gauze","Gauze treated with agents that accelerate blood clotting","Gauze soaked in antiseptic","Gauze used only in hospitals"],correct:1,explain:"Hemostatic gauze is impregnated with clotting-accelerating agents (kaolin or chitosan) that help form blood clots faster when packed into wounds. Brands include QuikClot Combat Gauze and Celox."},
    {q:"What is the Hartford Consensus?",opts:["A law requiring AEDs in all schools","A 2013 agreement establishing that bystander bleeding control saves lives","A military trauma protocol","A standard for hospital emergency rooms"],correct:1,explain:"The Hartford Consensus (2013) was a landmark agreement by medical, law enforcement, and emergency response leaders establishing that immediate bystander action — particularly hemorrhage control — can prevent preventable trauma deaths."},
    {q:"What does AVPU stand for in trauma assessment?",opts:["Airway, Ventilation, Pulse, Unconscious","Alert, Verbal, Pain, Unresponsive","Assess, Verify, Prioritize, Understand","Airway, Vitals, Pupils, Unresponsive"],correct:1,explain:"AVPU is a rapid mental status tool: Alert (aware), Verbal (responds to voice), Pain (responds only to pain), Unresponsive (no response). Used to quickly gauge how much blood a trauma patient has lost."},
    {q:"What is the minimum width recommended for an improvised tourniquet?",opts:["Half an inch","1 inch","3 inches","5 inches"],correct:1,explain:"An improvised tourniquet should be at least 1 inch wide. Narrower materials (like rope or wire) cut into tissue without stopping arterial blood flow and can cause permanent damage."},
    {q:"Which bleeding control step comes FIRST after scene safety?",opts:["Apply tourniquet","Put on gloves","Call 911","Pack the wound"],correct:1,explain:"After confirming scene safety, the first step is always to put on gloves (PPE). Protecting yourself from bloodborne pathogens is essential before any patient contact."},
    {q:"What is the purpose of writing the time on a tourniquet?",opts:["To track how long the patient has been injured","To tell the hospital how long the tourniquet has been on so they can plan for complications","To help police document the event","It is not necessary in civilian settings"],correct:1,explain:"Tourniquet time helps hospital staff assess ischemia risk. Tourniquets left on >2 hours risk nerve and muscle damage. Knowing the exact time allows surgeons to plan removal and possible fasciotomy."},
    {q:"Stop the Bleed kits in public spaces are most often co-located with which other device?",opts:["Fire extinguishers","AEDs (Automated External Defibrillators)","First aid stations","Security cameras"],correct:1,explain:"Stop the Bleed kits are increasingly placed alongside AEDs in schools, airports, stadiums, and public buildings — following the same public access model that normalized AEDs in public spaces."},
    {q:"What is the 'windlass' on a CAT tourniquet?",opts:["The Velcro strap","A rod that is twisted to tighten the tourniquet","The buckle that holds the band","The time-stamp window"],correct:1,explain:"The windlass is the plastic rod on a CAT tourniquet that is twisted to tighten the band after initial application — the mechanism that provides the mechanical advantage needed to occlude arterial blood flow."},
    {q:"Which law protects bystanders who give emergency aid in good faith?",opts:["HIPAA","Duty to Act law","Good Samaritan law","Emergency Medical Treatment Act"],correct:2,explain:"Good Samaritan laws in all 50 U.S. states protect bystanders who provide emergency first aid in good faith and without expectation of payment from civil liability — encouraging public intervention."},
    {q:"What should you do with a wound that has an object impaled in it?",opts:["Remove the object before packing","Apply pressure around the object — never remove it","Cover it and ignore it","Wiggle it to assess depth"],correct:1,explain:"Never remove an impaled object — it may be tamponading (plugging) the bleeding vessel. Apply pressure around the object, stabilize it, and transport immediately."},
    {q:"Direct pressure is the first step for which types of wounds?",opts:["Limb wounds only","All external bleeding wounds","Junctional wounds only","Wounds with impaled objects only"],correct:1,explain:"Direct pressure — pressing firmly on the wound — is the first step for ALL external bleeding, regardless of location. A tourniquet is added for uncontrolled limb bleeding; packing is added for deep or junctional wounds."},
    {q:"What does it mean if a tourniquet is 'properly applied'?",opts:["The patient feels pain","The bleeding has stopped","The limb turns blue","The tourniquet is as tight as possible"],correct:1,explain:"A properly applied tourniquet has stopped the bleeding. The endpoint is cessation of hemorrhage — not a specific tightness level and not patient pain. If bleeding continues, apply a second tourniquet above the first."},
    {q:"Approximately how much blood can an adult lose before hemorrhagic shock develops?",opts:["200–300 mL (less than 1 pint)","1,000–1,500 mL (about 1–1.5 quarts)","4,000 mL (1 gallon)","Only IV fluids can replace lost blood"],correct:1,explain:"Loss of 1,000–1,500 mL (about 30% of the 5-liter adult blood volume) produces significant hemorrhagic shock. Death can occur after loss of >40% (~2,000 mL). This is why rapid hemorrhage control is so critical."},
    {q:"What is the correct action if you apply a tourniquet and the bleeding continues?",opts:["Remove the tourniquet and try direct pressure","Loosen and retighten the same tourniquet","Apply a second tourniquet immediately above the first","Wait for EMS to decide"],correct:2,explain:"If bleeding continues after the first tourniquet, apply a second tourniquet directly above (proximal to) the first — never remove the first one. Continue until bleeding stops."},
    {q:"How should you position an unconscious patient after controlling hemorrhage?",opts:["Flat on their back","On their side (recovery position)","Sitting upright","Face down"],correct:1,explain:"Place an unconscious patient in the recovery position (on their side) after controlling hemorrhage — this protects the airway from aspiration of vomit while you wait for EMS."},
    {q:"Which of the following is NOT a component of a standard Stop the Bleed kit?",opts:["Tourniquet","Hemostatic gauze","Gloves","Blood pressure cuff"],correct:3,explain:"Standard Stop the Bleed kits contain a tourniquet, hemostatic or regular gauze, gloves, a pressure bandage, and a marker. A blood pressure cuff is a clinical device — not part of a field bleeding control kit."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"Why does the MARCH protocol prioritize massive hemorrhage control BEFORE airway management?",opts:["Airway is less important than bleeding","Exsanguination kills faster than most airway obstructions in trauma — seconds matter","It is easier to control bleeding than manage an airway","Military protocol has never been evaluated"],correct:1,explain:"MARCH (Massive Hemorrhage, Airway, Respiration, Circulation, Hypothermia) prioritizes hemorrhage because exsanguination from arterial bleeding kills in 3–5 minutes — faster than most traumatic airway obstructions. This is counterintuitive to traditional ABC training."},
    {q:"What is the 'lethal triad' of trauma and why is it dangerous?",opts:["Bleeding, pain, and shock — cause patient distress","Hypothermia, acidosis, and coagulopathy — each worsens the others in a deadly cycle","Hypoxia, hypovolemia, and hypotension — cause cardiac arrest","Infection, dehydration, and organ failure — late complications"],correct:1,explain:"The lethal triad is hypothermia + acidosis + coagulopathy. Each worsens the others: cold blood doesn't clot, acidosis further impairs clotting enzymes, coagulopathy causes more blood loss → more hypothermia and acidosis. Breaking this cycle requires targeted resuscitation with blood products and warming."},
    {q:"Why is permissive hypotension used in penetrating trauma resuscitation?",opts:["It conserves IV fluids in resource-limited settings","High BP forces more clot breakdown; low BP allows clots to form and avoids diluting clotting factors with crystalloid","Patients with penetrating trauma cannot tolerate normal BP","It reduces pain from the injury"],correct:1,explain:"In penetrating trauma, allowing systolic BP of 80–90 mmHg prevents dislodging forming clots, reduces crystalloid-induced dilution of clotting factors, and minimizes the lethal triad. It is NOT used in traumatic brain injury where cerebral perfusion pressure must be maintained."},
    {q:"What distinguishes hemostatic gauze brands Celox and QuikClot Combat Gauze?",opts:["They are identical products with different names","QuikClot uses kaolin to activate the clotting cascade; Celox uses chitosan which forms clots independent of the clotting cascade — useful in hypothermic or anticoagulated patients","Celox is only for military use; QuikClot is for civilians","QuikClot generates dangerous heat; Celox does not work"],correct:1,explain:"QuikClot Combat Gauze uses kaolin to trigger the body's normal clotting cascade. Celox uses chitosan (shellfish-derived) to physically bind red blood cells and form a gel-like clot independent of clotting factors — potentially more effective in anticoagulated or hypothermic patients where the clotting cascade is impaired."},
    {q:"A trauma patient has Class III hemorrhagic shock. What does this mean clinically?",opts:["Minor blood loss — give oral fluids and monitor","Moderate loss — IV saline will restore volume","Loss of 30–40% blood volume (1500–2000 mL) — requires immediate blood product transfusion, not just IV fluids","Loss >40% — patient is already dead"],correct:2,explain:"Class III hemorrhage (30–40% blood loss) causes: heart rate >120, hypotension, altered mental status, markedly decreased urine output. At this point, crystalloid alone is insufficient and may worsen the lethal triad. Packed red blood cells, plasma, and platelets in 1:1:1 ratio are needed."},
    {q:"Why is TXA (tranexamic acid) ineffective or possibly harmful when given more than 3 hours after injury?",opts:["The drug expires after 3 hours","After 3 hours, fibrinolysis has already completed — blocking it further may cause pathological clot formation","The kidneys clear TXA too quickly to be effective","TXA only works on arterial bleeding"],correct:1,explain:"In early trauma, fibrinolysis (clot breakdown) is pathologically accelerated. TXA blocks this to preserve clots. By 3 hours, the fibrinolytic phase has resolved — giving TXA then risks promoting thrombosis without benefit. The CRASH-2 trial showed harm when TXA was given 3+ hours post-injury."},
    {q:"A patient on rivaroxaban (Xarelto) sustains a major laceration. How does this complicate bleeding control?",opts:["It has no effect — Xarelto only prevents heart attacks","Rivaroxaban inhibits Factor Xa, impairing the coagulation cascade — standard hemostasis may be inadequate; reversal with andexanet alfa is needed in hospital","Rivaroxaban causes excessive clotting, not bleeding","The drug wears off before bleeding becomes a problem"],correct:1,explain:"Factor Xa inhibitors like rivaroxaban impair the coagulation cascade — patients bleed more and clot less effectively. Field treatment is the same (direct pressure, packing, tourniquet) but hemostatic agents like Celox (chitosan, clotting-factor independent) may be more effective. Hospital reversal requires andexanet alfa (Andexxa)."},
    {q:"What is damage control resuscitation (DCR) and how does it differ from traditional trauma resuscitation?",opts:["DCR uses more IV fluids to rapidly restore blood pressure","DCR limits crystalloids, uses early 1:1:1 blood products, allows permissive hypotension, and prevents hypothermia — replacing the traditional high-volume crystalloid approach","DCR focuses only on surgery, not fluid management","DCR is only used in military, not civilian trauma"],correct:1,explain:"Traditional resuscitation used large crystalloid volumes (normal saline, LR) to restore BP. DCR replaces this with: early 1:1:1 blood product transfusion, permissive hypotension (~80–90 mmHg systolic), TXA within 3 hours, and aggressive prevention of hypothermia. Crystalloid overload worsens the lethal triad."},
    {q:"What is REBOA and when is it used?",opts:["A type of tourniquet for the abdomen","A resuscitative endovascular balloon occlusion device placed in the aorta to reduce flow to non-compressible hemorrhage sites — bridges to surgery","A reversal agent for anticoagulant-related bleeding","A technique for packing pelvic wounds"],correct:1,explain:"REBOA (Resuscitative Endovascular Balloon Occlusion of the Aorta) involves placing a balloon catheter in the aorta and inflating it to reduce blood flow to areas of non-compressible hemorrhage (pelvis, abdomen). It temporarily maintains cerebral and cardiac perfusion while the patient is transported to an OR. It is a bridge, not a definitive treatment."},
    {q:"Why does major trauma cause coagulopathy within minutes of injury, even before significant blood loss?",opts:["The body releases anti-clotting hormones as a protective response","Tissue factor release, endothelial damage, and shock activate anticoagulant and fibrinolytic pathways early — this trauma-induced coagulopathy (TIC) is distinct from DIC","Blood dilution from crystalloid infusion is the sole cause","Coagulopathy in trauma is always a late finding"],correct:1,explain:"Trauma-induced coagulopathy (TIC) begins within minutes of major injury from: tissue factor release at injury sites triggering systemic coagulation activation, hypoperfusion activating protein C (anticoagulant), and endothelial damage causing fibrinolysis. TIC can be severe before any resuscitation fluids have been given."},
    {q:"A tourniquet has been in place for 3 hours when the patient arrives at the hospital. What complication must the surgical team anticipate?",opts:["Tourniquet site infection","Compartment syndrome and reperfusion injury when blood flow is restored","Permanent paralysis in all cases","The tourniquet must be left on permanently"],correct:1,explain:"Prolonged tourniquet application (>2 hours) causes ischemia to distal tissues. When blood flow is restored, reperfusion injury occurs — releasing inflammatory mediators that damage muscle cells. Compartment syndrome (pressure buildup) can develop and may require fasciotomy (surgical release of fascial compartments)."},
    {q:"In a mass casualty event, which patients should receive bleeding control interventions FIRST?",opts:["The most severely injured patient with no vital signs","All patients in order of arrival","Patients with life-threatening hemorrhage who are still conscious and have vital signs","Patients with the least severe injuries to ensure fastest recovery"],correct:2,explain:"In mass casualty triage (SALT or START), bleeding control focuses on patients in the RED (immediate) category — life-threatening bleeding with vital signs present. Patients with no vital signs (BLACK/expectant) receive lowest priority when resources are limited. This maximizes lives saved."},
    {q:"What is the significance of narrowing pulse pressure in a hemorrhaging patient?",opts:["It indicates the patient is stabilizing","Narrowing pulse pressure (systolic–diastolic) is an early sign of volume loss and vasoconstriction — often precedes frank hypotension","It means the tourniquet is too tight","It indicates infection"],correct:1,explain:"Pulse pressure (systolic BP minus diastolic BP) narrows when blood volume decreases — the body constricts peripheral vessels (raising diastolic), while systolic pressure is maintained by increased heart rate. Narrowing pulse pressure can be an earlier warning than absolute hypotension."},
    {q:"Why is wound irrigation contraindicated in the field for penetrating wounds?",opts:["Irrigation causes pain","Irrigation can dislodge forming clots, worsen bleeding, and introduce air into vascular wounds","Irrigation is fine in the field","Irrigation is only contraindicated for abdominal wounds"],correct:1,explain:"Field irrigation or probing of penetrating wounds risks dislodging clots that have formed naturally, potentially causing more severe hemorrhage. Cover and compress — do not irrigate, probe, or remove impaled objects. Leave that for the hospital."},
    {q:"How does hypothermia impair hemorrhage control in major trauma?",opts:["It has no effect on clotting","Hypothermia reduces clotting enzyme function (optimal at 37°C) and impairs platelet aggregation — worsening coagulopathy and increasing bleeding","It causes vasoconstriction that reduces bleeding","Hypothermia only matters after hospital admission"],correct:1,explain:"Clotting is an enzyme-driven process optimized at 37°C. At 34°C, clotting efficiency drops significantly. At <32°C, coagulation is severely impaired. This is why trauma patients must be kept warm — blankets, warm IV fluids, warm resuscitation rooms — as part of damage control resuscitation."},
    {q:"What information must be communicated during EMS handoff for a bleeding patient?",opts:["Only the patient's name and insurance","Time of injury, tourniquet application time, mechanism of injury, estimated blood loss, interventions performed, and changes in patient condition","Only the type of wound","EMS does not need field information"],correct:1,explain:"An effective EMS handoff includes: time of injury (T=), tourniquet time (T=), mechanism of injury, estimated blood loss, all interventions performed, and any changes in mental status or vital signs. This directly guides hospital decision-making and tourniquet management."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"A patient in Class IV hemorrhagic shock has lost >40% of blood volume. Their physiology includes all of the following EXCEPT:",opts:["Heart rate >140 bpm","Severe hypotension","Bradycardia as the primary compensatory mechanism","Loss of consciousness"],correct:2,explain:"Class IV hemorrhage causes TACHYCARDIA (not bradycardia) as the primary compensatory mechanism — the body increases heart rate to maintain cardiac output. Bradycardia in shock (vagally-mediated or terminal) is a pre-arrest sign. All other options — tachycardia, severe hypotension, altered consciousness — are hallmarks of Class IV."},
    {q:"Balanced resuscitation with 1:1:1 (pRBC:FFP:platelets) is superior to crystalloid resuscitation in massive hemorrhage primarily because:",opts:["It avoids the need for surgical intervention","Blood products replace volume AND clotting factors while avoiding the dilutional coagulopathy, hypothermia, and acidosis caused by large crystalloid volumes","It is less expensive than saline","It works faster than IV fluids"],correct:1,explain:"Crystalloid (saline, LR) replaces volume but dilutes clotting factors, lowers body temperature, and can cause hyperchloremic acidosis — all three elements of the lethal triad. Blood products restore both volume and clotting capacity. The PROPPR trial confirmed that 1:1:1 resuscitation reduces 24-hour and 30-day mortality in massive hemorrhage."},
    {q:"Viscoelastic testing (TEG/ROTEM) guides trauma resuscitation by providing which information that standard coagulation tests (INR, PTT) cannot?",opts:["Patient blood type","Real-time assessment of the entire clotting process — initiation, clot strength, and fibrinolysis — allowing goal-directed blood product therapy","Whether a tourniquet was applied correctly","Patient's medication history"],correct:1,explain:"Standard tests (INR, PTT, platelet count) measure individual components and take 30–60 minutes. TEG/ROTEM measures the complete clot formation and lysis process in real time (20–30 minutes), showing exactly which component is deficient — fibrinogen (needs cryoprecipitate), factors (needs FFP), platelets (needs platelet transfusion) or fibrinolysis (needs TXA). This guides targeted, goal-directed therapy."},
    {q:"In the context of damage control surgery (DCS), what is the correct sequence of care?",opts:["Full definitive repair immediately, then ICU, then rehabilitation","Abbreviated hemorrhage/contamination control in OR → ICU resuscitation (correct lethal triad) → planned return to OR for definitive repair","ICU stabilization first, then surgery when patient is stronger","Surgery is deferred until all blood products are available"],correct:1,explain:"DCS is staged: (1) Abbreviated OR — stop bleeding (packing, ligation, shunts), control contamination, close temporarily; (2) ICU — correct hypothermia, acidosis, coagulopathy with blood products; (3) Return to OR (24–72 hours) — definitive anatomic repair. This approach prevents the lethal triad from killing the patient during a prolonged initial surgery."},
    {q:"A patient with von Willebrand disease type 3 sustains a major laceration. Standard field hemostatic dressings are applied. Why might hospital treatment differ significantly from a patient without a bleeding disorder?",opts:["No difference — bleeding disorders don't affect wound healing","vWD Type 3 patients lack von Willebrand factor and may also have low Factor VIII — bleeding will continue despite local measures until vWF concentrate and Factor VIII are replaced","They need a higher tourniquet pressure","Standard tourniquets are contraindicated in bleeding disorders"],correct:1,explain:"von Willebrand factor (vWF) is essential for platelet adhesion to damaged vessel walls and carries Factor VIII. Type 3 vWD (complete absence of vWF) causes severe bleeding that local hemostatics and tourniquets cannot fully control — vWF concentrate (Humate-P, Wilate) with Factor VIII is required. Field care buys time; definitive treatment is factor replacement."},
    {q:"REBOA (Resuscitative Endovascular Balloon Occlusion of the Aorta) is contraindicated in which zone for hemorrhage from a pelvic fracture?",opts:["Zone I (descending thoracic aorta) — indicated here","Zone III (infra-renal aorta) — most appropriate for pelvic hemorrhage","Zone II (visceral aorta) — contraindicated due to renal and mesenteric ischemia","Zone IV (iliac arteries) — indicated here"],correct:2,explain:"REBOA is placed in Zone I (descending thoracic aorta, above celiac) for abdominal/thoracic hemorrhage or Zone III (infra-renal, below renal arteries) for pelvic hemorrhage. Zone II is contraindicated — inflation here occludes the renal and mesenteric vessels, causing immediate ischemic injury to kidneys and bowel. Zone III inflation for pelvic hemorrhage maintains renal perfusion while reducing pelvic hemorrhage."},
    {q:"The CRASH-2 trial's primary finding regarding TXA administration timing has which clinical implication for Stop the Bleed-trained bystanders and first responders?",opts:["Bystanders should carry TXA and administer it immediately","First responders who can administer medications should consider early TXA — and report accurate injury time to hospital so the 3-hour window can be tracked","TXA has no role in prehospital care","TXA should only be given after blood pressure is stabilized"],correct:1,explain:"CRASH-2 showed TXA reduces trauma mortality when given within 1–3 hours of injury. While bystanders cannot administer IV TXA, first responders (paramedics) should consider early TXA administration. Critically, accurate documentation of injury time (by any bystander) allows the hospital team to determine if TXA is still within its therapeutic window — another way bystander documentation saves lives."},
  ]);
})();

// ── STOP THE BLEED DEDUPLICATION ──────────────────────────────────────────
(function(){
  if(!window.QB_STOP_BLEED) return;
  var seenF = {}, seenQ = {};
  ['easy','medium','hard'].forEach(function(d){
    var arr = window.QB_STOP_BLEED.flashcards[d] || [];
    window.QB_STOP_BLEED.flashcards[d] = arr.filter(function(f){
      var key = (f.term||f.front||'').toLowerCase().trim();
      if(seenF[key]) return false;
      seenF[key] = true;
      return true;
    });
    var qArr = window.QB_STOP_BLEED.quiz[d] || [];
    window.QB_STOP_BLEED.quiz[d] = qArr.filter(function(q){
      var key = (q.q||q.question||'').toLowerCase().trim();
      if(seenQ[key]) return false;
      seenQ[key] = true;
      return true;
    });
  });
})();

// ── STOP THE BLEED TOP-UP (+159 flash, +66 quiz) ──────────────────────────
(function(){
  if(!window.QB_STOP_BLEED) return;
  var fc = window.QB_STOP_BLEED.flashcards;
  var qz = window.QB_STOP_BLEED.quiz;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});

  fc.easy = fc.easy.concat([
    {term:"Hemorrhage control priority",def:"Control life-threatening bleeding before any other intervention except scene safety — hemorrhage is the #1 preventable cause of trauma death"},
    {term:"Tourniquet effectiveness in combat",def:"Military data shows tourniquet use reduced extremity hemorrhage deaths by up to 85% in Iraq and Afghanistan with minimal complications"},
    {term:"Stop the Bleed training population",def:"Millions of civilians trained since 2015 — teachers, students, coaches, office workers — anyone can learn to stop life-threatening bleeding"},
    {term:"Bleeding emergency location",def:"Most life-threatening bleeding emergencies happen in everyday settings — workplaces, schools, roads — not just combat or hospitals"},
    {term:"Tourniquet social stigma (historical)",def:"Tourniquets were once avoided due to fear of limb loss — modern evidence shows properly applied tourniquets rarely cause permanent harm"},
    {term:"Chest wound (sucking chest wound)",def:"A penetrating chest wound that makes a sucking sound — cover with a vented chest seal to prevent tension pneumothorax"},
    {term:"Chest seal",def:"A one-way valve dressing placed over a penetrating chest wound — allows air to escape but prevents it from entering the chest cavity"},
    {term:"Tension pneumothorax",def:"Air trapped in the chest compressing the heart and lungs — a life threat caused by sealing a chest wound without a vented seal"},
    {term:"Tourniquet over clothing",def:"Acceptable if needed — applying over clothing is better than delaying; tighten enough to stop bleeding"},
    {term:"High and tight tourniquet rule",def:"When in doubt about tourniquet placement, go higher on the limb — this is safer than placing too low near the wound"},
    {term:"Windlass lock",def:"The securing mechanism that holds the windlass rod in place after tightening — must be locked to prevent tourniquet from loosening"},
    {term:"Velcro strap (tourniquet)",def:"The wide strap on a CAT tourniquet wrapped around the limb first — must be tight before windlass is twisted"},
    {term:"Self-application of tourniquet",def:"A CAT tourniquet can be applied one-handed to one's own arm — a key design feature for soldiers and injured first responders"},
    {term:"Blood soaked through dressing",def:"Do NOT remove — add more material on top and continue firm pressure; removing can disrupt forming clots"},
    {term:"Elevation in bleeding control",def:"Elevating a bleeding limb above the heart can help reduce blood flow to the wound — used alongside direct pressure"},
    {term:"Pressure point technique",def:"Pressing on the major artery proximal to a wound (e.g., brachial, femoral) to reduce blood flow — a supplemental, not standalone, technique"},
    {term:"Femoral artery location",def:"The major artery of the thigh running through the groin — damage causes rapid, life-threatening hemorrhage"},
    {term:"Brachial artery location",def:"The major artery of the upper arm — injury causes significant bleeding; tourniquet applied above injury controls it"},
    {term:"Popliteal artery",def:"The artery behind the knee — injuries here are serious; tourniquet placed above the knee controls distal leg bleeding"},
    {term:"Radial and ulnar arteries",def:"The two main arteries of the forearm — together supply the hand; tourniquet on the forearm controls both"},
    {term:"Hemostatic bandage",def:"A bandage pre-impregnated with hemostatic agents — applied directly to wounds as an alternative to loose hemostatic gauze"},
    {term:"Pressure bandage wrapping",def:"Wrap bandage firmly in overlapping layers, pulling with consistent tension — too loose won't maintain pressure, too tight adds no benefit over tourniquet"},
    {term:"Tourniquet friction adaptor buckle",def:"The metal buckle on a CAT tourniquet that allows the strap to be cinched tight before windlass tightening"},
    {term:"Time-critical nature of hemorrhage",def:"Every minute of uncontrolled hemorrhage worsens shock and coagulopathy — bystander action in the first minutes saves lives no EMS can save"},
    {term:"Hemorrhage control education goal",def:"To create a nation of immediate responders — just as CPR training created a nation of bystander defibrillation advocates"},
    {term:"Bleeding control first aid vs CPR",def:"Bleeding control training is 2 hours vs CPR's 4–8 hours — shorter barrier to learning a potentially life-saving skill"},
    {term:"Pediatric blood volume",def:"Children have smaller total blood volume (~80 mL/kg) — much less blood loss is proportionally life-threatening compared to adults"},
    {term:"Elderly and hemorrhagic shock",def:"Older patients have less cardiovascular reserve — may decompensate at lower blood loss volumes than younger patients"},
    {term:"Antiplatelet drugs and bleeding",def:"Aspirin and clopidogrel (Plavix) impair platelet function — patients on these bleed more; field care same but hospital treatment differs"},
    {term:"Splenic laceration (internal)",def:"A common internal injury from blunt abdominal trauma — causes significant internal hemorrhage; field treatment: position, keep warm, rapid transport"},
    {term:"Liver laceration (internal)",def:"The liver is highly vascular — lacerations cause massive internal hemorrhage that can only be controlled surgically"},
    {term:"Pelvic fracture hemorrhage",def:"Pelvic fractures can cause 2–4+ liters of internal blood loss — treated with pelvic binder in field, angioembolization or surgery in hospital"},
    {term:"Pelvic binder",def:"A circumferential compression device applied around the pelvis to reduce pelvic volume and tamponade internal bleeding from pelvic fractures"},
    {term:"Femur fracture blood loss",def:"A closed femur fracture can cause 1–1.5 liters of internal blood loss — significant even without visible bleeding"},
    {term:"Traction splint",def:"A device that applies longitudinal traction to a fractured femur — reduces pain, prevents further injury, and reduces blood loss by closing dead space"},
    {term:"Wound contamination in the field",def:"Do not clean wounds in the field — cover, control bleeding, transport; infection risk is secondary to hemorrhage control"},
    {term:"Tourniquet removal timing (hospital)",def:"Typically within 2 hours of application in the operating room — surgeon assesses vessel injury and performs definitive repair"},
    {term:"Blood transfusion triggers",def:"Hemoglobin <7–8 g/dL in stable patients; <10 g/dL in hemodynamically unstable trauma patients — guides transfusion decisions"},
    {term:"Type and screen vs crossmatch",def:"Type and screen identifies blood type and antibodies; crossmatch confirms compatibility — both done before elective transfusion"},
    {term:"Emergency O-negative blood",def:"Type O-negative ('universal donor') RBCs given when no time for type and crossmatch — stocked in trauma bays for immediate use"},
    {term:"Hemoglobin function",def:"Hemoglobin in red blood cells carries oxygen — blood loss reduces oxygen-carrying capacity, causing tissue hypoxia and organ failure"},
    {term:"Oxygen delivery in shock",def:"DO2 = Cardiac Output × Hemoglobin × 1.34 × O2 saturation — hemorrhagic shock reduces both CO and hemoglobin, collapsing oxygen delivery"},
    {term:"Lactic acidosis in hemorrhage",def:"When tissues don't get enough oxygen, they switch to anaerobic metabolism, producing lactic acid — serum lactate is a key trauma resuscitation marker"},
    {term:"Base deficit in trauma",def:"A negative base excess indicating acidosis from tissue hypoperfusion — used alongside lactate to assess severity of hemorrhagic shock"},
    {term:"Tranexamic acid (TXA) dose",def:"1 gram IV over 10 minutes as initial dose, followed by 1 gram over 8 hours — the CRASH-2 trial dosing regimen"},
    {term:"Topical TXA",def:"TXA can be applied directly to wounds on hemostatic gauze — emerging prehospital and point-of-care application"},
    {term:"Hemorrhage and hypothermia prevention",def:"Keep bleeding patients warm — remove wet clothing, use blankets, use warm IV fluids — hypothermia worsens coagulopathy"},
    {term:"Needle decompression",def:"A large-bore needle inserted into the 2nd intercostal space at the midclavicular line — treats tension pneumothorax in the field"},
    {term:"Tension pneumothorax signs",def:"Absent breath sounds on one side, tracheal deviation, hypotension, distended neck veins — a tension pneumothorax must be decompressed immediately"},
    {term:"Abdominal evisceration",def:"Protruding abdominal organs — do NOT push back in; cover with moist dressing and transport immediately"},
    {term:"Impaled object management",def:"Stabilize in place with bulky dressings — never remove; the object may be tamponading major vessel bleeding"},
    {term:"Wound closure strips",def:"Butterfly strips or Steri-Strips used for minor lacerations — not appropriate for life-threatening hemorrhage control"},
    {term:"Nasal hemorrhage (epistaxis)",def:"Pack the nostril with gauze and pinch the nose for 10+ minutes; lean forward to prevent blood from going down the throat"},
    {term:"Ear bleeding after head trauma",def:"Blood from the ear after trauma may indicate a basilar skull fracture — do not pack; cover loosely and seek immediate care"},
    {term:"Eye injury and bleeding",def:"Cover both eyes (to reduce movement) with a rigid eye shield — do not apply pressure to a potentially ruptured globe"},
    {term:"Soft tissue injury vs vascular injury",def:"Soft tissue bleeding is usually venous and controllable; vascular injury (arterial) requires tourniquet or surgical repair"},
    {term:"Amputation and hemorrhage",def:"Traumatic amputation causes significant arterial bleeding — apply tourniquet as high as possible on the remaining limb immediately"},
    {term:"Partial vs complete amputation",def:"Both require tourniquet and hemorrhage control — do not complete the amputation; transport both the patient and the amputated part if possible"},
    {term:"Ring avulsion injury",def:"A ring caught on an object that strips the skin and vessels off a finger — can cause significant vascular injury requiring tourniquet and surgical repair"},
    {term:"Scalp laceration bleeding",def:"Scalp has rich blood supply — even small lacerations can bleed profusely; apply firm direct pressure; rarely life-threatening alone"},
    {term:"Blood on clothing estimate",def:"A fist-sized blood stain on clothing ≈ 500 mL lost — a useful rough estimate when assessing blood loss at the scene"},
    {term:"Bystander fatigue in bleeding control",def:"Maintaining firm pressure for 3+ minutes is physically tiring — rescuers can rotate while keeping continuous pressure on the wound"},
    {term:"Tourniquet application in clothing",def:"Cut or lift clothing to expose the wound and confirm tourniquet placement — confirming that bleeding has stopped requires visualizing the wound"},
    {term:"Stop the Bleed in schools",def:"Many states now mandate Stop the Bleed training in schools — students as young as middle school can effectively apply tourniquets"},
    {term:"Bleeding control hands-on practice",def:"Skills decay without practice — periodic simulation with tourniquet trainers and wound packing mannequins maintains competency"},
    {term:"First responder bleeding control",def:"Police officers, firefighters, and EMS are now routinely trained and equipped with tourniquets — 'Stop the Bleed' principles apply to all first responders"},
  ]);

  fc.medium = fc.medium.concat([
    {term:"Hemorrhage control algorithm",def:"(1) Scene safe + PPE → (2) Call 911 → (3) Assess bleeding type → (4) Direct pressure → (5) Tourniquet if limb + uncontrolled → (6) Pack if junctional → (7) Monitor and reassess"},
    {term:"Tourniquet vs direct pressure decision",def:"Use direct pressure first for all wounds; escalate to tourniquet only for extremity wounds where direct pressure fails — tourniquets are not for every wound"},
    {term:"Limb viability after tourniquet",def:"Studies show limb viability is preserved in the vast majority of properly applied tourniquet cases — concerns about limb loss are significantly overstated"},
    {term:"Proximal pressure point as adjunct",def:"Pressing on the femoral artery in the groin or brachial artery in the axilla reduces distal blood flow — useful adjunct while preparing tourniquet or packing materials"},
    {term:"Hemorrhage control in the dark",def:"Tourniquets can be applied by feel — practice without looking to simulate low-light or high-stress conditions where fine motor skills are degraded"},
    {term:"Stress inoculation in bleeding control",def:"Training under simulated stress (noise, time pressure, simulated blood) prepares bystanders to perform better in actual emergencies"},
    {term:"B-Con (Bleeding Control) course",def:"The formal Stop the Bleed curriculum — includes lecture on hemorrhage physiology, demonstration, and hands-on practice with tourniquet and packing simulator"},
    {term:"Hemorrhage and coagulation cascade",def:"The clotting cascade has intrinsic (XII→XI→IX→X) and extrinsic (VII→X) pathways converging at Factor X → thrombin → fibrin clot"},
    {term:"Platelet plug formation",def:"Primary hemostasis: platelets adhere to damaged vessel wall via vWF, aggregate, and form a temporary plug — reinforced by fibrin in secondary hemostasis"},
    {term:"Secondary hemostasis",def:"The coagulation cascade produces fibrin strands that strengthen the platelet plug into a stable clot — can be impaired by medication, hypothermia, or dilution"},
    {term:"Fibrin formation steps",def:"Thrombin cleaves fibrinogen → fibrin monomers → Factor XIIIa cross-links fibrin → stable clot mesh surrounding the platelet plug"},
    {term:"Plasmin and fibrinolysis",def:"Plasmin breaks down fibrin clots — normally a controlled process; in major trauma, pathological fibrinolysis breaks clots prematurely, worsening hemorrhage"},
    {term:"Protein C anticoagulant pathway",def:"Activated by hypoperfusion in trauma — Protein C inhibits clotting factors V and VIII, contributing to trauma-induced coagulopathy within minutes of injury"},
    {term:"Hypovolemia vs dehydration",def:"Hypovolemia is reduced intravascular blood volume (hemorrhage); dehydration is total body water deficit — both cause shock but have different treatments"},
    {term:"Hemorrhagic shock vs distributive shock",def:"Hemorrhagic shock: inadequate preload from blood loss. Distributive (septic, anaphylactic): maldistribution of blood flow. Different mechanisms require different interventions"},
    {term:"Crystalloid vs colloid in hemorrhage",def:"Neither replaces lost red cells and clotting factors — crystalloid is temporary volume; colloid (albumin) is expensive with no mortality benefit in trauma"},
    {term:"Hypertonic saline in trauma",def:"Small volumes (250 mL) of 7.5% saline rapidly restore intravascular volume — used in military settings where weight and volume are limited"},
    {term:"Fresh frozen plasma (FFP)",def:"Contains all clotting factors — used in 1:1:1 resuscitation to replace consumed factors in massive hemorrhage; must be thawed before use (10–15 min delay)"},
    {term:"Thawed plasma",def:"Pre-thawed FFP kept at 1–6°C for up to 5 days — available immediately without thawing delay, increasingly used in trauma bays and helicopters"},
    {term:"Platelet transfusion in trauma",def:"Platelets support primary hemostasis — given in 1:1:1 protocol; target platelet count >50,000 in actively bleeding trauma patients"},
    {term:"Cryoprecipitate vs FFP for fibrinogen",def:"Cryoprecipitate has 5–10x higher fibrinogen concentration than FFP — preferred when fibrinogen is specifically depleted (<150 mg/dL)"},
    {term:"Fibrinogen concentrate",def:"A purified fibrinogen product increasingly used instead of cryoprecipitate — faster to prepare, consistent dosing, increasingly available in trauma centers"},
    {term:"Point-of-care coagulation testing",def:"Devices like TEG, ROTEM, and i-STAT provide real-time coagulation data in the trauma bay — guiding targeted blood product resuscitation within 20–30 minutes"},
    {term:"Massive transfusion protocol activation criteria",def:"Activated when patient is predicted to need >10 units pRBC in 24 hours — typically triggered by shock index (HR/SBP) >1.0 or ABC score ≥2"},
    {term:"Shock index",def:"Heart rate divided by systolic BP — normal <0.8; >1.0 suggests significant blood loss and predicts massive transfusion need"},
    {term:"ABC score (trauma)",def:"Assessment of Blood Consumption score: penetrating mechanism, HR>120, SBP<90, positive FAST — ≥2 points triggers massive transfusion protocol"},
    {term:"FAST exam in trauma",def:"Focused Assessment with Sonography in Trauma — rapid bedside ultrasound looking for free fluid (blood) in abdomen, pelvis, and pericardium"},
    {term:"Damage control anesthesia",def:"Anesthetic strategy during damage control surgery — accept lower BP targets, use ketamine for hemodynamic stability, minimize inhalational agents that vasodilate"},
    {term:"Abdominal compartment syndrome",def:"Intraabdominal pressure >20 mmHg causing organ failure — complication of massive resuscitation and bowel edema; treated with decompressive laparotomy"},
    {term:"Open abdomen management",def:"After damage control surgery, the abdomen may be left open with a temporary closure device — allows re-entry and prevents abdominal compartment syndrome"},
    {term:"Transfusion-related acute lung injury (TRALI)",def:"Acute hypoxemic respiratory failure within 6 hours of transfusion — caused by donor antibodies reacting with recipient leukocytes; leading cause of transfusion-related death"},
    {term:"Transfusion-associated circulatory overload (TACO)",def:"Pulmonary edema from fluid overload during transfusion — treated with diuretics; more common in elderly and patients with cardiac disease"},
    {term:"Hypothermia prevention in field",def:"Remove wet clothing, use emergency blankets, add layers — prevents the lethal triad cycle; keep patient off the cold ground"},
    {term:"Warm IV fluids in hemorrhage",def:"Pre-warming IV fluids to 37–39°C prevents iatrogenic hypothermia during resuscitation — especially important in prolonged transport"},
  ]);

  fc.hard = fc.hard.concat([
    {term:"Oxygen extraction ratio (O2ER)",def:"O2ER = VO2/DO2 — normally 0.25 (25% of delivered O2 consumed); rises toward 0.60–0.70 as DO2 falls in shock — signals impending O2 supply-demand crisis"},
    {term:"Mixed venous oxygen saturation (SvO2)",def:"Normal ~65–75% — falls in hemorrhagic shock as tissues extract more O2 from reduced blood supply; monitored via pulmonary artery catheter or central venous line"},
    {term:"Lactate clearance as resuscitation endpoint",def:"Lactate should clear to <2 mmol/L within 6–24 hours of resuscitation — failure to clear predicts organ failure and mortality; superior to static pressure targets"},
    {term:"Thromboelastography (TEG) parameters",def:"R-time (clot initiation), K-time (clot strengthening speed), alpha angle (fibrin cross-linking), MA (maximum amplitude = clot strength), LY30 (fibrinolysis at 30 min)"},
    {term:"Heparin resistance in trauma",def:"Trauma causes antithrombin III consumption — patients become relatively heparin-resistant; AT-III supplementation may be needed for anticoagulation in VTE prevention"},
    {term:"Endogenous heparinization in trauma",def:"The endothelial glycocalyx releases heparan sulfate after trauma-induced hypoperfusion — a potential contributor to early coagulopathy alongside protein C activation"},
    {term:"Hyperfibrinolysis in trauma",def:"Pathological acceleration of clot breakdown — detected on TEG as LY30 >7.5%; treated with TXA; associated with extremely high mortality if untreated"},
    {term:"Fibrinolysis shutdown",def:"A paradoxical state in severe trauma where fibrinolysis is suppressed — TEG shows LY30 <0.8%; associated with high thromboembolic risk and possibly worse outcomes than hyperfibrinolysis"},
    {term:"Prothrombin complex concentrate (PCC)",def:"4-factor PCC (Factors II, VII, IX, X) — faster reversal of warfarin-associated coagulopathy than FFP; 25–50 units/kg; increasingly used in trauma as FFP alternative"},
    {term:"Andexanet alfa (Andexxa)",def:"Reversal agent for Factor Xa inhibitors (rivaroxaban, apixaban) — recombinant modified Factor Xa that acts as decoy; approved 2018; expensive (~$25,000/dose)"},
    {term:"Idarucizumab (Praxbind)",def:"Monoclonal antibody reversal agent for dabigatran (Pradaxa, direct thrombin inhibitor) — FDA approved 2015; complete reversal in minutes"},
    {term:"Four-factor PCC vs FFP for warfarin reversal",def:"4F-PCC reverses warfarin faster (minutes vs hours), in smaller volume (50 mL vs 600+ mL), and without TRALI risk — preferred in actively hemorrhaging warfarin patients"},
    {term:"Cell-free hemoglobin oxygen carriers",def:"Experimental hemoglobin-based oxygen carriers (HBOCs) that can carry O2 without refrigeration and cross-match — still investigational for trauma; potential military/remote use"},
    {term:"Acute traumatic coagulopathy (ATC) mechanisms",def:"ATC is driven by: (1) tissue factor release, (2) hypoperfusion activating protein C, (3) sympathoadrenal response causing fibrinolysis, (4) endothelial glycocalyx shedding releasing heparan sulfate — all occurring within minutes"},
    {term:"PROPPR trial findings",def:"Pragmatic Randomized Optimal Platelets and Plasma Ratios trial: 1:1:1 (FFP:platelets:pRBC) vs 1:1:2 — 1:1:1 significantly reduced 24-hour mortality and improved hemostasis; established 1:1:1 as standard of care"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"What does 'direct pressure' mean in bleeding control?",opts:["Pressing on an artery upstream from the wound","Applying firm, continuous pressure directly on the wound itself","Applying pressure around the wound edges","Using a tourniquet above the wound"],correct:1,explain:"Direct pressure means pressing firmly and continuously on the wound itself — using hands, a cloth, or gauze. It is the first step for ALL bleeding wounds and compresses blood vessels to allow clotting to begin."},
    {q:"Why is glove use so important before treating a bleeding patient?",opts:["Gloves keep hands warm","Gloves protect the rescuer from bloodborne pathogens like HIV and hepatitis","Gloves are required by law","Gloves help grip the tourniquet better"],correct:1,explain:"Bloodborne pathogens (HIV, Hepatitis B, Hepatitis C) can be transmitted through contact with infected blood. Gloves create a physical barrier protecting the rescuer — always the first step before touching a bleeding patient."},
    {q:"What is the FIRST action at any emergency scene, including a bleeding emergency?",opts:["Apply a tourniquet","Ensure scene safety","Call the patient's family","Check the patient's pulse"],correct:1,explain:"Scene safety is always the first priority — ensure there is no active danger (traffic, shooter, hazards) before approaching a victim. A second victim cannot help the first. Then call 911 and provide care."},
    {q:"Venous bleeding is characterized by which feature?",opts:["Bright red blood spurting with each heartbeat","Dark red blood flowing steadily","Slow oozing from the skin surface","Blood appearing only after several minutes"],correct:1,explain:"Venous blood is dark red (lower oxygen content) and flows steadily — not spurting. It is serious but generally less immediately life-threatening than arterial bleeding. Large veins can still cause fatal hemorrhage if not controlled."},
    {q:"What is capillary bleeding?",opts:["The most dangerous type of bleeding","Bleeding that requires a tourniquet","Slow oozing from small surface vessels — the least dangerous type","Bleeding from a major artery"],correct:2,explain:"Capillary bleeding comes from the smallest blood vessels and appears as slow, oozing bleeding. It is the least immediately life-threatening type and is usually controlled with light direct pressure alone."},
    {q:"What does it mean to 'pack' a wound?",opts:["Put ice in the wound","Tightly fill the wound cavity with gauze","Cover the wound lightly with a bandage","Suture the wound closed"],correct:1,explain:"Wound packing means tightly filling the entire wound cavity with gauze — pushing it in layer by layer until the cavity is full. Then firm direct pressure is applied for at least 3 minutes to help clotting occur."},
    {q:"What is the minimum time you should hold firm pressure after wound packing?",opts:["30 seconds","1 minute","3 minutes","10 minutes"],correct:2,explain:"Hold firm, continuous pressure for at least 3 minutes after wound packing — this gives hemostatic agents time to activate and allows the clotting process to begin. Do not peek under the dressing during this time."},
    {q:"Which body areas are considered 'junctional' wounds?",opts:["Forearm, thigh, and shin","Groin, armpit, and neck","Scalp, back, and abdomen","Hands, feet, and ears"],correct:1,explain:"Junctional wounds are in areas where a tourniquet cannot be applied — the groin, armpit, neck, and pelvis. These require wound packing with firm direct pressure rather than a tourniquet."},
    {q:"What is the proper response if a bleeding patient becomes unconscious?",opts:["Stop applying pressure and call family","Place in recovery position (on side) and maintain pressure if possible","Lay flat on back and elevate legs","Remove tourniquet to improve blood flow to brain"],correct:1,explain:"Place an unconscious patient in the recovery position (on their side) to protect the airway from vomiting while maintaining any hemorrhage control measures already applied. Continue waiting for EMS."},
    {q:"Which of the following is a sign of arterial bleeding?",opts:["Dark blood seeping slowly","Bright red blood spurting in pulses","Pink blood oozing steadily","No visible blood"],correct:1,explain:"Arterial blood is bright red (highly oxygenated) and spurts or pulses with each heartbeat because arteries carry blood under high pressure directly from the heart. This is the most immediately life-threatening type."},
    {q:"What should you do if the first tourniquet does not stop the bleeding?",opts:["Remove it and try direct pressure","Loosen it and retighten","Apply a second tourniquet above the first","Wait for EMS to decide"],correct:2,explain:"If the first tourniquet doesn't stop bleeding, apply a second one immediately above (proximal to) the first — never remove the first. Continue until bleeding stops. Tighten both until the bleeding ceases."},
    {q:"Stop the Bleed kits are most commonly co-located with which other public safety device?",opts:["Fire extinguishers","Security cameras","AEDs (Automated External Defibrillators)","First aid kits"],correct:2,explain:"Following the AED public access model, Stop the Bleed kits are increasingly placed alongside AEDs in schools, airports, stadiums, and public buildings — making hemorrhage control tools available to bystanders wherever emergencies may occur."},
    {q:"What does it mean that a tourniquet is 'properly tightened'?",opts:["The patient reports maximum pain","The limb turns blue within 30 seconds","The bleeding has completely stopped","The tourniquet is as tight as physically possible"],correct:2,explain:"A tourniquet is properly tightened when the bleeding has stopped — not when a specific tightness level is reached and not when the patient feels maximum pain. If bleeding continues, tighten more or apply a second tourniquet."},
    {q:"The Hartford Consensus concluded which of the following?",opts:["Civilians should not attempt to control bleeding","Tourniquets cause more harm than good","Bystander bleeding control saves lives and everyone should be trained","Only medical professionals should intervene at trauma scenes"],correct:2,explain:"The Hartford Consensus (2013) established that immediate bystander action — particularly hemorrhage control using tourniquets and wound packing — can prevent deaths in the critical minutes before EMS arrives. It formed the basis for Stop the Bleed."},
    {q:"How long does the standard Stop the Bleed course take?",opts:["30 minutes","2 hours","4 hours","8 hours"],correct:1,explain:"The standard Stop the Bleed course is approximately 2 hours, including instruction on hemorrhage physiology, demonstration of techniques, and hands-on practice with tourniquet trainers and wound packing simulators."},
    {q:"An adult's total blood volume is approximately:",opts:["1 liter (2 pints)","2 liters (4 pints)","5 liters (10–12 pints)","8 liters (16 pints)"],correct:2,explain:"An adult has approximately 5 liters (10–12 pints) of blood. Loss of just 30% (~1.5 liters) can cause life-threatening hemorrhagic shock. This is why rapid hemorrhage control in the first minutes is so critical."},
    {q:"What should you tell EMS when they arrive about a tourniquet you applied?",opts:["Nothing — they will assess it themselves","The time the tourniquet was applied","The patient's name and phone number","Whether the patient was in pain"],correct:1,explain:"Always tell EMS the exact time the tourniquet was applied (and write it on the patient). This helps the hospital team assess ischemia risk and plan for tourniquet removal. Time of application is the single most critical piece of tourniquet information to communicate."},
    {q:"Is it safe for a non-medical bystander to apply a tourniquet?",opts:["No — tourniquets should only be used by trained medical professionals","Yes — bystander tourniquet application saves lives and is protected by Good Samaritan laws","Only if the patient gives consent","Only for children, not adults"],correct:1,explain:"Yes — bystander tourniquet application is safe, effective, and protected by Good Samaritan laws in all 50 states. The risk of not applying a tourniquet (death from hemorrhage) vastly outweighs any risk of the tourniquet itself when properly applied."},
    {q:"What does the 'windlass' mechanism on a tourniquet do?",opts:["Holds the strap velcro in place","Provides a rod that is twisted to tighten the tourniquet band mechanically","Marks the time of application","Locks the tourniquet permanently to the limb"],correct:1,explain:"The windlass is a plastic or metal rod that is inserted through a loop and twisted to mechanically tighten the tourniquet band after initial application. It provides the mechanical advantage needed to occlude arterial blood flow in a large limb."},
    {q:"What is meant by 'scene safety' in a bleeding emergency?",opts:["Making sure you have enough supplies","Ensuring there is no active danger before approaching a victim","Checking that the patient has insurance","Confirming EMS has been called"],correct:1,explain:"Scene safety means verifying that no active threat exists — active shooter, traffic, fire, unstable structure, or chemical hazard — before approaching. A rescuer who becomes a second victim helps no one. Assess, ensure safety, then act."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"A patient in hemorrhagic shock has a narrowing pulse pressure. What does this indicate physiologically?",opts:["The tourniquet is too tight","Vasoconstriction is raising diastolic pressure as the body compensates for reduced preload — an early warning sign before frank hypotension develops","The patient is improving","The patient needs immediate IV access, not hemorrhage control"],correct:1,explain:"Narrowing pulse pressure (systolic minus diastolic BP) reflects peripheral vasoconstriction — the body increases diastolic pressure to maintain perfusion as preload falls. It is an earlier sign of volume loss than frank hypotension, and often missed in field assessment."},
    {q:"Why does the CRASH-2 trial have direct implications for bystander bleeding control?",opts:["Bystanders should now carry IV TXA","The trial shows TXA must be given at exactly 3 hours post-injury","Accurate injury time documentation by bystanders determines whether TXA is still within its therapeutic window when the patient reaches hospital","The trial only applies to military wounds"],correct:2,explain:"CRASH-2 showed TXA must be given within 3 hours of injury. Bystanders who accurately document the time of injury enable hospital teams to determine TXA eligibility. This is a direct, practical way that bystander documentation — not just direct treatment — saves lives."},
    {q:"A combat medic uses the MARCH protocol. Why does 'Massive Hemorrhage' precede 'Airway' in this protocol?",opts:["Airway management is too complex for field providers","The medic is more likely to have tourniquet supplies than airway equipment","Exsanguination kills faster than most traumatic airway obstructions — seconds count differently for these two threats","Airway problems are self-correcting in the field"],correct:2,explain:"In penetrating trauma, exsanguination from arterial bleeding kills in 3–5 minutes. Most traumatic airway obstructions allow somewhat longer — a jaw thrust or position change may buy time. MARCH's hemorrhage-first prioritization reflects this time-to-death difference, maximizing lives saved."},
    {q:"What is the physiological basis for wound packing with hemostatic gauze being effective?",opts:["The gauze absorbs enough blood to prevent further loss","The gauze physically fills the wound cavity applying intracavitary pressure while hemostatic agents activate the clotting cascade","The gauze contains pain medication that causes vasoconstriction","The gauze creates a waterproof seal"],correct:1,explain:"Wound packing works through two mechanisms: (1) physical tamponade — the tightly packed gauze creates pressure within the wound cavity that compresses bleeding vessels, and (2) hemostatic activation — agents like kaolin (QuikClot) or chitosan (Celox) accelerate platelet activation and fibrin formation at the wound surface."},
    {q:"A patient with a pelvic fracture arrives with hypotension. EMS applied a pelvic binder in the field. What is the mechanism of benefit?",opts:["The binder acts as a tourniquet for the pelvis","The binder reduces pelvic volume, tamponades venous and arterial bleeding by restoring pelvic ring continuity","The binder prevents the patient from moving","The binder provides pain control"],correct:1,explain:"Pelvic fractures disrupt the pelvic ring, creating a larger volume in which blood can accumulate. The pelvic binder reduces pelvic volume by closing the fracture and tamponading bleeding — similar to how the intact pelvis normally contains pelvic vasculature. It is a temporizing measure before angioembolization or surgical fixation."},
    {q:"In which of the following scenarios is a tourniquet clearly contraindicated or ineffective?",opts:["A deep thigh laceration with arterial spurting","A forearm wound with uncontrolled venous bleeding","Hemorrhage from a gunshot wound to the torso","A lower leg wound that has not responded to direct pressure"],correct:2,explain:"Tourniquets can only be applied to limbs — they encircle a limb to occlude arterial inflow. A gunshot wound to the torso represents non-compressible hemorrhage that CANNOT be controlled with a tourniquet. Treatment: cover wound, provide pressure if accessible, and prioritize immediate transport to a trauma center with surgical capability."},
    {q:"How does shock index (SI = HR/SBP) predict the need for massive transfusion?",opts:["SI < 0.5 indicates massive hemorrhage","SI > 1.0 suggests significant blood loss and predicts the need for massive transfusion protocol activation","SI only applies to pediatric patients","SI is an outdated measure replaced entirely by lactate"],correct:1,explain:"Shock index combines two vital sign trends: rising HR (compensatory tachycardia) and falling SBP. Normal SI is 0.5–0.8. SI > 1.0 predicts massive transfusion need with reasonable sensitivity. SI > 1.4 is associated with very high mortality. It is a rapid, bedside screening tool requiring no laboratory testing."},
    {q:"What distinguishes trauma-induced coagulopathy (TIC) from disseminated intravascular coagulation (DIC)?",opts:["They are identical conditions","TIC is early (minutes post-injury), driven by shock and tissue damage; DIC is typically a later complication driven by sustained inflammation, sepsis, or obstetric emergency","TIC only occurs in penetrating trauma; DIC only in blunt trauma","DIC is more severe than TIC in all cases"],correct:1,explain:"TIC develops within minutes of major injury from protein C activation and fibrinolysis triggered by hypoperfusion and endothelial damage. DIC is a later syndrome of dysregulated coagulation from sustained systemic inflammation (sepsis, major burn, obstetric catastrophe). Understanding the distinction guides appropriate early treatment."},
    {q:"A patient on apixaban (Eliquis) sustains a major laceration requiring emergency surgery. What is the most appropriate hospital reversal agent?",opts:["Vitamin K — reverses all anticoagulants","Fresh frozen plasma (FFP)","Andexanet alfa (Andexxa) — specific reversal for Factor Xa inhibitors","Protamine sulfate — reverses heparin"],correct:2,explain:"Apixaban is a direct Factor Xa inhibitor. Andexanet alfa (Andexxa) is the specific reversal agent — a modified recombinant Factor Xa that acts as a decoy, binding apixaban and rivaroxaban without activating the clotting cascade. Vitamin K only reverses warfarin. Protamine reverses heparin/LMWH. FFP provides factors but does not specifically reverse Xa inhibition."},
    {q:"What is the 'Platinum 10 Minutes' principle in trauma?",opts:["Surgeons have 10 minutes to begin surgery after arrival","First responders should aim to spend no more than 10 minutes on scene for major trauma before transport","TXA must be given within 10 minutes of injury","Tourniquets must be removed within 10 minutes"],correct:1,explain:"'Platinum 10 Minutes' (analogous to the 'Golden Hour') is the goal of limiting total scene time to 10 minutes for major trauma. Each minute at scene delays definitive hemorrhage control surgery. Field interventions should be limited to those that directly save life (tourniquet, airway) — complex procedures are deferred to hospital."},
    {q:"Why is maintaining patient warmth a hemorrhage control priority in the field?",opts:["Cold patients are more likely to wake up and resist treatment","Hypothermia below 35°C significantly impairs clotting enzyme function, worsening coagulopathy and increasing hemorrhage","Warmth increases blood pressure directly","Blankets help identify patients in dark environments"],correct:1,explain:"The coagulation cascade involves enzymatic reactions optimized at 37°C. Below 35°C, clotting efficiency decreases measurably. Below 33°C, coagulation is severely impaired. In major trauma, hypothermia contributes to the lethal triad cycle. Field measures: remove wet clothing, use foil/emergency blankets, insulate from cold ground."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"A trauma patient's TEG shows prolonged R-time, decreased MA, and LY30 of 15%. Which targeted therapy is indicated?",opts:["Give platelets only — MA is the key parameter","Give FFP (prolonged R-time = factor deficiency) + TXA (LY30 >7.5% = hyperfibrinolysis) + consider cryoprecipitate if fibrinogen low","Give crystalloid bolus to restore volume","Administer heparin to prevent paradoxical clotting"],correct:1,explain:"TEG interpretation: R-time (clot initiation) prolonged = factor deficiency → FFP. MA (clot strength) decreased = platelet or fibrinogen deficiency → platelets/cryoprecipitate. LY30 = 15% (>7.5% threshold) = hyperfibrinolysis → TXA. This is goal-directed resuscitation — targeting the specific coagulation defect rather than empiric 1:1:1."},
    {q:"The endothelial glycocalyx is disrupted in hemorrhagic shock. What are the clinical consequences?",opts:["Vessels become stronger and resist further injury","Loss of the glycocalyx increases vascular permeability, promotes leukocyte adhesion, releases heparan sulfate (causing endogenous anticoagulation), and worsens edema","Glycocalyx disruption stops bleeding by activating clotting","There are no clinically significant consequences"],correct:1,explain:"The endothelial glycocalyx is a proteoglycan layer lining blood vessels. In hemorrhagic shock, ischemia causes it to shed: (1) releases heparan sulfate → endogenous anticoagulation contributing to TIC; (2) exposes endothelium → increased platelet adhesion and inflammation; (3) increased vascular permeability → fluid leaks into tissues; (4) activated protein C further impairs clotting. Large crystalloid volumes worsen glycocalyx damage."},
    {q:"A damage control surgery patient returns to the ICU after abbreviated laparotomy. Their ABG shows pH 7.18, PaCO2 28, HCO3 10, lactate 8 mmol/L. What is the metabolic picture and primary resuscitation priority?",opts:["Respiratory acidosis — intubate and increase respiratory rate","Metabolic acidosis from severe tissue hypoperfusion (high lactate, low HCO3) — priority is optimizing DO2 via blood products and surgical hemorrhage control, NOT sodium bicarbonate","Metabolic alkalosis — give normal saline","Respiratory alkalosis — reduce ventilator rate"],correct:1,explain:"pH 7.18 = acidosis. Low PaCO2 = respiratory compensation (hyperventilating to blow off CO2). Low HCO3 + high lactate = metabolic acidosis from tissue hypoperfusion. The only treatment that works is improving oxygen delivery (DO2) — more blood products, definitive hemorrhage control, and warming. Sodium bicarbonate temporarily raises pH but does not treat the underlying cause and may worsen intracellular acidosis."},
    {q:"Why does the PROPPR trial represent a paradigm shift in massive hemorrhage resuscitation?",opts:["It showed crystalloid is superior to blood products","It proved that 1:1:1 (plasma:platelets:pRBC) resuscitation reduces 24-hour and 30-day mortality compared to 1:1:2 ratio — establishing balanced blood product resuscitation as the standard of care","It showed TXA is ineffective in civilian trauma","It proved tourniquets cause more harm than good in civilian settings"],correct:1,explain:"Pre-PROPPR, many centers used 1:1:2 (less plasma and platelets relative to red cells). PROPPR showed 1:1:1 significantly improved 24-hour survival and hemostasis, with more patients achieving hemostasis and fewer deaths from hemorrhage. This shifted the standard from empiric red-cell-dominant transfusion to balanced resuscitation mimicking whole blood composition."},
    {q:"A patient with known hemophilia A (Factor VIII deficiency) is brought in after a motor vehicle collision with suspected internal hemorrhage. What coagulation pathway is impaired and what is the specific treatment?",opts:["Extrinsic pathway impaired — give PCC","Intrinsic pathway impaired (Factor VIII is in intrinsic pathway XII→XI→IX→VIII→X) — treat with recombinant Factor VIII concentrate or factor replacement; standard 1:1:1 resuscitation is insufficient without Factor VIII","Common pathway impaired — give cryoprecipitate only","No specific treatment — hemophilia A patients clot normally in trauma"],correct:1,explain:"Hemophilia A is Factor VIII deficiency, impairing the intrinsic coagulation pathway. Without Factor VIII, the tenase complex (IXa+VIIIa) cannot activate Factor X at therapeutic levels. FFP contains Factor VIII but in low concentration — it is insufficient alone for severe hemophilia A. Recombinant Factor VIII concentrate (Advate, Xyntha) at 50 units/kg restores hemostasis. In emergency, FFP + cryoprecipitate bridge until concentrate is available."},
  ]);
})();

// ── STOP THE BLEED FINAL TOP-UP (+44 flash, +30 quiz) ─────────────────────
(function(){
  if(!window.QB_STOP_BLEED) return;
  var fc = window.QB_STOP_BLEED.flashcards;
  var qz = window.QB_STOP_BLEED.quiz;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});

  fc.easy = fc.easy.concat([
    {term:"Pressure application technique",def:"Use both hands to maintain firm, consistent pressure — lean body weight into the wound; do not rock or shift pressure as this disrupts clot formation"},
    {term:"Glove alternatives (no gloves available)",def:"Use a plastic bag, extra clothing layers, or any available barrier between your hands and the patient's blood if gloves are unavailable"},
    {term:"Calling 911 — what to say",def:"Location, nature of emergency (severe bleeding), number of victims, and that hemorrhage control is in progress — this helps EMS bring the right resources"},
    {term:"Checking for bleeding cessation",def:"Gently lift the edge of the dressing only after 3 minutes — if bleeding has stopped, apply a pressure bandage; if not, continue pressure or escalate to tourniquet"},
    {term:"When to stop CPR to control bleeding",def:"Active life-threatening hemorrhage should be controlled before or simultaneously with CPR — you cannot circulate oxygenated blood if it is all leaving the body"},
    {term:"Bystander emotional response",def:"It is normal to feel panic, nausea, or shock at a bleeding emergency — the 3 steps (Call, Compress, Tourniquet) are designed to be simple enough to do under stress"},
    {term:"Blood on rescuer after the event",def:"After EMS arrives, wash exposed skin thoroughly with soap and water; report any mucous membrane exposure (eyes, mouth) to healthcare provider for bloodborne pathogen evaluation"},
    {term:"Stop the Bleed poster locations",def:"Stop the Bleed awareness posters and QR code instructions are displayed in schools, transit systems, stadiums, and offices — normalizing hemorrhage control knowledge"},
    {term:"Refresher training frequency",def:"Skills decay without practice — annual refresher training with hands-on simulation is recommended to maintain tourniquet and wound packing competency"},
    {term:"Bystander legality of bleeding control",def:"No U.S. state requires bystanders to act, but Good Samaritan laws protect those who do — acting in good faith carries no legal liability in emergency bleeding care"},
    {term:"Stop the Bleed for teens",def:"Middle and high school students can effectively apply tourniquets after brief training — many states now include Stop the Bleed in school health curricula"},
    {term:"Hemorrhage from IV drug use site",def:"Injection sites can develop infected, fragile veins — treat like any other wound with direct pressure; do not remove any needles at the scene"},
    {term:"Patient reassurance during care",def:"Talk to the patient — tell them what you're doing, that help is coming, and that they can help by staying still; reduces panic and improves cooperation"},
    {term:"Tourniquet for a child",def:"Pediatric limbs are small — a commercial tourniquet on a child's limb may need to be applied differently; a pediatric tourniquet or narrow improvised material may be more appropriate"},
    {term:"Dental and oral bleeding",def:"Apply direct pressure with gauze; bite down to maintain pressure for tooth extractions; oral bleeding rarely causes hemorrhagic shock unless major vessel is involved"},
    {term:"Bleeding from ear after head trauma",def:"Blood from the ear canal after head injury may indicate a basilar skull fracture — do NOT pack; cover loosely and transport immediately"},
    {term:"Internal bleeding detection in field",def:"You cannot control internal bleeding in the field — signs (distended abdomen, pain, shock symptoms) should prompt immediate transport to surgical care"},
    {term:"Motorcycle accident and road rash",def:"Large surface area abrasions bleed from many capillaries — apply light pressure with a large dressing; typically not life-threatening but can cause significant blood loss"},
    {term:"Major amputation — preserve the part",def:"Keep the amputated part cool (wrapped in moist gauze in a plastic bag on ice — do NOT freeze) and bring to the hospital with the patient; replantation may be possible"},
    {term:"Do not give water to severely bleeding patient",def:"Bleeding patients may feel intense thirst but should not receive oral fluids — they may lose consciousness or need surgery; vomiting into a tourniquet is dangerous"},
    {term:"Stop the Bleed and school lockdowns",def:"In an active shooter situation, bleeding control is deployed in the Rescue Task Force model — bleeding victims are treated during or after the threat phase"},
  ]);

  fc.medium = fc.medium.concat([
    {term:"Rescue Task Force model",def:"Coordinated law enforcement + EMS model where officers enter active threat scenes with medical teams behind them — bleeding control begins during the ongoing threat"},
    {term:"Zone of care in active threat",def:"Hot zone (active threat, no treatment), Warm zone (threat reduced, minimal life-saving only), Cold zone (threat controlled, full medical care) — Stop the Bleed applies from warm zone onward"},
    {term:"Coagulation factor half-lives",def:"Factor VII has the shortest half-life (~4–6 hours); Factor I (fibrinogen) has the longest (~3–5 days) — warfarin first depletes VII, explaining early PT prolongation before other factors"},
    {term:"INR and coagulopathy threshold",def:"INR >1.5 is associated with clinically significant coagulopathy in trauma — INR > 2.0 indicates severe factor depletion requiring FFP or PCC replacement"},
    {term:"Platelet count thresholds in trauma",def:"Platelet count >50,000/μL adequate for hemostasis; <50,000 in actively bleeding patient requires platelet transfusion; target >100,000 in severe TBI"},
    {term:"Fibrinogen level in hemorrhage",def:"Fibrinogen <150 mg/dL is associated with ongoing hemorrhage and poor outcomes — treat with cryoprecipitate (10 units raises fibrinogen ~50 mg/dL) or fibrinogen concentrate"},
    {term:"Lactate as resuscitation endpoint",def:"Target lactate <2 mmol/L within 6 hours of resuscitation — persistent lactic acidosis indicates ongoing inadequate oxygen delivery despite apparent hemodynamic stability"},
    
    {term:"Permissive hypotension exceptions",def:"Permissive hypotension is CONTRAINDICATED in traumatic brain injury (TBI) — cerebral perfusion pressure must be maintained; target SBP >120 mmHg when TBI is suspected"},
    {term:"Blunt vs penetrating trauma hemorrhage",def:"Penetrating wounds cause local vascular injury — direct pressure or tourniquet works well. Blunt trauma causes internal hemorrhage — surgery is the only definitive treatment"},
    {term:"Hemorrhage and oxygen debt",def:"Each minute of inadequate oxygen delivery creates oxygen debt in tissues — prolonged oxygen debt leads to SIRS, multi-organ failure, and ARDS even after bleeding is controlled"},
    {term:"Abdominal compartment syndrome prevention",def:"Limit crystalloid volumes, use diuresis when stable, consider open abdomen closure, and monitor bladder pressure (>20 mmHg = ACS threshold) in post-operative trauma patients"},
    {term:"Citrate toxicity in massive transfusion",def:"Stored blood products contain citrate (anticoagulant) — massive transfusion can cause citrate accumulation, binding calcium and causing hypocalcemia and myocardial depression"},
    {term:"Ionized calcium supplementation",def:"Calcium gluconate or calcium chloride given during massive transfusion to replace citrate-bound calcium — maintains cardiac contractility and coagulation enzyme function"},
    {term:"Cold storage lesion in pRBCs",def:"Red cells stored >14–21 days have reduced 2,3-DPG (impairing oxygen unloading), increased potassium, and decreased deformability — fresh units preferred in massive transfusion when available"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"What does 'hemorrhage' mean?",opts:["Low blood pressure","Severe or uncontrolled bleeding","Infection from a wound","A blood clot inside a vein"],correct:1,explain:"Hemorrhage means severe, uncontrolled, or abnormal bleeding — from a blood vessel injury. The term specifically refers to bleeding that is significant in quantity or cannot be easily controlled. Life-threatening hemorrhage is the #1 preventable cause of trauma death."},
    {q:"What is the 'Good Samaritan law'?",opts:["A law requiring everyone to perform CPR","A law protecting bystanders who provide emergency aid in good faith from legal liability","A law requiring all public buildings to have first aid kits","A specific Stop the Bleed training certification"],correct:1,explain:"Good Samaritan laws protect lay people who voluntarily provide emergency medical assistance in good faith and without expectation of compensation. They exist in all 50 U.S. states and are specifically intended to encourage bystander action during emergencies."},
    {q:"What is the purpose of a 'marker' in a Stop the Bleed kit?",opts:["To mark the wound location for EMS","To write the time of tourniquet application on the patient or tourniquet","To label the patient's blood type","To sign the consent form"],correct:1,explain:"A marker is used to write the time of tourniquet application (T= HH:MM) directly on the patient's skin (usually the forehead or limb) or on the tourniquet itself. This single piece of information is critical for hospital teams managing tourniquet removal and ischemia risk."},
    {q:"Which type of wound requires you to cover it with a moist dressing and avoid direct pressure?",opts:["Deep thigh laceration","Abdominal wound with protruding organs (evisceration)","Junctional groin wound","Forearm laceration"],correct:1,explain:"An abdominal evisceration (organs protruding from the abdominal wall) should be covered with a moist, clean dressing to prevent drying — but never pushed back in and never covered with dry material. Apply no direct pressure. Transport immediately."},
    {q:"What is the 'recovery position' and when is it used in bleeding emergencies?",opts:["Sitting upright to prevent fainting","On the side, to protect an unconscious patient's airway while awaiting EMS","Face down to slow blood flow","Flat on back with legs elevated"],correct:1,explain:"The recovery position places an unconscious patient on their side — protecting the airway from aspiration of vomit while EMS is en route. It is used after hemorrhage has been controlled and the patient loses consciousness. Never use if spinal injury is suspected."},
    {q:"What does 'exsanguination' mean and why is it relevant to Stop the Bleed?",opts:["A type of infection from blood","Death from excessive blood loss — it is the condition Stop the Bleed training is designed to prevent","Vomiting blood","A tourniquet complication"],correct:1,explain:"Exsanguination is death due to loss of blood. It is the leading cause of preventable trauma death and occurs within minutes from major arterial hemorrhage. Stop the Bleed training exists to give bystanders the tools to prevent exsanguination in the critical minutes before EMS arrives."},
    {q:"When should you call 911 in a bleeding emergency?",opts:["Only after you have successfully controlled the bleeding","Immediately — as the first or concurrent with beginning hemorrhage control","Only if the patient is unconscious","After 5 minutes if bleeding hasn't stopped"],correct:1,explain:"Call 911 immediately or have a bystander call while you begin hemorrhage control. Do not delay calling EMS to finish applying a tourniquet — both happen simultaneously. Early EMS notification gets surgical resources en route sooner."},
    {q:"What is a 'hemostatic agent'?",opts:["An IV medication that raises blood pressure","A substance applied to wounds that accelerates blood clotting","A type of tourniquet material","A bandage that applies automatic pressure"],correct:1,explain:"Hemostatic agents are substances that accelerate the body's natural clotting process. In bleeding control, they are impregnated into gauze (like QuikClot or Celox) to help control severe hemorrhage — especially in wounds where mechanical pressure alone is insufficient."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"A trauma patient has compensated hemorrhagic shock. Which vital sign change is most likely present?",opts:["Bradycardia and high blood pressure","Tachycardia with normal or slightly narrow pulse pressure — BP still maintained by compensation","Hypotension and bradycardia — both falling together","Normal vital signs with only lactate elevation"],correct:1,explain:"In compensated shock, the body maintains blood pressure through tachycardia and peripheral vasoconstriction. HR rises above 100 bpm and pulse pressure narrows (diastolic rises from vasoconstriction) but systolic BP remains relatively preserved. Recognition of compensated shock before decompensation is critical for early intervention."},
    {q:"A bystander has applied a tourniquet that stopped limb bleeding 40 minutes ago. EMS arrives. What information MUST be communicated?",opts:["The patient's name and phone number","Time tourniquet was applied, mechanism of injury, estimated blood loss, and any changes in mental status since tourniquet placement","Whether the patient refused treatment","The tourniquet brand and color"],correct:1,explain:"Critical handoff information: (1) T= time of tourniquet application, (2) mechanism of injury, (3) estimated blood loss before tourniquet, (4) any interventions performed, (5) changes in consciousness or vital signs. Time of tourniquet application is the most critical single data point — it determines ischemia risk and guides surgical decision-making."},
    {q:"What is the physiological reason why warming a hemorrhaging trauma patient improves coagulation?",opts:["Heat constricts blood vessels, reducing bleeding","Clotting enzymes in the coagulation cascade function optimally at 37°C — below 35°C, enzymatic activity decreases significantly","Warmth increases blood viscosity","Heat activates platelets directly"],correct:1,explain:"The coagulation cascade involves enzymatic reactions — each step catalyzed by a specific protease. These enzymes are optimized for 37°C. Below 35°C, enzyme activity drops ~10% per degree Celsius. Platelet function is similarly impaired by cold. Warming is a direct treatment for coagulopathy, not just patient comfort."},
    {q:"Why is calcium supplementation important during massive blood transfusion?",opts:["Stored blood is calcium-depleted and must be replenished","Citrate added to stored blood products chelates (binds) free ionized calcium, causing hypocalcemia that impairs cardiac contractility and coagulation","Calcium prevents TRALI","Calcium prevents hypothermia from cold blood products"],correct:1,explain:"Blood products are stored with citrate anticoagulant. During massive transfusion, large citrate loads chelate ionized calcium faster than the liver can metabolize citrate. Hypocalcemia causes: reduced cardiac contractility (hypotension, reduced cardiac output), impaired platelet function, and reduced clotting factor activity. IV calcium gluconate or chloride is given empirically during massive transfusion."},
    {q:"A patient has lost 2,000 mL of blood (Class IV). The treating team debates giving 2 L normal saline vs blood products. The evidence-based choice is:",opts:["2L normal saline — rapidly restores volume","Blood products in 1:1:1 ratio — normal saline dilutes clotting factors, worsens hypothermia, causes hyperchloremic acidosis, and does not restore oxygen-carrying capacity","Either is equivalent — volume is the priority","No fluids — wait for operative hemorrhage control"],correct:1,explain:"Class IV hemorrhage (>40% blood volume loss) requires blood products, not crystalloid. Normal saline at this volume: dilutes clotting factors (worsening coagulopathy), lowers temperature (contributing to hypothermia), causes hyperchloremic metabolic acidosis, and provides no hemoglobin. Blood products restore oxygen-carrying capacity, clotting factors, and volume simultaneously."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"A patient receives 12 units pRBC, 12 units FFP, and 2 platelet pheresis units over 4 hours. Repeat TEG shows elevated MA (maximum amplitude >72 mm) with shortened R-time and alpha angle. What does this TEG pattern suggest?",opts:["Hyperfibrinolysis — add TXA","Fibrinogen deficiency — give cryoprecipitate","Hypercoagulable state — withhold further blood products and consider anticoagulation prophylaxis","Factor deficiency — continue FFP"],correct:2,explain:"Elevated MA (>72 mm) on TEG indicates clot that is too strong — hypercoagulability. Shortened R-time indicates rapid clot initiation. This pattern, after massive transfusion, signals thrombosis risk — deep vein thrombosis, pulmonary embolism, or even arterial clot. This warrants withholding further procoagulant transfusion and considering early pharmacological VTE prophylaxis once surgical bleeding is controlled."},
  ]);
})();

// ── STOP THE BLEED MICRO TOP-UP (+9 flash, +16 quiz) ──────────────────────
(function(){
  if(!window.QB_STOP_BLEED) return;
  var fc = window.QB_STOP_BLEED.flashcards;
  var qz = window.QB_STOP_BLEED.quiz;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});

  fc.easy = fc.easy.concat([
    {term:"Tourniquet skin protection",def:"Tourniquets should be applied over clothing or with padding when possible — bare skin application increases risk of blistering but is acceptable in emergencies"},
    {term:"Wound closure timing",def:"Lacerations should be cleaned and closed within 6–8 hours (golden period) to minimize infection risk — hemorrhage control always takes priority first"},
    {term:"Freeze-dried plasma",def:"A lyophilized plasma product that can be stored at room temperature and reconstituted with water — used by military for far-forward resuscitation where refrigeration is unavailable"},
    {term:"Resuscitative thoracotomy",def:"Emergency open-chest surgery at the bedside — last resort for cardiac arrest from penetrating chest trauma; must be performed within minutes of arrest"},
    {term:"Intraosseous (IO) access",def:"Needle inserted into bone marrow (typically proximal tibia or humerus) — allows rapid drug and fluid administration when IV access is impossible in major trauma"},
    {term:"Base deficit in shock",def:"A negative base excess reflecting metabolic acidosis from tissue hypoperfusion — values below −6 indicate moderate shock; below −14 indicate severe, life-threatening shock"},
    {term:"AVPU vs GCS in field assessment",def:"AVPU (Alert/Verbal/Pain/Unresponsive) is used in the field for rapid assessment; GCS (Glasgow Coma Scale 3–15) is used in hospital for detailed neurological monitoring"},
    {term:"Tourniquet limb reassessment",def:"Check the distal limb every 10–15 minutes after tourniquet application — document any changes in color, sensation, or bleeding that you can report to EMS"},
    {term:"Stop the Bleed coalition",def:"A broad coalition of government agencies (DHS, DoD, HHS), medical societies, and corporations supporting expansion of public bleeding control training nationwide"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"What is the correct response if a wound has an object impaled in it?",opts:["Remove it quickly to clean the wound","Stabilize it in place — never remove; apply pressure around it","Push it in deeper to stop bleeding","Ignore it and apply a tourniquet"],correct:1,explain:"Never remove an impaled object — it may be tamponading (plugging) a bleeding blood vessel. Removing it can cause catastrophic hemorrhage. Stabilize it with bulky dressings on either side and transport immediately."},
    {q:"What type of wound should never have circumferential pressure applied to it?",opts:["Thigh laceration","Forearm wound","Neck wound","Calf wound"],correct:2,explain:"Never apply circumferential pressure to the neck — this would compress the airway and jugular veins and could cause serious harm. For neck wounds, apply direct pressure with fingers on the bleeding site without encircling the neck."},
    {q:"Why is it important to remove wet clothing from a severely bleeding trauma patient?",opts:["Wet clothing increases bleeding","Wet clothing causes hypothermia — cold impairs clotting and worsens shock","Wet clothing hides the wound","EMS prefers to see dry patients"],correct:1,explain:"Wet clothing rapidly causes hypothermia through evaporation and conduction. Hypothermia below 35°C significantly impairs the clotting cascade, worsening hemorrhage. Remove wet clothing and cover with blankets to maintain body temperature as part of hemorrhage management."},
    {q:"What is the single most important skill a bystander can contribute at a mass casualty bleeding event?",opts:["Performing surgery","Applying tourniquets and wound packing to actively bleeding victims","Triaging all patients before treating any","Taking photographs for documentation"],correct:1,explain:"Applying tourniquets and wound packing to actively hemorrhaging victims is the highest-impact skill a trained bystander can perform. In a mass casualty event, multiple bystanders each controlling one bleeding victim can collectively save many more lives than EMS alone could reach."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"A patient received 1 gram of TXA intravenously at the scene of a car crash 45 minutes after injury. According to CRASH-2 dosing, what should happen next?",opts:["No further TXA — one dose is sufficient","A second 1 gram dose of TXA should be given over 8 hours in hospital","TXA must be repeated every hour for 3 hours","TXA should not have been given in the field at all"],correct:1,explain:"CRASH-2 TXA dosing: 1 gram IV over 10 minutes immediately, then 1 gram IV over 8 hours. The second dose is essential — it maintains TXA plasma levels to continue anti-fibrinolytic effect during the critical early resuscitation period. The two-dose protocol showed the mortality benefit."},
    {q:"A patient with a stab wound to the left chest has absent breath sounds on the left, tracheal deviation to the right, distended neck veins, and hypotension. What intervention is indicated?",opts:["Tourniquet on the chest","Needle decompression at 2nd intercostal space midclavicular line on the left","Wound packing into the chest","IV fluid bolus of 2 liters normal saline"],correct:1,explain:"This is tension pneumothorax — absent unilateral breath sounds, tracheal deviation AWAY from affected side, neck vein distension (impaired venous return), and obstructive shock. Treatment: immediate needle decompression at 2nd ICS midclavicular line on affected side (left) — releases trapped air and restores cardiac output. Fluid bolus temporarily raises filling pressure but does not fix the cause."},
    {q:"In the MARCH protocol, what does the 'H' (Hypothermia) component address?",opts:["Giving warm IV fluids only","All measures to prevent heat loss — removing wet clothing, applying insulation, using warm blankets, warm IV fluids, and warming the environment","Only removing wet clothing","Treating fever from infection"],correct:1,explain:"Hypothermia prevention in MARCH encompasses all heat-conservation measures: removing wet clothing (evaporative loss), insulating from cold surfaces, applying reflective/emergency blankets, warming IV fluids to 37–39°C, and warming the transport environment. Even in mild climates, evaporation from wet trauma patients rapidly causes clinically significant hypothermia."},
    {q:"Why is the ABCDE assessment (Airway, Breathing, Circulation, Disability, Exposure) modified to MARCH in tactical/combat settings?",opts:["ABCDE was developed for civilians only","In high-threat settings, exsanguination kills faster than airway issues — MARCH front-loads hemorrhage control before airway to match time-to-death priorities in penetrating trauma","MARCH is easier to remember","ABCDE does not include hemorrhage control"],correct:1,explain:"ABCDE prioritizes airway because it was developed for medical/cardiac emergencies where airway compromise is primary. In penetrating trauma and tactical settings, massive hemorrhage kills faster than airway obstruction. MARCH reorders priorities to match survival data — hemorrhage control first saves the most lives in the trauma population."},
    {q:"A patient who received 18 units of pRBCs over 6 hours develops hypocalcemia, hypotension, and QT prolongation on ECG. What is the most likely cause?",opts:["Transfusion reaction from blood type mismatch","Citrate toxicity — massive citrate load from blood products chelating ionized calcium","Iron overload from excessive red cell transfusion","Hyperkalemia from stored blood"],correct:1,explain:"Citrate is added to all stored blood products as an anticoagulant. During massive transfusion, large citrate loads exceed the liver's capacity to metabolize it (>1.5 mL/kg/min of pRBC). Free ionized calcium is chelated, causing hypocalcemia: reduced myocardial contractility (hypotension), QT prolongation (arrhythmia risk), and coagulopathy (calcium required for multiple coagulation steps). Treat with IV calcium gluconate or chloride."},
    {q:"What is the difference between a 'junctional tourniquet device' and a standard limb tourniquet, and why does it matter?",opts:["They are identical devices used in different locations","Junctional devices (SAM JT, JETT) apply pneumatic pressure to the groin or axilla — areas where standard circumferential limb tourniquets physically cannot be placed due to body geometry","Junctional devices are for pediatric use only","Junctional devices are experimental and not field-approved"],correct:1,explain:"Standard tourniquets require a cylindrical limb to encircle. The groin and axilla have complex geometry (body meets limb at an angle) where circumferential encirclement is impossible. Junctional tourniquet devices use pneumatic bladders or pressure plates that press directly into the groin or axilla, occluding the femoral or axillary arteries by direct compression rather than circumferential pressure."},
    {q:"A HOSA competitor studying Stop the Bleed is asked: what single action by a bystander has the greatest impact on survival from major extremity hemorrhage?",opts:["Calling 911 immediately without touching the patient","Applying a tourniquet within the first few minutes, before 30% blood volume is lost","Elevating the limb above the heart","Applying ice to slow blood flow"],correct:1,explain:"Early tourniquet application — within the first few minutes before Class III hemorrhage develops — has the greatest single impact on survival from major extremity bleeding. Military and civilian data consistently show that bystander tourniquet application before EMS arrival dramatically increases survival rates. Time is blood: every minute of uncontrolled arterial hemorrhage moves the patient closer to irreversible shock."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"A patient's ROTEM shows EXTEM CT (clotting time) prolonged, EXTEM A5 (amplitude at 5 min) low, and FIBTEM A5 nearly zero. What is the most specific blood product indicated?",opts:["Platelets — low A5 indicates platelet deficiency","FFP only — prolonged CT indicates factor deficiency","Cryoprecipitate or fibrinogen concentrate — near-zero FIBTEM A5 specifically indicates severe fibrinogen deficiency independent of platelet contribution","Whole blood transfusion"],correct:2,explain:"ROTEM interpretation: EXTEM CT prolonged = factor deficiency (FFP indicated). FIBTEM measures fibrin-only clot strength (runs without platelets). Near-zero FIBTEM A5 = fibrinogen critically low — cryoprecipitate or fibrinogen concentrate is the specific treatment. While FFP also addresses the CT, the dominant abnormality is fibrinogen depletion, which is the first clotting factor consumed in major hemorrhage. Target fibrinogen >150–200 mg/dL."},
  ]);
})();

// ── STOP THE BLEED QUIZ MICRO TOP-UP (+4 quiz) ────────────────────────────
(function(){
  if(!window.QB_STOP_BLEED) return;
  var qz = window.QB_STOP_BLEED.quiz;
  if(!qz.easy) qz.easy=[];
  qz.easy = qz.easy.concat([
    {q:"What does 'PPE' stand for in bleeding control?",opts:["Protective Patient Equipment","Personal Protective Equipment","Pre-hospital Packing Equipment","Primary Prevention of Exsanguination"],correct:1,explain:"PPE stands for Personal Protective Equipment — in bleeding control, this primarily means gloves. Gloves protect the rescuer from contact with blood and potential bloodborne pathogens such as HIV, Hepatitis B, and Hepatitis C."},
    {q:"Which is the correct sequence for responding to a bleeding emergency?",opts:["Tourniquet → Call 911 → Gloves → Assess","Gloves → Assess → Call 911 → Direct pressure → Tourniquet if needed","Assess → Tourniquet → Call 911 → Direct pressure","Call 911 → Tourniquet only → Wait for EMS"],correct:1,explain:"The correct sequence: put on gloves (PPE first), assess the wound, call 911 (or have someone call), apply direct pressure, escalate to tourniquet if limb bleeding doesn't stop, or pack if junctional wound. Scene safety always precedes all of these steps."},
    {q:"A bystander applies a tourniquet to a thigh. 2 minutes later the patient says 'it hurts, please loosen it.' What is the correct response?",opts:["Loosen it slightly — patient comfort matters","Remove it and try direct pressure instead","Explain that the pain is expected and normal, and that the tourniquet must stay in place","Tighten it further to speed up the process"],correct:2,explain:"Tourniquet pain is expected and normal — the pain does not mean it is applied incorrectly. Never loosen or remove a tourniquet because of pain. Explain reassuringly to the patient that this is temporary and necessary to save their limb and life, and that EMS and medications are coming."},
    {q:"Why is Stop the Bleed training considered a 'public health initiative'?",opts:["It is required for all U.S. high school students","It trains the general public as immediate responders — reducing preventable deaths from hemorrhage in the minutes before EMS arrives, just as CPR training reduced cardiac arrest mortality","It primarily trains healthcare workers on new techniques","It was developed by the U.S. Public Health Service"],correct:1,explain:"Stop the Bleed is a public health initiative because it addresses a population-level problem — preventable deaths from hemorrhage — by training the broadest possible public audience. The public health model: create a trained public who act as immediate responders closing the gap between injury and EMS arrival, similar to the CPR/AED public health movement."},
  ]);
})();

