// ── HOSA BOWL EXPANSION ────────────────────────────────────────────────────
(function(){
  if(!window.QB_HOSA_BOWL) return;
  var fc = window.QB_HOSA_BOWL.flashcards;
  var qz = window.QB_HOSA_BOWL.quiz;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});

  fc.easy = fc.easy.concat([
    {term:"HOSA Bowl format",def:"Three-member team answers toss-up and bonus questions across four topic areas: HOSA history/bylaws, medical terminology, health science, and current health issues"},
    {term:"HOSA Bowl toss-up",def:"An open question any team member can answer first by buzzing in — worth a set point value; incorrect answer forfeits the opportunity"},
    {term:"HOSA Bowl bonus",def:"Follow-up questions awarded to the team that correctly answers a toss-up — team may confer on bonus answers"},
    {term:"HOSA Bowl illegal consultation",def:"Conferring with teammates during a toss-up — results in loss of opportunity to answer that question"},
    {term:"HOSA Bowl tie-breaker",def:"Sudden death toss-up questions used when scores are tied at the end of regulation play"},
    {term:"HOSA Bowl team size",def:"Three members per team — each HOSA Bowl team consists of exactly 3 competitors plus an optional pre-registered alternate"},
    {term:"Systolic blood pressure",def:"The top number in a blood pressure reading — pressure in arteries when the heart beats; normal adult systolic is less than 120 mmHg"},
    {term:"Diastolic blood pressure",def:"The bottom number in a blood pressure reading — pressure when the heart rests between beats; normal adult diastolic is less than 80 mmHg"},
    {term:"Normal adult respiratory rate",def:"12–20 breaths per minute — fewer than 12 is bradypnea; more than 20 is tachypnea"},
    {term:"Pulse oximetry",def:"Measures the percentage of hemoglobin saturated with oxygen (SpO2); normal is 95–100%"},
    {term:"GCS (Glasgow Coma Scale)",def:"Assesses consciousness using Eye opening (1–4), Verbal response (1–5), and Motor response (1–6); total 3–15; ≤8 = severe TBI"},
    {term:"Triage",def:"The process of sorting patients by severity of injury or illness to prioritize treatment when resources are limited"},
    {term:"Scope of practice",def:"The legal boundary defining what a licensed healthcare professional is authorized to do based on their training and license"},
    {term:"Advance directive",def:"A legal document stating a patient's wishes for medical treatment if they become unable to communicate — includes living will and healthcare proxy"},
    {term:"DNR (Do Not Resuscitate)",def:"A medical order directing healthcare providers not to perform CPR if the patient's heart stops — requires physician authorization"},
    {term:"Patient autonomy",def:"The right of a competent patient to make their own healthcare decisions, including refusing treatment"},
    {term:"Beneficence",def:"The ethical principle of acting in the patient's best interest — one of the four core bioethical principles"},
    {term:"Non-maleficence",def:"'First, do no harm' — the ethical obligation to avoid causing unnecessary harm to patients"},
    {term:"Justice (bioethics)",def:"The fair and equitable distribution of healthcare resources and treatment — one of the four core bioethical principles"},
    {term:"Prefix: dys-",def:"Difficult, painful, or abnormal — dyspnea (difficulty breathing), dysphagia (difficulty swallowing), dysrhythmia (abnormal rhythm)"},
    {term:"Prefix: poly-",def:"Many or much — polydipsia (excessive thirst), polyuria (excessive urination), polyneuropathy (many nerves affected)"},
    {term:"Prefix: peri-",def:"Around or surrounding — pericardium (sac around the heart), peritoneum (lining around abdominal organs)"},
    {term:"Prefix: retro-",def:"Behind or backward — retroperitoneal (behind the peritoneum), retrosternal (behind the sternum)"},
    {term:"Suffix: -algia",def:"Pain — myalgia (muscle pain), neuralgia (nerve pain), arthralgia (joint pain)"},
    {term:"Suffix: -plasty",def:"Surgical repair or reconstruction — rhinoplasty (nose), arthroplasty (joint), mammoplasty (breast)"},
    {term:"Suffix: -stenosis",def:"Narrowing — aortic stenosis (narrowed aortic valve), pyloric stenosis (narrowed pylorus)"},
    {term:"Suffix: -rrhea",def:"Flow or discharge — diarrhea (frequent loose stools), rhinorrhea (runny nose), menorrhea (menstrual flow)"},
    {term:"Root: cardi/o",def:"Heart — cardiology, carditis, cardiomegaly (enlarged heart), cardiovascular"},
    {term:"Root: pulmon/o",def:"Lung — pulmonology, pulmonary embolism, cardiopulmonary"},
    {term:"Root: gastr/o",def:"Stomach — gastritis, gastrointestinal, gastroenterology"},
    {term:"Root: neur/o",def:"Nerve — neurology, neuritis, neuropathy, neurosurgeon"},
    {term:"Root: arthr/o",def:"Joint — arthritis, arthroscopy, arthroplasty"},
    {term:"Root: derm/o / dermat/o",def:"Skin — dermatology, dermatitis, epidermis"},
    {term:"Root: oste/o",def:"Bone — osteoporosis, osteomyelitis, osteoarthritis"},
    {term:"Root: hem/o / hemat/o",def:"Blood — hematology, hemoglobin, hemorrhage, hematoma"},
    {term:"Root: cyst/o",def:"Bladder or sac — cystitis (bladder infection), cystoscopy, cystectomy"},
    {term:"Root: enter/o",def:"Intestine — enteritis, gastroenteritis, parenteral (beside the intestine)"},
    {term:"Root: rhin/o",def:"Nose — rhinitis, rhinorrhea, rhinoplasty"},
    {term:"Root: ophthalm/o",def:"Eye — ophthalmology, ophthalmoscope, ophthalmic"},
    {term:"Root: ot/o",def:"Ear — otitis, otoscope, otolaryngology"},
    {term:"Root: my/o",def:"Muscle — myalgia, myocardium, myositis"},
    {term:"Root: thorac/o",def:"Chest — thoracic, thoracotomy, pneumothorax"},
    {term:"Root: abdomin/o",def:"Abdomen — abdominal, abdominoplasty"},
    {term:"Root: cephal/o",def:"Head — cephalic, hydrocephalus, encephalopathy"},
    {term:"Root: cyan/o",def:"Blue — cyanosis (blue discoloration from low oxygen), cyanotic"},
    {term:"Root: leuk/o",def:"White — leukocyte (white blood cell), leukemia"},
    {term:"Root: erythr/o",def:"Red — erythrocyte (red blood cell), erythema (redness)"},
    {term:"Root: melan/o",def:"Black or dark — melanoma, melanin, melanocyte"},
    {term:"CDC",def:"Centers for Disease Control and Prevention — U.S. federal agency responsible for disease surveillance, outbreak investigation, and public health promotion"},
    {term:"WHO",def:"World Health Organization — the United Nations agency responsible for international public health, setting global health standards"},
    {term:"NIH",def:"National Institutes of Health — the primary U.S. agency for biomedical and health research, composed of 27 institutes and centers"},
    {term:"FDA",def:"Food and Drug Administration — regulates food safety, prescription and OTC drugs, medical devices, and biologics in the U.S."},
    {term:"OSHA",def:"Occupational Safety and Health Administration — sets and enforces workplace safety standards; requires bloodborne pathogen training for healthcare workers"},
    {term:"ICD codes",def:"International Classification of Diseases — standardized codes used worldwide to classify diseases, injuries, and causes of death"},
    {term:"CPT codes",def:"Current Procedural Terminology — codes used by healthcare providers to bill for medical procedures and services"},
    {term:"EHR (Electronic Health Record)",def:"The digital version of a patient's medical chart — shared across providers to improve care coordination and reduce errors"},
    {term:"Vaccination schedule",def:"The CDC-recommended timeline for immunizations — includes childhood vaccines (MMR, DTaP, polio) and adult vaccines (flu, shingles, pneumococcal)"},
    {term:"Herd immunity threshold formula",def:"1 − (1/R0) — when enough of a population is immune, disease cannot sustain transmission; measles requires ~95% immunity (R0 of 12–18)"},
    {term:"Social determinants of health",def:"Non-medical factors affecting health outcomes — income, education, housing, food security, transportation, neighborhood safety"},
    {term:"Health disparity",def:"Preventable differences in health outcomes between population groups — linked to social, economic, and environmental disadvantages"},
    {term:"Body mass index (BMI)",def:"Weight (kg) ÷ height (m²) — screening tool for weight categories: <18.5 underweight, 18.5–24.9 normal, 25–29.9 overweight, ≥30 obese"},
    {term:"Caloric needs (adult)",def:"Average adult needs 2,000–2,500 kcal/day — varies by age, sex, activity level, and metabolic rate"},
    {term:"Macronutrients",def:"Carbohydrates (4 cal/g), proteins (4 cal/g), fats (9 cal/g) — the three energy-providing nutrients"},
    {term:"Recommended daily fiber intake",def:"25g/day for women, 38g/day for men (or 14g per 1,000 calories) — most Americans consume only 15g/day"},
    {term:"Hypertension classification",def:"Normal: <120/<80; Elevated: 120–129/<80; Stage 1 HTN: 130–139/80–89; Stage 2 HTN: ≥140/≥90"},
    {term:"Diabetes diagnostic criteria",def:"Fasting glucose ≥126 mg/dL, random glucose ≥200 with symptoms, HbA1c ≥6.5%, or 2-hour glucose ≥200 on OGTT"},
    {term:"HbA1c",def:"Glycated hemoglobin — reflects average blood glucose over 2–3 months; <5.7% normal, 5.7–6.4% prediabetes, ≥6.5% diabetes"},
    {term:"LDL cholesterol",def:"Low-density lipoprotein — 'bad' cholesterol that deposits in artery walls; target <100 mg/dL (general), <70 in high-risk patients"},
    {term:"HDL cholesterol",def:"High-density lipoprotein — 'good' cholesterol that removes LDL from arteries; higher is better; <40 men, <50 women = low"},
    {term:"Triglycerides",def:"Blood fats used for energy — normal <150 mg/dL; elevated levels increase cardiovascular risk, especially with low HDL"},
    
    {term:"Osteoporosis definition",def:"Bone mineral density ≥2.5 standard deviations below the young adult mean (T-score ≤−2.5) — increases fracture risk"},
    {term:"DEXA scan",def:"Dual-energy X-ray absorptiometry — gold standard for measuring bone mineral density to diagnose osteoporosis"},
    {term:"Iron deficiency anemia signs",def:"Fatigue, pallor, brittle nails, pica (eating non-food items), koilonychia (spoon-shaped nails), glossitis"},
    {term:"B12 deficiency signs",def:"Macrocytic anemia, peripheral neuropathy (numbness/tingling), glossitis, neuropsychiatric symptoms"},
    {term:"Scurvy",def:"Vitamin C deficiency — bleeding gums, perifollicular hemorrhages, poor wound healing, corkscrew hairs"},
    {term:"Rickets",def:"Vitamin D deficiency in children — soft, bowing bones; in adults the same deficiency causes osteomalacia"},
    {term:"Pellagra",def:"Niacin (B3) deficiency — the 4 Ds: Dermatitis, Diarrhea, Dementia, Death"},
    {term:"Kwashiorkor",def:"Protein deficiency (adequate calories) — edema especially abdominal, growth failure, fatty liver; seen in weaned children"},
    {term:"Marasmus",def:"Both calorie and protein deficiency — severe wasting, no edema; seen in infants with overall starvation"},
    {term:"Leading causes of death (U.S.)",def:"Heart disease, cancer, COVID-19/respiratory diseases, accidents, stroke — top 5 leading causes of death in the U.S."},
    {term:"Opioid epidemic statistics",def:"Over 100,000 overdose deaths per year in the U.S. — fentanyl is the leading driver; highest in adults aged 25–54"},
    {term:"Mental health statistics (U.S.)",def:"1 in 5 U.S. adults lives with a mental illness; depression is the leading cause of disability worldwide"},
    {term:"Cancer screening guidelines (overview)",def:"Mammography at 40–50+, colonoscopy at 45, Pap smear at 21, low-dose CT for lung cancer in heavy smokers, PSA for prostate"},
    {term:"Antibiotic resistance",def:"Bacteria evolving to withstand antibiotics — a major global health threat; caused by overuse and improper use of antibiotics"},
    {term:"MRSA",def:"Methicillin-resistant Staphylococcus aureus — antibiotic-resistant staph; treated with vancomycin; contact precautions required"},
    {term:"Standard precautions",def:"Applied to ALL patients — hand hygiene, gloves, gown/mask/eye protection based on exposure risk, safe sharps disposal"},
    {term:"Transmission-based precautions",def:"Contact (MRSA, C. diff), Droplet (flu, meningitis), Airborne (TB, measles, chickenpox) — added to standard precautions"},
    {term:"Hand hygiene technique",def:"Soap and water for 20 seconds OR alcohol-based sanitizer — most effective infection prevention measure"},
    {term:"Chain of infection",def:"6 links: infectious agent → reservoir → portal of exit → mode of transmission → portal of entry → susceptible host"},
    {term:"Vector-borne disease",def:"Transmitted through arthropods (mosquitoes, ticks) — examples: malaria, Lyme disease, West Nile virus, dengue fever"},
    {term:"Zoonotic disease",def:"Infectious disease transmissible between animals and humans — examples: rabies, salmonella, Lyme disease, COVID-19"},
    {term:"R0 (basic reproduction number)",def:"Average number of secondary cases one infectious person generates in a fully susceptible population; R0 >1 = epidemic growing"},
    {term:"Incidence vs prevalence",def:"Incidence: new cases over a time period. Prevalence: all existing cases at a point in time — chronic diseases have high prevalence"},
    {term:"Case fatality rate (CFR)",def:"Deaths ÷ confirmed cases × 100 — overstates mortality when mild/asymptomatic cases go undetected"},
    {term:"Epidemiologic triad",def:"Host, Agent, Environment — the three interacting factors that determine disease occurrence in a population"},
    {term:"Cohort study",def:"Follows an exposed and unexposed group over time to measure incidence and relative risk — good for common exposures"},
    {term:"Case-control study",def:"Compares those with disease (cases) to those without (controls) looking backward at exposures — best for rare diseases"},
    {term:"Randomized controlled trial (RCT)",def:"The gold standard for establishing causation — participants randomly assigned to treatment or control groups"},
    {term:"Relative risk (RR)",def:"Risk in exposed group ÷ risk in unexposed group — RR=1: no association; RR>1: increased risk; RR<1: protective"},
    {term:"Number needed to treat (NNT)",def:"1 ÷ absolute risk reduction — the number of patients who must receive treatment to prevent one adverse outcome"},
    {term:"Sensitivity vs specificity",def:"Sensitivity: true positive rate (rules OUT disease if negative). Specificity: true negative rate (rules IN disease if positive)"},
  ]);

  fc.medium = fc.medium.concat([
    {term:"HOSA Bowl strategy: powering questions",def:"Buzz in before the question is fully read when confident — earns points and a bonus, but an incorrect early answer forfeits the opportunity"},
    {term:"HOSA Bowl study domain: HOSA bylaws",def:"Know officer roles, Delegate Assembly procedures, amendment processes, membership divisions, and chapter governance"},
    {term:"HOSA Bowl study domain: current health issues",def:"Monitor CDC updates, WHO reports, and major health news in the months before competition — outbreak data, policy changes, statistics"},
    {term:"HOSA Bowl study domain: medical terminology",def:"Roots, prefixes, and suffixes — focus on high-yield combinations and clinical application of terms"},
    {term:"HOSA Bowl study domain: health science",def:"Anatomy, physiology, disease processes, nutrition, pharmacology basics, public health, and health career pathways"},
    {term:"Pharmacokinetics: ADME",def:"Absorption, Distribution, Metabolism, Excretion — the four processes governing how drugs move through the body"},
    {term:"First-pass metabolism",def:"Drugs absorbed from the GI tract pass through the liver before reaching systemic circulation — some are extensively metabolized, reducing bioavailability"},
    {term:"Half-life (drug)",def:"Time for plasma drug concentration to decrease by 50% — determines dosing frequency; 4–5 half-lives to reach steady state"},
    {term:"Blood-brain barrier",def:"Selectively permeable barrier formed by tight junctions in brain capillaries — allows lipid-soluble molecules through; protects CNS from pathogens and toxins"},
    {term:"Autonomic nervous system division",def:"Sympathetic ('fight or flight') and parasympathetic ('rest and digest') — complementary divisions controlling involuntary body functions"},
    {term:"Sympathetic nervous system effects",def:"Increases HR, BP, respiratory rate, dilates pupils, diverts blood to muscles — epinephrine and norepinephrine are key neurotransmitters"},
    {term:"Parasympathetic nervous system effects",def:"Decreases HR, increases GI motility, constricts pupils, promotes digestion — acetylcholine is the key neurotransmitter"},
    {term:"Renin-angiotensin-aldosterone system (RAAS)",def:"Hormonal cascade maintaining blood pressure and fluid balance — renin released by kidney → angiotensin II → aldosterone → sodium/water retention"},
    {term:"ACE inhibitors mechanism",def:"Block conversion of angiotensin I to angiotensin II — lower blood pressure, reduce heart failure progression, protect kidneys in diabetes"},
    {term:"Beta-blockers mechanism",def:"Block beta-adrenergic receptors — reduce heart rate, blood pressure, and cardiac oxygen demand; used in HTN, heart failure, arrhythmias"},
    {term:"Statins mechanism",def:"Inhibit HMG-CoA reductase — reduce LDL cholesterol synthesis; used to prevent cardiovascular events; may cause myopathy"},
    {term:"Diuretics mechanism",def:"Increase urine output by reducing renal sodium reabsorption — reduce blood volume and blood pressure; thiazides are first-line for HTN"},
    {term:"Antibiotic classes overview",def:"Beta-lactams (penicillins, cephalosporins), macrolides, fluoroquinolones, aminoglycosides, tetracyclines — each targets different bacterial structures"},
    {term:"Corticosteroid effects",def:"Anti-inflammatory and immunosuppressive — used for asthma, autoimmune disease, allergic reactions; side effects include hyperglycemia, osteoporosis, immunosuppression"},
    {term:"Insulin types",def:"Rapid-acting (lispro, aspart), short-acting (regular), intermediate (NPH), long-acting (glargine, detemir) — different onset and duration profiles"},
    {term:"Cardiac output formula",def:"CO = Heart Rate × Stroke Volume — normal adult CO is 4–8 L/min; decreased in heart failure, increased during exercise"},
    {term:"Frank-Starling law",def:"The more the ventricle is filled (preload), the greater the force of contraction — up to a limit; basis of cardiac compensation in heart failure"},
    {term:"Preload vs afterload",def:"Preload: ventricular filling pressure (volume returned to heart). Afterload: resistance the heart pumps against (systemic vascular resistance)"},
    {term:"Congestive heart failure signs",def:"Left-sided: pulmonary edema, dyspnea, orthopnea. Right-sided: peripheral edema, JVD, hepatomegaly — often combined"},
    {term:"Atrial fibrillation",def:"Irregular, chaotic atrial electrical activity — causes irregular ventricular rate; increases stroke risk 5-fold; treated with rate control and anticoagulation"},
    {term:"Coronary artery disease risk factors",def:"HTN, hyperlipidemia, diabetes, smoking, obesity, family history, age, male sex — Framingham risk factors"},
    {term:"STEMI treatment",def:"ST-elevation MI — primary PCI (percutaneous coronary intervention) within 90 minutes; aspirin + P2Y12 inhibitor; anticoagulation"},
    {term:"Pneumonia pathogens by setting",def:"Community: S. pneumoniae, H. influenzae, atypicals (Mycoplasma). Hospital: gram-negatives, MRSA. Aspiration: anaerobes"},
    {term:"COPD vs asthma difference",def:"COPD: irreversible airflow obstruction (usually smokers, older adults). Asthma: reversible bronchospasm (often allergic, younger patients)"},
    {term:"Spirometry in COPD",def:"FEV1/FVC ratio <0.70 confirms obstruction; GOLD staging based on FEV1 % predicted — I (mild) to IV (very severe)"},
    {term:"Pulmonary embolism signs",def:"Sudden dyspnea, pleuritic chest pain, tachycardia; Wells score + D-dimer or CT-PA for diagnosis; anticoagulation for treatment"},
    {term:"Hepatic encephalopathy",def:"Brain dysfunction from liver failure — ammonia accumulates (liver can't detoxify); symptoms: confusion, asterixis, coma; treated with lactulose, rifaximin"},
    {term:"Cirrhosis complications",def:"Portal hypertension → esophageal varices, ascites, splenomegaly; hepatic encephalopathy; spontaneous bacterial peritonitis; hepatorenal syndrome"},
    {term:"Acute kidney injury (AKI) causes",def:"Pre-renal (dehydration, hemorrhage), intrinsic (nephrotoxins, glomerulonephritis), post-renal (obstruction) — most common is pre-renal"},
    {term:"Glomerular filtration rate (GFR)",def:"Volume of blood filtered per minute — normal 90–120 mL/min; used to stage chronic kidney disease (CKD stages 1–5)"},
    {term:"CKD management",def:"Control BP (ACE inhibitor or ARB), manage diabetes, dietary protein/potassium/phosphate restriction, erythropoietin for anemia, prepare for dialysis if stage 4–5"},
    {term:"Thyroid function tests",def:"TSH: best screening test (elevated in hypothyroidism, low in hyperthyroidism). T4 and T3: actual hormone levels — confirm diagnosis"},
    {term:"Hypothyroidism signs",def:"Fatigue, weight gain, cold intolerance, constipation, bradycardia, myxedema — treated with levothyroxine"},
    {term:"Hyperthyroidism signs",def:"Weight loss, heat intolerance, tachycardia, sweating, exophthalmos (Graves' disease), tremor — treated with methimazole, RAI, or surgery"},
    {term:"Cushing's syndrome",def:"Excess cortisol — central obesity, moon face, buffalo hump, hypertension, hyperglycemia, skin striae; most common cause is exogenous steroids"},
    {term:"Addison's disease",def:"Primary adrenal insufficiency — hyperpigmentation, weakness, hypotension, hyponatremia, hyperkalemia; treated with hydrocortisone + fludrocortisone"},
    {term:"Rheumatoid arthritis vs osteoarthritis",def:"RA: symmetric joint inflammation, morning stiffness >1hr, autoimmune (anti-CCP antibodies). OA: asymmetric, worse with use, degenerative — affects weight-bearing joints"},
    {term:"Lupus (SLE) features",def:"Butterfly malar rash, photosensitivity, joint pain, nephritis, serositis, cytopenias, anti-dsDNA antibodies — multi-system autoimmune disease"},
    {term:"Multiple sclerosis",def:"Autoimmune demyelination of CNS — relapsing-remitting or progressive; Lhermitte's sign, Uhthoff's phenomenon; MRI white matter lesions"},
    {term:"Parkinson's disease triad",def:"Tremor (resting, pill-rolling), Rigidity, Bradykinesia — also postural instability; dopamine deficiency in substantia nigra; treated with levodopa"},
    {term:"Alzheimer's disease pathology",def:"Amyloid-beta plaques and neurofibrillary tangles (tau protein) — progressive memory loss; acetylcholine deficit; treated with cholinesterase inhibitors"},
    {term:"Meningitis diagnosis",def:"Lumbar puncture: bacterial (cloudy CSF, high WBC, low glucose, high protein); viral (clear CSF, moderate WBC, normal glucose)"},
    {term:"Sepsis definition (Sepsis-3)",def:"Life-threatening organ dysfunction from dysregulated host response to infection — SOFA score increase ≥2 points"},
    {term:"Septic shock definition",def:"Sepsis with persistent hypotension despite adequate fluid resuscitation requiring vasopressors, plus lactate >2 mmol/L"},
    {term:"1-hour sepsis bundle",def:"Measure lactate, blood cultures ×2, broad-spectrum antibiotics, 30 mL/kg crystalloid if hypotensive, vasopressors if needed"},
    {term:"SIADH vs diabetes insipidus",def:"SIADH: low sodium, concentrated urine, too much ADH. DI: high sodium, dilute urine, too little ADH (central) or ADH resistance (nephrogenic)"},
    {term:"DKA vs HHS comparison",def:"DKA: type 1, ketosis, pH <7.3, glucose 250–600. HHS: type 2, no ketosis, pH normal, glucose >600, severe dehydration"},
    {term:"Cancer hallmarks",def:"Self-sufficiency in growth signals, insensitivity to growth inhibitors, evading apoptosis, limitless replication, angiogenesis, invasion/metastasis"},
    {term:"TNM staging",def:"T (tumor size/invasion), N (lymph node involvement), M (metastasis) — standardized cancer staging system used worldwide"},
    {term:"HPV and cancer",def:"High-risk HPV (strains 16, 18) causes cervical, oropharyngeal, anal, vulvar, vaginal, and penile cancers — prevented by Gardasil 9 vaccine"},
    {term:"BRCA1/BRCA2 genes",def:"Tumor suppressor genes — mutations significantly increase lifetime risk of breast (~70%) and ovarian (~44%) cancer"},
    {term:"Helicobacter pylori",def:"Gram-negative bacteria colonizing the gastric mucosa — major cause of peptic ulcer disease and gastric cancer; treated with triple therapy"},
    {term:"Clostridium difficile (C. diff)",def:"Anaerobic spore-forming bacteria causing antibiotic-associated colitis — profuse watery diarrhea; contact precautions; treated with vancomycin or fidaxomicin"},
    {term:"HIV/AIDS progression",def:"Acute infection (flu-like) → chronic HIV (years, CD4 decline) → AIDS (CD4 <200 or opportunistic infection); ART stops progression"},
    {term:"Opportunistic infections in AIDS",def:"PCP (Pneumocystis jirovecii pneumonia), CMV retinitis, MAC, toxoplasmosis, cryptococcal meningitis — occur when CD4 <200"},
    {term:"Tuberculosis (TB) pathophysiology",def:"Mycobacterium tuberculosis inhaled → primary infection → latent TB (can reactivate) or active TB; acid-fast bacillus; treated with RIPE regimen"},
    {term:"RIPE TB treatment",def:"Rifampin, Isoniazid, Pyrazinamide, Ethambutol — 4-drug regimen for 2 months, then 2 drugs for 4–7 more months"},
    {term:"Vaccine types",def:"Live-attenuated (MMR, varicella), inactivated (flu shot, polio-IPV), subunit (Hep B, HPV), toxoid (tetanus, diphtheria), mRNA (COVID-19)"},
    {term:"Herd immunity concept",def:"When enough of a population is immune (through vaccination or infection), disease cannot spread efficiently — protects those unable to be vaccinated"},
    {term:"Public health surveillance",def:"Ongoing systematic collection, analysis, and interpretation of health data — enables early outbreak detection and evidence-based program planning"},
    {term:"Healthy People 2030",def:"U.S. national health objectives framework — sets measurable goals across health topics to improve health and well-being over the decade"},
    {term:"Triple Aim (IHI)",def:"Three interdependent goals: better patient experience, improved population health, reduced per-capita cost — developed by the Institute for Healthcare Improvement"},
    {term:"Quadruple Aim",def:"Triple Aim plus a fourth goal: improving the work life of healthcare providers — addressing burnout and professional satisfaction"},
    {term:"Value-based care",def:"Reimburses providers based on patient outcomes and quality rather than volume of services — incentivizes prevention and efficiency"},
    {term:"Accountable Care Organization (ACO)",def:"A network of providers sharing responsibility for quality and cost of care for a defined patient population — shares savings if quality targets are met"},
    {term:"Population health management",def:"Proactive approach to improving health outcomes of a defined group — uses data analytics to identify high-risk patients and intervene early"},
    {term:"Health literacy",def:"A patient's ability to obtain, process, and understand health information to make decisions — poor health literacy linked to worse outcomes"},
    {term:"Cultural competence in healthcare",def:"Effectively serving patients from diverse cultural backgrounds by respecting their values, beliefs, and communication styles — reduces health disparities"},
    {term:"Implicit bias in healthcare",def:"Unconscious attitudes affecting clinical decisions — associated with disparities in pain management, diagnosis, and treatment across racial groups"},
    {term:"Telehealth advantages and limitations",def:"Advantages: access, convenience, reduced cost. Limitations: not all conditions suitable for remote care, technology barriers, evolving reimbursement policies"},
    {term:"Artificial intelligence in healthcare",def:"AI applications include diagnostic imaging analysis, EHR data mining, drug discovery, clinical decision support, and predictive analytics"},
    {term:"CRISPR-Cas9",def:"Gene editing technology that can precisely cut and modify DNA — used in research and emerging therapies for genetic diseases like sickle cell anemia"},
    {term:"mRNA vaccine technology",def:"Delivers mRNA instructing cells to produce a viral protein, triggering immune response — pioneer application: COVID-19 vaccines (Moderna, Pfizer-BioNTech)"},
    {term:"Immunotherapy in cancer",def:"Checkpoint inhibitors (PD-1/PD-L1, CTLA-4), CAR-T cell therapy, cancer vaccines — harness the immune system to target cancer cells"},
    {term:"Precision medicine",def:"Treatment based on individual genetic, environmental, and lifestyle factors — 'right treatment, right patient, right time'"},
    {term:"One Health concept",def:"Recognizes that human, animal, and environmental health are interconnected — requires collaboration between medicine, veterinary science, and ecology"},
    {term:"Climate change and health",def:"Worsens air quality, expands vector ranges, increases heat illness, disrupts food and water security — a major emerging public health threat"},
    {term:"Food insecurity and health",def:"Lack of reliable access to sufficient nutritious food — linked to obesity paradox, chronic disease, poor child development, and mental health issues"},
  ]);

  fc.hard = fc.hard.concat([
    {term:"Complement system activation pathways",def:"Classical (antibody-dependent), lectin (mannose-binding lectin), and alternative (direct pathogen surface) — all converge at C3 cleavage → MAC formation"},
    {term:"MHC class I vs class II",def:"MHC I: present on all nucleated cells, present intracellular antigens to CD8+ cytotoxic T cells. MHC II: on APCs, present extracellular antigens to CD4+ helper T cells"},
    {term:"Cytokine storm",def:"Uncontrolled systemic inflammation from excessive cytokine release — can occur in severe infection, CAR-T therapy, or autoimmune conditions; causes multi-organ failure"},
    {term:"Warburg effect",def:"Cancer cells preferentially use glycolysis even in the presence of oxygen ('aerobic glycolysis') — produces lactate; basis for PET scan (glucose uptake)"},
    {term:"Epigenetics in disease",def:"DNA methylation and histone modification alter gene expression without changing DNA sequence — lifestyle factors (diet, stress) can reverse these changes"},
    {term:"Pharmacogenomics",def:"Study of how genetic variation affects drug response — CYP450 gene variants alter drug metabolism; guides personalized prescribing"},
    {term:"QALY (quality-adjusted life year)",def:"Measure of disease burden combining quantity and quality of life — 1 QALY = 1 year of perfect health; used in health economic evaluations"},
    {term:"Number needed to harm (NNH)",def:"Number of patients who must receive a treatment for one additional patient to experience harm — balances against NNT in clinical decisions"},
    {term:"Ecological fallacy",def:"Drawing individual-level conclusions from group-level data — common error in epidemiological research using aggregate statistics"},
    {term:"Berkson's bias",def:"Selection bias in hospital-based studies — hospitalized patients are not representative of the general population, distorting associations"},
    {term:"Intention-to-treat analysis",def:"All randomized participants are analyzed in their assigned group regardless of compliance — preserves randomization and reduces bias"},
    {term:"Bradford Hill criteria",def:"9 criteria for establishing causality: strength, consistency, specificity, temporality, biological gradient, plausibility, coherence, experiment, analogy"},
    {term:"Mendelian randomization",def:"Uses genetic variants as instrumental variables to estimate causal effects of exposures on outcomes — reduces confounding in observational studies"},
    {term:"CRISPR off-target effects",def:"Unintended DNA editing at sites similar to the target sequence — a major safety concern for therapeutic CRISPR applications"},
    {term:"CAR-T cell therapy mechanism",def:"Patient's T cells engineered with chimeric antigen receptors targeting tumor-specific antigens — reinfused to kill cancer cells; used in hematologic malignancies"},
    {term:"Liquid biopsy",def:"Detection of tumor DNA, cells, or exosomes in blood — enables early cancer detection, treatment monitoring, and resistance detection without surgical biopsy"},
    {term:"Microbiome and health",def:"Trillions of microorganisms (bacteria, fungi, viruses) in the gut — influence immunity, metabolism, mental health, and drug responses through the gut-brain axis"},
    {term:"Long COVID",def:"Persistent symptoms after acute COVID-19 infection lasting >12 weeks — fatigue, cognitive impairment ('brain fog'), dyspnea; affects ~10–30% of those infected"},
    {term:"Pandemic preparedness framework",def:"IHR (International Health Regulations) — legally binding WHO framework requiring countries to develop surveillance, reporting, and response capacities for public health emergencies"},
    {term:"Antimicrobial stewardship",def:"Coordinated interventions to improve appropriate antibiotic use — reduces resistance, Clostridioides difficile infections, and healthcare costs"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"What is the normal adult heart rate?",opts:["40–60 bpm","60–100 bpm","100–120 bpm","120–160 bpm"],correct:1,explain:"Normal adult heart rate is 60–100 bpm. Below 60 is bradycardia; above 100 is tachycardia. Athletes may normally have resting heart rates in the 40s–50s."},
    {q:"What does the prefix 'tachy-' mean?",opts:["Slow","Fast","Under","Pain"],correct:1,explain:"Tachy- means fast or rapid. Examples: tachycardia (fast heart rate), tachypnea (fast breathing rate)."},
    {q:"What does the suffix '-ectomy' mean?",opts:["Inflammation","Surgical removal","Visual examination","Disease"],correct:1,explain:"-ectomy means surgical removal. Examples: appendectomy, tonsillectomy, mastectomy."},
    {q:"What does the root 'cardi/o' refer to?",opts:["Lung","Liver","Heart","Kidney"],correct:2,explain:"Cardi/o refers to the heart. Examples: cardiology, cardiomegaly, cardiovascular, pericardium."},
    {q:"What does CDC stand for?",opts:["Center for Disease Control","Centers for Disease Control and Prevention","Clinical Disease and Care","Chronic Disease Center"],correct:1,explain:"CDC stands for Centers for Disease Control and Prevention — the U.S. federal agency responsible for disease surveillance, outbreak investigation, and public health promotion."},
    {q:"What does HDL stand for and why is it called 'good' cholesterol?",opts:["High-density lipoprotein — it transports cholesterol to cells","High-density lipoprotein — it removes LDL from arteries back to the liver","Heavy-density lipid — it provides energy","High-dose lipid — it reduces inflammation"],correct:1,explain:"HDL (High-density lipoprotein) is called 'good' cholesterol because it picks up excess LDL cholesterol from artery walls and returns it to the liver for removal — reducing cardiovascular risk. Higher HDL levels are protective."},
    {q:"What is the first-line treatment for anaphylaxis?",opts:["Antihistamine (diphenhydramine)","Corticosteroids (prednisone)","Epinephrine IM (EpiPen)","Albuterol inhaler"],correct:2,explain:"Epinephrine (adrenaline) IM in the anterolateral thigh is the only first-line treatment for anaphylaxis. It addresses all three components: vasodilation (alpha-1), bronchospasm (beta-2), and cardiac effects (beta-1). Antihistamines and steroids are adjuncts only."},
    {q:"What organization is responsible for setting global health standards?",opts:["CDC","NIH","WHO","FDA"],correct:2,explain:"The World Health Organization (WHO) is the United Nations agency responsible for international public health, coordinating responses to global health emergencies and setting international health standards."},
    {q:"Normal adult blood pressure is classified as:",opts:["<140/90 mmHg","<130/80 mmHg","<120/80 mmHg","<100/70 mmHg"],correct:2,explain:"Normal blood pressure is less than 120/80 mmHg. Elevated is 120–129/<80. Stage 1 hypertension is 130–139/80–89. Stage 2 is ≥140/≥90."},
    {q:"What does HIPAA primarily protect?",opts:["Healthcare worker wages","Patient protected health information (PHI)","Hospital financial records","Drug pricing information"],correct:1,explain:"HIPAA (Health Insurance Portability and Accountability Act) primarily protects patient Protected Health Information (PHI) — any information that can identify a patient and relates to their health condition, treatment, or payment for care."},
    {q:"What is the leading cause of death in the United States?",opts:["Cancer","Stroke","Heart disease","Accidents"],correct:2,explain:"Heart disease is the leading cause of death in the United States, accounting for about 1 in every 4 deaths. It includes coronary artery disease, heart failure, and arrhythmias."},
    {q:"What does the root 'derm/o' refer to?",opts:["Bone","Skin","Blood","Nerve"],correct:1,explain:"Derm/o or dermat/o refers to the skin. Examples: dermatology, dermatitis, epidermis, dermis."},
    {q:"What does the prefix 'hypo-' mean?",opts:["Above normal","Below normal","Around","Before"],correct:1,explain:"Hypo- means below or under normal. Examples: hypoglycemia (low blood sugar), hypotension (low blood pressure), hypothermia (low body temperature)."},
    {q:"What does the suffix '-ology' mean?",opts:["Surgical removal","Inflammation","The study of","Disease"],correct:2,explain:"-ology means the study of. Examples: cardiology (study of the heart), neurology (study of the nervous system), dermatology (study of the skin)."},
    {q:"What is BMI used to screen for?",opts:["Cholesterol levels","Blood glucose levels","Weight categories (underweight through obese)","Bone density"],correct:2,explain:"BMI (Body Mass Index) = weight (kg) ÷ height (m²). It is used to screen for weight categories: <18.5 underweight, 18.5–24.9 normal, 25–29.9 overweight, ≥30 obese. It is a screening tool, not a direct measure of body fat."},
    {q:"What does R0 measure in epidemiology?",opts:["The death rate from a disease","Average new cases one infectious person generates in a fully susceptible population","The recovery rate","The percentage hospitalized"],correct:1,explain:"R0 (R-naught) is the basic reproduction number — the average number of secondary infections caused by one infectious person in a completely susceptible population. R0 >1 means the epidemic is growing."},
    {q:"Which vitamin deficiency causes scurvy?",opts:["Vitamin A","Vitamin B12","Vitamin C","Vitamin D"],correct:2,explain:"Vitamin C (ascorbic acid) deficiency causes scurvy — characterized by bleeding gums, poor wound healing, perifollicular hemorrhages, and corkscrew body hairs. Vitamin C is essential for collagen synthesis."},
    {q:"What does the root 'neur/o' refer to?",opts:["Muscle","Nerve","Kidney","Bone"],correct:1,explain:"Neur/o refers to the nerve or nervous system. Examples: neurology, neuritis, neuropathy, neurosurgeon."},
    {q:"What is the FAST acronym used to identify?",opts:["Fire safety response","Stroke signs (Face drooping, Arm weakness, Speech difficulty, Time to call 911)","First aid steps","Fasting blood sugar testing"],correct:1,explain:"FAST stands for Face drooping, Arm weakness, Speech difficulty, Time to call 911 — a tool for quickly recognizing stroke symptoms. Every minute of untreated stroke causes death of 1.9 million neurons."},
    {q:"What is the primary function of red blood cells?",opts:["Fighting infection","Clotting blood","Carrying oxygen via hemoglobin","Producing antibodies"],correct:2,explain:"Red blood cells (erythrocytes) carry oxygen from the lungs to body tissues via hemoglobin, and transport carbon dioxide back to the lungs. They lack a nucleus and have a lifespan of about 120 days."},
    {q:"Which nutrient provides the most calories per gram?",opts:["Carbohydrates (4 cal/g)","Protein (4 cal/g)","Fat (9 cal/g)","Fiber (2 cal/g)"],correct:2,explain:"Fat provides 9 calories per gram — more than twice that of carbohydrates or protein (both 4 cal/g). Alcohol provides 7 cal/g. This is why high-fat foods are calorie-dense."},
    {q:"What does OSHA regulate in healthcare settings?",opts:["Drug pricing","Workplace safety standards, including bloodborne pathogen training","Patient billing practices","Insurance coverage requirements"],correct:1,explain:"OSHA (Occupational Safety and Health Administration) sets and enforces workplace safety standards. In healthcare, this includes the Bloodborne Pathogens Standard requiring training on HIV, hepatitis B/C, and proper PPE use."},
    {q:"What is herd immunity?",opts:["All members of a herd are vaccinated","When enough of a population is immune that disease cannot spread efficiently — protecting those who cannot be vaccinated","Only animals can develop herd immunity","Immunity from natural infection only"],correct:1,explain:"Herd immunity occurs when a sufficient proportion of a population is immune — either through vaccination or prior infection — so that the disease cannot maintain sustained transmission. This protects individuals who cannot be vaccinated (infants, immunocompromised)."},
    {q:"What does the suffix '-algia' mean?",opts:["Inflammation","Surgical removal","Pain","Disease"],correct:2,explain:"-algia means pain. Examples: myalgia (muscle pain), neuralgia (nerve pain), arthralgia (joint pain), fibromyalgia (widespread muscle pain)."},
    {q:"What is the normal fasting blood glucose range?",opts:["<70 mg/dL","70–99 mg/dL","100–125 mg/dL","≥126 mg/dL"],correct:1,explain:"Normal fasting blood glucose is 70–99 mg/dL. Prediabetes is 100–125 mg/dL (impaired fasting glucose). Diabetes is diagnosed at ≥126 mg/dL on two occasions."},
    {q:"Which pathway does TB (tuberculosis) use for transmission?",opts:["Contact","Droplet","Airborne","Vector-borne"],correct:2,explain:"Tuberculosis (TB) is transmitted through airborne particles (droplet nuclei <5 micrometers) that remain suspended in air for hours. This is why TB requires airborne precautions — N95 respirator and negative pressure room."},
    {q:"What does the root 'hem/o' refer to?",opts:["Heart","Liver","Blood","Lung"],correct:2,explain:"Hem/o or hemat/o refers to blood. Examples: hematology (study of blood), hemorrhage (bleeding), hemoglobin (oxygen-carrying protein in blood), hematoma (collection of blood)."},
    {q:"What is the role of the pancreas in blood sugar regulation?",opts:["Produces bile for fat digestion","Produces insulin (lowers blood sugar) and glucagon (raises blood sugar)","Filters blood and removes glucose","Stores glycogen"],correct:1,explain:"The pancreas has dual endocrine functions: beta cells produce insulin (lowers blood glucose by enabling cellular uptake), and alpha cells produce glucagon (raises blood glucose by stimulating glycogen breakdown in the liver)."},
    {q:"What does the prefix 'peri-' mean?",opts:["Before","After","Around","Between"],correct:2,explain:"Peri- means around or surrounding. Examples: pericardium (sac around the heart), peritoneum (membrane surrounding abdominal organs), periodontal (around the teeth)."},
    {q:"Which type of study is considered the gold standard for establishing causation?",opts:["Cohort study","Case-control study","Randomized controlled trial (RCT)","Cross-sectional survey"],correct:2,explain:"Randomized controlled trials (RCTs) are the gold standard for establishing causation. Random assignment to treatment or control groups eliminates most confounding. Observational studies can show association but cannot prove causation."},
    {q:"What does HbA1c measure?",opts:["Fasting blood glucose at a single point in time","Average blood glucose over the past 2–3 months","Total hemoglobin in the blood","Insulin resistance"],correct:1,explain:"HbA1c (glycated hemoglobin) reflects the average blood glucose over the past 2–3 months — the lifespan of red blood cells. Normal: <5.7%, Prediabetes: 5.7–6.4%, Diabetes: ≥6.5%."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"A HOSA Bowl competitor hears the question start: 'The hormone secreted by the posterior pituitary gland that promotes water reabsorption in the kidney...' and buzzes in before the question is finished. If they answer incorrectly, what happens?",opts:["They lose points and the question is re-read","They lose the opportunity; the opposing team may answer","The team is disqualified for the match","Nothing — it's only a penalty in the bonus round"],correct:1,explain:"Buzzing in incorrectly on a toss-up (powering the question) forfeits the opportunity to answer. The opposing team may then answer without penalty. This is why the decision to power must be made with high confidence."},
    {q:"Which of the following BEST describes the difference between incidence and prevalence?",opts:["Incidence measures deaths; prevalence measures new cases","Incidence measures new cases over a time period; prevalence measures all existing cases at a point in time","They are different terms for the same measurement","Prevalence is always higher than incidence"],correct:1,explain:"Incidence = new cases occurring in a defined population over a specified time period (measures risk). Prevalence = all existing cases (new and old) at a point in time (measures burden). A chronic disease can have low incidence but high prevalence."},
    {q:"A patient has a T-score of −2.7 on a DEXA scan. What does this indicate?",opts:["Normal bone density","Osteopenia (low bone mass)","Osteoporosis — T-score ≤−2.5","Severe osteoporosis requiring immediate surgery"],correct:2,explain:"T-score ≤−2.5 = osteoporosis. T-score −1.0 to −2.5 = osteopenia. T-score ≥−1.0 = normal. DEXA scan is the gold standard for measuring bone mineral density."},
    {q:"The RAAS system is activated when blood pressure falls. Which is the correct sequence of events?",opts:["Angiotensin II → renin → aldosterone → sodium retention","Renin → angiotensin I → angiotensin II (via ACE) → aldosterone → sodium/water retention","Aldosterone → renin → angiotensin II → water excretion","ACE → angiotensin II → renin → sodium loss"],correct:1,explain:"RAAS sequence: low BP → kidney releases renin → renin converts angiotensinogen to angiotensin I → ACE converts angiotensin I to angiotensin II → angiotensin II stimulates aldosterone release → aldosterone causes sodium/water retention → BP rises."},
    {q:"What is the significance of sensitivity and specificity in screening tests?",opts:["High sensitivity rules in disease; high specificity rules out disease","High sensitivity rules out disease (SnNout); high specificity rules in disease (SpPin)","They both measure the same thing","Sensitivity is only used for rare diseases"],correct:1,explain:"SnNout: high Sensitivity, Negative test rules OUT disease (good for screening). SpPin: high Specificity, Positive test rules IN disease (good for confirmation). A good screening test has high sensitivity; a good confirmatory test has high specificity."},
    {q:"A patient with HIV has a CD4 count of 150 cells/μL. What is their clinical status and primary concern?",opts:["Healthy — CD4 above 100 is safe","AIDS — CD4 <200 means they are at high risk for opportunistic infections","Chronic HIV — no immediate concerns","Pre-HIV — not yet infected"],correct:1,explain:"CD4 <200 cells/μL meets the criteria for AIDS. At this level, the immune system cannot protect against opportunistic infections like PCP (Pneumocystis jirovecii pneumonia), CMV retinitis, toxoplasmosis, and MAC. Prophylaxis is required."},
    {q:"Which of the following BEST explains why antibiotic resistance is a global public health emergency?",opts:["Antibiotics are becoming too expensive to manufacture","Bacteria evolve resistance faster than new antibiotics are developed, potentially making common infections untreatable","Antibiotic resistance only affects immunocompromised patients","Resistance only develops when patients don't finish their antibiotics"],correct:1,explain:"Antibiotic resistance is driven by evolutionary selection pressure: bacteria with resistance mutations survive treatment and reproduce. WHO projects 10 million deaths annually from drug-resistant infections by 2050 without action — exceeding cancer mortality."},
    {q:"What distinguishes STEMI from NSTEMI on an ECG?",opts:["STEMI shows no ECG changes; NSTEMI shows ST elevation","STEMI shows ST elevation ≥1mm in two contiguous leads; NSTEMI shows ST depression or T-wave changes without ST elevation","They are identical on ECG — only troponin distinguishes them","NSTEMI only affects the right side of the heart"],correct:1,explain:"STEMI: ST elevation ≥1mm in ≥2 contiguous leads — indicates complete coronary occlusion requiring immediate reperfusion (PCI within 90 min). NSTEMI: no persistent ST elevation — partial occlusion; treated with anticoagulation and early invasive strategy."},
    {q:"A public health nurse notes that a new disease has an R0 of 4. What percentage of the population must be immune to achieve herd immunity?",opts:["25%","50%","75%","90%"],correct:2,explain:"Herd immunity threshold = 1 − (1/R0) = 1 − (1/4) = 1 − 0.25 = 0.75 = 75%. When 75% of the population is immune, each case generates <1 new case and the epidemic cannot sustain itself."},
    {q:"The Triple Aim in healthcare improvement focuses on simultaneously pursuing which three goals?",opts:["Cost, access, and technology","Better patient experience, improved population health, and reduced per-capita cost","Safety, quality, and efficiency","Provider satisfaction, patient satisfaction, and financial sustainability"],correct:1,explain:"The Triple Aim (developed by IHI): (1) Improve the patient experience of care (quality and satisfaction), (2) Improve the health of populations, (3) Reduce the per capita cost of healthcare. All three must be pursued simultaneously to avoid trade-offs."},
    {q:"Which HOSA Bowl topic area would include a question about the Sepsis-3 definition?",opts:["HOSA history and bylaws","Medical terminology only","Health science — clinical disease processes","Current events only"],correct:2,explain:"The Sepsis-3 definition (life-threatening organ dysfunction from dysregulated host response to infection, SOFA score ≥2) is a health science topic — covering clinical pathophysiology and diagnostic criteria. HOSA Bowl health science questions span from basic anatomy to current clinical standards."},
    {q:"A researcher studies whether regular exercise reduces risk of type 2 diabetes by following 10,000 people over 10 years. This is which type of study?",opts:["Case-control study","Cross-sectional study","Cohort study","Randomized controlled trial"],correct:2,explain:"A cohort study follows a defined population over time to assess exposure-outcome relationships. This is a prospective cohort study — 10,000 people followed for 10 years, comparing diabetes rates between exercisers and non-exercisers. Good for common exposures and outcomes."},
    {q:"What is the primary mechanism by which statins reduce cardiovascular risk?",opts:["They block calcium channels, reducing heart rate","They inhibit HMG-CoA reductase, reducing LDL cholesterol synthesis in the liver","They prevent platelet aggregation, reducing clot formation","They dilate coronary arteries to improve blood flow"],correct:1,explain:"Statins (atorvastatin, rosuvastatin, etc.) inhibit HMG-CoA reductase — the rate-limiting enzyme in cholesterol synthesis. This reduces LDL production in the liver and upregulates LDL receptors, lowering circulating LDL by 30–60%."},
    {q:"Which of the following is classified as an airborne precaution disease?",opts:["Influenza (flu)","Meningococcal meningitis","Tuberculosis (TB)","C. difficile (C. diff)"],correct:2,explain:"TB requires airborne precautions — N95 respirator and negative pressure room — because Mycobacterium tuberculosis spreads via tiny airborne particles (<5 μm) that remain suspended in air for hours. Flu uses droplet precautions. Meningococcemia uses droplet. C. diff uses contact precautions."},
    {q:"A patient's lab results show: FEV1/FVC = 0.65. What is the most likely diagnosis and what does this ratio indicate?",opts:["Normal — ratios between 0.6–0.8 are acceptable","Obstructive lung disease (COPD or asthma) — ratio <0.70 confirms obstruction","Restrictive lung disease — FVC reduction causes low ratio","Heart failure — fluid reduces lung volumes"],correct:1,explain:"FEV1/FVC <0.70 on spirometry confirms obstructive ventilatory pattern — characteristic of COPD and asthma. FEV1/FVC measures the proportion of forced vital capacity exhaled in the first second. In restriction (fibrosis), both FEV1 and FVC fall proportionally, maintaining a normal or elevated ratio."},
    {q:"What is the difference between the Healthy People framework and the Triple Aim?",opts:["They are identical frameworks with different names","Healthy People sets national health objectives over a decade; Triple Aim is a quality improvement framework for healthcare organizations to pursue simultaneously","Triple Aim is a government mandate; Healthy People is voluntary","Healthy People focuses only on prevention; Triple Aim focuses on treatment"],correct:1,explain:"Healthy People (currently Healthy People 2030) is a federal initiative setting measurable national health goals over 10-year periods — covering disease prevention, health equity, and behavioral health. The Triple Aim is an IHI framework for healthcare organizations to simultaneously improve patient experience, population health, and reduce costs."},
    {q:"CRISPR-Cas9 has shown promise in treating sickle cell disease. What is the mechanism?",opts:["It replaces the entire hemoglobin gene with a synthetic version","It edits the BCL11A gene to reactivate fetal hemoglobin (HbF) production — which does not sickle","It eliminates all red blood cells and replaces them with synthetic carriers","It directly repairs the HbS mutation in all circulating red blood cells"],correct:1,explain:"The most successful CRISPR approach for sickle cell disease targets BCL11A — a gene that suppresses fetal hemoglobin (HbF) after birth. Editing BCL11A reactivates HbF production. Since HbF does not sickle, high HbF levels prevent sickling crises. FDA approved this approach (Casgevy) in 2023."},
    {q:"What does 'value-based care' mean in contrast to 'fee-for-service'?",opts:["Value-based care is free for patients","In value-based care, providers are paid based on patient outcomes and quality rather than volume of services","Value-based care means providing the most expensive care","Fee-for-service is more patient-centered than value-based care"],correct:1,explain:"In fee-for-service, providers are paid for each service performed regardless of outcome — creating incentives for volume. In value-based care, payment is tied to quality metrics, outcomes, and efficiency — incentivizing prevention, coordination, and keeping patients healthy."},
    {q:"A HOSA Bowl question asks about the Bradford Hill criteria. Which criterion states that the cause must precede the effect?",opts:["Specificity","Biological gradient","Temporality","Coherence"],correct:2,explain:"Temporality is the one non-negotiable Bradford Hill criterion: the cause must precede the effect. No matter how strong the other criteria, if the 'cause' comes after the outcome, causation is impossible. The other 8 criteria (strength, consistency, specificity, gradient, plausibility, coherence, experiment, analogy) strengthen the causal argument."},
    {q:"Pharmacogenomics would be MOST useful in which clinical situation?",opts:["Choosing which antibiotic to use for a bacterial infection based on culture","Determining why a patient metabolizes warfarin differently — potentially due to CYP2C9 or VKORC1 genetic variants","Selecting the best vaccine for a patient based on their age","Estimating a patient's risk of developing hypertension"],correct:1,explain:"Pharmacogenomics studies how genetic variation affects drug response. Warfarin dosing is the classic example: CYP2C9 variants affect warfarin metabolism (clearance rate), while VKORC1 variants affect pharmacodynamic sensitivity. Patients with poor-metabolizer CYP2C9 genotypes need much lower warfarin doses to avoid bleeding."},
    {q:"What is the One Health concept and why is it relevant to public health?",opts:["All patients should have one primary care provider","Human, animal, and environmental health are interconnected — zoonotic diseases, antimicrobial resistance, and climate change require collaboration across disciplines","All public health funding should go to one federal agency","One standardized health protocol should apply to all countries"],correct:1,explain:"One Health recognizes that human health cannot be separated from animal and environmental health. Zoonotic diseases (COVID-19, SARS, Ebola, Lyme, rabies) originate in animals. Antibiotic use in livestock drives human antimicrobial resistance. Climate change affects vector ranges and disease distribution. Solving these requires medicine, veterinary science, and environmental science working together."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"A HOSA Bowl team powers a question and answers incorrectly. The opposing team answers correctly on the re-read. The question was worth 10 points with a 20-point bonus package. The correct sequence of scoring is:",opts:["Incorrect team: −5 points; Correct team: +10 points + bonus opportunity","Incorrect team: 0 (no penalty in toss-up); Correct team: +10 points + bonus opportunity","Both teams share the 10 points","Incorrect team: −10 points; no bonus available"],correct:1,explain:"In standard HOSA Bowl rules, an incorrect toss-up answer costs the answering team their opportunity (and may incur a penalty per CEP — check current rules). The opposing team gets a chance to answer the full question from the beginning. If correct, they earn the full toss-up points plus the bonus opportunity. Exact penalty rules vary by CEP year."},
    {q:"A patient has a resting SpO2 of 88% on room air, FEV1/FVC of 0.58, FEV1 of 38% predicted, and pursed-lip breathing. Using GOLD staging, this patient is classified as GOLD:",opts:["GOLD I (mild — FEV1 ≥80% predicted)","GOLD II (moderate — FEV1 50–79%)","GOLD III (severe — FEV1 30–49%)","GOLD IV (very severe — FEV1 <30%)"],correct:2,explain:"GOLD staging for COPD (after confirming FEV1/FVC <0.70 post-bronchodilator): GOLD I: FEV1 ≥80%. GOLD II: FEV1 50–79%. GOLD III: FEV1 30–49% — this patient at 38% is GOLD III (severe). GOLD IV: FEV1 <30%. SpO2 88% indicates hypoxemia requiring supplemental oxygen."},
    {q:"The Bradford Hill criterion of 'biological gradient' is present in smoking and lung cancer. Which finding BEST demonstrates this criterion?",opts:["Lung cancer is more common in men than women","Removing smoking causes cancer risk to return to baseline immediately","The risk of lung cancer increases proportionally with the number of cigarettes smoked per day — dose-response relationship","Multiple studies in different countries all find the same association"],correct:2,explain:"Biological gradient (dose-response) means that more exposure leads to more effect proportionally. The more cigarettes smoked, the higher the lung cancer risk — a clear dose-response relationship. Consistency (option D) is a separate criterion. The other options describe specificity, temporality, or other criteria."},
    {q:"A pharmaceutical company claims its new diabetes drug reduces cardiovascular events by 50% (relative risk reduction). The absolute event rates are 2% in the control group and 1% in the treatment group. What is the NNT?",opts:["2","50","100","10"],correct:2,explain:"Absolute risk reduction = 2% − 1% = 1%. NNT = 1 ÷ ARR = 1 ÷ 0.01 = 100. So 100 patients must be treated to prevent one cardiovascular event. While the 50% relative risk reduction sounds dramatic, the NNT of 100 provides clinical context — especially when weighing cost and side effects."},
    {q:"A HOSA Bowl competitor is asked about the mechanism of mRNA vaccines. Which explanation is most accurate?",opts:["mRNA is injected into the nucleus and permanently alters the patient's DNA","mRNA delivers instructions for ribosomes to produce a viral spike protein, triggering an immune response — mRNA degrades within days","mRNA vaccines contain live virus that causes mild infection to build immunity","mRNA replaces damaged DNA in cells to prevent immune overreaction"],correct:1,explain:"mRNA vaccines (Moderna, Pfizer-BioNTech COVID-19 vaccines) deliver single-stranded mRNA encoding the SARS-CoV-2 spike protein. Ribosomes translate the mRNA into spike protein, which the immune system recognizes and generates antibodies against. The mRNA never enters the nucleus and degrades within 1–2 days. It cannot alter DNA."},
    {q:"Which combination of findings would MOST suggest Cushing's syndrome rather than metabolic syndrome alone?",opts:["Hypertension, high triglycerides, abdominal obesity, and fasting glucose of 110 mg/dL","Central obesity, purple striae, proximal muscle weakness, moon facies, and buffalo hump — with suppressed ACTH","Fatigue, weight gain, cold intolerance, and bradycardia","Bilateral proptosis, weight loss, heat intolerance, and elevated free T4"],correct:1,explain:"Classic Cushing's syndrome features: central obesity with thin limbs, wide purple striae (>1 cm), proximal myopathy, moon facies, buffalo hump, hypertension, hyperglycemia, and easy bruising. Suppressed ACTH (undetectable) indicates adrenal adenoma. Elevated ACTH indicates pituitary (Cushing's disease) or ectopic source. Metabolic syndrome lacks the skin and muscle findings."},
    {q:"A community with high rates of childhood asthma is located near a highway. A public health researcher wants to determine if air pollution causes asthma in this population. Using Bradford Hill criteria, which evidence would MOST strengthen the causal argument beyond just association?",opts:["A survey showing residents believe air pollution causes their asthma","The association is statistically significant (p<0.05) in a cross-sectional study","A dose-response relationship where children closer to the highway have higher asthma rates AND a natural experiment showing asthma rates fell when a bypass reduced traffic — demonstrating temporality and experiment criteria","Two studies in different cities show similar results"],correct:2,explain:"Demonstrating (1) biological gradient: proximity to highway correlates with higher rates (dose-response) AND (2) experiment: a natural intervention (traffic reduction) reduced asthma rates satisfying temporality addresses multiple Bradford Hill criteria simultaneously. Statistical significance alone is insufficient for causation. Consistency (multiple studies) is only one criterion. Resident belief has no epidemiological weight."},
    {q:"In the context of HOSA Bowl current events, a 2024 WHO report declares antimicrobial resistance (AMR) a top global health threat. Which statement about AMR is MOST accurate for a HOSA Bowl competitor to know?",opts:["AMR only develops when patients do not finish antibiotic courses","AMR is projected to cause 10 million deaths annually by 2050 — exceeding cancer — driven by overuse in humans, agriculture, and inadequate infection prevention","AMR is a problem only in developing countries with poor sanitation","AMR is completely preventable through vaccination alone"],correct:1,explain:"WHO, CDC, and leading health economists project AMR will cause 10 million annual deaths by 2050 if current trends continue — potentially more than cancer. AMR is driven by: (1) antibiotic overuse in human medicine, (2) massive agricultural antibiotic use for growth promotion, (3) inadequate infection prevention, and (4) lack of new antibiotic development. It is a global One Health challenge."},
    {q:"HOSA Bowl advanced question: Mendelian randomization uses genetic variants as instrumental variables. Why does this method reduce confounding compared to observational studies?",opts:["Genetic variants are assigned randomly at conception — like randomization in an RCT — and are not influenced by lifestyle, environment, or reverse causation","Genetic variants are always associated with better health outcomes","It uses larger sample sizes than observational studies","It measures confounders more accurately than surveys"],correct:0,explain:"Mendelian randomization exploits the fact that genetic alleles are distributed randomly at conception (Mendel's laws) — they are not influenced by lifestyle, socioeconomic status, or other confounders, and they cannot be altered by the outcome (no reverse causation). This creates a 'natural randomization' similar to an RCT, allowing causal inference from observational data."},
  ]);
})();

// ── HOSA BOWL TOP-UP (+61 flash, +53 quiz) ───────────────────────────────
(function(){
  if(!window.QB_HOSA_BOWL) return;
  var fc = window.QB_HOSA_BOWL.flashcards;
  var qz = window.QB_HOSA_BOWL.quiz;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});

  fc.easy = fc.easy.concat([
    {term:"Prefix: a- / an-",def:"Without or absence of — anemia (without blood), apnea (without breathing), anesthesia (without sensation)"},
    {term:"Prefix: anti-",def:"Against — antibiotic (against bacteria), anticoagulant (against clotting), antihypertensive (against high BP)"},
    {term:"Prefix: bi-",def:"Two — bilateral (both sides), bicuspid (two cusps), bifurcation (splits into two)"},
    {term:"Prefix: endo-",def:"Within or inner — endoscopy (looking within), endocardium (inner heart lining), endocrine (secretes within)"},
    {term:"Prefix: epi-",def:"Upon or above — epidermis (upon the skin), epicardium (upon the heart), epidemic (upon the people)"},
    {term:"Prefix: hemi-",def:"Half — hemiplegia (paralysis of half the body), hemisphere (half a sphere)"},
    {term:"Prefix: inter-",def:"Between — intercostal (between ribs), interstitial (between cells), international"},
    {term:"Prefix: macro-",def:"Large — macrocyte (large cell), macrophage (large eater), macronutrient"},
    {term:"Prefix: micro-",def:"Small — microcyte (small cell), microorganism, microscope"},
    {term:"Suffix: -emia",def:"Blood condition — anemia (low blood), leukemia (cancer of blood cells), hyperglycemia (high blood sugar)"},
    {term:"Suffix: -oma",def:"Tumor or mass — carcinoma, lymphoma, hematoma (blood tumor/clot), lipoma"},
    {term:"Suffix: -pathy",def:"Disease or abnormality — cardiomyopathy, neuropathy, nephropathy"},
    {term:"Suffix: -scopy",def:"Visual examination with an instrument — endoscopy, colonoscopy, bronchoscopy"},
    {term:"Suffix: -tomy",def:"Cutting into (incision) — laparotomy (incision into abdomen), craniotomy, phlebotomy"},
    {term:"Suffix: -megaly",def:"Enlargement — cardiomegaly (enlarged heart), hepatomegaly (enlarged liver), splenomegaly"},
    {term:"Root: hepat/o",def:"Liver — hepatitis, hepatology, hepatomegaly, hepatocyte"},
    {term:"Root: nephr/o",def:"Kidney — nephrology, nephritis, nephron, nephrectomy"},
    {term:"Root: splen/o",def:"Spleen — splenomegaly, splenectomy, splenitis"},
    {term:"Root: pneum/o",def:"Lung or air — pneumonia, pneumothorax, pneumonectomy"},
    {term:"Root: vascul/o",def:"Blood vessel — cardiovascular, vasculitis, vascular"},
    {term:"Immune system: T cells vs B cells",def:"T cells: cell-mediated immunity (cytotoxic CD8+, helper CD4+). B cells: humoral immunity — produce antibodies"},
    {term:"Innate vs adaptive immunity",def:"Innate: immediate, nonspecific (neutrophils, macrophages, NK cells). Adaptive: slower, specific (T and B lymphocytes, memory cells)"},
    {term:"Vaccination mechanism",def:"Introduces antigens to stimulate adaptive immunity — produces memory B and T cells that respond rapidly upon actual infection"},
    {term:"Cancer risk factors",def:"Tobacco, obesity, UV radiation, alcohol, HPV, H. pylori, asbestos, radiation — modifiable and non-modifiable factors"},
    {term:"Five-year survival rate",def:"Percentage of patients alive 5 years after cancer diagnosis — used as a standard measure of cancer prognosis and treatment success"},
    {term:"Palliative care vs hospice",def:"Palliative: symptom management alongside curative treatment at any stage. Hospice: comfort-focused care when curative treatment is stopped (prognosis ≤6 months)"},
    {term:"POLST form",def:"Physician Orders for Life-Sustaining Treatment — a portable medical order specifying code status and treatment preferences; valid outside the hospital"},
    {term:"Interprofessional education (IPE)",def:"Students from different health professions learning together — builds teamwork, communication, and collaborative practice competencies"},
    {term:"SBAR communication tool",def:"Situation, Background, Assessment, Recommendation — standardized handoff communication tool reducing errors during patient transitions"},
    {term:"NPI (National Provider Identifier)",def:"A unique 10-digit identifier for all healthcare providers in the U.S. — required for insurance billing and health information exchange"},
    {term:"CDC immunization schedule (adult)",def:"Annual flu vaccine, Tdap once then Td every 10 years, HPV through age 26, pneumococcal at 65, shingles (Shingrix) at 50, COVID-19"},
    {term:"Outbreak vs epidemic vs pandemic",def:"Outbreak: localized increase above expected. Epidemic: widespread in a region. Pandemic: worldwide spread across multiple countries/continents"},
    {term:"Quarantine vs isolation",def:"Quarantine: restricts movement of exposed but not yet ill individuals. Isolation: separates confirmed or suspected infectious cases from others"},
    {term:"Contact tracing",def:"Identifying and notifying people who may have been exposed to an infectious disease — a cornerstone of outbreak control for TB, STIs, COVID-19"},
    {term:"Notifiable disease",def:"A disease legally required to be reported to public health authorities — includes TB, measles, salmonella, gonorrhea, Lyme disease"},
    {term:"Vital statistics",def:"Data on births, deaths, marriages, divorces — collected by state and federal agencies; used to monitor population health trends"},
    {term:"Life expectancy (U.S.)",def:"Average U.S. life expectancy is approximately 76–77 years — declined during COVID-19 pandemic; significant disparities by race and income"},
    {term:"Infant mortality rate",def:"Deaths of infants under 1 year per 1,000 live births — a key indicator of healthcare quality and social conditions; U.S. rate ~5–6/1,000"},
    {term:"Maternal mortality rate",def:"Deaths of women during pregnancy or within 42 days of delivery per 100,000 live births — U.S. rate among highest in developed nations (~23/100,000)"},
    {term:"Health equity vs health equality",def:"Equality: same resources for everyone. Equity: resources distributed based on need to achieve the same outcomes — equity is the goal in public health"},
    {term:"HOSA Bowl prep: WHO",def:"World Health Organization — monitors global disease burden, declares PHEICs (Public Health Emergencies of International Concern), sets health standards"},
  ]);

  fc.medium = fc.medium.concat([
    {term:"Ecological fallacy example",def:"Counties with more fast food restaurants have higher obesity rates — does NOT prove individuals who eat fast food become obese; group data ≠ individual causation"},
    {term:"Confounding variable",def:"A third variable associated with both the exposure and the outcome — can create false associations or mask true ones in observational studies"},
    {term:"Absolute risk vs relative risk",def:"Absolute risk: actual probability of outcome. Relative risk: ratio of risks between groups. Both needed for clinical context — RRR can be misleading without ARR"},
    {term:"Intention-to-treat vs per-protocol analysis",def:"ITT: analyze all randomized patients in assigned group — preserves randomization, conservative estimate. Per-protocol: only completers — overestimates efficacy"},
    {term:"Publication bias",def:"Studies with positive results are more likely to be published than negative ones — inflates apparent efficacy of treatments in the literature"},
    {term:"Meta-analysis vs systematic review",def:"Systematic review: comprehensive literature synthesis with defined search criteria. Meta-analysis: statistical pooling of quantitative results from multiple studies — increases statistical power"},
    {term:"Natural experiment",def:"A situation where exposure is determined by natural or policy events rather than deliberate assignment — provides causal inference without random assignment"},
    {term:"Dose-response relationship",def:"Greater exposure leads to greater effect — one of the Bradford Hill criteria; strengthens evidence of causation when present"},
    {term:"Propensity score matching",def:"Statistical method to reduce confounding in observational studies by matching participants on measured characteristics — approximates randomization"},
    {term:"GRADE evidence framework",def:"Grading of Recommendations, Assessment, Development, and Evaluations — rates quality of evidence from very low to high and strength of recommendations"},
    {term:"Number needed to screen (NNS)",def:"How many people must be screened to find one case — helps evaluate efficiency and cost-effectiveness of screening programs"},
    {term:"Lead time bias",def:"In cancer screening, earlier detection appears to improve survival time even if disease course is unchanged — makes survival statistics misleading"},
    {term:"Length bias",def:"Slow-growing tumors are detected more often by screening because they exist longer — screening programs appear to detect better-prognosis cancers"},
    {term:"Overdiagnosis in cancer screening",def:"Detection of cancers that would never have caused symptoms or death — a real harm of screening programs (e.g., prostate, thyroid cancer overdiagnosis)"},
    {term:"HOSA Bowl prep: Sepsis-3 definition",def:"Life-threatening organ dysfunction from dysregulated host response to infection — SOFA score ≥2; septic shock = sepsis + vasopressors + lactate >2 mmol/L"},
    {term:"HOSA Bowl prep: Pharmacogenomics CYP450",def:"Cytochrome P450 enzymes metabolize ~75% of drugs — genetic variants make patients poor, intermediate, normal, or ultrarapid metabolizers — affects dosing"},
    {term:"HOSA Bowl prep: CRISPR applications",def:"Sickle cell disease (BCL11A editing to restore HbF), transthyretin amyloidosis, cancer immunotherapy — first FDA-approved CRISPR therapy (Casgevy) in 2023"},
    {term:"HOSA Bowl prep: Long COVID",def:"Persistent symptoms >12 weeks after acute COVID-19 — fatigue, brain fog, dyspnea, autonomic dysfunction; affects ~10–30% of those infected; CDC active research area"},
    {term:"HOSA Bowl prep: AMR statistics",def:"WHO estimates 1.27 million direct deaths from AMR in 2019; projected 10 million/year by 2050; ESKAPE pathogens (Enterococcus, Staph aureus, Klebsiella, Acinetobacter, Pseudomonas, Enterobacter)"},
    {term:"HOSA Bowl prep: maternal mortality disparity",def:"Black women in the U.S. die in childbirth at 2.6× the rate of white women — one of the most significant racial health disparities in the United States"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"What does the prefix 'a-' or 'an-' mean?",opts:["With","Against","Without or absence of","Many"],correct:2,explain:"A-/an- means without or absence of. Examples: anemia (without blood), apnea (without breathing), anesthesia (without sensation), aphasia (without speech)."},
    {q:"What does the suffix '-oma' mean?",opts:["Inflammation","Tumor or mass","Surgical removal","Pain"],correct:1,explain:"-oma means tumor or mass. Examples: carcinoma (cancer tumor), lymphoma (lymph tissue tumor), hematoma (blood mass/clot), lipoma (fatty tumor), melanoma (pigment cell tumor)."},
    {q:"What does the prefix 'endo-' mean?",opts:["Above","Around","Within or inner","Outside"],correct:2,explain:"Endo- means within or inner. Examples: endoscopy (looking within the body), endocardium (inner lining of the heart), endocrine (secretes hormones within/into the bloodstream)."},
    {q:"What is the difference between quarantine and isolation?",opts:["They are the same thing","Quarantine restricts exposed but not yet ill people; isolation separates confirmed or infectious cases","Isolation is for healthy people; quarantine is for sick people","Both terms refer to hospital rooms only"],correct:1,explain:"Quarantine restricts movement of people who have been exposed to a disease but are not yet ill — preventing potential spread during the incubation period. Isolation separates people who ARE infected (confirmed or suspected) from others."},
    {q:"What is palliative care?",opts:["End-of-life care only, stopping all treatment","Symptom management and quality-of-life support provided alongside curative treatment at any disease stage","Emergency pain management in the ICU only","A type of physical therapy"],correct:1,explain:"Palliative care focuses on relieving symptoms, pain, and stress of serious illness — it can be provided alongside curative treatment at any stage. It is NOT the same as hospice (which is comfort care when curative treatment stops)."},
    {q:"What does the suffix '-emia' mean?",opts:["Disease","Blood condition","Surgical removal","Inflammation"],correct:1,explain:"-emia means a condition of the blood. Examples: anemia (low red blood cells), leukemia (cancer of blood cells), hyperglycemia (high blood sugar level), bacteremia (bacteria in the blood)."},
    {q:"What does the root 'hepat/o' refer to?",opts:["Heart","Liver","Kidney","Spleen"],correct:1,explain:"Hepat/o refers to the liver. Examples: hepatitis (liver inflammation), hepatology (study of the liver), hepatomegaly (enlarged liver), hepatocyte (liver cell)."},
    {q:"What does 'notifiable disease' mean?",opts:["A disease that is always fatal","A disease legally required to be reported to public health authorities","A disease covered by all insurance plans","A disease that must be posted on a patient's door"],correct:1,explain:"Notifiable diseases must be legally reported to local or state public health departments. This enables surveillance and outbreak detection. Examples: TB, measles, gonorrhea, salmonella, Lyme disease, and COVID-19 during the pandemic."},
    {q:"What does SBAR stand for in healthcare communication?",opts:["Situation, Background, Assessment, Recommendation","Safety, Barriers, Action, Results","Symptoms, Baseline, Acuity, Response","Status, Breathing, Allergy, Report"],correct:0,explain:"SBAR = Situation (what's happening now), Background (relevant history), Assessment (what you think is happening), Recommendation (what you need). It standardizes handoff communication — reducing errors during shift changes, transfers, and urgent calls."},
    {q:"What does the prefix 'micro-' mean?",opts:["Large","Small","Many","Few"],correct:1,explain:"Micro- means small. Examples: microorganism (very small living thing), microcyte (small red blood cell in iron deficiency), microscope (instrument to see small things), microbiology (study of microscopic organisms)."},
    {q:"What is the difference between an epidemic and a pandemic?",opts:["They are the same thing","An epidemic is localized to a region; a pandemic spreads across multiple countries or continents worldwide","A pandemic is less severe than an epidemic","An epidemic only affects animals; a pandemic affects humans"],correct:1,explain:"An epidemic is widespread disease in a geographic region above expected baseline. A pandemic is when an epidemic crosses multiple international borders and spreads globally. COVID-19 was declared a pandemic by the WHO in March 2020."},
    {q:"What does the suffix '-megaly' mean?",opts:["Small size","Surgical removal","Enlargement","Tumor"],correct:2,explain:"-megaly means enlargement. Examples: cardiomegaly (enlarged heart), hepatomegaly (enlarged liver), splenomegaly (enlarged spleen), acromegaly (enlargement of extremities from excess growth hormone)."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"A clinical trial reports that a new drug reduces the relative risk of heart attack by 40%. The control group has a 5% event rate. What is the NNT?",opts:["8","20","40","50"],correct:1,explain:"ARR = 5% × 0.40 = 2% absolute risk reduction. NNT = 1/ARR = 1/0.02 = 50. Wait — 5% × 40% = 2%; NNT = 1/0.02 = 50. So 50 patients must be treated to prevent one heart attack. The 40% relative reduction sounds impressive but the NNT of 50 reflects the modest absolute benefit when baseline risk is low."},
    {q:"What is publication bias and how does it affect clinical decision-making?",opts:["Journals publish only research from prestigious institutions","Studies with positive results are more likely to be published — making treatments appear more effective than they truly are in the overall evidence base","Publication bias has no effect — journals now require registration","Negative studies are published more frequently"],correct:1,explain:"Publication bias occurs because studies showing positive results are published more readily than null or negative results. This inflates the apparent efficacy of treatments in the literature. Meta-analyses can be misleading if they only include published studies. Funnel plot asymmetry can detect publication bias."},
    {q:"Overdiagnosis in cancer screening means:",opts:["A laboratory error in the diagnostic test","Detection of cancers that would never have caused symptoms or death — patients receive treatment with risk but no potential benefit","Missing cancers that could have been treated","Diagnosing cancer in the wrong organ"],correct:1,explain:"Overdiagnosis is a real and serious harm of cancer screening. Some detected cancers (particularly prostate, thyroid, and some breast cancers) are so slow-growing that the patient would die of another cause before the cancer became symptomatic. These patients undergo unnecessary treatment with real side effects and no benefit."},
    {q:"The GRADE framework classifies evidence quality from 'very low' to 'high.' Which study design starts at the highest quality level?",opts:["Case-control studies","Cohort studies","Randomized controlled trials","Expert opinion"],correct:2,explain:"In GRADE, RCTs start at HIGH quality evidence, while observational studies start at LOW quality. Evidence can be downgraded (risk of bias, inconsistency, indirectness, imprecision, publication bias) or upgraded (large effect size, dose-response, confounding). This is why 'hierarchy of evidence' places RCTs at the top."},
    {q:"A HOSA Bowl question about 'lead time bias' would most likely appear in which topic domain?",opts:["HOSA history and bylaws","Medical terminology","Health science — epidemiology and cancer screening","Current health events only"],correct:2,explain:"Lead time bias is an epidemiological concept relevant to cancer screening: earlier detection via screening appears to extend survival time even if the disease course is unchanged — because the 'clock starts earlier.' This is a health science domain topic in HOSA Bowl, specifically within epidemiology and research methodology."},
    {q:"Which of the following BEST describes why maternal mortality rates in the U.S. are significantly higher for Black women than white women?",opts:["Black women have higher rates of all chronic diseases","Research shows that systemic factors — including implicit bias in clinical care, socioeconomic barriers, and differential treatment quality — contribute to a 2.6× higher mortality rate for Black women","The disparity is fully explained by income differences alone","Maternal mortality statistics are inaccurate and the disparity does not actually exist"],correct:1,explain:"The Black-white maternal mortality disparity is one of the most significant U.S. racial health disparities. Multiple factors contribute: implicit bias affecting clinical recognition of warning signs, socioeconomic barriers to prenatal care, lower quality hospitals serving Black communities, and chronic stress from structural racism. This is a key HOSA Bowl current health issues topic."},
    {q:"A HOSA Bowl competitor is asked: 'What does the GRADE framework rate as its highest quality of evidence?' The correct answer is:",opts:["Expert opinion from specialty societies","Evidence from a single well-designed cohort study","Evidence from randomized controlled trials without serious flaws","Evidence from case series with large sample sizes"],correct:2,explain:"GRADE rates RCT evidence as HIGH quality — the starting point before any downgrading factors are applied. All observational study designs start at LOW quality. GRADE evaluates five factors that can downgrade (risk of bias, inconsistency, indirectness, imprecision, publication bias) and three that can upgrade observational evidence."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"A HOSA Bowl advanced question: BRCA1 mutation carriers have approximately 70% lifetime risk of breast cancer. Using the concept of absolute vs relative risk, which statement BEST explains this to a patient?",opts:["Your risk is 70 times higher than average — you are almost certain to develop cancer","Compared to the general population lifetime risk of ~12%, your risk of ~70% represents a ~5.8-fold relative increase — but 30% of BRCA1 carriers never develop breast cancer","You will definitely develop breast cancer — 70% certainty is a guarantee","This only applies to women who have already been diagnosed with cancer"],correct:1,explain:"BRCA1 lifetime breast cancer risk ~70% vs population risk ~12%: Relative risk = 70/12 ≈ 5.8-fold. Absolute risk = 70%. But 30% of carriers never develop breast cancer. This illustrates that high relative risk + high absolute risk still means some individuals are unaffected. Clinical communication should present both absolute risk and acknowledge that genetic risk is probabilistic, not deterministic."},
    {q:"In Mendelian randomization studying whether elevated LDL causes heart disease, a genetic variant in the PCSK9 gene (which naturally lowers LDL) is used as the instrumental variable. Why does this strengthen causal inference?",opts:["PCSK9 variants are more common in people who exercise — controlling for exercise","PCSK9 variants lower LDL through a mechanism unrelated to lifestyle or confounders — people with the LDL-lowering PCSK9 variant who have lower lifetime LDL also have proportionally lower cardiovascular events, supporting causation","The PCSK9 study used randomization for drug assignment","PCSK9 is directly linked to cardiovascular outcomes independent of LDL"],correct:1,explain:"PCSK9 loss-of-function variants randomly inherited at conception naturally lower LDL cholesterol — independent of diet, exercise, or other lifestyle factors. People with these variants (lower LDL) have proportionally lower cardiovascular event rates. This 'natural experiment' satisfies Mendelian randomization's assumptions: the variant is associated with the exposure (LDL), affects the outcome only through that exposure, and is not associated with confounders. It was a key precursor to developing PCSK9 inhibitor drugs."},
    {q:"A HOSA Bowl team is asked about the 2023 FDA approval of Casgevy (exa-cel). Which statement BEST describes this landmark event?",opts:["It was the first mRNA vaccine approved for a non-COVID disease","It was the first CRISPR-based gene therapy approved by the FDA — treating sickle cell disease by editing BCL11A to restore fetal hemoglobin production","It was the first CAR-T therapy approved for solid tumors","It was the first time a monoclonal antibody was approved for Alzheimer's disease"],correct:1,explain:"Casgevy (exagamglogene autotemcel, Vertex/CRISPR Therapeutics) received FDA approval in December 2023 — the first CRISPR-based gene editing therapy ever approved. It edits the BCL11A gene in patients' own stem cells, reactivating fetal hemoglobin (HbF) production. HbF doesn't sickle, preventing vaso-occlusive crises. A landmark in precision medicine and genetic disease treatment."},
  ]);
})();

