// ── MEDICAL READING EXPANSION ──────────────────────────────────────────────
(function(){
  if(!window.QB_MEDICAL_READING) return;
  var fc = window.QB_MEDICAL_READING.flashcards;
  var qz = window.QB_MEDICAL_READING.quiz;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});

  fc.easy = fc.easy.concat([
    {term:"Gifted Hands — setting",def:"Detroit, Michigan (childhood) and Baltimore, Maryland (Johns Hopkins Hospital) — the two primary settings of Ben Carson's memoir"},
    {term:"Gifted Hands — genre",def:"Autobiography/memoir — written in first person by Ben Carson about his own life and medical career"},
    {term:"Ben Carson — medical specialty",def:"Pediatric neurosurgery — Carson became director of pediatric neurosurgery at Johns Hopkins at age 33"},
    {term:"Gifted Hands — central theme",def:"Faith, determination, and education can overcome poverty and racial barriers — Carson's story shows that circumstances do not define destiny"},
    {term:"Carson's reading habit",def:"Sonya Carson required Ben and Curtis to read two books per week and write book reports — transforming Ben from class dunce to top student"},
    {term:"Curtis Carson",def:"Ben Carson's older brother — also succeeded academically under their mother's influence; the two were very close"},
    {term:"Sonya Carson's sacrifice",def:"Worked multiple jobs as a domestic worker to support her sons; hid her own illiteracy while pushing them to read and study"},
    {term:"Johns Hopkins — significance",def:"One of the top medical centers in the U.S. — where Carson performed landmark surgeries including the first successful separation of craniopagus twins joined at the back of the head"},
    {term:"Craniopagus twins",def:"Conjoined twins joined at the skull — the rarest and most dangerous type of conjoined twins; Carson's 1987 separation of the Binder twins was the first successful case"},
    {term:"Patrick and Benjamin Binder",def:"German conjoined twins joined at the back of the head whom Carson separated in 1987 — a 22-hour surgery involving 70 medical staff"},
    {term:"THINK BIG acronym",def:"Talent, Honesty, Insight, Nice, Knowledge, Books, In-depth learning, God — Carson's philosophy of success outlined in his memoir"},
    {term:"Carson's temper incident",def:"As a teenager, Carson nearly stabbed a friend — the experience led him to pray for self-control, which he credits as a turning point in his character development"},
    {term:"Yale University — Carson context",def:"Carson attended Yale as an undergraduate on a scholarship — excelled despite initial doubts about his academic ability"},
    {term:"University of Michigan Medical School",def:"Where Ben Carson attended medical school — he nearly quit when academic struggles threatened his career"},
    {term:"Selective attention — Carson example",def:"Carson's ability to focus completely on the task at hand — a key skill in long, complex neurosurgeries"},
    {term:"Wonder — genre",def:"Middle-grade realistic fiction — written by R.J. Palacio, told from multiple first-person perspectives"},
    {term:"R.J. Palacio — pen name",def:"The pen name of Raquel Jaramillo — inspired to write Wonder after an encounter with a child with facial differences at an ice cream shop"},
    {term:"Beecher Prep — setting",def:"The fictional New York private school where Auggie Pullman begins fifth grade — the main setting of Wonder"},
    {term:"Auggie's first day of school",def:"Auggie starts fifth grade at Beecher Prep — his first experience at a regular school after being homeschooled due to medical complications"},
    {term:"The plague — Wonder",def:"A cruel game at Beecher Prep where touching Auggie supposedly gives you a disease — Julian initiates it; it eventually collapses as others befriend Auggie"},
    {term:"Henry and Miles — Wonder",def:"Julian's followers who participate in bullying Auggie — foils to Jack Will who chooses friendship over peer pressure"},
    {term:"Amos — Wonder",def:"A popular student who defends Auggie from seventh-graders at the nature retreat — represents the shift in how Auggie is perceived"},
    {term:"Eddie — Wonder antagonist",def:"A seventh-grader who attacks Auggie and Jack at the nature retreat — the external antagonist who unites Beecher Prep kids behind Auggie"},
    {term:"Nature retreat — Wonder turning point",def:"The fifth-grade camping trip where seventh-graders attack Auggie and Jack; Amos, Miles, and Henry defend them — a pivotal moment of social transformation"},
    {term:"Mr. Tushman — Wonder",def:"The principal of Beecher Prep — a compassionate administrator who carefully manages Auggie's transition into school"},
    {term:"Charlotte — Wonder",def:"One of the three 'guides' assigned to help Auggie on his first day — kind but reserved; less central than Jack or Summer"},
    {term:"Auggie's hearing aids",def:"Auggie wears hearing aids due to complications from multiple surgeries — he calls them his 'old ones' when he switches to white ones that look like earbuds"},
    {term:"The Hobbit — Wonder connection",def:"Auggie and Jack bond over their shared love of The Hobbit — fantasy literature serves as common ground that transcends differences"},
    {term:"Daisy — Wonder",def:"The Pullman family's dog — Auggie's beloved pet who dies during the school year, adding grief to his already challenging first year"},
    {term:"The Hot Zone — genre",def:"Narrative nonfiction/science thriller — Richard Preston reconstructs real events surrounding Ebola outbreaks using novelistic techniques"},
    {term:"Richard Preston — background",def:"Science journalist and author — known for immersive narrative nonfiction that makes scientific topics accessible and dramatic"},
    {term:"Marburg virus",def:"A hemorrhagic fever virus related to Ebola — the first filovirus identified; named after Marburg, Germany where workers at a vaccine lab were infected in 1967"},
    {term:"Filovirus",def:"A family of RNA viruses with distinctive filamentous shape — includes Ebola and Marburg; cause hemorrhagic fever with high mortality"},
    {term:"Sudan Ebola vs Zaire Ebola",def:"Two different Ebola species with different fatality rates — Zaire strain (95% CFR in first outbreak) is most deadly; Sudan strain is less lethal but still dangerous"},
    {term:"Reston, Virginia — Hot Zone",def:"Site of a 1989 Ebola outbreak in a primate research facility — remarkably, the Reston strain did not cause disease in humans despite infecting workers"},
    {term:"Ebola Reston (RESTV)",def:"A species of Ebola that infected monkeys at a Reston, VA facility — infectious to humans but not pathogenic; did not cause human illness"},
    {term:"Charles Monet — Hot Zone",def:"The first case followed in The Hot Zone — a Frenchman in Kenya who contracted Marburg virus and died dramatically on a plane to Nairobi"},
    {term:"Nancy Jaax — Hot Zone",def:"U.S. Army veterinary pathologist who worked with Ebola samples despite a cut in her glove — a central heroic figure in the book"},
    {term:"Jerry Jaax — Hot Zone",def:"Nancy's husband and colleague — also an Army officer involved in the Reston response; the couple's partnership is central to the narrative"},
    {term:"Peter Jahrling — Hot Zone",def:"USAMRIID virologist who accidentally sniffed a sample of what turned out to be Ebola Reston — his response demonstrates proper exposure protocol"},
    {term:"Gene Johnson — Hot Zone",def:"USAMRIID scientist who first identified the Reston monkey facility as having a filovirus — key figure in coordinating the euthanasia of all monkeys"},
    {term:"USAMRIID",def:"U.S. Army Medical Research Institute of Infectious Diseases — the military research facility in Fort Detrick, Maryland that responds to biological threats including the Reston Ebola outbreak"},
    {term:"Fort Detrick",def:"U.S. Army research facility in Frederick, Maryland — home of USAMRIID; central location in The Hot Zone's response to the Reston outbreak"},
    {term:"Biosafety level 1-4 definitions",def:"BSL-1: no special precautions. BSL-2: standard labs. BSL-3: airborne precautions, filtered air. BSL-4: full pressure suits, maximum containment for the most dangerous agents"},
    {term:"Kit Hazleton monkey house",def:"The Reston, Virginia primate import facility where Ebola Reston was discovered — all monkeys were eventually euthanized in a military operation"},
    {term:"Space suit — Hot Zone",def:"The pressurized positive-pressure suit worn in BSL-4 labs — completely isolates the researcher from all potential exposure to the agent"},
    {term:"When Breath Becomes Air — author background",def:"Paul Kalanithi — neurosurgeon completing his residency at Stanford when diagnosed with stage IV lung cancer at age 36; died in 2015 before the book was published"},
    {term:"Lucy Kalanithi",def:"Paul's wife, also a physician — wrote the epilogue of When Breath Becomes Air; became an advocate for physician mental health and end-of-life care"},
    {term:"Cady Kalanithi",def:"Paul and Lucy's daughter, born 8 months before Paul died — he held her shortly before his death; her birth is a central emotional moment in the book"},
    {term:"Stanford University — Kalanithi",def:"Where Paul Kalanithi completed his neurosurgical residency and was diagnosed with cancer — also where he wrote When Breath Becomes Air"},
    {term:"T.S. Eliot — Kalanithi connection",def:"Paul Kalanithi quotes T.S. Eliot extensively — particularly The Waste Land; literary references reflect his identity as a scholar-physician"},
    {term:"Walt Whitman — Kalanithi connection",def:"Whitman's 'When Lilacs Last in the Dooryard Bloom'd' appears in the book — Kalanithi uses Whitman to explore mortality and the transcendence of death"},
    {term:"Neurosurgery residency demands",def:"Paul describes the brutality of surgical residency — 100-hour weeks, sleep deprivation, life-and-death decisions — as both crushing and deeply meaningful"},
    {term:"Death as a companion — Kalanithi",def:"Paul writes that neurosurgeons are uniquely positioned at the boundary between life and death — his cancer gave him the perspective of both sides"},
    {term:"Meaning in medicine — Kalanithi",def:"Paul's central question: what makes life worth living? He finds his answer in relationship, work, and fatherhood — not in survival alone"},
    {term:"What makes life meaningful — Kalanithi",def:"The central philosophical question of When Breath Becomes Air — Kalanithi argues meaning must be built even in the face of death and uncertainty"},
    {term:"Chasing My Cure — setting",def:"University of Pennsylvania Medical School and hospitals — where Fajgenbaum was both a medical student and a severely ill patient"},
    {term:"Castleman Disease Collaborative Network (CDCN)",def:"The research network David Fajgenbaum founded — connects researchers, clinicians, and patients worldwide to accelerate Castleman disease research"},
    {term:"Drug repurposing",def:"Using existing approved drugs for new indications — Fajgenbaum discovered sirolimus could treat his Castleman disease by analyzing his own lab data"},
    {term:"Sirolimus (rapamycin) — Fajgenbaum",def:"An immunosuppressant drug Fajgenbaum identified as potentially treating his iMCD — he became his own research subject; it has kept him in remission"},
    {term:"ACCELERATE registry",def:"Fajgenbaum's patient registry for Castleman disease — collects natural history data to identify treatment patterns and outcomes"},
    {term:"Overcoming Medical School — Fajgenbaum",def:"David had to take a leave of absence from Penn medical school during his illness — he returned to finish his MD/MBA after achieving remission"},
    {term:"Fajgenbaum's mother's death",def:"David's mother died of brain cancer when he was a teenager — her illness shaped his decision to pursue medicine and his approach to his own diagnosis"},
    {term:"IL-6 and cytokine storms",def:"Interleukin-6 is overproduced in iMCD — drives systemic inflammation, organ failure, and the cytokine storms that nearly killed Fajgenbaum five times"},
  ]);

  fc.medium = fc.medium.concat([
    {term:"Narrative medicine — definition",def:"A medical practice that uses close reading of literature to develop empathy, improve clinical skills, and help healthcare providers understand patient perspectives"},
    {term:"Rita Charon — narrative medicine",def:"Columbia physician who founded the narrative medicine program — argued that literary close-reading trains the perspective-taking essential for good clinical care"},
    {term:"Close reading technique",def:"Careful, detailed analysis of a text — attending to word choice, structure, tone, and imagery — the core skill of narrative medicine and literary analysis"},
    {term:"First-person vs third-person narration",def:"First-person (I): immediate, subjective, limited to narrator's knowledge. Third-person: observer perspective, may be omniscient or limited"},
    {term:"Unreliable narrator",def:"A narrator whose credibility is compromised — their account may be biased, self-deceptive, or incomplete; requires reader to read critically"},
    {term:"Dramatic irony",def:"When the reader knows something the character does not — creates tension and deeper understanding of the character's situation"},
    {term:"Symbol in medical literature",def:"An object or event that represents something beyond its literal meaning — Auggie's helmet (hiding), Kalanithi's unfinished manuscript (incomplete life), Fajgenbaum's lab results (hope)"},
    {term:"Motif",def:"A recurring element, image, or theme throughout a text — Carson: darkness/light; Kalanithi: identity; Fajgenbaum: time; Wonder: seeing beyond appearances"},
    {term:"Bildungsroman",def:"A coming-of-age novel — Wonder fits this genre as Auggie grows from isolated child to confident young person over one school year"},
    {term:"Epistolary elements",def:"Written communication (letters, reports) as part of narrative — Mr. Browne's postcards and precepts in Wonder function as epistolary elements"},
    {term:"In medias res",def:"Beginning a narrative in the middle of the action — The Hot Zone opens with Monet already exhibiting symptoms, immediately creating tension"},
    {term:"Deus ex machina critique",def:"An unrealistic resolution inserted to resolve plot — avoided in strong medical memoirs which maintain authenticity even when outcomes are uncertain"},
    {term:"Subtext",def:"The underlying meaning beneath the surface text — what characters think but don't say; reading subtext is a key skill in both literature and clinical medicine"},
    {term:"Juxtaposition in medical writing",def:"Placing contrasting elements side by side — The Hot Zone juxtaposes the beautiful African landscape with the horror of hemorrhagic fever"},
    {term:"Epiphany (literary)",def:"A sudden realization or insight by a character — Carson's moment of prayer after the stabbing; Kalanithi's decision to keep working after diagnosis"},
    {term:"Catharsis",def:"Emotional release experienced by the reader — medical memoirs frequently produce catharsis by taking readers through grief, fear, and ultimate resolution"},
    {term:"Pathos",def:"An appeal to the reader's emotions — Kalanithi's description of holding his daughter Cady is one of the most powerful instances of pathos in the HOSA reading list"},
    {term:"Ethos in medical writing",def:"The credibility or authority of the author — Fajgenbaum's dual identity as both patient and physician researcher gives his account unique ethos"},
    {term:"Logos in medical writing",def:"Logic and evidence in argumentation — Fajgenbaum's use of lab data and research methodology to support his treatment decisions"},
    {term:"Structure — When Breath Becomes Air",def:"Two parts: Part 1 (before cancer — becoming a neurosurgeon), Part 2 (after diagnosis — facing mortality) + epilogue by Lucy — the structure mirrors a life interrupted"},
    {term:"Structure — The Hot Zone",def:"Four parts: Part 1 (Africa origins), Part 2 (first Ebola victims in U.S.), Part 3 (Reston outbreak), Part 4 (aftermath) — builds mounting tension like a thriller"},
    {term:"Structure — Wonder",def:"Six sections named for characters who narrate — Auggie, Via, Summer, Jack, Justin, August — each section reveals new perspective on the same events"},
    {term:"Structure — Gifted Hands",def:"Chronological autobiography from childhood through Carson's greatest surgical achievements — episodic chapters, each focusing on a key moment"},
    {term:"Structure — Chasing My Cure",def:"Alternates between Fajgenbaum's medical crisis and his scientific detective work — parallels the dual role of patient and researcher"},
    {term:"Race and medicine — historical context",def:"Medical experimentation on Black Americans (Tuskegee, Henrietta Lacks) without consent — fundamental context for understanding medical ethics and health disparities"},
    {term:"Belmont Report (1979)",def:"Federal document establishing three principles for ethical research on humans: Respect for Persons, Beneficence, Justice — direct response to Tuskegee"},
    {term:"Institutional Review Board (IRB)",def:"Committee that reviews research protocols involving human subjects — ensures compliance with ethical standards including informed consent and risk minimization"},
    {term:"Common Rule",def:"Federal regulations governing human subjects research in the U.S. — updated in 2018; based on Belmont Report principles; governs IRB oversight"},
    {term:"Tissue ownership — legal context",def:"Moore v. Regents of UC (1990): patients have no property rights over cells removed from their bodies — directly relevant to Henrietta Lacks' story"},
    {term:"Rebecca Skloot's research method",def:"Skloot spent 10 years interviewing the Lacks family, reviewing medical records, and tracing HeLa cells — combining science journalism with personal narrative"},
    {term:"Deborah Lacks",def:"Henrietta's daughter — central figure in Skloot's narrative; deeply affected by her mother's legacy; helped Skloot access the family's story"},
    {term:"Lawrence Lacks",def:"Henrietta's eldest son — one of five children; represents the family's long exclusion from the benefits of their mother's cells"},
    {term:"HeLa cell contamination",def:"HeLa cells are so robust they can contaminate and overtake other cell cultures — a major problem in research labs worldwide for decades"},
    {term:"Cell culture technology",def:"Growing cells outside the body in a laboratory — HeLa cells were the first to be successfully cultured indefinitely; revolutionized medical research"},
    {term:"Polio vaccine connection — HeLa",def:"HeLa cells were critical for developing and testing the Salk polio vaccine — one of the first and most significant applications of Henrietta Lacks' cells"},
    {term:"Johns Hopkins policy — Henrietta Lacks",def:"Johns Hopkins took cells from Henrietta Lacks without consent, but did not profit from them — the cells were given away freely; criticism focuses on lack of consent, not profit"},
    {term:"George Gey — HeLa cells",def:"The Johns Hopkins researcher who cultured Henrietta Lacks' cells — he freely shared HeLa cells with researchers worldwide without commercializing them"},
    {term:"Commercial use of HeLa cells",def:"Third parties profited enormously from HeLa cells — the Lacks family received nothing and could not afford the health insurance that might have saved lives"},
    {term:"Bioethics and consent — contemporary",def:"Modern IRB requirements demand specific informed consent for tissue use in research — a direct legacy of cases like Henrietta Lacks"},
    {term:"Ebolavirus transmission",def:"Spreads through direct contact with bodily fluids of infected persons or animals — not airborne in standard conditions; requires BSL-4 containment"},
    {term:"Incubation period — Ebola",def:"2–21 days — a person can be infected but show no symptoms during this period; critical for contact tracing and outbreak containment"},
    {term:"Hemorrhagic fever pathophysiology",def:"Viral infection causes endothelial damage — blood vessels leak, clotting is impaired, leading to both internal bleeding and clotting simultaneously"},
    {term:"DIC in Ebola",def:"Disseminated intravascular coagulation — simultaneous clotting and bleeding caused by endothelial damage in Ebola and other hemorrhagic fevers"},
    {term:"Case fatality rate — 1976 Zaire Ebola",def:"The 1976 outbreak in what is now DRC had a ~90% case fatality rate — one of the highest CFRs ever recorded for an infectious disease"},
    {term:"Containment vs eradication",def:"Ebola outbreaks are contained (stopped through isolation and contact tracing) rather than eradicated — the virus persists in animal reservoirs"},
    {term:"Zoonotic spillover",def:"When a pathogen jumps from an animal reservoir to humans — fruit bats are the suspected natural reservoir for Ebola; spillover events initiate outbreaks"},
    {term:"PPE in hemorrhagic fever response",def:"Full personal protective equipment — gown, gloves, face shield, N95 — required for all contact with Ebola patients; the Hot Zone describes the BSL-4 space suit equivalent"},
    {term:"Carson's neurosurgical legacy",def:"Beyond the Binder twins, Carson pioneered awake craniotomies, vagal nerve stimulators, and advances in managing rare pediatric brain tumors"},
    
    {term:"Treacher Collins Syndrome — medical details",def:"Autosomal dominant condition affecting craniofacial development — caused by TCOF1 gene mutation; affects cheekbones, ears, eyelids, jaw; intelligence unaffected"},
    {term:"Multiple reconstructive surgeries — Auggie",def:"By the time Auggie starts fifth grade, he has had 27 surgeries — the accumulated trauma of his medical history is central to his character"},
    {term:"Inclusion in education — Wonder themes",def:"Auggie's story raises questions about mainstreaming vs. special education, the role of school culture in bullying, and the limits of policy vs. genuine acceptance"},
    {term:"Kalanithi's identity as humanist-physician",def:"Paul Kalanithi was a literature major before medical school — he believed literature and medicine both attempt to understand what makes life meaningful"},
    {term:"Death and identity — Kalanithi",def:"When Breath Becomes Air asks how identity changes when facing death — Paul moves from being a doctor who treats dying patients to a dying patient himself"},
    {term:"Time and uncertainty — Kalanithi",def:"After diagnosis, Paul cannot know if he has months or years — this uncertainty forces him to confront what matters most without a clear timeline"},
    {term:"Fajgenbaum's Five Neardeath Experiences",def:"Fajgenbaum nearly died five times from Castleman disease flares — each return to ICU deepened his resolve to find a treatment before the disease killed him"},
    {term:"Patient advocacy and rare disease",def:"Fajgenbaum's model: patients who understand their disease scientifically can accelerate research — challenges the traditional doctor-patient separation"},
    {term:"CDCN's data sharing model",def:"The Castleman Disease Collaborative Network required all member researchers to share data immediately — a departure from competitive science that accelerated discovery"},
    {term:"mTOR pathway and cancer",def:"The mammalian target of rapamycin (mTOR) pathway controls cell growth and metabolism — overactive in some cancers and in iMCD; sirolimus (rapamycin) inhibits mTOR"},
    {term:"Drug development timeline",def:"Average drug takes 10–15 years from discovery to approval — Fajgenbaum's repurposing of sirolimus bypassed this because it was already FDA-approved for other uses"},
    {term:"Orphan drug designation",def:"FDA designation for drugs treating diseases affecting fewer than 200,000 Americans — provides incentives for pharma to develop treatments for rare diseases"},
  ]);

  fc.hard = fc.hard.concat([
    {term:"Narrative medicine's clinical application",def:"Physicians trained in narrative medicine demonstrate improved empathy scores, better history-taking, and fewer diagnostic errors — literature training has measurable clinical outcomes"},
    {term:"Epistemic injustice in medicine",def:"Philosopher Miranda Fricker's concept: patients as knowers being systematically disbelieved — particularly affects women and minorities; relevant to Henrietta Lacks' and others' experiences"},
    {term:"The gaze (Foucauldian) in medicine",def:"Michel Foucault's concept of the 'clinical gaze' — medicine's tendency to see a disease rather than a whole person; challenged by narrative medicine and patient-centered care"},
    {term:"Dual role bias — physician-patient",def:"Physician-researchers treating themselves risk cognitive bias — seeing what they hope to see; Fajgenbaum addressed this by having colleagues review his data independently"},
    {term:"Compassion fatigue vs burnout",def:"Compassion fatigue: emotional exhaustion from absorbing patients' trauma. Burnout: depersonalization and reduced efficacy from systemic overload. Kalanithi addresses both in medical training context"},
    {term:"Moral residue in surgery",def:"The psychological weight of decisions made under uncertainty — Carson describes operating knowing a child could die or be permanently disabled; this residue accumulates over a career"},
    {term:"The Immortal Life — structural analysis",def:"Skloot alternates chapters between Henrietta's story (past) and Skloot's reporting (present) — this parallel structure enacts the book's thesis that Henrietta's past and the cells' present are inseparable"},
    {term:"Rhetoric of science vs rhetoric of literature",def:"Scientific writing prioritizes precision, reproducibility, and objectivity. Literary writing prioritizes voice, emotion, and ambiguity. Medical memoirs occupy both registers simultaneously"},
    {term:"Biopower (Foucault) and medicine",def:"The state's ability to control populations through medical knowledge — relevant to forced sterilization history, COVID public health mandates, and the unequal application of medical power to Lacks"},
    {term:"The patient as text",def:"A framework in narrative medicine where the patient's body and story are 'read' like a text — physicians must interpret both symptoms and narratives to diagnose and treat"},
    {term:"Genre hybridity in medical writing",def:"Many HOSA texts blend genres: The Hot Zone is nonfiction written as thriller; Chasing My Cure is memoir-science hybrid; When Breath Becomes Air is autobiography-philosophy — genre blending serves rhetorical purposes"},
    {term:"Existentialism and medicine — Kalanithi",def:"Paul Kalanithi engages with Sartre, Camus, and Heidegger's concepts of authenticity, death-as-possibility, and meaning-making — making When Breath Becomes Air a work of applied existentialism"},
    {term:"Translational research model",def:"Bench to bedside: basic science → animal models → clinical trials → treatment. Fajgenbaum's work compressed this by identifying an existing approved drug, skipping early development phases"},
    {term:"Publication bias in rare disease research",def:"Negative results are rarely published — creating a literature that overestimates treatment success; Fajgenbaum built CDCN's registry to capture ALL outcomes including failures"},
    {term:"Structural racism and health outcomes",def:"Historical and ongoing policies limiting Black Americans' access to education, wealth, and healthcare created persistent disparities — Henrietta Lacks' story is a case study in how structural racism affects medical ethics and outcomes"},
    {term:"Pandemic preparedness and The Hot Zone",def:"Preston's 1994 book predicted many aspects of pandemic response failures — insufficient PPE stockpiles, slow government response, and the challenge of containing a novel pathogen — proven prescient by COVID-19"},
    {term:"Bioethics case analysis framework",def:"Identify the ethical issue → identify stakeholders → apply principles (autonomy, beneficence, non-maleficence, justice) → consider contextual factors → propose and justify a resolution"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"Who wrote Gifted Hands?",opts:["R.J. Palacio","Richard Preston","Ben Carson","David Fajgenbaum"],correct:2,explain:"Gifted Hands is an autobiography written by Ben Carson — the neurosurgeon who grew up in poverty in Detroit and became director of pediatric neurosurgery at Johns Hopkins. It was co-written with Cecil Murphey."},
    {q:"What medical specialty is featured in Gifted Hands?",opts:["Cardiology","Pediatric neurosurgery","Oncology","Emergency medicine"],correct:1,explain:"Ben Carson became one of the world's foremost pediatric neurosurgeons, performing landmark procedures including the first successful separation of craniopagus (head-joined) conjoined twins."},
    {q:"What condition does Auggie Pullman have in Wonder?",opts:["Cerebral palsy","Treacher Collins Syndrome","Neurofibromatosis","Marfan Syndrome"],correct:1,explain:"Auggie has Treacher Collins Syndrome — a genetic condition affecting craniofacial development that causes differences in the cheekbones, ears, eyelids, and jaw. His intelligence and personality are completely unaffected."},
    {q:"Who wrote The Hot Zone?",opts:["Michael Crichton","David Quammen","Richard Preston","Carl Sagan"],correct:2,explain:"Richard Preston wrote The Hot Zone (1994), a narrative nonfiction account of Ebola outbreaks — including the 1976 outbreak in what is now the DRC and the 1989 Reston, Virginia primate facility outbreak."},
    {q:"What disease is the focus of The Hot Zone?",opts:["AIDS","Smallpox","Ebola (and Marburg) hemorrhagic fever","Bubonic plague"],correct:2,explain:"The Hot Zone centers on Ebola virus disease and the related Marburg virus — both filoviruses causing hemorrhagic fever with extremely high case fatality rates in early outbreaks."},
    {q:"What was Paul Kalanithi's profession before he was diagnosed with cancer?",opts:["Cardiologist","Neurosurgery resident at Stanford","Oncologist","Emergency physician"],correct:1,explain:"Paul Kalanithi was completing his neurosurgical residency at Stanford University when he was diagnosed with stage IV lung cancer at age 36. He died before When Breath Becomes Air was published."},
    {q:"What disease does David Fajgenbaum have in Chasing My Cure?",opts:["Leukemia","Lupus","Idiopathic multicentric Castleman disease (iMCD)","Multiple sclerosis"],correct:2,explain:"David Fajgenbaum was diagnosed with idiopathic multicentric Castleman disease (iMCD) — an extremely rare and life-threatening lymph node disorder that nearly killed him five times."},
    {q:"What is the theme of Wonder summarized by the phrase 'Choose Kind'?",opts:["Students should always obey teachers","Being kind to others, especially those who are different, is a choice that transforms school culture","Kindness means never disagreeing with anyone","Only adults need to practice kindness"],correct:1,explain:"'Choose Kind' is the central moral message of Wonder — that kindness is an active choice, not a passive feeling. Mr. Browne's precepts throughout the book build this theme."},
    {q:"Sonya Carson required her sons to do what activity that changed Ben's academic trajectory?",opts:["Memorize scripture daily","Join a sports team","Read two library books per week and write reports","Attend tutoring sessions"],correct:2,explain:"Sonya Carson, a domestic worker who worked multiple jobs, required Ben and Curtis to read two books per week and submit written reports to her — even though she herself could not read. This transformed Ben from a failing student to top of his class."},
    {q:"What does BSL-4 stand for, and what does it mean?",opts:["Biological Safety Level 4 — the lowest level of containment","Biosafety Level 4 — maximum containment for the most dangerous pathogens, requiring full pressure suits","Blood Safety Level 4 — for patients with severe infections","Bioterrorism Security Level 4 — highest government alert"],correct:1,explain:"BSL-4 (Biosafety Level 4) is the highest containment level — required for agents like Ebola that pose extreme risk and have no treatment or vaccine. Researchers wear pressurized space-suit-like garments with external air supply."},
    {q:"Where did the 1989 U.S. Ebola outbreak occur that is featured in The Hot Zone?",opts:["Atlanta, Georgia","New York City","Reston, Virginia","Houston, Texas"],correct:2,explain:"Ebola Reston was discovered at the Hazelton Research Products primate import facility in Reston, Virginia in 1989. Remarkably, although workers were infected, the Reston strain of Ebola did not cause disease in humans."},
    {q:"Who is the narrator of most of Wonder?",opts:["Via Pullman","Jack Will","Summer Dawson","August 'Auggie' Pullman"],correct:3,explain:"Most of Wonder is narrated in first person by August 'Auggie' Pullman. However, the novel uniquely includes sections narrated by other characters — Via, Summer, Jack, and Justin — giving multiple perspectives on Auggie's story."},
    {q:"What drug did David Fajgenbaum identify as a potential treatment for his own disease?",opts:["Methotrexate","Siltuximab","Sirolimus (rapamycin)","Prednisone"],correct:2,explain:"Fajgenbaum identified sirolimus (rapamycin) — an mTOR inhibitor already approved as an immunosuppressant — by analyzing his own lab data and noticing his mTOR pathway was overactivated. He has been in remission on sirolimus since 2014."},
    {q:"What surgical procedure did Ben Carson pioneer as a treatment for severe epilepsy?",opts:["Deep brain stimulation","Vagotomy","Hemispherectomy — removing one brain hemisphere","Corpus callosotomy only"],correct:2,explain:"Carson pioneered hemispherectomy for severe epilepsy — surgical removal of one brain hemisphere — achieving results that allowed previously seized, non-functional children to develop normal or near-normal function as the remaining hemisphere took over."},
    {q:"What is narrative medicine?",opts:["Writing prescriptions in story form","A medical practice using close reading of literature to develop empathy and improve clinical skills","Fiction writing taught in medical schools for entertainment","A type of therapy using storytelling to treat patients"],correct:1,explain:"Narrative medicine, developed by Dr. Rita Charon at Columbia, uses close reading of literature and reflective writing to help healthcare providers understand patients' experiences, develop empathy, and improve clinical reasoning."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"Why does The Hot Zone open with Charles Monet's illness rather than starting with the discovery of Ebola in a lab? What literary technique does this represent?",opts:["Preston lacked access to lab records","In medias res — starting in the middle of dramatic action immediately creates tension and draws the reader into the horror of hemorrhagic fever before scientific context is provided","This is a chronological error corrected in later editions","The lab discovery was classified and could not be published"],correct:1,explain:"Preston uses in medias res — beginning in the middle of a dramatic situation. Opening with Monet's symptoms creates immediate visceral horror before the scientific and historical context is established. This thriller technique serves the narrative nonfiction genre's goal of making science emotionally compelling."},
    {q:"Wonder uses six different first-person narrators. What does this structural choice reveal about the book's central theme?",opts:["R.J. Palacio could not decide on a main character","The multiple perspectives demonstrate that everyone has an invisible story — the theme of 'seeing beyond appearances' applies to all characters, not just Auggie","This structure mirrors medical charts with multiple reporters","Wonder was originally six separate short stories combined"],correct:1,explain:"The six-narrator structure enacts Wonder's core theme: everyone carries an invisible story. Via's grief over losing her place in the family, Jack's conflict between friendship and peer pressure, Summer's choice of kindness over popularity — each perspective adds depth and shows that 'choosing kind' requires understanding others' hidden struggles."},
    {q:"In When Breath Becomes Air, Paul Kalanithi writes that he was 'a man who knew what made life meaningful and was now living it.' How does his cancer diagnosis complicate this sense of certainty?",opts:["The diagnosis confirmed his meaning was in surgery, which he continued","His diagnosis removes all previous meaning — he must start over","The diagnosis forces him to ask whether the meaning he built as a physician (serving dying patients) can sustain him when he himself is dying — shifting him from the role of guide to the one who needs guidance","He abandons the question of meaning and focuses only on surviving"],correct:2,explain:"Kalanithi's crisis is not just medical but existential — he had built his identity around being the physician who helps others confront death. When he becomes the dying patient, his previous framework is disrupted. Part 2 of the book is his attempt to reconstruct meaning without a guaranteed future, culminating in his decision to have a child despite his prognosis."},
    {q:"The Lacks family did not benefit financially from HeLa cells while corporations profited enormously. Which bioethical principle does this situation MOST violate?",opts:["Autonomy — Henrietta's cells were used without her consent","Non-maleficence — the cells harmed Henrietta directly","Justice — the benefits and burdens of research were not distributed equitably","Beneficence — no one benefited from the cells"],correct:2,explain:"While autonomy (consent) was also violated, the ongoing injustice of the Lacks family receiving none of the enormous commercial value generated from Henrietta's cells most clearly violates the principle of justice — the fair distribution of research benefits and burdens. The Lacks family could not afford health insurance while HeLa cells generated billions in commercial value."},
    {q:"How does David Fajgenbaum's position as both physician-researcher and patient create unique advantages AND ethical challenges?",opts:["It creates no advantages — he was too sick to think clearly","Advantage: deep understanding of the disease and access to research; Challenge: cognitive bias (seeing what he hopes to see) and the risk of violating norms about self-experimentation","Only the ethical challenges matter — physician self-treatment is always inappropriate","Advantage: he could skip IRB approval; Challenge: he had to pay for his own drugs"],correct:1,explain:"Fajgenbaum's dual role gave him unparalleled insight into his disease and unusual determination — most researchers lack the existential urgency of a patient. But self-experimentation risks confirmation bias (overinterpreting positive results), and his desperation could compromise scientific rigor. He addressed this by building CDCN to involve independent researchers who reviewed his data objectively."},
    {q:"The Hot Zone's portrayal of Ebola at BSL-4 labs has been criticized for prioritizing drama over accuracy. What is the most legitimate scientific critique of Preston's work?",opts:["Ebola cannot actually infect humans","The scientists portrayed did not exist","Preston exaggerates the manner of Ebola's physical destruction of the body and the risk of airborne transmission, creating fear disproportionate to actual epidemiological risk — while the BSL-4 procedures are accurate","Preston invented the Reston outbreak — it never happened"],correct:2,explain:"Scientists have critiqued The Hot Zone for overstating hemorrhagic effects (making it sound more visually horrific than typical cases) and for language that implies Ebola might become airborne — a claim that had no scientific support. The Reston outbreak and the BSL-4 containment procedures are accurately portrayed. The book's value is raising public awareness of emerging pathogens; its risk is inducing disproportionate fear."},
    {q:"Ben Carson's story in Gifted Hands is often cited as an example of 'grit' and resilience. Which nuance is MOST important for a health professional to understand about this narrative?",opts:["Carson's story proves that any individual can overcome systemic barriers through hard work alone","Carson benefited from specific structural supports — a mother with unusual determination, Detroit's public libraries, scholarship access to Yale, and mentors at Hopkins — making his success a product of both individual resilience and systemic opportunity","Carson's story only applies to African Americans facing racial barriers","The lesson is only about religious faith, not systemic factors"],correct:1,explain:"A critical reading of Gifted Hands recognizes that while Carson's individual determination was extraordinary, it operated within specific enabling conditions: Sonya Carson's unusual strategy of mandated reading, Detroit's robust public library system, affirmative action programs that opened Yale to him, and mentors at Hopkins who recognized his talent. Health disparities research shows individual resilience cannot compensate for systematic resource deprivation — Carson's story illustrates both individual agency AND the power of structural opportunity."},
    {q:"In what way does Paul Kalanithi's use of T.S. Eliot and Walt Whitman throughout When Breath Becomes Air function beyond mere literary decoration?",opts:["The poetry makes the book more commercially appealing","Kalanithi uses literary allusion to locate his personal experience within a larger tradition of human reckoning with mortality — poetry becomes a framework for meaning-making that medicine alone cannot provide","He references these poets only because they were on his medical school reading list","The allusions are ironic — he ultimately rejects literature in favor of science"],correct:1,explain:"Kalanithi was a literature major before medicine. His use of Eliot and Whitman is not decorative but functional — these poets had grappled with fragmentation (Eliot) and death's transcendence (Whitman) in ways that gave Kalanithi a vocabulary for his own experience. The book argues implicitly that humanities education is not separate from medicine but essential to it — providing frameworks for meaning when science offers only prognosis."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"The Immortal Life of Henrietta Lacks and Chasing My Cure both examine the relationship between individual patients and the medical research enterprise. What is the key structural difference in how each book positions the patient?",opts:["Both position patients as victims of medical exploitation","Lacks was an unknowing subject whose cells were taken without consent and used without compensation — she had no agency in her relationship with research. Fajgenbaum actively became a researcher-patient who gained agency over his own treatment — representing a transformation in the patient's role enabled by patient advocacy and open science movements","Both books argue that patients should control all research","The books are set in different eras with no meaningful comparison"],correct:1,explain:"This contrast represents a historical shift: Lacks (1950s) represents the era of paternalistic medicine where patients were passive subjects — especially Black patients who had even less power over their medical encounters. Fajgenbaum (2010s) represents the emerging patient-researcher model enabled by digital information access, patient advocacy networks, and changing norms around open science. The juxtaposition illuminates how patient power in research has evolved."},
    {q:"From a narrative medicine perspective, what does close reading of The Hot Zone reveal about how fear is rhetorically constructed in science writing, and why does this matter clinically?",opts:["Fear has no place in science writing","Preston constructs fear through visceral physical description, direct address, near-miss personal danger scenes, and the withholding of scientific context — techniques that engage emotion before reason. Clinically, understanding fear construction helps providers recognize how media-induced fear shapes patient behavior and health decisions","The Hot Zone is too inaccurate to use in clinical education","Fear construction is only relevant in fiction, not nonfiction"],correct:1,explain:"Preston's rhetorical arsenal includes: second-person address ('you are in a hot zone'), graphic physical descriptions that bypass analytical defenses, near-miss scenes with scientists the reader has come to identify with, and strategic omission of reassuring epidemiological context (e.g., that Ebola is difficult to transmit). Understanding these techniques helps clinicians recognize why patients may have fear responses to disease outbreaks that are disproportionate to actual risk — and how to address fear-based health behaviors with empathy and evidence."},
    {q:"Paul Kalanithi argues in When Breath Becomes Air that the question 'What makes life meaningful?' cannot be answered by medicine alone. What is the philosophical basis for this claim, and what implications does it have for medical education?",opts:["Medicine can answer all questions about human life through biology","Kalanithi draws on existentialist philosophy — particularly Heidegger's concept of 'being-toward-death' — to argue that confronting mortality requires frameworks (literary, philosophical, spiritual) that biomedicine lacks; medical education that excludes humanities training produces physicians who cannot help patients find meaning in illness and dying","Meaning is subjective and irrelevant to clinical practice","Medical science has already answered questions of meaning through neuroscience"],correct:1,explain:"Kalanithi's argument is explicitly philosophical: drawing on Heidegger, he argues that death is not a medical failure but an ontological certainty that defines human existence. Medicine provides prognostic information but cannot tell a patient what their remaining time means or how to live it. This is the function of what he calls 'literature, philosophy, and the humanities.' His book implicitly argues for integrating humanities into medical education — the framework of narrative medicine — because patients need physicians who can be present with them in meaninglessness, not just treat their biology."},
    {q:"Using Bradford Hill criteria and the HOSA Medical Reading texts, construct an argument for why the scientific relationship between IL-6 overproduction and iMCD is more persuasive than the relationship between 'heredity' and Treacher Collins Syndrome depicted in Wonder, even though both are biological causation claims.",opts:["Both claims have equal scientific validity","The IL-6/iMCD relationship is supported by multiple Bradford Hill criteria: biological plausibility (IL-6 drives the inflammatory cascade), biological gradient (higher IL-6 correlates with disease severity), experiment (siltuximab blocking IL-6 treats iMCD), and consistency across patients. Wonder's presentation of TCS as simply 'inherited' lacks the mechanistic depth — while accurate (TCOF1 mutation is causal), the book doesn't demonstrate the Bradford Hill criteria chain because it's a novel, not a scientific text","Wonder is more scientifically accurate because it's more widely read","Causation claims in medical memoirs are always more valid than in fiction"],correct:1,explain:"This question tests the ability to apply epidemiological reasoning to literary claims. The IL-6/iMCD claim in Chasing My Cure is supported by Fajgenbaum's mechanistic evidence: IL-6 drives cytokine storms (biological plausibility), higher IL-6 = worse disease (gradient), siltuximab blocks IL-6 and treats iMCD (natural experiment). Wonder's TCS claim is factually accurate but presented without mechanistic depth — it asserts inheritance without demonstrating the Bradford Hill criteria chain. This reflects the different rhetorical goals of the two texts: Fajgenbaum must persuade a scientific audience; Palacio must create empathy, not scientific literacy."},
  ]);
})();

// ── MEDICAL READING TOP-UP (+99 flash, +76 quiz) ──────────────────────────
(function(){
  if(!window.QB_MEDICAL_READING) return;
  var fc = window.QB_MEDICAL_READING.flashcards;
  var qz = window.QB_MEDICAL_READING.quiz;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});

  fc.easy = fc.easy.concat([
    {term:"Prologue",def:"An introductory section before the main text — Gifted Hands begins with Carson in the OR; When Breath Becomes Air opens with Paul discovering his cancer"},
    {term:"Epilogue",def:"A concluding section after the main text — When Breath Becomes Air's epilogue is written by Lucy Kalanithi; it provides closure after Paul's death"},
    {term:"Memoir vs autobiography",def:"Memoir: focuses on a specific period or theme of the author's life. Autobiography: covers the full life story. Carson's Gifted Hands and Kalanithi's When Breath Becomes Air are memoirs"},
    {term:"Protagonist",def:"The main character of a story — Auggie Pullman in Wonder; Ben Carson in Gifted Hands; Paul Kalanithi in When Breath Becomes Air; David Fajgenbaum in Chasing My Cure"},
    {term:"Antagonist",def:"The character or force opposing the protagonist — Julian in Wonder; racism and poverty in Gifted Hands; cancer in When Breath Becomes Air; Castleman disease in Chasing My Cure"},
    {term:"Setting in medical literature",def:"Time and place of the narrative — setting affects character experience, access to care, and cultural context for medical decisions"},
    {term:"Conflict types",def:"Person vs person (Julian vs Auggie), Person vs self (Kalanithi's identity crisis), Person vs nature (Ebola), Person vs society (Lacks and racial injustice)"},
    {term:"Rising action",def:"Events building toward the climax — in Wonder, Auggie's gradual integration into school life; in Chasing My Cure, each near-death experience leading to the sirolimus discovery"},
    {term:"Climax",def:"The turning point of maximum tension — Carson's Binder twin surgery; Kalanithi completing his manuscript; Fajgenbaum beginning sirolimus and going into remission"},
    {term:"Resolution / denouement",def:"How the story is resolved after the climax — Auggie winning the medal; Kalanithi's posthumous publication; Fajgenbaum founding CDCN"},
    {term:"Flashback",def:"A scene set earlier than the current narrative timeline — Carson's childhood flashbacks; Skloot's reconstruction of Henrietta's life in 1950s Baltimore"},
    {term:"Dialogue in memoirs",def:"Reconstructed conversations in memoir are necessarily approximate — authors note they reflect the substance of exchanges rather than verbatim records"},
    {term:"Scene vs summary",def:"Scene: detailed dramatic moment (showing). Summary: compressed narration of events (telling). Strong memoirs balance both — Kalanithi excels at both"},
    {term:"Voice",def:"The distinctive personality of the narrator as expressed through word choice and style — Carson's confident, direct voice vs Kalanithi's literary, reflective voice"},
    {term:"Diction",def:"The author's word choice — Preston uses clinical, visceral diction in The Hot Zone; Palacio uses age-appropriate accessible language in Wonder"},
    {term:"Syntax",def:"Sentence structure — Kalanithi uses complex, layered sentences reflecting philosophical depth; Wonder uses simple direct sentences reflecting Auggie's child voice"},
    {term:"Imagery",def:"Language that appeals to the senses — Preston's physical descriptions of hemorrhagic fever symptoms; Kalanithi's descriptions of the OR and hospital at night"},
    {term:"Metaphor in medical writing",def:"Comparing unlike things without 'like' or 'as' — Kalanithi: 'Time is the coin of life'; Fajgenbaum: his lab as 'a battlefield for his own body'"},
    {term:"Simile",def:"Comparison using 'like' or 'as' — Preston describes Ebola spreading 'like fire through a paper house'"},
    {term:"Personification",def:"Giving human qualities to non-human things — Fajgenbaum describes the Castleman disease cells 'hunting' him; Preston describes the virus 'looking for a way out'"},
    {term:"Hyperbole",def:"Exaggeration for effect — The Hot Zone is sometimes criticized for hyperbolic descriptions of Ebola's physical effects"},
    {term:"Understatement",def:"Saying less than is meant for effect — Kalanithi's understatement about his prognosis ('months to years') carries more weight than any dramatic declaration"},
    {term:"Deus ex machina",def:"An unlikely or contrived resolution — Fajgenbaum's story avoids this by acknowledging that sirolimus works for him but may not work for all iMCD patients"},
    {term:"Cliffhanger",def:"Ending a chapter at a moment of tension to keep the reader engaged — Preston uses this repeatedly between scenes in The Hot Zone"},
    {term:"Suspense in The Hot Zone",def:"Maintained through near-misses (Jahrling sniffing Ebola), countdown elements (how long before the virus escapes Reston), and the reader knowing the danger before the characters do"},
    {term:"Wonder — Henry and Miles redemption",def:"Henry and Miles, Julian's former followers, eventually defend Auggie at the nature retreat — showing that peer pressure can be overcome and people can change"},
    {term:"Auggie's medal — Wonder",def:"Auggie receives the Henry Ward Beecher medal at graduation — a school award, symbolizing full acceptance and recognition by his community"},
    {term:"Treacher Collins — inheritance pattern",def:"Autosomal dominant — a mutation in one copy of the TCOF1 gene is sufficient to cause the syndrome; 60% of cases are new mutations, not inherited from a parent"},
    {term:"Auggie's hearing — Wonder",def:"Auggie has hearing loss from his syndrome — he switches from behind-the-ear aids to white in-ear devices that look like earbuds, making them less conspicuous"},
    {term:"Via's sacrifice — Wonder",def:"Via (Olivia) has spent years protecting and advocating for Auggie — at the cost of her own needs and visibility; her narrative reveals the hidden burden on siblings of children with disabilities"},
    {term:"Justin — Wonder",def:"Via's boyfriend, narrator of one section — an outsider who falls in love with the Pullman family; his section reveals the family dynamic from a fresh perspective"},
    {term:"Mr. Browne's precepts",def:"Monthly moral statements Mr. Browne shares with his class — each becomes a discussion point about kindness, identity, and character; Auggie's classmates submit their own at year's end"},
    {term:"Ebola — 2014 West Africa outbreak",def:"The largest Ebola outbreak in history — over 28,000 cases and 11,000 deaths; primarily in Guinea, Sierra Leone, and Liberia; required massive international response"},
    {term:"PPE in Ebola response",def:"Double gloves, gown, face shield, N95 respirator, boot covers — strict donning and doffing protocols prevent self-contamination; PPE failures caused some healthcare worker deaths"},
    {term:"Contact tracing — Ebola",def:"Identifying all individuals who had contact with an Ebola patient — monitoring them for 21 days (maximum incubation period); critical for outbreak containment"},
    {term:"Isolation vs quarantine — Ebola",def:"Isolation: separates confirmed/probable Ebola cases. Quarantine: restricts movement of exposed contacts during the 21-day incubation period"},
    {term:"Stigma in infectious disease",def:"Ebola, HIV, and COVID-19 patients all faced social stigma — affecting care-seeking, mental health, and community response; a recurring theme in public health ethics"},
    {term:"Animal reservoir — Ebola",def:"Fruit bats (Pteropus species) are the most likely natural reservoir for Ebola — the virus persists in bat populations without causing disease; human contact with bats or intermediate hosts triggers spillover"},
    {term:"Zoonotic spillover event",def:"When a pathogen jumps from an animal reservoir to humans — hunting and eating bushmeat, handling infected animals, or contact with bat habitat are known risk factors for Ebola spillover"},
    {term:"One Health approach — Ebola",def:"Preventing Ebola requires monitoring animal populations, human-wildlife interfaces, and community health simultaneously — a classic One Health challenge"},
    {term:"HeLa cells — scientific contributions",def:"Beyond polio vaccine: cancer research, AIDS research, genetics, space research (sent to study how cells behave in zero gravity), COVID-19 vaccine research"},
    {term:"Lacks family today",def:"The Lacks family still lives in poverty despite HeLa cells generating billions in commercial value — their story prompted debate about bioequity and compensation for research participants"},
    {term:"National Institutes of Health — Lacks agreement",def:"In 2013, NIH reached an agreement with the Lacks family giving them representatives on a committee that reviews requests to use HeLa genome data — a step toward recognition"},
    {term:"Biobank",def:"A collection of biological samples (tissues, blood, DNA) stored for research — Fajgenbaum built a Castleman disease biobank as part of CDCN to enable future research"},
    {term:"Patient registry",def:"A database tracking all known cases of a disease — Fajgenbaum's ACCELERATE registry collects clinical data on Castleman disease patients worldwide"},
    {term:"Open science model",def:"Sharing research data and findings publicly — CDCN required all member researchers to share data immediately rather than waiting for publication; accelerated discovery"},
    {term:"Rare disease definition",def:"A disease affecting fewer than 200,000 people in the U.S. — there are approximately 7,000 rare diseases, most without effective treatments; Castleman disease is rare"},
    {term:"Orphan Drug Act (1983)",def:"U.S. law providing incentives (tax credits, market exclusivity) for developing drugs for rare diseases affecting fewer than 200,000 Americans — directly relevant to Castleman disease treatment"},
    {term:"mTOR — function overview",def:"Mammalian target of rapamycin — a key cellular signaling protein regulating cell growth, proliferation, and metabolism; overactivated in some cancers and in iMCD"},
    {term:"Sirolimus (rapamycin) origin",def:"Discovered from a soil bacterium (Streptomyces hygroscopicus) found in Easter Island (Rapa Nui) in 1964 — originally developed as an antifungal before its immunosuppressant properties were discovered"},
    {term:"Fajgenbaum as his own case study",def:"By tracking his own biomarkers through five relapses, Fajgenbaum identified patterns (mTOR activation, specific cytokine elevations) that led to his sirolimus hypothesis"},
  ]);

  fc.medium = fc.medium.concat([
    {term:"Narrative arc in medical memoir",def:"The emotional and thematic journey of the narrator — Carson's arc: poverty→education→surgical excellence; Kalanithi's arc: ambition→wisdom→acceptance; Fajgenbaum's: illness→discovery→advocacy"},
    {term:"Crisis of identity — medical professionals",def:"When physicians become patients, their identity as healers is disrupted — Kalanithi and Fajgenbaum both navigate this dual identity; narrative medicine uses literature to prepare students for this experience"},
    {term:"Witness literature",def:"Literature that bears witness to suffering or injustice — The Immortal Life of Henrietta Lacks and When Breath Becomes Air both function as witness literature, insisting that individual stories not be lost in data"},
    {term:"Medical gaze and patient narrative",def:"The clinical tendency to see disease rather than the whole person — narrative medicine addresses this by training physicians to attend to patient stories as carefully as diagnostic data"},
    {term:"Informed consent — evolution",def:"Informed consent evolved from paternalistic medicine (doctor knows best) to patient autonomy (patient decides) following Nuremberg Code (1947), Declaration of Helsinki (1964), and Belmont Report (1979)"},
    {term:"Nuremberg Code (1947)",def:"The first international standard for ethical research involving humans — written after Nazi medical experimentation was exposed at Nuremberg trials; established voluntary consent as essential"},
    {term:"Declaration of Helsinki (1964)",def:"World Medical Association guidelines for ethical medical research — updated multiple times; emphasizes that research on human subjects must respect patient rights and minimize harm"},
    {term:"Tuskegee Syphilis Study (1932–1972)",def:"U.S. government study that withheld treatment from Black men with syphilis to observe disease progression — directly led to Belmont Report and modern informed consent requirements"},
    {term:"Community benefit requirement",def:"Modern research ethics requires that research designs benefit the communities that participate — a principle violated in Tuskegee and in early use of HeLa cells"},
    {term:"Biospecimen consent",def:"Patients must now specifically consent to how their biological samples may be used in research — a direct response to cases like Henrietta Lacks where samples were used without specific consent"},
    {term:"Genetic privacy — biobank",def:"Genomic data in biobanks can identify individuals and families — raises privacy concerns even when samples are de-identified; relevant to HeLa genome sequencing controversy"},
    {term:"Henrietta Lacks — genome sequencing controversy",def:"In 2013, researchers published the HeLa genome without consulting the family — revealing genetic information about Lacks' descendants; NIH later agreed to oversight committee including family members"},
    {term:"Science journalism vs peer review",def:"Science journalists (like Preston and Skloot) communicate science to lay audiences using narrative techniques; peer review ensures scientific accuracy but reaches only specialists"},
    {term:"Translational bottleneck",def:"Most basic science discoveries never reach clinical application — Fajgenbaum's approach addresses this by starting from patient data and working backward to mechanisms, rather than forward from bench to bedside"},
    {term:"n-of-1 trial",def:"A clinical trial in a single patient testing a treatment — Fajgenbaum's self-experimentation with sirolimus was effectively an n-of-1 trial; ethically controversial but sometimes the only option in rare diseases"},
    {term:"Compassionate use / expanded access",def:"FDA pathway allowing patients with serious conditions to access unapproved drugs outside clinical trials — relevant to Castleman disease patients who cannot wait for standard drug approval"},
    {term:"Precision oncology",def:"Cancer treatment tailored to the specific molecular profile of a tumor — using genomics to identify which mutations drive the cancer and match targeted therapies; iMCD treatment increasingly follows this model"},
    {term:"Cytokine signaling networks",def:"Complex webs of signaling proteins (cytokines) that regulate immune responses — Fajgenbaum's research maps the specific cytokine network disrupted in iMCD, identifying intervention targets"},
    {term:"Patient advocacy organizations (PAO)",def:"Organizations like CDCN that fund research, connect patients, and advocate for policy changes — increasingly recognized as essential partners in rare disease research"},
    {term:"Wonder — disability studies perspective",def:"Wonder can be read through a disability studies lens: does the book's focus on Auggie's triumph over adversity reinforce the 'supercrip' narrative (disabled person who overcomes all), or does it genuinely critique ableism?"},
    {term:"Supercrip narrative critique",def:"A disability studies concept: stories of disabled people overcoming disability to achieve 'normal' success can imply that the only valuable disabled person is one who compensates for disability — rather than challenging ableist norms"},
    {term:"Inclusion vs integration — education",def:"Integration: placing students with disabilities in general education settings. Inclusion: fully welcoming students as equal members of the community, adapting the environment to them — Wonder depicts the shift from integration to inclusion"},
    {term:"'See the person, not the disability'",def:"A disability advocacy message reflected in Wonder's theme — the book asks readers to look past physical difference to see Auggie's whole self; some disability scholars critique this framing as placing the burden on the disabled person"},
    {term:"Risk communication in public health",def:"How information about health risks is communicated to the public — The Hot Zone demonstrates how emotional, vivid communication can create disproportionate fear; effective risk communication balances accuracy with emotional resonance"},
    {term:"Media framing of disease",def:"How media coverage shapes public perception of illness — Ebola coverage post-Hot Zone created significant fear disproportionate to actual U.S. risk; COVID-19 coverage similarly created both fear and dangerous denial"},
    {term:"Comparative effectiveness research",def:"Studying which available treatments work best for specific patients — CDCN's registry enables this by collecting treatment and outcome data from all known Castleman patients"},
    {term:"Implementation science",def:"The study of how to translate research into clinical practice — a major gap in medicine; Fajgenbaum's model of building networks first, then generating evidence, exemplifies implementation science thinking"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"What is a memoir?",opts:["A comprehensive account of an author's entire life","A narrative focused on a specific period or theme of the author's life, written in first person","A biography written by someone other than the subject","A fictional story based on real events"],correct:1,explain:"A memoir focuses on a specific period or theme rather than the author's entire life. Gifted Hands focuses on Carson's path from poverty to surgical excellence. When Breath Becomes Air focuses on Kalanithi's confrontation with mortality. Both are memoirs, not full autobiographies."},
    {q:"Who is the antagonist in Wonder?",opts:["Mr. Tushman","Summer Dawson","Julian Albans","Jack Will"],correct:2,explain:"Julian Albans is the primary antagonist — he initiates 'the plague' (touching Auggie supposedly infects you), leads the bullying, and pressures other students to exclude Auggie. He is driven by fear and peer pressure, and later undergoes some reflection through the book's bonus material."},
    {q:"What is the setting of The Hot Zone's U.S. outbreak section?",opts:["Atlanta, Georgia","Houston, Texas","Reston, Virginia","Baltimore, Maryland"],correct:2,explain:"The U.S. outbreak in The Hot Zone occurs at a primate import facility in Reston, Virginia — a suburb of Washington, D.C. The Reston Ebola strain (RESTV) infected monkeys and several workers but remarkably did not cause disease in humans."},
    {q:"Who wrote the epilogue of When Breath Becomes Air, and why?",opts:["Paul's brother, because Paul couldn't finish","Lucy Kalanithi, Paul's wife, because Paul died before completing the book","Paul's editor at Random House","Paul's neurosurgery mentor"],correct:1,explain:"Lucy Kalanithi, Paul's wife (also a physician), wrote the epilogue. Paul Kalanithi died in March 2015, before the book was published in January 2016. Lucy's epilogue provides closure about Paul's final days, his daughter Cady, and the meaning Paul found in his last year."},
    {q:"What is a flashback in literature?",opts:["A chapter that predicts future events","A scene set earlier than the current narrative timeline","A character's hallucination","A rapid summary of many years"],correct:1,explain:"A flashback interrupts the current timeline to show an earlier event. Carson uses flashbacks to his Detroit childhood throughout Gifted Hands. Skloot uses flashbacks to reconstruct Henrietta Lacks' life in 1950s Baltimore alongside her present-day reporting."},
    {q:"What does 'in medias res' mean?",opts:["At the very beginning of the story","In the middle of the action — starting a narrative at a dramatic moment without background","At the end of the story","A Latin term for a plot twist"],correct:1,explain:"In medias res (Latin: 'in the middle of things') means beginning a narrative at a dramatic moment rather than at the chronological beginning. The Hot Zone opens with Charles Monet already exhibiting Marburg symptoms — immediately creating tension before any context is provided."},
    {q:"What is the Carson Scholars Fund?",opts:["A fund to pay Carson's medical school debt","A scholarship program Carson founded to reward academic achievement and community service in students","A hospital fund for children who cannot afford brain surgery","A government grant for neurosurgery research"],correct:1,explain:"The Carson Scholars Fund is a non-profit scholarship program Ben Carson and his wife Candy founded in 1994 — recognizing students who achieve high academic standards AND show humanitarian qualities. It has awarded thousands of scholarships to students who demonstrate 'gifted hands' in both academics and community service."},
    {q:"What is the theme of a story?",opts:["The main character's name","The central idea or message the author wants to communicate","The time and place of the story","The sequence of events in the plot"],correct:1,explain:"Theme is the central message or insight about human experience that the author communicates through the narrative. Wonder's themes include: choose kindness, everyone has an invisible story, appearance vs. reality. Theme differs from plot (what happens) and setting (where/when)."},
    {q:"What is foreshadowing?",opts:["A character's daydream about the future","Hints or clues in a text that suggest what will happen later","A flashback to past events","The author's opinion stated directly"],correct:1,explain:"Foreshadowing involves hints, clues, or references that signal future events. The Hot Zone uses foreshadowing extensively — early references to Ebola's extreme danger hint at the crisis to come. In Wonder, early tension between Jack and Julian foreshadows the Halloween confrontation."},
    {q:"What does 'choose kind' mean as Wonder's central message?",opts:["Always agree with others to keep the peace","Being kind is a conscious, deliberate choice that transforms school culture and relationships — not a passive feeling","Only adults are capable of choosing kindness","Kind people always finish last"],correct:1,explain:"'Choose Kind' (also the name of the anti-bullying movement inspired by Wonder) means that kindness is an active decision, not just an emotion. The book shows characters — Jack, Summer, Amos, and eventually even Henry and Miles — making deliberate choices to include and defend Auggie rather than following the crowd."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"How does Wonder's use of multiple first-person narrators create dramatic irony?",opts:["It creates confusion about who the main character is","Readers learn information from one narrator that other characters don't know — creating dramatic irony when those characters act on incomplete information","Multiple narrators eliminate dramatic irony by explaining everything","Dramatic irony only occurs in third-person narration"],correct:1,explain:"When Jack's chapter reveals his internal conflict about Auggie, readers understand his Halloween comment (which devastated Auggie) as a failure of courage under peer pressure — not cruelty. Auggie doesn't know this yet. This is dramatic irony: the reader understands something a character does not. The multi-narrator structure enables this by giving us Jack's internal world before reconciliation."},
    {q:"The Belmont Report established three principles for ethical research. How does the Henrietta Lacks case violate all three?",opts:["The Lacks case only violates one principle — autonomy","Respect for Persons violated: no consent for cell use. Beneficence violated: cells benefited science enormously while the family received no benefit. Justice violated: the burdens (cells taken without consent) fell on a poor Black woman while benefits flowed to wealthy institutions and corporations","None — informed consent rules didn't exist in 1951 so no violation occurred","Only beneficence was violated because Henrietta didn't directly benefit"],correct:1,explain:"All three Belmont principles are violated: (1) Respect for Persons/Autonomy: Henrietta did not consent to cell collection or research use — the 'consent form' she signed was for treatment, not research. (2) Beneficence: the benefit-risk calculation was never presented to her; enormous benefits flowed to others at her unknowing expense. (3) Justice: the burdens fell on a poor Black woman historically subject to medical exploitation, while benefits enriched predominantly white academic and commercial institutions."},
    {q:"What narrative technique does Chasing My Cure use to demonstrate the dual nature of Fajgenbaum's experience, and how effective is it?",opts:["Third-person omniscient narration to show both doctor and patient perspectives","Alternating timelines — cutting between his ICU crisis and his laboratory research — creates structural parallelism that enacts his thesis: the patient and the scientist are not separable","Linear chronology — the simplest and most effective structure","Stream of consciousness to capture delirium from illness"],correct:1,explain:"Fajgenbaum alternates between ICU scenes (patient experiencing crisis) and lab scenes (researcher analyzing data) — often within the same chapter. This structural choice enacts the book's central argument: that separating patient from researcher creates an artificial division that slows discovery. The most effective scenes occur when both roles collapse into one — analyzing his own blood results to figure out what is killing him."},
    {q:"Richard Preston has been criticized for overstating Ebola's physical destruction in The Hot Zone. What is the most significant consequence of this for public health literacy?",opts:["It makes the book more entertaining with no public health consequences","By making Ebola seem uniquely grotesque and visually horrific, Preston's narrative may cause readers to misunderstand that most infectious diseases that kill more people (flu, TB, malaria) are less dramatic but far more prevalent — creating a hierarchy of fear disconnected from actual disease burden","The exaggeration was corrected in later editions so it has no ongoing impact","Preston's descriptions are fully accurate — no criticism is warranted"],correct:1,explain:"Preston's visceral descriptions create what public health scholars call 'spectacular disease' — illness that is visually dramatic gets more attention and fear than statistically more dangerous diseases. Ebola kills thousands per outbreak (serious); flu kills hundreds of thousands annually globally (far more dangerous). By making Ebola uniquely horror-show-horrific, The Hot Zone may distort readers' ability to prioritize actual health risks. This is a legitimate critique of science journalism that prioritizes narrative impact over calibrated risk communication."},
    {q:"How does Paul Kalanithi's dual identity as physician-literary scholar shape When Breath Becomes Air's structure and argument?",opts:["He separates medicine and literature completely — alternating medical chapters and literary chapters","His literary background shapes the memoir's non-linear time structure, its philosophical depth, and its central argument that literature and medicine address the same fundamental questions about human meaning — but from different angles","Literature was only a hobby — his argument is purely medical","He ultimately concludes that medicine is more important than literature"],correct:1,explain:"The book's structure reflects Kalanithi's hybrid identity: Part 1 (becoming a physician) and Part 2 (becoming a dying patient) mirror the two forms of knowledge — the physician's knowledge of death in others and the experiential knowledge of one's own death. His literary allusions (Eliot, Whitman, Beckett) are not decorative — they provide frameworks for meaning-making that medicine cannot. His central argument is that excellence in medicine requires both scientific training AND humanistic depth."},
    {q:"What is the significance of Fajgenbaum founding CDCN while still a medical student recovering from near-death experiences?",opts:["It shows that medical students have too much free time","It demonstrates that patient advocacy can restructure how medical research is organized — CDCN's data-sharing requirement challenged the competitive norms of academic science","Only wealthy patients can afford to found research organizations","The CDCN was fully funded by the NIH from the start"],correct:1,explain:"CDCN's founding is significant on multiple levels: (1) A patient, not an established researcher, restructured research norms for a disease — demonstrating patient agency. (2) The data-sharing requirement challenged academic science's culture of competition and publication prioritization. (3) A medical student (with the credibility of both physician-in-training and lived patient experience) could bring researchers, clinicians, and industry together in ways neither a purely patient advocacy group nor a traditional academic consortium could."},
    {q:"In what way does Gifted Hands function as both an individual success story and a structural critique of American society?",opts:["It is only an individual success story — it does not address structural issues","Carson's narrative demonstrates both his extraordinary determination and the structural barriers that nearly prevented his success (poverty, underfunded Detroit schools, racial prejudice in medicine) — implicitly arguing that individual success does not eliminate the structural conditions that make similar journeys unnecessarily difficult for others","Carson explicitly argues that structural barriers don't matter — only individual effort","The book avoids any mention of structural issues"],correct:1,explain:"Read critically, Gifted Hands contains both messages simultaneously. Carson's individual story is inspiring. But his narrative also documents: under-resourced Detroit schools that failed most students (not just him), racial prejudice in medical school and hospital settings, the absence of Black physician role models, and the exceptional intervention of one mother compensating for structural failures. The book's power lies partly in this tension — a story of triumph that implicitly reveals how much more common triumph could be with better structural conditions."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"How does the structural choice in The Immortal Life of Henrietta Lacks (alternating chapters) both solve and create a problem for narrative journalism?",opts:["It solves all problems with no downsides","Alternating between Henrietta's 1950s story (reconstructed) and Skloot's contemporary reporting solves the problem of combining history with journalism — but creates the problem of reader trust, since Henrietta's sections are necessarily speculative reconstructions of thoughts and feelings the author cannot actually know","The alternating structure only works in fiction","Skloot avoids this problem by using only documents"],correct:1,explain:"Skloot's alternating structure elegantly connects past and present — showing HeLa cells' origins and their living legacy simultaneously. But it creates a significant journalism ethics problem: the Henrietta chapters include reconstructed internal states ('Henrietta thought...', 'she felt...') that Skloot cannot actually know. Even when thoroughly sourced from family testimony, this reconstruction technique blurs the boundary between fact and informed imagination. Skloot acknowledges this in her notes, but readers who miss the notes may not distinguish reconstructed from documented."},
    {q:"Fajgenbaum's sirolimus discovery relied on identifying mTOR pathway activation in his own biomarkers. What does this case reveal about the epistemological limitations of traditional clinical trial design for rare diseases?",opts:["Traditional trials are ideal for all diseases including rare ones","Traditional RCTs require statistical power that rare disease populations cannot provide (too few patients); N-of-1 trials and adaptive trial designs, biomarker-driven precision approaches, and platform trials that allow multiple comparisons simultaneously are more appropriate epistemological tools for rare disease research","Rare diseases do not require evidence — empirical treatment is acceptable","Fajgenbaum's approach was unscientific and should not be replicated"],correct:1,explain:"This question probes evidence epistemology. Standard RCTs need hundreds or thousands of participants for statistical power. iMCD affects ~1,700 Americans annually — an RCT powered for a definitive answer is essentially impossible in a reasonable timeframe. This is the epistemological limitation Fajgenbaum's case reveals: the evidence hierarchy that places RCTs above all else creates an access barrier for rare disease patients who cannot wait 15+ years for sufficient enrollment. Adaptive trial designs (modifying protocols based on interim results), N-of-1 trials, and registry-based analyses using real-world data represent legitimate epistemological alternatives when traditional designs are infeasible."},
    {q:"Apply the four bioethical principles to evaluate the decision by Johns Hopkins to share HeLa cells freely with researchers worldwide (rather than profiting commercially) while never seeking or obtaining Henrietta Lacks' consent. Is this decision ethically defensible?",opts:["It is fully defensible because the cells were used for good","It is fully indefensible because consent was not obtained","The decision is ethically complex: sharing freely honors beneficence (maximum public benefit) and some sense of justice (no private enrichment). But it was preceded by a clear autonomy violation (no consent), and the justice principle is not fully satisfied because the Lacks family — who bore the burden — received no benefit. The 'good intentions' of those who shared HeLa cells cannot retroactively justify the initial consent violation, but do mitigate some culpability","Bioethics principles do not apply to decisions made in 1951"],correct:2,explain:"This requires applying all four principles simultaneously. Autonomy: Violated — Henrietta did not consent to cell collection for research. Beneficence: Honored — freely sharing cells maximized scientific benefit to humanity. Non-maleficence: Ambiguous — cells were not directly harmful, but the knowledge they were 'out there' causing commercial profits distressed Deborah and the family. Justice: Partially violated — the global scientific community benefited enormously while the family who bore the costs received nothing. A full ethical assessment must weigh all four principles: you can honor beneficence and violate autonomy simultaneously. The lesson is that ends (scientific benefit) do not justify means (consent violation) in modern bioethics."},
    {q:"What would Paul Kalanithi likely argue about the current medical education model based on the arguments in When Breath Becomes Air?",opts:["Medical education is perfect as currently designed","Medical education trains physicians in technical excellence but inadequately prepares them to help patients find meaning in illness and dying — humanities integration (literature, philosophy, ethics) should be equal in standing to clinical training, not an elective add-on","Literature education is irrelevant to medicine and should be eliminated from medical school curricula","Medical education only needs more surgical training"],correct:1,explain:"Kalanithi's entire book implicitly argues for medical education reform. He was a literature major who found that medical training gave him technical excellence but not the frameworks to help dying patients make meaning — or to make meaning of his own dying. His argument mirrors that of narrative medicine's founder Rita Charon: close reading of literature develops the empathy, tolerance for ambiguity, and attention to voice that biomedicine trains out of physicians. He would likely argue for required humanities curricula with equal weight to clinical sciences, not elective 'wellness' offerings."},
  ]);
})();

// ── MEDICAL READING DEDUP ─────────────────────────────────────────────────
(function(){
  if(!window.QB_MEDICAL_READING) return;
  var seenF={}, seenQ={};
  ['easy','medium','hard'].forEach(function(d){
    window.QB_MEDICAL_READING.flashcards[d]=(window.QB_MEDICAL_READING.flashcards[d]||[]).filter(function(f){
      var k=(f.term||'').toLowerCase().trim(); if(seenF[k])return false; seenF[k]=true; return true;
    });
    window.QB_MEDICAL_READING.quiz[d]=(window.QB_MEDICAL_READING.quiz[d]||[]).filter(function(q){
      var k=(q.q||'').toLowerCase().trim(); if(seenQ[k])return false; seenQ[k]=true; return true;
    });
  });
})();

// ── MEDICAL READING FINAL TOP-UP (+22 flash, +55 quiz) ────────────────────
(function(){
  if(!window.QB_MEDICAL_READING) return;
  var fc = window.QB_MEDICAL_READING.flashcards;
  var qz = window.QB_MEDICAL_READING.quiz;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});

  fc.easy = fc.easy.concat([
    {term:"Genre of Wonder",def:"Middle-grade realistic fiction — R.J. Palacio; features a child protagonist navigating a realistic school environment with social and emotional challenges"},
    {term:"Genre of Gifted Hands",def:"Memoir/autobiography — Ben Carson; chronicles his real life from childhood poverty to landmark surgeries"},
    {term:"Genre of When Breath Becomes Air",def:"Medical memoir — Paul Kalanithi; a physician's reflection on identity, meaning, and mortality after a terminal cancer diagnosis"},
    {term:"Genre of The Hot Zone",def:"Narrative nonfiction / science thriller — Richard Preston; reconstructs real Ebola outbreaks using literary techniques"},
    {term:"Genre of Chasing My Cure",def:"Medical memoir and science narrative — David Fajgenbaum; combines personal illness account with scientific detective story"},
    {term:"Point of view — Wonder",def:"Multiple first-person narrators (Auggie, Via, Summer, Jack, Justin) — each chapter is told from that character's perspective using 'I'"},
    {term:"Point of view — Gifted Hands",def:"First-person — Ben Carson narrates his own life story; gives direct access to his thoughts, faith, and motivations"},
    {term:"Point of view — The Hot Zone",def:"Third-person omniscient — Preston narrates events as an outside observer, giving access to multiple characters' thoughts and actions"},
    {term:"Point of view — When Breath Becomes Air",def:"First-person — Paul Kalanithi narrates his own experience; the epilogue shifts to first-person by Lucy Kalanithi"},
    {term:"Tone — Wonder",def:"Hopeful and earnest — despite bullying and pain, the overall emotional register of Wonder is warm and ultimately optimistic about human kindness"},
    {term:"Tone — The Hot Zone",def:"Tense and ominous — Preston creates dread through clinical precision about the virus's effects and near-miss scenes"},
    {term:"Tone — When Breath Becomes Air",def:"Reflective and philosophical — Kalanithi's tone is contemplative, searching for meaning rather than dramatic or self-pitying"},
    {term:"Tone — Chasing My Cure",def:"Urgent and determined — Fajgenbaum's tone reflects his dual identity as desperate patient and methodical scientist"},
    {term:"Tone — Gifted Hands",def:"Confident and faith-driven — Carson's tone reflects his belief that his gifts and faith were given by God for a purpose"},
    {term:"Resolution — Wonder",def:"Auggie wins the school's highest honor (Henry Ward Beecher medal) at graduation — symbolizing his full acceptance and the transformation of the school community"},
    {term:"Resolution — Chasing My Cure",def:"Fajgenbaum achieves remission on sirolimus, founds CDCN, completes his MD/MBA, and marries Katelyn — but acknowledges the disease could return"},
    {term:"Resolution — Gifted Hands",def:"Carson becomes director of pediatric neurosurgery at Johns Hopkins at age 33 — achieving his childhood dream and becoming a role model for others"},
    {term:"Resolution — When Breath Becomes Air",def:"Paul Kalanithi dies in March 2015 — but leaves behind his memoir, his daughter Cady, and a model of how to live meaningfully in the face of death"},
    {term:"Resolution — The Hot Zone",def:"The Reston monkeys are euthanized, Ebola Reston is contained, no humans die — but Preston emphasizes the virus still exists in nature and will emerge again"},
    {term:"Carson and faith",def:"Ben Carson's Christian faith is central to Gifted Hands — he credits prayer and God with his transformation from violent teenager to skilled surgeon"},
    {term:"Paul Kalanithi — literature major",def:"Kalanithi studied literature and human biology at Stanford before medical school — his dual background shapes When Breath Becomes Air's literary depth and philosophical inquiry"},
    {term:"Fajgenbaum and collaboration",def:"David Fajgenbaum specifically rejected competitive academic science — the CDCN model requires all members to share data immediately, prioritizing speed over individual publication credit"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"What is the genre of Wonder?",opts:["Science fiction","Historical fiction","Middle-grade realistic fiction","Autobiography"],correct:2,explain:"Wonder is middle-grade realistic fiction written by R.J. Palacio. It features a fictional child protagonist (Auggie Pullman) in a realistic contemporary school setting. Unlike memoir, it is not based on the author's personal experience."},
    {q:"Who narrates most of Gifted Hands?",opts:["Sonya Carson","Curtis Carson","Ben Carson himself — first-person autobiography","Cecil Murphey the co-author"],correct:2,explain:"Gifted Hands is narrated by Ben Carson himself in first person ('I') — making it an autobiography/memoir. Cecil Murphey co-wrote the book, helping shape the narrative, but the voice and perspective are Ben Carson's."},
    {q:"What point of view does The Hot Zone use?",opts:["First-person — Richard Preston as narrator","Second-person — addressing the reader directly throughout","Third-person omniscient — Preston observes and narrates multiple characters' experiences","Stream of consciousness"],correct:2,explain:"The Hot Zone uses third-person omniscient narration — Preston describes events, characters, and even characters' thoughts as an outside observer with access to multiple perspectives. This is standard for narrative nonfiction."},
    {q:"What is the tone of When Breath Becomes Air?",opts:["Angry and bitter about the unfairness of cancer","Lighthearted and humorous","Reflective and philosophical — searching for meaning","Detached and clinical"],correct:2,explain:"Kalanithi's tone is deeply reflective and philosophical. He does not rage against his diagnosis but examines it with the same careful attention he brought to literature and medicine. His tone is searching — asking what makes life meaningful — rather than bitter or self-pitying."},
    {q:"What is the resolution of Wonder?",opts:["Auggie transfers to a school for children with disabilities","Julian apologizes and becomes Auggie's best friend","Auggie receives the Henry Ward Beecher school medal — symbolizing his full acceptance by the community","Auggie moves to a new city to start over"],correct:2,explain:"At fifth-grade graduation, Auggie receives the Henry Ward Beecher medal — the school's highest honor, awarded for human dignity. This resolution symbolizes Auggie's complete integration into the school community and the transformation of his classmates through the year's experiences."},
    {q:"What type of conflict does Auggie face in Wonder?",opts:["Person vs nature","Person vs self only","Person vs person (Julian and bullies) AND person vs society (ableism and exclusion)","Person vs technology"],correct:2,explain:"Auggie faces multiple conflict types simultaneously: person vs person (direct conflict with Julian and his followers), person vs society (the broader culture of exclusion and staring he encounters everywhere), and person vs self (his own doubts and fear about fitting in)."},
    {q:"What is the climax of Chasing My Cure?",opts:["Fajgenbaum's first hospitalization","Receiving his MD degree","Identifying sirolimus as a potential treatment and beginning it — marking the transition from patient to patient-researcher","The founding of CDCN"],correct:2,explain:"The climax of Chasing My Cure is Fajgenbaum's discovery that the mTOR pathway is activated in his disease and his decision to self-administer sirolimus — this is the moment his scientific analysis and his desperation as a patient converge, transforming him from victim to agent in his own survival."},
    {q:"What role does Sonya Carson play in Gifted Hands?",opts:["She is a physician who mentors Ben","She is the antagonist who pushes Ben too hard","She is the transformative figure who instills a love of reading and a belief in possibility — the catalyst for Ben's academic transformation","She is mentioned only briefly"],correct:2,explain:"Sonya Carson is central to Gifted Hands — her decision to require two books per week, combined with her unwavering belief in her sons despite her own illiteracy and poverty, is the single most important factor in Ben's transformation from failing student to academic achiever."},
    {q:"What does Fajgenbaum mean when he describes treating himself as his own 'n-of-1 trial'?",opts:["He was the only doctor treating himself","He conducted a clinical experiment on himself — tracking his own biomarkers as data to test whether sirolimus was working","He refused to share his data with anyone","He only needed one dose of sirolimus"],correct:1,explain:"An n-of-1 trial is a clinical experiment conducted on a single patient. Fajgenbaum tracked his own biomarkers carefully before and after starting sirolimus — essentially treating himself as the subject of a scientific study. This is ethically controversial in medicine but was his only option given the disease's rarity and urgency."},
    {q:"How does Paul Kalanithi's literary background affect When Breath Becomes Air?",opts:["It makes the book unnecessarily complicated","It has no effect — medicine is separate from literature","It gives the memoir philosophical depth and literary allusions (Eliot, Whitman) that frame his confrontation with mortality as part of a larger human tradition","It only added length to the book"],correct:2,explain:"Kalanithi was a literature major before medical school. His background gives When Breath Becomes Air its distinctive voice — he uses T.S. Eliot and Walt Whitman not decoratively but as frameworks for understanding mortality. The book implicitly argues that literature and medicine are both attempts to understand what makes life meaningful."},
    {q:"What technique does Richard Preston use to make The Hot Zone feel like a thriller despite being nonfiction?",opts:["He invents fictional characters to add drama","He uses cliffhangers, in medias res opening, near-miss personal danger, visceral physical description, and dramatic chapter breaks — thriller techniques applied to real events","He focuses only on action and omits scientific facts","He uses first-person narration to create immediacy"],correct:1,explain:"Preston uses multiple thriller techniques: beginning with Monet mid-symptoms (in medias res), ending chapters at moments of tension (cliffhanger), putting known characters at personal risk (near-miss), and describing Ebola's physical effects with visceral clinical detail. These techniques make nonfiction read with the pacing of fiction."},
    {q:"What is the central conflict in The Hot Zone?",opts:["Richard Preston vs the U.S. government","Human civilization vs a deadly virus that could potentially spread beyond containment","The Army vs the CDC","Researchers vs pharmaceutical companies"],correct:1,explain:"The central conflict of The Hot Zone is human civilization (particularly the scientists and soldiers working to contain it) vs the Ebola virus — an entity that Preston anthropomorphizes as having 'aims' and 'strategies.' The tension is whether the virus will escape containment and reach the general human population."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"What is the difference between theme and plot in the context of Wonder?",opts:["They are the same thing","Plot: Auggie starts fifth grade at Beecher Prep, faces bullying, makes friends, and wins the school medal. Theme: choosing kindness transforms communities; everyone has an invisible story; appearance vs. reality","Theme is the setting; plot is the character's feelings","Theme only exists in novels, not in nonfiction"],correct:1,explain:"Plot is what happens (the sequence of events). Theme is the central message or insight the events convey. Wonder's plot covers one school year at Beecher Prep. Its themes include choosing kindness, the gap between appearance and inner reality, the burden on siblings of children with disabilities, and how school culture shapes behavior."},
    {q:"The Hot Zone opens: 'The Sierra Nevada de Santa Marta is a pyramid of rock and snow that breaks off from the main chain of the Andes...' How does this opening function to establish theme?",opts:["It establishes the setting but has no thematic function","The description of a pyramid that 'breaks off' from the main chain foreshadows Ebola's emergence from the African ecosystem — introducing the theme that the natural world contains forces that exist independently of human awareness or control","This is a factual error — Ebola originated in the DRC, not near the Sierra Nevada","The opening only establishes geographic setting"],correct:1,explain:"Preston's opening landscape description is thematically loaded: the Sierra Nevada is ancient, indifferent, and overwhelming — qualities he attributes to the virus throughout. 'Breaks off from the main chain' foreshadows spillover (the virus breaking from its animal reservoir into humans). This landscape-as-theme technique immediately positions the natural world as the domain where Ebola operates, not as backdrop."},
    {q:"Why is Gifted Hands an important text for health professions students despite being written by someone who later became politically controversial?",opts:["It is not important — only texts by uncontroversial figures should be studied","For health professions students, Gifted Hands documents the experience of racial barriers in medical training and practice from an insider perspective — this firsthand account of discrimination remains relevant to understanding health disparities and physician diversity pipelines, regardless of the author's later political positions","Controversial authors cannot produce educationally valuable texts","The book should be studied only if students agree with Carson's politics"],correct:1,explain:"This question requires separating the author's later political career from the text's educational value. Gifted Hands documents firsthand: the experience of racial prejudice in medical school and hospital settings (1960s–1970s), the role of structural supports (scholarships, mentors) in physician diversity, and the experience of being one of few Black physicians at an elite institution. These experiences remain educationally valuable for understanding physician diversity and barriers to healthcare access — independent of Carson's subsequent political positions."},
    {q:"How does Skloot's reporting methodology in The Immortal Life of Henrietta Lacks exemplify — and complicate — the principles of narrative journalism?",opts:["Skloot's work is pure science journalism with no narrative techniques","Skloot exemplifies narrative journalism by: spending 10 years with sources, using scene reconstruction, alternating timelines, and centering the Lacks family as co-narrators rather than subjects. But she complicates it by reconstructing Henrietta's internal states (thoughts, feelings) that she cannot verify — blurring journalism's fact/interpretation boundary","Skloot's work is a straightforward biography with no journalism complications","Narrative journalism has no established principles"],correct:1,explain:"Skloot exemplifies narrative journalism's best practices: deep sourcing (10 years, hundreds of interviews), transparency about method (author's note), centering marginalized voices, and using literary techniques to create engagement. But reconstruction of Henrietta's internal states (even when sourced from family testimony) crosses a line that strict journalism avoids — the reader cannot distinguish documented fact from informed speculation. Skloot acknowledges this in her methodology notes; the question is whether most readers notice."},
    {q:"How does the nature retreat scene in Wonder function as the structural climax, and what does it reveal about each character?",opts:["The nature retreat is just background — the real climax is Auggie's medal","The nature retreat is the climax because it's the first external danger to crystallize the internal social dynamics — Amos, Henry, and Miles' defense of Auggie reveals their true character beyond peer pressure; it also shows Auggie's transformation from victim to someone others feel compelled to protect","The nature retreat reveals that Julian was right all along","The retreat has no thematic significance"],correct:1,explain:"The nature retreat functions as structural climax for several reasons: (1) external threat (seventh-graders) forces characters to act on their values rather than social performance; (2) Amos, Henry, and Miles — Julian's former followers — choose to defend Auggie, showing character growth; (3) this physical defense mirrors the social defense Auggie has needed all year but never received; (4) it marks the community's turning point — students who were neutral or complicit now actively oppose bullying. The climax externalizes the internal social conflict."},
    {q:"Fajgenbaum argues that the competitive model of academic science (researchers guarding data until publication) is particularly harmful for rare disease research. What is the strongest version of this argument?",opts:["Competition in science is always harmful","For common diseases, competition's slow pace is acceptable — many researchers work in parallel, and eventual results are sufficient. For rare diseases with small patient populations and urgent need, competitive science means: each group reinvents the wheel on small n samples; datasets that could reach significance if combined remain underpowered; patients die during the publication cycle. Collaboration is epistemologically necessary, not just morally preferable","Competition should be replaced with cooperation only in medical research","Fajgenbaum's argument applies equally to all diseases"],correct:1,explain:"The strongest version of Fajgenbaum's argument is epistemological, not just ethical: rare disease research CANNOT achieve statistical power without data pooling. A single institution seeing 5 iMCD patients per year needs 20 years to match the dataset CDCN assembled in 2 years by pooling. This means the traditional competitive model produces science that is literally statistically inadequate for rare diseases — not just slower, but fundamentally epistemologically insufficient."},
    {q:"Compare how Ben Carson and Paul Kalanithi each resolve the tension between technical mastery and humanistic care in medicine.",opts:["Both reject technical mastery in favor of spirituality","Carson resolves the tension through faith — God guides his technically skilled hands. Kalanithi never fully resolves it — his book documents the sustained difficulty of being simultaneously technically excellent and humanistically present with dying patients and family members","Both argue that technical mastery is the only thing that matters","Neither discusses this tension"],correct:1,explain:"This comparison reveals two fundamentally different frameworks: Carson's resolution is theistic — his technical gifts are God-given, and his faith provides the humanistic element. This is coherent but potentially inaccessible to non-believers. Kalanithi's resolution is existentialist — he holds the tension without resolving it, arguing that the discomfort of being simultaneously scientist and humanist is not a problem to solve but a condition to inhabit. Neither resolution is 'correct' — they represent two valid frameworks for integrating medicine's dual demands."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"Apply narratology (Gérard Genette's concepts of story, discourse, and narrative) to analyze how When Breath Becomes Air creates meaning through its structural choices.",opts:["Narratology doesn't apply to memoir","Story (what happened): Kalanithi's life from Stanford to death. Discourse (how it's told): Part 1 ends mid-sentence at a residency achievement; Part 2 begins with diagnosis — the structural rupture enacts the narrative rupture. Narrative (the act of telling): Paul is writing toward death, creating temporal tension between the narrating self (who will die) and the narrated self (who is still learning) — making the reader aware of mortality as an organizing principle","Story and discourse are identical in memoir","Memoir cannot be analyzed with academic literary frameworks"],correct:1,explain:"Genette's framework illuminates the book's temporal construction: the story timeline (chronological life events) is interrupted by the discourse structure (how it's arranged) — Part 1's final chapter ends in professional triumph, Part 2 begins with cancer's revelation, creating a rupture that structurally enacts illness's interruption. The narrative level — Paul writing to an audience while dying — creates a meta-dimension: we read knowing the narrator will not live to read our response. This temporal awareness of the mortal narrator makes mortality a structural, not just thematic, element of the text."},
    {q:"The Immortal Life of Henrietta Lacks has been criticized for centering Rebecca Skloot's reporting journey rather than Henrietta Lacks' experience. How would a narrative medicine scholar and a disability studies scholar each evaluate this critique?",opts:["Both would agree the book is perfect","Narrative medicine scholar: the centering of Skloot's process models the transformative journey of the investigator — learning to see the patient as a whole person — which is pedagogically useful for teaching students how to approach patient stories. Disability/race studies scholar: centering Skloot's journey risks making the Lacks family another backdrop for a white researcher's growth narrative, reproducing the same dynamic of extraction (taking the story) that the book critiques — despite Skloot's best intentions and deep relationship with the family","Both would find the critique completely invalid","These scholarly frameworks cannot be applied to journalism"],correct:1,explain:"This question tests the ability to inhabit multiple critical frameworks simultaneously. The narrative medicine reading sees Skloot's journey as pedagogically valuable — it models the process of learning to see whole persons behind disease data. The critical race/disability studies reading identifies a structural problem: even well-intentioned white authors can reproduce extractive dynamics when they take stories from marginalized communities. Both readings can be valid simultaneously. The critique does not invalidate the book — it identifies a genuine tension that students should recognize and grapple with."},
    {q:"HOSA Medical Reading events ask students to analyze texts across multiple dimensions simultaneously. Rank the following HOSA books from most to least 'reliable' as sources of medical information, and justify your ranking using literary and scientific criteria.",opts:["All books are equally reliable as medical sources","Chasing My Cure (most reliable: primary author, peer-reviewed foundation, specific mechanisms documented) > The Hot Zone (reliable on containment/virology basics, less reliable on specific physical effects) > Gifted Hands (reliable on surgical experience, less reliable on neurological science details) > When Breath Becomes Air (reliable on experiential aspects, not a scientific reference) > Wonder (least reliable: fiction, explicitly not a medical text, though accurate on TCS basics)","Fiction is always more reliable than nonfiction","All nonfiction is equally reliable"],correct:1,explain:"This ranking requires applying both literary analysis (is the author a primary or secondary source? what is their epistemic position?) and scientific criteria (is the information peer-reviewed? independently verifiable?). Chasing My Cure ranks highest because Fajgenbaum is both patient and physician-researcher with direct access to lab data; his scientific claims are the most precisely sourced. The Hot Zone ranks second for biological facts but lower for physical effects (criticized as overstated). Gifted Hands is reliable for surgical experience but Carson's theological interpretations are not scientific claims. When Breath Becomes Air is primarily philosophical, not scientific. Wonder is explicitly fiction — its TCS description is accurate but it is not a medical reference. This ranking demonstrates that reliability is domain-specific: a text can be highly reliable on some claims and unreliable on others."},
  ]);
})();

// ── MEDICAL READING QUIZ MICRO TOP-UP (+33) ───────────────────────────────
(function(){
  if(!window.QB_MEDICAL_READING) return;
  var qz = window.QB_MEDICAL_READING.quiz;
  if(!qz.easy) qz.easy=[]; if(!qz.medium) qz.medium=[];

  qz.easy = qz.easy.concat([
    {q:"What is the setting of Gifted Hands?",opts:["Los Angeles and San Francisco","Boston and Chicago","Detroit (childhood) and Baltimore at Johns Hopkins (career)","New York City"],correct:2,explain:"Gifted Hands moves between two main settings: Detroit, Michigan, where Ben Carson grew up in poverty, and Baltimore, Maryland, where he trained and practiced at Johns Hopkins Hospital — one of the nation's top medical centers."},
    {q:"Who is Via in Wonder?",opts:["Auggie's teacher","Auggie's older sister Olivia, who narrates one section of the book","Auggie's school counselor","A student at Beecher Prep who becomes Auggie's friend"],correct:1,explain:"Via (short for Olivia) is Auggie's older sister. She narrates one section of Wonder, revealing her own invisible burden: years of being in Auggie's shadow, losing her parents' attention, and hiding her grief. Her perspective adds crucial depth to the family's experience."},
    {q:"What is the Castleman Disease Collaborative Network (CDCN)?",opts:["A government agency funding rare disease research","A pharmaceutical company developing Castleman treatments","A research network Fajgenbaum founded to connect researchers, clinicians, and patients worldwide to accelerate Castleman disease research","A support group for Castleman patients only"],correct:2,explain:"CDCN is a nonprofit research network Fajgenbaum founded while still a medical student. Its key innovation: requiring all member researchers to share data immediately rather than waiting for publication — directly challenging the competitive norms of academic science."},
    {q:"What is the climax of Gifted Hands?",opts:["Carson's high school graduation","The death of a patient during surgery","The 22-hour separation of the Binder conjoined twins — the first successful craniopagus twin separation in history","Carson receiving a scholarship to Yale"],correct:2,explain:"The surgical separation of Patrick and Benjamin Binder (German craniopagus twins joined at the back of the skull) in 1987 is the climactic achievement of Gifted Hands. It was a 70-person, 22-hour surgery — the most complex neurosurgical procedure ever attempted at the time."},
    {q:"What does 'motif' mean in literary analysis?",opts:["The most important character in the story","A recurring element, image, or theme throughout a text","The conflict between two characters","The author's point of view"],correct:1,explain:"A motif is a recurring element — image, word, symbol, or idea — that appears throughout a text and contributes to its themes. In Gifted Hands: darkness/light. In Kalanithi: time. In Wonder: seeing beyond appearances. Identifying motifs helps readers understand a text's deeper meanings."},
    {q:"What is the significance of the epilogue in When Breath Becomes Air?",opts:["It is written by Paul's editor and summarizes the book's themes","Lucy Kalanithi's epilogue provides closure about Paul's final days, the birth of their daughter Cady, and what Paul's life meant — completing a story Paul could not finish","It is a fictional addition not written by anyone who knew Paul","It repeats information already in the main text"],correct:1,explain:"Lucy Kalanithi's epilogue is essential to the book's emotional completion. Paul died before finishing his manuscript. Lucy's account of his final weeks — his continued engagement with writing, his relationship with baby Cady, and his death — provides narrative closure and demonstrates the very meaning-making in life's final moments that Paul described throughout the book."},
    {q:"Who is Deborah Lacks in The Immortal Life of Henrietta Lacks?",opts:["Henrietta's physician at Johns Hopkins","Rebecca Skloot's research partner at the laboratory","Henrietta's daughter — a central figure who helps Skloot access the family's story and grapples with her mother's legacy throughout her life","The journalist who first reported on HeLa cells"],correct:2,explain:"Deborah is Henrietta's daughter — she was a baby when her mother died and spent her life not knowing what happened to Henrietta's cells. Her relationship with Skloot forms the emotional core of the book as Deborah processes grief, pride, anger, and confusion about her mother's legacy and her own family's exclusion from its benefits."},
    {q:"What is catharsis in literature?",opts:["A type of literary conflict","The author's stated opinion","Emotional release experienced by the reader — a purging of emotions through engagement with a powerful narrative","A plot device used in mystery novels"],correct:2,explain:"Catharsis (from Greek: purification) is the emotional release readers experience after being taken through intense emotions by a narrative. When Breath Becomes Air and The Immortal Life of Henrietta Lacks are particularly cathartic — they process grief, injustice, and mortality in ways that release emotion in readers."},
    {q:"What does 'translational research' mean in the context of Chasing My Cure?",opts:["Research that translates medical texts into other languages","Research that moves discoveries from basic science to clinical application — bench to bedside","Research conducted by translators who speak multiple languages","Translating patient stories into scientific data"],correct:1,explain:"Translational research bridges basic science (understanding molecular mechanisms) and clinical application (treatments for patients). Fajgenbaum's work exemplifies this — he moved from identifying mTOR activation in his own cells (basic science finding) to self-administering sirolimus (clinical application), compressing the typical 10–15 year translational timeline."},
    {q:"What makes Treacher Collins Syndrome a genetic condition?",opts:["It is caused by a bacterial infection during pregnancy","It results from a mutation in the TCOF1 gene that affects craniofacial development — can be inherited or occur as a new mutation","It is caused by environmental exposure during the first trimester","It develops after birth from a childhood illness"],correct:1,explain:"Treacher Collins Syndrome is caused by mutations in the TCOF1 gene (or POLR1C/POLR1D genes). It follows an autosomal dominant pattern — one mutated copy is sufficient to cause the syndrome. About 60% of cases are new mutations (de novo), not inherited from a parent. The gene is involved in the development of facial bones and tissues."},
    {q:"How did Ben Carson's reading habits in childhood affect his medical career?",opts:["Reading made him want to become a writer, not a doctor","Reading two books per week developed his knowledge, vocabulary, and analytical skills — directly preparing him for the demanding academic and scientific content of medical school","Reading had no effect on his medical career","Reading only helped him socially, not academically"],correct:1,explain:"The books Carson read ranged widely — science, history, biography — building the foundational knowledge that allowed him to succeed academically and eventually in medical school. His mother's reading requirement transformed his learning identity from failure to scholar, which is the precondition for everything that followed in his career."},
    {q:"What literary technique does Wonder use when Henry, Miles, and Amos defend Auggie at the nature retreat?",opts:["Foreshadowing — the attack was predicted earlier","Deus ex machina — an unrealistic rescue inserted to end the conflict","Character development and revelation — the attack reveals who these characters truly are under pressure, beyond their social performances","Flashback — the scene is told from a character's memory"],correct:2,explain:"The nature retreat scene uses character revelation through crisis — an external threat strips away social performance and forces characters to act on their true values. Henry and Miles, who followed Julian, discover they are capable of courage and loyalty to Auggie. This is effective character development because it shows rather than tells who these characters are."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"How does The Hot Zone use the technique of juxtaposition to build its central theme?",opts:["Preston juxtaposes rich and poor characters","Preston juxtaposes the beautiful East African landscape with the horror of hemorrhagic fever — reinforcing the theme that existential danger exists within natural beauty, and that the natural world is indifferent to human survival","Preston juxtaposes military and civilian responses to disease","Preston juxtaposes scientific and lay understanding of disease"],correct:1,explain:"Preston's juxtapositions are structural: the opening African landscape descriptions are lush and beautiful — then immediately give way to visceral descriptions of viral destruction. This contrast is thematically purposeful: Ebola does not emerge from a desolate hellscape but from a pristine African rainforest. Nature is beautiful AND dangerous — indifferent to human welfare. This juxtaposition also serves to counter any narrative that disease is a product of poverty or 'dirty' environments."},
    {q:"In what way does Chasing My Cure challenge the traditional distinction between patient and researcher in medicine?",opts:["It doesn't — Fajgenbaum maintains clear separation between these roles","Fajgenbaum argues through his own example that the patient-researcher boundary is artificially maintained — patients with scientific training can generate valid hypotheses about their own disease, challenging a hierarchy that positions researchers as producers of knowledge and patients as passive subjects or data sources","Only patients with PhDs can challenge this distinction","The distinction is only relevant in academic medicine"],correct:1,explain:"Fajgenbaum's model explicitly challenges the assumption that knowledge flows one direction (researcher → patient). By analyzing his own biomarkers, generating hypotheses, testing them, and building a collaborative network, he demonstrates that the patient's perspective — particularly when combined with scientific training — can generate insights that external researchers without lived experience cannot. This has implications for how medicine values patient expertise more broadly."},
    {q:"How does the structure of When Breath Becomes Air (Part 1 / Part 2 / Epilogue) enact the book's central theme?",opts:["The structure is arbitrary — publishers divided the book for length reasons","The three-part structure mirrors a life's arc — Part 1 (building a life and identity), Part 2 (that life interrupted by cancer), Epilogue (life's legacy) — with the structural break between Part 1 and Part 2 enacting the rupture of diagnosis; the epilogue written by another author enacts Paul's incompleteness","The structure follows standard memoir conventions with no thematic significance","The epilogue undermines the book's theme by having someone else finish Paul's thoughts"],correct:1,explain:"The structure is thematically inseparable from the content. Part 1 ends at the peak of Paul's achievement — residency's completion — creating a narrative high point. Part 2 begins with cancer, enacting diagnosis as rupture. The incompleteness of Paul's manuscript (he died before finishing) is not a deficiency — it is structurally appropriate: an unfinished life produces an unfinished text. Lucy's epilogue is both completion and demonstration that Paul's meaning extends beyond him — enacting his own argument that meaning persists through relationships and legacy."},
    {q:"Compare the role of community in healing/survival in Wonder vs Chasing My Cure.",opts:["Community plays no role in either book","In Wonder, community (school) is both the source of Auggie's pain and the agent of his healing — his classmates' gradual acceptance transforms his experience from isolation to belonging. In Chasing My Cure, community (CDCN) is Fajgenbaum's deliberate creation — he builds the scientific community that doesn't yet exist because his life depends on it. Both books argue that individual resilience requires community support, but from opposite directions: Wonder's community finds Auggie; Fajgenbaum's community must be built from scratch","Only Wonder involves community — Chasing My Cure is an individual story","Both books argue that community is harmful and independence is preferable"],correct:1,explain:"This comparative analysis reveals an important structural contrast: Auggie is a passive recipient of community (he cannot choose his school community; they must choose to accept him). Fajgenbaum is an active creator of community (CDCN didn't exist; he built it because existing structures were inadequate). Both narratives confirm that no individual — however exceptional — survives or thrives without community. But they differ on whether community is found or built, suggesting that the appropriate response to inadequate community structures is to create better ones."},
    {q:"In The Immortal Life of Henrietta Lacks, Skloot documents that Henrietta's cells were given freely to researchers worldwide by George Gey. Does this free sharing mitigate or eliminate the ethical violation of taking her cells without consent? Justify your answer.",opts:["Yes — free sharing fully eliminates the ethical violation","No — the consent violation and the sharing decision are independent ethical events; the subsequent good use of cells cannot retroactively justify their non-consensual collection; however, Gey's decision not to profit personally does mitigate some culpability compared to commercial exploitation","Yes — because no financial harm occurred, no ethical harm occurred","No — because the cells should have been destroyed, not shared"],correct:1,explain:"This question requires separating distinct ethical events. The consent violation (taking cells without permission) is complete at the moment of collection — Gey's subsequent decision about sharing cannot undo it. Consent is about respecting Henrietta's autonomy, not about preventing financial harm. However, Gey's free sharing does affect the justice analysis: the injustice of commercial exploitation by third parties falls on them, not on Gey. The original violation (autonomy) is unmitigated; the subsequent justice failure (unequal distribution of benefits) is partially mitigated by Gey's non-commercial distribution."},
  ]);
})();

// ── MEDICAL READING FINAL 16 QUIZ ─────────────────────────────────────────
(function(){
  if(!window.QB_MEDICAL_READING) return;
  var qz = window.QB_MEDICAL_READING.quiz;
  if(!qz.easy) qz.easy=[]; if(!qz.medium) qz.medium=[];
  qz.easy = qz.easy.concat([
    {q:"What does 'pathos' mean in literary analysis?",opts:["Logic and evidence in writing","The credibility of the author","An appeal to the reader's emotions","A plot twist"],correct:2,explain:"Pathos is one of Aristotle's three rhetorical appeals — it appeals to the audience's emotions. Medical memoirs rely heavily on pathos: Kalanithi's scenes with baby Cady, Fajgenbaum describing nearly dying five times, Wonder's Halloween scene. Effective pathos creates empathy and emotional investment in the narrative."},
    {q:"What is the significance of Auggie winning the Henry Ward Beecher medal?",opts:["It means he scored highest on all academic tests","It represents Auggie's full acceptance and recognition by his community — the school's highest honor for human dignity","It is a made-up award with no significance","It means Julian apologized"],correct:1,explain:"The Beecher medal is awarded for demonstrating human dignity — not academics or athletics. Auggie receiving it symbolizes his complete integration: the community that once avoided him now honors him. It also validates Mr. Tushman's approach and shows that the school culture truly transformed over the year."},
    {q:"How many times did Fajgenbaum nearly die from Castleman disease flares?",opts:["Once","Three times","Five times","Seven times"],correct:2,explain:"David Fajgenbaum nearly died five times from Castleman disease flares before he identified sirolimus as a potential treatment. Each near-death experience deepened his resolve to find a treatment — and each hospitalization gave him more biomarker data he later used to identify the mTOR pathway activation."},
    {q:"What is ethos in writing?",opts:["An appeal to emotions","An appeal to logic and evidence","The credibility or authority of the author","The setting of the narrative"],correct:2,explain:"Ethos is the rhetorical appeal based on the author's credibility, expertise, or character. Fajgenbaum's dual identity as both patient and physician-researcher gives his book exceptional ethos — he has both lived experience and scientific authority. Carson's ethos comes from his actual surgical achievements, not just claimed expertise."},
    {q:"What does 'climax' mean in narrative structure?",opts:["The happiest moment in the story","The turning point of maximum tension — the moment of greatest conflict from which the resolution follows","The author's main argument","The final chapter"],correct:1,explain:"The climax is the story's turning point — the moment of highest tension where the central conflict reaches its peak. After the climax, the story moves toward resolution. In Gifted Hands, the Binder twin surgery. In Chasing My Cure, beginning sirolimus. In Wonder, the nature retreat attack and defense."},
    {q:"What does the motif of 'darkness and light' represent in Gifted Hands?",opts:["The color of hospital rooms","Carson's struggles with vision problems","The recurring contrast between ignorance/poverty/racial barriers (darkness) and education/faith/achievement (light) — reflecting Carson's journey from despair to success","Day and night shifts at the hospital"],correct:2,explain:"Carson uses light and darkness as recurring metaphors throughout Gifted Hands: the darkness of poverty, academic failure, and racial prejudice contrasted with the light of education, faith, and surgical skill. This motif reflects his Christian worldview — God brings light into darkness — and structures his autobiography as a spiritual journey as much as a professional one."},
    {q:"What is the narrative medicine concept of 'bearing witness'?",opts:["Testifying in a legal case involving a patient","Being physically present when a patient dies","The practice of attending carefully and compassionately to a patient's story without rushing to fix or interpret it","Writing witness statements for insurance claims"],correct:2,explain:"In narrative medicine, 'bearing witness' means receiving a patient's story with full attention, without immediately moving to clinical action or reassurance. It is a specific clinical skill — being present with suffering rather than trying to eliminate it. This skill is developed through close reading of literature, which also requires sustained attention to another's perspective."},
    {q:"What does 'diction' refer to in literary analysis?",opts:["How characters speak in dialogue","The author's word choice — the specific language selected to create tone, meaning, and effect","The number of words in a passage","Punctuation and grammar choices"],correct:1,explain:"Diction refers to word choice — the specific words an author selects. Carson uses direct, accessible language reflecting his desire to inspire ordinary readers. Kalanithi uses literary, philosophical diction reflecting his humanities background. Preston uses visceral clinical diction to create physical horror. Diction shapes tone and reveals character."},
  ]);
  qz.medium = qz.medium.concat([
    {q:"Analyze how Fajgenbaum's book reframes the traditional 'patient journey' narrative by incorporating scientific methodology.",opts:["It is a standard patient journey with no reframing","Traditional patient journey narratives (illness → treatment → recovery/acceptance) position the patient as a passive recipient of medical expertise. Fajgenbaum reframes this by inserting scientific methodology into each phase: diagnosis becomes data collection; treatment becomes hypothesis testing; advocacy becomes collaborative science — transforming the patient from subject to co-investigator","Medical methodology has no place in patient narratives","Fajgenbaum rejects the patient journey entirely"],correct:1,explain:"Chasing My Cure structurally disrupts the traditional patient journey by inserting the scientist's toolkit at each stage. This reframing has significant implications: it argues that patients with scientific training can accelerate their own treatment, challenges the passive patient role, and suggests that the patient-researcher binary is a cultural convention rather than an epistemological necessity. For HOSA students, this raises questions about what knowledge patients bring to clinical encounters and how medicine can better utilize that knowledge."},
    {q:"The Hot Zone was published in 1994. In what ways did it accurately predict challenges revealed by COVID-19, and where did it fall short as a pandemic preparedness text?",opts:["It perfectly predicted COVID-19 — no gaps","The Hot Zone accurately predicted: insufficient PPE stockpiles, slow government response to novel pathogens, the challenge of balancing public communication with preventing panic, and the role of international travel in disease spread. It fell short by: focusing on highly lethal filoviruses rather than respiratory pathogens, not anticipating the internet's role in both information and misinformation spread, and not addressing vaccine development timelines","The Hot Zone has nothing relevant to COVID-19 — different virus class","The Hot Zone only predicted the 2014 Ebola outbreak, not COVID-19"],correct:1,explain:"This requires applying Preston's 1994 text to a 2020 context. Accurate predictions: PPE shortages (exactly as described for Reston response), governmental hesitancy (documented in both cases), international transmission via air travel, and the tension between transparency and panic prevention. Shortfalls: COVID is respiratory (different transmission model than Ebola's fluid-contact), the infodemic (social media misinformation) was not anticipated, and vaccine technology has transformed the response capacity Preston's narrative implies is decades away. This analysis demonstrates both the value and limitations of narrative nonfiction as a policy tool."},
    {q:"How does R.J. Palacio use the character of Justin (Via's boyfriend) to contribute thematically to Wonder, even though he appears late in the narrative?",opts:["Justin's section is a publisher requirement with no thematic function","Justin is an outsider who falls in love with the Pullman family without predetermined expectations about Auggie — his section demonstrates that Auggie's effect on people is not limited to his school community but extends to anyone who encounters his family with genuine openness. Justin also shows Via's hidden self — a girlfriend, a young woman separate from her sister role — adding dimension to her character","Justin provides comic relief with no thematic weight","Justin's section reveals that Wonder is actually a romance novel"],correct:1,explain:"Justin functions as the narrative's 'fresh eyes' — he has no history with Auggie or Beecher Prep, so his immediate love for the Pullman family reflects what it looks like to encounter this family without the social conditioning that shapes how Auggie's classmates see him. His section also serves Via: it shows her as a full person — daughter, sister, girlfriend, actor — beyond her role as Auggie's protector. This adds depth to Via's narrative and demonstrates the book's theme that everyone contains multitudes beyond what others see."},
  ]);
})();

// ── MEDICAL READING FINAL 5 ───────────────────────────────────────────────
(function(){
  if(!window.QB_MEDICAL_READING) return;
  var qz = window.QB_MEDICAL_READING.quiz;
  if(!qz.easy) qz.easy=[];
  qz.easy = qz.easy.concat([
    {q:"What is the role of Mr. Browne in Wonder?",opts:["The school principal","A student who defends Auggie","Auggie's homeroom teacher who shares monthly precepts about character and kindness","The author's stand-in character"],correct:2,explain:"Mr. Browne is Auggie's homeroom teacher at Beecher Prep. Each month he shares a 'precept' — a moral statement about character, kindness, and purpose. His precepts become discussion points for the class and reinforce the book's central theme of choosing kindness. Students also write their own precepts to share with him over summer."},
    {q:"What is Paul Kalanithi's primary question in When Breath Becomes Air?",opts:["How can cancer be cured?","How can a physician balance work and family?","What makes life meaningful — especially when facing death?","How should medical education be reformed?"],correct:2,explain:"When Breath Becomes Air is organized around one central question: what makes life meaningful? Kalanithi asks this as a physician who studied dying patients, and then asks it again as a dying patient himself. His answer evolves — from professional achievement, to relationship, to fatherhood — but the question itself drives every section of the book."},
    {q:"What type of cells are HeLa cells?",opts:["Red blood cells from Henrietta Lacks","Skin cells used for allergy testing","Immortal cancer cells taken from Henrietta Lacks' cervical tumor that continue reproducing indefinitely in laboratory culture","Stem cells used in bone marrow transplants"],correct:2,explain:"HeLa cells are immortal cancer cells — taken from Henrietta Lacks' cervical tumor in 1951, they were the first human cells successfully cultured indefinitely in a laboratory. Unlike normal cells that die after a set number of divisions (Hayflick limit), HeLa cells keep dividing — a property of their cancerous origin. They became the foundation of modern cell biology research."},
    {q:"What does the term 'rare disease' mean in the U.S.?",opts:["Any disease that is difficult to diagnose","A disease affecting fewer than 200,000 people in the United States","A disease occurring in less than 1% of the global population","Any disease without a cure"],correct:1,explain:"In the U.S., a rare disease is defined as one affecting fewer than 200,000 Americans. There are approximately 7,000 rare diseases — most without effective treatments. iMCD (Castleman disease) qualifies as a rare disease. This definition determines eligibility for the Orphan Drug Act's incentives for pharmaceutical development."},
    {q:"What does 'narrative nonfiction' mean as a genre?",opts:["Fiction written in the style of a news report","True stories (nonfiction) told using literary techniques from fiction — character development, scene, dialogue, dramatic structure","Nonfiction with fictional characters added for interest","A type of journalism that always uses first-person narration"],correct:1,explain:"Narrative nonfiction (also called literary journalism) tells true stories using techniques from fiction: developed characters, scene-by-scene construction, dramatic structure, tension, dialogue, and sensory detail. The Hot Zone and The Immortal Life of Henrietta Lacks are examples — factually accurate but structured like compelling stories rather than reports."},
  ]);
})();
